// =====================================================================
// DbDo.cs - dual-mode (GUI + dot-prompt CLI) database manager
//
// Browses SQLite, Microsoft Access, Excel, dBASE, and CSV files via
// ADODB Connection and Recordset over COM interop. The same recordset
// is the single source of truth for current position, filter, and sort
// across both the WinForms GUI and the dBase-tradition dot-prompt CLI;
// changes from either side are visible in the other.
//
// User-facing vocabulary follows Microsoft's PowerShell verb canon
// (Common, Data, Diagnostic, Lifecycle, etc.). Internal C# code uses
// idiomatic API terminology (oRecordset.MoveNext, oRecordset.Filter,
// oRecordset.Bookmark, etc.) since that's natural in the language.
//
// Coding style: Camel Type. Lower-camelCase identifiers. Hungarian
// type prefixes (s string, i int, b bool, l list, d dictionary, a
// array, o other object). Constants named like variables but with
// words like "Default" or "Initial" rather than the c_ prefix.
//
// Targets .NET Framework 4.8 / x64. Compiled by buildDbDo.cmd as
// a /target:winexe /platform:x64. No external runtime dependencies
// beyond ADODB (present on every Windows install since 2000) plus
// the appropriate ODBC or OLE DB driver for whichever file format
// the user opens. See DbDo.md for deployment requirements.
// =====================================================================

using System;
using System.Collections.Generic;
using System.ComponentModel;
using System.Data;
using System.Drawing;
using System.IO;
using System.Reflection;
using System.Runtime.InteropServices;
using System.Text;
using System.Threading;
using System.Windows.Forms;
using System.Windows.Forms.Automation;
using System.Windows.Automation;
using System.Windows.Automation.Provider;
using Microsoft.CSharp.RuntimeBinder;
using Newtonsoft.Json;
using Newtonsoft.Json.Linq;

// =====================================================================
// Assembly version resource. csc.exe stamps these three attributes
// into the built EXE's Win32 version resource, so the Windows shell
// (file Properties -> Details), Add/Remove Programs, and any tester
// inspecting the binary all report the same number the About dialog
// shows. All three read the single constant DbDo.BuildInfo.VersionString
// below -- so the version is edited in exactly ONE place in the C#.
// Without these attributes the file-properties version stays 0.0.0.0
// on every build, which is what made the version look like it "never
// changed" to a tester checking the EXE rather than the About box.
// =====================================================================
[assembly: AssemblyVersion(DbDo.BuildInfo.VersionString)]
[assembly: AssemblyFileVersion(DbDo.BuildInfo.VersionString)]
[assembly: AssemblyInformationalVersion(DbDo.BuildInfo.VersionString)]

namespace DbDo
{
    // =====================================================================
    // BuildInfo: THE single source of truth for the application
    // version. Edit VersionString here on each release and nowhere
    // else. It feeds three things automatically:
    //   1. The About dialog, the --version console output, and the
    //      GitHub update check (all read BuildInfo.VersionString).
    //   2. The built EXE's file-properties version, via the
    //      [assembly: AssemblyVersion/AssemblyFileVersion] attributes
    //      above the namespace, which reference this same constant.
    //   3. DbDo_setup.iss's #define AppVersion line, which buildDbDo.cmd
    //      rewrites from this value on every build -- so the installer,
    //      the uninstall entry, and the tagRelease git tag can no longer
    //      drift behind the app. (Inno Setup cannot read a C# constant,
    //      so the build copies the value across rather than duplicating
    //      it by hand.)
    // =====================================================================
    public static class BuildInfo
    {
        public const string VersionString = "1.0.122";
    }

    // =====================================================================
    // LiveRegion: hidden announcement surface for screen-reader output.
    //
    // Purpose: a single global "speak this string" sink that works with
    // any active screen reader (JAWS, NVDA, Narrator, Windows Magnifier
    // speech) without DbDo having to know which one is in memory. The
    // screen reader uses its own active voice; DbDo's job is to raise
    // the standard accessibility events that screen readers listen for.
    //
    // Mechanism (the right one for .NET Framework 4.8):
    //
    //   1. A real Label control is added to the form, sized 1x1 and
    //      tucked under the menu strip at (0, 0) but
    //      Visible = true (screen readers ignore Visible=false elements).
    //      The Label's LiveSetting property is set to Polite. This is
    //      a built-in WinForms feature added in .NET Framework 4.7.1
    //      and surfaced as a property in 4.8: any text change on a
    //      Label whose LiveSetting is Polite or Assertive automatically
    //      raises a UIA LiveRegionChanged event, which JAWS, NVDA, and
    //      Narrator all listen for.
    //
    //   2. As a belt-and-suspenders fallback, after updating the
    //      Label.Text we also try to fire the UIA Notification event
    //      via reflection. RaiseAutomationNotification, added in the
    //      Windows 10 Fall Creators Update, makes the screen reader
    //      announce arbitrary text without requiring a control to be
    //      shown. The reflection guard means this is silently skipped
    //      on older Windows versions.
    //
    // Why the previous custom-NotifyWinEvent approach didn't work:
    // EVENT_OBJECT_LIVEREGIONCHANGED on its own does not make a
    // control a live region. The screen reader, on receiving the
    // event, queries the source's UIA LiveSetting property; if that
    // property is Off (the WinForms default), the event is ignored.
    // The fix is to set LiveSetting to Polite or Assertive; once set,
    // text changes auto-raise the right event with the right metadata.
    //
    // Caveats:
    //   - Whether a particular screen reader actually announces depends
    //     on its verbosity settings.
    //   - The Label MUST be added to a form's Controls collection
    //     before say() will reach a screen reader. DbDoForm wires
    //     this up in its constructor.
    //   - Polite (not Assertive) is the right choice: assertive
    //     interrupts whatever the screen reader is currently saying,
    //     which would make DbDo announcements rude. Polite queues
    //     them after current speech.
    // =====================================================================
    public static class LiveRegion
    {
        private static Label lbl;
        // Form reference saved at attach time so the pure-UIA path can
        // raise notifications from the form's AccessibleObject rather
        // than the 1x1 Label's. Narrator is particular about
        // notification source: it tends to honor notifications from
        // a top-level window's AccessibleObject and ignore them from
        // marginal hidden controls. JAWS and NVDA are more permissive
        // and pick up either source.
        private static Form frmOwner;

        // Reflection cache for AccessibleObject.RaiseAutomationNotification
        // was removed in v1.0.87 when the UIA path switched to native
        // P/Invoke against UIAutomationCore.dll. See dispatchNativeUia
        // Notification and the NotificationHostControl / AnnouncerProvider
        // classes below.

        // Attach the live region to a form. Called once during form
        // construction. The Label is a real on-screen control with
        // LiveSetting=Polite; WinForms automatically raises the UIA
        // LiveRegionChanged event when the Label's Text changes,
        // which JAWS, NVDA, and Narrator all listen for.
        //
        // Placement: 1x1 at the form origin (0, 0). The Label sits
        // tucked under the MenuStrip so it is visually unnoticeable
        // to sighted users, but stays inside the form's client area,
        // which guarantees it participates in the UIA tree. (A
        // far-off-screen Location can sometimes be pruned from the
        // tree by WinForms.)
        public static void attach(Form frm)
        {
            if (lbl != null) return;
            frmOwner = frm;
            lbl = new Label();
            lbl.AutoSize = false;
            lbl.Size = new Size(1, 1);
            lbl.Location = new Point(0, 0);
            lbl.TabStop = false;
            lbl.Visible = true;
            lbl.Text = "";
            lbl.AccessibleName = "";
            lbl.AccessibleRole = AccessibleRole.StaticText;
            lbl.LiveSetting = AutomationLiveSetting.Assertive;
            frm.Controls.Add(lbl);
            // Force the handle to be created so the AccessibleObject
            // is wired up before the first say() call. Without this,
            // the very first announcement can race ahead of UIA tree
            // initialization and be missed.
            IntPtr hForce = lbl.Handle;
        }

        // Push a string to the live region. The Label's Text change
        // auto-raises the UIA LiveRegionChanged event (because
        // LiveSetting was set to Polite at attach time), and we also
        // fire the UIA Notification event by reflection as a belt-
        // and-suspenders fallback. If the live region was never
        // attached (e.g., CLI-only mode), the call is silently
        // ignored.
        //
        // The say() pipeline. Determines which screen reader is
        // currently running and speaks through that reader's own
        // API so the speech uses the user's configured voice and
        // verbosity. No SAPI fallback -- if no screen reader is
        // running, no speech happens. Per-reader paths:
        //
        //   1. JAWS:     FreedomSci.JawsApi COM object's SayString.
        //                Detection: FindWindow("JFWUI2"), which is
        //                JAWS's top-level UI window class. Avoids the
        //                cost of creating the COM object just to test.
        //
        //   2. NVDA:     nvdaControllerClient.dll P/Invoke. The DLL
        //                must be shipped alongside DbDo.exe. NVDA
        //                does NOT expose a COM API; the controller
        //                client is the documented IPC channel.
        //                Detection: nvdaController_testIfRunning()
        //                returns 0 when NVDA is running.
        //
        //   3. Narrator: UIA Notification event via
        //                AccessibleObject.RaiseAutomationNotification.
        //                Narrator does not have a per-app API; it
        //                listens to UIA events. RaiseAutomationNotification
        //                is the documented "announce this text now"
        //                event. Also reaches NVDA and JAWS in their
        //                UIA-enabled modes, but we already covered
        //                those by direct API, so this is effectively
        //                the Narrator path.
        //                Detection: SystemParametersInfo SPI_GETSCREENREADER
        //                returns true when any screen reader is
        //                running. We use this only as a "does anything
        //                care?" hint -- the Notification event is
        //                cheap to fire whether or not Narrator is on.
        //
        // The Label-based live-region path that previous versions
        // used (Label.LiveSetting=Assertive) is preserved as part of
        // the Narrator path because some configurations of NVDA and
        // JAWS in UIA-only mode listen for LiveRegionChanged in
        // addition to / instead of their direct APIs.
        //
        // Priority order: if JAWS is detected, JAWS speaks and we
        // stop (we don't want JAWS to also receive a UIA Notification
        // and speak twice). Same for NVDA. Otherwise UIA Notification
        // fires for Narrator (and any other UIA-listening reader).
        public static void say(string sText)
        {
            // Extra-Speech gate: when off, DbDo's direct speech is
            // suppressed but the screen reader's natural focus and
            // selection announcements still occur. The flag is toggled
            // by Toggle-Extra-Speech (Alt+Shift+S) and persisted to
            // [General] extraSpeech in DbDo.inix. The toggle command
            // itself uses sayForced so the user always hears their
            // own action confirmed regardless of the flag's state.
            if (!bExtraSpeechEnabled) return;
            sayForced(sText);
        }

        // sayForced: bypass the Extra-Speech gate. Used for two
        // narrow purposes: the Toggle-Extra-Speech command's own
        // confirmation (so the user hears "extra speech off" when
        // turning it off), and the Test-Reader command (which must
        // produce speech to be diagnostic).
        public static void sayForced(string sText)
        {
            string sNew = sText ?? "";
            if (isJawsRunning() && jawsSay(sNew)) { sLastPath = "JAWS COM"; return; }
            if (isNvdaRunning() && nvdaSay(sNew)) { sLastPath = "NVDA controller client"; return; }
            // Fall through to the UIA path for Narrator and any
            // unrecognized UIA-aware reader. Also useful as a debug
            // signal: if you have a screen reader running that's
            // detectable via SPI_GETSCREENREADER but not JAWS or
            // NVDA, this is the path that reaches it.
            sayViaUia(sNew);
            sLastPath = "UIA Notification + LiveRegionChanged (Narrator and others)";
            // Optional SAPI backup (off by default; see bUseSapiAsBackup).
            // Speaks only when no screen reader is detected, so it never
            // doubles a live reader and gives audible output where a bare
            // UIA Notification would be silent. Mirrors Say's (the shared
            // toolkit's) UseSapiAsBackup behavior for cross-app consistency.
            if (bUseSapiAsBackup && !isJawsRunning() && !isNvdaRunning() && !isAnyScreenReaderActive())
                if (sapiSay(sNew)) sLastPath = "SAPI backup (no screen reader detected)";
        }

        // sayParts: speak each unit as its OWN direct-speech message
        // rather than concatenating into one run-on string. Both JAWS
        // (SayString flush=false) and the NVDA controller client queue
        // successive messages, so the units come out in order with a
        // natural pause between them, which is markedly more
        // intelligible. Each unit passes through the same Extra-Speech
        // gate as say(); empty units are skipped so a missing piece
        // doesn't leave a dead pause. This is the preferred way to
        // voice any announcement built of logical units -- a cell's
        // header / row / value, a list of columns, a column's values.
        public static void sayParts(IEnumerable<string> parts)
        {
            if (parts == null) return;
            foreach (string sPart in parts)
                if (!string.IsNullOrEmpty(sPart)) say(sPart);
        }

        public static void sayParts(params string[] aParts)
        {
            sayParts((IEnumerable<string>)aParts);
        }

        // Extra-Speech enabled flag. Public mutable so the toggle
        // command can flip it. Loaded from DbDo.inix at startup;
        // default true. Persisted on change.
        public static bool bExtraSpeechEnabled = true;

        // Records which path the most recent say() call used. The
        // Test-Reader command displays this so the user can confirm
        // whether they are hearing speech through the direct JAWS
        // COM call, the direct NVDA controller client, or the
        // generic UIA Notification fallback.
        private static string sLastPath = "(none yet)";
        public static string lastSpeechPath()
        {
            return sLastPath;
        }

        // Diagnostic snapshot of the speech pipeline. Returns a
        // multi-line string covering which readers are detected,
        // which DLL is loadable, and which path the most recent
        // say() used. Test-Reader presents this in a MessageBox.
        public static string speechDiagnostic()
        {
            StringBuilder sb = new StringBuilder();
            sb.AppendLine("Speech pipeline diagnostic");
            sb.AppendLine();
            sb.AppendLine("JAWS running (window class JFWUI2 found): " + (isJawsRunning() ? "yes" : "no"));
            sb.AppendLine("JAWS COM ProgID FreedomSci.JawsApi reachable: "
                + ((oJawsApi != null) ? "yes (cached)" : "(not yet probed or unavailable)"));
            sb.AppendLine();
            bool bNvdaDll = false;
            try { nvdaController_testIfRunning(); bNvdaDll = true; }
            catch (DllNotFoundException) { bNvdaDll = false; }
            catch { bNvdaDll = true; }
            sb.AppendLine("nvdaControllerClient.dll loadable: " + (bNvdaDll ? "yes" : "no (drop the DLL next to DbDo.exe to enable NVDA support)"));
            sb.AppendLine("NVDA running (controller client says so): " + (isNvdaRunning() ? "yes" : "no"));
            sb.AppendLine();
            // SystemParametersInfo SPI_GETSCREENREADER: a generic
            // "some screen reader is on" probe. Independent of JAWS
            // or NVDA detection.
            sb.AppendLine("Windows reports any screen reader active: " + (isAnyScreenReaderActive() ? "yes" : "no"));
            sb.AppendLine();
            sb.AppendLine("Most recent say() used path: " + sLastPath);
            return sb.ToString();
        }

        // SystemParametersInfo SPI_GETSCREENREADER (action 70).
        [DllImport("user32.dll", CharSet = CharSet.Auto)]
        private static extern bool SystemParametersInfo(int iAction, int iParam, ref bool bResult, int iUpdate);
        private const int SPI_GETSCREENREADER = 70;
        private static bool isAnyScreenReaderActive()
        {
            try
            {
                bool bActive = false;
                if (SystemParametersInfo(SPI_GETSCREENREADER, 0, ref bActive, 0))
                    return bActive;
            }
            catch { }
            return false;
        }

        // ---- JAWS: detection + speak ----
        // JAWS exposes a top-level UI window of class "JFWUI2". This
        // is the cheap detection path -- FindWindow does not require
        // COM startup. (Creating FreedomSci.JawsApi when JAWS is not
        // running is slow and produces a misleading "succeeded but
        // nobody listening" object.)
        [DllImport("user32.dll", CharSet = CharSet.Auto)]
        private static extern IntPtr FindWindow(string sClass, string sTitle);
        private static bool isJawsRunning()
        {
            try { return FindWindow("JFWUI2", null) != IntPtr.Zero; }
            catch { return false; }
        }

        // Speak through JAWS. The COM object is cached after first
        // successful creation. If COM creation succeeds, we re-use
        // the object across calls; if SayString throws (JAWS
        // crashed or was closed mid-session), reset and let the
        // next call try again.
        private static object oJawsApi;
        private static bool jawsSay(string sText)
        {
            if (string.IsNullOrEmpty(sText)) return false;
            try
            {
                if (oJawsApi == null)
                {
                    Type comType = Type.GetTypeFromProgID("FreedomSci.JawsApi");
                    if (comType == null) return false;
                    oJawsApi = Activator.CreateInstance(comType);
                    if (oJawsApi == null) return false;
                }
                dynamic oJaws = oJawsApi;
                // SayString(text, flush). flush=false queues politely
                // rather than interrupting whatever JAWS is reading.
                object result = oJaws.SayString(sText, false);
                return result != null && (bool)result;
            }
            catch
            {
                oJawsApi = null;
                return false;
            }
        }

        // ---- NVDA: detection + speak ----
        // NVDA ships a Controller Client DLL with C-style exports.
        // Starting in NVDA 2026.1 the DLL is named simply
        // nvdaControllerClient.dll (no architecture suffix); earlier
        // releases shipped it as nvdaControllerClient64.dll for x64
        // hosts and nvdaControllerClient32.dll for x86. NVDA's own
        // current C# example uses the unsuffixed name and that is
        // what the DbDo build script downloads and bundles. Place
        // the DLL next to DbDo.exe and the DllImport finds it via
        // the standard Windows DLL search order. If the DLL is
        // missing, DllNotFoundException is caught silently and the
        // NVDA path is unavailable.
        //
        // testIfRunning returns 0 when NVDA is running, non-zero
        // otherwise (it's a Windows error code). speakText takes
        // a wide-char string and returns 0 on success.
        [DllImport("nvdaControllerClient.dll", CharSet = CharSet.Unicode, EntryPoint = "nvdaController_testIfRunning")]
        private static extern int nvdaController_testIfRunning();
        [DllImport("nvdaControllerClient.dll", CharSet = CharSet.Unicode, EntryPoint = "nvdaController_speakText")]
        private static extern int nvdaController_speakText([MarshalAs(UnmanagedType.LPWStr)] string sText);
        [DllImport("nvdaControllerClient.dll", CharSet = CharSet.Unicode, EntryPoint = "nvdaController_cancelSpeech")]
        private static extern int nvdaController_cancelSpeech();

        private static bool bNvdaProbed;
        private static bool bNvdaDllPresent;
        private static bool isNvdaRunning()
        {
            // First call: probe whether the DLL is loadable at all.
            // Subsequent calls skip the probe and just call
            // testIfRunning, which is cheap and reliable.
            if (!bNvdaProbed)
            {
                bNvdaProbed = true;
                try
                {
                    int iResult = nvdaController_testIfRunning();
                    bNvdaDllPresent = true;
                    return iResult == 0;
                }
                catch (DllNotFoundException)
                {
                    bNvdaDllPresent = false;
                    return false;
                }
                catch { bNvdaDllPresent = false; return false; }
            }
            if (!bNvdaDllPresent) return false;
            try { return nvdaController_testIfRunning() == 0; }
            catch { return false; }
        }

        private static bool nvdaSay(string sText)
        {
            if (string.IsNullOrEmpty(sText)) return false;
            if (!bNvdaDllPresent) return false;
            try { return nvdaController_speakText(sText) == 0; }
            catch { return false; }
        }

        // ---- Optional SAPI backup (shared-toolkit parity) ----
        // Off by default. When enabled and no screen reader is detected,
        // say() routes through the Windows SAPI voice so there is audible
        // output where a bare UIA Notification would otherwise be silent.
        public static bool bUseSapiAsBackup = false;
        private static object oSapiVoice;
        private static bool sapiSay(string sText)
        {
            if (string.IsNullOrEmpty(sText)) return false;
            try
            {
                if (oSapiVoice == null)
                {
                    Type comType = Type.GetTypeFromProgID("SAPI.SPVoice");
                    if (comType == null) return false;
                    oSapiVoice = Activator.CreateInstance(comType);
                    if (oSapiVoice == null) return false;
                }
                dynamic oVoice = oSapiVoice;
                oVoice.Speak(sText, 1);
                return true;
            }
            catch
            {
                oSapiVoice = null;
                return false;
            }
        }

        // ---- Narrator / generic UIA path ----
        // Update the hidden Label's Text (auto-raises
        // LiveRegionChanged because LiveSetting=Assertive) and also
        // fire the UIA Notification event by reflection. Narrator
        // listens to both event families; the Label path is the
        // documented "live region" approach, the Notification path
        // is the explicit "announce this now" approach.
        private static void sayViaUia(string sText)
        {
            if (lbl == null) return;
            if (lbl.IsDisposed) return;
            try
            {
                if (lbl.InvokeRequired)
                {
                    lbl.Invoke(new Action<string>(sayViaUia), new object[] { sText });
                    return;
                }
                if (lbl.Text == sText) lbl.Text = "";
                lbl.Text = sText;
                lbl.AccessibleName = sText;
                raiseUiaNotification(sText);
            }
            catch { }
        }

        // raiseUiaNotification: legacy entry point used by sayViaUia
        // (which is invoked from say() as a Narrator-only fallback when
        // neither JAWS COM nor NVDA controller-client is reachable).
        // The historical reflection-on-Label path was a documented
        // dead end on .NET Framework 4.8: only Label / LinkLabel /
        // GroupBox / ProgressBar honor AccessibleObject.RaiseAutomation
        // Notification on that runtime, and even then the dispatch did
        // not reach Narrator reliably on Windows 11.
        //
        // v1.0.87 replaces the body with a native-P/Invoke call to
        // UiaRaiseNotificationEvent against a fresh per-call custom
        // IRawElementProviderSimple. That technique reaches all three
        // readers (verified by ChatGPT's reference sample, which the
        // user confirmed worked end to end). The reflection path is
        // gone; the method signature stays so sayViaUia's call site
        // doesn't have to change.
        private static void raiseUiaNotification(string sText)
        {
            dispatchNativeUiaNotification(sText, /*All*/ 2);
        }

        // sayUiaString: pure-UIA speech path. Fires the UIA
        // RaiseAutomationNotification event directly, without going
        // through JAWS COM, NVDA controller client, or the Label/
        // LiveRegionChanged intermediary. Use for testing the UIA
        // path in isolation or when the caller wants a single,
        // simple announcement that doesn't depend on JAWS or NVDA
        // being detected.
        //
        // Reaches JAWS, NVDA, and Narrator in their UIA-listening
        // modes (which is their default). Does NOT go through
        // JAWS's FreedomSci.JawsApi.SayString or NVDA's
        // nvdaControllerClient.dll, so this path is independent of
        // any per-screen-reader API.
        //
        // Inspired by the WPF approach in Kelly Ford's UIANotifications
        // demo (https://github.com/kellylford/TheWorkBench/tree/main/UiaNotifyDemo).
        // The WinForms equivalent uses AccessibleObject's
        // RaiseAutomationNotification instead of WPF's
        // UIElementAutomationPeer.RaiseNotificationEvent, but the
        // underlying UIA event is the same.
        //
        // Source element: the form's own AccessibleObject (not the
        // hidden 1x1 Label that the legacy say() path uses). Narrator
        // honors notifications from top-level windows but tends to
        // ignore them from marginal hidden controls. JAWS and NVDA
        // accept either. Processing mode is "All" (value 2), matching
        // the behavior of the legacy sayViaUia path that DbDo's
        // Narrator fallback was already using successfully -- "All"
        // means deliver to every listener without queue restrictions.
        // sayUiaString: pure-UIA speech path. Fires the UIA
        // notification event directly via native UIAutomationCore.dll,
        // bypassing JAWS COM, NVDA controller client, and the legacy
        // reflection-on-AccessibleObject technique that previous
        // versions (v1.0.76 - v1.0.86) used. The new path is adapted
        // from ChatGPT's verified reference sample which reaches
        // JAWS, NVDA, and Narrator on the same machine.
        //
        // Why it works where the managed RaiseAutomationNotification
        // failed: on .NET Framework 4.8, AccessibleObject.RaiseAutomation
        // Notification is honored only by Label / LinkLabel / GroupBox /
        // ProgressBar, and even those reach Narrator inconsistently.
        // The native UiaRaiseNotificationEvent (in UIAutomationCore.dll)
        // has no such restriction; given a fully-implemented
        // IRawElementProviderSimple anchored to a real window through
        // WM_GETOBJECT, the screen reader's UIA listener picks the
        // event up directly.
        //
        // Reaches JAWS, NVDA, and Narrator in their UIA-listening
        // modes. Does NOT go through JAWS's FreedomSci.JawsApi.SayString
        // or NVDA's nvdaControllerClient.dll.
        public static void sayUiaString(string sText)
        {
            dispatchNativeUiaNotification(sText, /*All*/ 2);
        }

        // sayUiaStringForced: like sayUiaString but uses the
        // ImportantMostRecent processing mode, which screen readers
        // treat as "interrupt current speech and say this now." Use
        // for time-critical announcements (errors, completion of a
        // long operation the user is waiting on).
        public static void sayUiaStringForced(string sText)
        {
            dispatchNativeUiaNotification(sText, /*ImportantMostRecent*/ 1);
        }

        // dispatchNativeUiaNotification: the actual native UIA path.
        // Adapted from ChatGPT-generated reference sample (which the
        // user confirmed works for JAWS, NVDA, and Narrator on Windows
        // 11 with .NET Framework 4.8). Bypasses the managed
        // AccessibleObject.RaiseAutomationNotification API entirely.
        //
        //   1. Create a fresh hidden NotificationHostControl (custom
        //      Control subclass that overrides WndProc to respond to
        //      WM_GETOBJECT by returning a custom IRawElementProvider
        //      Simple). The control is added to the form's Controls
        //      so it has a real window handle; UIA's source-validity
        //      check passes because WM_GETOBJECT returns a provider
        //      genuinely associated with the hwnd.
        //   2. Call UiaRaiseNotificationEvent (P/Invoke into
        //      UIAutomationCore.dll) with the provider as the source.
        //   3. Retain the host on a small ring so it survives long
        //      enough for the screen reader's async UIA listener to
        //      finish reading the Name property. We keep the last 5
        //      hosts before disposing the oldest. The unique sequence
        //      number on each host also prevents UIA from deduping
        //      "same source + same text" pairs.
        //
        // Threading: must run on the UI thread (creating Controls and
        // adding to frmOwner.Controls is a UI-thread operation). If
        // called from a worker thread, marshal via frmOwner.BeginInvoke.
        //
        // Why a fresh host per call (and not a reused pool): ChatGPT's
        // empirical investigation (uia_notify_winforms_repeat_fix
        // sample, "Most Important Behavioral Finding" in its findings
        // doc) determined that reusing a provider for multiple
        // announcements causes screen readers / UIA to silently drop
        // later events, even when the text differs. The dedupe
        // heuristic appears to operate per-source-HWND, so any reuse
        // -- whether a single host or a small pool cycled
        // round-robin -- will eventually drop announcements when two
        // consecutive calls land on the same host. A fresh control
        // per call is the only pattern proven to work for JAWS, NVDA,
        // and Narrator simultaneously.
        //
        // The cost is small in absolute terms: creating a 1x1 Control
        // with an HWND is on the order of tenths of a millisecond and
        // a few KB of managed memory. The retention ring caps the live
        // host count at 5; older hosts are disposed and their HWNDs
        // released. For a database manager where announcements fire
        // on user actions (cell moves, refreshes, edits), this is
        // invisible in normal usage. Do not "optimize" this to a
        // shared host -- it has been tried and it breaks Narrator and
        // NVDA after the first announcement.
        private static System.Collections.Generic.List<NotificationHostControl> lOldHosts
            = new System.Collections.Generic.List<NotificationHostControl>();
        private static int iNotificationSequence;

        private static void dispatchNativeUiaNotification(string sText, int iProcessing)
        {
            if (string.IsNullOrEmpty(sText)) return;
            if (frmOwner == null || frmOwner.IsDisposed) return;
            if (frmOwner.InvokeRequired)
            {
                try
                {
                    frmOwner.BeginInvoke(new Action(delegate()
                    {
                        dispatchNativeUiaNotification(sText, iProcessing);
                    }));
                }
                catch { /* form may be tearing down; non-fatal */ }
                return;
            }
            try
            {
                iNotificationSequence++;
                NotificationHostControl host = new NotificationHostControl(
                    iNotificationSequence, sText);
                host.Left = 0;
                host.Top = 0;
                frmOwner.Controls.Add(host);
                host.CreateControl();  // force hwnd allocation
                lOldHosts.Add(host);

                // Retain the last 5 hosts. Disposing immediately can
                // cause UIA / the screen reader to lose the source
                // before reading the Name property asynchronously.
                while (lOldHosts.Count > 5)
                {
                    NotificationHostControl old = lOldHosts[0];
                    lOldHosts.RemoveAt(0);
                    try
                    {
                        if (frmOwner != null && !frmOwner.IsDisposed)
                            frmOwner.Controls.Remove(old);
                    }
                    catch { }
                    try { old.Dispose(); } catch { }
                }

                // Fully qualify the enum types: both
                // System.Windows.Forms.Automation and
                // System.Windows.Automation define same-named enums
                // (AutomationNotificationKind, AutomationNotification
                // Processing). The UIAutomationCore.dll P/Invoke
                // expects the System.Windows.Automation versions.
                System.Windows.Automation.AutomationNotificationProcessing proc =
                    (iProcessing == 1)
                        ? System.Windows.Automation.AutomationNotificationProcessing.ImportantMostRecent
                        : System.Windows.Automation.AutomationNotificationProcessing.All;
                string sActivityId = "DbDo." + iNotificationSequence.ToString() + "." + Guid.NewGuid().ToString("N");
                UiaNative.UiaRaiseNotificationEvent(
                    host.ProviderAnnouncer,
                    System.Windows.Automation.AutomationNotificationKind.Other,
                    proc,
                    sText,
                    sActivityId);
            }
            catch { /* native UIA dispatch failures are non-fatal */ }
        }
    }

    // =====================================================================
    // Native UIA dispatch helpers (v1.0.87). Adapted from ChatGPT's
    // reference sample that the user confirmed reaches JAWS, NVDA, and
    // Narrator simultaneously on Windows 11 with .NET Framework 4.8.
    //
    // NotificationHostControl is a 1x1 invisible Control that owns a
    // genuine HWND. By overriding WndProc to respond to WM_GETOBJECT,
    // it returns a custom IRawElementProviderSimple (AnnouncerProvider)
    // when UIA queries the window. UIA / the screen reader sees a
    // legitimate UIA element in the tree, so when we call
    // UiaRaiseNotificationEvent against that provider, the event
    // reaches all three readers.
    //
    // AnnouncerProvider is the IRawElementProviderSimple implementation.
    // It exposes a minimal but complete set of UIA properties: Name
    // (the message text), AutomationId, ControlType=Text, FrameworkId,
    // IsControlElement=true, IsContentElement=true. HostRawElementProvider
    // anchors the provider to the host window via
    // AutomationInteropProvider.HostProviderFromHandle.
    //
    // UiaNative.UiaRaiseNotificationEvent is a P/Invoke binding to the
    // native function in UIAutomationCore.dll. The managed wrapper
    // AccessibleObject.RaiseAutomationNotification on .NET Framework
    // 4.8 only works for four specific control types (Label, LinkLabel,
    // GroupBox, ProgressBar) and even then doesn't reach Narrator
    // reliably; the native function has no such restriction.
    // =====================================================================
    public class NotificationHostControl : Control
    {
        private const int c_iWmGetObject = 0x003D;
        private AnnouncerProvider providerAnnouncer;
        public int iSequence;
        public string sMessageText;

        public NotificationHostControl(int iSeq, string sMsg)
        {
            this.TabStop = false;
            this.Width = 1;
            this.Height = 1;
            this.Text = "DbDo notification host " + iSeq.ToString();
            this.AccessibleName = sMsg;
            this.iSequence = iSeq;
            this.sMessageText = sMsg;
            this.providerAnnouncer = null;
        }

        public AnnouncerProvider ProviderAnnouncer
        {
            get
            {
                ensureProvider();
                return providerAnnouncer;
            }
        }

        protected override void OnHandleCreated(EventArgs e)
        {
            base.OnHandleCreated(e);
            ensureProvider();
        }

        protected override void WndProc(ref Message m)
        {
            if (m.Msg == c_iWmGetObject)
            {
                ensureProvider();
                m.Result = AutomationInteropProvider.ReturnRawElementProvider(
                    this.Handle, m.WParam, m.LParam, providerAnnouncer);
                return;
            }
            base.WndProc(ref m);
        }

        private void ensureProvider()
        {
            if (providerAnnouncer == null && this.IsHandleCreated)
            {
                providerAnnouncer = new AnnouncerProvider(this.Handle, iSequence, sMessageText);
            }
        }
    }

    public class AnnouncerProvider : IRawElementProviderSimple
    {
        private const int c_iAutomationIdProperty   = 30011;
        private const int c_iControlTypeProperty    = 30003;
        private const int c_iFrameworkIdProperty    = 30024;
        private const int c_iIsContentElementProperty = 30017;
        private const int c_iIsControlElementProperty = 30016;
        private const int c_iNameProperty           = 30005;
        private const int c_iTextControlType        = 50020;

        private IntPtr hWindow;
        private int iSequence;
        private string sName;

        public AnnouncerProvider(IntPtr hWnd, int iSeq, string sNameIn)
        {
            this.hWindow = hWnd;
            this.iSequence = iSeq;
            this.sName = sNameIn;
        }

        public ProviderOptions ProviderOptions
        {
            get { return ProviderOptions.ServerSideProvider; }
        }

        public IRawElementProviderSimple HostRawElementProvider
        {
            get { return AutomationInteropProvider.HostProviderFromHandle(hWindow); }
        }

        public object GetPatternProvider(int iPatternId)
        {
            return null;
        }

        public object GetPropertyValue(int iPropertyId)
        {
            if (iPropertyId == c_iNameProperty)              return sName;
            if (iPropertyId == c_iAutomationIdProperty)      return "DbDoNotification" + iSequence.ToString();
            if (iPropertyId == c_iControlTypeProperty)       return c_iTextControlType;
            if (iPropertyId == c_iFrameworkIdProperty)       return "WinForms";
            if (iPropertyId == c_iIsControlElementProperty)  return true;
            if (iPropertyId == c_iIsContentElementProperty)  return true;
            return null;
        }
    }

    public static class UiaNative
    {
        [DllImport("UIAutomationCore.dll", PreserveSig = true)]
        public static extern int UiaRaiseNotificationEvent(
            IRawElementProviderSimple provider,
            System.Windows.Automation.AutomationNotificationKind notificationKind,
            System.Windows.Automation.AutomationNotificationProcessing notificationProcessing,
            [MarshalAs(UnmanagedType.BStr)] string displayString,
            [MarshalAs(UnmanagedType.BStr)] string activityId);
    }

    // =====================================================================
    // JawsSettingsInstaller: copy DbDo.jkm and DbDo.jss into every
    // installed JAWS user-settings folder and run scompile.exe to
    // produce DbDo.jsb there. The Pascal-Script equivalent that
    // shipped with v1.0.39 worked but lived inside DbDo_setup.iss;
    // moving it to C# lets the user re-trigger it later without
    // re-running the full installer, and consolidates the JAWS-
    // version-discovery logic in one place.
    //
    // Invoked two ways:
    //   - From the installer's [Run] section as
    //     `DbDo.exe --install-jaws-settings`, which runs the install
    //     and exits without launching the GUI.
    //   - From the Help menu's "Install JAWS settings" command, which
    //     re-runs the install (for users who upgraded JAWS to a new
    //     year-version after installing DbDo).
    //
    // Returns a multi-line report of what was done. Caller chooses
    // whether to show it (the menu version pops a dialog; the CLI
    // version prints it).
    // =====================================================================
    public static class JawsSettingsInstaller
    {
        // Find scompile.exe for a given JAWS year-version. Tries the
        // registry value HKLM\Software\Freedom Scientific\JAWS\<ver>\
        // Target first, then falls back to {pf}\Freedom Scientific\
        // JAWS\<ver>\scompile.exe.
        private static string findScompilePath(string sVersion)
        {
            try
            {
                using (Microsoft.Win32.RegistryKey key = Microsoft.Win32.Registry.LocalMachine
                    .OpenSubKey(@"Software\Freedom Scientific\JAWS\" + sVersion))
                {
                    if (key != null)
                    {
                        string sTarget = key.GetValue("Target") as string;
                        if (!string.IsNullOrEmpty(sTarget))
                        {
                            string sCompile = System.IO.Path.Combine(sTarget, "scompile.exe");
                            if (System.IO.File.Exists(sCompile)) return sCompile;
                        }
                    }
                }
            }
            catch { /* registry access can fail under low privilege; fall through */ }

            string sPf = Environment.GetFolderPath(Environment.SpecialFolder.ProgramFiles);
            string sFallback = System.IO.Path.Combine(sPf,
                @"Freedom Scientific\JAWS\" + sVersion + @"\scompile.exe");
            if (System.IO.File.Exists(sFallback)) return sFallback;
            return null;
        }

        // Run the install. Returns a human-readable report and, via
        // the iCopied / iCompiled out-parameters, totals the caller
        // can use for status text. Records every path placed in a
        // log under %APPDATA%\DbDo\jawsSettings.log so the matching
        // uninstall path can remove exactly those files.
        public static string install(string sAppFolder, out int iCopied, out int iCompiled)
        {
            iCopied = 0;
            iCompiled = 0;
            System.Text.StringBuilder sb = new System.Text.StringBuilder();
            System.Collections.Generic.List<string> lLog = new System.Collections.Generic.List<string>();

            string sJawsRoot = System.IO.Path.Combine(
                Environment.GetFolderPath(Environment.SpecialFolder.ApplicationData),
                @"Freedom Scientific\JAWS");
            if (!System.IO.Directory.Exists(sJawsRoot))
            {
                sb.AppendLine("JAWS does not appear to be installed for the current user.");
                sb.AppendLine("(No folder at " + sJawsRoot + ")");
                return sb.ToString();
            }

            string sJkmSource = System.IO.Path.Combine(sAppFolder, "DbDo.jkm");
            string sJssSource = System.IO.Path.Combine(sAppFolder, "DbDo.jss");
            if (!System.IO.File.Exists(sJkmSource))
            {
                sb.AppendLine("DbDo.jkm not found in " + sAppFolder + ".");
                return sb.ToString();
            }
            if (!System.IO.File.Exists(sJssSource))
            {
                sb.AppendLine("DbDo.jss not found in " + sAppFolder + ".");
                return sb.ToString();
            }

            foreach (string sVersionPath in System.IO.Directory.GetDirectories(sJawsRoot))
            {
                string sVersion = System.IO.Path.GetFileName(sVersionPath);
                string sSettingsPath = System.IO.Path.Combine(sVersionPath, "Settings");
                if (!System.IO.Directory.Exists(sSettingsPath)) continue;
                string sScompile = findScompilePath(sVersion);

                foreach (string sLangPath in System.IO.Directory.GetDirectories(sSettingsPath))
                {
                    string sLang = System.IO.Path.GetFileName(sLangPath);
                    string sJkmTarget = System.IO.Path.Combine(sLangPath, "DbDo.jkm");
                    string sJssTarget = System.IO.Path.Combine(sLangPath, "DbDo.jss");
                    string sJsbTarget = System.IO.Path.Combine(sLangPath, "DbDo.jsb");

                    bool bJkmOk = false, bJssOk = false, bJsbOk = false;
                    try { System.IO.File.Copy(sJkmSource, sJkmTarget, true); bJkmOk = true; iCopied++; lLog.Add(sJkmTarget); }
                    catch (Exception ex) { sb.AppendLine("FAIL: copy jkm to " + sJkmTarget + ": " + ex.Message); }
                    try { System.IO.File.Copy(sJssSource, sJssTarget, true); bJssOk = true; iCopied++; lLog.Add(sJssTarget); }
                    catch (Exception ex) { sb.AppendLine("FAIL: copy jss to " + sJssTarget + ": " + ex.Message); }

                    if (bJssOk && !string.IsNullOrEmpty(sScompile))
                    {
                        try
                        {
                            System.Diagnostics.ProcessStartInfo psi =
                                new System.Diagnostics.ProcessStartInfo(sScompile, "DbDo.jss");
                            psi.WorkingDirectory = sLangPath;
                            psi.UseShellExecute = false;
                            psi.CreateNoWindow = true;
                            psi.RedirectStandardOutput = true;
                            psi.RedirectStandardError = true;
                            using (System.Diagnostics.Process proc = System.Diagnostics.Process.Start(psi))
                            {
                                proc.WaitForExit(10000);
                                if (proc.HasExited && proc.ExitCode == 0 && System.IO.File.Exists(sJsbTarget))
                                { bJsbOk = true; iCompiled++; lLog.Add(sJsbTarget); }
                                else
                                {
                                    string sErr = proc.HasExited ? proc.StandardError.ReadToEnd() : "(timed out)";
                                    sb.AppendLine("FAIL: compile " + sJsbTarget + " - " + sErr.Trim());
                                }
                            }
                        }
                        catch (Exception ex) { sb.AppendLine("FAIL: compile " + sJsbTarget + ": " + ex.Message); }
                    }
                    else if (bJssOk && string.IsNullOrEmpty(sScompile))
                    {
                        sb.AppendLine("WARN: scompile.exe not found for JAWS " + sVersion
                            + "; placed jss but did not compile (run scompile manually).");
                    }

                    sb.AppendLine("JAWS " + sVersion + " / " + sLang + ": "
                        + (bJkmOk ? "jkm " : "no-jkm ")
                        + (bJssOk ? "jss " : "no-jss ")
                        + (bJsbOk ? "jsb" : "no-jsb"));
                }
            }

            // Persist the log so the matching uninstall step can
            // remove exactly the files we placed.
            try
            {
                string sLogPath = getLogPath();
                System.IO.Directory.CreateDirectory(System.IO.Path.GetDirectoryName(sLogPath));
                System.IO.File.WriteAllLines(sLogPath, lLog);
            }
            catch (Exception ex) { sb.AppendLine("WARN: could not write log: " + ex.Message); }

            return sb.ToString();
        }

        // Uninstall: read the log, delete each path listed, then
        // delete the log itself. Mirrors what the Pascal Script
        // CurUninstallStepChanged did in v1.0.39.
        public static string uninstall(out int iDeleted)
        {
            iDeleted = 0;
            System.Text.StringBuilder sb = new System.Text.StringBuilder();
            string sLogPath = getLogPath();
            if (!System.IO.File.Exists(sLogPath))
            {
                sb.AppendLine("No jawsSettings.log found; nothing to remove.");
                return sb.ToString();
            }
            try
            {
                string[] aPaths = System.IO.File.ReadAllLines(sLogPath);
                foreach (string sPath in aPaths)
                {
                    if (string.IsNullOrWhiteSpace(sPath)) continue;
                    try
                    {
                        if (System.IO.File.Exists(sPath))
                        {
                            System.IO.File.Delete(sPath);
                            iDeleted++;
                            sb.AppendLine("removed " + sPath);
                        }
                    }
                    catch (Exception ex) { sb.AppendLine("FAIL: " + sPath + ": " + ex.Message); }
                }
                try { System.IO.File.Delete(sLogPath); } catch { /* tolerate */ }
                try { System.IO.Directory.Delete(System.IO.Path.GetDirectoryName(sLogPath), false); }
                catch { /* only succeeds if empty; ok either way */ }
            }
            catch (Exception ex) { sb.AppendLine("FAIL: read log: " + ex.Message); }
            return sb.ToString();
        }

        private static string getLogPath()
        {
            return System.IO.Path.Combine(
                Environment.GetFolderPath(Environment.SpecialFolder.ApplicationData),
                @"DbDo\jawsSettings.log");
        }
    }

    // =====================================================================
    // ScriptHelper: file-system support for DbDo's Invoke / Edit
    // Script commands.
    // Scripts live as plain files under %APPDATA%\DbDo\Scripts\.
    // Files ending in .js are executed as JScript .NET via
    // DbDo.JS.runScript (in the separately-compiled DbDo.dll);
    // all other extensions are treated as plain text and displayed in
    // a standard MessageBox as reference material.
    //
    // No custom script editor. The user edits scripts in their own
    // preferred editor (Notepad by default; configurable in DbDo.inix
    // under [Scripts] editor=path-to-editor). The Pick dialog for
    // choosing a script to invoke or edit reuses the existing
    // LbcDialog used throughout DbDo (Choose Table, Recent Files,
    // etc.).
    //
    // (Note: a text editor's "Save Script" command captures selected
    // or whole-document text from the current view and writes
    // it to a script file. DbDo is not a text editor, so there is
    // no analogous "current selection" to capture. The Save Script
    // command from v1.0.44 dev preview is dropped here in favor of
    // Edit Script covering the new-file case too -- the user picks
    // a "[New script...]" entry in the pick list when no existing
    // file is the target.)
    // =====================================================================
    public static class ScriptHelper
    {
        // Script folder under %APPDATA%\DbDo\Scripts. Created on
        // first access. Path is stable across DbDo upgrades because
        // it lives under the user's roaming application data, not
        // the install folder.
        //
        // First-creation seeding: if we are creating the folder for
        // the first time (no .seeded sentinel yet), copy any *.js
        // files from {app}\SampleScripts into the user's folder so
        // they have working examples to learn from. The sentinel
        // prevents re-seeding on later launches (so users can delete
        // samples they don't want without them coming back). Failure
        // is silent: bad permissions, missing source folder, etc.,
        // all just leave the script folder empty.
        public static string getScriptDir()
        {
            string sDir = System.IO.Path.Combine(
                Environment.GetFolderPath(Environment.SpecialFolder.ApplicationData),
                @"DbDo\Scripts");
            try { System.IO.Directory.CreateDirectory(sDir); }
            catch { /* tolerate; the caller will surface the error */ }
            seedSampleScriptsIfNew(sDir);
            return sDir;
        }

        // getSampleDir: the per-user folder of sample databases,
        // %APPDATA%\DbDo\Samples, seeded once from the install's
        // {app}\Samples folder on first access -- the exact pattern
        // getScriptDir uses for Scripts. The Sample Databases command
        // lists the .db files here, and the user can drop their own
        // databases into the folder to add them to that list.
        public static string getSampleDir()
        {
            string sDir = System.IO.Path.Combine(
                Environment.GetFolderPath(Environment.SpecialFolder.ApplicationData),
                @"DbDo\Samples");
            try { System.IO.Directory.CreateDirectory(sDir); }
            catch { /* tolerate; the caller will surface the error */ }
            seedSampleDatabasesIfNew(sDir);
            return sDir;
        }

        // seedSampleDatabasesIfNew: one-time copy of the bundled sample
        // databases ({app}\Samples\*.db) into the user's Samples folder.
        // A .seeded sentinel records that seeding has run, so deleting a
        // sample does not make it reappear on the next launch.
        private static void seedSampleDatabasesIfNew(string sDir)
        {
            try
            {
                string sSentinel = System.IO.Path.Combine(sDir, ".seeded");
                bool bFirstSeed = !System.IO.File.Exists(sSentinel);

                string sAppFolder = System.IO.Path.GetDirectoryName(
                    System.Reflection.Assembly.GetExecutingAssembly().Location) ?? "";
                string sSrcFolder = System.IO.Path.Combine(sAppFolder, "Samples");
                if (System.IO.Directory.Exists(sSrcFolder))
                {
                    // Each sample database lives in its own subfolder
                    // (Samples\<name>\<name>.db, plus that database's own
                    // scripts and report/transfer .inix files beside it).
                    // On the FIRST seed every bundled file is copied. On
                    // later launches a file is refreshed only when it still
                    // exists here AND the installed copy is newer -- so a
                    // new install's updated samples replace the older ones
                    // by the same name, while a sample the user deleted is
                    // not resurrected and an edit the user made after the
                    // install (newer timestamp) is preserved.
                    foreach (string sSubSrc in System.IO.Directory.GetDirectories(sSrcFolder))
                    {
                        string sSubDst = System.IO.Path.Combine(sDir, System.IO.Path.GetFileName(sSubSrc));
                        try { System.IO.Directory.CreateDirectory(sSubDst); } catch { }
                        foreach (string sSrcPath in System.IO.Directory.GetFiles(sSubSrc))
                        {
                            string sDstPath = System.IO.Path.Combine(sSubDst, System.IO.Path.GetFileName(sSrcPath));
                            copyBundledSample(sSrcPath, sDstPath, bFirstSeed);
                        }
                    }
                    // Tolerate any loose .db left directly in the source
                    // Samples folder (older flat layout).
                    foreach (string sSrcPath in System.IO.Directory.GetFiles(sSrcFolder, "*.db"))
                    {
                        string sDstPath = System.IO.Path.Combine(sDir, System.IO.Path.GetFileName(sSrcPath));
                        copyBundledSample(sSrcPath, sDstPath, bFirstSeed);
                    }
                }
                if (bFirstSeed)
                {
                    try { System.IO.File.WriteAllText(sSentinel, "seeded " + DateTime.Now.ToString("o")); }
                    catch { }
                }
            }
            catch { /* never let seeding block the picker */ }
        }

        // copyBundledSample: seed or refresh one bundled sample file.
        //   - missing destination: copied only on the first seed, so a
        //     sample the user has deliberately deleted stays gone;
        //   - existing destination: overwritten only when the installed
        //     source is newer, so a fresh install's updated files replace
        //     the older same-named ones while a later user edit is kept.
        private static void copyBundledSample(string sSrcPath, string sDstPath, bool bFirstSeed)
        {
            try
            {
                bool bExists = System.IO.File.Exists(sDstPath);
                if (!bExists)
                {
                    if (!bFirstSeed) return;                 // don't resurrect deleted samples
                    System.IO.File.Copy(sSrcPath, sDstPath, false);
                    clearReadOnly(sDstPath);                 // keep the seeded copy editable
                    return;
                }
                if (System.IO.File.GetLastWriteTimeUtc(sSrcPath)
                    > System.IO.File.GetLastWriteTimeUtc(sDstPath))
                {
                    clearReadOnly(sDstPath);                 // so the overwrite can proceed
                    System.IO.File.Copy(sSrcPath, sDstPath, true);   // replace older same-named file
                    clearReadOnly(sDstPath);                 // and stay editable afterward
                }
            }
            catch { /* keep going for the rest */ }
        }

        // clearReadOnly: drop the read-only attribute a File.Copy may have
        // carried over from a read-only installed source, so the seeded
        // sample can be refreshed on a later upgrade and edited by the user.
        private static void clearReadOnly(string sPath)
        {
            try
            {
                System.IO.FileAttributes attr = System.IO.File.GetAttributes(sPath);
                if ((attr & System.IO.FileAttributes.ReadOnly) != 0)
                    System.IO.File.SetAttributes(sPath, attr & ~System.IO.FileAttributes.ReadOnly);
            }
            catch { }
        }

        // listSampleDatabases: the full paths of the bundled sample
        // databases. Each sample lives in its own subfolder of the
        // user's Samples folder (Samples\<name>\<name>.db) so its
        // database-specific scripts can sit beside it. Returns one
        // .db per subfolder, sorted, for the Sample Databases pick list.
        public static string[] listSampleDatabases()
        {
            List<string> l = new List<string>();
            try
            {
                string sDir = getSampleDir();
                // One .db per per-database subfolder (the standard
                // layout: Samples\<name>\<name>.db).
                foreach (string sSub in System.IO.Directory.GetDirectories(sDir))
                    foreach (string sP in System.IO.Directory.GetFiles(sSub, "*.db"))
                        l.Add(sP);
                // Plus any loose .db directly in Samples (tolerated).
                foreach (string sP in System.IO.Directory.GetFiles(sDir, "*.db"))
                    l.Add(sP);
                l.Sort(StringComparer.OrdinalIgnoreCase);
            }
            catch { }
            return l.ToArray();
        }

        // seedSampleScriptsIfNew: one-time copy of the bundled
        // sample scripts into the user's script folder. Copies
        // every .js, .sql, and .dbdo file from {app}\Scripts into
        // %APPDATA%\DbDo\Scripts. A .seeded sentinel file inside
        // the user's script folder records that seeding has run,
        // so deleting a sample doesn't cause it to reappear on
        // the next launch.
        //
        // The source folder is called Scripts in the install layout
        // (same name as the destination); earlier versions called
        // it SampleScripts and the variable name lingers in the
        // method name for backward compatibility but the actual
        // path is just "Scripts".
        private static void seedSampleScriptsIfNew(string sDir)
        {
            try
            {
                string sSentinel = System.IO.Path.Combine(sDir, ".seeded");
                if (System.IO.File.Exists(sSentinel)) return;

                string sAppFolder = System.IO.Path.GetDirectoryName(
                    System.Reflection.Assembly.GetExecutingAssembly().Location) ?? "";
                string sSrcFolder = System.IO.Path.Combine(sAppFolder, "Scripts");
                // Backward compatibility: if the new "Scripts" folder
                // doesn't exist next to the EXE but the older
                // "SampleScripts" folder does, use that instead.
                if (!System.IO.Directory.Exists(sSrcFolder))
                {
                    string sLegacy = System.IO.Path.Combine(sAppFolder, "SampleScripts");
                    if (System.IO.Directory.Exists(sLegacy)) sSrcFolder = sLegacy;
                }
                if (System.IO.Directory.Exists(sSrcFolder))
                {
                    string[] aPatterns = new string[] { "*.js", "*.sql", "*.dbdo" };
                    foreach (string sPattern in aPatterns)
                    {
                        string[] aSrcFiles = System.IO.Directory.GetFiles(sSrcFolder, sPattern);
                        foreach (string sSrcPath in aSrcFiles)
                        {
                            string sName = System.IO.Path.GetFileName(sSrcPath);
                            string sDstPath = System.IO.Path.Combine(sDir, sName);
                            // Only copy if the destination doesn't
                            // already exist. Even on first-run, if
                            // a same-named script somehow exists
                            // (manual placement), don't clobber it.
                            if (!System.IO.File.Exists(sDstPath))
                            {
                                try { System.IO.File.Copy(sSrcPath, sDstPath, false); }
                                catch { /* keep going for the rest */ }
                            }
                        }
                    }
                }
                // Mark seeded regardless of whether anything was
                // copied. An empty source folder, a missing source
                // folder, or permissions failures all count as "we
                // tried" -- we won't retry on later runs.
                try { System.IO.File.WriteAllText(sSentinel, "DbDo script folder seeded.\r\n"); }
                catch { /* tolerate */ }
            }
            catch
            {
                /* swallow everything -- script folder still works
                   without the samples */
            }
        }

        // Editor command. The optional [Scripts] editor= setting in
        // the per-user DbDo.inix overrides; default is Notepad on
        // PATH. Returns the editor executable path or "notepad" if
        // no override.
        //
        // IniSession lives nested inside DbDoForm (where most ini
        // access happens) so we reach it via the qualified name.
        // No new helper class is introduced for one call site.
        public static string getEditorCommand()
        {
            string sIniEditor = DbDoForm.IniSession.read("Scripts", "editor");
            if (!string.IsNullOrEmpty(sIniEditor)) return sIniEditor;
            return "notepad";
        }

        // List the script files, sorted alphabetically by name (not
        // by full path). Returns the bare filenames, suitable for an
        // LbcDialog presentation.
        //
        // Prefix note: dirInfo / fileInfos here use the lower-camel
        // class-name prefix per Camel Type for non-COM .NET objects;
        // they are NOT prefixed "o" (which is for COM/Variant types).
        // listScripts: return the names of every DbDo script file
        // in the user's scripts folder. The recognized extensions
        // are .js (JScript .NET), .sql (SQL batch), and .dbdo
        // (DbDo command batch). The .seeded sentinel and any other
        // file types are hidden. Returns names without paths, sorted
        // alphabetically case-insensitively.
        public static string[] listScripts()
        {
            return listScriptsInFolder(getScriptDir());
        }

        // listScriptsInFolder: the script-file names (.js, .sql,
        // .dbdo) directly in one folder, sorted case-insensitively,
        // without paths. Any non-script file -- including a database
        // sitting in the same folder, and the .seeded sentinel -- is
        // ignored. This is the building block for both the generic
        // script folder and a database's own folder, where its
        // database-specific scripts live beside the .db file.
        public static string[] listScriptsInFolder(string sFolder)
        {
            if (string.IsNullOrEmpty(sFolder) || !System.IO.Directory.Exists(sFolder))
                return new string[0];
            System.IO.DirectoryInfo dirInfo = new System.IO.DirectoryInfo(sFolder);
            List<string> lNames = new List<string>();
            foreach (System.IO.FileInfo fi in dirInfo.GetFiles())
            {
                string sExt = fi.Extension.ToLowerInvariant();
                if (sExt == ".js" || sExt == ".sql" || sExt == ".dbdo")
                    lNames.Add(fi.Name);
            }
            lNames.Sort(StringComparer.OrdinalIgnoreCase);
            return lNames.ToArray();
        }

        // isDbDoInstallFolder: true when sFolder is DbDo's own program
        // directory -- the folder that holds DbDo.exe. That directory
        // holds DbDo's own files (DbDo.exe, DbDo.dll, and the DbDo.js
        // build source that is compiled into DbDo.dll), none of which are
        // user scripts. It is therefore never mined for a database's
        // associated scripts, even when a database happens to sit
        // directly in it. A database in any other folder -- including a
        // subfolder such as Samples\media -- is scanned normally, so this
        // is a location rule about DbDo's own directory, not a filter on
        // any particular file name.
        public static bool isDbDoInstallFolder(string sFolder)
        {
            if (string.IsNullOrEmpty(sFolder)) return false;
            try
            {
                string sExeDir = System.IO.Path.GetDirectoryName(
                    System.Windows.Forms.Application.ExecutablePath) ?? "";
                if (string.IsNullOrEmpty(sExeDir)) return false;
                string sA = System.IO.Path.GetFullPath(sFolder).TrimEnd('\\', '/');
                string sB = System.IO.Path.GetFullPath(sExeDir).TrimEnd('\\', '/');
                return string.Equals(sA, sB, StringComparison.OrdinalIgnoreCase);
            }
            catch { return false; }
        }

        // Open the user's editor on a script file path. The file is
        // created (touched) if it does not exist so the editor opens
        // a real path rather than failing on a "file not found" prompt.
        // Returns true on success.
        public static bool openInEditor(string sFilePath)
        {
            try
            {
                if (!System.IO.File.Exists(sFilePath))
                {
                    System.IO.File.WriteAllText(sFilePath, "");
                }
                System.Diagnostics.ProcessStartInfo psi =
                    new System.Diagnostics.ProcessStartInfo(getEditorCommand(), "\"" + sFilePath + "\"");
                psi.UseShellExecute = false;
                System.Diagnostics.Process.Start(psi);
                return true;
            }
            catch { return false; }
        }

        // Run a script. The script's file extension determines the
        // engine:
        //
        //   .js   -- JScript .NET. Load the file content and call
        //            DbDo.JS.runScript via reflection so DbDo.cs
        //            does not need a compile-time reference to
        //            DbDo.dll's types. The script has access to
        //            host objects `db` (DbDoManager) and `frm`
        //            (DbDoForm) and can do arbitrary computation;
        //            the string it leaves on its last expression
        //            becomes the result.
        //
        //   .sql  -- SQL batch. Statements separated by ';' are run
        //            in order through DbDoManager.invokeSql, which
        //            handles both SELECT (renders rows) and DML
        //            (returns row count). All output is captured to
        //            a StringWriter and returned for display in the
        //            memo dialog.
        //
        //   .dbdo  -- DbDo command batch. Each non-blank, non-comment
        //            line is parsed and dispatched through the dot-
        //            prompt's resolver as if the user had typed it
        //            at the prompt. Comments start with '#' or '--'.
        //            stdout output from each command is captured and
        //            returned together.
        //
        // The .dbdo extension is reserved for DbDo's command-batch
        // format; it does not collide with any major file type. .dbd
        // was considered (collision with ER/Studio and InterBase),
        // .dot was considered (Graphviz, Word templates).
        //
        // The frm and db parameters are typed as object because at
        // this layer we don't need the static types -- the JScript
        // engine takes them as Object[] anyway. frm IS a DbDoForm
        // and db IS a DbDoManager at the call site.
        //
        // Returns the result string (script output, or "ERROR: ..."
        // on failure).
        public static string runScript(string sFilePath, object frm, object db)
        {
            string sExt = System.IO.Path.GetExtension(sFilePath).ToLowerInvariant();
            string sBody;
            try { sBody = System.IO.File.ReadAllText(sFilePath); }
            catch (Exception ex) { return "ERROR: could not read " + sFilePath + ": " + ex.Message; }

            switch (sExt)
            {
                case ".js":
                    return runJScript(sBody, frm, db);
                case ".sql":
                    return runSqlBatch(sBody, db);
                case ".dbdo":
                    return runDuoBatch(sBody, frm, db);
                default:
                    // Unsupported extension. Return the file contents
                    // verbatim so a user can still inspect a stray
                    // file's body via the picker, but with a clear
                    // marker that no execution happened.
                    return "(unsupported extension '" + sExt + "'; showing file contents)\n\n" + sBody;
            }
        }

        // evaluateExpression: run a single expression or snippet
        // through the JScript .NET engine and return its result -- the
        // inline counterpart to runScript, which reads a saved file.
        // Used by the Evaluate Expression command , which hands the engine a one-off expression
        // rather than a script file. The current window and table flow
        // through to the engine exactly as for Invoke Script.
        public static string evaluateExpression(string sBody, object frm, object db)
        {
            return runJScript(sBody ?? "", frm, db);
        }

        // runJScript: invoke DbDo.JS.runScript via reflection so we
        // don't take a compile-time dependency on the JScript
        // assembly's namespace from C#. We use Assembly.LoadFrom
        // with the full path rather than Assembly.Load("DbDo")
        // because the running EXE is also named DbDo and a
        // simple-name load would resolve to it instead.
        private static string runJScript(string sBody, object frm, object db)
        {
            try
            {
                string sExePath = System.Reflection.Assembly.GetExecutingAssembly().Location;
                string sDllPath = System.IO.Path.Combine(
                    System.IO.Path.GetDirectoryName(sExePath) ?? "",
                    "DbDo.dll");
                System.Reflection.Assembly asm = System.Reflection.Assembly.LoadFrom(sDllPath);
                Type jsType = asm.GetType("DbDo.JS");
                if (jsType == null) return "ERROR: DbDo.JS type not found in DbDo.dll";
                System.Reflection.MethodInfo methodInfo = jsType.GetMethod("runScript",
                    new Type[] { typeof(string), typeof(object), typeof(object) });
                if (methodInfo == null) return "ERROR: DbDo.JS.runScript(string, object, object) not found";
                object result = methodInfo.Invoke(null, new object[] { sBody, frm, db });
                return result != null ? result.ToString() : "";
            }
            catch (Exception ex) { return "ERROR: " + ex.Message; }
        }

        // runSqlBatch: split the body on semicolons that end a
        // statement (semicolons inside quoted strings are ignored)
        // and run each non-empty statement through db.invokeSql.
        // Output from every statement is concatenated. SELECT
        // results, DML row counts, and PRAGMA output all flow
        // through the same StringWriter.
        //
        // Lines starting with '--' (SQL line comment) or wholly
        // empty are dropped before splitting; this lets users
        // sprinkle '-- description: ...' lines at the top of a .sql
        // file without confusing the parser.
        private static string runSqlBatch(string sBody, object db)
        {
            DbDoManager mgr = db as DbDoManager;
            if (mgr == null) return "ERROR: no database manager available";
            if (!mgr.isOpen()) return "ERROR: no database open";

            // Strip whole-line SQL comments before splitting on ';'.
            // Inline -- comments inside a statement are NOT stripped
            // because SQLite handles them itself.
            System.Text.StringBuilder sbStripped = new System.Text.StringBuilder();
            foreach (string sLine in sBody.Split('\n'))
            {
                string sTrim = sLine.TrimStart();
                if (sTrim.StartsWith("--")) continue;
                sbStripped.AppendLine(sLine);
            }
            string[] aStatements = splitSqlStatements(sbStripped.ToString());

            System.IO.StringWriter sw = new System.IO.StringWriter();
            int iCount = 0;
            foreach (string sStmt in aStatements)
            {
                string sTrim = sStmt.Trim();
                if (sTrim.Length == 0) continue;
                iCount++;
                try
                {
                    if (iCount > 1) sw.WriteLine();
                    sw.WriteLine("-- Statement " + iCount + " --");
                    int iAffected = mgr.invokeSql(sTrim, sw);
                    if (iAffected >= 0)
                        sw.WriteLine("(rows affected: " + iAffected + ")");
                }
                catch (Exception ex)
                {
                    sw.WriteLine("ERROR on statement " + iCount + ": " + ex.Message);
                    sw.WriteLine("Aborting batch.");
                    break;
                }
            }
            return sw.ToString();
        }

        // splitSqlStatements: split a SQL batch on top-level ';'
        // boundaries. Semicolons inside single-quoted strings are
        // preserved (a literal "Hello; world" must not break a
        // statement). Double-dash inline comments are stripped to
        // end-of-line. Block comments /* ... */ are stripped.
        // Returns an array of statements WITHOUT trailing
        // semicolons.
        private static string[] splitSqlStatements(string sBatch)
        {
            List<string> lStmts = new List<string>();
            System.Text.StringBuilder sb = new System.Text.StringBuilder();
            int i = 0;
            int n = sBatch.Length;
            while (i < n)
            {
                char c = sBatch[i];
                // Block comment
                if (c == '/' && i + 1 < n && sBatch[i + 1] == '*')
                {
                    int j = sBatch.IndexOf("*/", i + 2);
                    if (j < 0) { i = n; break; }
                    i = j + 2;
                    continue;
                }
                // Line comment
                if (c == '-' && i + 1 < n && sBatch[i + 1] == '-')
                {
                    int j = sBatch.IndexOf('\n', i + 2);
                    if (j < 0) { i = n; break; }
                    i = j + 1;
                    continue;
                }
                // Single-quoted string: copy through, preserving
                // embedded '' as the SQL escape for a literal quote.
                if (c == '\'')
                {
                    sb.Append(c);
                    i++;
                    while (i < n)
                    {
                        char d = sBatch[i];
                        sb.Append(d);
                        if (d == '\'' && i + 1 < n && sBatch[i + 1] == '\'') { sb.Append(sBatch[++i]); i++; continue; }
                        i++;
                        if (d == '\'') break;
                    }
                    continue;
                }
                // Statement boundary
                if (c == ';')
                {
                    lStmts.Add(sb.ToString());
                    sb.Length = 0;
                    i++;
                    continue;
                }
                sb.Append(c);
                i++;
            }
            if (sb.Length > 0) lStmts.Add(sb.ToString());
            return lStmts.ToArray();
        }

        // runDuoBatch: parse the body line-by-line and dispatch each
        // non-blank, non-comment line through the dot-prompt's
        // dispatcher. The dispatcher's stdout is captured to a
        // StringWriter by temporarily swapping Console.Out around
        // each line; output from all lines is concatenated and
        // returned.
        //
        // Comments: lines starting with '#' or '--' are skipped.
        // Blank lines are skipped. Leading and trailing whitespace
        // is trimmed before dispatch.
        //
        // Error handling: by default an error on any line aborts
        // the batch (the failing line's error message is appended
        // and the rest of the file is not run). A leading '?' on a
        // line marks "continue on error" -- the line runs, the
        // error is captured, but the batch keeps going. This
        // matches the common DOS / batch-file convention.
        //
        // The dispatcher is called via DotPromptHost.runLine, a thin
        // wrapper that exposes the (private) dispatch() method for
        // external callers.
        private static string runDuoBatch(string sBody, object frm, object db)
        {
            System.IO.StringWriter sw = new System.IO.StringWriter();
            System.IO.TextWriter origOut = Console.Out;
            int iLineNo = 0;
            try
            {
                Console.SetOut(sw);
                foreach (string sRawLine in sBody.Split('\n'))
                {
                    iLineNo++;
                    string sLine = sRawLine.Trim();
                    if (sLine.Length == 0) continue;
                    if (sLine.StartsWith("#") || sLine.StartsWith("--")) continue;

                    bool bContinueOnError = false;
                    if (sLine.StartsWith("?"))
                    {
                        bContinueOnError = true;
                        sLine = sLine.Substring(1).TrimStart();
                        if (sLine.Length == 0) continue;
                    }

                    sw.WriteLine("-- Line " + iLineNo + ": " + sLine);
                    try
                    {
                        DotPromptHost.runLine(sLine);
                    }
                    catch (Exception ex)
                    {
                        sw.WriteLine("ERROR on line " + iLineNo + ": " + ex.Message);
                        if (!bContinueOnError)
                        {
                            sw.WriteLine("Aborting batch (use a leading '?' on a line to continue on error).");
                            break;
                        }
                    }
                }
            }
            finally
            {
                Console.SetOut(origOut);
            }
            return sw.ToString();
        }
    }

    // =====================================================================
    // ADODB constants. ADODB is COM, so the interop in this file is
    // late-bound through dynamic. Late binding doesn't carry the
    // type library's enum values, so we name them ourselves. The
    // values come from Microsoft's ADO documentation; they are stable
    // since ADO 2.0 (Windows 2000) and won't change.
    //
    // Listed alphabetically within each group. Naming follows Camel
    // Type for constants: lower-camelCase with a descriptive word
    // (Default, Initial, Mode, Type, Position) replacing the older
    // c_ prefix. The ADO-original names are kept verbatim where they
    // are well-known (CursorLocationEnum values etc.), since coders
    // looking at this file will be reading ADO docs alongside.
    // =====================================================================
    public static class AdoConstants
    {
        // CursorLocationEnum
        public const int adUseClient = 3;     // client-side cursor; gives us bookmarks, sort, filter uniformly across providers
        public const int adUseServer = 2;     // (default; not used here)

        // CursorTypeEnum
        public const int adOpenForwardOnly = 0;
        public const int adOpenKeyset      = 1;
        public const int adOpenDynamic     = 2;
        public const int adOpenStatic      = 3;  // we use this; client-side cursors are always static

        // LockTypeEnum
        public const int adLockReadOnly        = 1;
        public const int adLockPessimistic     = 2;
        public const int adLockOptimistic      = 3;  // we use this for editable views
        public const int adLockBatchOptimistic = 4;

        // CursorOptionEnum (Recordset.Supports). adUpdate is true when
        // the cursor's lock/type permit the Update method at all; we
        // use it to confirm a result is writable before declaring it
        // editable, which also catches the read-only-lock fallback.
        public const int adUpdate = 0x1008000;

        // ConnectModeEnum
        public const int adModeUnknown         = 0;
        public const int adModeRead            = 1;  // read-only mode (we set this when bReadOnly is true)
        public const int adModeWrite           = 2;
        public const int adModeReadWrite       = 3;
        public const int adModeShareDenyRead   = 4;
        public const int adModeShareDenyWrite  = 8;
        public const int adModeShareExclusive  = 12;
        public const int adModeShareDenyNone   = 16;

        // CommandTypeEnum
        public const int adCmdUnknown      = 8;
        public const int adCmdText         = 1;
        public const int adCmdTable        = 2;
        public const int adCmdStoredProc   = 4;
        public const int adCmdTableDirect  = 512;

        // ExecuteOptionEnum
        public const int adExecuteNoRecords = 128;

        // SearchDirectionEnum (for Recordset.Find)
        public const int adSearchForward  = 1;
        public const int adSearchBackward = -1;

        // BookmarkEnum (for Recordset.Find start position)
        public const int adBookmarkCurrent = 0;
        public const int adBookmarkFirst   = 1;
        public const int adBookmarkLast    = 2;

        // PositionEnum
        public const int adPosUnknown = -1;
        public const int adPosBOF     = -2;
        public const int adPosEOF     = -3;

        // GetRowsOptionEnum
        public const int adGetRowsRest = -1;
    }

    // =====================================================================
    // Str: string predicates and small helpers, in the spirit of
    // HomerLib's StringContains / StringEqual / StringEquiv / StringPlural.
    //
    // C# has all of these built in via various overloads of String.*,
    // String.Equals, etc., but reading the code with named predicates is
    // clearer than scattered case-insensitive flag arguments. The "Str"
    // namespace is short on purpose so calls don't overwhelm a line.
    //
    // The constants near the top (space, comma, commaSpace, bar, colon,
    // semicolon, quote) replace magic-string literals throughout the
    // codebase. They're separately useful for distinguishing "comma for
    // SQL" (Str.comma) from "comma-space for display" (Str.commaSpace).
    // =====================================================================
    public static class Str
    {
        // Common literals as named constants -- mirroring HomerLib's
        // xSpace, xComma, xCommaSpace, xBar, xQuote, xColon, xSemicolon.
        public const string space        = " ";
        public const string comma        = ",";
        public const string commaSpace   = ", ";
        public const string bar          = "|";
        public const string colon        = ":";
        public const string semicolon    = ";";
        public const string quote        = "\"";
        public const string apostrophe   = "'";
        public const string newLine      = "\r\n";

        // True for null or empty string. Mirrors HomerLib.IsBlank.
        public static bool isBlank(string s)
        {
            return string.IsNullOrEmpty(s);
        }

        // True for any non-empty string. Mirrors HomerLib.IsNonBlank.
        public static bool isNonBlank(string s)
        {
            return !isBlank(s);
        }

        // Case-sensitive equal. Mirrors HomerLib.StringEqual.
        public static bool equal(string s1, string s2)
        {
            if (s1 == null && s2 == null) return true;
            if (s1 == null || s2 == null) return false;
            return string.Compare(s1, s2, StringComparison.Ordinal) == 0;
        }

        // Case-insensitive equal. Mirrors HomerLib.StringEquiv.
        public static bool equiv(string s1, string s2)
        {
            if (s1 == null && s2 == null) return true;
            if (s1 == null || s2 == null) return false;
            return string.Compare(s1, s2, StringComparison.OrdinalIgnoreCase) == 0;
        }

        // True if sText contains sMatch (case-insensitive by default).
        public static bool contains(string sText, string sMatch)
        {
            if (sText == null || sMatch == null) return false;
            return sText.IndexOf(sMatch, StringComparison.OrdinalIgnoreCase) >= 0;
        }

        public static bool startsWith(string sText, string sLead)
        {
            if (sText == null || sLead == null) return false;
            return sText.StartsWith(sLead, StringComparison.OrdinalIgnoreCase);
        }

        public static bool endsWith(string sText, string sTrail)
        {
            if (sText == null || sTrail == null) return false;
            return sText.EndsWith(sTrail, StringComparison.OrdinalIgnoreCase);
        }

        // Capitalize first letter, leave the rest. "jamal" -> "Jamal".
        public static string capitalize(string sText)
        {
            if (string.IsNullOrEmpty(sText)) return sText;
            return char.ToUpperInvariant(sText[0]) + sText.Substring(1);
        }

        // Capitalize first letter, lowercase the rest. "JAMAL" -> "Jamal".
        public static string properCase(string sText)
        {
            if (string.IsNullOrEmpty(sText)) return sText;
            return char.ToUpperInvariant(sText[0]) + sText.Substring(1).ToLowerInvariant();
        }

        // Singular or plural form. plural("record", 0) -> "0 records".
        // plural("record", 1) -> "1 record". plural("record", 5) -> "5 records".
        public static string plural(string sItem, int iCount)
        {
            if (iCount == 1) return iCount + " " + sItem;
            return iCount + " " + sItem + "s";
        }

        // Join a list with ", " in display style.
        public static string joinDisplay(IEnumerable<string> lItems)
        {
            return string.Join(commaSpace, lItems);
        }

        // Wrap text to a maximum line length. HomerLib.StringWrap
        // equivalent. Used for long descriptive text in Show-Object.
        public static string wrap(string sText, int iMaxLine)
        {
            if (string.IsNullOrEmpty(sText) || iMaxLine <= 0) return sText ?? "";
            StringBuilder sbOut = new StringBuilder();
            foreach (string sLine in sText.Split('\n'))
            {
                string sCur = sLine.TrimEnd('\r');
                while (sCur.Length > iMaxLine)
                {
                    int iBreak = sCur.LastIndexOf(' ', iMaxLine);
                    if (iBreak <= 0) iBreak = iMaxLine;
                    sbOut.AppendLine(sCur.Substring(0, iBreak));
                    sCur = sCur.Substring(iBreak).TrimStart();
                }
                sbOut.AppendLine(sCur);
            }
            return sbOut.ToString().TrimEnd('\r', '\n');
        }
    }

    // =====================================================================
    // Metadata: convention-based names for the bookkeeping columns that
    // appear on every well-formed DbDo schema (modeled on Pax.db and the
    // older AccAudit schema).
    //
    // These are not enforced -- a SQLite database without them still works
    // -- but when present, DbDo treats them specially:
    //
    //   1. The Edit-Record dialog hides metadata fields by default and
    //      shows only 'distinct' (substantive) fields. Use the "more"
    //      checkbox to expose them.
    //
    //   2. New-Record skips them entirely; the database fills them in via
    //      DEFAULT current_timestamp on added/edited/observed and
    //      DEFAULT 0 on marked.
    //
    //   3. Show-Object groups them in a separate "metadata" section at
    //      the bottom of the field list, so screen readers reach them
    //      after the substantive content.
    //
    //   4. Set-Mark / Clear-Mark work against the 'marked' column and
    //      do nothing if the table lacks one.
    //
    //   5. The view_ prefix on a table name is the convention DbDo uses
    //      to distinguish views from tables in the schema tree. ADOX
    //      Catalog.Tables enumeration returns both as the same kind of
    //      object; we filter on the Type property and on the prefix.
    //
    // Tables and field names are lower snake_case by user convention,
    // without Hungarian prefix -- the case where database identifiers do
    // NOT follow Camel Type because they are persisted, named once, and
    // memorized by anyone querying the database. Internal C# variables
    // that hold these strings still get Camel Type prefix (s for string).
    // =====================================================================
    public static class Metadata
    {
        // DbDo's standard-field convention. Verified against
        // Pax.db's seven canonical tables (apps, screens, controls,
        // rules, issues, states, lookups) and against dbDot.vbs's
        // fillFieldArrays (line 318): the column names suppressed
        // from the default data-list view are exactly:
        //
        //   <table>_id, added, edited, marked, look, prm
        //
        // 'look' and 'prm' are stored-generated (PRAGMA table_xinfo
        // hidden=3); the calculated-column auto-hide rule would
        // catch them even without the by-name rule, but the by-name
        // rule is faster and works on providers that don't expose
        // generated-column metadata.
        //
        // 'marked' is hidden from the data list but surfaces in the
        // status bar only when the current row's value is true (see
        // updateStatusBar).
        //
        // 'observed', 'method', 'notes', 'tags' -- although standard
        // by convention -- are SHOWN. They carry user-visible content
        // (data-source timestamps, collection method, free-text
        // annotation, comma-separated keywords) and the user expects
        // them in the row scan.
        //
        // All distinct fields are shown unless the schema marks them
        // as calculated (stored or virtual generated), in which case
        // they join the hidden set automatically.
        // StandardHiddenColumns: columns hidden from the listview by
        // default. The user reaches them via the Say-X family
        // (Say-Added, Say-Edited, Say-Url, Say-Tags, Say-Notes,
        // Say-Look, Say-Id) and edits them via the Set-Record dialog
        // (F2 Edit Record), which shows the FULL field set including
        // hidden columns.
        //
        // 'tags', 'notes', and 'url' joined the hidden set in v1.0.68
        // for the same reason 'look' and 'prm' are hidden: they're
        // "extended" data per row that bloats the listview if shown
        // unconditionally. The user can override via the Select
        // Columns command (Alt+S) and the override persists per
        // table via the DbDo.inix t<n>_selectlist entry.
        public static readonly string[] StandardHiddenColumns = new string[]
        {
            "added",
            "edited",
            "marked",
            "look",
            "prm",
            "prm",
            "url",
            "tags",
            "notes"
        };

        // No "force visible" overrides at present. The default is:
        // visible unless StandardHiddenColumns or the calculated-
        // column rule applies.
        public static readonly string[] StandardVisibleColumns = new string[] { };

        // Standard fields of any kind (hidden + conventional
        // visible). Used by Set-Record's "show more" toggle to
        // distinguish the conventional columns from a table's
        // distinct (substantive) columns.
        // ADMIN columns: maintained by the program and the database
        // (defaults, triggers, generated expressions, mark commands),
        // never presented in the New Record or Edit Record dialogs.
        // The primary key (bare "id" or any "*_id") is admin too,
        // handled by isAdminColumn's suffix logic. By contrast,
        // notes, tags, and url are EDITABLE standard fields and
        // appear in the dialogs like any substantive column.
        public static readonly string[] AdminColumns = new string[]
        {
            "added",
            "edited",
            "look",
            "marked",
            "method",
            "observed",
            "prm",
            "prm"
        };

        public const string PrimaryKeySuffix = "_id";
        // Centralized standard-column names. Code that references
        // these calculated/auto-managed columns should use the
        // constants here instead of string literals so a future
        // rename only needs to change the constant value.
        public const string AddedColumn    = "added";
        public const string EditedColumn   = "edited";
        public const string LookColumn     = "look";
        public const string MarkedColumn   = "marked";
        public const string NotesColumn    = "notes";
        public const string TagsColumn     = "tags";
        // PrimeColumn: the abbreviated name for the primary-key
        // expression column. Every database uses 'prm' -- a STORED
        // generated concatenation of a record's prime fields. There is
        // no legacy alternative; the older 'unq' name has been retired.
        public const string PrimeColumn    = "prm";
        public const string UrlColumn      = "url";

        // Standard date-sort column resolution. dbDot's standard for
        // "when did this row last change" is 'edited' (the
        // application-level "last edit" timestamp). 'observed' is
        // also a timestamp but records "when was this entity last
        // seen by the data-collection method" -- a different
        // semantic. 'added' is the row-creation timestamp; useful as
        // a fallback when 'edited' is absent.
        public static readonly string[] DateSortColumns = new string[]
        {
            "edited",
            "added",
            "observed"
        };

        // True if a column is hidden by the standard-fields rule
        // (not counting the calculated-column rule, which is checked
        // separately because it depends on schema metadata, not on
        // the column name).
        public static bool isStandardHidden(string sColumn, string sTable)
        {
            if (string.IsNullOrEmpty(sColumn)) return false;
            string sLower = sColumn.ToLowerInvariant();
            foreach (string sN in StandardHiddenColumns)
                if (sLower == sN) return true;
            // Key columns: any column ending in '_id' (primary or
            // foreign key by DbDo convention) and bare 'id'. These
            // hold integer references that don't carry meaningful
            // display value -- the user navigates between related
            // rows via Show-Related (Control+J) rather than reading
            // raw key values. Hides:
            //   - <table>_id (primary key, e.g. app_id, rule_id)
            //   - other *_id columns (foreign keys, e.g. screen_id
            //     in the controls table, audit_id in issues)
            //   - the literal column 'id'
            if (sLower == "id") return true;
            if (sLower.EndsWith(PrimaryKeySuffix)) return true;
            return false;
        }

        // True if a column is part of the standard-visible set.
        // Such columns are shown even if they would otherwise be
        // filtered (they don't override calculated-column hiding,
        // however -- if 'notes' were somehow a computed column the
        // calculated rule wins).
        public static bool isStandardVisible(string sColumn)
        {
            if (string.IsNullOrEmpty(sColumn)) return false;
            string sLower = sColumn.ToLowerInvariant();
            foreach (string sN in StandardVisibleColumns)
                if (sLower == sN) return true;
            return false;
        }

        // isAdminColumn: true for the program-maintained fields that
        // the record dialogs never present -- the primary key, added,
        // edited, look, prm, marked (plus the legacy observed and
        // method). Everything else, including notes/tags/url, is an
        // editable field.
        public static bool isAdminColumn(string sColumn, string sTable)
        {
            if (string.IsNullOrEmpty(sColumn)) return false;
            string sLower = sColumn.ToLowerInvariant();
            if (sLower == "id") return true;
            foreach (string sBk in AdminColumns)
                if (sLower == sBk) return true;
            if (sLower.EndsWith(PrimaryKeySuffix))
            {
                if (!string.IsNullOrEmpty(sTable))
                {
                    string sExpected = sTable.ToLowerInvariant() + PrimaryKeySuffix;
                    if (sLower == sExpected) return true;
                }
                return true;
            }
            return false;
        }

        // isDistinctColumn: the "distinct" summary columns that
        // distinctly identify a row -- the human-readable 'look'
        // summary and the 'prm' unique-key expression (plus the legacy
        // 'prm'). These are the default listview ("select") set: opening
        // a table shows look + prm unless the user has saved a different
        // SelectFields list. They are computed columns, so they are not
        // editable and not admin; they form their own category between
        // the leading admin keys and the editable data fields.
        public static bool isDistinctColumn(string sColumn)
        {
            if (string.IsNullOrEmpty(sColumn)) return false;
            string sLower = sColumn.ToLowerInvariant();
            return sLower == LookColumn || sLower == PrimeColumn;
        }


        // display label, mirroring the manual labels in DbDialog.cfg
        // (e.g. "First_Name" -> "First Name", "app_id" -> "App ID").
        //
        // Special cases:
        //   - Words ending the suffix '_id' become "ID" rather than "Id".
        //   - Two-letter all-lowercase words ('os', 'cd', 'pc', 'ui')
        //     are uppercased to convention.
        //   - Pure underscores become spaces; all other characters are
        //     left alone except for the leading-letter capitalization.
        //
        // Used by Show-Object and the Edit dialogs when displaying
        // labels for users. The user can override these by providing a
        // sidecar <basename>.ini file with [TableName] FieldLabels=...
        // (DbDialog.cfg style); for now, we always compute them.
        public static string fieldLabel(string sColumn)
        {
            if (string.IsNullOrEmpty(sColumn)) return "";
            string[] aParts = sColumn.Split('_');
            StringBuilder sbOut = new StringBuilder();
            for (int i = 0; i < aParts.Length; i++)
            {
                if (i > 0) sbOut.Append(' ');
                string sPart = aParts[i];
                if (string.IsNullOrEmpty(sPart)) continue;
                // Common abbreviations -> uppercase.
                string sLower = sPart.ToLowerInvariant();
                if (sLower == "id" || sLower == "os" || sLower == "url"
                    || sLower == "ui" || sLower == "pc" || sLower == "ip"
                    || sLower == "html" || sLower == "xml" || sLower == "json"
                    || sLower == "csv" || sLower == "sql" || sLower == "api")
                {
                    sbOut.Append(sPart.ToUpperInvariant());
                }
                else
                {
                    sbOut.Append(char.ToUpperInvariant(sPart[0]));
                    if (sPart.Length > 1)
                        sbOut.Append(sPart.Substring(1).ToLowerInvariant());
                }
            }
            return sbOut.ToString();
        }
    }

    // =====================================================================
    // InixCodec: read and write .inix files. Inix is DbDo's extended .ini
    // format -- a friendlier serialization than JSON or TOML for both
    // configuration data and tabular data, designed to be readable and
    // editable in any plain-text editor.
    //
    // SYNTAX
    //
    // Sections: [SectionName] on a line. Sections in order; the file is
    // a list of dictionaries. If the first line of the file is a key=value
    // pair without a section header, an implicit "[Global]" section is
    // assumed.
    //
    // Keys and values: key=value on a line. Whitespace around key and
    // value is trimmed. Empty value (key=) starts a multi-line value
    // that runs until the next key, the next section header, or EOF.
    //
    // Multi-line values, plain form:  key=  followed by lines verbatim
    // until a line that contains '=' (a new key) or '[' (a new section)
    // or end-of-file. Cannot contain lines whose first non-whitespace
    // character is '=' or '['.
    //
    // Multi-line values, fenced form:  key=`  on a line by itself, then
    // value lines verbatim, then a single `  on a line by itself to
    // close. Python-style key="""  ...  """ is equivalent. The fenced
    // form is the reliable way to embed '=' or '[' characters in a value.
    //
    // Comments: lines whose first non-whitespace character is ';' are
    // ignored at the top level. A section can be commented out with
    // [;SectionName] -- the whole section's body is skipped.
    //
    // Anonymous sections: [] (or just [Record], with optional NNN suffix)
    // implies a list-of-records table. Each anonymous or [RecordNNN]
    // section is one row. The keys of the first such section are the
    // column headers; subsequent sections may include any subset.
    //
    // Encoding: UTF-8 with BOM. Line terminators: CRLF. Verbatim
    // multi-line content preserves whatever line endings the source has.
    //
    // EXAMPLES
    //
    // Configuration form (dictionary of dictionaries):
    //
    //   ; Top-level "global" keys are an implicit [Global] section.
    //   IgnoreCase = True
    //
    //   [Replace dog with cat]
    //   find = dog
    //   replace = Cat
    //
    //   [Replace sheep with goat]
    //   find = Sheep
    //   replace = goat
    //
    // Table form (list of records):
    //
    //   [Record01]
    //   name = Alice
    //   notes =
    //   Alice's notes
    //   over two lines.
    //
    //   [Record02]
    //   name = Bob
    //   notes = single-line note
    //
    // The leading-zero width on [RecordNNN] section names matches the
    // record count: 5 records -> [Record1..5], 99 records -> [Record01..99],
    // 999 records -> [Record001..999]. ASCII sort of section names then
    // matches numeric order.
    // =====================================================================
    public static class InixCodec
    {
        // A single key/value pair, preserving order within a section.
        public class Pair
        {
            public string Key;
            public string Value;
            public Pair(string sK, string sV) { Key = sK; Value = sV; }
        }

        // A single section: name plus ordered list of pairs. Order of
        // pairs is preserved on round-trip.
        public class Section
        {
            public string Name;
            public List<Pair> Pairs = new List<Pair>();
            public Section(string sName) { Name = sName; }

            // Lookup is case-insensitive on the key (matches the .ini
            // convention). Returns null if the key is absent.
            public string get(string sKey)
            {
                foreach (Pair p in Pairs)
                    if (string.Equals(p.Key, sKey, StringComparison.OrdinalIgnoreCase))
                        return p.Value;
                return null;
            }

            // getArray: the value read as an array of items -- the read
            // side of the .inix array convention. A value that spans
            // multiple lines yields one item per line; a single-line value
            // containing commas is split on commas; any other non-blank
            // value is a one-item array. Surrounding whitespace and blank
            // items are dropped. Returns an empty list when the key is
            // absent or blank.
            public List<string> getArray(string sKey)
            {
                List<string> l = new List<string>();
                string sRaw = get(sKey);
                if (string.IsNullOrEmpty(sRaw)) return l;
                string sNorm = sRaw.Replace("\r\n", "\n").Replace("\r", "\n");
                string[] aParts;
                if (sNorm.IndexOf('\n') >= 0)     aParts = sNorm.Split('\n');
                else if (sNorm.IndexOf(',') >= 0) aParts = sNorm.Split(',');
                else                              aParts = new string[] { sNorm };
                foreach (string s in aParts)
                {
                    string sT = (s ?? "").Trim();
                    if (sT.Length > 0) l.Add(sT);
                }
                return l;
            }

            // Returns the full ordered list of keys.
            public List<string> keys()
            {
                List<string> l = new List<string>();
                foreach (Pair p in Pairs) l.Add(p.Key);
                return l;
            }
        }

        // Parse an .inix file. The returned list of sections preserves
        // file order. Implicit "[Global]" is created if the file starts
        // with key=value pairs before any explicit section header. The
        // returned list is empty if the file has no sections and no
        // top-level keys.
        public static List<Section> read(string sPath)
        {
            if (string.IsNullOrEmpty(sPath)) throw new ArgumentException("InixCodec.read requires a path.");
            if (!File.Exists(sPath)) throw new FileNotFoundException(".inix file not found.", sPath);
            string[] aLines = File.ReadAllLines(sPath, new UTF8Encoding(true));
            return parseLines(aLines);
        }

        // fileTask: the declared purpose of an .inix file, read from the
        // "FileTask" key of its implicit [Global] section -- e.g. "report"
        // for a report definition or "transfer" for a Transfer-Import map.
        // Returns "" when the file declares no FileTask, is unreadable, or
        // is absent. The value is trimmed and lower-cased so callers can
        // compare it directly. This is what lets a command that offers a
        // pick-list of .inix files show only the files whose task matches
        // the command (so a report picker never lists a transfer map or a
        // settings file, and vice versa).
        public static string fileTask(string sPath)
        {
            try { return fileTask(read(sPath)); }
            catch { return ""; }
        }

        // fileTask overload for callers that have already parsed the file,
        // so the FileTask can be read without a second pass over the disk.
        public static string fileTask(List<Section> lSections)
        {
            if (lSections == null) return "";
            foreach (Section s in lSections)
                if (string.Equals(s.Name, "Global", StringComparison.OrdinalIgnoreCase))
                {
                    string sValue = s.get("FileTask");
                    return string.IsNullOrEmpty(sValue) ? "" : sValue.Trim().ToLowerInvariant();
                }
            return "";
        }

        // parseLines: the actual state machine. Separated from read so
        // unit tests can drive it without disk I/O.
        public static List<Section> parseLines(string[] aLines)
        {
            List<Section> lSections = new List<Section>();
            Section secCurrent = null;       // null means "no section yet"
            string sPendingKey = null;       // multi-line value accumulator state
            StringBuilder sbValue = null;
            string sFenceToken = null;       // "`" or "\"\"\"" when inside a fenced value
            bool bSkipSection = false;       // section commented out via [;Name]

            // Helper to commit a pending multi-line value to the
            // current section. Strips the LAST trailing newline so that
            // the value doesn't carry an extra CRLF from the closing
            // line break.
            Action commitPending = delegate()
            {
                if (sPendingKey == null) return;
                string sFinal = (sbValue != null) ? sbValue.ToString() : "";
                // Drop one trailing newline if present.
                if (sFinal.EndsWith("\r\n")) sFinal = sFinal.Substring(0, sFinal.Length - 2);
                else if (sFinal.EndsWith("\n")) sFinal = sFinal.Substring(0, sFinal.Length - 1);
                if (secCurrent != null && !bSkipSection)
                    secCurrent.Pairs.Add(new Pair(sPendingKey, sFinal));
                sPendingKey = null;
                sbValue = null;
                sFenceToken = null;
            };

            for (int i = 0; i < aLines.Length; i++)
            {
                string sRaw = aLines[i] ?? "";

                // Fenced multi-line value: accept the line VERBATIM
                // until a closing fence appears on a line by itself.
                if (sFenceToken != null)
                {
                    if (sRaw.Trim() == sFenceToken)
                    {
                        // Closing fence: commit and exit fenced mode.
                        commitPending();
                        continue;
                    }
                    if (sbValue.Length > 0) sbValue.Append("\r\n");
                    sbValue.Append(sRaw);
                    continue;
                }

                string sTrim = sRaw.Trim();

                // Plain multi-line value: accumulate lines until we see
                // a line that looks like a section header or a key=
                // line. The plain form requires that continuation lines
                // do NOT start with '[' or contain '=' as a meaningful
                // separator. Comment lines (starting with ';') in plain-
                // multi-line mode are treated as ordinary value content.
                if (sPendingKey != null)
                {
                    bool bLooksLikeSection = sTrim.StartsWith("[") && sTrim.EndsWith("]");
                    bool bLooksLikeKey = !sTrim.StartsWith(";")
                                         && sTrim.IndexOf('=') > 0
                                         && !looksLikePartOfValue(sTrim);
                    if (bLooksLikeSection || bLooksLikeKey)
                    {
                        commitPending();
                        // Fall through to process this line as the new
                        // section or key.
                    }
                    else
                    {
                        if (sbValue.Length > 0) sbValue.Append("\r\n");
                        sbValue.Append(sRaw);
                        continue;
                    }
                }

                // Section header.
                if (sTrim.StartsWith("[") && sTrim.EndsWith("]") && sTrim.Length >= 2)
                {
                    string sInner = sTrim.Substring(1, sTrim.Length - 2);
                    bSkipSection = sInner.StartsWith(";");
                    if (bSkipSection)
                    {
                        // We still create a section with an empty name
                        // and no pairs, but mark it skipped so we don't
                        // store anything? Simpler: just don't create a
                        // section at all -- the comment-out is total.
                        secCurrent = null;
                        continue;
                    }
                    if (sInner.Length == 0)
                    {
                        // Anonymous section in a list -- assign a
                        // Record<N> name based on position. The N is
                        // (count of unnamed/recordNNN sections + 1)
                        // counting only data-bearing sections.
                        int iN = countAnonymousOrRecord(lSections) + 1;
                        sInner = "Record" + iN;
                    }
                    secCurrent = new Section(sInner);
                    lSections.Add(secCurrent);
                    continue;
                }

                // Skip comment and blank lines outside a value.
                if (sTrim.Length == 0) continue;
                if (sTrim.StartsWith(";") || sTrim.StartsWith("#")) continue;
                if (bSkipSection) continue;

                // Key=Value line.
                int iEq = sRaw.IndexOf('=');
                if (iEq <= 0) continue;  // not a valid key=value
                string sKey = sRaw.Substring(0, iEq).Trim();
                string sVal = sRaw.Substring(iEq + 1);

                // If no section opened yet, create an implicit
                // [Global] section.
                if (secCurrent == null)
                {
                    secCurrent = new Section("Global");
                    lSections.Add(secCurrent);
                }

                string sValTrim = sVal.Trim();
                // Fenced multi-line starts with key=` or key=""" on a
                // line by itself (the equals is part of the line; the
                // fence token is the entire remainder).
                if (sValTrim == "`" || sValTrim == "\"\"\"")
                {
                    sPendingKey = sKey;
                    sbValue = new StringBuilder();
                    sFenceToken = sValTrim;
                    continue;
                }
                // Plain multi-line starts with key= (empty value on
                // this line). The accumulator gathers subsequent lines
                // until the next key= or section header.
                if (sValTrim.Length == 0)
                {
                    sPendingKey = sKey;
                    sbValue = new StringBuilder();
                    continue;
                }
                // Single-line value.
                secCurrent.Pairs.Add(new Pair(sKey, sValTrim));
            }

            // EOF: commit any open multi-line value.
            commitPending();
            return lSections;
        }

        // looksLikePartOfValue: a heuristic to keep the plain-multi-line
        // parser from prematurely closing a value when a continuation
        // line happens to contain an '=' character. We only treat
        // 'x=y' as a key if the part before '=' is a plausible
        // identifier (letters, digits, underscores). For values that
        // contain natural-language text with arbitrary '=', users
        // should use the fenced form.
        private static bool looksLikePartOfValue(string sLine)
        {
            int iEq = sLine.IndexOf('=');
            if (iEq <= 0) return true;
            string sBefore = sLine.Substring(0, iEq).Trim();
            if (sBefore.Length == 0) return true;
            foreach (char c in sBefore)
            {
                if (!char.IsLetterOrDigit(c) && c != '_' && c != ' ' && c != '-')
                    return true;
            }
            return false;
        }

        private static int countAnonymousOrRecord(List<Section> l)
        {
            int n = 0;
            foreach (Section s in l)
                if (s.Name != null && s.Name.StartsWith("Record",
                    StringComparison.OrdinalIgnoreCase)) n++;
            return n;
        }

        // ----------------------------------------------------------------
        // Write helpers. Output is UTF-8 with BOM and CRLF line endings,
        // matching the rest of DbDo's text-file conventions.
        // ----------------------------------------------------------------

        // Choose the right fence for a value: prefer plain multi-line
        // (no fence) when the value has no '=' or '[' that would
        // confuse the plain parser; prefer ` when '"""' is in the
        // value; prefer """ when "`" is in the value; fall back to
        // ` as a default for fenced values.
        private static string chooseFence(string sValue)
        {
            if (sValue == null) return null;
            bool bHasEq     = sValue.IndexOf('=') >= 0;
            bool bHasBkt    = sValue.IndexOf('[') >= 0;
            bool bMultiline = sValue.IndexOf('\n') >= 0 || sValue.IndexOf('\r') >= 0;
            if (!bMultiline && !bHasEq && !bHasBkt) return null;  // single-line literal OK
            if (!bMultiline) return "`";  // single-line but with = or [ -> fence it for safety
            // Multi-line. Choose a fence not present as a sole line.
            bool bBacktickFree = !containsSoleLine(sValue, "`");
            bool bTriquoteFree = !containsSoleLine(sValue, "\"\"\"");
            if (bBacktickFree) return "`";
            if (bTriquoteFree) return "\"\"\"";
            // Both candidate fences collide. Backtick is rare in
            // real-world text; prefer it and hope.
            return "`";
        }

        private static bool containsSoleLine(string sValue, string sToken)
        {
            // Split on \n; a "sole line" is one whose trim equals the token.
            int i = 0;
            while (i < sValue.Length)
            {
                int j = sValue.IndexOf('\n', i);
                int end = (j < 0) ? sValue.Length : j;
                string sLine = sValue.Substring(i, end - i).TrimEnd('\r').Trim();
                if (sLine == sToken) return true;
                i = (j < 0) ? sValue.Length : j + 1;
            }
            return false;
        }

        // writeAsConfig: serialize a list of named sections as an
        // .inix configuration file. Sections are written in the order
        // given; pairs within each section in the order given.
        public static void writeAsConfig(string sPath, List<Section> lSections)
        {
            if (string.IsNullOrEmpty(sPath)) throw new ArgumentException("writeAsConfig requires a path.");
            if (lSections == null) throw new ArgumentNullException("lSections");
            using (StreamWriter w = new StreamWriter(sPath, false, new UTF8Encoding(true)))
            {
                w.NewLine = "\r\n";
                bool bFirst = true;
                foreach (Section sec in lSections)
                {
                    if (sec == null) continue;
                    if (!bFirst) w.WriteLine();
                    bFirst = false;
                    if (!string.IsNullOrEmpty(sec.Name)
                        && !string.Equals(sec.Name, "Global", StringComparison.OrdinalIgnoreCase))
                        w.WriteLine("[" + sec.Name + "]");
                    writePairs(w, sec.Pairs);
                }
            }
        }

        // writeAsTable: serialize a sequence of records as an .inix
        // list-of-records file. The leading-zero width on the section
        // name [RecordNNN] is chosen so ASCII sort matches numeric
        // order. Pairs within each record are written in the order
        // they appear in lFields; values missing from a record are
        // simply omitted (no "key=" with empty value).
        public static void writeAsTable(string sPath, List<string> lFields,
                                        List<Dictionary<string, string>> lRows)
        {
            if (string.IsNullOrEmpty(sPath)) throw new ArgumentException("writeAsTable requires a path.");
            if (lFields == null || lRows == null) throw new ArgumentNullException();
            int n = lRows.Count;
            int iWidth = (n == 0) ? 1 : (int)Math.Floor(Math.Log10(n)) + 1;
            string sFmt = "D" + iWidth;
            using (StreamWriter w = new StreamWriter(sPath, false, new UTF8Encoding(true)))
            {
                w.NewLine = "\r\n";
                for (int i = 0; i < n; i++)
                {
                    if (i > 0) w.WriteLine();
                    w.WriteLine("[Record" + (i + 1).ToString(sFmt) + "]");
                    Dictionary<string, string> dRow = lRows[i];
                    if (dRow == null) continue;
                    List<Pair> lPairs = new List<Pair>();
                    foreach (string sF in lFields)
                    {
                        string sV;
                        if (!dRow.TryGetValue(sF, out sV)) continue;
                        if (sV == null) continue;
                        lPairs.Add(new Pair(sF, sV));
                    }
                    writePairs(w, lPairs);
                }
            }
        }

        private static void writePairs(StreamWriter w, List<Pair> lPairs)
        {
            foreach (Pair p in lPairs)
            {
                string sKey = p.Key ?? "";
                string sVal = p.Value ?? "";
                string sFence = chooseFence(sVal);
                if (sFence == null)
                {
                    // Single-line value, safe to write inline.
                    w.WriteLine(sKey + " = " + sVal);
                }
                else
                {
                    // Fenced form, even if value happens to be single
                    // line -- chooseFence returns non-null when the
                    // single line contains '=' or '['.
                    w.WriteLine(sKey + "=" + sFence);
                    // Write value lines verbatim. Normalize line
                    // endings to CRLF so the output is a Windows file.
                    string sNormalized = sVal.Replace("\r\n", "\n").Replace("\r", "\n");
                    foreach (string sLn in sNormalized.Split('\n'))
                        w.WriteLine(sLn);
                    w.WriteLine(sFence);
                }
            }
        }

        // writeValue: surgically set, replace, or remove ONE key in an
        // .inix file, preserving every comment and every other line --
        // unlike writeAsConfig, which rewrites the whole file and
        // would drop comments. Used for the per-user settings file,
        // where the shipped template's documentation comments must
        // survive machine writes.
        //
        // Inix-aware in both directions: a value containing a newline
        // is written in the fenced form (key=` ... `), an existing
        // fenced value is replaced or removed as a whole block, and
        // the scan skips over fenced blocks so a key= line INSIDE a
        // fenced value is never mistaken for a real key. Pass an
        // empty value to remove the key. Returns false on I/O failure
        // so callers can log it (this class stays log-independent).
        public static bool writeValue(string sPath, string sSection, string sKey, string sValue)
        {
            string sHeader = "[" + sSection + "]";
            List<string> lLines = new List<string>();
            if (File.Exists(sPath))
            {
                try { lLines.AddRange(File.ReadAllLines(sPath, new UTF8Encoding(true))); } catch { return false; }
            }

            int iSectionEnd = -1, iSectionStart = -1;
            for (int i = 0; i < lLines.Count; i++)
            {
                string sTrim = lLines[i].Trim();
                if (sTrim.Equals(sHeader, StringComparison.OrdinalIgnoreCase))
                {
                    iSectionStart = i;
                    iSectionEnd = lLines.Count;
                    for (int j = i + 1; j < lLines.Count; j++)
                    {
                        string sJ = lLines[j].Trim();
                        if (sJ.StartsWith("[")) { iSectionEnd = j; break; }
                    }
                    break;
                }
            }

            // Render the new value as one or more lines: fenced when
            // it spans lines or itself contains '=' or '[' (the cases
            // where the plain form is unreliable), plain otherwise.
            List<string> lNewLines = new List<string>();
            if (!string.IsNullOrEmpty(sValue))
            {
                bool bFenced = sValue.IndexOf('\n') >= 0
                            || sValue.IndexOf('=') >= 0
                            || sValue.TrimStart().StartsWith("[");
                if (bFenced)
                {
                    // Default to the ` fence; fall back to the triple-quote
                    // fence when the content itself contains a ` (which would
                    // otherwise be mistaken for the closing fence).
                    string sFence = (sValue.IndexOf('`') >= 0) ? "\"\"\"" : "`";
                    lNewLines.Add(sKey + "=" + sFence);
                    string sNormalized = sValue.Replace("\r\n", "\n").Replace("\r", "\n");
                    foreach (string sLn in sNormalized.Split('\n')) lNewLines.Add(sLn);
                    lNewLines.Add(sFence);
                }
                else lNewLines.Add(sKey + " = " + sValue);
            }

            if (iSectionStart < 0)
            {
                if (lLines.Count > 0 && lLines[lLines.Count - 1].Trim().Length > 0) lLines.Add("");
                lLines.Add(sHeader);
                lLines.AddRange(lNewLines);
            }
            else
            {
                int iFound = -1, iFoundEnd = -1;  // inclusive line range of the existing entry
                for (int i = iSectionStart + 1; i < iSectionEnd; i++)
                {
                    string sT = lLines[i].Trim();
                    if (sT.Length == 0) continue;
                    if (sT.StartsWith(";") || sT.StartsWith("#")) continue;
                    int iEq = sT.IndexOf('=');
                    if (iEq <= 0) continue;
                    string sName = sT.Substring(0, iEq).Trim();
                    string sRest = sT.Substring(iEq + 1).Trim();
                    bool bFenceOpen = (sRest == "`" || sRest == "\"\"\"");
                    int iEntryEnd = i;
                    if (bFenceOpen)
                    {
                        iEntryEnd = iSectionEnd - 1;  // unterminated fence: rest of section
                        for (int j = i + 1; j < iSectionEnd; j++)
                            if (lLines[j].Trim() == sRest) { iEntryEnd = j; break; }
                    }
                    if (string.Equals(sName, sKey, StringComparison.OrdinalIgnoreCase))
                    { iFound = i; iFoundEnd = iEntryEnd; break; }
                    i = iEntryEnd;  // skip past a fenced block belonging to another key
                }
                if (iFound >= 0)
                {
                    lLines.RemoveRange(iFound, iFoundEnd - iFound + 1);
                    if (lNewLines.Count > 0) lLines.InsertRange(iFound, lNewLines);
                }
                else if (lNewLines.Count > 0)
                {
                    lLines.InsertRange(iSectionStart + 1, lNewLines);
                }
            }

            try { File.WriteAllLines(sPath, lLines.ToArray()); return true; }
            catch { return false; }
        }

        // writeArrayValue: the write side of the .inix array convention.
        // Stores the items under sKey, choosing the presentation
        // automatically: inline and comma-separated when the items are few
        // (up to six) and short and none contains a space or comma, else
        // one item per line in a fenced block. Reuses writeValue, which
        // selects the ` fence by default and the triple-quote fence when an
        // item contains a `. Blank items are dropped; an empty list clears
        // the key.
        public static bool writeArrayValue(string sPath, string sSection, string sKey, List<string> items)
        {
            List<string> clean = new List<string>();
            if (items != null)
                foreach (string it in items)
                {
                    string s = (it ?? "").Replace("\r\n", " ").Replace("\r", " ").Replace("\n", " ").Trim();
                    if (s.Length > 0) clean.Add(s);
                }
            if (clean.Count == 0) return writeValue(sPath, sSection, sKey, "");

            bool bInline = clean.Count <= 6;
            if (bInline)
            {
                int iLen = 0;
                foreach (string s in clean)
                {
                    if (s.IndexOf(' ') >= 0 || s.IndexOf(',') >= 0 || s.IndexOf('`') >= 0) { bInline = false; break; }
                    iLen += s.Length + 2;
                }
                if (iLen > 80) bInline = false;
            }
            string sValue = bInline ? string.Join(", ", clean.ToArray())
                                    : string.Join("\n", clean.ToArray());
            return writeValue(sPath, sSection, sKey, sValue);
        }
    }

    // =====================================================================
    // DbDoManager: the single source of truth for the current
    // recordset state (current position, filter, sort, bookmarks).
    //
    // Wraps a long-lived ADODB.Connection and a current ADODB.Recordset.
    // All COM calls are late-bound through dynamic, so no Interop.ADODB
    // assembly is required at compile time and the resulting DbDo.exe
    // ships as a single self-contained binary.
    //
    // The recordset is opened CursorLocation = adUseClient and CursorType
    // = adOpenStatic, which guarantees uniform support for Bookmark,
    // Sort, and Filter across SQLite (via SQLite ODBC), Access, Excel,
    // dBASE, and CSV (the last four via the ACE OLE DB Provider).
    //
    // File-extension dispatch in openDatabase() picks the driver:
    //   .db, .sqlite, .sqlite3      -> SQLite ODBC Driver
    //   .mdb, .accdb                -> ACE OLEDB.16.0 (Access)
    //   .xlsx, .xls                 -> ACE OLEDB.16.0 with Excel mode
    //   .dbf or folder              -> ACE OLEDB.16.0 with dBASE IV mode
    //   .csv, .tsv, .tab, .txt      -> ACE OLEDB.16.0 with Text mode
    //
    // Synchronization design: bookmark-survives-sort. Before any
    // operation that re-shapes the recordset (filter change, sort
    // change, requery), we capture oRecordset.Bookmark. After, we
    // assign it back. ADODB's bookmark is opaque but stable across
    // sort and filter -- if the bookmarked row survived, the cursor
    // returns to it; if not, we fall to the first row. This is the
    // pattern dbDot.vbs uses and is the central reason we picked
    // ADODB over rolling our own cursor on top of System.Data.SQLite.
    // =====================================================================
    // JScriptExpr: evaluate a JScript .NET expression at run time. Used
    // by transfer-map imports so a mapping line can reshape a value as
    // it is copied. Inside an expression, $v is the current source
    // field's value and $<name> is any other source field in the same
    // row. The referenced names are bound as JScript vars and the
    // expression is wrapped in a self-invoking function, so it returns a
    // single value. On any error the raw $v is returned, so a bad
    // expression degrades to a plain copy instead of aborting the
    // import. The VsaEngine is created once and reused. JScript .NET
    // ships with every .NET Framework install (the same engine the
    // build already uses via jsc.exe), so this adds no new dependency
    // beyond a /reference:Microsoft.JScript.dll at compile time.
    public static class JScriptExpr
    {
        private static Microsoft.JScript.Vsa.VsaEngine oEngine;
        private static readonly object oLock = new object();

        public static string eval(string sExpr, string sCurrent, Dictionary<string, string> dRow)
        {
            if (string.IsNullOrEmpty(sExpr)) return sCurrent ?? "";
            try
            {
                StringBuilder sbVars = new StringBuilder();
                HashSet<string> hSeen = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
                foreach (System.Text.RegularExpressions.Match m in
                    System.Text.RegularExpressions.Regex.Matches(sExpr, "\\$([A-Za-z_][A-Za-z0-9_]*)"))
                {
                    string sName = m.Groups[1].Value;
                    if (!hSeen.Add(sName)) continue;
                    string sVal;
                    if (string.Equals(sName, "v", StringComparison.OrdinalIgnoreCase)) sVal = sCurrent ?? "";
                    else if (dRow == null || !dRow.TryGetValue(sName, out sVal) || sVal == null) sVal = "";
                    sbVars.Append("var ").Append(sName).Append('=').Append(jsString(sVal)).Append(';');
                }
                string sBody = System.Text.RegularExpressions.Regex.Replace(
                    sExpr, "\\$([A-Za-z_][A-Za-z0-9_]*)", "$1");
                string sProgram = "(function(){" + sbVars + "return (" + sBody + ");})()";
                object oResult = Microsoft.JScript.Eval.JScriptEvaluate(sProgram, engine());
                return (oResult == null) ? "" : Convert.ToString(oResult,
                    System.Globalization.CultureInfo.InvariantCulture);
            }
            catch { return sCurrent ?? ""; }
        }

        private static Microsoft.JScript.Vsa.VsaEngine engine()
        {
            lock (oLock)
            {
                if (oEngine == null) oEngine = Microsoft.JScript.Vsa.VsaEngine.CreateEngine();
                return oEngine;
            }
        }

        // Encode a string as a JScript double-quoted string literal.
        private static string jsString(string s)
        {
            StringBuilder sb = new StringBuilder("\"");
            foreach (char c in (s ?? ""))
            {
                switch (c)
                {
                    case '\\': sb.Append("\\\\"); break;
                    case '"': sb.Append("\\\""); break;
                    case '\n': sb.Append("\\n"); break;
                    case '\r': sb.Append("\\r"); break;
                    case '\t': sb.Append("\\t"); break;
                    default:
                        if (c < ' ') sb.Append("\\u").Append(((int)c).ToString("x4"));
                        else sb.Append(c);
                        break;
                }
            }
            sb.Append('"');
            return sb.ToString();
        }
    }

    // ReportEngine: render a report template band against one record's
    // fields. A band is multi-line text in which $field / ${field}
    // expand to the record's values and {{ jscript-expression }} is
    // evaluated by JScriptExpr (the same engine transfer maps use).
    // {# ... #} is an inline comment. The rendering is line-oriented and
    // mail-merge style: a line that carried a substitution token but came
    // out blank is suppressed (so an absent field leaves no gap) and a
    // surviving data line is trimmed with interior runs of spaces
    // collapsed; a line with no token is emitted verbatim, preserving
    // literal blank lines and Markdown structure.
    public static class ReportEngine
    {
        private static readonly System.Text.RegularExpressions.Regex rxComment =
            new System.Text.RegularExpressions.Regex("\\{#.*?#\\}");
        private static readonly System.Text.RegularExpressions.Regex rxExpr =
            new System.Text.RegularExpressions.Regex("\\{\\{(.*?)\\}\\}");
        private static readonly System.Text.RegularExpressions.Regex rxField =
            new System.Text.RegularExpressions.Regex("\\$\\{(\\w+)\\}|\\$(\\w+)");
        private static readonly System.Text.RegularExpressions.Regex rxPlace =
            new System.Text.RegularExpressions.Regex("\u0000(\\d+)\u0001");
        private static readonly System.Text.RegularExpressions.Regex rxSpaces =
            new System.Text.RegularExpressions.Regex(" {2,}");

        // Render a whole band; returns its lines joined with CRLF (empty
        // when the band is null/blank).
        public static string renderBand(string sBand, Dictionary<string, string> dRow)
        {
            if (string.IsNullOrEmpty(sBand)) return "";
            string[] aLines = sBand.Replace("\r\n", "\n").Replace("\r", "\n").Split('\n');
            List<string> lOut = new List<string>();
            foreach (string sLine in aLines)
            {
                string sR = renderLine(sLine, dRow);
                if (sR != null) lOut.Add(sR);
            }
            return string.Join("\r\n", lOut.ToArray());
        }

        // Render one line. Returns null to mean "suppress this line".
        public static string renderLine(string sLine, Dictionary<string, string> dRow)
        {
            bool bHad = false;
            string s = rxComment.Replace(sLine ?? "", "");

            // {{ expression }} -> evaluate, stash, leave a placeholder so
            // the $field pass below doesn't touch the result text.
            List<string> lResults = new List<string>();
            s = rxExpr.Replace(s, delegate(System.Text.RegularExpressions.Match m)
            {
                bHad = true;
                string r = JScriptExpr.eval(m.Groups[1].Value.Trim(), "", dRow);
                lResults.Add(r ?? "");
                return "\u0000" + (lResults.Count - 1).ToString() + "\u0001";
            });

            // $field / ${field}
            s = rxField.Replace(s, delegate(System.Text.RegularExpressions.Match m)
            {
                bHad = true;
                string sName = m.Groups[1].Success ? m.Groups[1].Value : m.Groups[2].Value;
                string sVal;
                return (dRow != null && dRow.TryGetValue(sName, out sVal) && sVal != null) ? sVal : "";
            });

            // Restore the {{ }} results.
            s = rxPlace.Replace(s, delegate(System.Text.RegularExpressions.Match m)
            {
                int i = int.Parse(m.Groups[1].Value);
                return (i >= 0 && i < lResults.Count) ? lResults[i] : "";
            });

            if (bHad)
            {
                string sNorm = rxSpaces.Replace(s, " ").Trim();
                return (sNorm.Length == 0) ? null : sNorm;
            }
            return s;
        }
    }

    public class DbDoManager : IDisposable
    {
        // ------- Constants -------
        private const int InitialFetchBatch = 1000;  // rows fetched per chunk for table loads
        private const string DefaultProvider = "Microsoft.ACE.OLEDB.16.0";

        // ------- Fields (alphabetical within each type) -------
        private bool bDisposed;
        private bool bReadOnly;

        private dynamic oCatalog;     // ADOX.Catalog (lazy; only when getTableNames is called)
        private dynamic oConn;        // ADODB.Connection
        private dynamic oRecordset;   // ADODB.Recordset (current table)

        // Synthetic current-table name for a multi-table / expression
        // query result that maps to no single base table.
        private const string c_sQueryTable = "(query)";
        private string sConnectString;
        private string sCurrentTable;
        private string sFilePath;
        // The SELECT/WITH that opened the current recordset as a
        // custom query (Control+Q); null for a directly-opened
        // table or view. Read back by Say Query.
        private string sSourceSql;

        // sActiveSort: the current sort, as the user-facing clause
        // ("col ASC, col DESC, ..."). DbDo applies sorting through a SQL
        // ORDER BY re-query rather than ADO's Recordset.Sort property:
        // the client-cursor Sort silently returns NULL field values for
        // some ODBC providers (the "every cell goes blank after I sort"
        // report), whereas ORDER BY runs in the engine and is reliable.
        // This field is the source of truth the sort getter returns,
        // since the re-queried recordset's own Sort property stays "".
        private string sActiveSort = "";

        // ------- Constructor / Dispose -------
        public DbDoManager()
        {
            sCurrentTable = "";
            sFilePath = "";
            sConnectString = "";
            bReadOnly = false;
            bReadOnlyInnate = false;
        }

        public void Dispose()
        {
            if (bDisposed) return;
            try { closeRecordset(); } catch { }
            try { if (oConn != null) oConn.Close(); } catch { }
            releaseCom(oRecordset); oRecordset = null;
            releaseCom(oCatalog); oCatalog = null;
            releaseCom(oConn); oConn = null;
            bDisposed = true;
        }

        // ------- Public read-only properties -------
        public string filePath { get { return sFilePath; } }
        public string currentTable { get { return sCurrentTable; } }
        // Read-only is layered: bReadOnly is the USER's safeguard
        // toggle (Alt+Z, or the read-only checkbox at open);
        // bReadOnlyInnate marks recordsets that are read-only by
        // NATURE -- views and query results ADO cannot update --
        // which no toggle can unlock. readOnly is the union.
        public bool readOnly { get { return bReadOnly || bReadOnlyInnate; } }
        public bool readOnlyInnate { get { return bReadOnlyInnate; } }
        // The custom query SQL behind the current recordset, or null
        // when a real table or view is open.
        public string sourceSql { get { return sSourceSql; } }
        // True when the recordset is an ad-hoc query with no single
        // base table (shown as "Custom" rather than a table name).
        public bool currentIsCustomQuery { get { return sCurrentTable == c_sQueryTable; } }
        private bool bReadOnlyInnate;
        // bDataModified: set true whenever a record is committed (update)
        // or deleted, cleared when a database is opened. For a directly-
        // opened SQLite file this is informational only (edits are already
        // durable). For a workbook working copy it is what drives the
        // unsaved-changes indicator: it means the in-memory working data
        // differs from the .xlsx on disk until Save writes it back.
        public bool bDataModified;
        public string connectString { get { return sConnectString; } }

        // ------- isOpen / connection state -------
        public bool isOpen()
        {
            if (oConn == null) return false;
            try { return ((int)oConn.State) != 0; }
            catch { return false; }
        }

        public bool hasRecordset()
        {
            if (oRecordset == null) return false;
            try { return ((int)oRecordset.State) != 0; }
            catch { return false; }
        }

        // =====================================================================
        // openDatabase: file-extension dispatch to the right provider.
        //
        // sPath may be a file or a folder. A folder is treated as a
        // dBASE source (dbDot's convention). A relative path is
        // resolved against the current working directory, matching
        // dbDot's "if (sPath does not contain backslash) prepend cur dir."
        //
        // sTable is optional. If supplied, the recordset is opened on
        // that table after the connection is established. For .csv
        // and .dbf single-file paths the file's basename is used as
        // the table by default.
        // =====================================================================
        // stripUtf8BomIfNeeded: removes a leading UTF-8 BOM from a
        // Text-family file in place so the ACE Text engine does not fold
        // it into the first column name. No-op for non-text formats, for
        // files with no BOM, and (silently, logged) for any I/O error so
        // a locked or read-only file can never break the open.
        private static void stripUtf8BomIfNeeded(string sPath, string sExt)
        {
            if (sExt != "csv" && sExt != "tsv" && sExt != "tab" && sExt != "txt") return;
            try
            {
                byte[] aBytes = File.ReadAllBytes(sPath);
                if (aBytes.Length < 3 || aBytes[0] != 0xEF || aBytes[1] != 0xBB || aBytes[2] != 0xBF) return;
                byte[] aStripped = new byte[aBytes.Length - 3];
                Array.Copy(aBytes, 3, aStripped, 0, aStripped.Length);
                File.WriteAllBytes(sPath, aStripped);
                DbDoLog.write("Stripped a UTF-8 BOM from " + sPath + " (it corrupts the first column name when read through the ACE Text engine).");
            }
            catch (Exception ex)
            {
                try { DbDoLog.write("stripUtf8BomIfNeeded skipped for " + sPath + ": " + ex.Message); } catch { }
            }
        }

        public void openDatabase(string sPath, string sTable, bool bReadOnlyFlag)
        {
            if (isOpen()) close();
            bDataModified = false;

            if (string.IsNullOrEmpty(sPath))
                throw new ArgumentException("openDatabase requires a path.");

            // Resolve relative path. If the input has no directory
            // separator, dbDot's pattern is to prepend the current
            // working directory. We mirror that.
            if (!Path.IsPathRooted(sPath))
                sPath = Path.GetFullPath(Path.Combine(Environment.CurrentDirectory, sPath));

            string sExt;
            bool bIsFolder = Directory.Exists(sPath);
            if (bIsFolder) sExt = "dbf";  // a folder is treated as a dBASE source
            else
            {
                if (!File.Exists(sPath))
                    throw new FileNotFoundException("File not found: " + sPath, sPath);
                sExt = Path.GetExtension(sPath).TrimStart('.').ToLowerInvariant();
            }

            // A UTF-8 BOM (EF BB BF) at the start of a Text-family file
            // is not stripped by the ACE Text engine, so it gets folded
            // onto the first column name (e.g. "RuleID" reads back as
            // <BOM>RuleID) and shows as a corrupt leading character.
            // Since DbDo now edits these files in place, normalize the
            // BOM away before connecting -- it is metadata, not data, so
            // removing it leaves the file logically identical while making
            // both reads and writes correct. Skipped on read-only opens
            // (we don't modify a file the user asked not to write) and
            // best-effort otherwise: a locked file just opens with the
            // cosmetic glitch.
            if (!bIsFolder && !bReadOnlyFlag) stripUtf8BomIfNeeded(sPath, sExt);

            sConnectString = buildConnectString(sPath, sExt, bIsFolder, ref sTable);
            sFilePath = sPath;
            bReadOnly = bReadOnlyFlag;
            bReadOnlyInnate = false;

            oConn = createComObject("ADODB.Connection");
            try
            {
                oConn.CursorLocation = AdoConstants.adUseClient;
                if (bReadOnlyFlag) oConn.Mode = AdoConstants.adModeRead;
                oConn.Open(sConnectString);
            }
            catch (COMException ex)
            {
                throw new Exception(translateConnectError(ex, sExt), ex);
            }

            // Auto-create recommended indexes on SQLite databases:
            // every foreign-key column (any column whose name ends
            // in '_id' and is not the table's own primary key) and
            // every 'marked' column gets a CREATE INDEX IF NOT
            // EXISTS. This benefits Show-Object's related-records
            // lookups (which issue SELECT look FROM <child> WHERE
            // <fk> = <value>) and any filter on 'marked = true'.
            //
            // Skipped on read-only opens, on file formats other than
            // SQLite (Access manages indexes through ADOX; CSV and
            // dBASE don't index at all), and (silently) on any error
            // so a bad sweep can't break the open.
            if (!bReadOnlyFlag && (sExt == "db" || sExt == "sqlite" || sExt == "sqlite3"))
            {
                try { ensureRecommendedIndexes(); }
                catch (Exception exIdx)
                { try { DbDoLog.write("ensureRecommendedIndexes failed: " + exIdx.Message); } catch { } }
            }

            if (!string.IsNullOrEmpty(sTable))
                selectTable(sTable);
        }

        // ensureRecommendedIndexes: for every base table in the
        // currently-open SQLite database, issue CREATE INDEX IF
        // NOT EXISTS on the columns that benefit from being indexed
        // in DbDo's typical access patterns:
        //
        //   - Foreign-key columns (any column whose name ends in
        //     '_id' and is not the table's own primary key) -- used
        //     by Show-Object's related-records lookup.
        //   - The 'marked' column -- used by filters and the
        //     bulk-mark / unmark operations.
        //   - Standard sortable columns reachable via the Alt+letter
        //     Sort-by hotkeys: look (Alt+L), tags (Alt+T), url (Alt+
        //     U), plus added and updated which are common sort
        //     targets from the Custom Sort dialog.
        //
        // The IF NOT EXISTS guard means re-opening a database is
        // idempotent -- only the first open of a database adds
        // indexes; subsequent opens do nothing observable.
        //
        // The naming convention is idx_<table>_<column>. SQLite
        // requires index names unique across the whole database,
        // so encoding both table and column in the name avoids
        // collisions between tables that share a column name like
        // 'marked'.
        //
        // The walk uses sqlite_master to enumerate tables, then
        // PRAGMA table_info for each to discover columns. Both
        // queries return ADODB recordsets in this DbDo path.
        // INDEX creation goes through oConn.Execute directly,
        // not a recordset.
        //
        // Every created index is logged to DbDoLog so the user
        // can see what changed.
        private void ensureRecommendedIndexes()
        {
            if (oConn == null || ((int)oConn.State) == 0) return;

            // Step 1: list all base tables.
            List<string> lTables = new List<string>();
            dynamic oRs = null;
            try
            {
                oRs = createComObject("ADODB.Recordset");
                oRs.Open("SELECT name FROM sqlite_master WHERE type='table' AND name NOT LIKE 'sqlite_%' AND name NOT LIKE 'sqlean_%'",
                    oConn, 0 /* adOpenForwardOnly */, 1 /* adLockReadOnly */, 1 /* adCmdText */);
                while (!(bool)oRs.EOF)
                {
                    object objName = oRs.Fields["name"].Value;
                    if (objName != null && objName != DBNull.Value) lTables.Add(objName.ToString());
                    oRs.MoveNext();
                }
                try { oRs.Close(); } catch { }
            }
            finally { releaseCom(oRs); oRs = null; }

            // Step 2: for each table, scan columns and create
            // missing indexes. The PK-column name pattern is
            // <table>_id; we skip indexes on that one since
            // SQLite already maintains a rowid alias index.
            foreach (string sTable in lTables)
            {
                string sPk = sTable + Metadata.PrimaryKeySuffix;
                List<string> lColumns = new List<string>();
                dynamic oCols = null;
                try
                {
                    oCols = createComObject("ADODB.Recordset");
                    string sQuoted = "\"" + sTable.Replace("\"", "\"\"") + "\"";
                    oCols.Open("PRAGMA table_info(" + sQuoted + ")",
                        oConn, 0, 1, 1);
                    while (!(bool)oCols.EOF)
                    {
                        object objName = oCols.Fields["name"].Value;
                        if (objName != null && objName != DBNull.Value) lColumns.Add(objName.ToString());
                        oCols.MoveNext();
                    }
                    try { oCols.Close(); } catch { }
                }
                catch { /* table may be inaccessible; skip */ }
                finally { releaseCom(oCols); oCols = null; }

                foreach (string sCol in lColumns)
                {
                    bool bIsFk = sCol.EndsWith("_id", StringComparison.OrdinalIgnoreCase)
                                 && !string.Equals(sCol, sPk, StringComparison.OrdinalIgnoreCase)
                                 && !string.Equals(sCol, "id", StringComparison.OrdinalIgnoreCase);
                    bool bIsMarked = string.Equals(sCol, Metadata.MarkedColumn,
                                                    StringComparison.OrdinalIgnoreCase);
                    // Standard columns reachable via the Alt+letter
                    // Sort-by hotkeys (added v1.0.69): look (Alt+L),
                    // tags (Alt+T), url (Alt+U). Also added and
                    // updated which are sortable from the Custom Sort
                    // dialog and are very common sort targets. The PK
                    // already has SQLite's implicit rowid-alias
                    // index, so id is excluded.
                    bool bIsSortableStandard =
                        string.Equals(sCol, "look",    StringComparison.OrdinalIgnoreCase) ||
                        string.Equals(sCol, "tags",    StringComparison.OrdinalIgnoreCase) ||
                        string.Equals(sCol, "url",     StringComparison.OrdinalIgnoreCase) ||
                        string.Equals(sCol, "added",   StringComparison.OrdinalIgnoreCase) ||
                        string.Equals(sCol, "edited", StringComparison.OrdinalIgnoreCase);
                    if (!bIsFk && !bIsMarked && !bIsSortableStandard) continue;

                    string sIdxName = "idx_" + sTable + "_" + sCol;
                    string sSql = "CREATE INDEX IF NOT EXISTS \""
                                + sIdxName.Replace("\"", "\"\"") + "\" ON \""
                                + sTable.Replace("\"", "\"\"") + "\" (\""
                                + sCol.Replace("\"", "\"\"") + "\")";
                    try
                    {
                        oConn.Execute(sSql, Type.Missing,
                            128 /* adExecuteNoRecords */ | 1 /* adCmdText */);
                        try { DbDoLog.write("ensureRecommendedIndexes: " + sSql); } catch { }
                    }
                    catch (Exception exSql)
                    {
                        try { DbDoLog.write("ensureRecommendedIndexes skip " + sIdxName + ": " + exSql.Message); } catch { }
                    }
                }
            }
        }


        // =====================================================================
        // buildConnectString: per-extension connection-string assembly.
        // Mirrors dbDot.vbs lines 869-914 in spirit; the hard-coded
        // strings are now fallbacks behind a [ConnectStrings] section
        // in DbDo.inix that lets advanced users override on a per-
        // extension basis. The ini template substitutes {path} with
        // the full file path and {folder} with the parent folder; the
        // ini code never escapes characters in {path}, so the user
        // is responsible for any quoting that the connection string
        // syntax requires (the templates that ship use the right
        // quoting form for each provider).
        // sqliteLoadExtClause: if a SQLean bundle named sqlean.dll sits
        // in the same folder as the executable, return a connection-string
        // clause "LoadExt=<full path>;" so the SQLite ODBC driver loads it
        // at connect time (which also enables extension loading, off by
        // default), making REGEXP and the other SQLean functions available.
        // Returns "" when the file is absent, so a plain install -- one
        // without the DLL dropped in -- builds exactly the old string. The
        // full native path is used rather than a bare filename so the load
        // does not depend on the process working directory or the Windows
        // DLL search order; backslashes are correct both for the driver's
        // attribute value (terminated by ';', not escaped) and for the
        // underlying LoadLibrary call.
        private static string sqliteLoadExtClause()
        {
            try
            {
                string sAppDir = Path.GetDirectoryName(
                    System.Reflection.Assembly.GetExecutingAssembly().Location) ?? "";
                string sDll = Path.Combine(sAppDir, "sqlean.dll");
                // Forward slashes: SQLite derives the extension entry point
                // (sqlite3_sqlean_init) from the filename between the last
                // '/' and the first '.', scanning for forward slashes only.
                // A backslash path defeats that derivation, so the load
                // silently fails; forward slashes also load fine on Windows.
                if (File.Exists(sDll)) return string.Format("LoadExt={0};", sDll.Replace('\\', '/'));
            }
            catch { }
            return "";
        }

        // =====================================================================
        private string buildConnectString(string sPath, string sExt, bool bIsFolder, ref string sTable)
        {
            // First check the [ConnectStrings] section of the per-user
            // DbDo.inix for an override. Empty / missing value falls
            // through to the hard-coded defaults below.
            string sOverride = readConnectStringOverride(sExt);
            if (!string.IsNullOrEmpty(sOverride))
            {
                string sFolderForOverride = bIsFolder ? sPath : Path.GetDirectoryName(sPath) ?? "";
                // For dBASE / CSV / TSV the override may use {folder};
                // also infer a table name from the filename if not
                // already set, since the ACE Text and dBASE drivers
                // address tables as files-within-the-folder.
                if (sExt == "dbf" && !bIsFolder && string.IsNullOrEmpty(sTable))
                    sTable = Path.GetFileNameWithoutExtension(sPath);
                if ((sExt == "csv" || sExt == "tsv" || sExt == "tab" || sExt == "txt")
                    && string.IsNullOrEmpty(sTable))
                    sTable = Path.GetFileName(sPath);
                string sBuilt = sOverride
                    .Replace("{path}", sPath ?? "")
                    .Replace("{folder}", sFolderForOverride);
                // SQLite backends: honor the drop-in sqlean.dll auto-load
                // (DLL beside the executable) even when a [ConnectStrings]
                // override is in force -- the override would otherwise
                // return here before the default's LoadExt logic runs.
                // Skipped if the override already names a LoadExt of its
                // own, so an explicit choice still wins.
                if ((sExt == "db" || sExt == "sqlite" || sExt == "sqlite3")
                    && sBuilt.IndexOf("loadext", StringComparison.OrdinalIgnoreCase) < 0)
                    sBuilt += sqliteLoadExtClause();
                return sBuilt;
            }
            switch (sExt)
            {
                case "db":
                case "sqlite":
                case "sqlite3":
                    // Auto-load a SQLean bundle if sqlean.dll is present
                    // next to the executable; absent that file the clause
                    // is empty and this is the original plain string.
                    return string.Format("DRIVER=SQLite3 ODBC Driver;Database={0};{1}", sPath, sqliteLoadExtClause());

                case "mdb":
                case "accdb":
                    return string.Format(
                        "Provider={0};Data Source={1};Persist Security Info=False;",
                        DefaultProvider, sPath);

                case "xlsx":
                case "xls":
                case "xlsm":
                case "xlsb":
                    return string.Format(
                        "Provider={0};Data Source={1};Extended Properties=\"Excel 12.0 Xml;HDR=Yes;IMEX=1;\";",
                        DefaultProvider, sPath);

                case "dbf":
                {
                    string sFolder = bIsFolder ? sPath : Path.GetDirectoryName(sPath);
                    if (!bIsFolder && string.IsNullOrEmpty(sTable))
                        sTable = Path.GetFileNameWithoutExtension(sPath);
                    return string.Format(
                        "Provider={0};Data Source={1};Extended Properties=dBASE IV;",
                        DefaultProvider, sFolder);
                }

                case "csv":
                case "tsv":
                case "tab":
                case "txt":
                {
                    string sFolder = Path.GetDirectoryName(sPath);
                    if (string.IsNullOrEmpty(sTable))
                    {
                        // ACE's Text provider names the table with the
                        // extension's dot replaced by '#': "data.csv"
                        // becomes "data#csv". Match that so the auto-
                        // opened table resolves (and so it agrees with
                        // the names the catalog enumerator returns).
                        string sLeaf = Path.GetFileName(sPath);
                        int iDot = sLeaf.LastIndexOf('.');
                        sTable = (iDot >= 0)
                            ? sLeaf.Substring(0, iDot) + "#" + sLeaf.Substring(iDot + 1)
                            : sLeaf;
                    }
                    string sFmt = (sExt == "tsv" || sExt == "tab") ? "TabDelimited" : "Delimited";
                    return string.Format(
                        "Provider={0};Data Source={1};Extended Properties=\"Text;HDR=Yes;FMT={2};\";",
                        DefaultProvider, sFolder, sFmt);
                }

                default:
                    throw new Exception("Unrecognized database file extension: ." + sExt
                        + ". Supported: .db, .sqlite, .sqlite3, .mdb, .accdb, .xlsx, .xls, .dbf, .csv, .tsv, .txt, or a folder.");
            }
        }

        // readConnectStringOverride: consult the [ConnectStrings]
        // section of the per-user DbDo.inix (with legacy fallback to
        // the shipped template next to the EXE) for an override of
        // the connection-string template for the given file
        // extension. Returns "" when no override is present.
        private static string readConnectStringOverride(string sExt)
        {
            try
            {
                // Per-database settings file first (highest precedence):
                // a database may override the connection template for a
                // file type in its own <DbBaseName>.inix.
                string sDbV = DbDoForm.readPerDbValue("ConnectStrings", sExt);
                if (!string.IsNullOrEmpty(sDbV)) return sDbV;
                // Per-user next.
                string sUserBase = Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData);
                if (!string.IsNullOrEmpty(sUserBase))
                {
                    string sIni = Path.Combine(sUserBase, "DbDo", "DbDo.inix");
                    if (File.Exists(sIni))
                    {
                        string sV = readIniFromFile(sIni, "ConnectStrings", sExt);
                        if (!string.IsNullOrEmpty(sV)) return sV;
                    }
                }
                // Shipped template.
                string sShipped = Path.Combine(
                    Path.GetDirectoryName(Application.ExecutablePath) ?? ".",
                    "DbDo.inix");
                if (File.Exists(sShipped))
                {
                    string sV = readIniFromFile(sShipped, "ConnectStrings", sExt);
                    if (!string.IsNullOrEmpty(sV)) return sV;
                }
            }
            catch { }
            return "";
        }

        // readIniFromFile: section/key reader used by
        // readConnectStringOverride. Routed through InixCodec so a
        // connection string can be written in the fenced multi-line
        // Inix form (key` ... `), which sidesteps quoting problems
        // for values that themselves contain '=' characters. A
        // multi-line value is joined back to a single line, since a
        // connection string is logically one line however it is
        // written in the file.
        internal static string readIniFromFile(string sPath, string sSection, string sKey)
        {
            try
            {
                foreach (InixCodec.Section sec in InixCodec.read(sPath))
                {
                    if (!string.Equals(sec.Name, sSection, StringComparison.OrdinalIgnoreCase)) continue;
                    string sV = sec.get(sKey);
                    if (sV == null) return "";
                    sV = sV.Replace("\r\n", "").Replace("\n", "").Trim();
                    return sV;
                }
            }
            catch { }
            return "";
        }


        // =====================================================================
        // translateConnectError: turns the typical COM error into
        // the actionable message about driver installation. The
        // SQLite ODBC and ACE providers each have a distinctive
        // failure mode when not installed.
        // =====================================================================
        private string translateConnectError(COMException ex, string sExt)
        {
            string sMsg = ex.Message ?? "";
            string sLower = sMsg.ToLowerInvariant();

            if (sLower.Contains("data source name not found") || sLower.Contains("im002"))
            {
                if (sExt == "db" || sExt == "sqlite" || sExt == "sqlite3")
                    return "SQLite ODBC driver not installed. Install sqliteodbc_w64.exe from "
                         + "http://www.ch-werner.de/sqliteodbc/ then retry. "
                         + "(No WinGet or Chocolatey package exists for this driver.) "
                         + "Original error: " + sMsg;
            }
            if (sLower.Contains("not registered") || sLower.Contains("provider cannot be found"))
            {
                return "Microsoft Access Database Engine 2016 Redistributable not installed. "
                     + "Install via WinGet: 'winget install Microsoft.AccessDatabaseEngine.2016 --silent', "
                     + "via Chocolatey: 'choco install made-2016 -y', "
                     + "or download accessdatabaseengine_X64.exe from "
                     + "https://www.microsoft.com/en-us/download/details.aspx?id=54920 and run it with the /passive flag. "
                     + "Original error: " + sMsg;
            }
            return sMsg;
        }

        // ------- close -------
        public void close()
        {
            try { closeRecordset(); } catch { }
            try { if (oConn != null && ((int)oConn.State) != 0) oConn.Close(); } catch { }
            releaseCom(oRecordset); oRecordset = null;
            releaseCom(oCatalog); oCatalog = null;
            releaseCom(oConn); oConn = null;
            sCurrentTable = "";
            sFilePath = "";
            sConnectString = "";
            bReadOnly = false;
            bReadOnlyInnate = false;
            clearTableCache();
            dColumnTypes.Clear();
        }

        private void closeRecordset()
        {
            if (oRecordset != null)
            {
                try { if (((int)oRecordset.State) != 0) oRecordset.Close(); } catch { }
            }
            releaseCom(oRecordset); oRecordset = null;
        }

        // =====================================================================
        // selectTable: opens (or re-opens) the recordset on the named
        // table or view. Closes any prior recordset. Sets CursorType
        // and LockType appropriate for whether we're read-only AND for
        // whether the named object is a view (always read-only).
        //
        // The ADODB.Recordset.Open overload takes a Source, ActiveConn,
        // CursorType, LockType, Options. We use adCmdTable (2) so the
        // Source argument is treated as a literal table or view name
        // rather than an SQL string. Most providers happily accept a
        // view name through adCmdTable.
        // =====================================================================
        // =====================================================================
        // Session table cache: per-database, the manager remembers
        // every table or view the user has opened in this session and
        // each table's filter / sort / current-row position. When the
        // user switches back to a previously-visited table, those
        // settings are restored automatically. The cache lives only as
        // long as the database connection; closing the database
        // discards it.
        //
        // Why we cache *settings* and not the live Recordset object:
        //   - A live Recordset holds row data that can go stale when
        //     other writers (or the same writer through a different
        //     statement) modify the underlying table. Re-opening the
        //     recordset on each return guarantees fresh data.
        //   - ADO Recordsets in adUseClient mode hold the rowset in
        //     memory; keeping multiple open simultaneously balloons
        //     memory for tables of any size.
        //   - The settings are cheap to capture (three values: filter,
        //     sort, absolute position) and applying them to a freshly-
        //     opened recordset takes microseconds.
        //
        // Order: lVisitedTables is the insertion order of unique table
        // names visited. Used by Control+Tab cycling. selectTable
        // appends to it on first visit; subsequent visits leave the
        // ordering untouched.
        // =====================================================================
        public class TableSettings
        {
            public string sFilter;       // Recordset.Filter string ("" for none)
            public string sSort;         // Recordset.Sort string ("" for none)
            public int iAbsolutePosition;// 1-based row number (0 if no rows)
            // Comma-separated select list -- the explicit set of
            // columns the user wants visible in the ListView for
            // this table. Empty string means "use the default
            // rule-based selection (standard-hidden + calculated
            // hidden, everything else shown)."
            public string sSelectList = "";
            // Last virtual-cell column for this table, by NAME (not
            // by index). Empty string means "use the first column."
            // The name is more durable than an index because the
            // listview's column set can change between sessions
            // (Select Columns), but a column name typically survives.
            public string sVirtualColumn = "";
        }
        private Dictionary<string, TableSettings> dTableCache = new Dictionary<string, TableSettings>(StringComparer.OrdinalIgnoreCase);
        private List<string> lVisitedTables = new List<string>();

        // Public read-only enumeration of the per-table cache. The form
        // uses this at OnFormClosing time to persist every visited
        // table's state (filter, sort, position, virtual column) to
        // the RecentFiles ini block, not just the currently-active
        // table.
        //
        // Before returning, the currently-active table's cache entry
        // is brought up-to-date by calling cacheCurrentTableSettings,
        // because the in-flight values for the current table only
        // get written into the cache when the table is left.
        public IEnumerable<KeyValuePair<string, TableSettings>> tableCacheEntries()
        {
            cacheCurrentTableSettings();
            return new List<KeyValuePair<string, TableSettings>>(dTableCache);
        }

        // Cache of table-name -> isView, populated when
        // getCatalogObjectNames walks the ADOX catalog. The TYPE
        // column from the catalog is the authoritative source for
        // "view vs base table"; we cache the answer here so
        // selectTable can consult it without re-walking the catalog
        // on every table switch. Cleared by close().
        private Dictionary<string, bool> dIsViewByName = new Dictionary<string, bool>(StringComparer.OrdinalIgnoreCase);

        // Cache of (table, column) -> isCalculated. Populated by
        // selectTable when a new table is opened. SQLite reports
        // calculated columns through PRAGMA table_xinfo's 'hidden'
        // column (values 2 = virtual-generated, 3 = stored-
        // generated). Other providers (ACE/Jet) do not reliably
        // expose this through ADO, so for those tables the cache
        // contains only Metadata's standard 'look' entry.
        //
        // Keys are formatted as "<table>::<column>" (case-
        // insensitive). The cache survives across selectTable
        // calls within a session; close() clears it.
        private Dictionary<string, bool> dCalculatedColumns = new Dictionary<string, bool>(StringComparer.OrdinalIgnoreCase);

        public bool isCalculatedColumn(string sTable, string sColumn)
        {
            if (string.IsNullOrEmpty(sColumn)) return false;
            string sKey = (sTable ?? "") + "::" + sColumn;
            bool bResult;
            return dCalculatedColumns.TryGetValue(sKey, out bResult) && bResult;
        }

        // True if the name is in our schema cache and recorded as a
        // view. False otherwise (either it's a known table OR it's
        // not in the cache at all -- caller will open optimistic and
        // the provider will reject the lock if the name is wrong).
        public bool isKnownView(string sName)
        {
            if (string.IsNullOrEmpty(sName)) return false;
            bool bResult;
            return dIsViewByName.TryGetValue(sName, out bResult) && bResult;
        }

        // Snapshot the settings of the currently-open table, if any.
        // Called by selectTable just before switching away.
        private void cacheCurrentTableSettings()
        {
            if (string.IsNullOrEmpty(sCurrentTable)) return;
            if (oRecordset == null) return;
            // Preserve sSelectList and sVirtualColumn from the prior
            // entry: those are owned by the form and not part of the
            // recordset-mirror snapshot we're rebuilding here. Without
            // this preservation a table switch would wipe the user's
            // column-visibility choices and remembered virtual column.
            string sPriorSelect = "", sPriorVirtual = "";
            TableSettings prior;
            if (dTableCache.TryGetValue(sCurrentTable, out prior))
            {
                sPriorSelect  = prior.sSelectList   ?? "";
                sPriorVirtual = prior.sVirtualColumn ?? "";
            }
            TableSettings snap = new TableSettings();
            snap.sFilter           = filter ?? "";
            snap.sSort             = sort ?? "";
            snap.iAbsolutePosition = absolutePosition;
            snap.sSelectList       = sPriorSelect;
            snap.sVirtualColumn    = sPriorVirtual;
            dTableCache[sCurrentTable] = snap;
        }

        // Apply a previously-captured snapshot to the just-opened
        // recordset. Called by selectTable after Open() succeeds.
        // Filter and sort are best-effort: if the cached expression no
        // longer parses (e.g., a referenced column was dropped), we
        // ignore the failure rather than fail the table switch.
        private void applyTableSettings(string sTable)
        {
            if (oRecordset == null) return;
            // (1) Session cache (this run's remembered filter / sort /
            // position for a previously-visited table).
            if (dTableCache.ContainsKey(sTable))
            {
                TableSettings snap = dTableCache[sTable];
                if (!string.IsNullOrEmpty(snap.sFilter))
                {
                    try { filter = snap.sFilter; } catch { /* stale filter; skip */ }
                }
                if (!string.IsNullOrEmpty(snap.sSort))
                {
                    try { sort = snap.sSort; } catch { /* stale sort; skip */ }
                }
                if (snap.iAbsolutePosition > 0)
                {
                    try { absolutePosition = snap.iAbsolutePosition; } catch { /* row may not exist anymore */ }
                }
            }

            // (2) Per-database [Table:<name>] config -- the saved view
            // that travels with the database (SelectFields, OrderFields,
            // WhereFilter). Applied after the session cache so the saved
            // config wins; position stays session-only. Each is skipped
            // when absent so a table with no saved view falls back to the
            // default (look + prm) selection and no sort/filter.
            try
            {
                string sSel = DbDoForm.readPerDbValue("Table:" + sTable, "SelectFields");
                if (!string.IsNullOrEmpty(sSel)) setSelectList(sTable, sSel);
                string sOrd = DbDoForm.readPerDbValue("Table:" + sTable, "OrderFields");
                if (!string.IsNullOrEmpty(sOrd)) { try { sort = sOrd; } catch { } }
                string sWhr = DbDoForm.readPerDbValue("Table:" + sTable, "WhereFilter");
                if (!string.IsNullOrEmpty(sWhr)) { try { filter = sWhr; } catch { } }
            }
            catch { }
        }

        // Public list of tables visited in this session, in insertion
        // order. Used by the Control+Tab cycle in DbDoForm.
        public List<string> visitedTableNames()
        {
            return new List<string>(lVisitedTables);
        }

        // Drop the cache. Called by close() so a fresh database starts
        // with no stale entries.
        private void clearTableCache()
        {
            dTableCache.Clear();
            lVisitedTables.Clear();
            dIsViewByName.Clear();
        }

        // refreshTableList: called after DDL (New Database, Add
        // Table) so cached per-table settings and view flags cannot
        // describe a schema that no longer matches the file.
        public void refreshTableList()
        {
            clearTableCache();
        }

        // needsExplicitSelect: every ACE OLEDB provider (Access, Excel,
        // Text/CSV, dBASE) rejects ADO's adCmdTable auto-query when the
        // table/sheet name contains spaces, '$' (Excel) or '#' (Text) --
        // ADO emits an UNBRACKETED FROM clause and the provider raises
        // "Syntax error in FROM clause", so a picked table never opens.
        // For those sources we build an explicit, bracketed
        // "SELECT * FROM [name]" instead. SQLite (the ch-werner ODBC
        // driver) keeps the lighter adCmdTable path. Detected from the
        // live connection string so it also covers folder-as-dBASE
        // sources, which have no file extension.
        private bool needsExplicitSelect()
        {
            return !string.IsNullOrEmpty(sConnectString)
                && sConnectString.IndexOf("ACE.OLEDB", StringComparison.OrdinalIgnoreCase) >= 0;
        }

        // quoteOpenTable: identifier quoting for the table-open SELECT.
        // ACE providers bracket the real table name (brackets work for
        // Access, Excel sheets, Text files and dBASE alike); SQLite
        // double-quotes. This differs from quoteIdentifier only for
        // dBASE, where quoteIdentifier sanitizes a name for CREATE TABLE
        // but opening must reference the table's actual name.
        private string quoteOpenTable(string sTable)
        {
            if (needsExplicitSelect())
                return "[" + sTable.Replace("]", "") + "]";
            return "\"" + sTable.Replace("\"", "\"\"") + "\"";
        }

        public void selectTable(string sTable)
        {
            if (!isOpen()) throw new InvalidOperationException("No database open.");
            if (string.IsNullOrEmpty(sTable))
                throw new ArgumentException("selectTable requires a table name.");

            // Capture settings of the table we're leaving so a later
            // return restores them.
            cacheCurrentTableSettings();

            closeRecordset();

            oRecordset = createComObject("ADODB.Recordset");
            oRecordset.CursorLocation = AdoConstants.adUseClient;

            // Views are always read-only regardless of the manager's
            // bReadOnly flag, since SQLite views are not generally
            // updatable through ADO and ACE views never are.
            //
            // Detection: prefer the cached schema type populated by
            // getCatalogObjectNames -- that comes from ADOX's TYPE
            // column, the authoritative source. Fall back to opening
            // optimistic and letting the provider reject the lock if
            // the name is unknown to us (recently-created view that
            // we haven't catalogued yet, or a typed-in name from the
            // dot prompt).
            bool bIsView = isKnownView(sTable);
            int iLock;
            if (bReadOnly || bIsView)
                iLock = AdoConstants.adLockReadOnly;
            else
                iLock = AdoConstants.adLockOptimistic;

            try
            {
                if (needsExplicitSelect())
                {
                    string sSql = "SELECT * FROM " + quoteOpenTable(sTable);
                    DbDoLog.write("selectTable: explicit ACE query: " + sSql);
                    oRecordset.Open(sSql, oConn,
                        AdoConstants.adOpenStatic, iLock, AdoConstants.adCmdText);
                }
                else
                {
                    oRecordset.Open(sTable, oConn,
                        AdoConstants.adOpenStatic, iLock, AdoConstants.adCmdTable);
                }
            }
            catch (COMException ex)
            {
                releaseCom(oRecordset); oRecordset = null;
                throw new Exception("Cannot open " + (bIsView ? "view" : "table")
                    + " '" + sTable + "': " + ex.Message, ex);
            }

            sCurrentTable = sTable;
            sSourceSql = null;
            bCurrentIsView = bIsView;
            sActiveSort = "";   // fresh open starts unsorted; cached sort re-applied via applyTableSettings
            // A view is read-only by nature (SQLite/ADO cannot
            // update it); mark it innate so edits are blocked and
            // Alt+Z cannot unlock it. A real table clears the flag.
            bReadOnlyInnate = bIsView;

            // Track session visit history. First visit appends to the
            // ordered list; revisits leave the order alone so cycling
            // remains predictable. Then restore any cached settings.
            bool bAlreadyVisited = false;
            foreach (string sN in lVisitedTables)
            {
                if (string.Equals(sN, sTable, StringComparison.OrdinalIgnoreCase))
                { bAlreadyVisited = true; break; }
            }
            if (!bAlreadyVisited) lVisitedTables.Add(sTable);
            applyTableSettings(sTable);

            // Populate the calculated-columns cache for this table
            // by running PRAGMA table_xinfo. SQLite returns a row
            // per column with a 'hidden' integer:
            //   0 = normal, 1 = hidden via constraint, 2 = virtual
            //   generated, 3 = stored generated. Values 2 and 3
            //   are calculated columns; we mark them hidden in the
            //   DbDo display.
            //
            // For non-SQLite databases (ACE, Excel, dBase), the
            // PRAGMA call fails silently; the only calculated
            // column those tables will hide is 'look', which is
            // hardcoded in Metadata.
            populateCalculatedColumnsCache(sTable);
        }

        // selectTableFiltered: open a table restricted by a SQL WHERE
        // clause -- the drill path for related records. The SELECT
        // stays single-base-table (SELECT * FROM <table> WHERE ...),
        // so with the client cursor and optimistic lock the result
        // remains UPDATABLE exactly like a plain table open; the
        // WHERE may contain IN-subqueries through maps, which is how
        // related-record views are produced. Unlike selectTable, any
        // cached per-table settings are deliberately NOT reapplied:
        // a drill view is defined by its WHERE clause, and restoring
        // a remembered filter on top would silently change the
        // result set.
        public void selectTableFiltered(string sTable, string sWhereSql)
        {
            if (!isOpen()) throw new InvalidOperationException("No database open.");
            if (string.IsNullOrEmpty(sTable))
                throw new ArgumentException("selectTableFiltered requires a table name.");
            if (string.IsNullOrEmpty(sWhereSql))
            { selectTable(sTable); return; }

            cacheCurrentTableSettings();
            closeRecordset();

            oRecordset = createComObject("ADODB.Recordset");
            oRecordset.CursorLocation = AdoConstants.adUseClient;

            bool bIsView = isKnownView(sTable);
            int iLock = (bReadOnly || bIsView)
                ? AdoConstants.adLockReadOnly
                : AdoConstants.adLockOptimistic;
            string sSql = "SELECT * FROM " + quoteOpenTable(sTable)
                + " WHERE " + sWhereSql;
            try
            {
                oRecordset.Open(sSql, oConn,
                    AdoConstants.adOpenStatic, iLock, AdoConstants.adCmdText);
            }
            catch (COMException ex)
            {
                releaseCom(oRecordset); oRecordset = null;
                throw new Exception("Cannot open filtered view of '" + sTable
                    + "': " + ex.Message + "\nSQL: " + sSql, ex);
            }

            sCurrentTable = sTable;
            sSourceSql = null;
            bCurrentIsView = bIsView;
            sActiveSort = "";   // fresh open starts unsorted; cached sort re-applied via applyTableSettings
            // A view is read-only by nature (SQLite/ADO cannot
            // update it); mark it innate so edits are blocked and
            // Alt+Z cannot unlock it. A real table clears the flag.
            bReadOnlyInnate = bIsView;
            bool bAlreadyVisited = false;
            foreach (string sN in lVisitedTables)
            {
                if (string.Equals(sN, sTable, StringComparison.OrdinalIgnoreCase))
                { bAlreadyVisited = true; break; }
            }
            if (!bAlreadyVisited) lVisitedTables.Add(sTable);
            populateCalculatedColumnsCache(sTable);
        }

        private void populateCalculatedColumnsCache(string sTable)
        {
            if (oConn == null) return;
            if (string.IsNullOrEmpty(sTable)) return;
            try
            {
                string sSql = "PRAGMA table_xinfo(\"" + sTable.Replace("\"", "\"\"") + "\")";
                dynamic oRs = createComObject("ADODB.Recordset");
                try
                {
                    oRs.Open(sSql, oConn, AdoConstants.adOpenStatic,
                        AdoConstants.adLockReadOnly, AdoConstants.adCmdText);
                    while (!(bool)oRs.EOF)
                    {
                        string sColName = "";
                        int iHidden = 0;
                        try { sColName = (string)oRs.Fields["name"].Value; } catch { }
                        try { iHidden = Convert.ToInt32(oRs.Fields["hidden"].Value); } catch { }
                        if (!string.IsNullOrEmpty(sColName))
                        {
                            // hidden values 2 and 3 are stored/virtual generated.
                            bool bCalc = (iHidden == 2 || iHidden == 3);
                            dCalculatedColumns[sTable + "::" + sColName] = bCalc;
                        }
                        oRs.MoveNext();
                    }
                }
                finally
                {
                    try { oRs.Close(); } catch { }
                    releaseCom(oRs);
                }
            }
            catch
            {
                // Non-SQLite or PRAGMA disallowed -- ignore. The
                // hardcoded 'look' rule in Metadata still works.
            }
        }

        // True if the currently-open object is a view (read-only).
        // Set by selectTable based on the name prefix.
        public bool currentIsView { get { return bCurrentIsView; } }
        private bool bCurrentIsView = false;

        // openSqlRecordset: open an arbitrary SELECT or WITH
        // statement as the current recordset, replacing whatever
        // recordset was open. Opened optimistically: when every
        // selected column maps to a SINGLE base table the result
        // stays fully editable and that base table becomes the
        // current table (Edit, Delete, and marks all save back to
        // disk); a join, aggregate, or expression mix has no single
        // table identity, so it is read-only BY NATURE
        // (bReadOnlyInnate, which the Alt+Z toggle cannot unlock).
        //
        // Called from Query (Control+Q -- in its own child window
        // via openQueryWindow) and Open New Recordset.
        public void openSqlRecordset(string sSql)
        {
            if (!isOpen()) throw new InvalidOperationException("No database open.");
            if (string.IsNullOrEmpty(sSql)) throw new ArgumentException("openSqlRecordset requires a non-empty SQL string.");
            sSourceSql = sSql;
            sActiveSort = "";   // query windows sort via ADO fallback; start clean

            // Capture settings of whatever was open so a later
            // selectTable can return to that state.
            cacheCurrentTableSettings();
            closeRecordset();

            oRecordset = createComObject("ADODB.Recordset");
            oRecordset.CursorLocation = AdoConstants.adUseClient;

            // Open optimistically so a single-base-table SELECT
            // stays editable (LockType governs updatability, not
            // CommandType); fall back to read-only if the provider
            // refuses the optimistic open.
            try
            {
                oRecordset.Open(sSql, oConn,
                    AdoConstants.adOpenStatic, AdoConstants.adLockOptimistic, AdoConstants.adCmdText);
            }
            catch (COMException)
            {
                try
                {
                    oRecordset.Open(sSql, oConn,
                        AdoConstants.adOpenStatic, AdoConstants.adLockReadOnly, AdoConstants.adCmdText);
                }
                catch (COMException ex)
                {
                    releaseCom(oRecordset); oRecordset = null;
                    throw new Exception("Cannot open recordset: " + ex.Message, ex);
                }
            }

            // Updatability detection has two parts. (1) Recordset
            // .Supports(adUpdate) asks the cursor service whether the
            // Update method is available at all -- this is false when
            // the optimistic open failed and we fell back to a
            // read-only lock, so it guards against silently treating a
            // read-only-locked result as editable. (2) The client
            // cursor exposes each field's BASETABLENAME; when every
            // field maps to ONE base table, ADO can write updates back
            // to it. Both must hold for the query window to be fully
            // editable (Edit / Delete / marks save back, and that base
            // table becomes the current table). A read-only lock, a
            // join, an expression mix, or detection failure means
            // read-only BY NATURE -- bReadOnlyInnate, which the Alt+Z
            // toggle cannot unlock.
            bool bSupportsUpdate = false;
            try { bSupportsUpdate = (bool)oRecordset.Supports(AdoConstants.adUpdate); }
            catch { bSupportsUpdate = false; }
            string sBaseTable = null;
            bool bSingleBase = true;
            try
            {
                for (int i = 0; i < (int)oRecordset.Fields.Count; i++)
                {
                    object oBase = oRecordset.Fields[i].Properties["BASETABLENAME"].Value;
                    string sThis = (oBase == null || oBase is DBNull) ? "" : oBase.ToString();
                    if (sThis.Length == 0) { bSingleBase = false; break; }
                    if (sBaseTable == null) sBaseTable = sThis;
                    else if (!string.Equals(sBaseTable, sThis, StringComparison.OrdinalIgnoreCase))
                    { bSingleBase = false; break; }
                }
            }
            catch { bSingleBase = false; }
            if (bSupportsUpdate && bSingleBase && !string.IsNullOrEmpty(sBaseTable))
            {
                sCurrentTable = sBaseTable;
                bCurrentIsView = false;
                bReadOnlyInnate = false;
            }
            else
            {
                // Synthetic table name so dialogs and status bars
                // have something to display; the leading '(' prevents
                // collision with any real table.
                sCurrentTable = c_sQueryTable;
                bCurrentIsView = true;
                bReadOnlyInnate = true;
            }
        }

        // connectionProperty: read a single named dynamic property from
        // the live connection's Properties collection, or "" if absent
        // or unreadable. Used by Database Summary for the engine/driver
        // identity (DBMS Version, Driver Name/Version, Read-Only).
        public string connectionProperty(string sName)
        {
            try
            {
                if (oConn == null || string.IsNullOrEmpty(sName)) return "";
                object oVal = oConn.Properties.Item(sName).Value;
                return (oVal == null || oVal is DBNull) ? "" : oVal.ToString();
            }
            catch { return ""; }
        }

        // probeScalar: run a one-value SELECT on the live connection and
        // return its first field as text, or null with sError set to the
        // provider message. Used by the extension-load diagnostic.
        private string probeScalar(string sSql, out string sError)
        {
            dynamic oRs = null;
            sError = "";
            try
            {
                oRs = createComObject("ADODB.Recordset");
                oRs.Open(sSql, oConn, 0, 1, 1);   // adOpenForwardOnly, adLockReadOnly, adCmdText
                object oVal = ((bool)oRs.EOF) ? null : oRs.Fields[0].Value;
                return (oVal == null || oVal is DBNull) ? "(null)" : oVal.ToString();
            }
            catch (Exception ex) { sError = ex.Message; return null; }
            finally
            {
                try { if (oRs != null && ((int)oRs.State) != 0) oRs.Close(); } catch { }
                try { releaseCom(oRs); } catch { }
            }
        }

        // describeTable: a per-column data profile of the current base
        // table -- the iPython %whos / "describe" idea. For each column
        // it shows the declared type and key/null/FK flags from the
        // schema, then the live null count, distinct count, and min and
        // max values computed in SQL. Read-only. The distinct count uses
        // a subquery form so it works on SQLite and Access alike. It can
        // be slow on very large tables, since it scans once per column.
        public string describeTable()
        {
            if (!isOpen()) return "No database is open.";
            string sTable = sCurrentTable;
            if (string.IsNullOrEmpty(sTable) || sTable == c_sQueryTable)
                return "Describe Table works on a base table; the current view is a custom query.";

            List<SchemaColumn> lCols = getSchemaColumns(sTable);
            if (lCols.Count == 0) return "Could not read the schema for \"" + sTable + "\".";

            string sQuotedTable = "\"" + sTable.Replace("\"", "\"\"") + "\"";
            string sErr;
            string sTotalRaw = probeScalar("SELECT count(*) FROM " + sQuotedTable, out sErr);
            long iTotal = 0; long.TryParse(sTotalRaw, out iTotal);

            StringBuilder sb = new StringBuilder();
            sb.AppendLine("Describe " + sTable + " -- " + iTotal + " row"
                + (iTotal == 1 ? "" : "s") + ", " + lCols.Count + " column"
                + (lCols.Count == 1 ? "" : "s"));
            sb.AppendLine();
            foreach (SchemaColumn sc in lCols)
            {
                string sCol = "\"" + sc.name.Replace("\"", "\"\"") + "\"";
                string sNonNullRaw = probeScalar("SELECT count(" + sCol + ") FROM " + sQuotedTable, out sErr);
                string sDistinct   = probeScalar("SELECT count(*) FROM (SELECT DISTINCT " + sCol + " FROM " + sQuotedTable + ")", out sErr);
                string sMin        = probeScalar("SELECT min(" + sCol + ") FROM " + sQuotedTable, out sErr);
                string sMax        = probeScalar("SELECT max(" + sCol + ") FROM " + sQuotedTable, out sErr);

                long iNonNull = 0; long.TryParse(sNonNullRaw, out iNonNull);
                long iNull = iTotal - iNonNull;
                if (iNull < 0) iNull = 0;

                List<string> lFlags = new List<string>();
                if (sc.isPrimaryKey) lFlags.Add("PK");
                if (sc.notNull) lFlags.Add("not null");
                if (!string.IsNullOrEmpty(sc.foreignKeyRef)) lFlags.Add("FK -> " + sc.foreignKeyRef);

                sb.Append(sc.name);
                sb.Append(" (");
                sb.Append(string.IsNullOrEmpty(sc.dataType) ? "untyped" : sc.dataType);
                if (lFlags.Count > 0) { sb.Append(", "); sb.Append(string.Join(", ", lFlags.ToArray())); }
                sb.AppendLine(")");
                sb.AppendLine("  nulls " + iNull + ", distinct " + describeCount(sDistinct)
                    + ", min " + describeValue(sMin) + ", max " + describeValue(sMax));
            }
            return sb.ToString();
        }

        // describeCount / describeValue: format a probeScalar result for
        // the Describe Table report. probeScalar returns null on error,
        // "(null)" for a SQL NULL, or the value as text otherwise.
        private static string describeCount(string sValue)
        {
            return (sValue == null) ? "?" : sValue;
        }
        private static string describeValue(string sValue)
        {
            if (sValue == null) return "(error)";
            if (sValue == "(null)") return "(null)";
            if (sValue.Length == 0) return "(empty)";
            if (sValue.Length > 40) return sValue.Substring(0, 40) + "...";
            return sValue;
        }

        // appendAdoProps: dump an ADO Properties collection. Reading a
        // property's value can throw (write-only or unsupported), so
        // each is guarded independently.
        private static void appendAdoProps(StringBuilder sb, object oPropsObj)
        {
            if (oPropsObj == null) { sb.AppendLine("  (none)"); return; }
            dynamic oProps = oPropsObj;
            int iCount;
            try { iCount = (int)oProps.Count; }
            catch (Exception ex) { sb.AppendLine("  (enumeration failed: " + ex.Message + ")"); return; }
            if (iCount == 0) { sb.AppendLine("  (none)"); return; }
            for (int i = 0; i < iCount; i++)
            {
                string sName = "?";
                string sVal = "";
                try
                {
                    dynamic oProp = oProps.Item(i);
                    sName = (string)oProp.Name;
                    object oVal = null;
                    try { oVal = oProp.Value; } catch { oVal = null; }
                    sVal = (oVal == null || oVal is DBNull) ? "" : oVal.ToString();
                }
                catch { continue; }
                sb.AppendLine("  " + sName + " = " + sVal);
            }
        }

        // =====================================================================
        // getTableNames: ADOX.Catalog walks the connection's tables.
        // We filter out system / view / link types since users want
        // user data tables.
        //
        // ADOX is a separate COM library from ADODB; the Catalog
        // object connects to the same ADODB.Connection via its
        // ActiveConnection property.
        // =====================================================================
        public List<string> getTableNames()
        {
            return getCatalogObjectNames(true, false);
        }

        public List<string> getViewNames()
        {
            return getCatalogObjectNames(false, true);
        }

        public List<string> getTableAndViewNames()
        {
            return getCatalogObjectNames(true, true);
        }

        // Walk ADOX Catalog.Tables once and apply the appropriate filter.
        //
        // The TYPE column from ADOX is authoritative for distinguishing
        // a base table from a view. SQLite ODBC, ACE OLE DB, Jet,
        // dBASE, and all major ADODB-compatible providers populate
        // TYPE as "TABLE" or "VIEW" for the two cases. We rely on
        // this exclusively; the older view_ name-prefix convention
        // is no longer consulted.
        //
        // As a side effect we populate dIsViewByName so selectTable
        // can answer "is this name a view" without re-walking the
        // catalog. The cache is cleared on close().
        //
        // Tables that begin with "sqlite_" (sqlite_master, sqlite_sequence,
        // sqlite_stat1) are SQLite internals and excluded.
        //
        // Tables that begin with "MSys" are ACE/Jet system catalog and
        // excluded.
        private List<string> getCatalogObjectNames(bool bIncludeTables, bool bIncludeViews)
        {
            List<string> lResult = new List<string>();
            if (!isOpen()) return lResult;

            if (oCatalog == null)
                oCatalog = createComObject("ADOX.Catalog");

            try { oCatalog.ActiveConnection = oConn; }
            catch { /* ignore; some providers don't support ADOX */ }

            try
            {
                dynamic oTables = oCatalog.Tables;
                int iCount = (int)oTables.Count;
                for (int i = 0; i < iCount; i++)
                {
                    dynamic oTable = oTables[i];
                    string sName = (string)oTable.Name;
                    string sType = "";
                    try { sType = (string)oTable.Type; } catch { }

                    // Skip system catalog tables.
                    string sLowerName = sName.ToLowerInvariant();
                    if (sLowerName.StartsWith("sqlite_")) continue;
                    // SQLean's own bookkeeping tables (e.g. sqlean_define,
                    // created by the define extension) are internals, not
                    // user data -- keep them out of the default UI the way
                    // sqlite_ tables are. They stay reachable via raw SQL.
                    if (sLowerName.StartsWith("sqlean_")) continue;
                    if (sName.StartsWith("MSys", StringComparison.OrdinalIgnoreCase)) continue;
                    if (sType == "ACCESS TABLE") continue;
                    if (sType == "SYSTEM TABLE") continue;

                    bool bIsView = (sType == "VIEW");
                    bool bIsTable = !bIsView
                        && (sType == "TABLE" || sType == "PASS-THROUGH" || sType == "");

                    // Populate the type cache for selectTable's use.
                    dIsViewByName[sName] = bIsView;

                    if (bIsView && bIncludeViews) lResult.Add(sName);
                    else if (bIsTable && bIncludeTables) lResult.Add(sName);
                }
            }
            catch
            {
                // Provider without ADOX; caller will fall back to direct
                // SQL against sqlite_master / INFORMATION_SCHEMA.
            }
            lResult.Sort(StringComparer.OrdinalIgnoreCase);
            return lResult;
        }

        // True if the given name refers to a view rather than a base
        // table. Consults the schema-type cache populated by
        // getCatalogObjectNames. Returns false for unknown names.
        public bool isViewName(string sName)
        {
            return isKnownView(sName);
        }

        // getColumnsOfTable: list the column names of a named table
        // WITHOUT switching the current recordset to it. Used by the
        // Enter-Child drill-down to scan candidate child tables for a
        // foreign-key column matching the parent's primary key.
        //
        // Walks ADOX.Catalog.Tables[sTable].Columns. If ADOX is
        // unavailable on the current provider, falls back to opening
        // a minimal "SELECT * FROM table WHERE 1=0" recordset to
        // read the Fields collection without fetching any rows.
        // Both paths are read-only and don't disturb the current
        // recordset's filter/sort/position.
        public List<string> getColumnsOfTable(string sTable)
        {
            List<string> lResult = new List<string>();
            if (!isOpen() || string.IsNullOrEmpty(sTable)) return lResult;

            // First try ADOX. Cheap when it works.
            try
            {
                if (oCatalog == null)
                    oCatalog = createComObject("ADOX.Catalog");
                try { oCatalog.ActiveConnection = oConn; } catch { }
                dynamic oTable = oCatalog.Tables[sTable];
                dynamic oCols = oTable.Columns;
                int iCount = (int)oCols.Count;
                for (int i = 0; i < iCount; i++)
                {
                    dynamic oCol = oCols[i];
                    lResult.Add((string)oCol.Name);
                }
                if (lResult.Count > 0) return lResult;
            }
            catch
            {
                // Provider without ADOX (or table not in catalog).
                // Fall through to the empty-recordset path.
            }

            // Fallback: read field metadata as the QUERY ENGINE sees it,
            // which includes STORED GENERATED columns (look, prm/prm) that
            // ADOX omits.
            List<string> lViaSelect = getColumnsViaSelect(sTable);
            if (lViaSelect.Count > 0) lResult.AddRange(lViaSelect);
            return lResult;
        }

        // getColumnsViaSelect: column names as the query engine reports
        // them for SELECT * -- crucially INCLUDING the STORED GENERATED
        // columns (look and the prime-key column prm/prm). The ODBC
        // schema catalog used by ADOX does NOT list generated columns, so
        // this SELECT-based reader is the reliable source whenever the
        // generated key column must be detected (see primeColumnFor).
        // Opens a no-row recordset (WHERE 1=0) purely for its Fields.
        public List<string> getColumnsViaSelect(string sTable)
        {
            List<string> lResult = new List<string>();
            if (!isOpen() || string.IsNullOrEmpty(sTable)) return lResult;
            try
            {
                string sQuoted = "[" + sTable.Replace("]", "]]") + "]";
                dynamic oRs = createComObject("ADODB.Recordset");
                oRs.Open("SELECT * FROM " + sQuoted + " WHERE 1=0", oConn,
                    1 /* adOpenKeyset */, 1 /* adLockReadOnly */, 1 /* adCmdText */);
                dynamic oFields = oRs.Fields;
                int iCount = (int)oFields.Count;
                for (int i = 0; i < iCount; i++)
                    lResult.Add((string)oFields[i].Name);
                try { oRs.Close(); } catch { }
                releaseCom(oRs);
            }
            catch { }
            return lResult;
        }

        // primeColumnFor: the prime/unique-key column name of a named
        // table -- "prm" on databases this DbDo builds, and the legacy
        // "prm" on databases that predate the rename. Resolved by reading
        // the table's actual columns (SELECT * exposes the STORED
        // generated key column), so it is correct per table rather than
        // assuming a database-wide convention. Defaults to "prm" when
        // neither column is detectable, which is the right choice for
        // every database this DbDo creates. Used wherever SQL must name a
        // table's key column -- e.g. the related-table drill's
        // "<prime> IN (SELECT prmN FROM maps ...)" filter.
        public string primeColumnFor(string sTable)
        {
            try
            {
                // Read the columns as the QUERY ENGINE exposes them:
                // SELECT * includes the STORED GENERATED key column
                // (prm), which the ODBC schema catalog (ADOX, preferred
                // by getColumnsOfTable) omits -- leaving the key
                // undetected. Fall back to getColumnsOfTable only if the
                // SELECT reader returns nothing.
                List<string> lCols = getColumnsViaSelect(sTable);
                if (lCols.Count == 0) lCols = getColumnsOfTable(sTable);
                foreach (string sCol in lCols)
                    if (string.Equals(sCol, Metadata.PrimeColumn, StringComparison.OrdinalIgnoreCase))
                        return Metadata.PrimeColumn;
            }
            catch { }
            return Metadata.PrimeColumn;
        }

        // by running SELECT COUNT(*) FROM <table>. Returns -1 on any
        // error (table absent, provider quirk). Read-only; doesn't
        // disturb the current recordset's position, filter, or sort.
        //
        // Used by Database Summary (Alt+D) to report per-table totals.
        public long countRowsOfTable(string sTable)
        {
            if (!isOpen() || string.IsNullOrEmpty(sTable)) return -1;
            dynamic oRs = null;
            try
            {
                string sQuoted = "[" + sTable.Replace("]", "]]") + "]";
                oRs = createComObject("ADODB.Recordset");
                oRs.Open("SELECT COUNT(*) AS n FROM " + sQuoted, oConn,
                    0 /* adOpenForwardOnly */, 1 /* adLockReadOnly */, 1 /* adCmdText */);
                if ((bool)oRs.EOF) return 0;
                object v = oRs.Fields[0].Value;
                long n = (v == null || v == DBNull.Value) ? 0 : Convert.ToInt64(v);
                try { oRs.Close(); } catch { }
                return n;
            }
            catch
            {
                return -1;
            }
            finally
            {
                if (oRs != null) releaseCom(oRs);
            }
        }

        // actualPrimaryKey: look up the actual primary-key column of
        // a named table from the database's own schema metadata,
        // rather than guessing from the table-name singularization.
        //
        // The schema-truth approach matters because English-plural
        // rules are irregular: a table named "classes" has PK
        // "class_id" (not "classe_id" or "classes_id"); a table
        // named "cities" has PK "city_id" (not "citie_id"); a
        // table named "teachers" happens to work with naive
        // s-stripping. Rather than enumerate plural rules, we
        // read the real metadata.
        //
        // Strategy:
        //   1. SQLite -- query "PRAGMA table_info(<table>)" through
        //      ADO and look for the row with pk > 0. This is the
        //      authoritative source for SQLite.
        //   2. ADOX fallback -- for Access and other providers
        //      that expose ADOX.Catalog, ask for the table's
        //      primary-key Keys collection and read the first
        //      column from it.
        //
        // Returns the actual column name (preserving case) or null
        // if no PK can be determined. For composite primary keys
        // returns the FIRST column of the key.
        public string actualPrimaryKey(string sTable)
        {
            if (!isOpen() || string.IsNullOrEmpty(sTable)) return null;

            // SQLite path. PRAGMA returns one row per column; the
            // 'pk' column is 0 for non-PK columns and a 1-based
            // ordinal for PK columns. We want pk = 1 (or, for
            // composite keys, the column with the smallest pk).
            string sExt = currentExtensionForSql();
            if (sExt == "db" || sExt == "sqlite" || sExt == "sqlite3")
            {
                string sQuoted = "\"" + sTable.Replace("\"", "\"\"") + "\"";
                dynamic oRs = null;
                try
                {
                    oRs = createComObject("ADODB.Recordset");
                    oRs.Open("PRAGMA table_info(" + sQuoted + ")", oConn,
                        0 /* adOpenForwardOnly */, 1 /* adLockReadOnly */, 1 /* adCmdText */);
                    string sFirstPk = null;
                    int iFirstPkOrdinal = int.MaxValue;
                    while (!(bool)oRs.EOF)
                    {
                        try
                        {
                            // Fields: cid, name, type, notnull, dflt_value, pk
                            int iPk = 0;
                            try { iPk = Convert.ToInt32(oRs.Fields["pk"].Value); } catch { iPk = 0; }
                            if (iPk > 0 && iPk < iFirstPkOrdinal)
                            {
                                object objName = oRs.Fields["name"].Value;
                                if (objName != null && objName != DBNull.Value)
                                {
                                    sFirstPk = objName.ToString();
                                    iFirstPkOrdinal = iPk;
                                }
                            }
                        }
                        catch { }
                        oRs.MoveNext();
                    }
                    try { oRs.Close(); } catch { }
                    if (!string.IsNullOrEmpty(sFirstPk)) return sFirstPk;
                }
                catch (Exception ex)
                {
                    try { DbDoLog.write("actualPrimaryKey PRAGMA failed: " + ex.Message); } catch { }
                }
                finally { releaseCom(oRs); }
            }

            // ADOX path: applies to Access and other ADOX-friendly
            // providers, and is also a fallback when PRAGMA fails.
            try
            {
                if (oCatalog == null)
                    oCatalog = createComObject("ADOX.Catalog");
                try { oCatalog.ActiveConnection = oConn; } catch { }
                dynamic oTable = oCatalog.Tables[sTable];
                dynamic oKeys = oTable.Keys;
                int iKeyCount = (int)oKeys.Count;
                const int iAdKeyPrimary = 1;
                for (int i = 0; i < iKeyCount; i++)
                {
                    dynamic oKey = oKeys[i];
                    int iType = 0;
                    try { iType = Convert.ToInt32(oKey.Type); } catch { iType = 0; }
                    if (iType != iAdKeyPrimary) continue;
                    dynamic oCols = oKey.Columns;
                    if ((int)oCols.Count == 0) continue;
                    return (string)oCols[0].Name;
                }
            }
            catch { }

            return null;
        }

        // ---------------------------------------------------------------
        // Column declared-type metadata cache
        // ---------------------------------------------------------------
        //
        // dColumnTypes maps table -> column-name -> declared-type string.
        // Built lazily on first request per table; invalidated by
        // closeDatabase. Used to drive the textline/textmemo decision
        // for record-edit dialogs.
        //
        // The declared types stored here are whatever the schema says:
        //   - SQLite: the type token from CREATE TABLE, preserved
        //     verbatim by PRAGMA table_info. Common values include
        //     'textline', 'textmemo', 'text', 'integer', 'datetime',
        //     'boolean', etc. SQLite preserves the case the user used,
        //     so isMultilineColumn must compare case-insensitively.
        //   - Access: an integer ADOX Type constant translated to a
        //     name string (e.g. "MEMO" for adLongVarWChar). Mapping
        //     is approximate; we only need to recognize the memo case.
        //   - Other / unknown: empty string. isMultilineColumn returns
        //     false in this case, so the default single-line behavior
        //     applies.
        private Dictionary<string, Dictionary<string, string>> dColumnTypes
            = new Dictionary<string, Dictionary<string, string>>(StringComparer.OrdinalIgnoreCase);

        // getColumnDeclaredType: return the schema-declared type
        // string for one column, or "" if unknown. Caches per table
        // so repeated lookups during an edit-dialog build don't fire
        // duplicate PRAGMA queries.
        //
        // The returned string is the type as the schema author wrote
        // it (preserving case). Callers wanting to test for specific
        // type names should compare case-insensitively.
        public string getColumnDeclaredType(string sTable, string sColumn)
        {
            if (!isOpen() || string.IsNullOrEmpty(sTable) || string.IsNullOrEmpty(sColumn))
                return "";
            Dictionary<string, string> dForTable;
            if (!dColumnTypes.TryGetValue(sTable, out dForTable))
            {
                dForTable = loadColumnTypes(sTable);
                dColumnTypes[sTable] = dForTable;
            }
            string sType;
            return dForTable.TryGetValue(sColumn, out sType) ? sType : "";
        }

        // isMultilineColumn: should the edit dialog show this column
        // with a multi-line text box? True for SQLite types whose
        // declared name is 'textmemo' (case-insensitive); also true
        // for Access columns with MEMO affinity (ADOX type 203 ==
        // adLongVarWChar) or any declared type containing the
        // substring "memo".
        //
        // The convention is straightforward: name a SQLite column
        // 'textmemo' in CREATE TABLE if you intend its content to
        // span multiple lines. SQLite's type affinity rules group
        // anything containing 'TEXT' or 'BLOB' as TEXT or BLOB
        // affinity, so 'textmemo' stores identically to 'TEXT' --
        // the declared type is purely a hint for tools that read
        // the schema. PRAGMA table_info preserves it verbatim,
        // so DbDo can read it back and decide on the widget.
        public bool isMultilineColumn(string sTable, string sColumn)
        {
            string sType = getColumnDeclaredType(sTable, sColumn);
            if (string.IsNullOrEmpty(sType)) return false;
            return sType.IndexOf("memo", StringComparison.OrdinalIgnoreCase) >= 0
                || sType.IndexOf("markdown", StringComparison.OrdinalIgnoreCase) >= 0;
        }

        // isMarkdownColumn: the declared type is 'textmarkdown' --
        // a multi-line column (isMultilineColumn is also true) whose
        // content is expected to be Markdown, surfaced as a hint on
        // the edit control. SQLite gives it TEXT affinity like any
        // other TEXT* name; the declared name is the signal.
        public bool isMarkdownColumn(string sTable, string sColumn)
        {
            string sType = getColumnDeclaredType(sTable, sColumn);
            return !string.IsNullOrEmpty(sType)
                && sType.IndexOf("markdown", StringComparison.OrdinalIgnoreCase) >= 0;
        }

        // loadColumnTypes: read every column's declared type for one
        // table from the schema metadata. SQLite path is PRAGMA
        // table_info; Access path is ADOX.Catalog.Tables[t].Columns.
        // Returns an empty dictionary on failure (callers fall back
        // to default single-line behavior).
        private Dictionary<string, string> loadColumnTypes(string sTable)
        {
            Dictionary<string, string> dResult
                = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
            if (!isOpen() || string.IsNullOrEmpty(sTable)) return dResult;

            string sExt = currentExtensionForSql();

            // SQLite path: PRAGMA table_info exposes declared types
            // in column index 2 (cid=0, name=1, type=2, notnull=3,
            // dflt_value=4, pk=5).
            if (sExt == "db" || sExt == "sqlite" || sExt == "sqlite3")
            {
                string sQuoted = "\"" + sTable.Replace("\"", "\"\"") + "\"";
                dynamic oRs = null;
                try
                {
                    oRs = createComObject("ADODB.Recordset");
                    oRs.Open("PRAGMA table_info(" + sQuoted + ")", oConn,
                        0 /* adOpenForwardOnly */, 1 /* adLockReadOnly */, 1 /* adCmdText */);
                    while (!(bool)oRs.EOF)
                    {
                        string sName = "", sType = "";
                        try
                        {
                            object objName = oRs.Fields["name"].Value;
                            object objType = oRs.Fields["type"].Value;
                            if (objName != null && objName != DBNull.Value) sName = objName.ToString();
                            if (objType != null && objType != DBNull.Value) sType = objType.ToString();
                        }
                        catch { }
                        if (!string.IsNullOrEmpty(sName))
                            dResult[sName] = sType ?? "";
                        oRs.MoveNext();
                    }
                    try { oRs.Close(); } catch { }
                    return dResult;
                }
                catch (Exception ex)
                {
                    try { DbDoLog.write("loadColumnTypes PRAGMA failed: " + ex.Message); }
                    catch { }
                }
                finally { releaseCom(oRs); }
            }

            // ADOX path: works for Access, and is a fallback if the
            // SQLite path failed. The ADOX Type property is an
            // integer constant; we translate the few values that
            // matter for the textline/textmemo distinction.
            try
            {
                if (oCatalog == null)
                    oCatalog = createComObject("ADOX.Catalog");
                try { oCatalog.ActiveConnection = oConn; } catch { }
                dynamic oTable = oCatalog.Tables[sTable];
                dynamic oColumns = oTable.Columns;
                int iCount = (int)oColumns.Count;
                for (int i = 0; i < iCount; i++)
                {
                    dynamic oCol = oColumns[i];
                    string sName = "";
                    try { sName = (string)oCol.Name; } catch { }
                    if (string.IsNullOrEmpty(sName)) continue;
                    int iType = 0;
                    try { iType = Convert.ToInt32(oCol.Type); } catch { iType = 0; }
                    dResult[sName] = adoxTypeToDeclaredName(iType);
                }
            }
            catch { }

            return dResult;
        }

        // adoxTypeToDeclaredName: translate ADOX Type integer codes
        // to declared-type strings DbDo recognizes. Only covers
        // the cases that affect the edit dialog's textline/textmemo
        // decision; everything else maps to "" (which yields the
        // default single-line behavior).
        //   adLongVarWChar  (203)  -> "textmemo"  (Access "Memo")
        //   adLongVarChar   (201)  -> "textmemo"
        //   adVarWChar      (202)  -> "textline"  (Access "Text 255")
        //   adVarChar       (200)  -> "textline"
        //   adWChar         (130)  -> "textline"
        //   adChar          (129)  -> "textline"
        private static string adoxTypeToDeclaredName(int iType)
        {
            switch (iType)
            {
                case 201: case 203: return "textmemo";
                case 129: case 130: case 200: case 202: return "textline";
                default: return "";
            }
        }

        // SchemaColumn: structural metadata for one column. Used by
        // Table Summary (Alt+T) to render a per-column overview line
        // packing the maximum useful info: name, type, key/null/FK
        // status, default. Populated from PRAGMA table_info plus
        // PRAGMA foreign_key_list on SQLite; falls back to a minimal
        // (name + type) version on other backends.
        public class SchemaColumn
        {
            public string name;
            public string dataType;       // declared type, e.g. "TEXT" / "INTEGER"
            public bool   isPrimaryKey;
            public bool   notNull;
            public string defaultValue;   // empty if none
            public string foreignKeyRef;  // "tableName.columnName" or empty
        }

        // getSchemaColumns: return one SchemaColumn per column of the
        // given table, in natural (schema-defined) order. SQLite path
        // queries PRAGMA table_info plus PRAGMA foreign_key_list. For
        // other backends, returns just name + type from the open
        // recordset's Fields collection (no FK / PK / NOT NULL detail).
        // Returns an empty list on failure.
        public List<SchemaColumn> getSchemaColumns(string sTable)
        {
            List<SchemaColumn> lResult = new List<SchemaColumn>();
            if (!isOpen() || string.IsNullOrEmpty(sTable)) return lResult;

            string sExt = currentExtensionForSql();
            if (sExt == "db" || sExt == "sqlite" || sExt == "sqlite3")
            {
                // PRAGMA table_info: cid(0), name(1), type(2),
                // notnull(3), dflt_value(4), pk(5).
                string sQuoted = "\"" + sTable.Replace("\"", "\"\"") + "\"";
                dynamic oRs = null;
                try
                {
                    oRs = createComObject("ADODB.Recordset");
                    oRs.Open("PRAGMA table_info(" + sQuoted + ")", oConn,
                        0 /* adOpenForwardOnly */, 1 /* adLockReadOnly */, 1 /* adCmdText */);
                    while (!(bool)oRs.EOF)
                    {
                        SchemaColumn sc = new SchemaColumn();
                        try { sc.name = oRs.Fields["name"].Value.ToString(); } catch { sc.name = ""; }
                        try { sc.dataType = (oRs.Fields["type"].Value ?? "").ToString(); } catch { sc.dataType = ""; }
                        try
                        {
                            object v = oRs.Fields["notnull"].Value;
                            if (v != null) sc.notNull = Convert.ToInt32(v) != 0;
                        }
                        catch { }
                        try
                        {
                            object v = oRs.Fields["dflt_value"].Value;
                            if (v != null && v != DBNull.Value) sc.defaultValue = v.ToString();
                            else sc.defaultValue = "";
                        }
                        catch { sc.defaultValue = ""; }
                        try
                        {
                            object v = oRs.Fields["pk"].Value;
                            if (v != null) sc.isPrimaryKey = Convert.ToInt32(v) != 0;
                        }
                        catch { }
                        if (!string.IsNullOrEmpty(sc.name)) lResult.Add(sc);
                        oRs.MoveNext();
                    }
                    try { oRs.Close(); } catch { }
                }
                catch (Exception ex)
                {
                    try { DbDoLog.write("getSchemaColumns PRAGMA failed: " + ex.Message); }
                    catch { }
                }
                finally { releaseCom(oRs); }

                // PRAGMA foreign_key_list returns one row per FK
                // constraint: id(0), seq(1), table(2), from(3), to(4).
                // The 'from' column maps to one of our SchemaColumns.
                dynamic oFk = null;
                try
                {
                    oFk = createComObject("ADODB.Recordset");
                    oFk.Open("PRAGMA foreign_key_list(" + sQuoted + ")", oConn,
                        0, 1, 1);
                    while (!(bool)oFk.EOF)
                    {
                        string sFrom = "", sToTable = "", sToColumn = "";
                        try { sFrom = (oFk.Fields["from"].Value ?? "").ToString(); } catch { }
                        try { sToTable = (oFk.Fields["table"].Value ?? "").ToString(); } catch { }
                        try { sToColumn = (oFk.Fields["to"].Value ?? "").ToString(); } catch { }
                        if (!string.IsNullOrEmpty(sFrom) && !string.IsNullOrEmpty(sToTable))
                        {
                            foreach (SchemaColumn sc in lResult)
                            {
                                if (string.Equals(sc.name, sFrom, StringComparison.OrdinalIgnoreCase))
                                {
                                    sc.foreignKeyRef = string.IsNullOrEmpty(sToColumn)
                                        ? sToTable
                                        : (sToTable + "." + sToColumn);
                                    break;
                                }
                            }
                        }
                        oFk.MoveNext();
                    }
                    try { oFk.Close(); } catch { }
                }
                catch { }
                finally { releaseCom(oFk); }

                return lResult;
            }

            // Non-SQLite fallback: minimal (name + declared type) via
            // the open recordset's Fields collection. No FK / PK info.
            if (oRecordset != null)
            {
                try
                {
                    dynamic oFields = oRecordset.Fields;
                    int iCount = (int)oFields.Count;
                    for (int i = 0; i < iCount; i++)
                    {
                        dynamic oF = oFields[i];
                        SchemaColumn sc = new SchemaColumn();
                        try { sc.name = (string)oF.Name; } catch { sc.name = ""; }
                        try { sc.dataType = adoxTypeToDeclaredName(Convert.ToInt32(oF.Type)); }
                        catch { sc.dataType = ""; }
                        if (!string.IsNullOrEmpty(sc.name)) lResult.Add(sc);
                    }
                }
                catch { }
            }
            return lResult;
        }


        // pull values from one column of one table, with an optional
        // WHERE clause. Returns up to iMaxRows results as strings.
        // Used by Show-Object's related-records section to fetch
        // the 'look' values of child rows efficiently, without
        // touching the user's current recordset.
        //
        // We deliberately issue a parametric SQL query rather than
        // re-using the ADO client-side .Filter mechanism: the
        // server-side WHERE clause is O(matching rows) and lets
        // SQLite use any indexes on the FK column, while .Filter
        // is O(total rows in child table) because it post-filters
        // a fully-loaded client-cursor recordset. For Show-Object's
        // hot-path display this is the right choice.
        //
        // Returns iCountFound by reference so the caller can
        // distinguish "20 of 25 rows shown" from "exactly 20 rows
        // exist". Set iMaxRows to a large value (or int.MaxValue)
        // to get all rows.
        //
        // sTable and sColumn are quoted as identifiers per the
        // back-end's convention; sWhereExpr and sWhereValue go
        // through quoteSqlLiteral if you supply them, so caller
        // doesn't have to worry about SQL injection from FK values.
        public List<string> queryColumnValues(
            string sTable, string sColumn,
            string sWhereColumn, string sWhereValue,
            int iMaxRows, out int iCountFound)
        {
            iCountFound = 0;
            List<string> lValues = new List<string>();
            if (!isOpen() || string.IsNullOrEmpty(sTable) || string.IsNullOrEmpty(sColumn))
                return lValues;

            // Build the SQL. Use double-quoted identifiers, which
            // SQLite (default), Access (also accepts), and ANSI
            // SQL all support. Single-quote string literals with
            // apostrophe doubling.
            string sExt = currentExtensionForSql();
            StringBuilder sb = new StringBuilder();
            sb.Append("SELECT ");
            sb.Append(quoteIdentifier(sColumn, sExt));
            sb.Append(" FROM ");
            sb.Append(quoteIdentifier(sTable, sExt));
            if (!string.IsNullOrEmpty(sWhereColumn))
            {
                sb.Append(" WHERE ");
                sb.Append(quoteIdentifier(sWhereColumn, sExt));
                if (string.IsNullOrEmpty(sWhereValue))
                {
                    sb.Append(" IS NULL");
                }
                else
                {
                    // If the value parses as a number, leave bare;
                    // otherwise single-quote with apostrophe doubling.
                    double dN;
                    if (double.TryParse(sWhereValue,
                            System.Globalization.NumberStyles.Any,
                            System.Globalization.CultureInfo.InvariantCulture,
                            out dN))
                    { sb.Append(" = "); sb.Append(sWhereValue); }
                    else
                    { sb.Append(" = '"); sb.Append(sWhereValue.Replace("'", "''")); sb.Append("'"); }
                }
            }

            dynamic oRs = null;
            try
            {
                oRs = createComObject("ADODB.Recordset");
                // Server-side cursor for this fetch: we only need
                // forward-only reads and we don't want to disturb
                // the manager's client-side cursor settings.
                oRs.Open(sb.ToString(), oConn,
                    0 /* adOpenForwardOnly */,
                    1 /* adLockReadOnly */,
                    1 /* adCmdText */);
                while (!(bool)oRs.EOF)
                {
                    iCountFound++;
                    if (lValues.Count < iMaxRows)
                    {
                        object objV;
                        try { objV = oRs.Fields[0].Value; } catch { objV = null; }
                        lValues.Add((objV == null || objV == DBNull.Value) ? "" : objV.ToString());
                    }
                    oRs.MoveNext();
                }
                try { oRs.Close(); } catch { }
            }
            catch (Exception ex)
            {
                // Caller may want to know the query failed (e.g.,
                // 'look' column doesn't exist on this table). The
                // out param iCountFound stays at 0 and the list
                // stays empty; log for diagnostics.
                try { DbDoLog.write("queryColumnValues failed: " + ex.Message + " SQL=" + sb.ToString()); }
                catch { }
            }
            finally
            {
                releaseCom(oRs);
            }
            return lValues;
        }

        // getLookupValues: the valid-value choices the builtin
        // lookups table offers for one table+field pair, in ordinal
        // then alphabetical order. Powers the F4 / Alt+DownArrow
        // pick list in the edit dialog (and, later, the grid-side
        // Pick Value command). Convention over configuration: any
        // table whose rows carry matching tbl and fld values opts
        // that field into pick lists with no further setup.
        public List<string> getLookupValues(string sTbl, string sFld, int iMaxRows)
        {
            int iFound;
            List<string> lsValues = new List<string>();
            if (!isOpen() || string.IsNullOrEmpty(sTbl) || string.IsNullOrEmpty(sFld)) return lsValues;
            string sSql = "SELECT val FROM lookups WHERE tbl = '" + sTbl.Replace("'", "''")
                + "' AND fld = '" + sFld.Replace("'", "''")
                + "' ORDER BY ordinal, val";
            foreach (string[] aRow in queryRowsSql(sSql, iMaxRows, out iFound))
            {
                if (aRow.Length > 0 && aRow[0].Length > 0) lsValues.Add(aRow[0]);
            }
            return lsValues;
        }

        // adoDiagnostics: walk the connection's ADO Errors
        // collection -- where the provider parks one Error object
        // per problem (Number, NativeError, SQLState, Source,
        // Description) after a failed operation -- and render it as
        // text for the error dialog's details. The collection
        // persists until the next ADO operation, so it is read at
        // error-display time. (ADO also raises connection events --
        // InfoMessage for provider warnings, ExecuteComplete /
        // WillExecute around statements -- which a future build can
        // sink for a rolling log; the Errors collection is the
        // reliable post-mortem source and is what ships here.)
        public string adoDiagnostics()
        {
            try
            {
                if (oConn == null) return "";
                dynamic oErrors = oConn.Errors;
                int iCount = (int)oErrors.Count;
                if (iCount == 0) return "";
                System.Text.StringBuilder sbDiag = new System.Text.StringBuilder();
                sbDiag.AppendLine("ADO provider errors (" + iCount + "):");
                for (int i = 0; i < iCount; i++)
                {
                    dynamic oErr = oErrors[i];
                    try
                    {
                        sbDiag.AppendLine("  [" + (i + 1) + "] " + (string)(oErr.Description ?? ""));
                        sbDiag.AppendLine("      Number=0x" + ((int)oErr.Number).ToString("X8")
                            + "  NativeError=" + (int)oErr.NativeError
                            + "  SQLState=" + (string)(oErr.SQLState ?? "")
                            + "  Source=" + (string)(oErr.Source ?? ""));
                    }
                    catch { }
                }
                return sbDiag.ToString();
            }
            catch { return ""; }
        }

        // countMarked: how many records in the CURRENT filtered view
        // have marked = true. Uses an ADO clone of the live
        // recordset, so the user's cursor position and filter are
        // untouched and no re-query happens (the clone shares the
        // client-side rowset). The clone does not inherit the live
        // Filter, so the base filter is re-applied combined with the
        // marked test. DbDo writes marked as the literal 'true', so
        // that is the value tested. Returns -1 when the clone path
        // fails (complex base filters can exceed ADO's filter
        // grammar); callers fall back to a position walk.
        public int countMarked()
        {
            if (!hasRecordset()) return 0;
            // SQL-direct fast path: when no ADO filter is active and
            // the recordset spans the whole table, the count goes
            // straight to SQLite -- SELECT COUNT(*) ... WHERE
            // marked = 'true' is answered from the marked-column
            // index (see the CREATE INDEX IF NOT EXISTS machinery)
            // without touching the rowset. The whole-table test
            // compares the table's COUNT(*) to recordCount so a
            // subset recordset (child views, Open Recordset) never
            // overcounts; any failure falls through to the clone.
            if (string.IsNullOrEmpty(filter) && !string.IsNullOrEmpty(currentTable))
            {
                try
                {
                    int iFound;
                    int iParsed;
                    int iTotal = -1;
                    int iMarkedSql = -1;
                    string sQuoted = "\"" + currentTable.Replace("\"", "\"\"") + "\"";
                    foreach (string[] aRow in queryRowsSql("SELECT COUNT(*) FROM " + sQuoted, 1, out iFound))
                        if (aRow.Length > 0 && int.TryParse(aRow[0], out iParsed)) iTotal = iParsed;
                    if (iTotal == recordCount)
                    {
                        foreach (string[] aRow in queryRowsSql("SELECT COUNT(*) FROM " + sQuoted
                            + " WHERE " + Metadata.MarkedColumn + " = 'true'", 1, out iFound))
                            if (aRow.Length > 0 && int.TryParse(aRow[0], out iParsed)) iMarkedSql = iParsed;
                        if (iMarkedSql >= 0) return iMarkedSql;
                    }
                }
                catch { /* fall through to the clone path */ }
            }
            try
            {
                dynamic oClone = oRecordset.Clone(AdoConstants.adLockReadOnly);
                try
                {
                    string sBase = filter ?? "";
                    string sMarkTest = Metadata.MarkedColumn + " = 'true'";
                    oClone.Filter = (sBase.Length > 0)
                        ? sBase + " AND " + sMarkTest : sMarkTest;
                    return oClone.RecordCount;
                }
                finally { try { oClone.Close(); } catch { } }
            }
            catch { return -1; }
        }

        // getObjectSql: the verbatim CREATE statement SQLite stores
        // for a table or view in sqlite_master. SQLite preserves the
        // raw statement text exactly as given, INCLUDING comments --
        // a documented behavior the project treats as a feature --
        // which is what makes comment-embedded schema documentation
        // possible. Caveat (also documented upstream): ALTER TABLE
        // ADD/RENAME/DROP COLUMN can rewrite this text and erase or
        // mangle comments; DbDo's regenerate-the-table approach to
        // schema changes composes its own CREATE statements, so it
        // controls (and should re-emit) the doc comments.
        public string getObjectSql(string sName)
        {
            int iFound;
            if (!isOpen() || string.IsNullOrEmpty(sName)) return "";
            string sSql = "SELECT sql FROM sqlite_master WHERE name = '"
                + sName.Replace("'", "''") + "'";
            foreach (string[] aRow in queryRowsSql(sSql, 1, out iFound))
            {
                if (aRow.Length > 0) return aRow[0] ?? "";
            }
            return "";
        }

        // getSchemaDoc: parse the doc comments embedded in an
        // object's CREATE statement, using the sqlite-docs
        // convention (github.com/asg017/sqlite-docs) so DbDo
        // databases are readable by that ecosystem too:
        //
        //   --! key: value     table-level documentation. DbDo treats
        //                      the text as YAML-ish key/value when a
        //                      colon is present (name, author,
        //                      version, description, abstract,
        //                      relationships, ...), free prose
        //                      otherwise (key returned as "").
        //   --- prose          documentation for the COLUMN whose
        //                      definition follows the comment line.
        //
        // Returned as parallel lists of [key, value] pairs
        // (lsTableDoc) and [column, doc] pairs (lsColumnDocs).
        // DbDo convention for DATABASE-level metadata: the --! block
        // of the builtin lookups table (present in every DbDo
        // database) describes the database itself.
        public bool getSchemaDoc(string sName,
            out List<string[]> lsTableDoc, out List<string[]> lsColumnDocs)
        {
            lsTableDoc = new List<string[]>();
            lsColumnDocs = new List<string[]>();
            string sCreate = getObjectSql(sName);
            if (string.IsNullOrEmpty(sCreate)) return false;
            List<string> lsPending = new List<string>();
            foreach (string sRaw in sCreate.Replace("\r", "").Split('\n'))
            {
                string sLine = sRaw.Trim();
                if (sLine.StartsWith("--!"))
                {
                    string sBody = sLine.Substring(3).Trim();
                    int iColon = sBody.IndexOf(':');
                    if (iColon > 0 && iColon < 40)
                        lsTableDoc.Add(new string[] {
                            sBody.Substring(0, iColon).Trim(),
                            sBody.Substring(iColon + 1).Trim() });
                    else if (sBody.Length > 0)
                        lsTableDoc.Add(new string[] { "", sBody });
                }
                else if (sLine.StartsWith("---"))
                {
                    string sDoc = sLine.Substring(3).Trim();
                    if (sDoc.Length > 0) lsPending.Add(sDoc);
                }
                else if (lsPending.Count > 0 && sLine.Length > 0
                    && !sLine.StartsWith("--")
                    && sLine.IndexOf("CREATE ", StringComparison.OrdinalIgnoreCase) < 0)
                {
                    // The first identifier on this line is the column
                    // the pending --- lines document.
                    string sCol = sLine.TrimStart('"', '[', '`');
                    int iEnd = 0;
                    while (iEnd < sCol.Length
                        && (char.IsLetterOrDigit(sCol[iEnd]) || sCol[iEnd] == '_')) iEnd++;
                    sCol = sCol.Substring(0, iEnd);
                    if (sCol.Length > 0)
                        foreach (string sDoc in lsPending)
                            lsColumnDocs.Add(new string[] { sCol, sDoc });
                    lsPending.Clear();
                }
            }
            return lsTableDoc.Count > 0 || lsColumnDocs.Count > 0;
        }

        // queryRowsSql: run an arbitrary SELECT on the shared
        // connection through a transient forward-only, read-only
        // recordset (same isolation rationale as queryColumnValues)
        // and return up to iMaxRows rows, each as a string array of
        // its column values (NULL -> ""). The caller composes the
        // SQL and is responsible for quoting; used by the maps
        // relationship helpers, whose queries need multiple WHERE
        // conditions and multiple output columns.
        public List<string[]> queryRowsSql(string sSql, int iMaxRows, out int iCountFound)
        {
            iCountFound = 0;
            List<string[]> lRows = new List<string[]>();
            if (!isOpen() || string.IsNullOrEmpty(sSql)) return lRows;
            dynamic oRs = null;
            try
            {
                oRs = createComObject("ADODB.Recordset");
                oRs.Open(sSql, oConn,
                    0 /* adOpenForwardOnly */,
                    1 /* adLockReadOnly */,
                    1 /* adCmdText */);
                int iFieldCount = (int)oRs.Fields.Count;
                while (!(bool)oRs.EOF)
                {
                    iCountFound++;
                    if (lRows.Count < iMaxRows)
                    {
                        string[] aRow = new string[iFieldCount];
                        for (int i = 0; i < iFieldCount; i++)
                        {
                            object objV;
                            try { objV = oRs.Fields[i].Value; } catch { objV = null; }
                            aRow[i] = (objV == null || objV == DBNull.Value) ? "" : objV.ToString();
                        }
                        lRows.Add(aRow);
                    }
                    oRs.MoveNext();
                }
                try { oRs.Close(); } catch { }
            }
            catch (Exception ex)
            {
                try { DbDoLog.write("queryRowsSql failed: " + ex.Message + " SQL=" + sSql); }
                catch { }
            }
            finally
            {
                releaseCom(oRs);
            }
            return lRows;
        }

        // hasMapsTable: true when the open database contains the
        // standard maps association table. Cached per table-list
        // fetch is unnecessary; the table list is already cached by
        // the manager, so this is a cheap scan.
        public bool hasMapsTable()
        {
            try
            {
                foreach (string sT in getTableNames())
                    if (string.Equals(sT, "maps", StringComparison.OrdinalIgnoreCase))
                        return true;
            }
            catch { }
            return false;
        }

        // sQuoteSqlLiteral: single-quote a string literal for SQL,
        // doubling embedded apostrophes.
        public static string sQuoteSqlLiteral(string sValue)
        {
            return "'" + (sValue ?? "").Replace("'", "''") + "'";
        }

        // lMapsRelations: every maps row touching the given record,
        // identified by its (table, prm) pair, in BOTH directions.
        // Each result row is: kind, other table, other prm, direction
        // ("subject" when the given record is tbl1/prm1, "object"
        // when it is tbl2/prm2), and the map row's notes.
        public List<string[]> lMapsRelations(string sTable, string sPrmValue, int iMaxRows)
        {
            List<string[]> lAll = new List<string[]>();
            if (string.IsNullOrEmpty(sTable) || string.IsNullOrEmpty(sPrmValue)) return lAll;
            if (!hasMapsTable()) return lAll;
            string sT = sQuoteSqlLiteral(sTable);
            string sU = sQuoteSqlLiteral(sPrmValue);
            int iFound;
            // The record as subject: related records are on side 2.
            foreach (string[] aRow in queryRowsSql(
                "SELECT kind, tbl2, prm2, 'subject', notes FROM maps WHERE tbl1 = "
                + sT + " AND prm1 = " + sU, iMaxRows, out iFound))
                lAll.Add(aRow);
            // The record as object: related records are on side 1.
            foreach (string[] aRow in queryRowsSql(
                "SELECT kind, tbl1, prm1, 'object', notes FROM maps WHERE tbl2 = "
                + sT + " AND prm2 = " + sU, iMaxRows, out iFound))
                lAll.Add(aRow);
            return lAll;
        }

        // sMapsEdgesCte: the normalized undirected edge view of maps,
        // shared by the two-hop queries. Each map row contributes an
        // edge in each direction, so traversal logic never has to
        // case-split on which side a record sits.
        private const string sMapsEdgesCte =
            "WITH edges(ft, fu, tt, tu) AS ("
            + "SELECT tbl1, prm1, tbl2, prm2 FROM maps "
            + "UNION ALL SELECT tbl2, prm2, tbl1, prm1 FROM maps) ";

        // lMapsTwoHop: records related to the given record THROUGH an
        // intermediate record -- contact -> events -> locations being
        // the canonical case ("where does this person's work happen").
        // Each result row is: via table, target table, target prm.
        // The starting record itself is excluded from the targets.
        // Requires a provider that accepts CTEs (SQLite does); on
        // failure the query helper returns an empty list, so callers
        // degrade gracefully to direct relations only.
        public List<string[]> lMapsTwoHop(string sTable, string sPrmValue, int iMaxRows)
        {
            List<string[]> lAll = new List<string[]>();
            if (string.IsNullOrEmpty(sTable) || string.IsNullOrEmpty(sPrmValue)) return lAll;
            if (!hasMapsTable()) return lAll;
            string sT = sQuoteSqlLiteral(sTable);
            string sU = sQuoteSqlLiteral(sPrmValue);
            int iFound;
            string sSql = sMapsEdgesCte
                + "SELECT DISTINCT e1.tt, e2.tt, e2.tu FROM edges e1 "
                + "JOIN edges e2 ON e2.ft = e1.tt AND e2.fu = e1.tu "
                + "WHERE e1.ft = " + sT + " AND e1.fu = " + sU
                + " AND NOT (e2.tt = " + sT + " AND e2.tu = " + sU + ")";
            foreach (string[] aRow in queryRowsSql(sSql, iMaxRows, out iFound))
                lAll.Add(aRow);
            return lAll;
        }

        // lMapsTwoHopTargets: the distinct target prm values for one
        // chosen (via table, target table) pair -- the filter set for
        // a two-hop drill.
        public List<string> lMapsTwoHopTargets(string sTable, string sPrmValue,
            string sViaTable, string sTargetTable, int iMaxRows, out int iCountFound)
        {
            List<string> lTargets = new List<string>();
            string sSql = sMapsEdgesCte
                + "SELECT DISTINCT e2.tu FROM edges e1 "
                + "JOIN edges e2 ON e2.ft = e1.tt AND e2.fu = e1.tu "
                + "WHERE e1.ft = " + sQuoteSqlLiteral(sTable)
                + " AND e1.fu = " + sQuoteSqlLiteral(sPrmValue)
                + " AND e1.tt = " + sQuoteSqlLiteral(sViaTable)
                + " AND e2.tt = " + sQuoteSqlLiteral(sTargetTable)
                + " AND NOT (e2.tt = " + sQuoteSqlLiteral(sTable)
                + " AND e2.tu = " + sQuoteSqlLiteral(sPrmValue) + ")";
            foreach (string[] aRow in queryRowsSql(sSql, iMaxRows, out iCountFound))
                lTargets.Add(aRow[0]);
            return lTargets;
        }

        // Current connection's extension key, used by
        // queryColumnValues to pick identifier-quoting style.
        // Falls back to "db" (SQLite) when nothing else fits.
        private string currentExtensionForSql()
        {
            if (string.IsNullOrEmpty(sFilePath)) return "db";
            string sExt = Path.GetExtension(sFilePath).TrimStart('.').ToLowerInvariant();
            switch (sExt)
            {
                case "db": case "sqlite": case "sqlite3": return "db";
                case "mdb": case "accdb": return "accdb";
                case "xlsx": case "xls": case "xlsm": case "xlsb": return "xlsx";
                case "csv": case "tsv": case "tab": case "txt": return "csv";
                case "dbf": return "dbf";
                default: return "db";
            }
        }
        public bool eof
        {
            get
            {
                if (!hasRecordset()) return true;
                try { return (bool)oRecordset.EOF; } catch { return true; }
            }
        }

        public bool bof
        {
            get
            {
                if (!hasRecordset()) return true;
                try { return (bool)oRecordset.BOF; } catch { return true; }
            }
        }

        public int recordCount
        {
            get
            {
                if (!hasRecordset()) return 0;
                try { return (int)oRecordset.RecordCount; } catch { return -1; }
            }
        }

        // =====================================================================
        // absolutePosition: 1-based dBase-tradition position. Matches
        // dbDot's convention exactly. ADODB also uses 1-based positions
        // (with -1, -2, -3 sentinels for unknown / BOF / EOF).
        //
        // The setter is the canonical "go to row N" operation.
        // =====================================================================
        public int absolutePosition
        {
            get
            {
                if (!hasRecordset()) return 0;
                try
                {
                    int i = (int)oRecordset.AbsolutePosition;
                    return i < 0 ? 0 : i;  // hide BOF/EOF/unknown sentinels from callers
                }
                catch { return 0; }
            }
            set
            {
                if (!hasRecordset()) return;
                if (recordCount == 0) return;
                int i = value;
                if (i < 1) i = 1;
                if (i > recordCount) i = recordCount;
                try { oRecordset.AbsolutePosition = i; } catch { }
            }
        }

        // =====================================================================
        // bookmark: opaque handle to the current row's identity.
        // Survives sort and filter changes (when the row remains in
        // the filtered set). The single most important property in
        // the synchronization design -- both the GUI's grid refresh
        // and the CLI's navigation can capture-then-restore around
        // any state change.
        //
        // Caller holds the value as an `object` and treats it as
        // opaque; the getter and setter just round-trip it through COM.
        // =====================================================================
        public object bookmark
        {
            get
            {
                if (!hasRecordset()) return null;
                try
                {
                    if (eof || bof) return null;
                    return oRecordset.Bookmark;
                }
                catch { return null; }
            }
            set
            {
                if (!hasRecordset() || value == null) return;
                try { oRecordset.Bookmark = value; }
                catch
                {
                    // Bookmark no longer valid (record removed by
                    // filter or deletion). Fall to first row.
                    try { oRecordset.MoveFirst(); } catch { }
                }
            }
        }

        // =====================================================================
        // filter / sort: server-side recordset operations. Both
        // capture the bookmark before the change and try to restore
        // it after, so the user's logical "current record" follows
        // itself across sort and filter changes when possible.
        // =====================================================================
        public string filter
        {
            get
            {
                if (!hasRecordset()) return "";
                try { return (string)(oRecordset.Filter ?? ""); }
                catch { return ""; }
            }
            set
            {
                if (!hasRecordset()) return;
                object bookmarkObj = bookmark;
                try { oRecordset.Filter = value ?? ""; }
                catch (COMException ex)
                {
                    throw new Exception("Filter rejected: " + ex.Message, ex);
                }
                if (bookmarkObj != null) bookmark = bookmarkObj;
            }
        }

        public string sort
        {
            get { return sActiveSort ?? ""; }
            set
            {
                if (!hasRecordset()) return;
                sActiveSort = (value ?? "").Trim();
                reopenWithCurrentSort();
            }
        }

        // reopenWithCurrentSort: apply sActiveSort by re-querying the
        // current table with a SQL ORDER BY clause, preserving the
        // active filter and a valid cursor position. This deliberately
        // avoids ADO's client-cursor Recordset.Sort, which returns NULL
        // for every field with some ODBC providers (the "all cells go
        // blank after sorting" bug). For a custom-SQL recordset (a query
        // window), there is no single table to re-SELECT, so the ADO
        // Sort property is used as a fallback there.
        private void reopenWithCurrentSort()
        {
            if (oRecordset == null) return;
            if (!string.IsNullOrEmpty(sSourceSql))
            {
                try { oRecordset.Sort = sActiveSort ?? ""; } catch { }
                return;
            }
            string sTable = sCurrentTable;
            if (string.IsNullOrEmpty(sTable)) return;

            string sExt = "";
            try { sExt = System.IO.Path.GetExtension(sFilePath ?? "").TrimStart('.').ToLowerInvariant(); }
            catch { }

            // Preserve the ADO filter (which DOES work) across the re-open.
            string sSavedFilter = "";
            try { sSavedFilter = (string)(oRecordset.Filter ?? ""); } catch { }

            bool bIsView = bCurrentIsView;
            int iLock = (bReadOnly || bIsView)
                ? AdoConstants.adLockReadOnly : AdoConstants.adLockOptimistic;

            string sOrderBy = buildOrderByClause(sActiveSort, sExt);
            string sSql = "SELECT * FROM " + quoteOpenTable(sTable)
                + (sOrderBy.Length > 0 ? " ORDER BY " + sOrderBy : "");

            try
            {
                closeRecordset();
                oRecordset = createComObject("ADODB.Recordset");
                oRecordset.CursorLocation = AdoConstants.adUseClient;
                oRecordset.Open(sSql, oConn, AdoConstants.adOpenStatic, iLock, AdoConstants.adCmdText);
                try { DbDoLog.write("Sort via ORDER BY: " + (sOrderBy.Length > 0 ? sOrderBy : "(cleared)")
                    + "; rows=" + (int)oRecordset.RecordCount); } catch { }
            }
            catch (COMException ex)
            {
                try { DbDoLog.write("Sort ORDER BY rejected: " + ex.Message + "; SQL: " + sSql); } catch { }
                // Don't leave a dead recordset: re-open the table unsorted.
                try
                {
                    oRecordset = createComObject("ADODB.Recordset");
                    oRecordset.CursorLocation = AdoConstants.adUseClient;
                    oRecordset.Open("SELECT * FROM " + quoteOpenTable(sTable), oConn,
                        AdoConstants.adOpenStatic, iLock, AdoConstants.adCmdText);
                    sActiveSort = "";
                }
                catch { }
                throw new Exception("Sort rejected: " + ex.Message, ex);
            }

            // Re-apply the filter that was active before the re-open.
            if (!string.IsNullOrEmpty(sSavedFilter))
            { try { oRecordset.Filter = sSavedFilter; } catch { } }

            try { if ((int)oRecordset.RecordCount > 0) oRecordset.MoveFirst(); } catch { }
        }

        // buildOrderByClause: turn the user-facing sort ("col asc,
        // col2 desc") into a provider-quoted SQL ORDER BY body
        // ("\"col\" ASC, \"col2\" DESC"). Each column is quoted with the
        // same helper the rest of the SQL builders use, so reserved
        // words and mixed case are safe. Unknown direction tokens
        // default to ASC.
        private string buildOrderByClause(string sSortClause, string sExt)
        {
            if (string.IsNullOrEmpty(sSortClause)) return "";
            List<string> lParts = new List<string>();
            foreach (string sRaw in sSortClause.Split(','))
            {
                string s = sRaw.Trim();
                if (s.Length == 0) continue;
                string sDir = "ASC";
                string sCol = s;
                int iSpace = s.LastIndexOf(' ');
                if (iSpace > 0)
                {
                    string sTail = s.Substring(iSpace + 1).Trim();
                    if (sTail.Equals("DESC", StringComparison.OrdinalIgnoreCase))
                    { sDir = "DESC"; sCol = s.Substring(0, iSpace).Trim(); }
                    else if (sTail.Equals("ASC", StringComparison.OrdinalIgnoreCase))
                    { sDir = "ASC"; sCol = s.Substring(0, iSpace).Trim(); }
                }
                // Strip any quoting the caller may have included.
                sCol = sCol.Trim('"', '[', ']', '`');
                if (sCol.Length == 0) continue;
                lParts.Add(quoteIdentifier(sCol, sExt) + " " + sDir);
            }
            return string.Join(", ", lParts.ToArray());
        }

        public void resetFilter() { filter = ""; }
        public void resetSort() { sort = ""; }

        // applyFilter: convenience alias used by Show-Related, identical
        // to setting the filter property.
        public void applyFilter(string sCriteria)
        {
            filter = sCriteria;
        }

        // ------- Field-type introspection -------
        // These wrap ADO Field.Type, Field.DefinedSize, and translate
        // the integer DataTypeEnum to a human-readable name. Used by
        // Get-Property to render the schema details dialog.
        public int getFieldType(string sName)
        {
            if (!hasRecordset()) return 0;
            try { return (int)oRecordset.Fields[sName].Type; }
            catch { return 0; }
        }

        public int getFieldDefinedSize(string sName)
        {
            if (!hasRecordset()) return 0;
            try { return (int)oRecordset.Fields[sName].DefinedSize; }
            catch { return 0; }
        }

        public string getFieldTypeName(string sName)
        {
            int iType = getFieldType(sName);
            switch (iType)
            {
                case   2: return "smallint";
                case   3: return "integer";
                case   4: return "real";
                case   5: return "double";
                case   6: return "currency";
                case   7: return "date";
                case  11: return "boolean";
                case  17: return "tinyint";
                case  18: return "unsignedsmallint";
                case  19: return "unsignedint";
                case  20: return "bigint";
                case  72: return "guid";
                case 128: return "binary";
                case 130: return "wchar";
                case 131: return "decimal";
                case 133: return "dbdate";
                case 134: return "dbtime";
                case 135: return "dbtimestamp";
                case 200: return "varchar";
                case 201: return "longvarchar";
                case 202: return "varwchar";
                case 203: return "longvarwchar";
                case 204: return "varbinary";
                case 205: return "longvarbinary";
                default:  return "type" + iType;
            }
        }

        // ------- Navigation -------
        public void moveFirst()    { if (hasRecordset()) try { oRecordset.MoveFirst();    } catch { } }
        public void moveLast()     { if (hasRecordset()) try { oRecordset.MoveLast();     } catch { } }
        public void moveNext()     { if (hasRecordset()) try { oRecordset.MoveNext();     } catch { } }
        public void movePrevious() { if (hasRecordset()) try { oRecordset.MovePrevious(); } catch { } }

        // =====================================================================
        // findRecord: ADODB's Find method walks the cursor forward
        // (or backward) from a starting position to the first row
        // matching the criteria expression. The expression is a
        // single-column predicate: "lastName LIKE '%Smith%'" or
        // "salary > 50000". Multi-column searches require multiple
        // Find calls, but that matches the GUI's Find dialog UX.
        //
        // Returns true on match (cursor on the row); false on no
        // match (cursor at EOF or BOF, restored to original position).
        // =====================================================================
        public bool findRecord(string sCriteria, bool bForward, bool bFromCurrent)
        {
            if (!hasRecordset()) return false;
            if (string.IsNullOrEmpty(sCriteria)) return false;

            int iDir = bForward ? AdoConstants.adSearchForward : AdoConstants.adSearchBackward;
            int iStart = bFromCurrent
                ? AdoConstants.adBookmarkCurrent
                : (bForward ? AdoConstants.adBookmarkFirst : AdoConstants.adBookmarkLast);

            object bookmarkSaved = bookmark;
            try
            {
                // ADODB Find(criteria, skipRows, searchDirection, start)
                // Skip 1 row if we're starting from current and going
                // forward, so we don't match the row we're already on.
                int iSkip = bFromCurrent ? (bForward ? 1 : -1) : 0;
                oRecordset.Find(sCriteria, iSkip, iDir, iStart);
            }
            catch (COMException ex)
            {
                throw new Exception("Find rejected: " + ex.Message, ex);
            }

            if (eof || bof)
            {
                // No match. Restore.
                if (bookmarkSaved != null) bookmark = bookmarkSaved;
                return false;
            }
            return true;
        }

        // findRegexRecord: move the cursor to the next (or previous)
        // row whose value in the named column matches the .NET regex.
        // If sColumn is null/empty or "*", any column matching the
        // regex counts as a hit (the cursor stops at the first such
        // row encountered).
        //
        // Unlike findRecord (which delegates to ADO's own Find with
        // LIKE semantics), this walks the recordset row-by-row in
        // memory. The client-cursor recordset makes the walk O(N) in
        // memory access, not disk seeks. Use plain Find for the
        // common case of case-insensitive substring matching; use
        // this for regex requirements -- anchors, alternation,
        // character classes, lookahead, etc.
        //
        // Returns true if a match was found (cursor on the matched
        // row); false otherwise (cursor restored to its original row).
        public bool findRegexRecord(string sColumn, string sPattern,
                                    bool bForward, bool bFromCurrent)
        {
            if (!hasRecordset()) return false;
            if (string.IsNullOrEmpty(sPattern)) return false;

            System.Text.RegularExpressions.Regex regex;
            try
            {
                regex = new System.Text.RegularExpressions.Regex(sPattern,
                    System.Text.RegularExpressions.RegexOptions.IgnoreCase
                    | System.Text.RegularExpressions.RegexOptions.CultureInvariant);
            }
            catch (Exception ex) { throw new Exception("Regex invalid: " + ex.Message, ex); }

            bool bAnyColumn = string.IsNullOrEmpty(sColumn) || sColumn == "*";
            List<string> lColumns = bAnyColumn ? getFieldNames() : new List<string>(new[] { sColumn });

            object bookmarkSaved = bookmark;

            // Choose the starting row and step direction.
            try
            {
                if (!bFromCurrent)
                {
                    if (bForward) moveFirst();
                    else          moveLast();
                }
                else
                {
                    // Step off the current row so we don't re-match it.
                    if (bForward) moveNext();
                    else          movePrevious();
                }
            }
            catch { }

            while (!eof && !bof)
            {
                foreach (string sCol in lColumns)
                {
                    string sV = getFieldValue(sCol);
                    if (sV != null && regex.IsMatch(sV))
                        return true;  // cursor is on the match
                }
                try { if (bForward) moveNext(); else movePrevious(); } catch { break; }
            }

            // No match. Restore.
            if (bookmarkSaved != null)
                try { bookmark = bookmarkSaved; } catch { }
            return false;
        }

        // =====================================================================
        // Field access. Field names are case-insensitive in ADODB.
        // Reading returns the stringified value; writing assigns and
        // does NOT call Update -- caller must call update() to commit.
        // This matches dbDot's pattern of "set fields then save."
        // =====================================================================
        public List<string> getFieldNames()
        {
            List<string> lResult = new List<string>();
            if (!hasRecordset()) return lResult;
            try
            {
                dynamic oFields = oRecordset.Fields;
                int iCount = (int)oFields.Count;
                for (int i = 0; i < iCount; i++)
                    lResult.Add((string)oFields[i].Name);
            }
            catch { }
            return lResult;
        }

        // getDisplayFieldNames: the columns the data list view
        // should show. Two-tier resolution:
        //
        //   (A) If the user has set an explicit select-list for the
        //       current table (via Select-Column), use that list
        //       after validating each name against the live field
        //       set. Names that no longer exist are dropped
        //       silently; the remaining names are shown in the
        //       order the user specified.
        //
        //   (B) Otherwise apply the default rules:
        //       1. Standard-visible columns (none currently) -- always shown.
        //       2. Standard-hidden columns (added, edited, marked,
        //          look, prm) -- always hidden.
        //       3. Any column ending in '_id' or named 'id' --
        //          always hidden (primary and foreign keys).
        //       4. Calculated columns from the schema (PRAGMA
        //          table_xinfo with hidden=2 or hidden=3) -- hidden.
        //
        // The Set-Record dialog and the dot prompt's 'show' command
        // still operate on the full getFieldNames() list, so hidden
        // columns are accessible for editing and inspection -- just
        // not present in the scrolling row view.
        public List<string> getDisplayFieldNames()
        {
            // (A) User-defined select list, if present.
            string sSelectList = getSelectList(sCurrentTable);
            if (!string.IsNullOrEmpty(sSelectList))
            {
                List<string> lFromUser = parseSelectList(sSelectList);
                HashSet<string> hFields = new HashSet<string>(getFieldNames(), StringComparer.OrdinalIgnoreCase);
                List<string> lValid = new List<string>();
                foreach (string sName in lFromUser)
                {
                    if (hFields.Contains(sName))
                    {
                        // Add with the canonical casing from the
                        // recordset (find the exact-cased name).
                        foreach (string sActual in getFieldNames())
                        {
                            if (string.Equals(sActual, sName, StringComparison.OrdinalIgnoreCase))
                            { lValid.Add(sActual); break; }
                        }
                    }
                }
                if (lValid.Count > 0) return lValid;
                // Fall through if the select-list yielded nothing
                // valid; the user expects to see something.
            }

            // (B) Default selection: the component fields that compose
            // the look/prime expression -- the substantive columns that
            // form the record's human-readable identity -- rather than
            // the derived look/prm columns themselves. Only applies to
            // tables that carry the standard summary columns; xlsx/csv
            // sources fall through to the rule-based selection in (C).
            bool bHasSummary = false;
            foreach (string sName in getFieldNames())
                if (Metadata.isDistinctColumn(sName)) { bHasSummary = true; break; }
            if (bHasSummary)
            {
                List<string> lComp = getPrmComponentFields();
                if (lComp.Count > 0) return lComp;
            }

            // (C) Fallback for tables without the standard summary
            // columns (e.g. .xlsx / .csv sources): the rule-based
            // selection -- every field except standard-hidden and
            // calculated columns.
            List<string> lResult = new List<string>();
            foreach (string sName in getFieldNames())
            {
                if (Metadata.isStandardVisible(sName))
                {
                    lResult.Add(sName);
                    continue;
                }
                if (Metadata.isStandardHidden(sName, sCurrentTable))
                    continue;
                if (isCalculatedColumn(sCurrentTable, sName))
                    continue;
                lResult.Add(sName);
            }
            // If the rules hid every column -- e.g. an ad-hoc query
            // (Control+Q) that selects only normally-hidden admin
            // fields such as 'added', 'id', or 'marked' -- the user
            // still expects to see what they asked for. Show the
            // fields as-is rather than an empty grid (which reads as
            // the listview's "Records" name with no cell content).
            if (lResult.Count == 0) lResult.AddRange(getFieldNames());
            return lResult;
        }

        // Parse a comma-separated (with optional whitespace) list
        // into a list of names. Empty entries are dropped.
        public static List<string> parseSelectList(string sList)
        {
            List<string> lResult = new List<string>();
            if (string.IsNullOrEmpty(sList)) return lResult;
            foreach (string sRaw in sList.Split(','))
            {
                string sName = sRaw.Trim();
                if (sName.Length > 0) lResult.Add(sName);
            }
            return lResult;
        }

        // Get the comma-separated select list for the named table.
        // Empty string means "no user override; use default rules."
        public string getSelectList(string sTable)
        {
            if (string.IsNullOrEmpty(sTable)) return "";
            TableSettings settings;
            if (dTableCache.TryGetValue(sTable, out settings))
                return settings.sSelectList ?? "";
            return "";
        }

        // Set the select list for the named table. Pass empty
        // string to clear the override and revert to default rules.
        // Validates each name against the live field set; invalid
        // names are dropped from the stored list. Returns the
        // canonicalized list (the valid names, exact-cased,
        // comma-separated).
        public string setSelectList(string sTable, string sList)
        {
            if (string.IsNullOrEmpty(sTable)) return "";
            // If the table is the current one, we can validate
            // against the live recordset's field names. For other
            // tables we accept the input verbatim and let
            // getDisplayFieldNames validate when the table is
            // later opened.
            string sStored = sList ?? "";
            if (hasRecordset() && string.Equals(sTable, sCurrentTable, StringComparison.OrdinalIgnoreCase))
            {
                List<string> lRequested = parseSelectList(sStored);
                HashSet<string> hFields = new HashSet<string>(getFieldNames(), StringComparer.OrdinalIgnoreCase);
                List<string> lValid = new List<string>();
                foreach (string sName in lRequested)
                {
                    if (hFields.Contains(sName))
                    {
                        foreach (string sActual in getFieldNames())
                        {
                            if (string.Equals(sActual, sName, StringComparison.OrdinalIgnoreCase))
                            { lValid.Add(sActual); break; }
                        }
                    }
                }
                sStored = string.Join(", ", lValid.ToArray());
            }

            TableSettings settings;
            if (!dTableCache.TryGetValue(sTable, out settings))
            {
                settings = new TableSettings();
                dTableCache[sTable] = settings;
            }
            settings.sSelectList = sStored;
            return sStored;
        }

        // seedTableSettings: pre-populate the in-session cache for a
        // table that has not yet been opened in this session. Called
        // by the form at file-open time to load saved per-table state
        // from RecentFiles into the manager so a later selectTable can
        // restore filter / sort / position / virtual column for any
        // previously-visited table, not just the one we land on first.
        public void seedTableSettings(string sTable, string sFilter, string sSort,
                                      int iPosition, string sVirtualColumn, string sSelectList)
        {
            if (string.IsNullOrEmpty(sTable)) return;
            TableSettings snap;
            if (!dTableCache.TryGetValue(sTable, out snap))
            {
                snap = new TableSettings();
                dTableCache[sTable] = snap;
            }
            snap.sFilter           = sFilter        ?? "";
            snap.sSort             = sSort          ?? "";
            snap.iAbsolutePosition = (iPosition > 0) ? iPosition : 1;
            snap.sVirtualColumn    = sVirtualColumn ?? "";
            snap.sSelectList       = sSelectList    ?? "";
        }

        // Get the remembered virtual-cell column name for the named
        // table. Empty string means "no remembered column; the
        // listview's first column is the default starting position."
        public string getVirtualColumn(string sTable)
        {
            if (string.IsNullOrEmpty(sTable)) return "";
            TableSettings settings;
            if (dTableCache.TryGetValue(sTable, out settings))
                return settings.sVirtualColumn ?? "";
            return "";
        }

        // Set the remembered virtual-cell column name for the named
        // table. The form calls this whenever the user moves the
        // virtual cursor to a new column, so the column survives
        // table switches within a session (and is later serialized
        // to ini for cross-session restore by RecentFiles).
        public void setVirtualColumn(string sTable, string sColumnName)
        {
            if (string.IsNullOrEmpty(sTable)) return;
            TableSettings settings;
            if (!dTableCache.TryGetValue(sTable, out settings))
            {
                settings = new TableSettings();
                dTableCache[sTable] = settings;
            }
            settings.sVirtualColumn = sColumnName ?? "";
        }

        // Distinct fields = field names that are NOT bookkeeping
        // (added, edited, observed, notes, tags, marked) and NOT the
        // primary-key column. These are the substantive content fields
        // and what the New-Record / Set-Record dialog shows by default.
        //
        // Pattern lifted from db.py's getDistinctFields, applied here at
        // the field level rather than the table-info level.
        public List<string> getEditableFieldNames()
        {
            List<string> lResult = new List<string>();
            string sTable = sCurrentTable ?? "";
            foreach (string sField in getFieldNames())
            {
                if (!Metadata.isAdminColumn(sField, sTable))
                    lResult.Add(sField);
            }
            return lResult;
        }

        // admin fields = the complement of editable fields: the
        // primary key plus the program-maintained columns. Show-Object
        // groups these at the bottom of its output; the record
        // dialogs never present them.
        public List<string> getAdminFieldNames()
        {
            List<string> lResult = new List<string>();
            string sTable = sCurrentTable ?? "";
            foreach (string sField in getFieldNames())
            {
                if (Metadata.isAdminColumn(sField, sTable))
                    lResult.Add(sField);
            }
            return lResult;
        }

        // True if the current table has the named column (case-insensitive).
        public bool hasField(string sName)
        {
            if (string.IsNullOrEmpty(sName)) return false;
            string sLower = sName.ToLowerInvariant();
            foreach (string sF in getFieldNames())
                if (sF.ToLowerInvariant() == sLower) return true;
            return false;
        }

        public string getFieldValue(string sName)
        {
            if (!hasRecordset()) return "";
            if (eof || bof) return "";
            try
            {
                dynamic oField = oRecordset.Fields[sName];
                object fieldValue = oField.Value;
                return (fieldValue == null || fieldValue is DBNull) ? "" : fieldValue.ToString();
            }
            catch { return ""; }
        }

        // isFieldNull: true when the named field's stored value is
        // SQL NULL -- distinct from the empty string. Cell speech
        // announces "null" versus "blank" on this basis.
        public bool isFieldNull(string sName)
        {
            if (!hasRecordset() || eof || bof) return false;
            try
            {
                dynamic oField = oRecordset.Fields[sName];
                object fieldValue = oField.Value;
                return (fieldValue == null || fieldValue is DBNull);
            }
            catch { return false; }
        }

        // setFieldNull: write SQL NULL into the named field of the
        // current record; the caller invokes update().
        public void setFieldNull(string sName)
        {
            dynamic oField = oRecordset.Fields[sName];
            oField.Value = DBNull.Value;
        }

        // True if the named field is a binary (BLOB) type. Used by the
        // grid renderer to substitute a size summary for the unhelpful
        // "System.Byte[]" that ADO returns for BLOB columns.
        //
        // ADO Field.Type returns the DataTypeEnum value. The binary
        // types we care about are:
        //   adBinary       = 128
        //   adVarBinary    = 204
        //   adLongVarBinary = 205
        public bool isFieldBinary(string sName)
        {
            if (!hasRecordset()) return false;
            try
            {
                dynamic oField = oRecordset.Fields[sName];
                int iType = (int)oField.Type;
                return (iType == 128 || iType == 204 || iType == 205);
            }
            catch { return false; }
        }

        // Length of a binary field's value, in bytes. Returns 0 for null,
        // -1 if the field cannot be sized (rare). ADO Field has an
        // ActualSize property that gives the byte count for variable
        // length data including BLOBs.
        public int getFieldByteLength(string sName)
        {
            if (!hasRecordset()) return 0;
            if (eof || bof) return 0;
            try
            {
                dynamic oField = oRecordset.Fields[sName];
                object fieldValue = oField.Value;
                if (fieldValue == null || fieldValue is DBNull) return 0;
                try { return (int)oField.ActualSize; }
                catch { }
                if (fieldValue is byte[]) return ((byte[])fieldValue).Length;
                return -1;
            }
            catch { return -1; }
        }

        public void setFieldValue(string sName, string sValue)
        {
            if (!hasRecordset()) throw new InvalidOperationException("No recordset open.");
            if (bReadOnly) throw new InvalidOperationException("Database is read-only.");
            try
            {
                oRecordset.Fields[sName].Value = (sValue == null) ? (object)DBNull.Value : (object)sValue;
            }
            catch (COMException ex)
            {
                throw new Exception("Cannot set field '" + sName + "': " + ex.Message, ex);
            }
        }

        // ------- Edit lifecycle -------
        public void addNew()
        {
            if (!hasRecordset()) throw new InvalidOperationException("No recordset open.");
            if (bReadOnly) throw new InvalidOperationException("Database is read-only.");
            oRecordset.AddNew();
        }

        public void update()
        {
            if (!hasRecordset()) return;
            if (bReadOnly) throw new InvalidOperationException("Database is read-only.");
            try { oRecordset.Update(); bDataModified = true; }
            catch (COMException ex) { throw new Exception("Update failed: " + ex.Message, ex); }
        }

        public void cancelUpdate()
        {
            if (!hasRecordset()) return;
            try { oRecordset.CancelUpdate(); } catch { }
        }

        // isPrmViolation: true when an exception is a UNIQUE-constraint
        // failure on this table's generated prm column -- the identity
        // field DbDo builds from the record's content fields -- rather
        // than a primary-key clash or some other unique index. The add
        // paths use this to recognise an ordinary "this would duplicate an
        // existing record" condition and offer the user a chance to change
        // a content field, instead of surfacing a raw ADO error.
        public bool isPrmViolation(Exception ex)
        {
            string s = "";
            for (Exception e = ex; e != null; e = e.InnerException)
                s += " " + (e.Message ?? "");
            s = s.ToLowerInvariant();
            return s.Contains("unique constraint") && s.Contains(".prm");
        }

        // getTableCreateSql: the CREATE TABLE text for a table from
        // sqlite_master, or "" if unavailable. Used to read generated-
        // column definitions; failures are swallowed.
        private string getTableCreateSql(string sTable)
        {
            if (oConn == null || string.IsNullOrEmpty(sTable)) return "";
            dynamic oRs = null;
            try
            {
                string sSql = "SELECT sql FROM sqlite_master WHERE type='table' AND name='"
                    + sTable.Replace("'", "''") + "' LIMIT 1";
                oRs = oConn.Execute(sSql, Type.Missing, AdoConstants.adCmdText);
                if (oRs != null && !(bool)oRs.EOF)
                {
                    object v = oRs.Fields[0].Value;
                    return (v == null || v is DBNull) ? "" : v.ToString();
                }
                return "";
            }
            catch { return ""; }
            finally
            {
                if (oRs != null)
                {
                    try { if (((int)oRs.State) != 0) oRs.Close(); } catch { }
                    try { releaseCom(oRs); } catch { }
                }
            }
        }

        // getPrmComponentFields: the content fields the current table's
        // generated prm column actually depends on, in order of first
        // appearance. Read by pulling the prm expression out of the table's
        // CREATE SQL and keeping the identifiers in it that are real columns
        // of the table (which discards SQL functions and keywords). This is
        // accurate whether prm is the simple positional concatenation Add
        // Table builds or a hand-tuned expression like the sample databases'
        // person-or-organization form. These are exactly the fields whose
        // combination must be unique, so they are what a user changes to
        // resolve a duplicate. Falls back to the full editable-field list if
        // the expression cannot be read or parsed.
        public List<string> getPrmComponentFields()
        {
            List<string> lEditable = getEditableFieldNames();
            try
            {
                string sCreate = getTableCreateSql(sCurrentTable);
                if (string.IsNullOrEmpty(sCreate)) return lEditable;
                System.Text.RegularExpressions.Match m =
                    System.Text.RegularExpressions.Regex.Match(sCreate,
                        "\\bprm\\b\\s+\\w+\\s+GENERATED\\s+ALWAYS\\s+AS\\s*\\(",
                        System.Text.RegularExpressions.RegexOptions.IgnoreCase);
                if (!m.Success) return lEditable;
                int iDepth = 1, i = m.Index + m.Length, iStart = i;
                while (i < sCreate.Length && iDepth > 0)
                {
                    char c = sCreate[i];
                    if (c == '(') iDepth++;
                    else if (c == ')') { iDepth--; if (iDepth == 0) break; }
                    i++;
                }
                string sExpr = sCreate.Substring(iStart, i - iStart);
                Dictionary<string, string> dCols = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
                foreach (string sF in getFieldNames()) dCols[sF] = sF;
                List<string> lComp = new List<string>();
                Dictionary<string, bool> dSeen = new Dictionary<string, bool>(StringComparer.OrdinalIgnoreCase);
                foreach (System.Text.RegularExpressions.Match mm in
                         System.Text.RegularExpressions.Regex.Matches(sExpr, "[A-Za-z_][A-Za-z0-9_]*"))
                {
                    string sTok = mm.Value;
                    if (dCols.ContainsKey(sTok) && !dSeen.ContainsKey(sTok))
                    { dSeen[sTok] = true; lComp.Add(dCols[sTok]); }
                }
                return lComp.Count > 0 ? lComp : lEditable;
            }
            catch { return lEditable; }
        }

        public void deleteCurrent()
        {
            if (!hasRecordset()) throw new InvalidOperationException("No recordset open.");
            if (bReadOnly) throw new InvalidOperationException("Database is read-only.");
            if (eof || bof) throw new InvalidOperationException("No current record.");
            try
            {
                oRecordset.Delete();
                bDataModified = true;
                // After Delete, ADODB leaves the cursor on the deleted
                // row (which is now invalid). Move to next.
                try { oRecordset.MoveNext(); } catch { }
                if (eof && recordCount > 0) try { oRecordset.MoveLast(); } catch { }
            }
            catch (COMException ex)
            {
                throw new Exception("Delete failed: " + ex.Message, ex);
            }
        }

        // ------- requery (Update-View) -------
        public void requery()
        {
            if (!hasRecordset()) return;
            object bookmarkObj = bookmark;
            try { oRecordset.Requery(); } catch (COMException ex) { throw new Exception("Requery failed: " + ex.Message, ex); }
            if (bookmarkObj != null) bookmark = bookmarkObj;
        }

        // resync: refresh the values of the current rowset from the
        // database via the ADO Resync method, without re-running the
        // query. Unlike Requery it preserves the cursor position and
        // does not pick up rows added or removed outside this
        // recordset -- it re-reads existing rows (and recomputes
        // STORED generated columns like look and prm), the
        // lightweight "refresh what I'm looking at" F5 wants.
        public void resync()
        {
            if (!hasRecordset()) return;
            try { oRecordset.Resync(); }
            catch (COMException ex) { throw new Exception("Resync failed: " + ex.Message, ex); }
        }

        // =====================================================================
        // invokeSql: raw SQL via Connection.Execute. Used by the CLI's
        // Invoke-Sql command and by the GUI's Verbatim SQL dialog.
        // Routing:
        //   queries (SELECT/PRAGMA/EXPLAIN/WITH) -> render results to sbOut
        //   statements (INSERT/UPDATE/DELETE/etc) -> records-affected count
        // Returns the records-affected count, or -1 if we rendered
        // results to sbOut.
        // =====================================================================
        public int invokeSql(string sSql, TextWriter sbOut)
        {
            if (!isOpen()) throw new InvalidOperationException("No database open.");
            if (string.IsNullOrEmpty(sSql)) return 0;

            string sTrim = sSql.TrimStart();
            string sUpper = sTrim.ToUpperInvariant();
            bool bIsQuery = sUpper.StartsWith("SELECT") || sUpper.StartsWith("PRAGMA")
                         || sUpper.StartsWith("EXPLAIN") || sUpper.StartsWith("WITH");

            if (bIsQuery)
            {
                dynamic oRs = createComObject("ADODB.Recordset");
                try
                {
                    oRs.CursorLocation = AdoConstants.adUseClient;
                    oRs.Open(sSql, oConn, AdoConstants.adOpenStatic,
                        AdoConstants.adLockReadOnly, AdoConstants.adCmdText);
                    renderRecordset(oRs, sbOut);
                }
                finally
                {
                    try { if (((int)oRs.State) != 0) oRs.Close(); } catch { }
                    releaseCom(oRs); oRs = null;
                }
                return -1;
            }
            else
            {
                int iAffected = 0;
                try
                {
                    // Connection.Execute(commandText, recordsAffected, options)
                    // ADODB returns the records-affected count via a [out]
                    // VARIANT* parameter. Late-bound C# can pass `ref`
                    // through the DLR's COM binder, but we're defensive
                    // here: if the ref-pattern fails for any reason, we
                    // re-execute without the ref argument and return 0.
                    object recordsAffected = 0;
                    try
                    {
                        oConn.Execute(sSql, ref recordsAffected,
                            AdoConstants.adCmdText | AdoConstants.adExecuteNoRecords);
                        if (recordsAffected is int) iAffected = (int)recordsAffected;
                        else if (recordsAffected != null)
                        {
                            int iTmp;
                            if (int.TryParse(recordsAffected.ToString(), out iTmp)) iAffected = iTmp;
                        }
                    }
                    catch (RuntimeBinderException)
                    {
                        // DLR couldn't bind the ref; fall back to two-arg form.
                        // The records-affected count is then unavailable.
                        oConn.Execute(sSql, Type.Missing,
                            AdoConstants.adCmdText | AdoConstants.adExecuteNoRecords);
                        iAffected = 0;
                    }
                }
                catch (COMException ex)
                {
                    throw new Exception("SQL failed: " + ex.Message, ex);
                }
                return iAffected;
            }
        }

        // =====================================================================
        // Look / Prm reconfiguration (pass two).
        //
        // 'look' and 'prm' are STORED generated columns, so their defining
        // expressions cannot be altered in place. Changing which component
        // fields build them means rebuilding the table with the SQLite-
        // recommended safe sequence: build a replacement under a NEW name
        // first, copy the data in, drop the old table, then rename the new
        // one into place (the reverse ordering can corrupt references in
        // triggers, views, and foreign keys). Because prm values change
        // when prm's components change, any maps rows that referenced the
        // table by its old prm are re-pointed to the new prm in the same
        // transaction. The whole thing refuses up front if the chosen prm
        // fields would not uniquely identify every record.
        // =====================================================================

        // sLookExprFromFields: the human-readable summary expression --
        // each non-empty field rendered "value | ", concatenated, then the
        // trailing separator trimmed. Mirrors lStandardTableDdl's shape.
        internal static string sLookExprFromFields(List<string> lFields)
        {
            if (lFields == null || lFields.Count == 0) return "''";
            StringBuilder sb = new StringBuilder("rtrim(");
            for (int i = 0; i < lFields.Count; i++)
            {
                string sC = "\"" + lFields[i] + "\"";
                if (i > 0) sb.Append(" || ");
                sb.Append("iif(" + sC + " IS NOT NULL AND length(CAST(" + sC
                    + " AS TEXT))>0, CAST(" + sC + " AS TEXT) || ' | ', '')");
            }
            sb.Append(", ' | ')");
            return sb.ToString();
        }

        // sPrmExprFromFields: the unique-key expression -- the positional
        // pipe-join of the component fields, each coalesced to '' so NULLs
        // do not poison the key. Mirrors lStandardTableDdl's prm shape.
        internal static string sPrmExprFromFields(List<string> lFields)
        {
            if (lFields == null || lFields.Count == 0) return "''";
            StringBuilder sb = new StringBuilder();
            for (int i = 0; i < lFields.Count; i++)
            {
                if (i > 0) sb.Append("||'|'||");
                sb.Append("coalesce(CAST(\"" + lFields[i] + "\" AS TEXT),'')");
            }
            return sb.ToString();
        }

        // sExtractGeneratedExpr: return the inner expression text of the
        // named generated column from a CREATE TABLE statement, matching
        // the parentheses by balance (the expression itself contains
        // nested parentheses). Returns "" if not found.
        internal static string sExtractGeneratedExpr(string sCreate, string sCol)
        {
            if (string.IsNullOrEmpty(sCreate)) return "";
            System.Text.RegularExpressions.Match m = System.Text.RegularExpressions.Regex.Match(
                sCreate, "(\\b" + System.Text.RegularExpressions.Regex.Escape(sCol)
                + "\\b[^,(]*?GENERATED ALWAYS AS\\s*)\\(",
                System.Text.RegularExpressions.RegexOptions.IgnoreCase);
            if (!m.Success) return "";
            int iStart = m.Index + m.Length - 1; // at '('
            int iDepth = 0, i = iStart;
            for (; i < sCreate.Length; i++)
            {
                char ch = sCreate[i];
                if (ch == '(') iDepth++;
                else if (ch == ')') { iDepth--; if (iDepth == 0) break; }
            }
            if (iDepth != 0) return "";
            return sCreate.Substring(iStart + 1, i - iStart - 1);
        }

        // replaceGeneratedExpr: return a copy of the CREATE statement with
        // the named generated column's expression replaced. Throws if the
        // column's generated definition is not found.
        internal static string replaceGeneratedExpr(string sCreate, string sCol, string sNewExpr)
        {
            System.Text.RegularExpressions.Match m = System.Text.RegularExpressions.Regex.Match(
                sCreate, "(\\b" + System.Text.RegularExpressions.Regex.Escape(sCol)
                + "\\b[^,(]*?GENERATED ALWAYS AS\\s*)\\(",
                System.Text.RegularExpressions.RegexOptions.IgnoreCase);
            if (!m.Success)
                throw new InvalidOperationException("Generated column not found: " + sCol);
            int iStart = m.Index + m.Length - 1; // at '('
            int iDepth = 0, i = iStart;
            for (; i < sCreate.Length; i++)
            {
                char ch = sCreate[i];
                if (ch == '(') iDepth++;
                else if (ch == ')') { iDepth--; if (iDepth == 0) break; }
            }
            if (iDepth != 0)
                throw new InvalidOperationException("Unbalanced expression for: " + sCol);
            return sCreate.Substring(0, iStart) + "(" + sNewExpr + ")" + sCreate.Substring(i + 1);
        }

        // lParseGeneratedFields: best-effort recovery of the component
        // fields currently driving a generated column, by scanning its
        // expression for identifiers that are columns of the table, in
        // order of first appearance. Used only to pre-fill the editor;
        // the saved [Table] config is the authoritative source when present.
        public List<string> lParseGeneratedFields(string sTable, string sCol)
        {
            List<string> lResult = new List<string>();
            try
            {
                int iN;
                List<string[]> lRows = queryRowsSql("SELECT sql FROM sqlite_schema WHERE type='table' AND name='"
                    + sTable.Replace("'", "''") + "'", 1, out iN);
                if (lRows.Count == 0 || lRows[0].Length == 0) return lResult;
                string sExpr = sExtractGeneratedExpr(lRows[0][0], sCol);
                if (string.IsNullOrEmpty(sExpr)) return lResult;
                HashSet<string> hCols = new HashSet<string>(getColumnsOfTable(sTable), StringComparer.OrdinalIgnoreCase);
                HashSet<string> hSeen = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
                foreach (System.Text.RegularExpressions.Match m in
                    System.Text.RegularExpressions.Regex.Matches(sExpr, "[A-Za-z_][A-Za-z0-9_]*"))
                {
                    string sTok = m.Value;
                    if (hCols.Contains(sTok) && !hSeen.Contains(sTok))
                    { hSeen.Add(sTok); lResult.Add(sTok); }
                }
            }
            catch { }
            return lResult;
        }

        // rebuildGeneratedColumns: reconfigure 'look' and 'prm' for a table
        // by rebuilding it with new generated-column expressions built from
        // the given component-field lists, re-pointing maps as needed.
        // Returns true on success; on any failure leaves the database
        // unchanged and sets sError. iMapsUpdated reports how many maps
        // references were re-pointed.
        public bool rebuildGeneratedColumns(string sTable, List<string> lLookFields,
            List<string> lPrmFields, out string sError, out int iMapsUpdated)
        {
            sError = ""; iMapsUpdated = 0;
            if (!isOpen()) { sError = "No database open."; return false; }
            if (string.IsNullOrEmpty(sTable)) { sError = "No table specified."; return false; }
            if (lPrmFields == null || lPrmFields.Count == 0)
            { sError = "At least one Prm field is required."; return false; }

            // Resolve the primary key, the non-generated columns, and confirm
            // the table actually has look + prm to reconfigure.
            string sPk = null;
            List<string> lNonGen = new List<string>();
            bool bHasLook = false, bHasPrm = false;
            int iN;
            foreach (string[] aRow in queryRowsSql("PRAGMA table_xinfo(\"" + sTable + "\")", 1000000, out iN))
            {
                if (aRow.Length < 7) continue;
                string sName = aRow[1];
                if (string.Equals(sName, "look", StringComparison.OrdinalIgnoreCase)) bHasLook = true;
                if (string.Equals(sName, "prm", StringComparison.OrdinalIgnoreCase)) bHasPrm = true;
                if (aRow[6] == "0") lNonGen.Add(sName);          // hidden==0 -> stored, copyable
                if (aRow[5] == "1" && string.IsNullOrEmpty(sPk)) sPk = sName; // pk flag
            }
            if (!bHasLook || !bHasPrm)
            { sError = "Table '" + sTable + "' has no look/prm columns to reconfigure."; return false; }
            if (string.IsNullOrEmpty(sPk))
            { sError = "Table '" + sTable + "' has no single-column primary key."; return false; }

            // Validate the field lists against the live columns.
            HashSet<string> hCols = new HashSet<string>(getColumnsOfTable(sTable), StringComparer.OrdinalIgnoreCase);
            foreach (string sF in lLookFields) if (!hCols.Contains(sF)) { sError = "Look field not found: " + sF; return false; }
            foreach (string sF in lPrmFields) if (!hCols.Contains(sF)) { sError = "Prm field not found: " + sF; return false; }

            string sLookExpr = sLookExprFromFields(lLookFields);
            string sPrmExpr  = sPrmExprFromFields(lPrmFields);

            // Refuse up front if the new prm would not be unique.
            int iDup = 0;
            foreach (string[] aRow in queryRowsSql("SELECT count(*) FROM (SELECT 1 FROM \"" + sTable
                + "\" GROUP BY " + sPrmExpr + " HAVING count(*)>1)", 1, out iN))
            { if (aRow.Length > 0) int.TryParse(aRow[0], out iDup); break; }
            if (iDup > 0)
            {
                sError = "The chosen Prm fields do not uniquely identify every record: " + iDup
                    + (iDup == 1 ? " value is" : " values are") + " shared by more than one record. "
                    + "Pick fields whose combination is unique for every record.";
                return false;
            }

            // Read the current CREATE and build the revised one under a temp name.
            string sOldCreate = null;
            foreach (string[] aRow in queryRowsSql("SELECT sql FROM sqlite_schema WHERE type='table' AND name='"
                + sTable.Replace("'", "''") + "'", 1, out iN))
            { if (aRow.Length > 0) sOldCreate = aRow[0]; break; }
            if (string.IsNullOrEmpty(sOldCreate))
            { sError = "Could not read the schema for '" + sTable + "'."; return false; }

            string sNewTable = "new_" + sTable;
            const string sHelper = "dbdo_oldprm";
            string sNewCreate;
            try
            {
                sNewCreate = replaceGeneratedExpr(sOldCreate, "look", sLookExpr);
                sNewCreate = replaceGeneratedExpr(sNewCreate, "prm", sPrmExpr);
                sNewCreate = new System.Text.RegularExpressions.Regex(
                    "CREATE TABLE\\s+\"?" + System.Text.RegularExpressions.Regex.Escape(sTable) + "\"?",
                    System.Text.RegularExpressions.RegexOptions.IgnoreCase)
                    .Replace(sNewCreate, "CREATE TABLE \"" + sNewTable + "\"", 1);
            }
            catch (Exception ex) { sError = "Could not build the revised table: " + ex.Message; return false; }

            // Indexes / triggers / views to recreate (skip auto-created ones
            // with NULL sql). After the rename these reference the table by
            // its final name, so they are valid as-is.
            List<string> lAux = new List<string>();
            foreach (string[] aRow in queryRowsSql("SELECT sql FROM sqlite_schema WHERE tbl_name='"
                + sTable.Replace("'", "''") + "' AND sql IS NOT NULL AND type IN ('index','trigger','view')",
                1000000, out iN))
                if (aRow.Length > 0 && !string.IsNullOrEmpty(aRow[0])) lAux.Add(aRow[0]);

            bool bHasMaps = false;
            foreach (string sT in getTableNames())
                if (string.Equals(sT, "maps", StringComparison.OrdinalIgnoreCase)) { bHasMaps = true; break; }

            StringBuilder sbCols = new StringBuilder();
            for (int i = 0; i < lNonGen.Count; i++)
            { if (i > 0) sbCols.Append(", "); sbCols.Append("\"" + lNonGen[i] + "\""); }
            string sColList = sbCols.ToString();
            string sQPk = "\"" + sPk + "\"";
            string sTableEsc = sTable.Replace("'", "''");

            // Defensive cleanup of leftovers from any prior failed attempt.
            try { invokeSql("DROP TABLE IF EXISTS \"" + sNewTable + "\"", null); } catch { }
            try { invokeSql("DROP TABLE IF EXISTS " + sHelper, null); } catch { }
            // foreign_keys is a no-op inside a transaction, so set it first.
            try { invokeSql("PRAGMA foreign_keys=OFF", null); } catch { }

            bool bInTrans = false;
            try
            {
                oConn.BeginTrans(); bInTrans = true;
                invokeSql("CREATE TABLE " + sHelper + " AS SELECT " + sQPk + " AS k, prm AS p FROM \"" + sTable + "\"", null);
                invokeSql(sNewCreate, null);
                invokeSql("INSERT INTO \"" + sNewTable + "\" (" + sColList + ") SELECT " + sColList + " FROM \"" + sTable + "\"", null);
                invokeSql("DROP TABLE \"" + sTable + "\"", null);
                invokeSql("ALTER TABLE \"" + sNewTable + "\" RENAME TO \"" + sTable + "\"", null);
                foreach (string sSql in lAux) invokeSql(sSql, null);
                if (bHasMaps)
                {
                    iMapsUpdated += invokeSql("UPDATE maps SET prm1=(SELECT n.prm FROM \"" + sTable
                        + "\" n JOIN " + sHelper + " o ON n." + sQPk + "=o.k WHERE o.p=maps.prm1 AND n.prm<>o.p) "
                        + "WHERE tbl1='" + sTableEsc + "' AND prm1 IN (SELECT o2.p FROM " + sHelper
                        + " o2 JOIN \"" + sTable + "\" n2 ON n2." + sQPk + "=o2.k WHERE n2.prm<>o2.p)", null);
                    iMapsUpdated += invokeSql("UPDATE maps SET prm2=(SELECT n.prm FROM \"" + sTable
                        + "\" n JOIN " + sHelper + " o ON n." + sQPk + "=o.k WHERE o.p=maps.prm2 AND n.prm<>o.p) "
                        + "WHERE tbl2='" + sTableEsc + "' AND prm2 IN (SELECT o2.p FROM " + sHelper
                        + " o2 JOIN \"" + sTable + "\" n2 ON n2." + sQPk + "=o2.k WHERE n2.prm<>o2.p)", null);
                }
                invokeSql("DROP TABLE " + sHelper, null);
                oConn.CommitTrans(); bInTrans = false;
            }
            catch (Exception ex)
            {
                sError = "Rebuild failed: " + ex.Message;
                if (bInTrans) { try { oConn.RollbackTrans(); } catch { } }
                try { invokeSql("DROP TABLE IF EXISTS \"" + sNewTable + "\"", null); } catch { }
                try { invokeSql("DROP TABLE IF EXISTS " + sHelper, null); } catch { }
                try { invokeSql("PRAGMA foreign_keys=ON", null); } catch { }
                try { DbDoLog.write("rebuildGeneratedColumns failed for '" + sTable + "': " + ex.Message); } catch { }
                return false;
            }
            try { invokeSql("PRAGMA foreign_keys=ON", null); } catch { }
            try { DbDoLog.write("Rebuilt look/prm for '" + sTable + "'. maps re-pointed=" + iMapsUpdated); } catch { }
            return true;
        }

        private void renderRecordset(dynamic oRs, TextWriter sbOut)
        {
            dynamic oFields = oRs.Fields;
            int iFieldCount = (int)oFields.Count;
            List<string> lH = new List<string>();
            for (int i = 0; i < iFieldCount; i++) lH.Add((string)oFields[i].Name);
            sbOut.WriteLine(string.Join(" | ", lH));
            sbOut.WriteLine(new string('-', Math.Min(80, string.Join(" | ", lH).Length)));
            int iRow = 0;
            while (!(bool)oRs.EOF)
            {
                List<string> lV = new List<string>();
                for (int i = 0; i < iFieldCount; i++)
                {
                    object fieldValue = oFields[i].Value;
                    lV.Add((fieldValue == null || fieldValue is DBNull) ? "" : fieldValue.ToString());
                }
                sbOut.WriteLine(string.Join(" | ", lV));
                iRow++;
                oRs.MoveNext();
            }
            sbOut.WriteLine(string.Format("({0} row(s))", iRow));
        }

        // =====================================================================
        // exportData: write the current view (filtered, sorted) to a
        // file. Format inferred from extension (.csv, .tsv, .xlsx,
        // .html, .docx). Currently we implement CSV, TSV, and HTML
        // natively in C#; XLSX and DOCX are deferred to the form layer
        // which can use the COM Excel/Word automation that dbDot does
        // (multiArrayToTables in dbDot.vbs lines 52-186).
        //
        // Save-As to a different .db / .mdb / .xlsx etc. is a separate
        // method (saveAs) that copies the entire database, not just
        // the current view.
        // =====================================================================
        public void exportData(string sDestPath)
        {
            if (!hasRecordset()) throw new InvalidOperationException("No recordset open.");
            if (string.IsNullOrEmpty(sDestPath)) throw new ArgumentException("exportData requires a path.");

            string sExt = Path.GetExtension(sDestPath).TrimStart('.').ToLowerInvariant();
            switch (sExt)
            {
                // Plain-text tabular.
                case "csv": exportDelimited(sDestPath, ","); break;
                case "tsv":
                case "tab": exportDelimited(sDestPath, "\t"); break;
                case "md":
                case "markdown":
                    exportMarkdown(sDestPath);
                    break;
                case "json":
                    exportJson(sDestPath);
                    break;
                case "inix":
                    exportInix(sDestPath);
                    break;
                // Document formats.
                case "html":
                case "htm": exportHtml(sDestPath); break;
                case "xlsx":
                case "xls":
                    exportSpreadsheet(sDestPath, sExt);
                    break;
                case "docx":
                case "doc":
                    exportWord(sDestPath, sExt, false);
                    break;
                // Database formats. Closes the "every input format
                // is also an export format" loop: anything DbDo can
                // open, it can also write.
                case "db":
                case "sqlite":
                case "sqlite3":
                case "mdb":
                case "accdb":
                case "dbf":
                    exportDatabase(sDestPath, sExt);
                    break;
                default:
                    throw new Exception("exportData: unsupported format ." + sExt
                        + ". Supported: csv, tsv, md, json, inix, html, xlsx, docx, db, sqlite, mdb, accdb, dbf. "
                        + "xlsx and docx require Microsoft Office.");
            }
        }

        // exportDataMulti: dbDot-compatible multi-format export.
        // Accepts a space-separated list of extensions (xlsx, docx,
        // html, csv) plus dbDot single-letter shortcuts (x, d, h, c).
        // Generates one file per extension in the same folder, named
        // after the current table with a unique numeric suffix if a
        // file by that name already exists. Returns the list of paths
        // actually written.
        //
        // xlsx and docx require Microsoft Office. The same Word
        // and Excel Application objects drive html and csv when
        // requested alongside; this matches dbDot.vbs / HomerLib.vbs
        // behavior verbatim.
        //
        // If sFolder is null/empty, the database file's folder is
        // used. If sBaseName is null/empty, the current table name
        // is used (with non-filesystem-safe characters replaced).
        public List<string> exportDataMulti(string sExtensions, string sFolder, string sBaseName)
        {
            if (!hasRecordset()) throw new InvalidOperationException("No recordset open.");
            string sExt = (sExtensions ?? "").Trim();
            if (sExt.Length == 0) sExt = "xlsx";

            // Normalize dbDot single-letter shortcuts and bare extension
            // names. The user can type "Export-Data x d h c m" or
            // "xlsx docx markdown" -- both work. Dots are stripped.
            sExt = sExt.Replace(".", " ").Replace(",", " ").ToLowerInvariant();
            List<string> lFormats = new List<string>();
            foreach (string sToken in sExt.Split(new[] { ' ', '\t' }, StringSplitOptions.RemoveEmptyEntries))
            {
                string sNorm = sToken;
                if (sNorm == "x") sNorm = "xlsx";
                else if (sNorm == "d") sNorm = "docx";
                else if (sNorm == "h") sNorm = "html";
                else if (sNorm == "c") sNorm = "csv";
                else if (sNorm == "t") sNorm = "tsv";
                else if (sNorm == "m" || sNorm == "markdown") sNorm = "md";
                else if (sNorm == "s" || sNorm == "sqlite" || sNorm == "sqlite3") sNorm = "db";
                else if (sNorm == "a" || sNorm == "access" || sNorm == "accdb") sNorm = "mdb";
                else if (sNorm == "b" || sNorm == "dbase") sNorm = "dbf";
                if (!lFormats.Contains(sNorm)) lFormats.Add(sNorm);
            }

            // Resolve folder.
            string sDir = sFolder;
            if (string.IsNullOrEmpty(sDir))
            {
                if (!string.IsNullOrEmpty(filePath)) sDir = Path.GetDirectoryName(filePath);
                if (string.IsNullOrEmpty(sDir)) sDir = Environment.CurrentDirectory;
            }
            try { if (!Directory.Exists(sDir)) Directory.CreateDirectory(sDir); }
            catch (Exception ex) { throw new Exception("Cannot create folder " + sDir + ": " + ex.Message); }

            // Resolve base name.
            string sBase = sBaseName;
            if (string.IsNullOrEmpty(sBase)) sBase = sCurrentTable;
            if (string.IsNullOrEmpty(sBase)) sBase = "Export";
            sBase = sanitizeFileName(sBase);

            List<string> lWritten = new List<string>();

            // Group all wanted formats.
            bool bWantXlsx = lFormats.Contains("xlsx");
            bool bWantCsv  = lFormats.Contains("csv");
            bool bWantTsv  = lFormats.Contains("tsv");
            bool bWantMd   = lFormats.Contains("md");
            bool bWantJson = lFormats.Contains("json");
            bool bWantDocx = lFormats.Contains("docx");
            bool bWantHtml = lFormats.Contains("html") || lFormats.Contains("htm");
            bool bWantDb   = lFormats.Contains("db");
            bool bWantMdb  = lFormats.Contains("mdb");
            bool bWantDbf  = lFormats.Contains("dbf");

            // Plain-text tabular outputs (native, no Office needed).
            if (bWantCsv)
            {
                string sP = uniqueExportPath(sDir, sBase, "csv");
                exportDelimited(sP, ",");
                lWritten.Add(sP);
            }
            if (bWantTsv)
            {
                string sP = uniqueExportPath(sDir, sBase, "tsv");
                exportDelimited(sP, "\t");
                lWritten.Add(sP);
            }
            if (bWantMd)
            {
                string sP = uniqueExportPath(sDir, sBase, "md");
                exportMarkdown(sP);
                lWritten.Add(sP);
            }
            if (bWantJson)
            {
                string sP = uniqueExportPath(sDir, sBase, "json");
                exportJson(sP);
                lWritten.Add(sP);
            }

            // Spreadsheet output via Excel COM.
            if (bWantXlsx)
            {
                string sP = uniqueExportPath(sDir, sBase, "xlsx");
                exportSpreadsheet(sP, "xlsx");
                lWritten.Add(sP);
            }

            // Document outputs via Word COM.
            if (bWantDocx)
            {
                string sP = uniqueExportPath(sDir, sBase, "docx");
                exportWord(sP, "docx", false);
                lWritten.Add(sP);
            }
            if (bWantHtml)
            {
                string sP = uniqueExportPath(sDir, sBase, "html");
                exportWord(sP, "html", true);
                lWritten.Add(sP);
            }

            // Database outputs via fresh ADODB.Connection.
            if (bWantDb)
            {
                string sP = uniqueExportPath(sDir, sBase, "db");
                exportDatabase(sP, "db");
                lWritten.Add(sP);
            }
            if (bWantMdb)
            {
                string sP = uniqueExportPath(sDir, sBase, "accdb");
                exportDatabase(sP, "accdb");
                lWritten.Add(sP);
            }
            if (bWantDbf)
            {
                string sP = uniqueExportPath(sDir, sBase, "dbf");
                exportDatabase(sP, "dbf");
                lWritten.Add(sP);
            }

            return lWritten;
        }

        // sanitizeFileName: keep alnum/underscore/dash/dot, replace
        // everything else with underscore. Conservative across all
        // Windows filesystems.
        private static string sanitizeFileName(string s)
        {
            if (string.IsNullOrEmpty(s)) return "Export";
            char[] aBad = Path.GetInvalidFileNameChars();
            StringBuilder sb = new StringBuilder();
            foreach (char c in s)
            {
                bool bBad = false;
                foreach (char cBad in aBad) if (c == cBad) { bBad = true; break; }
                sb.Append(bBad ? '_' : c);
            }
            return sb.ToString();
        }

        // uniqueExportPath: <folder>\<base>.<ext>, or if that exists,
        // <folder>\<base>_2.<ext>, then _3, etc. Matches the spirit
        // of dbDot/HomerLib's PathGetUnique. Stops at 999 to bound
        // unbounded loops on a misconfigured folder.
        private static string uniqueExportPath(string sFolder, string sBase, string sExt)
        {
            string sFirst = Path.Combine(sFolder, sBase + "." + sExt);
            if (!File.Exists(sFirst)) return sFirst;
            for (int i = 2; i <= 999; i++)
            {
                string sCandidate = Path.Combine(sFolder, sBase + "_" + i + "." + sExt);
                if (!File.Exists(sCandidate)) return sCandidate;
            }
            // Worst case: timestamp.
            return Path.Combine(sFolder, sBase + "_" + DateTime.Now.ToString("yyyyMMddHHmmss") + "." + sExt);
        }

        // exportSpreadsheet: write the current recordset to an .xlsx
        // file via Excel.Application late-bound COM. Requires Excel
        // to be installed. Throws InvalidOperationException with a
        // human message if the ProgID isn't registered.
        //
        // The output replicates dbDot's HomerLib.multiArrayToTables:
        // header row from getFieldNames, value rows below, column
        // widths auto-fit, cells wrap-text, vertical alignment top,
        // a named range "ColumnTitle" anchored at A1.
        //
        // For .xls (legacy), the same workflow runs and SaveAs uses
        // xlExcel8 (56) instead of xlWorkbookDefault (51).
        public void exportSpreadsheet(string sDestPath, string sExt)
        {
            if (!hasRecordset()) throw new InvalidOperationException("No recordset open.");
            object bookmarkObj = bookmark;

            dynamic oApp = null;
            dynamic oBook = null;
            dynamic oSheet = null;
            try
            {
                oApp = ComAutomation.createApp("Excel.Application");
                oApp.Visible = false;
                oApp.DisplayAlerts = false;
                try { oApp.ScreenUpdating = false; } catch { }

                oBook = oApp.Workbooks.Add();
                oSheet = oBook.Sheets[1];

                List<string> lFields = getDisplayFieldNames();
                if (lFields.Count == 0) lFields = getFieldNames();

                // Headers.
                for (int i = 0; i < lFields.Count; i++)
                    oSheet.Cells[1, i + 1] = lFields[i];

                // Anchor a named range at A1, matching dbDot.
                try { oSheet.Names.Add("ColumnTitle", oSheet.Range["A1"]); } catch { }

                // Rows.
                moveFirst();
                int iRow = 2;
                while (!eof)
                {
                    for (int i = 0; i < lFields.Count; i++)
                    {
                        string sVal = getFieldValue(lFields[i]) ?? "";
                        oSheet.Cells[iRow, i + 1] = sVal;
                    }
                    moveNext();
                    iRow++;
                }

                // Format like dbDot: auto-fit columns, wrap text,
                // align top, auto-fit rows. AutomationSecurity low
                // was set in dbDot to suppress macro prompts on Save.
                try { oSheet.Columns.AutoFit(); } catch { }
                try { oSheet.Cells.WrapText = true; } catch { }
                try { oSheet.Rows.AutoFit(); } catch { }
                try { oSheet.Rows.VerticalAlignment = -4160 /* xlVAlignTop */; } catch { }

                int iFmt = (sExt == "xls") ? 56 /* xlExcel8 */ : 51 /* xlWorkbookDefault */;
                oSheet.SaveAs(sDestPath, iFmt);
                oBook.Close(false);
            }
            finally
            {
                if (bookmarkObj != null) try { bookmark = bookmarkObj; } catch { }
                try { if (oApp != null) oApp.Quit(); } catch { }
                releaseCom(oSheet);
                releaseCom(oBook);
                releaseCom(oApp);
            }
        }

        // exportFrequencyChart: produce a bar chart of how often each
        // distinct value appears in one column of the current
        // filtered view. Writes an .xlsx file with two sheets: a
        // "Data" sheet containing value/count pairs sorted by count
        // descending, and a "Chart" sheet containing a bar chart
        // visualization. Useful for answering "what does my grade
        // distribution look like" or "how many students per major."
        //
        // The data walk uses the current recordset, so the active
        // Filter and Sort are respected -- chart only the rows the
        // user is currently viewing.
        //
        // Requires Excel installed (the .NET Framework 4.8 build of
        // DbDo has no native xlsx writer; Excel via late-bound COM
        // is the established pattern in DbDo). Throws InvalidOperation
        // with a human message if the ProgID isn't registered.
        //
        // Chart type: xlColumnClustered (51). Excel's default chart
        // style suffices; we don't customize colors or fonts, since
        // the goal is a quick at-a-glance summary not a publication
        // artifact. The user can polish the chart by hand in Excel.
        //
        // Returns the actual chart-data row count (i.e., distinct
        // value count); useful for the caller to report to the user.
        public int exportFrequencyChart(string sColumn, string sDestPath)
        {
            if (!hasRecordset()) throw new InvalidOperationException("No recordset open.");
            if (string.IsNullOrEmpty(sColumn)) throw new ArgumentException("Column name required.");
            if (!hasField(sColumn)) throw new ArgumentException("Column not found: " + sColumn);

            object bookmarkObj = bookmark;

            // Step 1: walk the recordset and accumulate counts. We
            // preserve insertion order in a List<string> so the
            // sort step below produces a stable secondary order
            // (alphabetical-by-first-seen) when counts tie.
            Dictionary<string, int> dCounts = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
            List<string> lOrder = new List<string>();
            moveFirst();
            while (!eof)
            {
                string sV = getFieldValue(sColumn);
                if (sV == null) sV = "";
                if (sV.Length == 0) sV = "blank";
                int iN;
                if (!dCounts.TryGetValue(sV, out iN)) { lOrder.Add(sV); iN = 0; }
                dCounts[sV] = iN + 1;
                moveNext();
            }

            // Sort by count descending, then alphabetically for ties.
            lOrder.Sort(delegate(string a, string b)
            {
                int iCmp = dCounts[b].CompareTo(dCounts[a]);
                if (iCmp != 0) return iCmp;
                return string.Compare(a, b, StringComparison.OrdinalIgnoreCase);
            });

            int iDistinct = lOrder.Count;

            // Step 2: emit the workbook and chart via Excel COM.
            dynamic oApp = null;
            dynamic oBook = null;
            dynamic oDataSheet = null;
            dynamic oChartSheet = null;
            dynamic oRange = null;
            try
            {
                oApp = ComAutomation.createApp("Excel.Application");
                oApp.Visible = false;
                oApp.DisplayAlerts = false;
                try { oApp.ScreenUpdating = false; } catch { }

                oBook = oApp.Workbooks.Add();
                oDataSheet = oBook.Sheets[1];
                oDataSheet.Name = "Data";

                // Headers.
                oDataSheet.Cells[1, 1] = sColumn;
                oDataSheet.Cells[1, 2] = "count";

                // Data rows.
                int iRow = 2;
                foreach (string sVal in lOrder)
                {
                    oDataSheet.Cells[iRow, 1] = sVal;
                    oDataSheet.Cells[iRow, 2] = dCounts[sVal];
                    iRow++;
                }

                try { oDataSheet.Columns.AutoFit(); } catch { }
                try { oDataSheet.Range["A1:B1"].Font.Bold = true; } catch { }

                // The data range used for the chart: A1:B(N+1).
                string sRangeAddr = "A1:B" + (iDistinct + 1);
                oRange = oDataSheet.Range[sRangeAddr];

                // Step 3: build the chart. AddChart2 with the
                // Excel 2013+ API is the modern entry point;
                // older API Charts.Add is a fallback. We try the
                // modern path first.
                dynamic oCharts = oBook.Charts;
                dynamic oChart = null;
                bool bModernChart = false;
                try
                {
                    // Sheets.Add for a new chart sheet, then set
                    // ChartType + SetSourceData.
                    oChartSheet = oCharts.Add();
                    oChart = oChartSheet;
                    oChart.ChartType = 51; // xlColumnClustered
                    oChart.SetSourceData(oRange);
                    // The Charts.Add path already names the sheet
                    // "Chart1"; rename to something friendlier.
                    try { oChart.Name = "Chart"; } catch { }
                    bModernChart = true;
                }
                catch (Exception exModern)
                {
                    try { DbDoLog.write("Chart Charts.Add path failed: " + exModern.Message); } catch { }
                }

                if (!bModernChart)
                {
                    // Fall back to embedding the chart on the data
                    // sheet via Shapes.AddChart2. This works on
                    // every modern Excel and is fine for a quick
                    // visualization.
                    try
                    {
                        oChart = oDataSheet.Shapes.AddChart2(-1 /* default style */,
                            51 /* xlColumnClustered */).Chart;
                        oChart.SetSourceData(oRange);
                    }
                    catch (Exception exEmbed)
                    {
                        throw new InvalidOperationException(
                            "Could not create chart: " + exEmbed.Message, exEmbed);
                    }
                }

                // Chart title: "<column> distribution" -- short and
                // accurate.
                try
                {
                    oChart.HasTitle = true;
                    oChart.ChartTitle.Text = sColumn + " distribution";
                }
                catch { }

                // Make sure the workbook saves as .xlsx.
                oBook.SaveAs(sDestPath, 51 /* xlWorkbookDefault */);
                oBook.Close(false);

                try { DbDoLog.write("Chart saved: " + sDestPath
                    + " (" + iDistinct + " distinct values)"); } catch { }
                return iDistinct;
            }
            finally
            {
                if (bookmarkObj != null) try { bookmark = bookmarkObj; } catch { }
                try { if (oApp != null) oApp.Quit(); } catch { }
                releaseCom(oRange);
                releaseCom(oChartSheet);
                releaseCom(oDataSheet);
                releaseCom(oBook);
                releaseCom(oApp);
            }
        }

        // exportScatterChart: produce an XY scatter of two numeric
        // columns. Walks the current filtered view once, keeps rows
        // where BOTH columns parse as numbers, writes an X/Y data sheet
        // and an xlXYScatter chart to sDestPath, and returns the number
        // of plotted points. Requires Excel (out-of-process COM, so it
        // is bitness-agnostic); throws a clear error if Excel is absent.
        public int exportScatterChart(string sColX, string sColY, string sDestPath)
        {
            if (!hasRecordset()) throw new InvalidOperationException("No recordset open.");
            if (string.IsNullOrEmpty(sColX) || string.IsNullOrEmpty(sColY))
                throw new ArgumentException("Two column names are required.");
            if (!hasField(sColX)) throw new ArgumentException("Column not found: " + sColX);
            if (!hasField(sColY)) throw new ArgumentException("Column not found: " + sColY);

            object bookmarkObj = bookmark;

            // Step 1: collect numeric (x, y) pairs from the filtered view.
            List<double> lX = new List<double>();
            List<double> lY = new List<double>();
            moveFirst();
            while (!eof)
            {
                string sx = getFieldValue(sColX) ?? "";
                string sy = getFieldValue(sColY) ?? "";
                double dx, dy;
                if (tryParseDoubleShared(sx, out dx) && tryParseDoubleShared(sy, out dy))
                { lX.Add(dx); lY.Add(dy); }
                moveNext();
            }
            int iPoints = lX.Count;
            if (iPoints == 0) { if (bookmarkObj != null) try { bookmark = bookmarkObj; } catch { } return 0; }

            // Step 2: emit the workbook and scatter chart via Excel COM.
            dynamic oApp = null, oBook = null, oDataSheet = null, oRange = null;
            try
            {
                oApp = ComAutomation.createApp("Excel.Application");
                oApp.Visible = false;
                oApp.DisplayAlerts = false;
                try { oApp.ScreenUpdating = false; } catch { }

                oBook = oApp.Workbooks.Add();
                oDataSheet = oBook.Sheets[1];
                oDataSheet.Name = "Data";
                oDataSheet.Cells[1, 1] = sColX;
                oDataSheet.Cells[1, 2] = sColY;
                for (int i = 0; i < iPoints; i++)
                {
                    oDataSheet.Cells[i + 2, 1] = lX[i];
                    oDataSheet.Cells[i + 2, 2] = lY[i];
                }
                try { oDataSheet.Columns.AutoFit(); } catch { }
                try { oDataSheet.Range["A1:B1"].Font.Bold = true; } catch { }

                string sRangeAddr = "A1:B" + (iPoints + 1);
                oRange = oDataSheet.Range[sRangeAddr];

                // xlXYScatter = -4169. Embed the chart on the data sheet.
                dynamic oChart = null;
                try
                {
                    oChart = oDataSheet.Shapes.AddChart2(-1, -4169).Chart;
                    oChart.SetSourceData(oRange);
                }
                catch (Exception exEmbed)
                {
                    throw new InvalidOperationException("Could not create scatter chart: " + exEmbed.Message, exEmbed);
                }
                try
                {
                    oChart.HasTitle = true;
                    oChart.ChartTitle.Text = sColY + " vs " + sColX;
                }
                catch { }

                oBook.SaveAs(sDestPath, 51 /* xlWorkbookDefault */);
                oBook.Close(false);
                try { DbDoLog.write("Scatter saved: " + sDestPath + " (" + iPoints + " points, "
                    + sColX + " vs " + sColY + ")"); } catch { }
                return iPoints;
            }
            finally
            {
                if (bookmarkObj != null) try { bookmark = bookmarkObj; } catch { }
                try { if (oApp != null) oApp.Quit(); } catch { }
                releaseCom(oRange);
                releaseCom(oDataSheet);
                releaseCom(oBook);
                releaseCom(oApp);
            }
        }

        // tryParseDoubleShared: invariant-culture numeric parse tolerant
        // of thousands separators and a leading currency symbol, matching
        // the leniency the statistics code uses. Public so the Generate
        // Output profiler can reuse the same numeric test the charts use.
        public static bool tryParseDoubleShared(string s, out double d)
        {
            d = 0;
            if (string.IsNullOrEmpty(s)) return false;
            string t = s.Trim();
            if (t.Length == 0) return false;
            // Strip one leading currency symbol and any thousands commas.
            if (t.Length > 0 && (t[0] == '$' || t[0] == '\u00A3' || t[0] == '\u20AC')) t = t.Substring(1).Trim();
            t = t.Replace(",", "");
            return double.TryParse(t, System.Globalization.NumberStyles.Any,
                System.Globalization.CultureInfo.InvariantCulture, out d);
        }

        // exportColumnChart: produce a chart matched to the column's
        // data type. Walks the current filtered view of one column,
        // then dispatches by sKind to one of several chart shapes,
        // writes an .xlsx to sDestPath, and returns the row count
        // that was plotted (caller uses this to phrase the
        // confirmation message).
        //
        // sKind values handled:
        //   "histogram"     -- numeric column; Sturges-binned columns
        //   "boxwhisker"    -- numeric column; xlBoxwhisker (121)
        //   "timeline"      -- date column; counts by year-month, line
        //   "byyear"        -- date column; counts by year, column
        //   "bymonth"       -- date column; counts by month-of-year,
        //                      column (seasonal pattern)
        //   "pie"           -- boolean column; True / False slices
        //   "pareto"        -- text column; top-15 frequencies sorted
        //
        // The function does NOT decide which chart fits; the caller
        // makes that decision from the column's detected data type.
        // Returns 0 if there is nothing to plot (e.g., all-empty
        // column); the caller surfaces that as a message.
        public int exportColumnChart(string sColumn, string sKind, string sDestPath)
        {
            if (!hasRecordset()) throw new InvalidOperationException("No recordset open.");
            if (string.IsNullOrEmpty(sColumn)) throw new ArgumentException("Column name required.");
            if (!hasField(sColumn)) throw new ArgumentException("Column not found: " + sColumn);
            if (string.IsNullOrEmpty(sKind)) throw new ArgumentException("Chart kind required.");

            object bookmarkObj = bookmark;

            // Walk the filtered view once, collecting every non-empty
            // cell value as a string. Per-chart-type processing kicks
            // in after the walk so we only iterate the recordset once.
            List<string> lRaw = new List<string>();
            moveFirst();
            while (!eof)
            {
                string sV = getFieldValue(sColumn);
                if (sV == null) sV = "";
                if (sV.Length > 0) lRaw.Add(sV);
                moveNext();
            }

            if (lRaw.Count == 0)
            {
                if (bookmarkObj != null) try { bookmark = bookmarkObj; } catch { }
                return 0;
            }

            // Per-chart preparation builds two parallel lists:
            //   lCategories -- the x-axis labels (strings for nominal
            //                  charts, dates for time charts, numeric
            //                  ranges for histograms, etc.)
            //   lValues     -- the corresponding numeric values
            // and a chart-type code (Excel XlChartType enum value, or
            // a flag value used to pick AddChart2 for box plot).
            List<string> lCategories = new List<string>();
            List<double> lValues = new List<double>();
            int iChartTypeCode = 51; // default xlColumnClustered
            string sChartTitle = sColumn;
            bool bUseAddChart2 = false; // true for xlBoxwhisker (121)
            // For boxwhisker we feed Excel the raw numeric values
            // (one per row); the chart engine computes Q1/median/Q3
            // itself. For all other types we pass aggregated counts.
            List<double> lRawNumeric = null;

            string sKindLower = sKind.ToLowerInvariant();
            if (sKindLower == "histogram")
            {
                List<double> lN = parseDoublesFromList(lRaw);
                if (lN.Count == 0) return 0;
                lN.Sort();
                // Sturges' rule: number of bins = ceil(log2(n)+1).
                int nBins = (int)Math.Ceiling(Math.Log(lN.Count, 2.0) + 1.0);
                if (nBins < 5)  nBins = 5;
                if (nBins > 20) nBins = 20;
                double dMin = lN[0];
                double dMax = lN[lN.Count - 1];
                if (dMax == dMin) { dMax = dMin + 1; } // protect against zero range
                double dBinWidth = (dMax - dMin) / nBins;
                int[] aBinCounts = new int[nBins];
                foreach (double d in lN)
                {
                    int iBin = (int)((d - dMin) / dBinWidth);
                    if (iBin >= nBins) iBin = nBins - 1;
                    if (iBin < 0) iBin = 0;
                    aBinCounts[iBin]++;
                }
                for (int i = 0; i < nBins; i++)
                {
                    double dLo = dMin + i * dBinWidth;
                    double dHi = dMin + (i + 1) * dBinWidth;
                    lCategories.Add(formatBinRange(dLo, dHi));
                    lValues.Add(aBinCounts[i]);
                }
                iChartTypeCode = 51; // xlColumnClustered for the binned distribution
                sChartTitle = sColumn + " distribution (histogram, " + nBins + " bins)";
            }
            else if (sKindLower == "boxwhisker")
            {
                lRawNumeric = parseDoublesFromList(lRaw);
                if (lRawNumeric.Count == 0) return 0;
                iChartTypeCode = 121; // xlBoxwhisker
                bUseAddChart2 = true;
                sChartTitle = sColumn + " (box and whisker)";
            }
            else if (sKindLower == "timeline")
            {
                List<DateTime> lDates = parseDatesFromList(lRaw);
                if (lDates.Count == 0) return 0;
                lDates.Sort();
                // Bucket by year-month so the timeline is smooth for
                // most real-world datasets; if the span is under 2
                // months, fall back to day buckets.
                bool bByDay = (lDates[lDates.Count - 1] - lDates[0]).TotalDays <= 60;
                Dictionary<string, int> dCounts = new Dictionary<string, int>();
                List<string> lOrder = new List<string>();
                foreach (DateTime dt in lDates)
                {
                    string sBucket = bByDay
                        ? dt.ToString("yyyy-MM-dd")
                        : dt.ToString("yyyy-MM");
                    int c;
                    if (!dCounts.TryGetValue(sBucket, out c)) { lOrder.Add(sBucket); c = 0; }
                    dCounts[sBucket] = c + 1;
                }
                foreach (string s in lOrder)
                {
                    lCategories.Add(s);
                    lValues.Add(dCounts[s]);
                }
                iChartTypeCode = 4; // xlLine
                sChartTitle = sColumn + " over time (" + (bByDay ? "by day" : "by month") + ")";
            }
            else if (sKindLower == "byyear")
            {
                List<DateTime> lDates = parseDatesFromList(lRaw);
                if (lDates.Count == 0) return 0;
                Dictionary<int, int> dCounts = new Dictionary<int, int>();
                foreach (DateTime dt in lDates)
                {
                    int c;
                    dCounts[dt.Year] = dCounts.TryGetValue(dt.Year, out c) ? c + 1 : 1;
                }
                List<int> lYears = new List<int>(dCounts.Keys);
                lYears.Sort();
                foreach (int y in lYears)
                {
                    lCategories.Add(y.ToString());
                    lValues.Add(dCounts[y]);
                }
                iChartTypeCode = 51; // xlColumnClustered
                sChartTitle = sColumn + " counts by year";
            }
            else if (sKindLower == "bymonth")
            {
                List<DateTime> lDates = parseDatesFromList(lRaw);
                if (lDates.Count == 0) return 0;
                string[] aMonthNames = new string[]
                { "Jan", "Feb", "Mar", "Apr", "May", "Jun",
                  "Jul", "Aug", "Sep", "Oct", "Nov", "Dec" };
                int[] aCounts = new int[12];
                foreach (DateTime dt in lDates) aCounts[dt.Month - 1]++;
                for (int i = 0; i < 12; i++)
                {
                    lCategories.Add(aMonthNames[i]);
                    lValues.Add(aCounts[i]);
                }
                iChartTypeCode = 51;
                sChartTitle = sColumn + " counts by month of year";
            }
            else if (sKindLower == "pie")
            {
                int iTrue = 0, iFalse = 0;
                foreach (string s in lRaw)
                {
                    if (isBooleanTrueLiteral(s)) iTrue++;
                    else iFalse++;
                }
                lCategories.Add("True"); lValues.Add(iTrue);
                lCategories.Add("False"); lValues.Add(iFalse);
                iChartTypeCode = 5; // xlPie
                sChartTitle = sColumn + " (true / false proportions)";
            }
            else if (sKindLower == "pareto")
            {
                Dictionary<string, int> dCounts = new Dictionary<string, int>(StringComparer.Ordinal);
                List<string> lOrder = new List<string>();
                foreach (string s in lRaw)
                {
                    int c;
                    if (!dCounts.TryGetValue(s, out c)) { lOrder.Add(s); c = 0; }
                    dCounts[s] = c + 1;
                }
                lOrder.Sort(delegate(string a, string b)
                {
                    int iCmp = dCounts[b].CompareTo(dCounts[a]);
                    if (iCmp != 0) return iCmp;
                    return string.Compare(a, b, StringComparison.OrdinalIgnoreCase);
                });
                int iMax = 15;
                int iShown = Math.Min(iMax, lOrder.Count);
                for (int i = 0; i < iShown; i++)
                {
                    lCategories.Add(lOrder[i]);
                    lValues.Add(dCounts[lOrder[i]]);
                }
                iChartTypeCode = 57; // xlBarClustered (horizontal bars work better for long labels)
                sChartTitle = (lOrder.Count <= iMax)
                    ? (sColumn + " frequencies")
                    : (sColumn + " top " + iShown + " of " + lOrder.Count);
            }
            else
            {
                throw new ArgumentException("Unknown chart kind: " + sKind);
            }

            if (lCategories.Count == 0) return 0;

            // Step: emit Excel workbook.
            dynamic oApp = null;
            dynamic oBook = null;
            dynamic oDataSheet = null;
            dynamic oChartSheet = null;
            dynamic oRange = null;
            try
            {
                oApp = ComAutomation.createApp("Excel.Application");
                oApp.Visible = false;
                oApp.DisplayAlerts = false;
                try { oApp.ScreenUpdating = false; } catch { }

                oBook = oApp.Workbooks.Add();
                oDataSheet = oBook.Sheets[1];
                oDataSheet.Name = "Data";

                int iDataRows;
                if (bUseAddChart2 && lRawNumeric != null)
                {
                    // Box-whisker: one column of raw values; Excel
                    // computes Q1/median/Q3 itself. Header row + n.
                    oDataSheet.Cells[1, 1] = sColumn;
                    for (int i = 0; i < lRawNumeric.Count; i++)
                        oDataSheet.Cells[i + 2, 1] = lRawNumeric[i];
                    iDataRows = lRawNumeric.Count;
                    string sAddr = "A1:A" + (iDataRows + 1);
                    oRange = oDataSheet.Range[sAddr];
                }
                else
                {
                    // Standard category/value pair.
                    oDataSheet.Cells[1, 1] = sColumn;
                    oDataSheet.Cells[1, 2] = "count";
                    for (int i = 0; i < lCategories.Count; i++)
                    {
                        oDataSheet.Cells[i + 2, 1] = lCategories[i];
                        oDataSheet.Cells[i + 2, 2] = lValues[i];
                    }
                    iDataRows = lCategories.Count;
                    string sAddr = "A1:B" + (iDataRows + 1);
                    oRange = oDataSheet.Range[sAddr];
                }
                try { oDataSheet.Columns.AutoFit(); } catch { }
                try
                {
                    string sHeaderAddr = bUseAddChart2 ? "A1" : "A1:B1";
                    oDataSheet.Range[sHeaderAddr].Font.Bold = true;
                }
                catch { }

                // Step: add the chart. xlBoxwhisker is a modern chart
                // that requires Shapes.AddChart2; classic chart types
                // use Sheets.Add with ChartType / SetSourceData.
                dynamic oChart = null;
                if (bUseAddChart2)
                {
                    // Embed on the data sheet. Style -1 is "use
                    // default style for this chart type." Position
                    // is well-clear of the data column.
                    try
                    {
                        oChart = oDataSheet.Shapes.AddChart2(-1, iChartTypeCode,
                            150, 10, 500, 320).Chart;
                        oChart.SetSourceData(oRange);
                    }
                    catch (Exception exAddChart2)
                    {
                        throw new InvalidOperationException(
                            "Could not create box-and-whisker chart: " + exAddChart2.Message
                            + " (requires Excel 2016 or newer).", exAddChart2);
                    }
                }
                else
                {
                    dynamic oCharts = oBook.Charts;
                    bool bModernChart = false;
                    try
                    {
                        oChartSheet = oCharts.Add();
                        oChart = oChartSheet;
                        oChart.ChartType = iChartTypeCode;
                        oChart.SetSourceData(oRange);
                        try { oChart.Name = "Chart"; } catch { }
                        bModernChart = true;
                    }
                    catch (Exception exModern)
                    {
                        try { DbDoLog.write("Plot Charts.Add path failed: " + exModern.Message); } catch { }
                    }
                    if (!bModernChart)
                    {
                        try
                        {
                            oChart = oDataSheet.Shapes.AddChart2(-1, iChartTypeCode).Chart;
                            oChart.SetSourceData(oRange);
                        }
                        catch (Exception exEmbed)
                        {
                            throw new InvalidOperationException(
                                "Could not create chart: " + exEmbed.Message, exEmbed);
                        }
                    }
                }

                try
                {
                    oChart.HasTitle = true;
                    oChart.ChartTitle.Text = sChartTitle;
                }
                catch { }

                oBook.SaveAs(sDestPath, 51 /* xlWorkbookDefault */);
                oBook.Close(false);

                try { DbDoLog.write("Plot saved: " + sDestPath
                    + " (" + iDataRows + " data points, kind=" + sKind + ")"); } catch { }
                return iDataRows;
            }
            finally
            {
                if (bookmarkObj != null) try { bookmark = bookmarkObj; } catch { }
                try { if (oApp != null) oApp.Quit(); } catch { }
                releaseCom(oRange);
                releaseCom(oChartSheet);
                releaseCom(oDataSheet);
                releaseCom(oBook);
                releaseCom(oApp);
            }
        }

        // parseDoublesFromList: filter a list of strings down to its
        // parseable doubles. Tries invariant culture first, then
        // current culture (so European decimal commas work).
        private static List<double> parseDoublesFromList(List<string> lRaw)
        {
            List<double> lN = new List<double>();
            foreach (string s in lRaw)
            {
                double d;
                if (double.TryParse(s,
                        System.Globalization.NumberStyles.Any,
                        System.Globalization.CultureInfo.InvariantCulture, out d)
                    || double.TryParse(s,
                        System.Globalization.NumberStyles.Any,
                        System.Globalization.CultureInfo.CurrentCulture, out d))
                {
                    lN.Add(d);
                }
            }
            return lN;
        }

        // parseDatesFromList: filter a list of strings down to its
        // parseable DateTime values. Requires a date-separator
        // character ('-' or '/') in the string so bare numbers like
        // "42" don't get treated as dates.
        private static List<DateTime> parseDatesFromList(List<string> lRaw)
        {
            List<DateTime> lD = new List<DateTime>();
            foreach (string s in lRaw)
            {
                if (s.IndexOf('-') < 0 && s.IndexOf('/') < 0) continue;
                DateTime dt;
                if (DateTime.TryParse(s,
                        System.Globalization.CultureInfo.InvariantCulture,
                        System.Globalization.DateTimeStyles.AssumeLocal, out dt)
                    || DateTime.TryParse(s,
                        System.Globalization.CultureInfo.CurrentCulture,
                        System.Globalization.DateTimeStyles.AssumeLocal, out dt))
                {
                    lD.Add(dt);
                }
            }
            return lD;
        }

        // isBooleanTrueLiteral: copy of the form's isBooleanTrue, but
        // on the manager so exportColumnChart doesn't need to call
        // into the form. Recognizes 1/-1/true/yes/y/t.
        private static bool isBooleanTrueLiteral(string s)
        {
            if (string.IsNullOrEmpty(s)) return false;
            string t = s.Trim().ToLowerInvariant();
            return t == "1" || t == "-1" || t == "true" || t == "yes" || t == "y" || t == "t";
        }

        // formatBinRange: render a histogram bin's [lo, hi) range as
        // a compact label. Uses fewer decimals for larger ranges so
        // the x-axis stays readable.
        private static string formatBinRange(double dLo, double dHi)
        {
            double dW = Math.Abs(dHi - dLo);
            string sFmt;
            if (dW >= 100) sFmt = "0";
            else if (dW >= 1) sFmt = "0.0";
            else sFmt = "0.000";
            return dLo.ToString(sFmt) + "-" + dHi.ToString(sFmt);
        }

        // exportWord: write the current recordset to a .docx file or
        // a Filtered-HTML .html file via Word.Application late-bound
        // COM. Requires Word to be installed.
        //
        // The output replicates dbDot's HomerLib.multiArrayToTables
        // Word path: header row in the first row of a Word table,
        // value rows below, heading-format on row 1, auto-fit
        // behavior wdAutoFitContent, a bookmark "ColumnTitle"
        // anchored at the second cell of the first row.
        //
        // bFilteredHtml = true uses wdFormatFilteredHtml (10), which
        // produces clean HTML without MSO-specific markup. Filtered
        // HTML is the user's preferred format for screen readers.
        public void exportWord(string sDestPath, string sExt, bool bFilteredHtml)
        {
            if (!hasRecordset()) throw new InvalidOperationException("No recordset open.");
            object bookmarkObj = bookmark;

            dynamic oApp = null;
            dynamic oDoc = null;
            try
            {
                oApp = ComAutomation.createApp("Word.Application");
                oApp.Visible = false;
                try { oApp.DisplayAlerts = 0 /* wdAlertsNone */; } catch { }
                try { oApp.ScreenUpdating = false; } catch { }

                oDoc = oApp.Documents.Add();
                dynamic oRange = oDoc.Content;

                List<string> lFields = getDisplayFieldNames();
                if (lFields.Count == 0) lFields = getFieldNames();
                int iFieldCount = lFields.Count;

                int iRowCount = recordCount;
                if (iRowCount < 0) iRowCount = 0;

                // Pre-size the table: header row + N value rows.
                dynamic oTable = oDoc.Tables.Add(oRange, iRowCount + 1, iFieldCount);

                // Header row.
                for (int i = 0; i < iFieldCount; i++)
                {
                    try { oTable.Rows[1].Cells[i + 1].Range.Text = lFields[i]; } catch { }
                }

                // Value rows.
                moveFirst();
                int iRow = 2;
                while (!eof && iRow <= iRowCount + 1)
                {
                    for (int i = 0; i < iFieldCount; i++)
                    {
                        string sVal = getFieldValue(lFields[i]) ?? "";
                        try { oTable.Rows[iRow].Cells[i + 1].Range.Text = sVal; } catch { }
                    }
                    moveNext();
                    iRow++;
                }

                // Format like dbDot: auto-fit, heading-format on
                // header row, named bookmark anchored to row 1 / col 2.
                try { oTable.AllowAutoFit = true; } catch { }
                try { oTable.AutoFitBehavior(1 /* wdAutoFitContent */); } catch { }
                try { oTable.Rows[1].HeadingFormat = true; } catch { }
                try { oTable.ApplyStyleHeadingRows = true; } catch { }
                try { if (iFieldCount >= 2) oDoc.Bookmarks.Add("ColumnTitle", oTable.Rows[1].Cells[2].Range); } catch { }

                // SaveAs format codes:
                //   wdFormatDocumentDefault  = 16  (docx)
                //   wdFormatFilteredHtml     = 10  (filtered HTML)
                int iFmt = bFilteredHtml ? 10 : 16;
                oDoc.SaveAs(sDestPath, iFmt);
                oDoc.Close(0 /* wdDoNotSaveChanges */);
                try { if (!(bool)oApp.NormalTemplate.Saved) oApp.NormalTemplate.Saved = true; } catch { }
            }
            finally
            {
                if (bookmarkObj != null) try { bookmark = bookmarkObj; } catch { }
                try { if (oApp != null) oApp.Quit(); } catch { }
                releaseCom(oDoc);
                releaseCom(oApp);
            }
        }

        // exportDatabase: write the current recordset to a new
        // database file in one of the formats DbDo can also OPEN
        // (SQLite, Access, dBASE). This closes the "every input
        // format is also an export format" loop. The new file gets
        // exactly one table, named after the source table.
        //
        // Strategy: open a fresh ADODB.Connection to the target
        // file using DbDo's own buildConnectString helper (so the
        // same provider mapping that drives openDatabase drives the
        // export); issue CREATE TABLE with TEXT columns for every
        // field (a permissive type that all three back-ends accept
        // and that round-trips screen-reader values cleanly); then
        // INSERT one row at a time. The original recordset is not
        // disturbed.
        //
        // For SQLite (.db / .sqlite / .sqlite3), the file is
        // created on disk first (SQLite ODBC opens an existing path
        // or implicitly creates one). For Access (.mdb / .accdb),
        // ADOX.Catalog.Create is the canonical way to create a
        // fresh database file. For dBASE (.dbf), the connection is
        // to the parent folder and the .dbf file is created by the
        // CREATE TABLE statement itself.
        //
        // Requires the appropriate driver installed: SQLite ODBC
        // for .db / .sqlite, ACE for .mdb / .accdb / .dbf. The
        // installer already handles those.
        public void exportDatabase(string sDestPath, string sExt)
        {
            if (!hasRecordset()) throw new InvalidOperationException("No recordset open.");
            if (string.IsNullOrEmpty(sDestPath)) throw new ArgumentException("exportDatabase requires a path.");
            string sExtLower = (sExt ?? "").ToLowerInvariant().TrimStart('.');

            // Make sure the destination folder exists.
            string sDir = Path.GetDirectoryName(sDestPath);
            if (!string.IsNullOrEmpty(sDir) && !Directory.Exists(sDir))
                Directory.CreateDirectory(sDir);

            // For Access we must create the empty database file via
            // ADOX before we can connect to it; for SQLite the ODBC
            // driver implicitly creates an empty file on open; for
            // dBASE the file is created by the CREATE TABLE itself.
            if (sExtLower == "mdb" || sExtLower == "accdb")
            {
                // Don't overwrite silently.
                if (File.Exists(sDestPath))
                    throw new IOException("Target file already exists: " + sDestPath);
                createEmptyAccessFile(sDestPath, sExtLower);
            }
            else if (sExtLower == "db" || sExtLower == "sqlite" || sExtLower == "sqlite3")
            {
                if (File.Exists(sDestPath))
                    throw new IOException("Target file already exists: " + sDestPath);
                // The SQLite ODBC driver creates the database file
                // on Open() if it doesn't exist. Nothing to do here.
            }

            object bookmarkObj = bookmark;
            // Save-As to a database is a FAITHFUL COPY of the table, so
            // the new file must get EVERY field -- matching this method's
            // contract ("CREATE TABLE ... for every field"). It must NOT
            // use getDisplayFieldNames(): the Alt+S display selection is a
            // transient view preference, and letting it drive the persisted
            // schema both drops columns the user has hidden (silent data
            // loss) and bakes the current selection into the new file --
            // e.g. exporting the standard 'notes' column as a visible field,
            // which the reopened copy then hides again as a standard column,
            // leaving its data reachable only via Say Notes. Copy all real
            // fields; the display preference is reapplied when the copy opens.
            List<string> lFields = getFieldNames();
            if (lFields.Count == 0) lFields = getDisplayFieldNames();

            // Build the connection string. For dBASE the path
            // points at the parent folder (not the file), and the
            // table name is derived separately. buildConnectStringForExport
            // handles both shapes cleanly.
            bool bIsFolder = (sExtLower == "dbf");
            // For dBASE, the connection is to the folder, not the
            // file. We construct the same way buildConnectString
            // expects for a folder.
            string sConnPath = sDestPath;
            string sTableName = sCurrentTable;
            if (string.IsNullOrEmpty(sTableName)) sTableName = "Export";
            if (sExtLower == "dbf")
            {
                // dBASE table names: max 8 chars, no extension, no spaces.
                sTableName = sanitizeDbaseTableName(sTableName);
            }
            string sConnect = buildConnectStringForExport(sConnPath, sExtLower, sTableName);

            dynamic oConnExport = null;
            try
            {
                oConnExport = createComObject("ADODB.Connection");
                oConnExport.CursorLocation = AdoConstants.adUseClient;
                oConnExport.Open(sConnect);

                // Build CREATE TABLE. TEXT columns are the safest
                // universal type. SQLite is dynamically typed, so
                // TEXT is fine. Access (Jet/ACE) accepts TEXT as a
                // synonym for the longest variable-length text
                // column it offers. dBASE accepts CHAR(n) and
                // MEMO; we use MEMO so very long fields don't
                // truncate.
                string sCreateSql = buildCreateTableSql(sTableName, lFields, sExtLower);
                oConnExport.Execute(sCreateSql);

                // Insert rows.
                string sInsertSql = buildInsertSql(sTableName, lFields, sExtLower);

                moveFirst();
                while (!eof)
                {
                    // Build the parameterized INSERT each time; we
                    // do this rather than prepared statements
                    // because late-bound ADO parameterization is
                    // awkward, and the values are already strings
                    // from getFieldValue. Escape single quotes
                    // and embedded delimiters per back-end.
                    List<string> lValues = new List<string>();
                    foreach (string sN in lFields)
                        lValues.Add(quoteSqlLiteral(getFieldValue(sN), sExtLower));
                    string sFullSql = sInsertSql.Replace("@@VALUES@@", string.Join(",", lValues));
                    oConnExport.Execute(sFullSql);
                    moveNext();
                }
            }
            finally
            {
                if (bookmarkObj != null) try { bookmark = bookmarkObj; } catch { }
                try { if (oConnExport != null) oConnExport.Close(); } catch { }
                releaseCom(oConnExport);
            }
        }

        // Build a connection string for an EXPORT target. Differs
        // from buildConnectString only in that the dBASE / text
        // cases want to point at the destination folder, not at the
        // destination file. For SQLite, Access, Excel we just reuse
        // the same provider strings.
        private static string buildConnectStringForExport(string sPath, string sExt, string sTable)
        {
            switch (sExt)
            {
                case "db":
                case "sqlite":
                case "sqlite3":
                    return string.Format("DRIVER=SQLite3 ODBC Driver;Database={0};", sPath);

                case "mdb":
                case "accdb":
                    return string.Format(
                        "Provider={0};Data Source={1};Persist Security Info=False;",
                        DefaultProvider, sPath);

                case "dbf":
                    // Point at the parent folder.
                    string sFolder = Path.GetDirectoryName(sPath);
                    if (string.IsNullOrEmpty(sFolder)) sFolder = Environment.CurrentDirectory;
                    return string.Format(
                        "Provider={0};Data Source={1};Extended Properties=\"dBASE IV;\"",
                        DefaultProvider, sFolder);

                default:
                    throw new Exception("exportDatabase: unsupported format ." + sExt);
            }
        }

        // Create an empty .mdb / .accdb file via ADOX.Catalog.Create.
        // This is the canonical way to fabricate a fresh Access
        // database without having to ship a stub file.
        private static void createEmptyAccessFile(string sPath, string sExt)
        {
            dynamic oCat = null;
            try
            {
                oCat = createComObject("ADOX.Catalog");
                string sConn = string.Format(
                    "Provider={0};Data Source={1};",
                    DefaultProvider, sPath);
                oCat.Create(sConn);
            }
            catch (Exception ex)
            {
                throw new Exception("Could not create Access database: " + ex.Message
                    + " (Is ADOX installed? It's part of MDAC/ACE.)", ex);
            }
            finally
            {
                releaseCom(oCat);
            }
        }

        // dBASE limits table (file) names to 8 characters and a
        // small character set. Truncate and replace forbidden
        // characters with underscore.
        private static string sanitizeDbaseTableName(string sName)
        {
            if (string.IsNullOrEmpty(sName)) return "EXPORT";
            StringBuilder sb = new StringBuilder();
            foreach (char c in sName.ToUpperInvariant())
            {
                if (sb.Length >= 8) break;
                if ((c >= 'A' && c <= 'Z') || (c >= '0' && c <= '9') || c == '_')
                    sb.Append(c);
                else
                    sb.Append('_');
            }
            if (sb.Length == 0) return "EXPORT";
            return sb.ToString();
        }

        // Build CREATE TABLE statement appropriate for each
        // back-end. All fields are text-typed for portability.
        private string buildCreateTableSql(string sTable, List<string> lFields, string sExt)
        {
            StringBuilder sb = new StringBuilder();
            sb.Append("CREATE TABLE ");
            sb.Append(quoteIdentifier(sTable, sExt));
            sb.Append(" (");
            for (int i = 0; i < lFields.Count; i++)
            {
                if (i > 0) sb.Append(", ");
                sb.Append(quoteIdentifier(lFields[i], sExt));
                sb.Append(' ');
                // Column type per back-end:
                //   SQLite -- TEXT (dynamic typing makes this no
                //     constraint anyway).
                //   Access -- MEMO (long text).
                //   dBASE -- MEMO (variable-length text, stored in
                //     a separate .dbt file alongside the .dbf).
                if (sExt == "db" || sExt == "sqlite" || sExt == "sqlite3")
                    sb.Append("TEXT");
                else if (sExt == "mdb" || sExt == "accdb")
                    sb.Append("MEMO");
                else // dbf
                    sb.Append("MEMO");
            }
            sb.Append(')');
            return sb.ToString();
        }

        // Build the INSERT template, with the literal "@@VALUES@@"
        // placeholder where the per-row value list will be spliced.
        private string buildInsertSql(string sTable, List<string> lFields, string sExt)
        {
            StringBuilder sb = new StringBuilder();
            sb.Append("INSERT INTO ");
            sb.Append(quoteIdentifier(sTable, sExt));
            sb.Append(" (");
            for (int i = 0; i < lFields.Count; i++)
            {
                if (i > 0) sb.Append(", ");
                sb.Append(quoteIdentifier(lFields[i], sExt));
            }
            sb.Append(") VALUES (@@VALUES@@)");
            return sb.ToString();
        }

        // Quote an identifier per back-end:
        //   SQLite -- double quotes (ANSI SQL).
        //   Access -- square brackets.
        //   dBASE  -- bare, uppercased, no special characters.
        private static string quoteIdentifier(string sName, string sExt)
        {
            if (sExt == "dbf")
                return sanitizeDbaseTableName(sName);
            if (sExt == "db" || sExt == "sqlite" || sExt == "sqlite3")
                return "\"" + sName.Replace("\"", "\"\"") + "\"";
            // All other ACE/Jet providers (Access, Excel, Text/CSV)
            // bracket the identifier; brackets are the universal Jet
            // quote and the only form that tolerates spaces, '$'
            // (Excel sheets) and '#' (Text files).
            return "[" + sName.Replace("]", "") + "]";
        }

        // Quote a literal value as a SQL string. NULL handling
        // differs slightly per back-end but SQL standard NULL is
        // accepted everywhere.
        private static string quoteSqlLiteral(string sValue, string sExt)
        {
            if (sValue == null) return "NULL";
            // All three back-ends accept SQL-standard apostrophe
            // doubling for embedded quotes within a single-quoted
            // string literal.
            return "'" + sValue.Replace("'", "''") + "'";
        }

        // exportMarkdown: write the current recordset as a GitHub-
        // flavored Markdown table. No external library needed --
        // the format is line-based plain text with pipe delimiters
        // and a header-separator row. Useful for pasting into a
        // README, an issue, a chat message, or any Markdown editor.
        public void exportMarkdown(string sDestPath)
        {
            if (!hasRecordset()) throw new InvalidOperationException("No recordset open.");
            object bookmarkObj = bookmark;
            List<string> lFields = getDisplayFieldNames();
            if (lFields.Count == 0) lFields = getFieldNames();

            using (StreamWriter writer2 = new StreamWriter(sDestPath, false, new UTF8Encoding(true)))
            {
                // Optional title line.
                if (!string.IsNullOrEmpty(sCurrentTable))
                {
                    writer2.WriteLine("# " + sCurrentTable);
                    writer2.WriteLine();
                }
                // Header row.
                writer2.Write("|");
                foreach (string sN in lFields) { writer2.Write(" "); writer2.Write(escapeMarkdownCell(sN)); writer2.Write(" |"); }
                writer2.WriteLine();
                // Separator row.
                writer2.Write("|");
                foreach (string sN in lFields) { writer2.Write(" --- |"); }
                writer2.WriteLine();
                // Value rows.
                moveFirst();
                while (!eof)
                {
                    writer2.Write("|");
                    foreach (string sN in lFields)
                    {
                        writer2.Write(" ");
                        writer2.Write(escapeMarkdownCell(getFieldValue(sN)));
                        writer2.Write(" |");
                    }
                    writer2.WriteLine();
                    moveNext();
                }
            }
            if (bookmarkObj != null) bookmark = bookmarkObj;
        }

        // exportJson: write the current recordset as a JSON array of
        // objects -- one object per row, field name to value -- pretty-
        // printed. Mirrors exportMarkdown's row walk and bookmark save/
        // restore. Numbers, booleans, and nulls are emitted as native
        // JSON types rather than quoted strings, so the file round-trips
        // cleanly through pandas.read_json, Python's json module, and the
        // like. Written UTF-8 without a BOM, which those readers expect.
        // Uses Json.NET (Newtonsoft.Json), fetched by buildDbDo.cmd.
        public void exportJson(string sDestPath)
        {
            if (!hasRecordset()) throw new InvalidOperationException("No recordset open.");
            object bookmarkObj = bookmark;
            List<string> lFields = getDisplayFieldNames();
            if (lFields.Count == 0) lFields = getFieldNames();

            JArray aRows = new JArray();
            moveFirst();
            while (!eof)
            {
                JObject oRow = new JObject();
                foreach (string sN in lFields)
                {
                    object oVal = null;
                    try { oVal = oRecordset.Fields[sN].Value; } catch { }
                    JToken tok;
                    if (oVal == null || oVal is DBNull) tok = JValue.CreateNull();
                    else { try { tok = JToken.FromObject(oVal); } catch { tok = new JValue(oVal.ToString()); } }
                    oRow[sN] = tok;
                }
                aRows.Add(oRow);
                moveNext();
            }
            if (bookmarkObj != null) bookmark = bookmarkObj;

            File.WriteAllText(sDestPath, aRows.ToString(Formatting.Indented), new UTF8Encoding(false));
        }

        // Escape a cell value for safe inclusion in a Markdown
        // table cell: pipes become \|, embedded newlines become
        // a <br> so the row doesn't collapse, and the original
        // newline/CR are stripped.
        private static string escapeMarkdownCell(string sValue)
        {
            if (sValue == null) return "";
            return sValue
                .Replace("|", "\\|")
                .Replace("\r\n", "<br>")
                .Replace("\n", "<br>")
                .Replace("\r", "<br>");
        }

        // importMarkdown: read a GitHub-flavored Markdown file
        // containing one or more pipe-delimited tables, and append
        // every value row into the currently-open recordset.
        //
        // Parse rules, deliberately lenient:
        //   * Lines starting with '|' (after trimming whitespace)
        //     are table rows.
        //   * The first table row is the header.
        //   * The second table row is the separator (---, :---,
        //     ---:, etc.); it is skipped.
        //   * Any subsequent | rows are value rows.
        //   * Header cell names are matched case-insensitively to
        //     columns in the currently-open table. Cells with no
        //     matching column are dropped silently.
        //   * Within a cell, "<br>" (case-insensitive) is converted
        //     back to a single newline, and "\|" back to a literal
        //     pipe. This is the inverse of escapeMarkdownCell.
        //   * If the file contains multiple tables (separated by
        //     blank lines), they all import; later tables append
        //     onto the same target.
        //
        // The current-table must already be open. The bookkeeping
        // columns (added, edited, marked, the primary key) take
        // their DEFAULT values automatically -- the import only
        // sets columns the Markdown header names.
        //
        // Returns the number of rows successfully inserted.
        public int importMarkdown(string sSourcePath)
        {
            if (!hasRecordset()) throw new InvalidOperationException("No recordset open. Use Open-Database first.");
            if (string.IsNullOrEmpty(sSourcePath)) throw new ArgumentException("importMarkdown requires a path.");
            if (!File.Exists(sSourcePath)) throw new FileNotFoundException("Markdown file not found.", sSourcePath);
            if (readOnly) throw new InvalidOperationException("The database was opened read-only. Close it and reopen without the -readonly flag to enable editing.");

            // Read every line. Files are usually small (Markdown
            // tables are rarely millions of rows); ReadAllLines is
            // acceptable.
            string[] aLines;
            try { aLines = File.ReadAllLines(sSourcePath, Encoding.UTF8); }
            catch (Exception ex) { throw new Exception("Could not read " + sSourcePath + ": " + ex.Message, ex); }

            int iInserted = 0;
            List<string> lHeaders = null;
            bool bSawSeparator = false;

            // Get the destination's column set so we can match by
            // name. ADO column-name comparison is case-insensitive.
            List<string> lAllDestFields = getFieldNames();
            HashSet<string> hDestFields = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
            foreach (string sN in lAllDestFields) hDestFields.Add(sN);

            for (int iLine = 0; iLine < aLines.Length; iLine++)
            {
                string sLine = (aLines[iLine] ?? "").Trim();
                if (sLine.Length == 0)
                {
                    // Blank line ends one table; next | line starts another.
                    lHeaders = null;
                    bSawSeparator = false;
                    continue;
                }
                if (!sLine.StartsWith("|")) continue;   // not a table row

                List<string> lCells = splitMarkdownRow(sLine);

                if (lHeaders == null)
                {
                    // First table row in this group = header.
                    lHeaders = lCells;
                    bSawSeparator = false;
                    continue;
                }
                if (!bSawSeparator)
                {
                    // The separator row is all dashes/colons. Don't
                    // be strict; any cell that is purely [-:\s] is
                    // accepted as separator. If the row doesn't
                    // look like one, treat it as the first value
                    // row (some Markdown dialects omit the separator).
                    bool bAllSep = true;
                    foreach (string sCell in lCells)
                    {
                        string sT = sCell.Trim();
                        if (sT.Length == 0) continue;
                        foreach (char c in sT)
                        {
                            if (c != '-' && c != ':' && c != ' ') { bAllSep = false; break; }
                        }
                        if (!bAllSep) break;
                    }
                    bSawSeparator = true;
                    if (bAllSep) continue;
                    // Otherwise fall through and treat the cells
                    // as a value row.
                }

                // Value row. Build column->value pairs by header.
                Dictionary<string, string> dRow = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
                for (int iCell = 0; iCell < lCells.Count && iCell < lHeaders.Count; iCell++)
                {
                    string sCol = lHeaders[iCell].Trim();
                    if (!hDestFields.Contains(sCol)) continue;
                    dRow[sCol] = unescapeMarkdownCell(lCells[iCell]).Trim();
                }
                if (dRow.Count == 0) continue;

                // Insert via ADO AddNew so column defaults fire.
                try
                {
                    oRecordset.AddNew();
                    foreach (KeyValuePair<string, string> kvp in dRow)
                    {
                        try { oRecordset.Fields[kvp.Key].Value = kvp.Value; }
                        catch { /* skip un-settable cells */ }
                    }
                    oRecordset.Update();
                    iInserted++;
                }
                catch
                {
                    // Cancel and continue; one bad row shouldn't
                    // sink the whole import.
                    try { oRecordset.CancelUpdate(); } catch { }
                }
            }

            return iInserted;
        }

        // importDelimited: read a CSV/TSV file and append each value row
        // to the current table, matching header names to columns case-
        // insensitively -- the same contract as importMarkdown (unmatched
        // columns dropped, one bad row doesn't sink the import). Uses a
        // native RFC 4180 reader (parseDelimited), so no Office/ACE text
        // driver is involved. cDelim is ',' for CSV or '\t' for TSV.
        public int importDelimited(string sSourcePath, char cDelim)
        {
            if (!hasRecordset()) throw new InvalidOperationException("No recordset open. Use Open-Database first.");
            if (string.IsNullOrEmpty(sSourcePath)) throw new ArgumentException("importDelimited requires a path.");
            if (!File.Exists(sSourcePath)) throw new FileNotFoundException("Delimited file not found.", sSourcePath);
            if (readOnly) throw new InvalidOperationException("The database was opened read-only. Close it and reopen without the -readonly flag to enable editing.");

            string sText;
            try { sText = File.ReadAllText(sSourcePath, Encoding.UTF8); }
            catch (Exception ex) { throw new Exception("Could not read " + sSourcePath + ": " + ex.Message, ex); }

            List<string[]> lRecords = parseDelimited(sText, cDelim);

            List<string> lAllDestFields = getFieldNames();
            HashSet<string> hDestFields = new HashSet<string>(lAllDestFields, StringComparer.OrdinalIgnoreCase);

            int iInserted = 0;
            string[] aHeaders = null;
            foreach (string[] aRec in lRecords)
            {
                if (rowIsEmpty(aRec)) continue;
                if (aHeaders == null) { aHeaders = aRec; continue; }   // first non-empty record = header

                Dictionary<string, string> dRow = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
                for (int i = 0; i < aRec.Length && i < aHeaders.Length; i++)
                {
                    string sCol = (aHeaders[i] ?? "").Trim();
                    if (sCol.Length == 0 || !hDestFields.Contains(sCol)) continue;
                    dRow[sCol] = aRec[i] ?? "";
                }
                if (dRow.Count == 0) continue;

                try
                {
                    oRecordset.AddNew();
                    foreach (KeyValuePair<string, string> kvp in dRow)
                    { try { oRecordset.Fields[kvp.Key].Value = kvp.Value; } catch { /* skip un-settable cells */ } }
                    oRecordset.Update();
                    iInserted++;
                }
                catch { try { oRecordset.CancelUpdate(); } catch { } }
            }
            return iInserted;
        }

        // parseDelimited: a self-contained RFC 4180 reader. A quoted field
        // may contain the delimiter, doubled quotes ("" -> a literal "),
        // and embedded newlines; CRLF and LF line endings are both
        // accepted. Returns one string[] per record (validated in Python
        // against the reference csv module across the tricky cases).
        internal static List<string[]> parseDelimited(string sText, char cDelim)
        {
            List<string[]> lRecords = new List<string[]>();
            if (string.IsNullOrEmpty(sText)) return lRecords;
            List<string> lRec = new List<string>();
            StringBuilder sbField = new StringBuilder();
            bool bInQuote = false, bPending = false;
            int i = 0, n = sText.Length;
            while (i < n)
            {
                char c = sText[i];
                if (bInQuote)
                {
                    if (c == '"')
                    {
                        if (i + 1 < n && sText[i + 1] == '"') { sbField.Append('"'); i += 2; continue; }
                        bInQuote = false; i++; continue;
                    }
                    sbField.Append(c); i++; continue;
                }
                if (c == '"') { bInQuote = true; bPending = true; i++; continue; }
                if (c == cDelim) { lRec.Add(sbField.ToString()); sbField.Length = 0; bPending = true; i++; continue; }
                if (c == '\r')
                {
                    if (i + 1 < n && sText[i + 1] == '\n') i++;
                    lRec.Add(sbField.ToString()); sbField.Length = 0;
                    lRecords.Add(lRec.ToArray()); lRec.Clear(); bPending = false; i++; continue;
                }
                if (c == '\n')
                {
                    lRec.Add(sbField.ToString()); sbField.Length = 0;
                    lRecords.Add(lRec.ToArray()); lRec.Clear(); bPending = false; i++; continue;
                }
                sbField.Append(c); bPending = true; i++; continue;
            }
            if (sbField.Length > 0 || lRec.Count > 0 || bPending)
            { lRec.Add(sbField.ToString()); lRecords.Add(lRec.ToArray()); }
            return lRecords;
        }

        // rowIsEmpty: true when every cell is blank/whitespace (so blank
        // lines and all-empty rows are skipped).
        private static bool rowIsEmpty(string[] aRec)
        {
            if (aRec == null) return true;
            foreach (string s in aRec) if (!string.IsNullOrEmpty(s) && s.Trim().Length > 0) return false;
            return true;
        }

        // importJson: read a JSON file -- either an array of objects or
        // a single object -- and append each object as a row to the
        // current table, matching property names to columns case-
        // insensitively (the same contract as importMarkdown: unmatched
        // properties are dropped, one bad row doesn't sink the import).
        // A property whose value is itself a JSON object or array is
        // stored as its compact JSON text. Uses Json.NET.
        public int importJson(string sSourcePath)
        {
            if (!hasRecordset()) throw new InvalidOperationException("No recordset open. Use Open-Database first.");
            if (string.IsNullOrEmpty(sSourcePath)) throw new ArgumentException("importJson requires a path.");
            if (!File.Exists(sSourcePath)) throw new FileNotFoundException("JSON file not found.", sSourcePath);
            if (readOnly) throw new InvalidOperationException("The database was opened read-only. Close it and reopen without the -readonly flag to enable editing.");

            string sText;
            try { sText = File.ReadAllText(sSourcePath); }
            catch (Exception ex) { throw new Exception("Could not read " + sSourcePath + ": " + ex.Message, ex); }

            JToken root;
            try { root = JToken.Parse(sText); }
            catch (Exception ex) { throw new Exception("Not valid JSON: " + ex.Message, ex); }

            // Accept a top-level array of objects, or a single object.
            JArray aRows;
            if (root is JArray) aRows = (JArray)root;
            else if (root is JObject) { aRows = new JArray(); aRows.Add(root); }
            else throw new Exception("JSON must be an array of objects or a single object.");

            // Destination columns, matched by name case-insensitively.
            List<string> lAllDestFields = getFieldNames();
            HashSet<string> hDestFields = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
            foreach (string sN in lAllDestFields) hDestFields.Add(sN);

            int iInserted = 0;
            foreach (JToken tRow in aRows)
            {
                JObject oRow = tRow as JObject;
                if (oRow == null) continue;   // skip non-object array entries

                Dictionary<string, object> dRow = new Dictionary<string, object>(StringComparer.OrdinalIgnoreCase);
                foreach (JProperty prop in oRow.Properties())
                {
                    if (!hDestFields.Contains(prop.Name)) continue;
                    JToken tv = prop.Value;
                    if (tv == null || tv.Type == JTokenType.Null) continue;
                    if (tv is JValue) dRow[prop.Name] = ((JValue)tv).Value;
                    else dRow[prop.Name] = tv.ToString(Formatting.None);   // nested object/array -> compact JSON text
                }
                if (dRow.Count == 0) continue;

                // Insert via ADO AddNew so column defaults fire.
                try
                {
                    oRecordset.AddNew();
                    foreach (KeyValuePair<string, object> kvp in dRow)
                    {
                        try { oRecordset.Fields[kvp.Key].Value = kvp.Value; }
                        catch { /* skip un-settable cells */ }
                    }
                    oRecordset.Update();
                    iInserted++;
                }
                catch
                {
                    // Cancel and continue; one bad row shouldn't
                    // sink the whole import.
                    try { oRecordset.CancelUpdate(); } catch { }
                }
            }

            return iInserted;
        }

        // Split a Markdown table row on unescaped pipe characters.
        // Strips the leading and trailing pipes if present, treats
        // \| as a literal pipe inside a cell.
        private static List<string> splitMarkdownRow(string sLine)
        {
            // Remove surrounding pipes.
            string s = sLine.Trim();
            if (s.StartsWith("|")) s = s.Substring(1);
            if (s.EndsWith("|") && !s.EndsWith("\\|")) s = s.Substring(0, s.Length - 1);

            List<string> lCells = new List<string>();
            StringBuilder sb = new StringBuilder();
            int iPos = 0;
            while (iPos < s.Length)
            {
                char c = s[iPos];
                if (c == '\\' && iPos + 1 < s.Length && s[iPos + 1] == '|')
                {
                    sb.Append('|');
                    iPos += 2;
                    continue;
                }
                if (c == '|')
                {
                    lCells.Add(sb.ToString());
                    sb.Clear();
                    iPos++;
                    continue;
                }
                sb.Append(c);
                iPos++;
            }
            lCells.Add(sb.ToString());
            return lCells;
        }

        // Invert escapeMarkdownCell: <br> back to newline; \| back
        // to |. Case-insensitive on the <br>.
        private static string unescapeMarkdownCell(string sCell)
        {
            if (sCell == null) return "";
            string s = sCell;
            // Replace <br>, <br/>, <br /> (any case).
            s = System.Text.RegularExpressions.Regex.Replace(
                s, @"<br\s*/?>", "\n",
                System.Text.RegularExpressions.RegexOptions.IgnoreCase);
            // Note: splitMarkdownRow already handled \| -> | when
            // splitting on pipe boundaries; here we leave \| alone
            // in case any leaked through.
            return s;
        }

        private void exportDelimited(string sDestPath, string sDelim)
        {
            object bookmarkObj = bookmark;
            List<string> lFields = getFieldNames();
            using (StreamWriter writer2 = new StreamWriter(sDestPath, false, new UTF8Encoding(true)))
            {
                List<string> lH = new List<string>();
                foreach (string sN in lFields) lH.Add(escapeDelimField(sN, sDelim));
                writer2.WriteLine(string.Join(sDelim, lH));

                moveFirst();
                while (!eof)
                {
                    List<string> lV = new List<string>();
                    foreach (string sN in lFields) lV.Add(escapeDelimField(getFieldValue(sN), sDelim));
                    writer2.WriteLine(string.Join(sDelim, lV));
                    moveNext();
                }
            }
            if (bookmarkObj != null) bookmark = bookmarkObj;
        }

        private static string escapeDelimField(string sValue, string sDelim)
        {
            if (sValue == null) return "";
            bool bNeedsQuote = sValue.Contains(sDelim) || sValue.Contains("\"") || sValue.Contains("\n") || sValue.Contains("\r");
            if (!bNeedsQuote) return sValue;
            return "\"" + sValue.Replace("\"", "\"\"") + "\"";
        }

        // exportInix: walk the current recordset and write rows to an
        // .inix file in list-of-records form. Each record becomes a
        // [RecordNNN] section; NULL values are omitted (no "key=" line
        // at all rather than an empty value). The encoding is UTF-8
        // with BOM and CRLF line endings, matching DbDo's text-file
        // conventions. Inix's leading-zero width on the section name
        // is chosen so ASCII sort of section names matches numeric
        // order across the file.
        //
        // The exported file can be read back by an .inix-aware tool
        // or by DbDo's Import Data command. It is also readable as
        // plain text in any editor -- the design goal of the format.
        private void exportInix(string sDestPath)
        {
            object bookmarkObj = bookmark;
            List<string> lFields = getFieldNames();
            List<Dictionary<string, string>> lRows = new List<Dictionary<string, string>>();
            moveFirst();
            while (!eof)
            {
                Dictionary<string, string> dRow = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
                foreach (string sN in lFields)
                {
                    string sV = getFieldValue(sN);
                    if (sV != null) dRow[sN] = sV;
                }
                lRows.Add(dRow);
                moveNext();
            }
            InixCodec.writeAsTable(sDestPath, lFields, lRows);
            if (bookmarkObj != null) bookmark = bookmarkObj;
        }

        // importInix: read an .inix file (list-of-records form or
        // [RecordNNN] form) and insert each section as a row in the
        // current table. Keys that don't match any column on the
        // target table are silently skipped (matching importMarkdown's
        // tolerance). Returns the number of rows successfully inserted.
        public int importInix(string sSourcePath)
        {
            if (!hasRecordset()) throw new InvalidOperationException("No recordset open. Use Open-Database first.");
            if (string.IsNullOrEmpty(sSourcePath)) throw new ArgumentException("importInix requires a path.");
            if (!File.Exists(sSourcePath)) throw new FileNotFoundException(".inix file not found.", sSourcePath);
            if (readOnly) throw new InvalidOperationException("The database was opened read-only. Close it and reopen without the -readonly flag to enable editing.");

            List<InixCodec.Section> lSections = InixCodec.read(sSourcePath);

            // Map case-insensitively to destination column names.
            List<string> lAllDest = getFieldNames();
            HashSet<string> hDest = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
            foreach (string sN in lAllDest) hDest.Add(sN);

            int iInserted = 0;
            foreach (InixCodec.Section sec in lSections)
            {
                if (sec == null || sec.Pairs.Count == 0) continue;
                // Skip the implicit Global section if it appears in
                // an otherwise table-shaped file -- it's almost
                // certainly a header for the document, not a row.
                if (string.Equals(sec.Name, "Global", StringComparison.OrdinalIgnoreCase) && lSections.Count > 1) continue;

                try
                {
                    oRecordset.AddNew();
                    foreach (InixCodec.Pair p in sec.Pairs)
                    {
                        if (!hDest.Contains(p.Key)) continue;
                        try { oRecordset.Fields[p.Key].Value = p.Value; }
                        catch { /* skip un-settable cells */ }
                    }
                    oRecordset.Update();
                    iInserted++;
                }
                catch
                {
                    try { oRecordset.CancelUpdate(); } catch { }
                }
            }
            return iInserted;
        }

        // importWithTransferMap: import records from an external SOURCE
        // file into the current table, renaming and transforming fields
        // through a transfer map held in an .inix file. The chosen
        // section holds one mapping per line:
        //
        //     destField = sourceField [ ; jscript-expression ]
        //
        // where $v is the source field's value and $<name> any other
        // source field in the same row. A repeated destField
        // concatenates (so two lines targeting extra_info join their
        // results). A directive line "@table = <name>" names the table
        // to read inside the source file; it defaults to the source
        // file's base name (right for a single-table dBASE file like
        // cts.dbf). An empty source value is skipped, leaving the
        // destination column at its default -- matching the legacy
        // DbDialog transfer semantics this revives. Modeled on
        // importJson's per-row AddNew/Update, so one bad row never sinks
        // the batch. Supported source formats: .dbf, .mdb/.accdb, and
        // .db/.sqlite/.sqlite3. Returns the number of rows added.
        public int importWithTransferMap(string sSourcePath, string sInixPath, string sSection)
        {
            if (!hasRecordset()) throw new InvalidOperationException("No recordset open. Use Open-Database first.");
            if (readOnly) throw new InvalidOperationException("The database was opened read-only. Close it and reopen without the -readonly flag to enable editing.");
            if (string.IsNullOrEmpty(sSourcePath) || !File.Exists(sSourcePath))
                throw new FileNotFoundException("Source file not found.", sSourcePath);
            if (string.IsNullOrEmpty(sInixPath) || !File.Exists(sInixPath))
                throw new FileNotFoundException("Transfer map (.inix) not found.", sInixPath);

            // Find the chosen mapping section.
            InixCodec.Section sec = null;
            foreach (InixCodec.Section s in InixCodec.read(sInixPath))
                if (string.Equals(s.Name, sSection, StringComparison.OrdinalIgnoreCase)) { sec = s; break; }
            if (sec == null) throw new Exception("The transfer map has no section named [" + sSection + "].");

            // Build the ordered mapping; pick up the @table directive.
            List<string[]> lMap = new List<string[]>();   // {destField, sourceField, expr}
            string sSourceTable = null;
            foreach (InixCodec.Pair p in sec.Pairs)
            {
                if (p.Key.StartsWith("@"))
                {
                    if (string.Equals(p.Key.Substring(1).Trim(), "table", StringComparison.OrdinalIgnoreCase))
                        sSourceTable = (p.Value ?? "").Trim();
                    continue;
                }
                string sSrc = p.Value ?? "";
                string sExpr = "";
                int iSemi = sSrc.IndexOf(';');
                if (iSemi >= 0) { sExpr = sSrc.Substring(iSemi + 1).Trim(); sSrc = sSrc.Substring(0, iSemi); }
                lMap.Add(new string[] { p.Key.Trim(), sSrc.Trim(), sExpr });
            }
            if (lMap.Count == 0) throw new Exception("Section [" + sSection + "] has no field mappings.");
            if (string.IsNullOrEmpty(sSourceTable))
                sSourceTable = Path.GetFileNameWithoutExtension(sSourcePath);

            // Destination columns, matched case-insensitively.
            HashSet<string> hDest = new HashSet<string>(getFieldNames(), StringComparer.OrdinalIgnoreCase);

            string sExtSrc = Path.GetExtension(sSourcePath).TrimStart('.').ToLowerInvariant();
            string sConnect = buildConnectStringForExport(sSourcePath, sExtSrc, sSourceTable);

            dynamic oConnSrc = null;
            dynamic oRsSrc = null;
            int iInserted = 0;
            try
            {
                oConnSrc = createComObject("ADODB.Connection");
                oConnSrc.CursorLocation = AdoConstants.adUseClient;
                oConnSrc.Open(sConnect);
                oRsSrc = oConnSrc.Execute("SELECT * FROM " + sSourceTable);

                List<string> lSrcFields = new List<string>();
                int nF = (int)oRsSrc.Fields.Count;
                for (int i = 0; i < nF; i++) lSrcFields.Add((string)oRsSrc.Fields[i].Name);

                while (!(bool)oRsSrc.EOF)
                {
                    // Read the source row into a case-insensitive map.
                    Dictionary<string, string> dSrc = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
                    foreach (string sFn in lSrcFields)
                    {
                        object oVal = oRsSrc.Fields[sFn].Value;
                        dSrc[sFn] = (oVal == null || oVal is DBNull)
                            ? "" : Convert.ToString(oVal, System.Globalization.CultureInfo.InvariantCulture);
                    }

                    // Apply the mapping: skip empty sources, run any
                    // expression, and accumulate repeated dest fields.
                    Dictionary<string, string> dDest = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
                    foreach (string[] aMap in lMap)
                    {
                        string sDestF = aMap[0], sSrcF = aMap[1], sExpr = aMap[2];
                        if (!hDest.Contains(sDestF)) continue;
                        string sVal;
                        if (!dSrc.TryGetValue(sSrcF, out sVal)) sVal = "";
                        if (string.IsNullOrEmpty(sVal)) continue;
                        string sRes = string.IsNullOrEmpty(sExpr) ? sVal : JScriptExpr.eval(sExpr, sVal, dSrc);
                        string sPrev;
                        dDest[sDestF] = dDest.TryGetValue(sDestF, out sPrev) ? sPrev + sRes : sRes;
                    }
                    if (dDest.Count == 0) { oRsSrc.MoveNext(); continue; }

                    // Insert via ADO AddNew so column defaults fire.
                    try
                    {
                        oRecordset.AddNew();
                        foreach (KeyValuePair<string, string> kvp in dDest)
                        {
                            try { oRecordset.Fields[kvp.Key].Value = kvp.Value; }
                            catch { /* skip un-settable cells */ }
                        }
                        oRecordset.Update();
                        iInserted++;
                    }
                    catch
                    {
                        try { oRecordset.CancelUpdate(); } catch { }
                    }

                    oRsSrc.MoveNext();
                }
            }
            finally
            {
                try { if (oRsSrc != null) oRsSrc.Close(); } catch { }
                try { if (oConnSrc != null) oConnSrc.Close(); } catch { }
                releaseCom(oRsSrc);
                releaseCom(oConnSrc);
            }

            DbDoLog.write("importWithTransferMap: added " + iInserted + " row(s) from "
                + sSourcePath + " [" + sSection + "]");
            return iInserted;
        }

        // generateReport: render a report template (.inix section) over the
        // whole physical table (optionally scoped by @filter and ordered by
        // @sort / @group), and return the resulting Markdown. Bands are
        // header (once), detail (per record), separator (between records),
        // footer (once), plus group_header/group_footer when @group is set.
        // A report is reproducible: it does NOT depend on the current grid
        // filter or sort (that is Generate from Grid's job). The live cursor is
        // untouched. See ReportEngine for the per-line substitution rules.
        public string generateReport(string sInixPath, string sSection)
        {
            if (!hasRecordset()) throw new InvalidOperationException("No recordset open. Open a table first.");
            if (string.IsNullOrEmpty(sInixPath) || !File.Exists(sInixPath))
                throw new FileNotFoundException("Report template (.inix) not found.", sInixPath);

            InixCodec.Section sec = null;
            foreach (InixCodec.Section s in InixCodec.read(sInixPath))
                if (string.Equals(s.Name, sSection, StringComparison.OrdinalIgnoreCase)) { sec = s; break; }
            if (sec == null) throw new Exception("The report file has no section named [" + sSection + "].");

            string sWantTable = sec.get("@table");
            if (!string.IsNullOrEmpty(sWantTable) && !string.IsNullOrEmpty(sCurrentTable)
                && !string.Equals(sWantTable.Trim(), sCurrentTable, StringComparison.OrdinalIgnoreCase))
                throw new Exception("This report is for table '" + sWantTable.Trim()
                    + "'. Open that table first (the current table is '" + sCurrentTable + "').");

            string sHeader = sec.get("header");
            string sDetail = sec.get("detail");
            string sFooter = sec.get("footer");
            string sGroupHeader = sec.get("group_header");
            string sGroupFooter = sec.get("group_footer");
            string sSeparator = resolveSeparator(sec.get("separator"));

            // Optional single-level grouping. When set, the report is
            // sorted by the group field automatically (so it is never wrong
            // because the user forgot to sort), and the group_header /
            // group_footer bands fire as the key changes. With no @group a
            // report is exactly the flat header/detail/footer it was before.
            string sGroup = sec.get("@group");
            sGroup = string.IsNullOrEmpty(sGroup) ? null : sGroup.Trim();

            List<string> lFields = getFieldNames();
            if (sGroup != null)
            {
                bool bFound = false;
                foreach (string sFn in lFields)
                    if (string.Equals(sFn, sGroup, StringComparison.OrdinalIgnoreCase)) { bFound = true; break; }
                if (!bFound) throw new Exception("This report groups by '" + sGroup
                    + "', which is not a column of '" + sCurrentTable + "'.");
            }

            // Read the WHOLE physical table -- not the current filtered
            // grid view -- so a report is reproducible and independent of
            // whatever filter/sort the user happens to have on screen. This
            // is the deliberate contrast with Generate from Grid (Alt+Shift+G),
            // which acts on the virtual grid. Optional @filter (a SQL WHERE
            // fragment) and @sort (an ORDER BY fragment) let a report scope
            // and order itself. queryRowsSql runs on the shared connection
            // and never disturbs the live cursor.
            string sFilter = sec.get("@filter"); sFilter = string.IsNullOrEmpty(sFilter) ? null : sFilter.Trim();
            string sSort   = sec.get("@sort");   sSort   = string.IsNullOrEmpty(sSort) ? null : sSort.Trim();
            StringBuilder sbCols = new StringBuilder();
            foreach (string sFn in lFields)
            {
                if (sbCols.Length > 0) sbCols.Append(", ");
                sbCols.Append("\"").Append(sFn.Replace("\"", "\"\"")).Append("\"");
            }
            StringBuilder sbSql = new StringBuilder();
            sbSql.Append("SELECT ").Append(sbCols).Append(" FROM \"")
                 .Append(sCurrentTable.Replace("\"", "\"\"")).Append("\"");
            if (sFilter != null) sbSql.Append(" WHERE ").Append(sFilter);
            if (sSort != null) sbSql.Append(" ORDER BY ").Append(sSort);

            List<Dictionary<string, string>> lRows = new List<Dictionary<string, string>>();
            int iFound;
            List<string[]> lRaw = queryRowsSql(sbSql.ToString(), int.MaxValue, out iFound);
            foreach (string[] aRow in lRaw)
            {
                Dictionary<string, string> dRow = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
                for (int i = 0; i < lFields.Count; i++)
                    dRow[lFields[i]] = (i < aRow.Length && aRow[i] != null) ? aRow[i] : "";
                lRows.Add(dRow);
            }

            if (sGroup != null && lRows.Count > 1) stableSortByField(lRows, sGroup);

            Dictionary<string, string> dEmpty = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
            Dictionary<string, string> dGrand = computeAggregates(lRows, lFields);

            List<string> lBlocks = new List<string>();
            string sHd = ReportEngine.renderBand(sHeader, mergeDicts(dEmpty, dGrand));
            if (!string.IsNullOrEmpty(sHd)) lBlocks.Add(sHd);

            if (sGroup == null)
            {
                appendDetailBlocks(lBlocks, sDetail, lRows, sSeparator);
            }
            else
            {
                int i = 0;
                while (i < lRows.Count)
                {
                    string sKey; lRows[i].TryGetValue(sGroup, out sKey); sKey = sKey ?? "";
                    List<Dictionary<string, string>> lGroup = new List<Dictionary<string, string>>();
                    while (i < lRows.Count)
                    {
                        string sK2; lRows[i].TryGetValue(sGroup, out sK2); sK2 = sK2 ?? "";
                        if (!string.Equals(sK2, sKey, StringComparison.OrdinalIgnoreCase)) break;
                        lGroup.Add(lRows[i]); i++;
                    }
                    // Group context: the group's first row (for fields like
                    // the group key itself) overlaid with the group's totals.
                    Dictionary<string, string> dGroupCtx = mergeDicts(lGroup[0], computeAggregates(lGroup, lFields));
                    string sGh = ReportEngine.renderBand(sGroupHeader, dGroupCtx);
                    if (!string.IsNullOrEmpty(sGh)) lBlocks.Add(sGh);
                    appendDetailBlocks(lBlocks, sDetail, lGroup, sSeparator);
                    string sGf = ReportEngine.renderBand(sGroupFooter, dGroupCtx);
                    if (!string.IsNullOrEmpty(sGf)) lBlocks.Add(sGf);
                }
            }

            string sFt = ReportEngine.renderBand(sFooter, mergeDicts(dEmpty, dGrand));
            if (!string.IsNullOrEmpty(sFt)) lBlocks.Add(sFt);

            DbDoLog.write("generateReport: [" + sSection + "] over " + lRows.Count + " record(s)"
                + (sGroup == null ? "" : " grouped by " + sGroup));
            return string.Join("\r\n\r\n", lBlocks.ToArray()) + "\r\n";
        }

        // Render each row's detail band into a block and append to lBlocks,
        // inserting the separator between consecutive detail blocks.
        private void appendDetailBlocks(List<string> lBlocks, string sDetail,
            List<Dictionary<string, string>> lRows, string sSeparator)
        {
            List<string> lDetail = new List<string>();
            foreach (Dictionary<string, string> dRow in lRows)
            {
                string sBlock = ReportEngine.renderBand(sDetail, dRow);
                if (!string.IsNullOrEmpty(sBlock)) lDetail.Add(sBlock);
            }
            for (int i = 0; i < lDetail.Count; i++)
            {
                if (i > 0 && !string.IsNullOrEmpty(sSeparator)) lBlocks.Add(sSeparator);
                lBlocks.Add(lDetail[i]);
            }
        }

        // Overlay dExtra onto a copy of dBase (dExtra wins on conflict).
        private static Dictionary<string, string> mergeDicts(
            Dictionary<string, string> dBase, Dictionary<string, string> dExtra)
        {
            Dictionary<string, string> d = new Dictionary<string, string>(dBase, StringComparer.OrdinalIgnoreCase);
            foreach (KeyValuePair<string, string> kvp in dExtra) d[kvp.Key] = kvp.Value;
            return d;
        }

        // Stable in-place sort of rows by a field, case-insensitive, ties
        // broken by original position (so within a group the current order
        // is preserved).
        private static void stableSortByField(List<Dictionary<string, string>> lRows, string sField)
        {
            List<KeyValuePair<int, Dictionary<string, string>>> lIdx =
                new List<KeyValuePair<int, Dictionary<string, string>>>();
            for (int i = 0; i < lRows.Count; i++)
                lIdx.Add(new KeyValuePair<int, Dictionary<string, string>>(i, lRows[i]));
            lIdx.Sort(delegate(KeyValuePair<int, Dictionary<string, string>> a,
                               KeyValuePair<int, Dictionary<string, string>> b)
            {
                string ka; a.Value.TryGetValue(sField, out ka); ka = ka ?? "";
                string kb; b.Value.TryGetValue(sField, out kb); kb = kb ?? "";
                int c = string.Compare(ka, kb, StringComparison.OrdinalIgnoreCase);
                return (c != 0) ? c : a.Key.CompareTo(b.Key);
            });
            lRows.Clear();
            foreach (KeyValuePair<int, Dictionary<string, string>> kv in lIdx) lRows.Add(kv.Value);
        }

        // Compute aggregate pseudo-fields over a set of rows: $count, and
        // for every field $sum_/$avg_/$min_/$max_ over the values that parse
        // as numbers (blanks and non-numbers ignored). These become ordinary
        // $-fields in the header/footer and group_header/group_footer bands.
        private static Dictionary<string, string> computeAggregates(
            List<Dictionary<string, string>> lRows, List<string> lFields)
        {
            Dictionary<string, string> d = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
            d["count"] = lRows.Count.ToString(System.Globalization.CultureInfo.InvariantCulture);
            foreach (string sField in lFields)
            {
                double dSum = 0, dMin = 0, dMax = 0;
                int n = 0;
                foreach (Dictionary<string, string> dRow in lRows)
                {
                    string sVal; double v;
                    if (dRow.TryGetValue(sField, out sVal) && tryParseNumber(sVal, out v))
                    {
                        if (n == 0) { dMin = v; dMax = v; }
                        else { if (v < dMin) dMin = v; if (v > dMax) dMax = v; }
                        dSum += v; n++;
                    }
                }
                d["sum_" + sField] = formatNumber(dSum);
                d["avg_" + sField] = (n > 0) ? formatNumber(dSum / n) : "";
                d["min_" + sField] = (n > 0) ? formatNumber(dMin) : "";
                d["max_" + sField] = (n > 0) ? formatNumber(dMax) : "";
            }
            return d;
        }

        private static bool tryParseNumber(string s, out double v)
        {
            v = 0;
            if (string.IsNullOrEmpty(s)) return false;
            string t = s.Trim().Replace(",", "");
            if (t.Length > 0 && (t[0] == '$' || t[0] == '\u00A3' || t[0] == '\u20AC')) t = t.Substring(1);
            return double.TryParse(t, System.Globalization.NumberStyles.Number,
                System.Globalization.CultureInfo.InvariantCulture, out v);
        }

        private static string formatNumber(double v)
        {
            return v.ToString("0.######", System.Globalization.CultureInfo.InvariantCulture);
        }

        // Resolve a separator value: a keyword maps to its Markdown/text,
        // anything else is treated as literal separator text; null means
        // no separator was specified.
        private static string resolveSeparator(string sRaw)
        {
            if (sRaw == null) return null;
            string sKey = sRaw.Trim().ToLowerInvariant();
            if (sKey == "blank") return "";       // rely on the inter-block blank line
            if (sKey == "rule") return "---";     // Markdown thematic break
            if (sKey == "page") return "\f";      // form feed (plain-text page break)
            return sRaw;                          // literal separator text
        }

        private void exportHtml(string sDestPath)
        {
            object bookmarkObj = bookmark;
            List<string> lFields = getFieldNames();
            using (StreamWriter writer2 = new StreamWriter(sDestPath, false, new UTF8Encoding(true)))
            {
                writer2.WriteLine("<!DOCTYPE html>");
                writer2.WriteLine("<html lang=\"en\"><head><meta charset=\"utf-8\"><title>" + htmlEscape(sCurrentTable) + "</title></head>");
                writer2.WriteLine("<body>");
                writer2.WriteLine("<h1>" + htmlEscape(sCurrentTable) + "</h1>");
                writer2.WriteLine("<table border=\"1\">");
                writer2.WriteLine("<caption>" + htmlEscape(sCurrentTable) + "</caption>");
                writer2.Write("<thead><tr>");
                foreach (string sN in lFields) writer2.Write("<th scope=\"col\">" + htmlEscape(sN) + "</th>");
                writer2.WriteLine("</tr></thead>");
                writer2.WriteLine("<tbody>");
                moveFirst();
                while (!eof)
                {
                    writer2.Write("<tr>");
                    foreach (string sN in lFields) writer2.Write("<td>" + htmlEscape(getFieldValue(sN)) + "</td>");
                    writer2.WriteLine("</tr>");
                    moveNext();
                }
                writer2.WriteLine("</tbody></table></body></html>");
            }
            if (bookmarkObj != null) bookmark = bookmarkObj;
        }

        private static string htmlEscape(string s)
        {
            if (s == null) return "";
            return s.Replace("&", "&amp;").Replace("<", "&lt;").Replace(">", "&gt;")
                    .Replace("\"", "&quot;").Replace("'", "&#39;");
        }

        // =====================================================================
        // saveAs: copy the entire database to a new file. For SQLite
        // we use the SQLite ODBC driver's BACKUP support (PRAGMA-based)
        // or fall back to a plain file copy when the database is not
        // currently being written. For the others, the simplest
        // correct approach is a file copy after closing the connection.
        //
        // Edge case: if the destination has a different extension
        // (e.g., copying foo.db to foo.csv), we route to exportData
        // for the current table only. Save-As semantics for "the
        // whole database" only make sense within the same format.
        // =====================================================================
        public void saveAs(string sDestPath)
        {
            if (!isOpen()) throw new InvalidOperationException("No database open.");
            if (string.IsNullOrEmpty(sDestPath)) throw new ArgumentException("saveAs requires a path.");

            // Refuse to copy the open database over itself. The same-
            // format path below closes the connection and copies the
            // file onto its own path, then reopens -- but the SQLite
            // ODBC handle (kept briefly by connection pooling even after
            // Close) still holds the file, so the copy stalls on the
            // lock rather than erroring cleanly. That is the reported
            // "I hit Yes to replace and it stopped responding." Fail
            // fast and clearly instead.
            try
            {
                if (string.Equals(Path.GetFullPath(sDestPath), Path.GetFullPath(sFilePath),
                                  StringComparison.OrdinalIgnoreCase))
                    throw new IOException("The destination is the database that is already open. "
                        + "Choose a different file name for the copy.");
            }
            catch (IOException) { throw; }
            catch { /* path normalization failed; fall through to the normal save */ }

            string sSrcExt = Path.GetExtension(sFilePath).TrimStart('.').ToLowerInvariant();
            string sDstExt = Path.GetExtension(sDestPath).TrimStart('.').ToLowerInvariant();

            if (sSrcExt != sDstExt)
            {
                // Cross-format save-as falls through to export of
                // current table.
                exportData(sDestPath);
                return;
            }

            // Same-format save-as is a file copy. We close the
            // connection first to release file locks.
            string sOriginalPath = sFilePath;
            string sOriginalTable = sCurrentTable;
            bool bOriginalReadOnly = bReadOnly;
            close();
            try
            {
                File.Copy(sOriginalPath, sDestPath, true);
            }
            catch (Exception ex)
            {
                // Re-open original on failure.
                openDatabase(sOriginalPath, sOriginalTable, bOriginalReadOnly);
                throw new Exception("Save-As failed: " + ex.Message, ex);
            }
            // Re-open the *original* file after the copy. The user is
            // making a backup, not switching to it.
            openDatabase(sOriginalPath, sOriginalTable, bOriginalReadOnly);
        }

        // =====================================================================
        // measureField: per-column statistics. Implements dbDot's
        // longest/shortest/min/max plus standard count/sum/avg.
        // Returns a structured result the CLI and GUI both render.
        // =====================================================================
        public class FieldStatistic
        {
            public string fieldName;
            public string statistic;
            public string value;
            public int recordPosition;  // 1-based; the row where the extreme was found, where applicable
        }

        public FieldStatistic measureField(string sField, string sStatistic)
        {
            if (!hasRecordset()) throw new InvalidOperationException("No recordset open.");
            if (string.IsNullOrEmpty(sField)) throw new ArgumentException("measureField requires a field name.");

            string sStat = (sStatistic ?? "count").ToLowerInvariant();
            FieldStatistic result = new FieldStatistic { fieldName = sField, statistic = sStat };

            object bookmarkObj = bookmark;
            try
            {
                moveFirst();
                if (eof) { result.value = "blank"; return result; }

                switch (sStat)
                {
                    case "count":
                        result.value = recordCount.ToString();
                        return result;
                    case "longest":
                    case "shortest":
                        measureLength(sField, sStat == "longest", result);
                        return result;
                    case "min":
                    case "max":
                        measureMinMax(sField, sStat == "max", result);
                        return result;
                    case "sum":
                    case "avg":
                    case "average":
                        measureSumAvg(sField, sStat == "sum", result);
                        return result;
                    case "median":
                    case "stddev":
                    case "stddev_pop":
                    case "variance":
                    case "var_pop":
                    case "percentile_25":
                    case "percentile_75":
                    case "percentile_90":
                    case "percentile_95":
                        measureSqlAggregate(sField, sStat, result);
                        return result;
                    default:
                        throw new ArgumentException("Unknown statistic: " + sStat
                            + ". Use count, longest, shortest, min, max, sum, avg, median, "
                            + "stddev, stddev_pop, variance, var_pop, or percentile_25/75/90/95.");
                }
            }
            finally
            {
                if (bookmarkObj != null) bookmark = bookmarkObj;
            }
        }

        // measureSqlAggregate: median / standard deviation / variance /
        // percentiles via SQLean's stats functions, computed in SQL over
        // the current view's source -- the table itself, or the custom
        // query's SELECT wrapped as a subquery. The function name is one
        // of the whitelisted switch cases above (never user text), so it
        // is injection-safe; the field name is double-quoted. These need
        // sqlean.dll, which DbDo auto-loads when it sits beside the
        // executable; if absent, the probe error is surfaced as the value
        // rather than thrown.
        private void measureSqlAggregate(string sField, string sFn, FieldStatistic result)
        {
            string sFrom = string.IsNullOrEmpty(sSourceSql)
                ? "\"" + (sCurrentTable ?? "").Replace("\"", "\"\"") + "\""
                : "(" + sSourceSql + ")";
            string sSql = "SELECT " + sFn + "(\"" + sField.Replace("\"", "\"\"") + "\") FROM " + sFrom;
            string sErr;
            string sVal = probeScalar(sSql, out sErr);
            result.value = (sErr.Length > 0)
                ? "unavailable (needs sqlean.dll): " + sErr
                : (sVal ?? "(null)");
        }

        private void measureLength(string sField, bool bLongest, FieldStatistic result)
        {
            int iExtreme = bLongest ? -1 : int.MaxValue;
            string sExtreme = "";
            int iPos = 1;
            int iAt = 1;
            moveFirst();
            while (!eof)
            {
                string sValue = getFieldValue(sField);
                int iLen = sValue.Length;
                if ((bLongest && iLen > iExtreme) || (!bLongest && iLen < iExtreme))
                {
                    iExtreme = iLen; sExtreme = sValue; iAt = iPos;
                }
                iPos++;
                moveNext();
            }
            result.value = string.Format("{0} chars: {1}", iExtreme, sExtreme);
            result.recordPosition = iAt;
        }

        private void measureMinMax(string sField, bool bMax, FieldStatistic result)
        {
            // Use ADODB to compare via the field's native type. We
            // collect all values and let .NET's IComparable do the
            // work, since string comparison and numeric comparison
            // disagree (strings sort "100" before "9"). The recordset
            // gives us the typed value through Field.Value.
            object extreme = null;
            int iAt = 1;
            int iPos = 1;
            moveFirst();
            while (!eof)
            {
                object fieldValue = null;
                try { fieldValue = oRecordset.Fields[sField].Value; } catch { }
                if (fieldValue != null && !(fieldValue is DBNull))
                {
                    if (extreme == null) { extreme = fieldValue; iAt = iPos; }
                    else
                    {
                        IComparable cmp = extreme as IComparable;
                        if (cmp != null)
                        {
                            int iCmp = 0;
                            try { iCmp = cmp.CompareTo(fieldValue); } catch { }
                            if ((bMax && iCmp < 0) || (!bMax && iCmp > 0))
                            {
                                extreme = fieldValue; iAt = iPos;
                            }
                        }
                    }
                }
                iPos++;
                moveNext();
            }
            result.value = (extreme == null) ? "(no values)" : extreme.ToString();
            result.recordPosition = iAt;
        }

        private void measureSumAvg(string sField, bool bSum, FieldStatistic result)
        {
            double dSum = 0.0;
            int iCount = 0;
            moveFirst();
            while (!eof)
            {
                object fieldValue = null;
                try { fieldValue = oRecordset.Fields[sField].Value; } catch { }
                if (fieldValue != null && !(fieldValue is DBNull))
                {
                    double dV;
                    if (double.TryParse(fieldValue.ToString(), out dV))
                    {
                        dSum += dV; iCount++;
                    }
                }
                moveNext();
            }
            if (iCount == 0) { result.value = "(no numeric values)"; return; }
            double dResult = bSum ? dSum : (dSum / iCount);
            result.value = dResult.ToString("G");
        }

        // =====================================================================
        // COM helpers. createComObject is the late-bound creation
        // entry point; releaseCom releases the underlying RCW so we
        // don't hold COM objects past their natural lifetime.
        //
        // releaseCom takes a plain object (not ref); caller assigns
        // null after the call. We avoid ref-with-dynamic because
        // late-bound dispatch and ref parameters interact poorly:
        // the static type 'dynamic' doesn't satisfy a 'ref T' generic
        // constraint cleanly under C# overload resolution.
        // =====================================================================
        private static dynamic createComObject(string sProgId)
        {
            Type comType = Type.GetTypeFromProgID(sProgId);
            if (comType == null)
                throw new Exception("COM ProgID not registered: " + sProgId);
            return Activator.CreateInstance(comType);
        }

        private static void releaseCom(object target)
        {
            if (target == null) return;
            try
            {
                if (Marshal.IsComObject(target))
                    Marshal.FinalReleaseComObject(target);
            }
            catch { }
        }
    }

    // INSERTION POINT FOR SUPPORT CLASSES, FORM, CLI, AND PROGRAM

    // =====================================================================
    // KeyMap: central Dictionary<Keys, ToolStripMenuItem> dispatch table.
    //
    // Every menu item registers
    // its preferred Keys value with KeyMap. The form's ProcessCmdKey
    // override consults this dictionary to dispatch a keystroke to the
    // matching menu item, bypassing ToolStripMenuItem.ShortcutKeys
    // validation. This means we can bind keystrokes the framework
    // otherwise rejects (plain Enter, plain Insert, plain Delete, Tab,
    // Escape, Alt+F4, Backspace, Space) while still showing them in
    // the menu via ShortcutKeyDisplayString.
    //
    // db.ini's [Keys] section can override any binding by command name.
    // Conflicts and parse-failures collect into lConflicts and surface
    // in a single startup dialog.
    // =====================================================================
    public static class KeyMap
    {
        public static Dictionary<Keys, ToolStripMenuItem> dKeyToMenu =
            new Dictionary<Keys, ToolStripMenuItem>();
        public static Dictionary<string, Keys> dCommandToKey =
            new Dictionary<string, Keys>();
        public static Dictionary<ToolStripMenuItem, string> dMenuToCommand =
            new Dictionary<ToolStripMenuItem, string>();
        // dCommandToSummary: one-line summary per canonical verb,
        // verb-first plain text. Used by the menu status bar (when the
        // item has focus), by Alt+F10 Alternate Menu (inline after the
        // chord), and by Control+F1 Key Help (on its own line).
        // dCommandToDescription: optional multi-line description used
        // in the Alternate Menu's detail pane. (Key Help itself
        // uses only the one-line summary -- a longer description would
        // be too verbose for a screen-reader announcement, so the
        // detail pane is the canonical surface for the long form.)
        public static Dictionary<string, string> dCommandToSummary =
            new Dictionary<string, string>();
        public static Dictionary<string, string> dCommandToDescription =
            new Dictionary<string, string>();
        // dCommandToContext: the parent/child context in which a command's
        // chord is live -- e.g. "Grid" (the main records window), "Cell
        // Editor" (the in-place field editor), or a dialog name. A command
        // with no entry is treated as "Global" (active wherever its menu
        // is). This is the authoritative answer to "where does this chord
        // apply", surfaced by the menu, Alt+F10, and Ctrl+F1 Key Help so a
        // chord that does different things in different contexts can be
        // documented once per context rather than guessed at.
        public static Dictionary<string, string> dCommandToContext =
            new Dictionary<string, string>();
        public static List<string> lConflicts = new List<string>();

        // KeyBinding: one row of the authoritative key-binding table -- a
        // command, the context its chord is live in ("Global" when
        // unscoped), its short summary and long description, and the chord
        // itself (Keys.None when the command is unbound). Each command sits
        // in a single context; a command carrying two chords simply yields
        // two rows. This typed list is the one structured surface the rest
        // of DbDo reads from, and projects cleanly to the [Hotkeys] text,
        // a TSV table, or a DbDo table for the user.
        public class KeyBinding
        {
            public Keys   keyData;        // Keys.None == unbound
            public string sCommand;
            public string sContext;
            public string sDescription;
            public string sSummary;
            public KeyBinding(string sContextIn, string sCommandIn, string sSummaryIn,
                              string sDescriptionIn, Keys keyDataIn)
            {
                keyData = keyDataIn;
                sCommand = sCommandIn;
                sContext = string.IsNullOrEmpty(sContextIn) ? "Global" : sContextIn;
                sDescription = sDescriptionIn ?? "";
                sSummary = sSummaryIn ?? "";
            }
            public bool bUnbound { get { return keyData == Keys.None; } }
        }

        // lExtraBindings: bindings that do NOT come from a menu item --
        // chords live only inside the listview grid, an LbcTextBox cell
        // editor, or an LbcDialog. The menu-derived table can't see these,
        // so they are registered here (via addBinding) and merged in by
        // bindings(). Left empty until those contexts are catalogued.
        public static List<KeyBinding> lExtraBindings = new List<KeyBinding>();

        // Key Help mode. When true, hotkeys are intercepted and
        // their (command, chord, description) triple is announced via
        // the live region instead of executing the command. The user
        // toggles this via Ctrl+F1 (Help > Key Help) or the dot-
        // prompt verb Toggle-KeyHelp.
        public static bool bKeyDescriber = false;

        public static void register(Keys key, ToolStripMenuItem mi, string sCommand)
        {
            // Record the command for every item on every window's menu, so
            // per-form dispatch and the help/summary lookups can resolve a
            // command name from any window's item (not only the first one
            // built). In MDI each window builds its own menu.
            dMenuToCommand[mi] = sCommand;
            if (key == Keys.None) return;
            if (dKeyToMenu.ContainsKey(key))
            {
                // The SAME command re-registering the SAME key from another
                // window is expected, not a conflict; only a DIFFERENT
                // command on an already-bound key is a real clash. Either
                // way, still set this item's display so the chord shows and
                // is announced in this window's menu too.
                string sExisting = dMenuToCommand.ContainsKey(dKeyToMenu[key]) ? dMenuToCommand[dKeyToMenu[key]] : "(unknown)";
                if (sExisting != sCommand)
                    lConflicts.Add(string.Format("{0} already bound to '{1}'; cannot rebind to '{2}'",
                        friendlyKey(key), sExisting, sCommand));
                applyChordDisplay(mi, key);
                return;
            }
            dKeyToMenu[key] = mi;
            dCommandToKey[sCommand] = key;
            applyChordDisplay(mi, key);
        }

        // applyChordDisplay: set a menu item's visible shortcut text and
        // its screen-reader accessible name to include the chord.
        private static void applyChordDisplay(ToolStripMenuItem mi, Keys key)
        {
            mi.ShortcutKeyDisplayString = friendlyKey(key);
            string sBase = mi.Text.Replace("&", "");
            if (sBase.EndsWith("...")) sBase = sBase.Substring(0, sBase.Length - 3).TrimEnd();
            mi.AccessibleName = sBase + "   " + friendlyKey(key);
        }

        // summaryFor: lookup the one-line summary for a canonical
        // verb. Falls back to the menu label (minus ampersand mnemonic
        // markers and trailing "...") when no explicit summary is
        // registered. Always returns a non-empty string so callers
        // never need to null-check.
        // normalizeCommandKey: collapse "Edit-Settings", "Edit Settings",
        // "edit-settings", "edit settings" all to a single canonical
        // lookup key. Used by summaryFor and descriptionFor so that
        // older documentation, scripts, or muscle memory using the
        // hyphenated form (the v1.0.91 and earlier canonical form)
        // keeps finding help for the same commands renamed in v1.0.92
        // to Title Case With Spaces.
        private static string normalizeCommandKey(string s)
        {
            if (string.IsNullOrEmpty(s)) return "";
            return s.Replace("-", " ").Replace("_", " ").Trim().ToLowerInvariant();
        }

        public static string summaryFor(string sCommand)
        {
            if (string.IsNullOrEmpty(sCommand)) return "";
            if (dCommandToSummary.ContainsKey(sCommand))
            {
                string s = dCommandToSummary[sCommand];
                if (!string.IsNullOrEmpty(s)) return s;
            }
            // v1.0.92: also try a normalized lookup so the historical
            // hyphenated form ("Edit-Settings") finds the same entry
            // as the Title-Case-with-spaces form ("Edit Settings").
            string sNorm = normalizeCommandKey(sCommand);
            foreach (KeyValuePair<string, string> kv in dCommandToSummary)
            {
                if (normalizeCommandKey(kv.Key) == sNorm && !string.IsNullOrEmpty(kv.Value))
                    return kv.Value;
            }
            // Fallback to the menu label.
            foreach (KeyValuePair<ToolStripMenuItem, string> kv in dMenuToCommand)
            {
                if (kv.Value == sCommand || normalizeCommandKey(kv.Value) == sNorm)
                {
                    string sLbl = kv.Key.Text.Replace("&", "");
                    if (sLbl.EndsWith("...")) sLbl = sLbl.Substring(0, sLbl.Length - 3).TrimEnd();
                    return sLbl;
                }
            }
            return sCommand;
        }

        // descriptionFor: lookup the optional multi-line description.
        // Returns "" when none is registered (callers should treat
        // an empty description as "no extra detail beyond the
        // summary").
        public static string descriptionFor(string sCommand)
        {
            if (string.IsNullOrEmpty(sCommand)) return "";
            if (dCommandToDescription.ContainsKey(sCommand))
                return dCommandToDescription[sCommand];
            // v1.0.92: also try a normalized lookup -- see summaryFor.
            string sNorm = normalizeCommandKey(sCommand);
            foreach (KeyValuePair<string, string> kv in dCommandToDescription)
            {
                if (normalizeCommandKey(kv.Key) == sNorm)
                    return kv.Value;
            }
            return "";
        }

        // contextFor: the parent/child context a command's chord is live
        // in. Returns "Global" when no narrower context is registered, so
        // callers never null-check and an unannotated command reads as
        // "works everywhere its menu does". Mirrors summaryFor/descriptionFor
        // including the normalized-key fallback for historical command forms.
        public static string contextFor(string sCommand)
        {
            if (string.IsNullOrEmpty(sCommand)) return "Global";
            if (dCommandToContext.ContainsKey(sCommand))
            {
                string s = dCommandToContext[sCommand];
                if (!string.IsNullOrEmpty(s)) return s;
            }
            string sNormC = normalizeCommandKey(sCommand);
            foreach (KeyValuePair<string, string> kv in dCommandToContext)
            {
                if (normalizeCommandKey(kv.Key) == sNormC && !string.IsNullOrEmpty(kv.Value))
                    return kv.Value;
            }
            return "Global";
        }

        // addBinding: record a non-menu binding (grid, cell editor, or
        // dialog chord) so it appears in the table alongside the menu
        // commands. Also feeds the summary/description/context dictionaries
        // so Key Help, the status line, and contextFor see it too. Pass
        // Keys.None for a command documented but not yet bound.
        public static void addBinding(string sContext, string sCommand, string sSummary,
                                      string sDescription, Keys keyData)
        {
            if (string.IsNullOrEmpty(sCommand)) return;
            if (!string.IsNullOrEmpty(sSummary)) dCommandToSummary[sCommand] = sSummary;
            if (!string.IsNullOrEmpty(sDescription)) dCommandToDescription[sCommand] = sDescription;
            if (!string.IsNullOrEmpty(sContext)) dCommandToContext[sCommand] = sContext;
            lExtraBindings.Add(new KeyBinding(sContext, sCommand, sSummary, sDescription, keyData));
        }

        // bindings: build the authoritative table fresh each call -- one
        // row per menu command (taken from the live dictionaries, so .ini
        // overrides are always reflected) plus the registered non-menu
        // rows. Building on demand keeps the table from going stale; it is
        // small enough that the cost is irrelevant.
        public static List<KeyBinding> bindings()
        {
            List<KeyBinding> l = new List<KeyBinding>();
            SortedSet<string> setCommands = new SortedSet<string>(StringComparer.OrdinalIgnoreCase);
            foreach (string sCmd in dCommandToSummary.Keys) setCommands.Add(sCmd);
            foreach (string sCmd in dCommandToKey.Keys) setCommands.Add(sCmd);
            foreach (KeyValuePair<ToolStripMenuItem, string> kv in dMenuToCommand) setCommands.Add(kv.Value);
            foreach (string sCmd in setCommands)
            {
                Keys key;
                if (!dCommandToKey.TryGetValue(sCmd, out key)) key = Keys.None;
                l.Add(new KeyBinding(contextFor(sCmd), sCmd, summaryFor(sCmd), descriptionFor(sCmd), key));
            }
            foreach (KeyBinding kb in lExtraBindings) l.Add(kb);
            return l;
        }

        // bindingTable: the table as tab-separated rows with a header --
        // Context, Command, Key, Summary, Description -- sorted by context
        // then command. A user-facing projection: copy into a spreadsheet
        // or open as a DbDo table. Tabs and newlines inside the text fields
        // are flattened to spaces so the TSV stays one row per binding.
        public static string bindingTable()
        {
            List<KeyBinding> l = bindings();
            l.Sort(delegate (KeyBinding a, KeyBinding b)
            {
                int c = string.Compare(a.sContext, b.sContext, StringComparison.OrdinalIgnoreCase);
                return c != 0 ? c : string.Compare(a.sCommand, b.sCommand, StringComparison.OrdinalIgnoreCase);
            });
            StringBuilder sb = new StringBuilder();
            sb.AppendLine("Context\tCommand\tKey\tSummary\tDescription");
            foreach (KeyBinding kb in l)
            {
                sb.Append(kb.sContext).Append('\t');
                sb.Append(kb.sCommand).Append('\t');
                sb.Append(kb.bUnbound ? "" : friendlyKey(kb.keyData)).Append('\t');
                sb.Append(flattenCell(kb.sSummary)).Append('\t');
                sb.AppendLine(flattenCell(kb.sDescription));
            }
            return sb.ToString();
        }

        // flattenCell: collapse tabs and newlines to single spaces so a
        // text field cannot break the one-row-per-binding TSV layout.
        private static string flattenCell(string s)
        {
            if (string.IsNullOrEmpty(s)) return "";
            return s.Replace('\t', ' ').Replace('\r', ' ').Replace('\n', ' ').Trim();
        }

        // registerDisplayOnly: show a chord in the menu UI without
        // routing it through the form-level dispatcher. Use this for
        // hotkeys that are dispatched locally by a specific control
        // (the data grid's KeyDown handler in DbDo's case), so the
        // chord only fires when that control has focus. The menu
        // text and AccessibleName carry the chord exactly as
        // register() would, so JAWS still announces "Shift+F" along
        // with the menu item.
        //
        // This drives the Shift+D /
        // Shift+L / Shift+S shortcuts: the menu shows the chord,
        // but the listbox's own KeyDown handler is what actually
        // recognizes the keystroke. Form-level ProcessCmdKey never
        // sees the chord, so capital letters typed in text boxes
        // and dialogs are not intercepted.
        public static void registerDisplayOnly(Keys key, ToolStripMenuItem mi, string sCommand)
        {
            dMenuToCommand[mi] = sCommand;
            if (key == Keys.None) return;
            // Record the command->key mapping so help screens and
            // the chord-summary table can find this binding, but
            // DON'T add to dKeyToMenu (form-level dispatch table).
            dCommandToKey[sCommand] = key;
            mi.ShortcutKeyDisplayString = friendlyKey(key);
            string sBase = mi.Text.Replace("&", "");
            if (sBase.EndsWith("...")) sBase = sBase.Substring(0, sBase.Length - 3).TrimEnd();
            mi.AccessibleName = sBase + "   " + friendlyKey(key);
        }

        // registerAlias: bind a SECONDARY key to a command that already
        // has a primary binding. Use this when a command has more than
        // one natural keystroke (e.g., Get-Property naturally responds
        // to both Alt+Enter as the Windows-standard "properties" key
        // and Shift+F6 as the "go to contents" key).
        //
        // The primary binding keeps its menu shortcut display; the
        // alias is only routed through tryDispatch and does not appear
        // in the menu.
        public static void registerAlias(Keys key, ToolStripMenuItem mi)
        {
            if (key == Keys.None) return;
            if (dKeyToMenu.ContainsKey(key))
            {
                string sExisting = dMenuToCommand.ContainsKey(dKeyToMenu[key]) ? dMenuToCommand[dKeyToMenu[key]] : "(unknown)";
                lConflicts.Add(string.Format("{0} already bound to '{1}'; cannot register as alias",
                    friendlyKey(key), sExisting));
                return;
            }
            dKeyToMenu[key] = mi;
        }

        public static bool overrideKey(string sCommand, string sKeyText)
        {
            ToolStripMenuItem mi = null;
            foreach (KeyValuePair<ToolStripMenuItem, string> kv in dMenuToCommand)
            {
                if (kv.Value == sCommand) { mi = kv.Key; break; }
            }
            if (mi == null) return false;

            if (dCommandToKey.ContainsKey(sCommand))
            {
                Keys keyOld = dCommandToKey[sCommand];
                dKeyToMenu.Remove(keyOld);
                dCommandToKey.Remove(sCommand);
            }

            string sTrim = sKeyText.Trim();
            if (sTrim.Length == 0 || sTrim.Equals("None", StringComparison.OrdinalIgnoreCase))
            {
                mi.ShortcutKeyDisplayString = "";
                return true;
            }

            Keys key;
            try
            {
                key = (Keys)System.ComponentModel.TypeDescriptor
                    .GetConverter(typeof(Keys))
                    .ConvertFromString(sTrim);
            }
            catch
            {
                lConflicts.Add(string.Format("Could not parse key '{0}' for '{1}'", sKeyText, sCommand));
                return false;
            }

            if (dKeyToMenu.ContainsKey(key))
            {
                string sExisting = dMenuToCommand[dKeyToMenu[key]];
                lConflicts.Add(string.Format("{0} already bound to '{1}'; cannot rebind to '{2}'",
                    friendlyKey(key), sExisting, sCommand));
                return false;
            }
            dKeyToMenu[key] = mi;
            dCommandToKey[sCommand] = key;
            mi.ShortcutKeyDisplayString = friendlyKey(key);
            string sBase = mi.Text.Replace("&", "");
            if (sBase.EndsWith("...")) sBase = sBase.Substring(0, sBase.Length - 3).TrimEnd();
            mi.AccessibleName = sBase + "   " + friendlyKey(key);
            return true;
        }

        public static bool tryDispatch(Keys key, IWin32Window owner)
        {
            if (!dKeyToMenu.ContainsKey(key)) return false;
            return dispatchMenuItem(dKeyToMenu[key], key);
        }

        // dispatchMenuItem: run (or, in Key Help mode, describe) the given
        // menu item, returning true when the keystroke is consumed. The
        // per-form dispatcher (DbDoForm.ProcessCmdKey) resolves the item
        // from the ACTIVE window's own table and calls this, so a chord
        // always acts on the focused window rather than whichever window
        // happened to register the chord first.
        public static bool dispatchMenuItem(ToolStripMenuItem mi, Keys key)
        {
            if (mi == null) return false;
            if (!mi.Enabled)
            {
                // The hotkey is bound but the menu item is currently
                // disabled (typical reason: no database open, or no
                // table selected). Announce why the key did nothing,
                // and consume it so the grid never sees it.
                string sCmd2 = dMenuToCommand.ContainsKey(mi) ? dMenuToCommand[mi] : mi.Text.Replace("&", "");
                LiveRegion.say(sCmd2 + " is unavailable right now (open a database file or select a table first)");
                return true;
            }
            if (bKeyDescriber)
            {
                // Key Help mode: announce (command, chord, summary) and
                // swallow the keystroke -- except the Key Describer toggle
                // itself, which must run so the mode can be exited.
                string sCmd = dMenuToCommand.ContainsKey(mi) ? dMenuToCommand[mi] : mi.Text.Replace("&", "");
                if (sCmd == "Key Describer Toggle")
                {
                    mi.PerformClick();
                    return true;
                }
                string sSummary = summaryFor(sCmd);
                string sChord = friendlyKey(key);
                string sCtx = contextFor(sCmd);
                string sCtxPart = (sCtx == "Global") ? "" : " Context: " + sCtx + ".";
                LiveRegion.say(sCmd + ". " + sChord + ". " + sSummary + "." + sCtxPart);
            }
            else
            {
                mi.PerformClick();
            }
            return true;
        }

        // Format a Keys value as a hotkey display string for menus,
        // help screens, and trace messages.
        //
        // Convention adopted by DbDo:
        //   - Modifiers in alphabetical order (Alt, then Control, then
        //     Shift), each followed by '+'.
        //   - The base key follows. Letter keys are capitalized whether
        //     or not Shift is a modifier (the on-screen label is the
        //     symbol on the physical keycap, not the typed character).
        //   - Function keys, arrow keys, digit keys, and named symbol
        //     keys are spelled out (F5, Up, 1, Backslash).
        //   - Examples: "Control+S", "Control+Shift+D", "Alt+Control+D",
        //     "Alt+F4", "F2", "Enter", "Ctrl+`" appears as
        //     "Control+Backquote".
        //
        // Unlike Keys.ToString(), which produces "S, Control" (letter
        // first, modifiers second, comma-separated), this method
        // produces the human-readable form with modifiers leading.
        // hotkeySummary: the single consultable (command, key, description)
        // listing. It is COMPUTED, not hand-maintained: it joins the same
        // dCommandToKey and dCommandToSummary tables the menus and Key Help
        // already draw from, so it cannot drift from the live bindings.
        // Format is "Command Name=Key, "Command Name=Key,
        // summary", one per line, sorted by command name, "None" for an
        // unbound command -- followed by a consistency trailer that flags
        // duplicate key assignments and commands missing a description.
        public static string hotkeySummary()
        {
            SortedSet<string> setCommands = new SortedSet<string>(StringComparer.OrdinalIgnoreCase);
            foreach (string sCmd in dCommandToSummary.Keys) setCommands.Add(sCmd);
            foreach (string sCmd in dCommandToKey.Keys) setCommands.Add(sCmd);

            // Reverse index for duplicate-chord detection.
            Dictionary<Keys, List<string>> dKeyUsers = new Dictionary<Keys, List<string>>();
            foreach (KeyValuePair<string, Keys> kv in dCommandToKey)
            {
                if (kv.Value == Keys.None) continue;
                if (!dKeyUsers.ContainsKey(kv.Value)) dKeyUsers[kv.Value] = new List<string>();
                dKeyUsers[kv.Value].Add(kv.Key);
            }

            StringBuilder sb = new StringBuilder();
            List<string> lNoDesc = new List<string>();
            int iUnbound = 0;
            sb.AppendLine("[Hotkeys]");
            foreach (string sCmd in setCommands)
            {
                Keys key;
                bool bHasKey = dCommandToKey.TryGetValue(sCmd, out key) && key != Keys.None;
                if (!bHasKey) iUnbound++;
                string sSummary;
                if (!dCommandToSummary.TryGetValue(sCmd, out sSummary) || string.IsNullOrEmpty(sSummary))
                { sSummary = ""; lNoDesc.Add(sCmd); }

                sb.Append(sCmd);
                sb.Append("=");
                sb.Append(bHasKey ? friendlyKey(key) : "None");
                if (sSummary.Length > 0) { sb.Append(", "); sb.Append(sSummary); }
                sb.AppendLine();
            }

            sb.AppendLine();
            sb.AppendLine("# Consistency notes");
            int iDup = 0;
            foreach (KeyValuePair<Keys, List<string>> kv in dKeyUsers)
            {
                if (kv.Value.Count > 1)
                { iDup++; sb.AppendLine("Duplicate key " + friendlyKey(kv.Key) + ": " + string.Join(", ", kv.Value.ToArray())); }
            }
            if (iDup == 0) sb.AppendLine("No duplicate key assignments.");
            sb.AppendLine("Commands without a description: " + (lNoDesc.Count == 0 ? "none" : string.Join(", ", lNoDesc.ToArray())));
            sb.AppendLine("Unbound commands (no chord): " + iUnbound + " of " + setCommands.Count + ".");
            return sb.ToString();
        }

        public static string friendlyKey(Keys key)
        {
            Keys keyBase = key & ~Keys.Modifiers;
            string sBase = baseKeyLabel(keyBase);
            if (sBase.Length == 0) return "";

            StringBuilder sbOut = new StringBuilder();
            if ((key & Keys.Alt)     == Keys.Alt)     sbOut.Append("Alt+");
            if ((key & Keys.Control) == Keys.Control) sbOut.Append("Control+");
            if ((key & Keys.Shift)   == Keys.Shift)   sbOut.Append("Shift+");
            sbOut.Append(sBase);
            return sbOut.ToString();
        }

        // Render a single Keys value (without modifiers) as its display
        // label. Letter keys A-Z are returned uppercase. Digit keys
        // D0-D9 become "0"-"9". Named symbol keys map to common
        // English names. Function keys F1-F24, arrow keys, Enter, etc.
        // pass through.
        private static string baseKeyLabel(Keys keyBase)
        {
            // Empty / pure-modifier
            if (keyBase == Keys.None) return "";

            // Letter keys: A-Z always shown uppercase
            if (keyBase >= Keys.A && keyBase <= Keys.Z) return keyBase.ToString();

            // Top-row digit keys: D0-D9
            if (keyBase >= Keys.D0 && keyBase <= Keys.D9)
                return ((int)(keyBase - Keys.D0)).ToString();

            // Numpad digits
            if (keyBase >= Keys.NumPad0 && keyBase <= Keys.NumPad9)
                return "NumPad" + ((int)(keyBase - Keys.NumPad0));

            // Named symbol keys: JAWS-canonical names (from JAWS
            // Default.JKM). This is the vocabulary the user is
            // already trained on through their screen reader.
            // Modifiers are kept in alpha order (Alt, Control,
            // Shift) by the caller; only base-key names are mapped
            // here.
            switch (keyBase)
            {
                case Keys.OemQuotes:        return "Apostrophe";
                case Keys.OemSemicolon:     return "Semicolon";
                case Keys.OemQuestion:      return "Slash";
                case Keys.OemPeriod:        return "Period";
                case Keys.Oemcomma:         return "Comma";
                case Keys.OemMinus:         return "Minus";
                case Keys.Oemplus:          return "Equals";
                case Keys.OemOpenBrackets:  return "LeftBracket";
                case Keys.OemCloseBrackets: return "RightBracket";
                case Keys.OemPipe:          return "Backslash";  // also Oem5
                case Keys.Oemtilde:         return "GraveAccent";
                case Keys.Back:             return "Backspace";
                case Keys.Return:           return "Enter";
                case Keys.Escape:           return "Escape";
                case Keys.Space:            return "Space";
                case Keys.Tab:              return "Tab";
                case Keys.Up:               return "UpArrow";
                case Keys.Down:             return "DownArrow";
                case Keys.Left:             return "LeftArrow";
                case Keys.Right:            return "RightArrow";
                case Keys.PageUp:           return "PageUp";
                case Keys.PageDown:         return "PageDown";
                case Keys.Home:             return "Home";
                case Keys.End:              return "End";
                case Keys.Insert:           return "Insert";
                case Keys.Delete:           return "Delete";
                case Keys.PrintScreen:      return "PrintScreen";
                case Keys.CapsLock:         return "CapsLock";
                case Keys.NumLock:          return "NumLock";
                case Keys.Scroll:           return "ScrollLock";
                // NumPad arithmetic keys -- JAWS conventions.
                case Keys.Add:              return "NumPadPlus";
                case Keys.Subtract:         return "NumPadMinus";
                case Keys.Multiply:         return "NumPadStar";
                case Keys.Divide:           return "NumPadSlash";
                case Keys.Decimal:          return "NumPadDot";
            }

            // Function keys and anything else
            return keyBase.ToString();
        }

        public static List<string[]> getAllCommands()
        {
            List<string[]> lOut = new List<string[]>();
            foreach (KeyValuePair<ToolStripMenuItem, string> kv in dMenuToCommand)
            {
                string sCmd = kv.Value;
                string sKey = dCommandToKey.ContainsKey(sCmd) ? friendlyKey(dCommandToKey[sCmd]) : "(unbound)";
                bool bEnabled = kv.Key.Enabled;
                lOut.Add(new string[] { sCmd, sKey, bEnabled ? "" : " (disabled)" });
            }
            lOut.Sort((a, b) => string.Compare(a[0], b[0], StringComparison.OrdinalIgnoreCase));
            return lOut;
        }
    }

    // =====================================================================
    // HelpDialog: reusable read-only multiline TextBox dialog. Used
    // for showing schema text, help contents, integrity check output,
    // and other long read-only content.
    // =====================================================================
    // LbcTextBox: the TextBox subclass used by every LbC text field and
    // by the read-only detail/help viewers. Its purpose is to be the one
    // place screen-reader conveniences live, so a convenience added here
    // propagates to every text field in the app at once rather than being
    // wired control-by-control (which is how some fields previously ended
    // up missing one). It adds only shortcuts WinForms does not provide as
    // built-ins:
    //   Control+A         select all text
    //   Control+Shift+A   clear the selection (unselect all)
    // ProcessCmdKey is overridden rather than OnKeyDown so the chord is
    // intercepted before the control's default processing, which is what
    // makes Control+A work even in multi-line and read-only boxes (where
    // the stock TextBox otherwise ignores it).
    public class LbcTextBox : TextBox
    {
        // Tip: focus tip spoken by Shift+F1; set by the Lbc adders.
        public string Tip = "";

        // lsLookupValues: opt-in F4 / Alt+DownArrow pick list. When an
        // editor assigns the valid values for this control's table+field
        // pair (from the builtin lookups table, e.g. maps.kind or
        // projects.kind), F4 opens an alphabetical pick list and replaces
        // the text with the chosen value -- the same pattern the multi-
        // field edit dialog offers, now available in any single Lbc text
        // line. Null or empty means no pick list for this control.
        public List<string> lsLookupValues = null;

        // ----- Text-control extra keys (HomerLbc_40 heritage) -----
        // Every Lbc text field gets this family of screen-reader
        // conveniences by being an LbcTextBox -- nothing is wired per
        // control, so a convenience added here reaches them all at once
        // (the modern replacement for HomerLbc's shared-handler + flag).
        // Copy takes the line WITHOUT its break (text payload); Cut and
        // Delete Line take the line WITH its break (removing the row),
        // then speak the line the caret lands on.
        //   Control+A        Select All          (ProcessCmdKey)
        //   Control+Shift+A  Unselect All        (ProcessCmdKey)
        //   Control+C        Copy: selection, else current line
        //   Alt+C            Copy Append: clipboard + selection-or-line
        //   Control+X        Cut: selection, else current line
        //   Alt+X            Cut Append: clipboard + what Cut removed
        //   Control+D        Delete Line (no clipboard)
        //   F8 / Shift+F8    Start / Complete Selection
        //   Control+F8       Copy All
        //   Alt+F8           Read All
        //   Alt+Y            Say Yield: line and character counts
        //   Alt+Apostrophe   Say Clipboard
        //   Shift+F1         Focus Tip
        // showLookupPick: open an alphabetical pick list of lsLookupValues
        // and, on OK, replace the text with the chosen value. Mirrors the
        // edit dialog's pickLookupValue so the F4 behavior is identical,
        // but is self-contained on the control so any single Lbc text line
        // can offer it just by assigning lsLookupValues.
        private void showLookupPick()
        {
            if (lsLookupValues == null || lsLookupValues.Count == 0) return;
            try
            {
                List<string> lsAlpha = new List<string>(lsLookupValues);
                lsAlpha.Sort(StringComparer.OrdinalIgnoreCase);   // pick list in alpha order
                using (LbcDialog dlgPick = new LbcDialog("Pick value", FindForm()))
                {
                    ListBox lbPick = dlgPick.addListBox("Choose a value:", lsAlpha, Text);
                    if (!string.Equals(dlgPick.runWithButtons(new string[] { "OK", "Cancel" }),
                            "OK", StringComparison.OrdinalIgnoreCase)) return;
                    if (lbPick.SelectedItem == null) return;
                    if (ReadOnly) { LiveRegion.say("Read-only"); return; }
                    Text = lbPick.SelectedItem.ToString();
                    SelectionStart = TextLength;
                    SelectionLength = 0;
                    LiveRegion.say(Text);
                }
            }
            catch (Exception exPick)
            { try { DbDoLog.write("showLookupPick failed: " + exPick.Message); } catch { } }
        }

        // Control+A / Control+Shift+A use ProcessCmdKey so they fire even
        // in multi-line and read-only boxes; the rest use OnKeyDown.
        protected override bool ProcessCmdKey(ref Message msg, Keys keyData)
        {
            if (keyData == (Keys.Control | Keys.A))
            { SelectAll(); LiveRegion.say("Selected all"); return true; }
            if (keyData == (Keys.Control | Keys.Shift | Keys.A))
            { SelectionLength = 0; LiveRegion.say("Selection cleared"); return true; }
            return base.ProcessCmdKey(ref msg, keyData);
        }

        protected override void OnKeyDown(KeyEventArgs evArgs)
        {
            base.OnKeyDown(evArgs);
            if (evArgs.Handled) return;
            int iLength;
            int iStart;
            string sLine;
            Keys key = evArgs.KeyData;

            if ((key == Keys.F4 || key == (Keys.Alt | Keys.Down))
                && lsLookupValues != null && lsLookupValues.Count > 0)
            {
                evArgs.Handled = true;
                evArgs.SuppressKeyPress = true;
                showLookupPick();
            }
            else if (key == (Keys.Control | Keys.C))
            {
                if (SelectionLength > 0) return;   // normal copy proceeds
                sLine = currentLineText();
                setClipboard(sLine);
                LiveRegion.say(sLine.Length == 0 ? "Copied blank line" : "Copied line");
            }
            else if (key == (Keys.Alt | Keys.C))
            {
                sLine = (SelectionLength > 0) ? SelectedText : currentLineText();
                setClipboard(clipboardJoin(sLine));
                LiveRegion.say("Appended to clipboard");
            }
            else if (key == (Keys.Control | Keys.X))
            {
                if (ReadOnly) { LiveRegion.say("Read-only"); return; }
                if (SelectionLength > 0) return;   // normal cut proceeds
                lineBounds(true, out iStart, out iLength);
                Select(iStart, iLength);
                Cut();
                SelectionStart = iStart;
                SelectionLength = 0;
                sayLanding();
            }
            else if (key == (Keys.Alt | Keys.X))
            {
                if (ReadOnly) { LiveRegion.say("Read-only"); return; }
                string sPrior = clipboardJoin("");
                if (SelectionLength == 0)
                {
                    lineBounds(true, out iStart, out iLength);
                    Select(iStart, iLength);
                }
                else iStart = SelectionStart;
                Cut();
                string sCut = "";
                try { sCut = Clipboard.GetText(); } catch { }
                setClipboard(sPrior + sCut);
                SelectionStart = iStart;
                SelectionLength = 0;
                sayLanding();
            }
            else if (key == (Keys.Control | Keys.D))
            {
                if (ReadOnly) { LiveRegion.say("Read-only"); return; }
                lineBounds(true, out iStart, out iLength);
                Text = Text.Remove(iStart, iLength);
                SelectionStart = Math.Min(iStart, TextLength);
                SelectionLength = 0;
                sayLanding();
            }
            else if (key == Keys.F8)
            {
                int iAnchor = SelectionStart + SelectionLength;
                Tag = iAnchor;
                LiveRegion.say("Start selection" + (iAnchor < TextLength ? " at " + Text[iAnchor] : ""));
            }
            else if (key == (Keys.Shift | Keys.F8))
            {
                if (!(Tag is int)) { LiveRegion.say("No selection start; press F8 first"); return; }
                int iAnchor2 = (int)Tag;
                int iCaret = SelectionStart + SelectionLength;
                Select(Math.Min(iAnchor2, iCaret), Math.Abs(iCaret - iAnchor2));
                LiveRegion.say(SelectionLength + (SelectionLength == 1 ? " character" : " characters"));
            }
            else if (key == (Keys.Control | Keys.F8))
            {
                setClipboard(Text);
                LiveRegion.say("Copied all");
            }
            else if (key == (Keys.Alt | Keys.F8))
            {
                LiveRegion.say(TextLength == 0 ? "Blank" : Text);
            }
            else if (key == (Keys.Alt | Keys.Y))
            {
                int iLines = Multiline ? Lines.Length : 1;
                LiveRegion.say(iLines + (iLines == 1 ? " line, " : " lines, ")
                    + TextLength + (TextLength == 1 ? " character" : " characters"));
            }
            else if (key == (Keys.Alt | Keys.OemQuotes))
            {
                string sClip = "";
                try { sClip = Clipboard.GetText(); } catch { }
                LiveRegion.say(sClip.Length == 0 ? "Clipboard empty" : sClip);
            }
            else if (key == (Keys.Shift | Keys.F1))
            {
                LiveRegion.say(string.IsNullOrEmpty(Tip) ? "No tip for this field" : Tip);
            }
            // Homer structured-text line operations, active only in
            // multiline fields (notes, tags). Each acts on the selected
            // lines, or all lines when there is no selection. Keys are
            // the original Homer editor bindings. These mutate text, so
            // they no-op (with a spoken note) on read-only fields.
            else if (Multiline && key == (Keys.Alt | Keys.Shift | Keys.O))   applyLineOp(sortLines,    "Sorted");
            else if (Multiline && key == (Keys.Alt | Keys.Shift | Keys.Z))   applyLineOp(reverseLines, "Reversed");
            else if (Multiline && key == (Keys.Alt | Keys.Shift | Keys.K))   applyLineOp(uniqueLines,  "Kept unique,");
            else if (Multiline && key == (Keys.Alt | Keys.Shift | Keys.N))   applyLineOp(numberLines,  "Numbered");
            else if (Multiline && key == (Keys.Control | Keys.Shift | Keys.Enter)) applyLineOp(trimBlanks, "Trimmed");
            else return;

            evArgs.Handled = true;
            evArgs.SuppressKeyPress = true;
        }

        // applyLineOp: run a line transform over the selected lines, or
        // all lines when nothing is selected, replacing the text in
        // place (undoable) and speaking the resulting line count.
        private void applyLineOp(Func<string, string> op, string sVerb)
        {
            if (ReadOnly) { LiveRegion.say("Read-only"); return; }
            if (SelectionLength == 0) SelectAll();
            string sOut = op(SelectedText);
            SelectedText = sOut;
            int iLines = (sOut.Length == 0) ? 0 : sOut.Split('\n').Length;
            LiveRegion.say(sVerb + " " + iLines + (iLines == 1 ? " line" : " lines"));
        }

        // Line-transform helpers (pure). splitTextLines normalizes any
        // line-break flavor to a list; joinTextLines re-emits CRLF.
        private static List<string> splitTextLines(string sText)
        {
            List<string> lLines = new List<string>();
            foreach (string sLine in sText.Replace("\r\n", "\n").Replace("\r", "\n").Split('\n'))
                lLines.Add(sLine);
            return lLines;
        }
        private static string joinTextLines(List<string> lLines)
        {
            return string.Join("\r\n", lLines.ToArray());
        }
        private static string sortLines(string sText)
        {
            List<string> lLines = splitTextLines(sText);
            lLines.Sort(StringComparer.OrdinalIgnoreCase);
            return joinTextLines(lLines);
        }
        private static string reverseLines(string sText)
        {
            List<string> lLines = splitTextLines(sText);
            lLines.Reverse();
            return joinTextLines(lLines);
        }
        private static string uniqueLines(string sText)
        {
            List<string> lOut = new List<string>();
            HashSet<string> hSeen = new HashSet<string>();
            foreach (string sLine in splitTextLines(sText))
                if (hSeen.Add(sLine)) lOut.Add(sLine);
            return joinTextLines(lOut);
        }
        private static string trimBlanks(string sText)
        {
            List<string> lOut = new List<string>();
            int iBlankRun = 0;
            foreach (string sLine in splitTextLines(sText))
            {
                string sTrim = sLine.Trim();
                if (sTrim.Length == 0)
                {
                    iBlankRun++;
                    if (iBlankRun <= 2) lOut.Add("");
                }
                else { iBlankRun = 0; lOut.Add(sTrim); }
            }
            return joinTextLines(lOut);
        }
        private static string numberLines(string sText)
        {
            List<string> lOut = new List<string>();
            int iNum = 0;
            foreach (string sLine in splitTextLines(sText))
            {
                iNum++;
                lOut.Add(iNum + ". " + sLine);
            }
            return joinTextLines(lOut);
        }

        // lineBounds: start index and length of the caret's line.
        // bIncludeBreak picks the Cut/Delete flavor (line plus its
        // terminator) versus the Copy flavor (text only).
        private bool lineBounds(bool bIncludeBreak, out int iStart, out int iLength)
        {
            int iEnd;
            int iIndex = SelectionStart + SelectionLength;
            int iRow = GetLineFromCharIndex(iIndex);
            iStart = GetFirstCharIndexFromLine(iRow);
            iEnd = GetFirstCharIndexFromLine(iRow + 1);
            if (iEnd <= 0) iEnd = TextLength;
            else if (!bIncludeBreak) iEnd--;
            if (iStart < 0) iStart = 0;
            iLength = iEnd - iStart;
            if (iLength < 0) iLength = 0;
            return true;
        }

        private string currentLineText()
        {
            int iLength;
            int iStart;
            lineBounds(false, out iStart, out iLength);
            return Text.Substring(iStart, iLength).TrimEnd('\r', '\n');
        }

        private void sayLanding()
        {
            string sLine = currentLineText();
            LiveRegion.say(sLine.Length == 0 ? "Blank" : sLine);
        }

        // clipboardJoin / setClipboard: shared by the text conveniences
        // here and by the Lbc list-box copy keys; static so both call
        // them without duplicating the bodies.
        internal static string clipboardJoin(string sAddition)
        {
            string sText = "";
            try { sText = Clipboard.GetText(); } catch { }
            if (sText.Length > 0 && !sText.EndsWith("\n")) sText += "\r\n";
            return sText + sAddition;
        }

        internal static bool setClipboard(string sText)
        {
            try { Clipboard.SetText(sText.Length == 0 ? " " : sText); return true; }
            catch { return false; }
        }
    }

    // =====================================================================
    // LbcForm: shared base for every Lbc dialog. Adds Control+Enter as
    // a universal "press OK" accelerator so the user can accept a dialog
    // from anywhere in it without tabbing to the OK button -- notably in
    // the sort-order dialog, where Enter on the Fields list does Add (not
    // OK). The OK button is located by its DialogResult (preferred) or an
    // "OK" label, deliberately NOT via the form's AcceptButton: some Lbc
    // dialogs point AcceptButton at a different default (e.g. Add) while
    // focus sits on a listbox, so AcceptButton is not a reliable handle
    // for "OK". If no OK button is found, Control+Enter falls through
    // untouched.
    public class LbcForm : Form
    {
        protected override bool ProcessCmdKey(ref Message msg, Keys keyData)
        {
            if (keyData == (Keys.Control | Keys.Enter))
            {
                Button btnOk = findButton(this, true);   // by DialogResult.OK
                if (btnOk == null) btnOk = findButton(this, false); // by "OK" label
                if (btnOk != null) { btnOk.PerformClick(); return true; }
            }
            return base.ProcessCmdKey(ref msg, keyData);
        }

        private static Button findButton(Control parent, bool bByDialogResult)
        {
            foreach (Control c in parent.Controls)
            {
                Button btn = c as Button;
                if (btn != null)
                {
                    if (bByDialogResult)
                    {
                        if (btn.DialogResult == DialogResult.OK) return btn;
                    }
                    else if (btn.Text != null
                        && btn.Text.Replace("&", "").Trim().Equals("OK", StringComparison.OrdinalIgnoreCase))
                        return btn;
                }
                Button nested = findButton(c, bByDialogResult);
                if (nested != null) return nested;
            }
            return null;
        }
    }

    // =====================================================================
    public static class HelpDialog
    {
        public static void show(IWin32Window owner, string sTitle, string sText)
        {
            using (Form dlg = new LbcForm())
            {
                dlg.Text = sTitle;
                dlg.AccessibleName = sTitle;
                dlg.StartPosition = FormStartPosition.CenterParent;
                dlg.ClientSize = new Size(720, 540);
                dlg.MinimumSize = new Size(400, 300);
                dlg.FormBorderStyle = FormBorderStyle.Sizable;
                dlg.MaximizeBox = true;
                dlg.MinimizeBox = false;
                dlg.ShowInTaskbar = false;
                dlg.KeyPreview = true;

                LbcTextBox tb = new LbcTextBox();
                tb.Multiline = true;
                tb.ReadOnly = true;
                tb.ScrollBars = ScrollBars.Vertical;
                tb.WordWrap = true;
                tb.Font = new Font(FontFamily.GenericMonospace, 10f);
                tb.Text = sText;
                tb.AccessibleName = "Help text";
                tb.TabIndex = 0;
                tb.SelectionStart = 0;
                tb.SelectionLength = 0;
                tb.Size = new Size(dlg.ClientSize.Width - 20, dlg.ClientSize.Height - 50);
                tb.Location = new Point(10, 10);
                tb.Anchor = AnchorStyles.Top | AnchorStyles.Left | AnchorStyles.Right | AnchorStyles.Bottom;

                Button btnClose = new Button();
                btnClose.Text = "&OK";
                btnClose.AccessibleName = "OK";
                btnClose.DialogResult = DialogResult.OK;
                btnClose.Size = new Size(90, 28);
                btnClose.Anchor = AnchorStyles.Bottom | AnchorStyles.Right;
                btnClose.Location = new Point(dlg.ClientSize.Width - 100, dlg.ClientSize.Height - 38);
                btnClose.UseVisualStyleBackColor = true;
                btnClose.TabIndex = 1;

                dlg.Controls.Add(tb);
                dlg.Controls.Add(btnClose);
                dlg.AcceptButton = btnClose;
                dlg.CancelButton = btnClose;
                dlg.ActiveControl = tb;

                dlg.ShowDialog(owner);
            }
        }

        // showRecordView: the Show view's read-only record display
        // with view-cycle and record-navigation keys. Returns a
        // verdict the caller's loop acts on:
        //   0  closed (Escape / OK)            -> list
        //   1  F6 (forward in the cycle)       -> list (show is last)
        //   2  Shift+F6 (back in the cycle)    -> form
        //   3  Control+PageDown                -> next record
        //   4  Control+PageUp                  -> previous record
        // Separate from show() so help text and query results keep
        // their plain read-only dialog without these keys.
        public static int showRecordView(IWin32Window owner, string sTitle, string sText)
        {
            int iVerdict = 0;
            using (Form dlg = new LbcForm())
            {
                dlg.Text = sTitle;
                dlg.AccessibleName = sTitle;
                dlg.StartPosition = FormStartPosition.CenterParent;
                dlg.ClientSize = new Size(720, 540);
                dlg.MinimumSize = new Size(400, 300);
                dlg.FormBorderStyle = FormBorderStyle.Sizable;
                dlg.MaximizeBox = true; dlg.MinimizeBox = false;
                dlg.ShowInTaskbar = false; dlg.KeyPreview = true;

                TextBox tb = new TextBox();
                tb.Multiline = true; tb.ReadOnly = true;
                tb.ScrollBars = ScrollBars.Vertical; tb.WordWrap = true;
                tb.Font = new Font(FontFamily.GenericMonospace, 10f);
                tb.Text = sText; tb.AccessibleName = "Record";
                tb.TabIndex = 0; tb.SelectionStart = 0; tb.SelectionLength = 0;
                tb.Size = new Size(dlg.ClientSize.Width - 20, dlg.ClientSize.Height - 50);
                tb.Location = new Point(10, 10);
                tb.Anchor = AnchorStyles.Top | AnchorStyles.Left | AnchorStyles.Right | AnchorStyles.Bottom;

                Button btnClose = new Button();
                btnClose.Text = "&OK"; btnClose.AccessibleName = "OK";
                btnClose.DialogResult = DialogResult.OK;
                btnClose.Size = new Size(90, 28);
                btnClose.Anchor = AnchorStyles.Bottom | AnchorStyles.Right;
                btnClose.Location = new Point(dlg.ClientSize.Width - 100, dlg.ClientSize.Height - 38);
                btnClose.UseVisualStyleBackColor = true; btnClose.TabIndex = 1;

                dlg.KeyDown += delegate(object o, KeyEventArgs ev)
                {
                    int v = 0;
                    if (ev.KeyData == Keys.F6) v = 1;
                    else if (ev.KeyData == (Keys.Shift | Keys.F6)) v = 2;
                    else if (ev.KeyData == (Keys.Control | Keys.PageDown)) v = 3;
                    else if (ev.KeyData == (Keys.Control | Keys.PageUp)) v = 4;
                    else return;
                    iVerdict = v;
                    ev.Handled = true; ev.SuppressKeyPress = true;
                    dlg.DialogResult = DialogResult.OK;
                    dlg.Close();
                };

                dlg.Controls.Add(tb);
                dlg.Controls.Add(btnClose);
                dlg.AcceptButton = btnClose;
                dlg.CancelButton = btnClose;
                dlg.ActiveControl = tb;
                dlg.ShowDialog(owner);
            }
            return iVerdict;
        }
    }

    // =====================================================================
    // LbcDialog: "Layout by Code" dialog builder.
    //
    // A reusable WinForms dialog that callers build by adding one
    // control at a time. Each add* method appends a labeled row
    // to a vertical stack, returns the inner editing control, and
    // wires its accessible name from the label so screen readers
    // announce the field correctly when the user tabs into it.
    //
    // After adding all controls, the caller invokes runOkCancel()
    // which appends an OK/Cancel button band, shows the dialog
    // modally, and returns true on OK. The caller then reads the
    // final values directly from the control references it kept.
    //
    // Borrowed pattern from Jamal Mazrui's Layout by Code system
    // (LbC), which exists in C#, Python, AutoIt, and JScript .NET
    // versions and codifies the practice of laying out screen-
    // reader-friendly dialogs by composing simple "add this
    // control" calls in sequence rather than using a designer file.
    //
    // Features carried over from HomerLbc (the mature JScript .NET
    // implementation):
    //   - Focus tips: each add* method takes an optional tip string;
    //     when the user tabs into the control, the tip appears in
    //     a status bar at the bottom of the dialog. Screen readers
    //     announce status-bar changes, so the tip is read aloud
    //     without forcing a popup. Tips replace tooltip popups,
    //     which JAWS often suppresses.
    //   - Name-based widget lookup: every control is registered in
    //     a Widgets dictionary keyed by an auto-generated name
    //     (<Kind>_<CleanedLabel>) so callers can retrieve controls
    //     by string name as well as by reference. Useful for
    //     handlers that get the sender but not the original ref,
    //     and for generic walkers (import/export, validation).
    //   - Memo-vs-AcceptButton coordination: while focus is on a
    //     multi-line TextBox (added via addTextMemo / addMemoBox),
    //     the form's AcceptButton is temporarily cleared so Enter
    //     inserts a newline instead of submitting; on LostFocus
    //     the AcceptButton is restored. This is the Homer LbC
    //     convention -- it lets memo editing feel natural while
    //     still letting Enter submit from single-line fields.
    //
    // Conventions:
    //   - Each labeled control gets a Label above it (not beside).
    //     Uniform vertical rhythm, label-then-control reading order.
    //   - The label text passes through unchanged (caller may
    //     include '&' for mnemonic letters); the control's
    //     AccessibleName strips '&' and trailing ':'.
    //   - TabIndex is assigned in add order. WinForms Labels are
    //     non-focusable and naturally skipped during tab traversal.
    //   - The dialog auto-sizes its height to its contents up to
    //     a cap; AutoScroll engages above the cap.
    //   - Two naming patterns coexist: bare-control adders (addLabel,
    //     addTextBox, addCheckBox) and labeled-control adders that
    //     mirror Homer LbC (addInputBox, addMemoBox, addPickBox,
    //     addComboPickBox). The labeled variants are aliases that
    //     emit a Label first and then call the bare adder.
    //
    // Typical usage:
    //
    //   LbcDialog dlg = new LbcDialog("Configuration", this);
    //   TextBox   tbMode = dlg.addInputBox("UI mode", "both", "How DbDo launches");
    //   CheckBox  cbBeep = dlg.addCheckBox("Beep on errors", true, "Audible cue on failure");
    //   TextBox   tbNote = dlg.addMemoBox("Startup note", "", "Free-form text shown at launch");
    //   if (dlg.runOkCancel())
    //   {
    //       string sMode = tbMode.Text;
    //       bool   bBeep = cbBeep.Checked;
    //       string sNote = tbNote.Text;
    //       // ... persist or apply
    //   }
    //
    //   // Or look up by name later:
    //   TextBox tbAgain = dlg.getTextBox("TextBox_UI_mode");
    // =====================================================================
    public class LbcDialog : IDisposable
    {
        // Layout constants, all alphabetical. Sized for screen-reader
        // users who often run at 125-150% display scaling -- generous
        // padding makes the dialog readable without crowding labels.
        private const int DefaultButtonHeight = 28;
        private const int DefaultButtonWidth  = 90;
        private const int DefaultDialogWidth  = 520;
        private const int DefaultLabelHeight  = 18;
        private const int DefaultLineHeight   = 24;
        private const int DefaultListHeight   = 100;
        private const int DefaultMaxHeight    = 600;
        private const int DefaultMemoHeight   = 96;
        private const int DefaultNumericWidth = 100;
        private const int DefaultPadding      = 12;
        private const int DefaultRowGap       = 6;
        private const int DefaultStatusHeight = 22;

        // Layout state. Built up by add* calls, consumed by runX.
        // Alphabetical declarations.
        private Dictionary<Control, string> dFocusTips;
        private Dictionary<string, int>     dNameCounts;
        private Dictionary<string, Control> dWidgets;
        private Control                     ctlFirstFocusable;
        private Form                        frm;
        private IWin32Window                owner;
        private Button                      btnSavedAccept;
        private FlowLayoutPanel             pnlStack;
        private Label                       lblStatusBar;
        private int                         iTabIndex;
        // Most-recent case-insensitive substring searched via Ctrl+J
        // inside a pick-list. F3 / Shift+F3 advance / retreat through
        // matches. Shared across all list boxes in this dialog so the
        // user can chain searches across multiple lists.
        private string                      sListSearchTerm = "";

        public LbcDialog(string sTitle, IWin32Window ownerWindow)
        {
            owner = ownerWindow;
            frm = new LbcForm();
            frm.Text = sTitle ?? "";
            frm.AccessibleName = sTitle ?? "";
            frm.StartPosition = FormStartPosition.CenterParent;
            frm.FormBorderStyle = FormBorderStyle.Sizable;
            frm.MaximizeBox = false;
            frm.MinimizeBox = false;
            frm.ShowInTaskbar = false;
            frm.KeyPreview = true;
            // Text-edit convenience hotkeys: route every keystroke
            // through onFormKeyDown so we can intercept Ctrl+C/X,
            // Alt+C/X/F8, F8/Shift+F8, Ctrl+F8, and Ctrl+D when the
            // focused control is a TextBox or memo. The handler is
            // a no-op for other controls and for keystrokes that
            // don't match the convenience set. Master enable flag
            // [Lbc] extraKeys in DbDo.inix, defaults Y.
            frm.KeyDown += new KeyEventHandler(onFormKeyDown);
            frm.MinimumSize = new Size(360, 200);
            frm.ClientSize = new Size(DefaultDialogWidth, 200);

            // Status bar at the bottom of the form. Updates as the
            // user tabs through controls -- each control's focus
            // tip (set via the optional sTip argument on add*
            // methods) appears here when the control receives focus.
            // JAWS, NVDA, and Narrator pick up status-bar text via
            // UIA live-region semantics; we set AccessibleRole to
            // StatusBar so the announcement is appropriately routed.
            //
            // Added BEFORE the stack so its Dock=Bottom claims the
            // bottom area. The button row (added later in run*) is
            // also Dock=Bottom and pushes the status bar up by its
            // own height.
            lblStatusBar = new Label();
            lblStatusBar.Text = "";
            lblStatusBar.AccessibleRole = AccessibleRole.StatusBar;
            lblStatusBar.AccessibleName = "Status";
            lblStatusBar.Dock = DockStyle.Bottom;
            lblStatusBar.Height = DefaultStatusHeight;
            lblStatusBar.TextAlign = ContentAlignment.MiddleLeft;
            lblStatusBar.Padding = new Padding(DefaultPadding, 2, DefaultPadding, 2);
            lblStatusBar.BorderStyle = BorderStyle.Fixed3D;
            frm.Controls.Add(lblStatusBar);

            // Vertical FlowLayoutPanel as the form's main container.
            // AutoScroll on so dialogs with many fields scroll instead
            // of overflowing the screen.
            pnlStack = new FlowLayoutPanel();
            pnlStack.FlowDirection = FlowDirection.TopDown;
            pnlStack.WrapContents = false;
            pnlStack.AutoScroll = true;
            pnlStack.Dock = DockStyle.Fill;
            pnlStack.Padding = new Padding(DefaultPadding);
            frm.Controls.Add(pnlStack);

            dFocusTips = new Dictionary<Control, string>();
            dNameCounts = new Dictionary<string, int>();
            dWidgets = new Dictionary<string, Control>(StringComparer.OrdinalIgnoreCase);
            iTabIndex = 0;
            ctlFirstFocusable = null;
            btnSavedAccept = null;
        }

        // ------- Add helpers -------
        //
        // Each adds one control (with optional label and tip) to the
        // vertical stack and returns the control so the caller can
        // stash a reference, attach event handlers, or query the
        // final value after dismissal.
        //
        // Naming pattern (mirrors Homer LbC):
        //   addX        -- bare control, no separate label above it
        //                  (X carries its own label, like CheckBox,
        //                  or no label is wanted)
        //   addXBox     -- labeled control: a Label is added first,
        //                  then the bare X (the convention from
        //                  Homer Lbc where "Box" suffix means
        //                  "with a label above")
        //
        // The Tip parameter, when given, is shown in the status bar
        // when the control receives focus.

        // addLabel: standalone explanatory text. Not focusable, so
        // tip is not applicable.
        public Label addLabel(string sText)
        {
            Label lbl = new Label();
            lbl.Text = sText ?? "";
            lbl.AutoSize = false;
            lbl.Size = new Size(innerWidth(), DefaultLabelHeight);
            lbl.Margin = new Padding(0, 0, 0, DefaultRowGap);
            lbl.TextAlign = ContentAlignment.MiddleLeft;
            registerWidget(lbl, "Label", sText);
            pnlStack.Controls.Add(lbl);
            return lbl;
        }

        // addTextBox: bare single-line text input (no separate
        // Label above). Returns the TextBox.

        public TextBox addTextBox(string sValue, string sTip)
        {
            LbcTextBox tb = new LbcTextBox();
            tb.Text = sValue ?? "";
            tb.Size = new Size(innerWidth(), DefaultLineHeight);
            tb.TabIndex = iTabIndex++;
            tb.Margin = new Padding(0, 0, 0, DefaultRowGap);
            // Inherit the AccessibleName from the most recent Label,
            // if one was just added. Mirrors Homer LbC.
            Label lblLast = currentLabelOrNull();
            if (lblLast != null) tb.AccessibleName = lblLast.AccessibleName;
            tb.GotFocus += handleGotFocus;
            registerWidget(tb, "TextBox", tb.AccessibleName);
            if (!string.IsNullOrEmpty(sTip)) { dFocusTips[tb] = sTip; tb.Tip = sTip; }
            pnlStack.Controls.Add(tb);
            if (ctlFirstFocusable == null) ctlFirstFocusable = tb;
            return tb;
        }

        // addInlineInputBox: labeled single-line text input where
        // the label and the text box share one row. Layout:
        //
        //   [Label:        ] [____textbox____________________]
        //
        // Used by the record edit dialog (New-Record / Set-Record)
        // for single-line fields, per the user-guide layout rule:
        // single-line fields put "Label: " inline with the textbox,
        // while multi-line fields put the label on the row above
        // the (taller) memo box. Inline placement gives the screen
        // reader a tight, scannable layout: Tab moves to the field
        // and JAWS announces "Label: <value>" without the user
        // hearing the bare label as a separate Tab stop.
        //
        // Implementation: a TableLayoutPanel with one row, two
        // columns. The label column is auto-sized to fit its text;
        // the textbox column fills the remaining width. The whole
        // panel is added as a single row to the outer FlowLayoutPanel.
        public TextBox addInlineInputBox(string sLabel, string sValue, string sTip)
        {
            TableLayoutPanel pnlRow = new TableLayoutPanel();
            pnlRow.ColumnCount = 2;
            pnlRow.RowCount = 1;
            pnlRow.AutoSize = true;
            pnlRow.AutoSizeMode = AutoSizeMode.GrowAndShrink;
            pnlRow.Margin = new Padding(0, 0, 0, DefaultRowGap);
            pnlRow.ColumnStyles.Clear();
            pnlRow.ColumnStyles.Add(new ColumnStyle(SizeType.AutoSize));
            pnlRow.ColumnStyles.Add(new ColumnStyle(SizeType.Percent, 100f));
            pnlRow.Width = innerWidth();

            Label lbl = new Label();
            lbl.Text = (sLabel ?? "").TrimEnd();
            if (!lbl.Text.EndsWith(":")) lbl.Text = lbl.Text + ":";
            lbl.AccessibleName = cleanLabel(sLabel);
            lbl.AutoSize = true;
            lbl.TextAlign = ContentAlignment.MiddleLeft;
            lbl.Margin = new Padding(0, 4, DefaultPadding, 0);
            pnlRow.Controls.Add(lbl, 0, 0);

            LbcTextBox tb = new LbcTextBox();
            tb.Text = sValue ?? "";
            tb.Dock = DockStyle.Fill;
            tb.TabIndex = iTabIndex++;
            tb.Margin = new Padding(0, 0, 0, 0);
            tb.AccessibleName = cleanLabel(sLabel);
            tb.GotFocus += handleGotFocus;
            registerWidget(tb, "TextBox", tb.AccessibleName);
            if (!string.IsNullOrEmpty(sTip)) { dFocusTips[tb] = sTip; tb.Tip = sTip; }
            pnlRow.Controls.Add(tb, 1, 0);

            pnlStack.Controls.Add(pnlRow);
            if (ctlFirstFocusable == null) ctlFirstFocusable = tb;
            return tb;
        }

        // addInputBox: labeled single-line text input. Adds a Label
        // first, then a TextBox whose AccessibleName comes from the
        // Label. Equivalent to AddInputBox in Homer LbC.
        //
        // Note: for the record edit dialog, callers should prefer
        // addInlineInputBox (label and textbox on one row). This
        // older addInputBox method (label above textbox) is still
        // used by some dialogs where vertical rhythm matters.
        public TextBox addInputBox(string sLabel, string sValue, string sTip)
        {
            addFieldLabel(sLabel);
            TextBox tb = addTextBox(sValue, sTip);
            // The label inheritance happened in addTextBox via
            // currentLabelOrNull. Set AccessibleName explicitly
            // here too as belt-and-suspenders.
            tb.AccessibleName = cleanLabel(sLabel);
            return tb;
        }

        // 2-arg overload (no tip). Convenient for dialogs where the
        // label is self-explanatory and no extra tooltip is needed.
        public TextBox addInputBox(string sLabel, string sValue)
        {
            return addInputBox(sLabel, sValue, null);
        }

        // addTextLine: alias for addInputBox without a tip. Kept
        // for backward compatibility with the earlier API.
        public TextBox addTextLine(string sLabel, string sValue)
        {
            return addInputBox(sLabel, sValue, null);
        }

        // addMemo: bare multi-line text input. Coordinates with
        // AcceptButton so Enter inside the memo inserts a newline
        // instead of submitting the dialog.
        public TextBox addMemo(string sValue, string sTip)
        {
            LbcTextBox tb = new LbcTextBox();
            tb.Text = sValue ?? "";
            tb.Multiline = true;
            tb.AcceptsReturn = true;
            tb.AcceptsTab = false;
            tb.ScrollBars = ScrollBars.Vertical;
            tb.WordWrap = true;
            tb.Size = new Size(innerWidth(), DefaultMemoHeight);
            tb.TabIndex = iTabIndex++;
            tb.Margin = new Padding(0, 0, 0, DefaultRowGap);
            Label lblLast = currentLabelOrNull();
            if (lblLast != null) tb.AccessibleName = lblLast.AccessibleName;
            tb.GotFocus += handleMemoGotFocus;
            tb.LostFocus += handleMemoLostFocus;
            registerWidget(tb, "Memo", tb.AccessibleName);
            if (!string.IsNullOrEmpty(sTip)) { dFocusTips[tb] = sTip; tb.Tip = sTip; }
            pnlStack.Controls.Add(tb);
            if (ctlFirstFocusable == null) ctlFirstFocusable = tb;
            return tb;
        }

        // addMemoBox: labeled multi-line text input. Equivalent to
        // AddMemoBox in Homer LbC.
        public TextBox addMemoBox(string sLabel, string sValue, string sTip)
        {
            addFieldLabel(sLabel);
            TextBox tb = addMemo(sValue, sTip);
            tb.AccessibleName = cleanLabel(sLabel);
            return tb;
        }

        // addTextMemo: alias for addMemoBox without a tip. Kept for
        // backward compatibility.
        public TextBox addTextMemo(string sLabel, string sValue)
        {
            return addMemoBox(sLabel, sValue, null);
        }

        // addCheckBox: boolean toggle. The label is part of the
        // checkbox itself (WinForms convention).
        public CheckBox addCheckBox(string sLabel, bool bValue, string sTip)
        {
            CheckBox cb = new CheckBox();
            cb.Text = sLabel ?? "";
            cb.AccessibleName = cleanLabel(sLabel);
            cb.Checked = bValue;
            cb.AutoSize = false;
            cb.Size = new Size(innerWidth(), DefaultLineHeight);
            cb.TabIndex = iTabIndex++;
            cb.Margin = new Padding(0, 0, 0, DefaultRowGap);
            cb.GotFocus += handleGotFocus;
            registerWidget(cb, "CheckBox", sLabel);
            if (!string.IsNullOrEmpty(sTip)) dFocusTips[cb] = sTip;
            pnlStack.Controls.Add(cb);
            if (ctlFirstFocusable == null) ctlFirstFocusable = cb;
            return cb;
        }

        // addCheckBox without tip: backward compat.
        public CheckBox addCheckBox(string sLabel, bool bValue)
        {
            return addCheckBox(sLabel, bValue, null);
        }

        // addListBox: bare pick-one list (no Label).
        public ListBox addListBox(IList<string> lNames, string sSelected, string sTip)
        {
            ListBox lb = new ListBox();
            lb.Size = new Size(innerWidth(), DefaultListHeight);
            lb.TabIndex = iTabIndex++;
            lb.Margin = new Padding(0, 0, 0, DefaultRowGap);
            populateListBox(lb, lNames, sSelected);
            Label lblLast = currentLabelOrNull();
            if (lblLast != null) lb.AccessibleName = lblLast.AccessibleName;
            lb.GotFocus += handleGotFocus;
            // Find-in-list keys. Ctrl+J prompts for a case-insensitive
            // substring; F3 advances to the next match; Shift+F3 the
            // previous. Mirrors the data list's Jump-to and Find-Next
            // chords. Useful when picking from long lists (Alternate
            // Menu, Choose Table on a large schema).
            lb.KeyDown += new KeyEventHandler(handleListBoxFindKeys);
            lb.KeyDown += new KeyEventHandler(handleListBoxCopyKeys);
            registerWidget(lb, "ListBox", lb.AccessibleName);
            if (!string.IsNullOrEmpty(sTip)) dFocusTips[lb] = sTip;
            pnlStack.Controls.Add(lb);
            if (ctlFirstFocusable == null) ctlFirstFocusable = lb;
            return lb;
        }

        // handleListBoxFindKeys: KeyDown handler attached to every
        // ListBox added via addListBox / addPickBox. Intercepts the
        // three find-in-list chords; defers everything else to the
        // ListBox's normal handling.
        // handleListBoxCopyKeys: Control+C copies the current list
        // item's text to the clipboard; Alt+C appends it (clipboard,
        // CRLF, item), mirroring the text-control family so every
        // Lbc control answers the same chords.
        private void handleListBoxCopyKeys(object sender, KeyEventArgs evArgs)
        {
            ListBox lb = sender as ListBox;
            if (lb == null) return;
            if (evArgs.KeyData != (Keys.Control | Keys.C)
                && evArgs.KeyData != (Keys.Alt | Keys.C)) return;
            string sItem = (lb.SelectedItem != null) ? lb.SelectedItem.ToString() : "";
            if (sItem.Length == 0) { LiveRegion.say("No item"); }
            else if (evArgs.KeyData == (Keys.Control | Keys.C))
            { LbcTextBox.setClipboard(sItem); LiveRegion.say("Copied item"); }
            else
            { LbcTextBox.setClipboard(LbcTextBox.clipboardJoin(sItem)); LiveRegion.say("Appended to clipboard"); }
            evArgs.Handled = true;
            evArgs.SuppressKeyPress = true;
        }

        private void handleListBoxFindKeys(object sender, KeyEventArgs evArgs)
        {
            ListBox lb = sender as ListBox;
            if (lb == null) return;
            Keys k = evArgs.KeyData;
            if (k == (Keys.Control | Keys.J))
            { promptAndFindInListBox(lb); evArgs.Handled = true; evArgs.SuppressKeyPress = true; }
            else if (k == Keys.F3)
            { findNextInListBox(lb, true); evArgs.Handled = true; evArgs.SuppressKeyPress = true; }
            else if (k == (Keys.Shift | Keys.F3))
            { findNextInListBox(lb, false); evArgs.Handled = true; evArgs.SuppressKeyPress = true; }
        }

        // Ctrl+J: prompt for a case-insensitive substring, then jump
        // to the first item containing it. The substring is stored
        // in sListSearchTerm so subsequent F3 / Shift+F3 can advance.
        private void promptAndFindInListBox(ListBox lb)
        {
            string sPrompt = "Find substring (case-insensitive):";
            string sInitial = sListSearchTerm ?? "";
            // Simple inline input: a tiny modal dialog with one input
            // box. We don't recurse into LbcDialog because nesting
            // would complicate event routing; a vanilla Form is fine.
            using (Form prompt = new LbcForm())
            {
                prompt.Text = "Find in list";
                prompt.AccessibleName = "Find in list";
                prompt.FormBorderStyle = FormBorderStyle.FixedDialog;
                prompt.StartPosition = FormStartPosition.CenterParent;
                prompt.MinimizeBox = false;
                prompt.MaximizeBox = false;
                prompt.ClientSize = new Size(400, 110);
                prompt.KeyPreview = true;
                Label lbl = new Label();
                lbl.Text = sPrompt;
                lbl.AutoSize = true;
                lbl.Location = new Point(12, 12);
                TextBox tb = new TextBox();
                tb.Text = sInitial;
                tb.SelectAll();
                tb.Location = new Point(12, 36);
                tb.Size = new Size(376, 20);
                tb.AccessibleName = "Find substring";
                Button btnOk = new Button();
                btnOk.Text = "&OK";
                btnOk.DialogResult = DialogResult.OK;
                btnOk.Location = new Point(232, 70);
                Button btnCancel = new Button();
                btnCancel.Text = "&Cancel";
                btnCancel.DialogResult = DialogResult.Cancel;
                btnCancel.Location = new Point(313, 70);
                prompt.Controls.Add(lbl);
                prompt.Controls.Add(tb);
                prompt.Controls.Add(btnOk);
                prompt.Controls.Add(btnCancel);
                prompt.AcceptButton = btnOk;
                prompt.CancelButton = btnCancel;
                if (prompt.ShowDialog(frm) != DialogResult.OK) return;
                sListSearchTerm = tb.Text ?? "";
            }
            if (string.IsNullOrEmpty(sListSearchTerm)) return;
            // Start search from item 0 (Ctrl+J is "find first match
            // from the top," not "find next from current position").
            int iFound = findInListBoxFrom(lb, 0, true, sListSearchTerm);
            if (iFound < 0)
                LiveRegion.say("No match for \"" + sListSearchTerm + "\"");
            else
            { lb.SelectedIndex = iFound; lb.Focus(); }
        }

        // F3 / Shift+F3: advance / retreat through matches of the
        // stored search term. If no search term is set, silently say
        // so (don't pop up a dialog -- F3 is a navigation key, not a
        // configuration key).
        private void findNextInListBox(ListBox lb, bool bForward)
        {
            if (string.IsNullOrEmpty(sListSearchTerm))
            { LiveRegion.say("No find substring set; press Control+J first"); return; }
            int iFrom = lb.SelectedIndex + (bForward ? 1 : -1);
            if (iFrom < 0) iFrom = lb.Items.Count - 1;
            if (iFrom >= lb.Items.Count) iFrom = 0;
            int iFound = findInListBoxFrom(lb, iFrom, bForward, sListSearchTerm);
            if (iFound < 0)
                LiveRegion.say("No more matches for \"" + sListSearchTerm + "\"");
            else
                lb.SelectedIndex = iFound;
        }

        // findInListBoxFrom: case-insensitive substring search through
        // the ListBox starting at iFrom, wrapping at the boundary.
        // Returns the index of the match or -1 if none.
        private static int findInListBoxFrom(ListBox lb, int iFrom, bool bForward, string sNeedle)
        {
            int n = lb.Items.Count;
            if (n == 0 || string.IsNullOrEmpty(sNeedle)) return -1;
            if (iFrom < 0) iFrom = 0;
            if (iFrom >= n) iFrom = n - 1;
            string sLowerNeedle = sNeedle.ToLowerInvariant();
            for (int i = 0; i < n; i++)
            {
                int j = bForward
                    ? (iFrom + i) % n
                    : ((iFrom - i) % n + n) % n;
                string sItem = (lb.Items[j] ?? "").ToString().ToLowerInvariant();
                if (sItem.Contains(sLowerNeedle)) return j;
            }
            return -1;
        }

