        // ------- Widget lookup helpers -------
        //
        // Every widget added via add* methods is registered in
        // dWidgets under an auto-generated name of the form
        // <Kind>_<CleanedLabel>. These helpers let callers fetch
        // widgets by name without having to keep references.
        //
        // The name generator strips non-alphanumeric chars from
        // the label, replaces spaces with underscore, and appends
        // a 2/3/... suffix on collisions.

        public Control findControl(string sName)
        {
            if (string.IsNullOrEmpty(sName)) return null;
            Control ctl;
            if (dWidgets.TryGetValue(sName, out ctl)) return ctl;
            return null;
        }

        public TextBox       getTextBox(string sName)       { return findControl(sName) as TextBox; }
        public CheckBox      getCheckBox(string sName)      { return findControl(sName) as CheckBox; }
        public ComboBox      getComboBox(string sName)      { return findControl(sName) as ComboBox; }
        public ListBox       getListBox(string sName)       { return findControl(sName) as ListBox; }
        public RadioButton   getRadioButton(string sName)   { return findControl(sName) as RadioButton; }
        public NumericUpDown getNumericUpDown(string sName) { return findControl(sName) as NumericUpDown; }
        public Label         getLabel(string sName)         { return findControl(sName) as Label; }

        // Snapshot of every widget added so far, keyed by name.
        // Useful for callers that want to walk the whole dialog.
        public IDictionary<string, Control> widgets
        { get { return new Dictionary<string, Control>(dWidgets); } }

        // ------- Finish and show -------

        // runOkCancel: convenience wrapper. Returns true on OK.
        public bool runOkCancel()
        {
            return string.Equals(runWithButtons(new string[] { "OK", "Cancel" }),
                                 "OK", StringComparison.OrdinalIgnoreCase);
        }

        // runWithButtons: add a button band at the bottom, show
        // modally, return the label of the button the user pressed
        // (or "" on Escape/close-box). The first label is the
        // AcceptButton (Enter); any "Cancel" or "Close" label is
        // the CancelButton (Escape).
        // Initial-focus override: when set, this control receives
        // focus once the dialog is shown (Focus() before Shown is a
        // no-op). Form-view record navigation uses it to land on
        // the same field across reopen cycles.
        private Control ctlInitialFocus;
        public void setInitialFocus(Control ctl) { ctlInitialFocus = ctl; }

        public string runWithButtons(string[] aButtonLabels)
        {
            return runWithButtons(aButtonLabels, true);
        }

        // Every Lbc dialog carries a Help button, placed rightmost in
        // the button row per Windows layout convention (and reachable
        // as Alt+H or F1). It describes the dialog's fields with
        // their tips plus the universal dialog keys. bAddHelp lets
        // the help dialog itself opt out, preventing recursion.
        public string runWithButtons(string[] aButtonLabels, bool bAddHelp)
        {
            string[] aGivenLabels = aButtonLabels;
            if (bAddHelp && Array.IndexOf(aButtonLabels, "Help") < 0)
            {
                List<string> lsAll = new List<string>(aButtonLabels);
                lsAll.Add("Help");
                aButtonLabels = lsAll.ToArray();
            }
            FlowLayoutPanel pnlButtonRow = new FlowLayoutPanel();
            pnlButtonRow.FlowDirection = FlowDirection.RightToLeft;
            pnlButtonRow.AutoSize = false;
            pnlButtonRow.Dock = DockStyle.Bottom;
            pnlButtonRow.Height = DefaultButtonHeight + DefaultPadding * 2;
            pnlButtonRow.Padding = new Padding(DefaultPadding);

            string sResult = "";
            Button btnAccept = null;
            Button btnCancel = null;

            // Add buttons right-to-left so the visual order reads
            // left-to-right as given. RightToLeft FlowDirection
            // puts the first-added at the right; we want first-
            // given at the left, so iterate in reverse. TabIndex is
            // assigned by LABEL position (not add order) so keyboard
            // tab order and initial focus follow the visual left-to-
            // right order: the first-given button (the AcceptButton,
            // e.g. Custom) is focused first, and the rightmost Help
            // button is last -- never the initial focus.
            int iBtnBase = iTabIndex;
            for (int i = aButtonLabels.Length - 1; i >= 0; i--)
            {
                string sLabel = aButtonLabels[i] ?? "";
                Button btn = new Button();
                btn.Text = "&" + sLabel.Replace("&", "");
                btn.AccessibleName = sLabel.Replace("&", "");
                btn.Size = new Size(DefaultButtonWidth, DefaultButtonHeight);
                btn.TabIndex = iBtnBase + i;
                btn.Margin = new Padding(DefaultRowGap, 0, 0, 0);
                btn.UseVisualStyleBackColor = true;

                string sCaptured = sLabel.Replace("&", "");
                if (bAddHelp && string.Equals(sCaptured, "Help", StringComparison.OrdinalIgnoreCase))
                {
                    btn.Click += delegate(object o, EventArgs e) { showHelp(); };
                }
                else
                {
                    btn.Click += delegate(object o, EventArgs e) {
                        sResult = sCaptured;
                        frm.DialogResult = DialogResult.OK;
                        frm.Close();
                    };
                }
                registerWidget(btn, "Button", sCaptured);
                pnlButtonRow.Controls.Add(btn);
                if (i == 0) btnAccept = btn;
                if (string.Equals(sCaptured, "Cancel", StringComparison.OrdinalIgnoreCase)
                    || string.Equals(sCaptured, "Close", StringComparison.OrdinalIgnoreCase))
                    btnCancel = btn;
            }
            frm.Controls.Add(pnlButtonRow);
            if (btnAccept != null) frm.AcceptButton = btnAccept;
            if (btnCancel != null) frm.CancelButton = btnCancel;
            // Control+Enter presses the accept button regardless of
            // keyboard focus -- including inside a multi-line memo,
            // where plain Enter inserts a newline (AcceptsReturn) and
            // never reaches the AcceptButton. This is the classic
            // windowing-guidelines rule (Enter and Control+Return both
            // invoke the default action, Control+Return covering the
            // multiline case), and it gives every Lbc dialog one
            // universal "submit from anywhere" chord.
            // Universal dialog keys, handled at form level:
            //   Control+Enter  press the accept button from anywhere
            //                  (covers memos, where plain Enter
            //                  inserts a newline)
            //   F1             show the dialog's Help
            //   Control+Home   focus the FIRST field (excluding the
            //   Control+End    button row) / the LAST field -- except
            //                  inside a multi-line memo, where these
            //                  chords keep their caret meaning
            //                  (start / end of text), which a text
            //                  editor's muscle memory expects.
            //   F7             list every focusable control in
            //                  navigation order; OK moves focus to
            //                  the chosen one.
            {
                Button btnDefault = btnAccept;
                bool bHelpHere = bAddHelp;
                frm.KeyPreview = true;
                frm.KeyDown += delegate(object sender, KeyEventArgs evArgs)
                {
                    TextBox tbActive = frm.ActiveControl as TextBox;
                    bool bInMemo = (tbActive != null) && tbActive.Multiline;
                    if (evArgs.KeyData == (Keys.Control | Keys.Enter) && btnDefault != null)
                    {
                        evArgs.Handled = true;
                        evArgs.SuppressKeyPress = true;
                        btnDefault.PerformClick();
                    }
                    else if (evArgs.KeyData == Keys.F1 && bHelpHere)
                    {
                        evArgs.Handled = true;
                        evArgs.SuppressKeyPress = true;
                        showHelp();
                    }
                    else if (evArgs.KeyData == (Keys.Control | Keys.Home) && !bInMemo)
                    {
                        evArgs.Handled = true;
                        evArgs.SuppressKeyPress = true;
                        focusFieldEdge(true);
                    }
                    else if (evArgs.KeyData == (Keys.Control | Keys.End) && !bInMemo)
                    {
                        evArgs.Handled = true;
                        evArgs.SuppressKeyPress = true;
                        focusFieldEdge(false);
                    }
                    else if (evArgs.KeyData == Keys.F7)
                    {
                        evArgs.Handled = true;
                        evArgs.SuppressKeyPress = true;
                        pickFocusControl();
                    }
                };
            }
            // Single-button confirmation dialogs (e.g., the read-only
            // memo dialog used by Invoke-Script and the speech-only
            // double-press) typically only carry an "OK" button. With
            // no explicit Cancel button, the user would otherwise
            // have to Tab to OK and press Enter or Space to dismiss
            // -- Escape would do nothing. Wire that one button as
            // BOTH AcceptButton and CancelButton so Escape, Enter,
            // and the click all close the dialog with the same
            // result. This matches the LbcDialog principle "minimum
            // keystrokes to dismiss" and the user expectation that
            // Escape always works.
            if (btnCancel == null && btnAccept != null
                && aGivenLabels.Length == 1)
                frm.CancelButton = btnAccept;

            int iContentHeight = computeStackHeight();
            int iTotalHeight = iContentHeight + pnlButtonRow.Height
                             + lblStatusBar.Height + 8;
            if (iTotalHeight > DefaultMaxHeight) iTotalHeight = DefaultMaxHeight;
            if (iTotalHeight < 200) iTotalHeight = 200;
            frm.ClientSize = new Size(DefaultDialogWidth, iTotalHeight);

            if (ctlFirstFocusable != null) frm.ActiveControl = ctlFirstFocusable;
            if (ctlInitialFocus != null)
            {
                Control ctlFocusLater = ctlInitialFocus;
                frm.Shown += delegate(object o, EventArgs e)
                { try { ctlFocusLater.Focus(); } catch { } };
            }
            frm.ShowDialog(owner);
            return sResult;
        }

        // form: outer access for callers who need to tweak something
        // the high-level API doesn't expose (e.g., add an Icon).
        public Form form { get { return frm; } }

        public void Dispose()
        {
            if (frm != null) { frm.Dispose(); frm = null; }
        }

        // ------- Internal helpers (kept private) -------

        // currentLabelOrNull: the most-recently-added Label, if the
        // last control added was a Label. Returns null if the last
        // control was something else (or the stack is empty). Used
        // by bare-control adders to inherit the accessible name
        // from an immediately-preceding Label, mirroring the Homer
        // LbC convention where AddTextBox after AddLabel automatically
        // gets the label's AccessibleName.
        private Label currentLabelOrNull()
        {
            int iCount = pnlStack.Controls.Count;
            if (iCount == 0) return null;
            return pnlStack.Controls[iCount - 1] as Label;
        }

        // handleGotFocus: status-bar tip update on focus.
        // showHelp: the Help button / F1 target. Lists the dialog's
        // fields in layout order with their focus tips, then the
        // universal dialog keys. Shown in a read-only memo so the
        // user can arrow through it line by line; the help dialog
        // suppresses its own Help button (bAddHelp false) to avoid
        // recursion.
        public void showHelp()
        {
            string sTip;
            StringBuilder sbHelp = new StringBuilder();
            sbHelp.AppendLine("Fields in this dialog:");
            foreach (Control ctl in pnlStack.Controls)
            {
                if (ctl is Label) continue;
                string sName = string.IsNullOrEmpty(ctl.AccessibleName)
                    ? ctl.GetType().Name : ctl.AccessibleName;
                sbHelp.Append("  ").Append(sName);
                if (dFocusTips.TryGetValue(ctl, out sTip) && !string.IsNullOrEmpty(sTip))
                    sbHelp.Append(" -- ").Append(sTip);
                sbHelp.AppendLine();
            }
            sbHelp.AppendLine();
            sbHelp.AppendLine("Dialog keys:");
            sbHelp.AppendLine("  Control+Enter presses the accept button from anywhere.");
            sbHelp.AppendLine("  Control+Home and Control+End move to the first and last field (outside multi-line text, where they move the caret).");
            sbHelp.AppendLine("  Escape cancels. F1 shows this help.");
            sbHelp.AppendLine("  F7 lists the dialog's controls in navigation order; choose one and press OK to focus it (type a letter to jump in the list).");
            sbHelp.AppendLine("  In text fields: Control+C copies the current line when nothing is selected, Alt+C appends, Control+X cuts the line, Control+D deletes it, F8 and Shift+F8 start and complete a selection, Control+F8 copies all, Alt+F8 reads all, Alt+Y says counts, Shift+F1 speaks the field tip.");
            sbHelp.AppendLine("  In lists: Control+C copies the current item, Alt+C appends it; Control+J then F3 search the list.");
            using (LbcDialog dlgHelp = new LbcDialog("Help: " + frm.Text, frm))
            {
                TextBox tbHelp = dlgHelp.addMemo(sbHelp.ToString(), null);
                tbHelp.ReadOnly = true;
                tbHelp.AccessibleName = "Help text";
                dlgHelp.runWithButtons(new string[] { "OK" }, false);
            }
        }

        // pickFocusControl: the F7 control list. Presents every
        // focusable control in the dialog -- content fields first in
        // navigation (tab) order, then the button row in visual
        // left-to-right order -- in a list box. The ListBox's native
        // type-a-letter behavior gives navigation by initial letter;
        // invoking OK moves focus to the chosen control. The idiom
        // mirrors a screen reader's elements list (JAWS Insert+F7),
        // scoped to the dialog. The chooser suppresses its own Help
        // button to stay lightweight; F7 inside it simply lists the
        // chooser's controls, which is harmless.
        private void pickFocusControl()
        {
            Dictionary<string, Control> dByName = new Dictionary<string, Control>();
            List<string> lsNames = new List<string>();
            string sCurrent = null;
            foreach (Control ctl in pnlStack.Controls)
                addFocusEntry(ctl, lsNames, dByName);
            // The button row is a sibling FlowLayoutPanel whose
            // Controls collection is stored right-to-left (see
            // runWithButtons); reverse it for navigation order.
            foreach (Control ctlTop in frm.Controls)
            {
                FlowLayoutPanel pnlRow = ctlTop as FlowLayoutPanel;
                if (pnlRow == null || pnlRow == pnlStack) continue;
                List<Control> lsRow = new List<Control>();
                foreach (Control ctl in pnlRow.Controls) lsRow.Add(ctl);
                lsRow.Reverse();
                foreach (Control ctl in lsRow) addFocusEntry(ctl, lsNames, dByName);
            }
            if (lsNames.Count == 0) { LiveRegion.say("No focusable controls"); return; }
            Control ctlActive = frm.ActiveControl;
            foreach (KeyValuePair<string, Control> pair in dByName)
            {
                if (pair.Value == ctlActive) { sCurrent = pair.Key; break; }
            }
            using (LbcDialog dlgPick = new LbcDialog("Controls: " + frm.Text, frm))
            {
                ListBox lb = dlgPick.addListBox("Choose a control to focus:",
                    lsNames, sCurrent != null ? sCurrent : lsNames[0]);
                if (!string.Equals(dlgPick.runWithButtons(new string[] { "OK", "Cancel" }, false),
                        "OK", StringComparison.OrdinalIgnoreCase)) return;
                string sChosen = (lb.SelectedItem != null) ? lb.SelectedItem.ToString() : null;
                Control ctlTarget;
                if (sChosen != null && dByName.TryGetValue(sChosen, out ctlTarget))
                    ctlTarget.Focus();
            }
        }

        // pressButton: programmatically invoke a button-row button
        // by its label (mnemonics ignored) -- the hook form-view
        // keys use to close-with-save (OK) or close-discarding
        // (Cancel) from inside a field handler, reusing the
        // button's own wiring.
        public bool pressButton(string sLabel)
        {
            foreach (Control ctlTop in frm.Controls)
            {
                FlowLayoutPanel pnlRow = ctlTop as FlowLayoutPanel;
                if (pnlRow == null || pnlRow == pnlStack) continue;
                foreach (Control ctl in pnlRow.Controls)
                {
                    Button btn = ctl as Button;
                    if (btn != null && string.Equals(btn.Text.Replace("&", ""), sLabel,
                            StringComparison.OrdinalIgnoreCase))
                    { btn.PerformClick(); return true; }
                }
            }
            return false;
        }

        // addFocusEntry: register one focusable control under a
        // unique display name (AccessibleName, else button text, else
        // type name; duplicates get a numeric suffix).
        private void addFocusEntry(Control ctl, List<string> lsNames, Dictionary<string, Control> dByName)
        {
            if (ctl is Label || !ctl.CanSelect || !ctl.Visible) return;
            string sBase = !string.IsNullOrEmpty(ctl.AccessibleName) ? ctl.AccessibleName
                : (!string.IsNullOrEmpty(ctl.Text) ? ctl.Text.Replace("&", "") : ctl.GetType().Name);
            string sName = sBase;
            int iSuffix = 2;
            while (dByName.ContainsKey(sName)) { sName = sBase + " " + iSuffix; iSuffix++; }
            lsNames.Add(sName);
            dByName[sName] = ctl;
        }

        // focusFieldEdge: Control+Home/End target -- the first or
        // last selectable field in the content stack. The button row
        // lives outside pnlStack, so OK, Cancel, and Help are
        // excluded by construction.
        private void focusFieldEdge(bool bFirst)
        {
            Control ctlTarget = null;
            foreach (Control ctl in pnlStack.Controls)
            {
                if (ctl is Label || !ctl.CanSelect) continue;
                ctlTarget = ctl;
                if (bFirst) break;
            }
            if (ctlTarget != null) ctlTarget.Focus();
        }

        // setStatusText: put a message on the dialog's status line --
        // the same line that shows focus tips, so the user already
        // knows where to look (and JAWS users can reread it with the
        // say-status-bar hotkey).
        public void setStatusText(string sText)
        {
            if (lblStatusBar != null) lblStatusBar.Text = sText ?? "";
        }

        private void handleGotFocus(object sender, EventArgs evArgs)
        {
            Control ctl = sender as Control;
            if (ctl == null) { lblStatusBar.Text = ""; return; }
            string sTip;
            lblStatusBar.Text = dFocusTips.TryGetValue(ctl, out sTip) ? sTip : "";
        }

        // handleMemoGotFocus: while a memo has focus, Enter must
        // insert a newline instead of submitting. Clear the form's
        // AcceptButton (remembering it for restore on LostFocus).
        // Also update the status bar.
        private void handleMemoGotFocus(object sender, EventArgs evArgs)
        {
            if (frm.AcceptButton != null)
                btnSavedAccept = frm.AcceptButton as Button;
            frm.AcceptButton = null;
            handleGotFocus(sender, evArgs);
        }

        // handleMemoLostFocus: restore the AcceptButton when the
        // memo loses focus, so Enter from a subsequent single-line
        // field submits as expected.
        private void handleMemoLostFocus(object sender, EventArgs evArgs)
        {
            if (btnSavedAccept != null && frm.AcceptButton == null)
                frm.AcceptButton = btnSavedAccept;
        }

        // ------- Text-edit convenience hotkeys -------
        //
        // When the focused control inside the LbcDialog is a single-
        // line TextBox (Name starts with "TextBox_") or a multi-line
        // memo (Name starts with "Memo_"), the following hotkeys are
        // recognized in addition to standard text-edit behavior:
        //
        //   Ctrl+C    Copy. If text is selected, copy selection
        //             (default behavior). If no selection, copy the
        //             current line to the clipboard.
        //   Alt+C     Append to clipboard. If selected, append the
        //             selection; if no selection, append the current
        //             line. Preserves the existing clipboard content;
        //             the new piece is added on a fresh line.
        //   Ctrl+X    Cut. If selected, cut the selection (default).
        //             If no selection, cut the current line and
        //             speak the next line as feedback.
        //   Alt+X     Cut + append. Like Alt+C but removes the cut
        //             text from the buffer after appending.
        //   F8        Mark the start of a selection at the current
        //             caret position. The position is stashed in
        //             tb.Tag. The character at the start is spoken
        //             as a confirmation.
        //   Shift+F8  Complete the selection from the saved start to
        //             the current caret. Highlights the range; the
        //             length is announced.
        //   Ctrl+F8   Copy ALL text in the field to the clipboard.
        //             Status bar reports "Copy All".
        //   Alt+F8    Speak ALL text in the field via the live
        //             region. Status bar reports "Read All".
        //   Ctrl+D    Delete the current line. The next line is
        //             spoken as feedback so the user knows where the
        //             caret ended up.
        //   Shift+F5  Run at Cursor. Take the selection (or current
        //             line) as a URL, file path, or address, and open
        //             it with the OS after a confirmation prompt.
        //
        // None of the above conflicts with standard control behavior:
        // F8, Shift+F8, Ctrl+F8, Alt+F8 are unbound in standard
        // WinForms TextBoxes; Ctrl+D is unbound; the Ctrl+C / Ctrl+X
        // overrides only act when there is no selection (the standard
        // Copy and Cut don't do anything without a selection); the
        // Alt+ variants are unbound. Pattern adapted from HomerLbc's
        // convenience hotkeys for text fields.
        //
        // Master enable flag: [Lbc] extraKeys in DbDo.inix, default Y.
        // When N, all of the above hotkeys are passed through to
        // standard control handling.

        private static bool? bExtraKeysCached = null;
        private static bool isExtraKeysOn()
        {
            if (bExtraKeysCached.HasValue) return bExtraKeysCached.Value;
            bool bDefault = true;
            try
            {
                string sIniPath = Path.Combine(
                    Path.GetDirectoryName(Application.ExecutablePath) ?? ".",
                    "DbDo.inix");
                if (!File.Exists(sIniPath)) { bExtraKeysCached = bDefault; return bDefault; }
                bool bInLbcSection = false;
                foreach (string sLine in File.ReadAllLines(sIniPath))
                {
                    string sTrim = sLine.Trim();
                    if (sTrim.Length == 0 || sTrim.StartsWith(";") || sTrim.StartsWith("#")) continue;
                    if (sTrim.StartsWith("["))
                    {
                        bInLbcSection = sTrim.Equals("[Lbc]", StringComparison.OrdinalIgnoreCase);
                        continue;
                    }
                    if (!bInLbcSection) continue;
                    int iEq = sTrim.IndexOf('=');
                    if (iEq <= 0) continue;
                    string sName = sTrim.Substring(0, iEq).Trim();
                    if (!sName.Equals("ExtraKeys", StringComparison.OrdinalIgnoreCase)) continue;
                    string sVal = sTrim.Substring(iEq + 1).Trim();
                    if (sVal.Length == 0) { bExtraKeysCached = bDefault; return bDefault; }
                    char c = sVal[0];
                    bExtraKeysCached = !(c == 'N' || c == 'n' || c == '0' || c == 'F' || c == 'f');
                    return bExtraKeysCached.Value;
                }
            }
            catch { /* tolerate; fall through to default */ }
            bExtraKeysCached = bDefault;
            return bDefault;
        }

        // textEditEligible: is the focused control a single-line text
        // box or a multi-line memo that DbDo registered via the
        // standard add* methods? Pattern matches the Name prefix that
        // registerWidget assigns (TextBox_ or Memo_).
        private static TextBox textEditEligible(Control ctl)
        {
            TextBox tb = ctl as TextBox;
            if (tb == null) return null;
            string sName = tb.Name ?? "";
            if (!sName.StartsWith("TextBox_") && !sName.StartsWith("Memo_")) return null;
            if (tb.ReadOnly) return null;
            return tb;
        }

        // onFormKeyDown: form-level KeyDown handler for the LbcDialog.
        // Frm.KeyPreview is on, so this fires before the focused
        // control sees the key. We intercept the
        // chords listed in the section header and pass everything
        // else through.
        private void onFormKeyDown(object sender, KeyEventArgs evArgs)
        {
            if (!isExtraKeysOn()) return;
            // GetFocus via active control on the form.
            Control ctl = getActiveControl();
            TextBox tb = textEditEligible(ctl);
            if (tb == null) return;

            Keys k = evArgs.KeyData;
            bool bHandled = true;

            if      (k == Keys.F8)                          textEditStartSelection(tb);
            else if (k == (Keys.Shift   | Keys.F8))         textEditCompleteSelection(tb);
            else if (k == (Keys.Control | Keys.F8))         textEditCopyAll(tb);
            else if (k == (Keys.Alt     | Keys.F8))         textEditReadAll(tb);
            else if (k == (Keys.Control | Keys.C))          { if (tb.SelectionLength > 0) bHandled = false; else textEditCopyLine(tb); }
            else if (k == (Keys.Alt     | Keys.C))          textEditAppendLineToClipboard(tb);
            else if (k == (Keys.Control | Keys.X))          { if (tb.SelectionLength > 0) bHandled = false; else textEditCutLine(tb); }
            else if (k == (Keys.Alt     | Keys.X))          textEditCutAppend(tb);
            else if (k == (Keys.Control | Keys.D))          textEditDeleteLine(tb);
            else if (k == (Keys.Shift   | Keys.F5))         textEditRunAtCursor(tb);
            else                                            bHandled = false;

            if (bHandled)
            {
                evArgs.Handled = true;
                evArgs.SuppressKeyPress = true;
            }
        }

        // getActiveControl: walk the active-control chain to find the
        // deepest focused control. Form.ActiveControl can return a
        // container; we descend through ContainerControls to the leaf.
        private Control getActiveControl()
        {
            Control ctl = frm.ActiveControl;
            while (ctl is ContainerControl)
            {
                Control child = ((ContainerControl)ctl).ActiveControl;
                if (child == null || child == ctl) break;
                ctl = child;
            }
            return ctl;
        }

        // Compute the (start, length) of the line containing the
        // current caret in tb. Used by every line-oriented hotkey.
        // The line END is computed as the start of the NEXT line
        // minus 1 (to exclude the trailing newline), or the end of
        // the text when on the last line.
        private static void textEditCurrentLineRange(TextBox tb, out int iStart, out int iLength)
        {
            int iCaret = tb.SelectionStart + tb.SelectionLength;
            int iRow = tb.GetLineFromCharIndex(iCaret);
            iStart = tb.GetFirstCharIndexFromLine(iRow);
            int iEnd = tb.GetFirstCharIndexFromLine(iRow + 1);
            if (iEnd <= 0) iEnd = tb.TextLength;
            else iEnd--;
            iLength = iEnd - iStart;
            if (iLength < 0) iLength = 0;
        }

        // F8 -- mark the start of a selection at the current caret.
        // The position is stored in tb.Tag as a boxed int. The char
        // at the start is spoken as a confirmation.
        private void textEditStartSelection(TextBox tb)
        {
            int iCaret = tb.SelectionStart + tb.SelectionLength;
            tb.Tag = iCaret;
            lblStatusBar.Text = "Start Selection";
            string sCh = iCaret < tb.TextLength ? tb.Text.Substring(iCaret, 1) : "end";
            LiveRegion.say("Start selection " + sCh);
        }

        // Shift+F8 -- complete a selection from the saved start to
        // the current caret. If no start was saved, fall back to
        // marking start at the current caret (so the user can press
        // F8 then Shift+F8 after another navigation step in either
        // order). Length is announced.
        private void textEditCompleteSelection(TextBox tb)
        {
            if (tb.Tag == null)
            {
                textEditStartSelection(tb);
                return;
            }
            int iStart;
            try { iStart = (int)tb.Tag; }
            catch { textEditStartSelection(tb); return; }
            int iEnd = tb.SelectionStart + tb.SelectionLength;
            if (iEnd < iStart) { int t = iStart; iStart = iEnd; iEnd = t; }
            int iLength = iEnd - iStart;
            tb.Select(iStart, iLength);
            lblStatusBar.Text = "Complete Selection, " + iLength + " character" + (iLength == 1 ? "" : "s");
            LiveRegion.say("Selected " + iLength + " character" + (iLength == 1 ? "" : "s"));
        }

        // Ctrl+F8 -- copy ALL text in the field to the clipboard.
        private void textEditCopyAll(TextBox tb)
        {
            try
            {
                Clipboard.SetText(tb.Text.Length == 0 ? " " : tb.Text);
                lblStatusBar.Text = "Copy All";
                LiveRegion.say("Copied all, " + tb.TextLength + " character" + (tb.TextLength == 1 ? "" : "s"));
            }
            catch { LiveRegion.say("Could not copy"); }
        }

        // Alt+F8 -- speak ALL text in the field via the live region.
        private void textEditReadAll(TextBox tb)
        {
            lblStatusBar.Text = "Read All";
            LiveRegion.say(tb.Text);
        }

        // Ctrl+C with no selection -- copy the current line.
        private void textEditCopyLine(TextBox tb)
        {
            int iStart, iLength;
            textEditCurrentLineRange(tb, out iStart, out iLength);
            string sLine = tb.Text.Substring(iStart, iLength);
            try { Clipboard.SetText(sLine.Length == 0 ? " " : sLine); }
            catch { LiveRegion.say("Could not copy"); return; }
            lblStatusBar.Text = "Copy Line";
            LiveRegion.say("Copied line");
        }

        // Alt+C -- append the current line (or selection) to the
        // existing clipboard contents, separated by a newline.
        private void textEditAppendLineToClipboard(TextBox tb)
        {
            string sExisting;
            try { sExisting = Clipboard.GetText() ?? ""; }
            catch { sExisting = ""; }
            if (sExisting.Length > 0 && !sExisting.EndsWith("\n")) sExisting += "\r\n";
            string sAdd;
            if (tb.SelectionLength > 0)
            {
                sAdd = tb.SelectedText;
            }
            else
            {
                int iStart, iLength;
                textEditCurrentLineRange(tb, out iStart, out iLength);
                sAdd = tb.Text.Substring(iStart, iLength);
            }
            try { Clipboard.SetText(sExisting + sAdd); }
            catch { LiveRegion.say("Could not append"); return; }
            lblStatusBar.Text = "Append to Clipboard";
            LiveRegion.say("Appended");
        }

        // Ctrl+X with no selection -- cut the current line.
        private void textEditCutLine(TextBox tb)
        {
            int iStart, iLength;
            textEditCurrentLineRange(tb, out iStart, out iLength);
            // Include the trailing newline if there is a next line
            // so the cut doesn't leave a blank line behind.
            int iCutLen = iLength;
            if (iStart + iLength < tb.TextLength)
                iCutLen = iLength + 1; // include "\n" or "\r"
            // Account for possible "\r\n" sequence -- TextBox uses
            // "\r\n" line endings on Windows; the row index treats
            // a single "\r\n" as one line break, so iEnd-1 already
            // excludes the "\n"; we also strip the "\r" by extending
            // by 1.
            if (iCutLen > 0 && iStart + iCutLen < tb.TextLength
                && tb.Text[iStart + iCutLen] == '\n')
                iCutLen++;
            string sLine = tb.Text.Substring(iStart, iCutLen);
            try { Clipboard.SetText(sLine.Length == 0 ? " " : sLine); }
            catch { LiveRegion.say("Could not cut"); return; }
            tb.Text = tb.Text.Remove(iStart, iCutLen);
            tb.SelectionStart = Math.Min(iStart, tb.TextLength);
            tb.SelectionLength = 0;
            lblStatusBar.Text = "Cut Line";
            // Speak the next line as feedback (the line that's now
            // at the caret).
            int iNextStart, iNextLen;
            textEditCurrentLineRange(tb, out iNextStart, out iNextLen);
            string sNext = tb.Text.Substring(iNextStart, iNextLen);
            LiveRegion.say(sNext.Length > 0 ? "Cut, now: " + sNext : "Cut, end of text");
        }

        // Alt+X -- cut current line / selection AND append to
        // clipboard. After the cut, the clipboard holds existing
        // contents plus the cut text (separator is a newline).
        private void textEditCutAppend(TextBox tb)
        {
            string sExisting;
            try { sExisting = Clipboard.GetText() ?? ""; }
            catch { sExisting = ""; }
            if (sExisting.Length > 0 && !sExisting.EndsWith("\n")) sExisting += "\r\n";

            string sAdd;
            int iStart, iLength;
            if (tb.SelectionLength > 0)
            {
                iStart = tb.SelectionStart;
                iLength = tb.SelectionLength;
                sAdd = tb.SelectedText;
            }
            else
            {
                textEditCurrentLineRange(tb, out iStart, out iLength);
                sAdd = tb.Text.Substring(iStart, iLength);
                // Include trailing "\n" so cut doesn't leave blank line
                if (iStart + iLength < tb.TextLength) iLength++;
                if (iLength > 0 && iStart + iLength < tb.TextLength
                    && tb.Text[iStart + iLength] == '\n') iLength++;
            }
            try { Clipboard.SetText(sExisting + sAdd); }
            catch { LiveRegion.say("Could not append"); return; }
            tb.Text = tb.Text.Remove(iStart, iLength);
            tb.SelectionStart = Math.Min(iStart, tb.TextLength);
            tb.SelectionLength = 0;
            lblStatusBar.Text = "Cut and Append";
            LiveRegion.say("Cut, appended");
        }

        // Ctrl+D -- delete the current line; speak the next line as
        // feedback. Does not touch the clipboard.
        private void textEditDeleteLine(TextBox tb)
        {
            int iStart, iLength;
            textEditCurrentLineRange(tb, out iStart, out iLength);
            int iCutLen = iLength;
            if (iStart + iLength < tb.TextLength) iCutLen++;
            if (iCutLen > 0 && iStart + iCutLen < tb.TextLength
                && tb.Text[iStart + iCutLen] == '\n') iCutLen++;
            tb.Text = tb.Text.Remove(iStart, iCutLen);
            tb.SelectionStart = Math.Min(iStart, tb.TextLength);
            tb.SelectionLength = 0;
            lblStatusBar.Text = "Delete Line";
            int iNextStart, iNextLen;
            textEditCurrentLineRange(tb, out iNextStart, out iNextLen);
            string sNext = tb.Text.Substring(iNextStart, iNextLen);
            LiveRegion.say(sNext.Length > 0 ? "Deleted, now: " + sNext : "Deleted, end of text");
        }

        // Shift+F5 -- Run at Cursor. Take the selected text, or the current
        // line when nothing is selected, clean it, apply light URL/email
        // heuristics, and (after a confirmation prompt) launch it with the
        // OS: a URL opens in the browser, a file path opens the file, an
        // address opens the mail app. Open-at-cursor behavior;
        // the confirmation step lets the user verify or edit the target
        // before anything is launched, which matters more here since the
        // text comes straight from a data field.
        private void textEditRunAtCursor(TextBox tb)
        {
            string sText;
            if (tb.SelectionLength > 0) sText = tb.SelectedText;
            else
            {
                int iStart, iLength;
                textEditCurrentLineRange(tb, out iStart, out iLength);
                sText = tb.Text.Substring(iStart, iLength);
            }
            // Clean: collapse embedded newlines to a space, then strip a
            // leading "<" or spaces and a trailing ">", spaces, or sentence
            // dots so an address pasted mid-sentence works.
            sText = System.Text.RegularExpressions.Regex.Replace(sText ?? "", "[\r\n]+", " ");
            sText = System.Text.RegularExpressions.Regex.Replace(sText, "^[<\\s]+", "");
            sText = System.Text.RegularExpressions.Regex.Replace(sText, "[>\\s.]+$", "");
            sText = sText.Trim();
            if (sText.Length == 0) { LiveRegion.say("Nothing at the cursor to run."); return; }

            string sLower = sText.ToLowerInvariant();
            if (sText.Contains("://")) { /* already a full URL */ }
            else if (sLower.StartsWith("www.")) sText = "http://" + sText;
            else if (sText.Contains("@") && !sLower.StartsWith("mailto:")) sText = "mailto:" + sText;

            string sTarget;
            using (LbcDialog dlg = new LbcDialog("Run at Cursor", frm))
            {
                dlg.addLabel("Open this with your system (a URL opens in your browser,");
                dlg.addLabel("a file path opens the file, an address opens your mail app):");
                TextBox tbT = dlg.addInputBox("&Target:", sText);
                if (!string.Equals(dlg.runWithButtons(new string[] { "Open", "Cancel" }),
                        "Open", StringComparison.OrdinalIgnoreCase))
                    return;
                sTarget = (tbT.Text ?? "").Trim();
            }
            if (sTarget.Length == 0) return;
            try
            {
                System.Diagnostics.Process.Start(sTarget);
                LiveRegion.say("Opening " + sTarget);
            }
            catch (Exception ex)
            {
                ErrorDialog.show(frm, "Run at Cursor", "Could not open:\r\n\r\n" + sTarget + "\r\n\r\n" + ex.Message);
            }
        }

        // registerWidget: store the control under an auto-generated
        // name <Kind>_<CleanedLabel> in dWidgets. On collisions a
        // numeric suffix is appended (TextBox_Name, TextBox_Name_2).
        private void registerWidget(Control ctl, string sKind, string sLabel)
        {
            string sClean = makeIdentifier(sLabel);
            string sBase = sKind + "_" + sClean;
            string sName = sBase;
            int iCount;
            if (dNameCounts.TryGetValue(sBase, out iCount) && iCount > 0)
                sName = sBase + "_" + (iCount + 1);
            dNameCounts[sBase] = (dNameCounts.ContainsKey(sBase) ? dNameCounts[sBase] : 0) + 1;
            ctl.Name = sName;
            dWidgets[sName] = ctl;
        }

        // makeIdentifier: turn a label into a programmer-friendly
        // identifier suffix. Strips '&' and ':', maps any run of
        // non-alphanumeric to a single underscore, trims leading
        // and trailing underscores, falls back to "field" on empty.
        private static string makeIdentifier(string sLabel)
        {
            if (string.IsNullOrEmpty(sLabel)) return "field";
            StringBuilder sb = new StringBuilder();
            bool bLastWasUnderscore = true; // suppress leading
            foreach (char c in sLabel)
            {
                if (char.IsLetterOrDigit(c)) { sb.Append(c); bLastWasUnderscore = false; }
                else if (!bLastWasUnderscore) { sb.Append('_'); bLastWasUnderscore = true; }
            }
            string s = sb.ToString();
            if (s.EndsWith("_")) s = s.Substring(0, s.Length - 1);
            return s.Length > 0 ? s : "field";
        }

        // The horizontal space inside the stack panel for a control,
        // accounting for padding and a scrollbar reservation.
        private int innerWidth()
        {
            return DefaultDialogWidth - DefaultPadding * 2 - 24;
        }

        // cleanLabel: strip '&' mnemonic markers and trailing ':'
        // before using a label as an AccessibleName.
        private string cleanLabel(string sLabel)
        {
            if (string.IsNullOrEmpty(sLabel)) return "";
            string s = sLabel.Replace("&", "");
            if (s.EndsWith(":")) s = s.Substring(0, s.Length - 1);
            return s.Trim();
        }

        // addFieldLabel: emit a Label above a field control. Reused
        // by every labeled-control adder (addInputBox, addMemoBox,
        // addPickBox, addComboPickBox, addNumericUpDown).
        private void addFieldLabel(string sText)
        {
            if (string.IsNullOrEmpty(sText)) return;
            Label lbl = new Label();
            lbl.Text = sText;
            lbl.AccessibleName = cleanLabel(sText);
            lbl.AutoSize = false;
            lbl.Size = new Size(innerWidth(), DefaultLabelHeight);
            lbl.Margin = new Padding(0, 0, 0, 0);
            lbl.TextAlign = ContentAlignment.MiddleLeft;
            pnlStack.Controls.Add(lbl);
        }

        // populateListBox: shared logic for filling a ListBox with
        // strings and pre-selecting one.
        private void populateListBox(ListBox lb, IList<string> lNames, string sSelected)
        {
            if (lNames == null) return;
            foreach (string sN in lNames) lb.Items.Add(sN);
            int iSel = -1;
            if (!string.IsNullOrEmpty(sSelected))
            {
                for (int i = 0; i < lb.Items.Count; i++)
                {
                    if (string.Equals(lb.Items[i].ToString(), sSelected,
                            StringComparison.OrdinalIgnoreCase))
                    { iSel = i; break; }
                }
            }
            if (iSel < 0 && lb.Items.Count > 0) iSel = 0;
            if (iSel >= 0) lb.SelectedIndex = iSel;
        }

        // populateComboBox: shared logic for filling a ComboBox.
        private void populateComboBox(ComboBox cb, IList<string> lNames, string sSelected)
        {
            if (lNames == null) return;
            foreach (string sN in lNames) cb.Items.Add(sN);
            int iSel = -1;
            if (!string.IsNullOrEmpty(sSelected))
            {
                for (int i = 0; i < cb.Items.Count; i++)
                {
                    if (string.Equals(cb.Items[i].ToString(), sSelected,
                            StringComparison.OrdinalIgnoreCase))
                    { iSel = i; break; }
                }
            }
            if (iSel < 0 && cb.Items.Count > 0) iSel = 0;
            if (iSel >= 0) cb.SelectedIndex = iSel;
        }

        // computeStackHeight: sum heights of stack children plus
        // margins. Used to choose an initial dialog height.
        private int computeStackHeight()
        {
            int iTotal = pnlStack.Padding.Vertical;
            foreach (Control c in pnlStack.Controls)
                iTotal += c.Height + c.Margin.Vertical;
            return iTotal + 8;
        }
    }

    // =====================================================================
    // RecordEditDialog: dynamic per-column field editor. Builds a
    // label + text box per column from a list of column names. The
    // caller passes initial values and an editable-flags list (false
    // marks a column read-only -- typically for primary key columns).
    // OK populates dValues with the final field values.
    // =====================================================================
    // =====================================================================
    // RecordEditDialog: dynamic per-column field editor. Builds a
    // labeled text input per column from a list of column names.
    // The caller passes initial values, an editable-flags list (false
    // marks a column read-only -- typically for primary key columns),
    // and the manager so the dialog can ask each column whether its
    // declared type is 'textmemo' (multi-line) or 'textline' / other
    // (single-line). OK populates dValues with the final field values.
    //
    // Built on top of LbcDialog so it gets the focus-tip status bar,
    // name-based widget lookup, AcceptButton-vs-memo coordination,
    // and all the layout polish for free. Single-line columns use
    // addInputBox; multi-line columns (declared textmemo) use
    // addMemoBox.
    //
    // The textline/textmemo convention: in CREATE TABLE statements,
    // declare single-line columns as 'textline' and multi-line ones
    // as 'textmemo'. SQLite stores both with TEXT affinity (the
    // declared type is purely a hint for tools), but PRAGMA table_info
    // round-trips the declared type verbatim, so DbDo can read it
    // back. Columns declared 'text' or anything else fall back to
    // single-line. Access provides the same distinction via ADOX
    // type codes (adLongVarWChar/adLongVarChar = memo).
    //
    // The constructor's API matches the prior version with one extra
    // parameter (the manager); existing callers update with one line.
    // The dialog is exposed as a class with an `OK` boolean and a
    // `dValues` result dictionary instead of being a Form subclass,
    // since LbcDialog is the actual Form now.
    // =====================================================================
    public class RecordEditDialog : IDisposable
    {
        public bool                        ok;        // true if user pressed OK
        public Dictionary<string, string>  dValues;   // final field values
        public int                         iFocusIndex;   // field index focused at close (restored across reopens)
        public int                         iNavigate;     // form-view verdict: 0 none, 1 next record, -1 previous, 2 delete current
        public int                         iViewSwitch;   // view-cycle verdict: 0 none, 1 forward (F6), -1 back (Shift+F6)
        public List<string>                lsNullFields;  // fields explicitly set to SQL NULL

        private LbcDialog                  dlg;
        private List<string>               lColumnNames;
        private List<TextBox>              lTextBoxes;
        private List<List<string>>         lLookupLists;  // per field: lookup values, or null when none
        private List<string>               lDeclaredTypes;
        private DbDoManager               mgr;
        private string                     sTableName;

        public RecordEditDialog(string sTitle,
                                List<string> lColumns,
                                Dictionary<string, string> dInitial,
                                List<bool> lEditable,
                                DbDoManager inputMgr)
        {
            ok = false;
            dValues = new Dictionary<string, string>();
            iFocusIndex = 0;
            iNavigate = 0;
            iViewSwitch = 0;
            lsNullFields = new List<string>();
            lColumnNames = new List<string>();
            lTextBoxes = new List<TextBox>();
            lLookupLists = new List<List<string>>();
            lDeclaredTypes = new List<string>();
            mgr = inputMgr;
            sTableName = (inputMgr != null) ? inputMgr.currentTable : "";

            dlg = new LbcDialog(sTitle, null);

            // Build one row per column. The widget kind comes from
            // the declared type:
            //   - textmemo, memo, longvarchar: tall multi-line memo
            //     box with the label on the row ABOVE the box
            //   - everything else: single-line input box with the
            //     label and the textbox sharing one row inline
            //
            // The two layouts are intentional. A single-line field
            // gets "Label: __textbox__" inline, mirroring how the
            // user-guide convention shows fields. A multi-line memo
            // gets the label on its own row above so the (tall) memo
            // box has the full row width.
            //
            // Type-aware display: for integer/real/numeric declared
            // types, the initial value goes through a string
            // round-trip that normalizes any locale-specific
            // thousands separators ("1,234" -> "1234") and trims
            // trailing zeros. Validation on OK re-parses the value
            // and refuses to close if a numeric field has non-
            // numeric content.
            // Per-field documentation from the table's --- schema
            // comments, so Shift+F1 on a field speaks the field's
            // purpose -- the field-level help the Contact Tracking
            // System pioneered, realized here through DbDo's own
            // schema-doc convention. Fields whose column carries no
            // doc comment are left exactly as before.
            Dictionary<string, string> dColumnDoc =
                new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
            if (inputMgr != null)
            {
                try
                {
                    List<string[]> lsTblDoc;
                    List<string[]> lsColDoc;
                    if (inputMgr.getSchemaDoc(sTableName, out lsTblDoc, out lsColDoc))
                        foreach (string[] aPair in lsColDoc)
                            if (aPair.Length == 2 && !dColumnDoc.ContainsKey(aPair[0]))
                                dColumnDoc[aPair[0]] = aPair[1];
                }
                catch { }
            }

            for (int i = 0; i < lColumns.Count; i++)
            {
                string sCol = lColumns[i];
                lColumnNames.Add(sCol);
                string sValue = (dInitial != null && dInitial.ContainsKey(sCol))
                                ? dInitial[sCol] : "";
                bool bEditable = (lEditable == null
                                  || i >= lEditable.Count
                                  || lEditable[i]);

                string sDeclared = (inputMgr != null)
                    ? inputMgr.getColumnDeclaredType(sTableName, sCol)
                    : "";
                lDeclaredTypes.Add(sDeclared ?? "");

                // Format for display.
                string sDisplay = convertForDisplay(sValue, sDeclared);

                // Tip: type plus optional read-only marker plus the
                // regex constraint string from DbDo.inix if one is
                // configured for <table>.<column>.
                string sRegex = lookupFieldRegex(sCol);
                StringBuilder sbTip = new StringBuilder();
                string sColDoc;
                if (dColumnDoc.TryGetValue(sCol, out sColDoc) && !string.IsNullOrEmpty(sColDoc))
                    sbTip.Append(sColDoc);
                if (!string.IsNullOrEmpty(sDeclared))
                {
                    if (sbTip.Length > 0) sbTip.Append(" -- ");
                    sbTip.Append("type ").Append(sDeclared);
                }
                if (!bEditable)
                {
                    if (sbTip.Length > 0) sbTip.Append(' ');
                    sbTip.Append("(read-only)");
                }
                if (!string.IsNullOrEmpty(sRegex))
                {
                    if (sbTip.Length > 0) sbTip.Append(' ');
                    sbTip.Append("must match ").Append(sRegex);
                }
                // Lookups-driven pick list: when the builtin lookups
                // table offers values for this table+field pair, F4
                // or Alt+DownArrow opens a pick list -- the universal
                // Windows open-the-combo pair -- and the field's tip
                // says so, which the dialog's status line speaks and
                // shows on focus.
                List<string> lsLookups = (inputMgr != null)
                    ? inputMgr.getLookupValues(sTableName, sCol, 500)
                    : new List<string>();
                if (lsLookups.Count > 0)
                {
                    if (sbTip.Length > 0) sbTip.Append(' ');
                    sbTip.Append("F4 picks from ").Append(lsLookups.Count)
                        .Append(lsLookups.Count == 1 ? " value" : " values");
                }
                string sTip = sbTip.ToString();

                bool bMultiline = (inputMgr != null)
                    && inputMgr.isMultilineColumn(sTableName, sCol);
                if (inputMgr != null && inputMgr.isMarkdownColumn(sTableName, sCol))
                {
                    if (sbTip.Length > 0) sbTip.Append(' ');
                    sbTip.Append("Markdown text.");
                    sTip = sbTip.ToString();
                }
                TextBox tb;
                if (bMultiline)
                {
                    // Multi-line memo: label on the row above.
                    tb = dlg.addMemoBox(sCol + ":", sDisplay, sTip);
                }
                else
                {
                    // Single-line: label and textbox on one row.
                    tb = dlg.addInlineInputBox(sCol, sDisplay, sTip);
                }
                if (!bEditable) tb.ReadOnly = true;
                if (lsLookups.Count > 0 && bEditable)
                {
                    string sColCaptured = sCol;
                    List<string> lsCaptured = lsLookups;
                    tb.KeyDown += delegate(object sndKey, KeyEventArgs evKey)
                    {
                        if (evKey.KeyData != Keys.F4
                            && evKey.KeyData != (Keys.Alt | Keys.Down)) return;
                        evKey.Handled = true;
                        evKey.SuppressKeyPress = true;
                        TextBox tbTarget = sndKey as TextBox;
                        if (tbTarget == null) return;
                        string sChosen = pickLookupValue(sColCaptured, lsCaptured, tbTarget.Text);
                        if (sChosen == null) return;
                        tbTarget.Text = sChosen;
                        tbTarget.SelectionStart = tbTarget.TextLength;
                        LiveRegion.say(sChosen);
                    };
                }
                lTextBoxes.Add(tb);
                lLookupLists.Add((bEditable && lsLookups != null && lsLookups.Count > 0)
                    ? lsLookups : null);
            }
        }

        // pickLookupValue: modal pick list over the lookups-supplied
        // values for one field. Returns the chosen value, or null on
        // cancel. The current field text preselects its entry when it
        // matches one, so F4 on an already-valid field lands on that
        // value rather than the top of the list.
        private string pickLookupValue(string sCol, List<string> lsValues, string sCurrent)
        {
            using (LbcDialog dlgPick = new LbcDialog("Pick " + sCol, dlg.form))
            {
                ListBox lb = dlgPick.addListBox("Choose a value for " + sCol + ":",
                    lsValues, sCurrent);
                if (!string.Equals(dlgPick.runWithButtons(new string[] { "OK", "Cancel" }),
                        "OK", StringComparison.OrdinalIgnoreCase)) return null;
                return (lb.SelectedItem != null) ? lb.SelectedItem.ToString() : null;
            }
        }

        // Show the dialog modally. Sets ok and populates dValues if
        // the user pressed OK. owner argument is the parent window.
        //
        // OK is gated by validation: every editable field's value
        // must (a) parse cleanly to its declared type and (b) match
        // its configured regex if one is set. A failed validation
        // pops a MessageBox naming the offending field, leaves the
        // dialog open with focus on that textbox, and the user can
        // correct and try again. Cancel is never gated.
        // applyFormViewSetup: wire the form-view conveniences onto
        // every field textbox --
        //   Control+PageDown/PageUp  save (validation applies) and
        //                            move to the next / previous
        //                            record, same field focused.
        //                            (Bare PageDown/PageUp keep
        //                            their caret meaning in long
        //                            memo fields -- same divergence
        //                            from the data list as
        //                            Control+Home/End, and the
        //                            chords echo the list's
        //                            same-column row extremes.)
        //   Control+Shift+D          delete the current record
        //                            without confirmation (its grid
        //                            meaning), discarding edits
        //   Control+Shift+Backspace  Null Value: set the focused
        //                            field to SQL NULL (typing
        //                            afterward revokes it)
        //   F6 / Shift+F6            save and switch to the next /
        //                            previous view (show / list)
        //   Control+Semicolon        Insert Date: put today's date
        //                            (yyyy-MM-dd) at the caret of the
        //                            focused field
        //   Control+Shift+Semicolon  Insert Time: put the current time
        //                            (HH:mm:ss) at the caret
        // The two insert chords mirror the long-standing Excel
        // date/time shortcuts and realize a convenience both DbDo
        // ancestors shipped (the Contact Tracking System's F8 date key
        // and DbDialog's /Date and :Time form buttons), here scoped to
        // DbDo's own edit form rather than the shared text control.
        // plus focused-field tracking so the caller's reopen loop
        // can restore position, and initial focus on the same
        // field.
        public void applyFormViewSetup(int iInitialFocus, List<string> lsInitialNulls)
        {
            if (lsInitialNulls != null)
                foreach (string sNull in lsInitialNulls)
                    if (!lsNullFields.Contains(sNull)) lsNullFields.Add(sNull);
            for (int i = 0; i < lTextBoxes.Count; i++)
            {
                int iIdx = i;
                string sName = lColumnNames[i];
                TextBox tbRow = lTextBoxes[i];
                if (lsNullFields.Contains(sName))
                    tbRow.AccessibleDescription = "currently null";
                tbRow.ContextMenuStrip = buildFieldContextMenu(tbRow, sName,
                    (iIdx < lLookupLists.Count) ? lLookupLists[iIdx] : null);
                tbRow.GotFocus += delegate(object o, EventArgs e)
                { iFocusIndex = iIdx; };
                tbRow.TextChanged += delegate(object o, EventArgs e)
                { lsNullFields.Remove(sName); };
                tbRow.KeyDown += delegate(object o, KeyEventArgs evKey)
                {
                    if (evKey.KeyData == (Keys.Control | Keys.PageDown)
                        || evKey.KeyData == (Keys.Control | Keys.PageUp))
                    {
                        iNavigate = (evKey.KeyData == (Keys.Control | Keys.PageDown)) ? 1 : -1;
                        evKey.Handled = true;
                        evKey.SuppressKeyPress = true;
                        dlg.pressButton("OK");
                    }
                    else if (evKey.KeyData == (Keys.Control | Keys.Shift | Keys.D))
                    {
                        iNavigate = 2;
                        evKey.Handled = true;
                        evKey.SuppressKeyPress = true;
                        dlg.pressButton("Cancel");
                    }
                    else if (evKey.KeyData == (Keys.Control | Keys.Shift | Keys.Back))
                    {
                        TextBox tbHit = o as TextBox;
                        evKey.Handled = true;
                        evKey.SuppressKeyPress = true;
                        if (tbHit == null) return;
                        tbHit.Clear();
                        if (!lsNullFields.Contains(sName)) lsNullFields.Add(sName);
                        LiveRegion.sayForced("null");
                    }
                    else if (evKey.KeyData == Keys.F6 || evKey.KeyData == (Keys.Shift | Keys.F6))
                    {
                        // Switch to the next/previous view in the
                        // cycle, saving first (like OK).
                        iViewSwitch = (evKey.KeyData == Keys.F6) ? 1 : -1;
                        evKey.Handled = true;
                        evKey.SuppressKeyPress = true;
                        dlg.pressButton("OK");
                    }
                    else if (evKey.KeyData == (Keys.Control | Keys.OemSemicolon)
                        || evKey.KeyData == (Keys.Control | Keys.Shift | Keys.OemSemicolon))
                    {
                        // Insert Date / Insert Time at the caret of the
                        // focused field, replacing any selection. The
                        // chords match Excel's date/time shortcuts.
                        TextBox tbHit = o as TextBox;
                        evKey.Handled = true;
                        evKey.SuppressKeyPress = true;
                        if (tbHit == null || tbHit.ReadOnly) return;
                        bool bTime = (evKey.KeyData == (Keys.Control | Keys.Shift | Keys.OemSemicolon));
                        string sStamp = bTime
                            ? DateTime.Now.ToString("HH:mm:ss")
                            : DateTime.Now.ToString("yyyy-MM-dd");
                        int iAt = tbHit.SelectionStart;
                        tbHit.Text = tbHit.Text.Remove(iAt, tbHit.SelectionLength).Insert(iAt, sStamp);
                        tbHit.SelectionStart = iAt + sStamp.Length;
                        tbHit.SelectionLength = 0;
                        lsNullFields.Remove(sName);
                        LiveRegion.say(sStamp);
                    }
                };
            }
            if (iInitialFocus >= 0 && iInitialFocus < lTextBoxes.Count)
                dlg.setInitialFocus(lTextBoxes[iInitialFocus]);
        }

        // buildFieldContextMenu: the form view's per-field
        // Shift+F10 / Apps-key menu, following the same platform
        // guidance as the data list's. Assigning a custom menu to a
        // TextBox replaces its native edit menu, so the expected
        // standard trio leads explicitly; then field operations --
        // Pick Value appears ONLY when the field has lookup values,
        // per the only-relevant-items rule -- then record
        // navigation, then Help. Every item mirrors an existing
        // key, displayed beside the label.
        private ContextMenuStrip buildFieldContextMenu(TextBox tb, string sField, List<string> lsLookups)
        {
            ContextMenuStrip cms = new ContextMenuStrip();
            ToolStripMenuItem item;
            item = new ToolStripMenuItem("Cu&t");
            item.Click += delegate(object o, EventArgs e) { tb.Cut(); };
            cms.Items.Add(item);
            item = new ToolStripMenuItem("&Copy");
            item.Click += delegate(object o, EventArgs e) { tb.Copy(); };
            cms.Items.Add(item);
            item = new ToolStripMenuItem("&Paste");
            item.Click += delegate(object o, EventArgs e) { tb.Paste(); };
            cms.Items.Add(item);
            cms.Items.Add(new ToolStripSeparator());
            item = new ToolStripMenuItem("Null &Value");
            item.ShortcutKeyDisplayString = "Control+Shift+Backspace";
            item.Click += delegate(object o, EventArgs e)
            {
                tb.Clear();
                if (!lsNullFields.Contains(sField)) lsNullFields.Add(sField);
                LiveRegion.sayForced("null");
            };
            cms.Items.Add(item);
            if (lsLookups != null)
            {
                item = new ToolStripMenuItem("Pick Va&lue...");
                item.ShortcutKeyDisplayString = "F4";
                item.Click += delegate(object o, EventArgs e)
                {
                    string sChosen = pickLookupValue(sField, lsLookups, tb.Text);
                    if (sChosen == null) return;
                    tb.Text = sChosen;
                    tb.SelectionStart = tb.TextLength;
                    LiveRegion.say(sChosen);
                };
                cms.Items.Add(item);
            }
            cms.Items.Add(new ToolStripSeparator());
            item = new ToolStripMenuItem("Save and Next &Record");
            item.ShortcutKeyDisplayString = "Control+PageDown";
            item.Click += delegate(object o, EventArgs e)
            { iNavigate = 1; dlg.pressButton("OK"); };
            cms.Items.Add(item);
            item = new ToolStripMenuItem("Save and Previo&us Record");
            item.ShortcutKeyDisplayString = "Control+PageUp";
            item.Click += delegate(object o, EventArgs e)
            { iNavigate = -1; dlg.pressButton("OK"); };
            cms.Items.Add(item);
            item = new ToolStripMenuItem("&Delete Record");
            item.ShortcutKeyDisplayString = "Control+Shift+D";
            item.Click += delegate(object o, EventArgs e)
            { iNavigate = 2; dlg.pressButton("Cancel"); };
            cms.Items.Add(item);
            cms.Items.Add(new ToolStripSeparator());
            item = new ToolStripMenuItem("&Help");
            item.ShortcutKeyDisplayString = "F1";
            item.Click += delegate(object o, EventArgs e) { dlg.showHelp(); };
            cms.Items.Add(item);
            return cms;
        }

        public DialogResult showDialog(IWin32Window owner)
        {
            Form frm = dlg.form;
            frm.StartPosition = FormStartPosition.CenterParent;
            // Loop on OK so a validation failure can keep the
            // dialog open. LbcDialog.runWithButtons returns the
            // button label that was pressed; "OK" requires
            // validation to pass.
            while (true)
            {
                string sButton = dlg.runWithButtons(new string[] { "OK", "Cancel" });
                bool bOk = string.Equals(sButton, "OK", StringComparison.OrdinalIgnoreCase);
                if (!bOk)
                { ok = false; return DialogResult.Cancel; }
                string sErr;
                int iOffending;
                if (validateValues(out sErr, out iOffending))
                {
                    ok = true;
                    for (int i = 0; i < lTextBoxes.Count; i++)
                        dValues[lColumnNames[i]] = convertForStorage(lTextBoxes[i].Text, lDeclaredTypes[i]);
                    return DialogResult.OK;
                }
                // Least-intrusive correction (v1.0.108): no modal
                // box. The offending field gets focus with its text
                // selected (one keystroke replaces it), the dialog's
                // status line shows the message (the focus-tip line
                // the user already knows), and the message is spoken
                // once, forced so it cuts through. The user is never
                // more than typing-a-correct-value away from retrying
                // OK; Escape still cancels unconditionally.
                LiveRegion.sayForced(sErr);
                try { dlg.setStatusText(sErr); } catch { }
                if (iOffending >= 0 && iOffending < lTextBoxes.Count)
                {
                    try { lTextBoxes[iOffending].Focus(); lTextBoxes[iOffending].SelectAll(); }
                    catch { }
                }
                iNavigate = 0;  // a failed save cancels any pending navigation
                // Loop continues -- dialog stays open for retry.
            }
        }

        // validateValues: walk every editable field, parse its value
        // against its declared type, and (if a regex is configured
        // for that field in DbDo.inix) check Regex.IsMatch. Returns
        // true if all clean; otherwise false with sErr describing
        // the first failure and iOffending = index of the failing
        // textbox.
        private bool validateValues(out string sErr, out int iOffending)
        {
            sErr = null;
            iOffending = -1;
            for (int i = 0; i < lTextBoxes.Count; i++)
            {
                if (lTextBoxes[i].ReadOnly) continue;
                string sCol = lColumnNames[i];
                string sVal = lTextBoxes[i].Text ?? "";
                string sDeclared = lDeclaredTypes[i];

                // Empty values are allowed (nullable columns; the
                // database layer decides if NULL is acceptable).
                if (sVal.Length == 0) continue;

                // Type-aware parse check.
                string sTypeErr = checkTypeParse(sVal, sDeclared);
                if (sTypeErr != null)
                {
                    sErr = "Field '" + sCol + "': " + sTypeErr;
                    iOffending = i;
                    return false;
                }

                // Regex check: a per-field pattern from DbDo.inix
                // wins; otherwise the field's declared type supplies
                // a default "picture" pattern (dBASE III+ PICTURE
                // clause spirit), also configurable in [Validation].
                string sRegex = lookupFieldRegex(sCol);
                if (string.IsNullOrEmpty(sRegex)) sRegex = typeDefaultRegex(sDeclared);
                if (!string.IsNullOrEmpty(sRegex))
                {
                    bool bMatch = false;
                    try { bMatch = System.Text.RegularExpressions.Regex.IsMatch(sVal, sRegex); }
                    catch (Exception ex)
                    {
                        sErr = "Field '" + sCol + "': invalid regex in DbDo.inix: " + ex.Message;
                        iOffending = i;
                        return false;
                    }
                    if (!bMatch)
                    {
                        sErr = "Field '" + sCol + "': value does not match required pattern (" + sRegex + ")";
                        iOffending = i;
                        return false;
                    }
                }
            }
            return true;
        }

        // checkTypeParse: returns null if sValue parses cleanly for
        // sDeclared, or a human-friendly error string otherwise.
        // The check is permissive on textual types (anything goes)
        // and strict on numeric/date types.
        private static string checkTypeParse(string sValue, string sDeclared)
        {
            if (string.IsNullOrEmpty(sDeclared)) return null;
            string sLow = sDeclared.ToLowerInvariant();
            // Numeric integer
            if (sLow.Contains("int") || sLow == "integer")
            {
                long iN;
                if (!long.TryParse(sValue,
                        System.Globalization.NumberStyles.Integer
                        | System.Globalization.NumberStyles.AllowThousands,
                        System.Globalization.CultureInfo.InvariantCulture,
                        out iN))
                    return "expected an integer, got '" + sValue + "'";
                return null;
            }
            // Numeric real
            if (sLow.Contains("real") || sLow.Contains("float")
                || sLow.Contains("double") || sLow.Contains("numeric")
                || sLow.Contains("decimal"))
            {
                double dN;
                if (!double.TryParse(sValue,
                        System.Globalization.NumberStyles.Float
                        | System.Globalization.NumberStyles.AllowThousands,
                        System.Globalization.CultureInfo.InvariantCulture,
                        out dN))
                    return "expected a number, got '" + sValue + "'";
                return null;
            }
            // Date
            if (sLow.Contains("date") || sLow.Contains("time"))
            {
                DateTime dt;
                if (!DateTime.TryParse(sValue,
                        System.Globalization.CultureInfo.InvariantCulture,
                        System.Globalization.DateTimeStyles.None,
                        out dt))
                    return "expected a date or date-time, got '" + sValue + "'";
                return null;
            }
            return null;
        }

        // convertForDisplay: take a raw value as it came from ADO
        // and produce a string suitable for the textbox. For most
        // types this is the value unchanged. For numerics it
        // normalizes thousands separators and trims trailing zeros
        // off real values. For dates it produces ISO yyyy-MM-dd
        // for date-only columns and yyyy-MM-dd HH:mm:ss for
        // date-time columns.
        private static string convertForDisplay(string sValue, string sDeclared)
        {
            if (string.IsNullOrEmpty(sValue) || string.IsNullOrEmpty(sDeclared)) return sValue;
            string sLow = sDeclared.ToLowerInvariant();
            try
            {
                if (sLow.Contains("int"))
                {
                    long iN;
                    if (long.TryParse(sValue,
                        System.Globalization.NumberStyles.Any,
                        System.Globalization.CultureInfo.InvariantCulture,
                        out iN))
                        return iN.ToString(System.Globalization.CultureInfo.InvariantCulture);
                }
                else if (sLow.Contains("real") || sLow.Contains("float")
                         || sLow.Contains("double") || sLow.Contains("numeric")
                         || sLow.Contains("decimal"))
                {
                    double dN;
                    if (double.TryParse(sValue,
                        System.Globalization.NumberStyles.Any,
                        System.Globalization.CultureInfo.InvariantCulture,
                        out dN))
                    {
                        // Round-trip without locale; "G17" preserves
                        // round-trippable double precision but reads
                        // ugly for typical user data. "G15" is more
                        // human-readable and lossless for most
                        // user-entered values.
                        return dN.ToString("G15",
                            System.Globalization.CultureInfo.InvariantCulture);
                    }
                }
                else if (sLow.Contains("date") || sLow.Contains("time"))
                {
                    DateTime dt;
                    if (DateTime.TryParse(sValue,
                        System.Globalization.CultureInfo.InvariantCulture,
                        System.Globalization.DateTimeStyles.None,
                        out dt))
                    {
                        bool bTimeOnly = sLow.Contains("time") && !sLow.Contains("date");
                        bool bDateOnly = sLow.Contains("date") && !sLow.Contains("time");
                        if (bDateOnly) return dt.ToString("yyyy-MM-dd");
                        if (bTimeOnly) return dt.ToString("HH:mm:ss");
                        return dt.ToString("yyyy-MM-dd HH:mm:ss");
                    }
                }
            }
            catch { /* fall through to raw */ }
            return sValue;
        }

        // convertForStorage: inverse of convertForDisplay. Takes a
        // textbox value (already validated) and produces the string
        // form the database layer will use. For most types this is
        // a passthrough; for dates we always emit ISO yyyy-MM-dd[T...]
        // since that's what every backend (SQLite, Access, dBASE)
        // accepts unambiguously.
        private static string convertForStorage(string sValue, string sDeclared)
        {
            if (string.IsNullOrEmpty(sValue) || string.IsNullOrEmpty(sDeclared)) return sValue;
            string sLow = sDeclared.ToLowerInvariant();
            try
            {
                if (sLow.Contains("int"))
                {
                    long iN;
                    if (long.TryParse(sValue,
                        System.Globalization.NumberStyles.Any,
                        System.Globalization.CultureInfo.InvariantCulture,
                        out iN))
                        return iN.ToString(System.Globalization.CultureInfo.InvariantCulture);
                }
                else if (sLow.Contains("real") || sLow.Contains("float")
                         || sLow.Contains("double") || sLow.Contains("numeric")
                         || sLow.Contains("decimal"))
                {
                    double dN;
                    if (double.TryParse(sValue,
                        System.Globalization.NumberStyles.Any,
                        System.Globalization.CultureInfo.InvariantCulture,
                        out dN))
                        return dN.ToString("G15",
                            System.Globalization.CultureInfo.InvariantCulture);
                }
                else if (sLow.Contains("date") || sLow.Contains("time"))
                {
                    DateTime dt;
                    if (DateTime.TryParse(sValue,
                        System.Globalization.CultureInfo.InvariantCulture,
                        System.Globalization.DateTimeStyles.None,
                        out dt))
                    {
                        bool bTimeOnly = sLow.Contains("time") && !sLow.Contains("date");
                        bool bDateOnly = sLow.Contains("date") && !sLow.Contains("time");
                        if (bDateOnly) return dt.ToString("yyyy-MM-dd");
                        if (bTimeOnly) return dt.ToString("HH:mm:ss");
                        return dt.ToString("yyyy-MM-dd HH:mm:ss");
                    }
                }
            }
            catch { }
            return sValue;
        }

        // lookupFieldRegex: read the regex constraint for <table>.<column>
        // from DbDo.inix. The config schema is one INI section per
        // table named [Validation:<table>]; within it, each key is a
        // column name and each value is a .NET regex pattern. Example:
        //
        //   [Validation:students]
        //   email = ^[^@\s]+@[^@\s]+\.[a-z]+$
        //   year = ^(Freshman|Sophomore|Junior|Senior)$
        //
        // A missing entry means no regex applied. The lookup is
        // table-scoped, so the same column name can have different
        // regexes in different tables.
        private string lookupFieldRegex(string sColumn)
        {
            if (string.IsNullOrEmpty(sColumn) || string.IsNullOrEmpty(sTableName)) return null;
            try { return IniValidation.lookup(sTableName, sColumn); }
            catch { return null; }
        }

        // typeDefaultRegex: the "picture" pattern for a declared type
        // or affinity, in the spirit of the dBASE III+ PICTURE
        // clause: a BOOLEAN field accepts ^(0|1)$, a TEXTTIME field a
        // standard SQLite timestamp, and so on. Read from DbDo.inix
        // [Validation] (key = declared type name, value = regex) so
        // the user can tighten or loosen any type; the compiled
        // defaults below apply when no entry exists. Empty values
        // never reach here (nullable columns pass), and unknown
        // types validate freely.
        private string typeDefaultRegex(string sDeclared)
        {
            string sKey = (sDeclared ?? "").Trim().ToUpperInvariant();
            string sUser = null;
            if (sKey.Length == 0) return null;
            // Per-database [Validation] override wins over the per-user
            // DbDo.inix, which in turn wins over the compiled default.
            try { sUser = DbDoForm.readPerDbValue("Validation", sKey); } catch { }
            if (!string.IsNullOrEmpty(sUser)) return sUser;
            try { sUser = DbDoForm.IniSession.read("Validation", sKey); } catch { }
            if (!string.IsNullOrEmpty(sUser)) return sUser;
            switch (sKey)
            {
                case "BOOLEAN":  return "^(0|1)$";
                case "INTEGER":  return "^[+-]?[0-9]+$";
                case "REAL":     return @"^[+-]?([0-9]+(\.[0-9]*)?|\.[0-9]+)([eE][+-]?[0-9]+)?$";
                case "NUMERIC":  return @"^[+-]?([0-9]+(\.[0-9]*)?|\.[0-9]+)$";
                case "TEXTTIME": return @"^[0-9]{4}-[0-9]{2}-[0-9]{2}([ T][0-9]{2}:[0-9]{2}(:[0-9]{2}(\.[0-9]+)?)?)?$";
                default:         return null;
            }
        }

        public void Dispose()
        {
            if (dlg != null) { dlg.Dispose(); dlg = null; }
        }
    }

    // IniValidation: load and look up per-field regex constraints
    // from DbDo.inix. The config schema is one section per table
    // named [Validation:<table>], with one key-value pair per
    // column where the key is the column name and the value is
    // a .NET regex pattern. The whole file is read lazily on
    // first lookup and cached for the rest of the session.
    public static class IniValidation
    {
        private static Dictionary<string, Dictionary<string, string>> dByTable;
        private static bool bLoaded = false;

        // Reset is used by the Edit-Settings dialog after a
        // save, to invalidate the cache so subsequent dialogs pick
        // up the new regexes.
        public static void reset()
        {
            bLoaded = false;
            dByTable = null;
        }

        public static string lookup(string sTable, string sColumn)
        {
            if (!bLoaded) load();
            if (dByTable == null) return null;
            Dictionary<string, string> dCols;
            if (!dByTable.TryGetValue(sTable.ToLowerInvariant(), out dCols)) return null;
            string sRegex;
            if (!dCols.TryGetValue(sColumn.ToLowerInvariant(), out sRegex)) return null;
            return sRegex;
        }

        private static void load()
        {
            bLoaded = true;
            dByTable = new Dictionary<string, Dictionary<string, string>>(StringComparer.OrdinalIgnoreCase);
            // Compute the per-user DbDo.inix path directly. The
            // matching helper inside DbDoForm (IniSession.iniPath)
            // is private to that class; rather than expose it
            // publicly just for one caller, replicate the simple
            // path-build here. The path layout matches IniSession
            // exactly so the same file is read.
            string sIni;
            try
            {
                string sBase = Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData);
                if (string.IsNullOrEmpty(sBase))
                {
                    // %LOCALAPPDATA% unavailable: fall back to the
                    // EXE folder. This keeps lookup working in the
                    // unusual case where the user profile path is
                    // unset (portable installs, sandboxes, etc.)
                    string sExeDir = System.IO.Path.GetDirectoryName(Application.ExecutablePath) ?? ".";
                    sIni = System.IO.Path.Combine(sExeDir, "DbDo.inix");
                }
                else
                {
                    string sDir = System.IO.Path.Combine(sBase, "DbDo");
                    sIni = System.IO.Path.Combine(sDir, "DbDo.inix");
                }
            }
            catch { return; }
            if (string.IsNullOrEmpty(sIni)) return;
            if (!System.IO.File.Exists(sIni)) return;
            try
            {
                string[] aLines = System.IO.File.ReadAllLines(sIni);
                string sCurrentTable = null;
                foreach (string sLine in aLines)
                {
                    string sTrim = sLine.Trim();
                    if (sTrim.Length == 0) continue;
                    if (sTrim.StartsWith(";") || sTrim.StartsWith("#")) continue;
                    if (sTrim.StartsWith("[") && sTrim.EndsWith("]"))
                    {
                        string sSection = sTrim.Substring(1, sTrim.Length - 2).Trim();
                        const string sPrefix = "Validation:";
                        if (sSection.StartsWith(sPrefix, StringComparison.OrdinalIgnoreCase))
                            sCurrentTable = sSection.Substring(sPrefix.Length).Trim();
                        else
                            sCurrentTable = null;
                        continue;
                    }
                    if (sCurrentTable == null) continue;
                    int iEq = sTrim.IndexOf('=');
                    if (iEq <= 0) continue;
                    string sKey = sTrim.Substring(0, iEq).Trim();
                    string sVal = sTrim.Substring(iEq + 1).Trim();
                    if (sKey.Length == 0 || sVal.Length == 0) continue;
                    Dictionary<string, string> dCols;
                    string sTKey = sCurrentTable.ToLowerInvariant();
                    if (!dByTable.TryGetValue(sTKey, out dCols))
                    {
                        dCols = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
                        dByTable[sTKey] = dCols;
                    }
                    dCols[sKey] = sVal;
                }
                try { DbDoLog.write("IniValidation loaded " + dByTable.Count + " table section(s)"); } catch { }
            }
            catch (Exception ex)
            {
                try { DbDoLog.write("IniValidation load failed: " + ex.Message); } catch { }
            }
        }
    }

    // =====================================================================
    // =====================================================================
    // ColumnSequenceDialog: the reusable Lbc-family picker for an
    // ORDERED sequence of column names. Two side-by-side listboxes,
    // "Available:" and "Chosen:"; Add (Alt+A, or Enter in Available)
    // moves the selected available column to the END of the chosen
    // list -- so the order of adding IS the sequence; Remove (Alt+R,
    // or Enter/Delete in Chosen) sends a chosen column back,
    // re-inserted alphabetically. OK yields the chosen names and
    // their comma-separated form, ready to become a select list, a
    // Sort property value, or any other column-sequence argument.
    // The available list is alphabetical, initially selecting the
    // column the caller passes (typically the virtual cursor column).
    // =====================================================================
    // ColumnSequenceDialog: the side-by-side Names / Picks chooser
    // behind Select Columns and Order Records. Names lists every
    // column in NATURAL order with the db cursor's column
    // preselected; the Picks order IS the result sequence. Tab
    // order: Names, Picks, then the action row, then OK / Cancel /
    // Help. In select mode the action row is Add and Remove; in
    // sort mode it is Ascending (the default), Descending, and
    // Remove, and each pick reads "name asc" or "name desc".
    // Remove restores the name to its natural position in Names and
    // puts focus there. Enter in Names invokes the default action;
    // Enter or Delete in Picks removes.
    public class ColumnSequenceDialog : LbcForm
    {
        private bool bSortStyle;
        private Button btnDefault;
        private ListBox lbNames;
        private ListBox lbPicks;
        private List<string> lsNatural;

        public List<string> lChosenColumns = new List<string>();
        public string sChosenCsv { get { return string.Join(", ", lChosenColumns.ToArray()); } }

        public ColumnSequenceDialog(string sTitle, IList<string> lAllColumns,
            string sInitialSelection, IList<string> lInitialChosen)
            : this(sTitle, lAllColumns, sInitialSelection, lInitialChosen, false) { }

        public ColumnSequenceDialog(string sTitle, IList<string> lAllColumns,
            string sInitialSelection, IList<string> lInitialChosen, bool bSortMode)
        {
            bSortStyle = bSortMode;
            lsNatural = new List<string>(lAllColumns);
            Text = sTitle;
            StartPosition = FormStartPosition.CenterParent;
            FormBorderStyle = FormBorderStyle.FixedDialog;
            MinimizeBox = false; MaximizeBox = false; ShowInTaskbar = false;
            ClientSize = new System.Drawing.Size(560, 348);

            Label lblNames = new Label();
            lblNames.Text = "&Fields:";
            lblNames.SetBounds(12, 9, 200, 18);
            lblNames.TabIndex = 0;

            lbNames = new ListBox();
            lbNames.SetBounds(12, 30, 250, 226);
            lbNames.TabIndex = 1;
            lbNames.AccessibleName = "Fields";
            lbNames.KeyDown += (sndr, evK) =>
            {
                if (evK.KeyCode == Keys.Return)
                { addClicked(bSortStyle ? "asc" : null); evK.Handled = true; evK.SuppressKeyPress = true; }
            };
            lbNames.DoubleClick += (sndr, evA) => addClicked(bSortStyle ? "asc" : null);

            Label lblPicks = new Label();
            lblPicks.Text = "&Picks:";
            lblPicks.SetBounds(286, 9, 200, 18);
            lblPicks.TabIndex = bSortStyle ? 5 : 4;

            lbPicks = new ListBox();
            lbPicks.SetBounds(286, 30, 250, 226);
            lbPicks.TabIndex = bSortStyle ? 6 : 5;
            lbPicks.AccessibleName = "Picks";
            lbPicks.KeyDown += (sndr, evK) =>
            {
                if (evK.KeyCode == Keys.Return || evK.KeyCode == Keys.Delete)
                { removeClicked(null, null); evK.Handled = true; evK.SuppressKeyPress = true; }
            };
            lbPicks.DoubleClick += removeClicked;

            int iX = 12;
            if (bSortStyle)
            {
                Button btnAsc = new Button();
                btnAsc.Text = "Add &Ascending";
                btnAsc.SetBounds(iX, 266, 110, 26); iX += 118;
                btnAsc.TabIndex = 2;
                btnAsc.Click += (sndr, evA) => addClicked("asc");
                btnDefault = btnAsc;
                Controls.Add(btnAsc);

                Button btnDesc = new Button();
                btnDesc.Text = "Add &Descending";
                btnDesc.SetBounds(iX, 266, 110, 26); iX += 118;
                btnDesc.TabIndex = 3;
                btnDesc.Click += (sndr, evA) => addClicked("desc");
                Controls.Add(btnDesc);
            }
            else
            {
                Button btnAdd = new Button();
                btnAdd.Text = "&Add";
                btnAdd.SetBounds(iX, 266, 96, 26); iX += 104;
                btnAdd.TabIndex = 2;
                btnAdd.Click += (sndr, evA) => addClicked(null);
                btnDefault = btnAdd;
                Controls.Add(btnAdd);
            }
            Button btnRemove = new Button();
            btnRemove.Text = "&Remove";
            btnRemove.SetBounds(iX, 266, 96, 26); iX += 104;
            btnRemove.TabIndex = bSortStyle ? 4 : 3;
            btnRemove.Click += removeClicked;
            Controls.Add(btnRemove);

            // Clear: empty the Picks list in one gesture and return every
            // field to its natural place in Fields (its own band below).
            Button btnClear = new Button();
            btnClear.Text = "C&lear";
            btnClear.SetBounds(12, 300, 96, 26);
            btnClear.TabIndex = bSortStyle ? 7 : 6;
            btnClear.Click += (sndr, evA) =>
            {
                int iCleared = lbPicks.Items.Count;
                lbPicks.Items.Clear();
                lbNames.Items.Clear();
                foreach (string sN in lsNatural) lbNames.Items.Add(sN);
                if (lbNames.Items.Count > 0) lbNames.SelectedIndex = 0;
                lbNames.Focus();
                LiveRegion.say(iCleared + (iCleared == 1 ? " pick cleared" : " picks cleared"));
            };
            Controls.Add(btnClear);

            Button btnOk = new Button();
            btnOk.Text = "&OK";
            btnOk.SetBounds(286, 306, 76, 26);
            btnOk.TabIndex = bSortStyle ? 8 : 7;
            btnOk.Click += (sndr, evA) =>
            {
                lChosenColumns.Clear();
                foreach (object o in lbPicks.Items) lChosenColumns.Add(o.ToString());
                DialogResult = DialogResult.OK;
            };

            Button btnCancel = new Button();
            btnCancel.Text = "&Cancel";
            btnCancel.SetBounds(370, 306, 76, 26);
            btnCancel.TabIndex = bSortStyle ? 9 : 8;
            btnCancel.DialogResult = DialogResult.Cancel;
            CancelButton = btnCancel;

            Button btnHelp = new Button();
            btnHelp.Text = "&Help";
            btnHelp.SetBounds(454, 306, 76, 26);
            btnHelp.TabIndex = bSortStyle ? 10 : 9;
            btnHelp.Click += (sndr, evA) => HelpDialog.show(this, Text, helpText());

            // The action default (Add / Ascending) is the dialog's
            // AcceptButton, per spec; the listbox Enter handlers
            // above take precedence inside the lists, so Enter in
            // Picks still removes.
            AcceptButton = btnDefault;

            Controls.Add(lblNames); Controls.Add(lbNames);
            Controls.Add(lblPicks); Controls.Add(lbPicks);
            Controls.Add(btnClear);
            Controls.Add(btnOk); Controls.Add(btnCancel); Controls.Add(btnHelp);

            // Populate: Picks first (caller's order, suffixes intact
            // in sort mode), then Names = the rest in NATURAL order.
            HashSet<string> hPicked = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
            if (lInitialChosen != null)
            {
                foreach (string sC in lInitialChosen)
                {
                    if (string.IsNullOrEmpty(sC)) continue;
                    lbPicks.Items.Add(sC);
                    hPicked.Add(bareName(sC));
                }
            }
            foreach (string sC in lsNatural)
                if (!hPicked.Contains(sC)) lbNames.Items.Add(sC);

            if (lbNames.Items.Count > 0)
            {
                int iInit = 0;
                if (!string.IsNullOrEmpty(sInitialSelection))
                {
                    for (int i = 0; i < lbNames.Items.Count; i++)
                    {
                        if (string.Equals(lbNames.Items[i].ToString(), sInitialSelection,
                            StringComparison.OrdinalIgnoreCase))
                        { iInit = i; break; }
                    }
                }
                lbNames.SelectedIndex = iInit;
            }
            if (lbPicks.Items.Count > 0) lbPicks.SelectedIndex = 0;
            Shown += (sndr, evA) => lbNames.Focus();
        }

        // bareName: a pick without its sort-mode direction suffix.
        private string bareName(string sPick)
        {
            if (!bSortStyle) return sPick;
            int iSpace = sPick.LastIndexOf(' ');
            return (iSpace > 0) ? sPick.Substring(0, iSpace) : sPick;
        }

        private void addClicked(string sSuffix)
        {
            if (lbNames.SelectedIndex < 0)
            { LiveRegion.say("No name selected"); return; }
            int iIdx = lbNames.SelectedIndex;
            string sName = lbNames.Items[iIdx].ToString();
            lbNames.Items.RemoveAt(iIdx);
            string sPick = sName + (bSortStyle ? " " + sSuffix : "");
            lbPicks.Items.Add(sPick);
            lbPicks.SelectedIndex = lbPicks.Items.Count - 1;
            if (lbNames.Items.Count > 0)
                lbNames.SelectedIndex = Math.Min(iIdx, lbNames.Items.Count - 1);
            LiveRegion.say(sPick + " picked, " + lbPicks.Items.Count + " picks");
        }

        private void removeClicked(object sender, EventArgs evArgs)
        {
            if (lbPicks.SelectedIndex < 0)
            { LiveRegion.say("No pick selected"); return; }
            int iIdx = lbPicks.SelectedIndex;
            string sName = bareName(lbPicks.Items[iIdx].ToString());
            lbPicks.Items.RemoveAt(iIdx);
            // Restore at the name's NATURAL position among the names
            // currently present, then put focus there, per spec.
            int iRank = lsNatural.FindIndex(
                sN => string.Equals(sN, sName, StringComparison.OrdinalIgnoreCase));
            int iInsert = 0;
            while (iInsert < lbNames.Items.Count
                && lsNatural.FindIndex(sN => string.Equals(sN,
                       lbNames.Items[iInsert].ToString(), StringComparison.OrdinalIgnoreCase)) < iRank)
                iInsert++;
            lbNames.Items.Insert(iInsert, sName);
            lbNames.SelectedIndex = iInsert;
            if (lbPicks.Items.Count > 0)
                lbPicks.SelectedIndex = Math.Min(iIdx, lbPicks.Items.Count - 1);
            lbNames.Focus();
            LiveRegion.say(sName + " removed, " + lbPicks.Items.Count + " picks");
        }

        // helpText: generated for the Help button / dialog mode.
        private string helpText()
        {
            System.Text.StringBuilder sbHelp = new System.Text.StringBuilder();
            sbHelp.AppendLine("Fields lists the columns in natural order; Picks holds your choices, and the order of Picks is the order applied.");
            sbHelp.AppendLine();
            if (bSortStyle)
                sbHelp.AppendLine("Add Ascending (the default; Enter in Fields) or Add Descending moves the selected field to Picks with its direction. Each pick reads like: city asc.");
            else
                sbHelp.AppendLine("Add (the default; Enter in Fields) moves the selected field to the bottom of Picks.");
            sbHelp.AppendLine("Remove (or Enter or Delete in Picks) returns the selected pick to its natural place in Fields and moves focus there.");
            sbHelp.AppendLine("Clear empties the Picks list at once. OK applies the picks; an empty Picks list clears the setting. Escape cancels.");
            return sbHelp.ToString();
        }
    }

    // FilterDialog: Select-Record dialog. Three controls -- filter
    // text, column chooser, match-mode chooser. The column chooser
    // includes "All columns" as the first option (for any-column
    // matches). The match modes are Contains, Starts with, Equals.
    // =====================================================================
    public class FilterDialog : LbcForm
    {
        public string sFilterText;
        public string sFilterColumn;
        public string sMatchMode;
        // bClearRequested: the user clicked Clear (Alt+C) rather than
        // OK. Caller treats this as "set an empty filter and close",
        // restoring the full unfiltered view. Distinct from Cancel
        // (DialogResult.Cancel = "do nothing").
        public bool bClearRequested;

        public FilterDialog(List<string> lColumns, string sCurrentText, string sCurrentColumn, string sCurrentMode)
        {
            this.Text = "Where Filter";
            this.AccessibleName = "Where filter";
            this.AccessibleDescription = "";
            this.StartPosition = FormStartPosition.CenterParent;
            this.ClientSize = new Size(440, 200);
            this.FormBorderStyle = FormBorderStyle.FixedDialog;
            this.MaximizeBox = false;
            this.MinimizeBox = false;
            this.ShowInTaskbar = false;
            this.KeyPreview = true;

            Label lbl1 = new Label();
            lbl1.Text = "Filter &text:";
            lbl1.Location = new Point(12, 16);
            lbl1.Size = new Size(110, 20);
            this.Controls.Add(lbl1);

            TextBox tbFilter = new TextBox();
            tbFilter.AccessibleName = "Filter text";
            tbFilter.Location = new Point(130, 13);
            tbFilter.Size = new Size(290, 23);
            tbFilter.TabIndex = 0;
            tbFilter.Text = sCurrentText ?? "";
            this.Controls.Add(tbFilter);

            Label lbl2 = new Label();
            lbl2.Text = "&In column:";
            lbl2.Location = new Point(12, 48);
            lbl2.Size = new Size(110, 20);
            this.Controls.Add(lbl2);

            ComboBox cbCol = new ComboBox();
            cbCol.AccessibleName = "Column";
            cbCol.Location = new Point(130, 45);
            cbCol.Size = new Size(290, 23);
            cbCol.TabIndex = 1;
            cbCol.DropDownStyle = ComboBoxStyle.DropDownList;
            cbCol.Items.Add("All columns");
            foreach (string s in lColumns) cbCol.Items.Add(s);
            cbCol.SelectedItem = (sCurrentColumn != null && cbCol.Items.Contains(sCurrentColumn)) ? (object)sCurrentColumn : (object)"All columns";
            this.Controls.Add(cbCol);

            Label lbl3 = new Label();
            lbl3.Text = "&Match mode:";
            lbl3.Location = new Point(12, 80);
            lbl3.Size = new Size(110, 20);
            this.Controls.Add(lbl3);

            ComboBox cbMode = new ComboBox();
            cbMode.AccessibleName = "Match mode";
            cbMode.Location = new Point(130, 77);
            cbMode.Size = new Size(290, 23);
            cbMode.TabIndex = 2;
            cbMode.DropDownStyle = ComboBoxStyle.DropDownList;
            cbMode.Items.Add("Contains");
            cbMode.Items.Add("Starts with");
            cbMode.Items.Add("Equals");
            cbMode.SelectedItem = (sCurrentMode != null && cbMode.Items.Contains(sCurrentMode)) ? (object)sCurrentMode : (object)"Contains";
            this.Controls.Add(cbMode);

            // Three-button row: OK (default, Enter), Clear (Alt+C),
            // Cancel (Escape). Clear restores the full unfiltered
            // view with one keystroke; the user's typed input is
            // discarded.
            Button btnOk = new Button();
            btnOk.Text = "&OK";
            btnOk.DialogResult = DialogResult.OK;
            btnOk.Size = new Size(80, 28);
            btnOk.Location = new Point(150, 150);
            btnOk.TabIndex = 3;
            btnOk.UseVisualStyleBackColor = true;
            btnOk.Click += (s, e) => {
                sFilterText = tbFilter.Text;
                sFilterColumn = cbCol.SelectedItem as string;
                sMatchMode = cbMode.SelectedItem as string;
                bClearRequested = false;
            };
            this.Controls.Add(btnOk);

            Button btnClear = new Button();
            btnClear.Text = "&Clear";
            btnClear.Size = new Size(80, 28);
            btnClear.Location = new Point(240, 150);
            btnClear.TabIndex = 4;
            btnClear.UseVisualStyleBackColor = true;
            btnClear.Click += (s, e) => {
                bClearRequested = true;
                sFilterText = "";
                sFilterColumn = "All columns";
                sMatchMode = "Contains";
                this.DialogResult = DialogResult.OK;
                this.Close();
            };
            this.Controls.Add(btnClear);

            Button btnCancel = new Button();
            btnCancel.Text = "Ca&ncel";
            btnCancel.DialogResult = DialogResult.Cancel;
            btnCancel.Size = new Size(80, 28);
            btnCancel.Location = new Point(330, 150);
            btnCancel.TabIndex = 5;
            btnCancel.UseVisualStyleBackColor = true;
            this.Controls.Add(btnCancel);

            this.AcceptButton = btnOk;
            this.CancelButton = btnCancel;
            this.ActiveControl = tbFilter;
            tbFilter.SelectAll();
        }
    }

    // =====================================================================
    // CommandPickerDialog: flat picker over every registered command.
    // Filter text box on top, listbox below, detail pane at the
    // bottom. Provides an Alternate Menu command
    // (Alt+F10) -- same name, same chord, same idea: an alphabetized
    // searchable list of every command in the application. The
    // internal class name is kept as CommandPickerDialog to avoid
    // an internal renaming churn; the user-visible name is
    // "Alternate Menu" everywhere it surfaces.
    // =====================================================================
    public class CommandPickerDialog : LbcForm
    {
        public ToolStripMenuItem miChosen;
        private List<ToolStripMenuItem> lAllItems = new List<ToolStripMenuItem>();
        private List<string> lAllDisplay = new List<string>();
        private TextBox tbFilter;
        private ListBox lbCommands;
        private TextBox tbDetail;

        public CommandPickerDialog()
        {
            this.Text = "Alternate Menu";
            this.AccessibleName = "Alternate Menu";
            this.AccessibleDescription = "";
            this.StartPosition = FormStartPosition.CenterParent;
            this.ClientSize = new Size(640, 520);
            this.MinimumSize = new Size(420, 360);
            this.FormBorderStyle = FormBorderStyle.Sizable;
            this.MaximizeBox = true;
            this.MinimizeBox = false;
            this.ShowInTaskbar = false;
            this.KeyPreview = true;

            Label lblF = new Label();
            lblF.Text = "&Filter:";
            lblF.Location = new Point(12, 14);
            lblF.Size = new Size(60, 20);
            this.Controls.Add(lblF);

            tbFilter = new TextBox();
            tbFilter.AccessibleName = "Filter";
            tbFilter.Location = new Point(80, 11);
            tbFilter.Size = new Size(540, 23);
            tbFilter.TabIndex = 0;
            tbFilter.Anchor = AnchorStyles.Top | AnchorStyles.Left | AnchorStyles.Right;
            tbFilter.TextChanged += filterChanged;
            tbFilter.KeyDown += filterKeyDown;
            this.Controls.Add(tbFilter);

            Label lblL = new Label();
            lblL.Text = "&Commands:";
            lblL.Location = new Point(12, 42);
            lblL.Size = new Size(120, 20);
            this.Controls.Add(lblL);

            lbCommands = new ListBox();
            lbCommands.AccessibleName = "Commands";
            lbCommands.Location = new Point(12, 64);
            // Shrink the list height so the description detail box
            // fits below it. The list still uses the form's full
            // width and anchors to all four sides for resize.
            lbCommands.Size = new Size(608, 220);
            lbCommands.Anchor = AnchorStyles.Top | AnchorStyles.Left | AnchorStyles.Right | AnchorStyles.Bottom;
            lbCommands.IntegralHeight = false;
            lbCommands.TabIndex = 1;
            lbCommands.DoubleClick += (s, e) => activateChosen();
            lbCommands.KeyDown += listKeyDown;
            lbCommands.SelectedIndexChanged += listSelectionChanged;
            this.Controls.Add(lbCommands);

            // Description detail box: read-only multi-line TextBox
            // below the listbox. Shows the summary on its first line
            // and the optional description below. Always populated
            // so the user has a self-orientation cue without having
            // to read the listbox row plus a separate doc.
            Label lblD = new Label();
            lblD.Text = "&Detail:";
            lblD.Location = new Point(12, 292);
            lblD.Size = new Size(60, 20);
            lblD.Anchor = AnchorStyles.Left | AnchorStyles.Bottom;
            this.Controls.Add(lblD);

            tbDetail = new TextBox();
            tbDetail.AccessibleName = "Detail";
            tbDetail.Location = new Point(12, 312);
            tbDetail.Size = new Size(608, 64);
            tbDetail.Anchor = AnchorStyles.Left | AnchorStyles.Right | AnchorStyles.Bottom;
            tbDetail.Multiline = true;
            tbDetail.ReadOnly = true;
            tbDetail.ScrollBars = ScrollBars.Vertical;
            tbDetail.TabStop = false;
            this.Controls.Add(tbDetail);

            Button btnOk = new Button();
            btnOk.Text = "&OK";
            btnOk.Size = new Size(90, 28);
            btnOk.Location = new Point(440, 484);
            btnOk.Anchor = AnchorStyles.Bottom | AnchorStyles.Right;
            btnOk.TabIndex = 2;
            btnOk.UseVisualStyleBackColor = true;
            btnOk.Click += (s, e) => activateChosen();
            this.Controls.Add(btnOk);

            Button btnCancel = new Button();
            btnCancel.Text = "&Cancel";
            btnCancel.DialogResult = DialogResult.Cancel;
            btnCancel.Size = new Size(90, 28);
            btnCancel.Location = new Point(536, 484);
            btnCancel.Anchor = AnchorStyles.Bottom | AnchorStyles.Right;
            btnCancel.TabIndex = 3;
            btnCancel.UseVisualStyleBackColor = true;
            this.Controls.Add(btnCancel);

            this.CancelButton = btnCancel;

            foreach (KeyValuePair<ToolStripMenuItem, string> kv in KeyMap.dMenuToCommand)
            {
                string sCmd = kv.Value;
                string sKey = KeyMap.dCommandToKey.ContainsKey(sCmd) ? KeyMap.friendlyKey(KeyMap.dCommandToKey[sCmd]) : "(unbound)";
                string sDisabled = kv.Key.Enabled ? "" : "  (disabled)";
                string sSummary = KeyMap.summaryFor(sCmd);
                lAllItems.Add(kv.Key);
                // Inline format: "Verb-Name  [Chord]  — summary
                // text"; the em dash separates the metadata block
                // (verb + chord + enabled flag) from the prose.
                lAllDisplay.Add(string.Format("{0}  [{1}]{2}  \u2014 {3}",
                    sCmd, sKey, sDisabled, sSummary));
            }
            int[] aOrder = new int[lAllDisplay.Count];
            for (int i = 0; i < aOrder.Length; i++) aOrder[i] = i;
            Array.Sort(aOrder, (i, j) => string.Compare(lAllDisplay[i], lAllDisplay[j], StringComparison.OrdinalIgnoreCase));
            List<ToolStripMenuItem> lSortedItems = new List<ToolStripMenuItem>();
            List<string> lSortedDisplay = new List<string>();
            foreach (int i in aOrder) { lSortedItems.Add(lAllItems[i]); lSortedDisplay.Add(lAllDisplay[i]); }
            lAllItems = lSortedItems;
            lAllDisplay = lSortedDisplay;

            applyFilter("");
            // Force initial detail fill in case SelectedIndexChanged
            // didn't fire for index 0.
            listSelectionChanged(null, EventArgs.Empty);
            this.ActiveControl = tbFilter;
        }

        private void applyFilter(string sNeedle)
        {
            lbCommands.BeginUpdate();
            lbCommands.Items.Clear();
            string sLow = sNeedle.ToLowerInvariant();
            for (int i = 0; i < lAllDisplay.Count; i++)
            {
                if (sLow.Length == 0 || lAllDisplay[i].ToLowerInvariant().Contains(sLow))
                    lbCommands.Items.Add(new PickerItem(i, lAllDisplay[i]));
            }
            if (lbCommands.Items.Count > 0) lbCommands.SelectedIndex = 0;
            lbCommands.EndUpdate();
        }

        private void filterChanged(object sender, EventArgs evArgs) { applyFilter(tbFilter.Text); }

        // listSelectionChanged: update the detail panel when the user
        // moves through the filtered list. The first line is the
        // canonical verb plus chord; subsequent lines are the
        // optional description. Always shows the summary in the
        // listbox itself so this panel adds detail rather than
        // duplicates.
        private void listSelectionChanged(object sender, EventArgs evArgs)
        {
            if (tbDetail == null) return;
            PickerItem pick = lbCommands.SelectedItem as PickerItem;
            if (pick == null) { tbDetail.Text = ""; return; }
            ToolStripMenuItem mi = lAllItems[pick.iOriginalIndex];
            string sCmd = KeyMap.dMenuToCommand.ContainsKey(mi) ? KeyMap.dMenuToCommand[mi] : "";
            string sSummary = KeyMap.summaryFor(sCmd);
            string sDescription = KeyMap.descriptionFor(sCmd);
            StringBuilder sb = new StringBuilder();
            sb.Append(sCmd);
            if (KeyMap.dCommandToKey.ContainsKey(sCmd))
                sb.Append("  [").Append(KeyMap.friendlyKey(KeyMap.dCommandToKey[sCmd])).Append("]");
            sb.AppendLine();
            string sCtx = KeyMap.contextFor(sCmd);
            if (sCtx != "Global") sb.Append("Context: ").AppendLine(sCtx);
            sb.Append("Summary: ").AppendLine(sSummary);
            if (!string.IsNullOrEmpty(sDescription))
            {
                sb.AppendLine();
                sb.AppendLine(sDescription);
            }
            tbDetail.Text = sb.ToString();
        }

        private void filterKeyDown(object sender, KeyEventArgs evArgs)
        {
            if (evArgs.KeyCode == Keys.Down)
            {
                if (lbCommands.Items.Count > 0)
                {
                    lbCommands.Focus();
                    if (lbCommands.SelectedIndex < 0) lbCommands.SelectedIndex = 0;
                }
                evArgs.Handled = true;
            }
            else if (evArgs.KeyCode == Keys.Enter)
            {
                activateChosen();
                evArgs.Handled = true;
                evArgs.SuppressKeyPress = true;
            }
        }

        private void listKeyDown(object sender, KeyEventArgs evArgs)
        {
            if (evArgs.KeyCode == Keys.Enter)
            {
                activateChosen();
                evArgs.Handled = true;
                evArgs.SuppressKeyPress = true;
            }
        }

        private void activateChosen()
        {
            if (lbCommands.SelectedItem == null) return;
            PickerItem pick = lbCommands.SelectedItem as PickerItem;
            if (pick == null) return;
            miChosen = lAllItems[pick.iOriginalIndex];
            this.DialogResult = DialogResult.OK;
            this.Close();
        }

        private class PickerItem
        {
            public int iOriginalIndex;
            public string sDisplay;
            public PickerItem(int i, string s) { iOriginalIndex = i; sDisplay = s; }
            public override string ToString() { return sDisplay; }
        }
    }

    // =====================================================================
    // DbDoForm: the WinForms GUI. Holds a single DbDoManager
    // instance; the recordset inside is the single source of truth
    // for current position, filter, sort, and current table. The
    // form's grid is a render-only mirror, rebuilt on each refresh.
    //
    // Key architectural difference from the predecessor: the form
    // does NOT keep its own copies of filter/sort/current-row state.
    // All such state lives in the recordset; the form reads it on
    // every render, which guarantees consistency between GUI and CLI.
    // =====================================================================
    // =====================================================================
    // ErrorDialog: the standard error presenter, replacing bare
    // MessageBox for error conditions. Differences that matter to a
    // screen-reader user: the details live in a read-only multiline
    // TextBox (focused on open, so JAWS reads it immediately, and the
    // text is reviewable line by line and selectable), and a Copy
    // button (Alt+C) puts the full details on the clipboard for
    // pasting into a chat, an email, or an issue. Escape or Enter
    // closes. Every error shown here is also written to the log.
    // =====================================================================
    public static class ErrorDialog
    {
        public static void show(IWin32Window owner, string sTitle, string sText)
        {
            show(owner, sTitle, sText, false);
        }

        // Exception-aware overload: leads with a friendly,
        // plain-language explanation of common database errors,
        // then the raw message, the ADO provider's Errors
        // collection (via the manager), and the full .NET stack
        // trace -- all in the dialog's copyable details box, so
        // Copy captures a complete log for a bug report.
        public static void show(IWin32Window owner, string sTitle, Exception ex, DbDoManager mgr)
        {
            System.Text.StringBuilder sbAll = new System.Text.StringBuilder();
            string sFriendly = friendlyAdoMessage(ex != null ? ex.Message : "");
            if (sFriendly.Length > 0)
            {
                sbAll.AppendLine(sFriendly);
                sbAll.AppendLine();
            }
            sbAll.AppendLine("Message: " + (ex != null ? ex.Message : "(none)"));
            if (mgr != null)
            {
                string sDiag = mgr.adoDiagnostics();
                if (sDiag.Length > 0) { sbAll.AppendLine(); sbAll.Append(sDiag); }
            }
            if (ex != null)
            {
                sbAll.AppendLine();
                sbAll.AppendLine("Stack trace:");
                sbAll.AppendLine(ex.ToString());
            }
            show(owner, sTitle, sbAll.ToString(), false);
        }

        // friendlyAdoMessage: translate the database errors users
        // actually hit into plain language with a next step. Returns
        // "" when no translation applies (the raw message follows
        // either way).
        private static string friendlyAdoMessage(string sRaw)
        {
            string sLow = (sRaw ?? "").ToLowerInvariant();
            if (sLow.Contains("unique constraint"))
                return "A value that must be unique (such as prm or a key) already exists in another record. Change the value and try again.";
            if (sLow.Contains("foreign key constraint"))
                return "Another table still references this record, so the database refused the change. Remove or repoint the related records first.";
            if (sLow.Contains("not null constraint"))
                return "A required field was left null. Give it a value (Control+Shift+Backspace sets null; type to provide a value).";
            if (sLow.Contains("database is locked") || sLow.Contains("locked"))
                return "Another program (or another DbDo window mid-write) is holding the database file. Close the other writer or retry in a moment.";
            if (sLow.Contains("no such table"))
                return "The table named in the statement does not exist in this database. Check spelling, or press F6 to list tables.";
            if (sLow.Contains("no such column"))
                return "A column named in the statement does not exist in this table. Alt+Enter lists the table's columns.";
            if (sLow.Contains("syntax error"))
                return "SQLite could not parse the SQL statement. Check the syntax near the place the raw message names.";
            if (sLow.Contains("read-only") || sLow.Contains("readonly"))
                return "The recordset or file is read-only, so writes are refused. If the Alt+Z safeguard is on, turn it off; views and query joins cannot be made writable.";
            return "";
        }

        // bOfferQuit: the global runtime-error handlers pass true, so
        // a user caught in a repeating error (one that re-fires as
        // soon as the dialog closes) always has a one-keystroke way
        // out -- Quit (Alt+Q) exits DbDo immediately instead of
        // forcing Task Manager.
        public static void show(IWin32Window owner, string sTitle, string sText, bool bOfferQuit)
        {
            try { DbDoLog.write("ERROR [" + sTitle + "]: " + sText); } catch { }
            try
            {
                using (Form dlg = new LbcForm())
                {
                    dlg.Text = sTitle + " - DbDo Error";
                    dlg.StartPosition = FormStartPosition.CenterParent;
                    dlg.FormBorderStyle = FormBorderStyle.FixedDialog;
                    dlg.MinimizeBox = false; dlg.MaximizeBox = false;
                    dlg.ShowInTaskbar = false;
                    dlg.ClientSize = new System.Drawing.Size(560, 320);

                    Label lbl = new Label();
                    lbl.Text = "Error &details:";
                    lbl.SetBounds(12, 9, 536, 18);

                    LbcTextBox tb = new LbcTextBox();
                    tb.Multiline = true; tb.ReadOnly = true;
                    tb.ScrollBars = ScrollBars.Vertical; tb.WordWrap = true;
                    tb.Text = sText;
                    tb.SetBounds(12, 30, 536, 240);
                    tb.TabIndex = 0;

                    Button btnCopy = new Button();
                    btnCopy.Text = "&Copy";
                    btnCopy.SetBounds(372, 282, 80, 26);
                    btnCopy.TabIndex = 1;
                    btnCopy.Click += (sndr, evA) =>
                    {
                        bool bOk = false;
                        try
                        {
                            Clipboard.SetDataObject(sTitle + "\r\n\r\n" + sText, true, 5, 100);
                            bOk = true;
                        }
                        catch { }
                        MessageBox.Show(dlg,
                            bOk ? "Error details copied to the clipboard."
                                : "Could not access the clipboard. Select the text and press Control+C instead.",
                            "Copy", MessageBoxButtons.OK,
                            bOk ? MessageBoxIcon.Information : MessageBoxIcon.Warning);
                    };

                    Button btnClose = new Button();
                    btnClose.Text = "C&lose";
                    btnClose.SetBounds(468, 282, 80, 26);
                    btnClose.TabIndex = 2;
                    btnClose.DialogResult = DialogResult.OK;

                    Button btnQuit = null;
                    if (bOfferQuit)
                    {
                        btnQuit = new Button();
                        btnQuit.Text = "&Quit DbDo";
                        btnQuit.SetBounds(264, 282, 96, 26);
                        btnQuit.TabIndex = 3;
                        btnQuit.Click += (sndr, evA) =>
                        {
                            try { DbDoLog.write("User chose Quit from the error dialog."); } catch { }
                            Environment.Exit(1);
                        };
                    }

                    Button btnEmailLog = new Button();
                    btnEmailLog.Text = "&Email Log";
                    btnEmailLog.SetBounds(156, 282, 100, 26);
                    btnEmailLog.TabIndex = 4;
                    btnEmailLog.Click += (sndr, evA) => { DbDoForm.emailLogFile(dlg); };

                    dlg.Controls.Add(lbl);
                    dlg.Controls.Add(tb);
                    dlg.Controls.Add(btnEmailLog);
                    if (btnQuit != null) dlg.Controls.Add(btnQuit);
                    dlg.Controls.Add(btnCopy);
                    dlg.Controls.Add(btnClose);
                    dlg.AcceptButton = btnClose;
                    dlg.CancelButton = btnClose;
                    dlg.Shown += (sndr, evA) => { tb.Focus(); tb.SelectionStart = 0; tb.SelectionLength = 0; };
                    if (owner != null) dlg.ShowDialog(owner); else dlg.ShowDialog();
                }
            }
            catch
            {
                // Last-resort fallback: the plain MessageBox still
                // supports Control+C to copy its contents. This must
                // stay a MessageBox -- calling ErrorDialog.show here
                // would recurse on the very failure being handled.
                try { MessageBox.Show(owner, sText, sTitle, MessageBoxButtons.OK, MessageBoxIcon.Error); }
                catch { }
            }
        }

        // Exception overload: composes the context line, the exception
        // type and message, every inner exception, and the stack trace.
        public static void show(IWin32Window owner, string sTitle, string sContext, Exception ex)
        {
            show(owner, sTitle, sContext, ex, false);
        }

        public static void show(IWin32Window owner, string sTitle, string sContext, Exception ex, bool bOfferQuit)
        {
            StringBuilder sb = new StringBuilder();
            if (!string.IsNullOrEmpty(sContext)) { sb.AppendLine(sContext); sb.AppendLine(); }
            Exception exWalk = ex;
            while (exWalk != null)
            {
                sb.AppendLine(exWalk.GetType().Name + ": " + exWalk.Message);
                exWalk = exWalk.InnerException;
                if (exWalk != null) sb.AppendLine("Caused by:");
            }
            if (ex != null && !string.IsNullOrEmpty(ex.StackTrace))
            {
                sb.AppendLine();
                sb.AppendLine("Stack trace:");
                sb.AppendLine(ex.StackTrace);
            }
            show(owner, sTitle, sb.ToString().TrimEnd(), bOfferQuit);
        }

        // Repeat suppression for the global handlers: when the SAME
        // error fires again within the window (the classic paint-loop
        // failure, where closing the dialog immediately re-raises the
        // exception), it is logged but NOT re-shown -- the loop that
        // previously required killing the task cannot recur.
        private static string sLastShownError = "";
        private static DateTime dtLastShown = DateTime.MinValue;
        public static bool shouldShowRepeat(string sErrorText)
        {
            try
            {
                DateTime dtNow = DateTime.UtcNow;
                if (sErrorText == sLastShownError
                    && (dtNow - dtLastShown).TotalSeconds < 5)
                {
                    DbDoLog.write("Suppressed repeat error dialog (same error within 5s).");
                    return false;
                }
                sLastShownError = sErrorText;
                dtLastShown = dtNow;
            }
            catch { }
            return true;
        }
    }

    // =====================================================================
    // LbcListView: the Lbc-enhanced ListView that embodies DbDo's
    // "db cursor" concept.
    //
    // The db cursor is the user's position in the current recordset:
    // a current ROW and a current COLUMN.
    //
    //   Row    -- always the ListView's single focused row. Whenever
    //             the recordset has at least one row, exactly one row
    //             carries both keyboard focus and ListView selection
    //             (ensureCursorRow enforces the invariant). ListView
    //             selection is purely the cursor; multi-row selection
    //             semantics belong to DbDo's mark infrastructure (the
    //             standard boolean 'marked' column, Set Mark
    //             Control+M, Clear Mark, Toggle Marked Control+Space,
    //             and the marked-navigation family).
    //   Column -- a virtual construct: the standard ListView has no
    //             cell focus, so the current column lives here as
    //             cursorColumn (0-based display-column index) and is
    //             voiced rather than drawn. The owning form keeps the
    //             ADO absolutePosition (1-based) as the row's source
    //             of truth and mirrors it to the focused row.
    //
    // Column-preservation principle: the cursor column persists
    // across row movement (arrows, PageUp/PageDown, jumps, refresh)
    // and changes only when a command explicitly or implicitly says
    // otherwise (Home/End, Alt+Control+LeftArrow/RightArrow, the
    // corner moves, type-ahead column targeting, or a table switch
    // restoring that table's remembered column by name).
    // =====================================================================
    public class LbcListView : ListView
    {
        // Fields
        private int iCursorColumn = 0;

        // cursorColumn: 0-based index of the db cursor's current
        // column among the displayed columns. Clamped on set.
        public int cursorColumn
        {
            get { return iCursorColumn; }
            set
            {
                int iMax = (Columns.Count > 0) ? Columns.Count - 1 : 0;
                if (value < 0) value = 0;
                if (value > iMax) value = iMax;
                iCursorColumn = value;
            }
        }

        // cursorRowIndex: 0-based index of the db cursor's row (the
        // focused row), or -1 when the list is empty.
        public int cursorRowIndex
        {
            get
            {
                if (FocusedItem != null) return FocusedItem.Index;
                if (SelectedIndices.Count > 0) return SelectedIndices[0];
                return -1;
            }
        }

        // ensureCursorRow: enforce the invariant that a non-empty
        // list always has exactly one row carrying both focus and
        // selection. Returns true when a row holds the cursor on
        // exit. Safe in VirtualMode (SelectedIndices.Add and Items[i]
        // both work against virtual items).
        public bool ensureCursorRow()
        {
            int iRow;
            if (VirtualListSize <= 0 && !VirtualMode && Items.Count == 0) return false;
            if (VirtualMode && VirtualListSize <= 0) return false;
            iRow = cursorRowIndex;
            if (iRow < 0) iRow = 0;
            try
            {
                if (SelectedIndices.Count == 0) SelectedIndices.Add(iRow);
                if (FocusedItem == null) Items[iRow].Focused = true;
                // Force the native selected + focused state so screen
                // readers see a real selection, not the focused-but-
                // unselected state that managed selection leaves in
                // VirtualMode (which JAWS announced as "Unselected").
                selectAndFocusNative(iRow);
            }
            catch { return false; }
            return true;
        }

        // ---- Native selection state (VirtualMode) ----
        // WinForms' SelectedIndices.Add sets the managed selection, but
        // in VirtualMode the native list-item state that MSAA / UIA
        // (and therefore JAWS) read for "selected" is not reliably set
        // until the control is focused and the user acts (pressing
        // Space). That left the current row announced as "Unselected"
        // on first open. Sending LVM_SETITEMSTATE with LVIS_SELECTED |
        // LVIS_FOCUSED reproduces exactly what Space does, so the row
        // reads as selected immediately and on every programmatic move.
        private const int c_iLvmFirst = 0x1000;
        private const int c_iLvmSetItemState = c_iLvmFirst + 43;
        private const int c_iLvisFocused = 0x0001;
        private const int c_iLvisSelected = 0x0002;

        [StructLayout(LayoutKind.Sequential, CharSet = CharSet.Auto)]
        private struct LVITEM
        {
            public int mask;
            public int iItem;
            public int iSubItem;
            public int state;
            public int stateMask;
            public IntPtr pszText;
            public int cchTextMax;
            public int iImage;
            public IntPtr lParam;
            public int iIndent;
            public int iGroupId;
            public int cColumns;
            public IntPtr puColumns;
            public IntPtr piColFmt;
            public int iGroup;
        }

        [DllImport("user32.dll", CharSet = CharSet.Auto)]
        private static extern IntPtr SendMessage(IntPtr hWnd, int iMsg, IntPtr wParam, ref LVITEM lvi);

        // selectAndFocusNative: force native LVIS_SELECTED | LVIS_FOCUSED
        // on the given 0-based row. Only state and stateMask are used by
        // LVM_SETITEMSTATE. Best-effort; never throws.
        public void selectAndFocusNative(int iIndex)
        {
            if (iIndex < 0 || !IsHandleCreated) return;
            if (VirtualMode && iIndex >= VirtualListSize) return;
            try
            {
                LVITEM lvi = new LVITEM();
                lvi.stateMask = c_iLvisSelected | c_iLvisFocused;
                lvi.state = c_iLvisSelected | c_iLvisFocused;
                SendMessage(this.Handle, c_iLvmSetItemState, (IntPtr)iIndex, ref lvi);
            }
            catch { }
        }
    }

    // DbDoFrame: the MDI container window. DbDo uses a multiple-window model: each open recordset (typically a
    // table) lives in its own MDI child window (a DbDoForm), and the
    // window-management commands carry these command names and
    // keys: Current Windows (F4), Say Windows Open (Shift+F4),
    // Close Window (Control+F4), Close All But Current Window
    // (Control+Shift+F4), Next Window (Control+Tab), Previous Window
    // (Control+Shift+Tab), and Window Toggle (Shift+W). The handlers
    // live on DbDoForm (whose menu and ProcessCmdKey dispatch already
    // exist); they act through this frame. The frame itself carries
    // no MenuStrip: each child keeps its own menu bar, so the 200+
    // existing menu handlers continue to work unchanged and no
    // ToolStripManager merge is involved.
    //
    // Each child owns its own DbDoManager (and therefore its own
    // connection), a one-view-per-window model.
    // This deviates from the one-connection-per-database-file policy
    // adopted for recordsets WITHIN a manager; the deviation is
    // deliberate (per-window state is fully encapsulated, and SQLite
    // tolerates multiple local connections), and a shared-manager
    // registry remains a possible later refinement.
    public class DbDoFrame : Form
    {
        // Fields, grouped by type, types and names alphabetical.
        // The single frame instance, reachable in one place: one instance in scope, so the class-name
        // abbreviation alone is the variable name per Camel Type.
        public static DbDoFrame frame;
        private Form frmPriorActive;   // for Window Toggle: the child active before the current one
        private Form frmRecentActive;  // the currently/most recently active child
        private MenuStrip menuFrame;   // the frame-level menu bar (see constructor comment)

        public DbDoFrame()
        {
            frame = this;
            this.IsMdiContainer = true;
            // The frame owns the application's menu bar: in MDI, Alt activates the FRAME's MenuStrip,
            // so a menu living only on a child is unreachable (Alt
            // falls through to the system menu). Where a typical MDI app builds every menu
            // on the frame and routes handlers
            // through GetActiveChild(), DbDo instead relies on the
            // WinForms automatic MDI menu merge: each DbDoForm child
            // keeps building its own MenuStrip (with MainMenuStrip set,
            // which it already does), and on activation the framework
            // merges those items into this frame strip -- so the
            // user-visible result is identical (one menu bar on the
            // frame: File, Edit, Navigate, Query, Misc, Window, Help)
            // while the 200+ handlers stay on the child whose state
            // they manipulate. This is the deliberate improvement over
            // the Homer-app pattern: no GetActiveChild() indirection,
            // and per-window state stays encapsulated.
            menuFrame = new MenuStrip();
            menuFrame.AccessibleName = "Main menu";
            menuFrame.AllowMerge = true;
            menuFrame.Dock = DockStyle.Top;
            this.MainMenuStrip = menuFrame;
            this.Controls.Add(menuFrame);
            this.StartPosition = FormStartPosition.CenterScreen;
            this.Text = "DbDo";
            this.WindowState = FormWindowState.Maximized;
            this.MdiChildActivate += frameChildActivated;
            // When the last child closes, the frame closes too: with
            // no child there is no menu bar, so an empty frame would
            // be a dead end for a keyboard user.
            this.MdiChildActivate += delegate(object sender, EventArgs evX)
            {
                if (this.MdiChildren.Length == 0 && this.Visible) this.BeginInvoke((Action)delegate
                {
                    if (this.MdiChildren.Length == 0) this.Close();
                });
            };
        }

        // Track the most-recently-used pair of children so Window
        // Toggle can flip between them.
        private void frameChildActivated(object sender, EventArgs evArgs)
        {
            Form frmNow = this.ActiveMdiChild;
            if (frmNow == null || frmNow == frmRecentActive) return;
            frmPriorActive = frmRecentActive;
            frmRecentActive = frmNow;
        }

        public DbDoForm getActiveChild()
        {
            return this.ActiveMdiChild as DbDoForm;
        }

        // recentChild: the most recently active table window. Used by
        // the Dot Prompt's follow-active-window context resolution.
        // The MRU field is what was active even when focus has since
        // moved outside the frame (e.g., to the console window), which
        // is exactly the "previously opened MDI child" the prompt
        // should treat as current context.
        public DbDoForm recentChild()
        {
            DbDoForm frmRecent = frmRecentActive as DbDoForm;
            if (frmRecent != null && !frmRecent.IsDisposed) return frmRecent;
            return getActiveChild();
        }

        // openChildWindow: open a database (and optionally a table) in
        // a new MDI child window. Used by Open Table and available to
        // future Open-X commands per the Open-versus-Go-to
        // pattern (Open = new window, Go to = same window).
        // openQueryWindow: a child window holding the result of a
        // manual SELECT. The window's own manager opens the database
        // (no table), then the ad-hoc recordset; updatability is
        // decided inside openSqlRecordset (single base table ->
        // editable; otherwise innately read-only).
        public DbDoForm openQueryWindow(string sFile, string sSql)
        {
            DbDoForm frmChild = new DbDoForm(Program.UiMode.Gui);
            frmChild.MdiParent = this;
            try
            {
                frmChild.Db.openDatabase(sFile, null, false);
                frmChild.Db.openSqlRecordset(sSql);
                frmChild.invokeRefresh();
            }
            catch (Exception ex)
            {
                frmChild.Close();
                ErrorDialog.show(this, "Query", ex.Message);
                return null;
            }
            frmChild.Show();
            frmChild.Activate();
            return frmChild;
        }

        public DbDoForm openChildWindow(Program.UiMode mode, string sFile, string sTable)
        {
            DbDoForm frmChild = new DbDoForm(mode);
            frmChild.MdiParent = this;
            if (!string.IsNullOrEmpty(sFile))
            {
                try
                {
                    frmChild.Db.openDatabase(sFile, sTable, false);
                    frmChild.invokeRefresh();
                }
                catch (Exception ex)
                {
                    ErrorDialog.show(this, "Open Table", ex.Message);
                }
            }
            frmChild.Show();
            frmChild.Activate();
            return frmChild;
        }

        // findDrillChild: locate an open MDI child already showing a
        // related view for the same database file, target table, and
        // WHERE clause -- so Enter-Child reactivates it instead of
        // opening a duplicate window. The calling window is skipped.
        public DbDoForm findDrillChild(string sFile, string sTable, string sWhere, DbDoForm frmCaller)
        {
            foreach (Form frm in this.MdiChildren)
            {
                DbDoForm frmChild = frm as DbDoForm;
                if (frmChild == null || frmChild.IsDisposed || frmChild == frmCaller) continue;
                if (!string.Equals(frmChild.sDrillTable ?? "", sTable ?? "", StringComparison.OrdinalIgnoreCase)) continue;
                if (!string.Equals(frmChild.sDrillWhere ?? "", sWhere ?? "", StringComparison.Ordinal)) continue;
                string sChildFile = "";
                try { sChildFile = frmChild.Db.filePath ?? ""; } catch { }
                if (!string.Equals(sChildFile, sFile ?? "", StringComparison.OrdinalIgnoreCase)) continue;
                return frmChild;
            }
            return null;
        }

        // toggleWindow: activate the child that was active before the
        // current one (Window Toggle, Shift+W).
        public void toggleWindow()
        {
            if (this.MdiChildren.Length < 2) { LiveRegion.say("Only this window!"); return; }
            Form frmTarget = frmPriorActive;
            if (frmTarget == null || frmTarget.IsDisposed || frmTarget == this.ActiveMdiChild)
            {
                // No usable MRU partner yet: fall back to next window.
                stepWindow(true);
                return;
            }
            frmTarget.Activate();
            // Not announced through the live region: activating a window
            // makes it the active window, and JAWS speaks the new
            // window's title on that change, so repeating it here would
            // be double speech.
        }

        // stepWindow: activate the next (bNext true) or previous child
        // in MdiChildren order, wrapping at the ends. Next
        // Window / Previous Window.
        public void stepWindow(bool bNext)
        {
            Form[] aChildren = this.MdiChildren;
            int iPosition;
            if (aChildren.Length == 0) { LiveRegion.say("No windows!"); return; }
            if (aChildren.Length == 1) { LiveRegion.say("Only this window!"); return; }
            iPosition = Array.IndexOf(aChildren, this.ActiveMdiChild) + (bNext ? 1 : -1);
            if (iPosition >= aChildren.Length) iPosition = 0;
            if (iPosition < 0) iPosition = aChildren.Length - 1;
            aChildren[iPosition].Activate();
            // Not announced: JAWS speaks the newly active window's title
            // on the active-window change (Next / Previous Window also
            // still echo their command name when command echo is on).
        }

        // closeAllButCurrent: Close All But Current Window. Confirms
        // with a count of the windows closed.
        public void closeAllButCurrent()
        {
            Form frmKeep = this.ActiveMdiChild;
            if (frmKeep == null) return;
            int iClosed = 0;
            foreach (Form frmChild in this.MdiChildren)
            {
                if (frmChild != frmKeep) { frmChild.Close(); iClosed++; }
            }
            // The kept window was already active, so JAWS does not
            // re-announce it. Confirm the action with a count instead of
            // speaking the surviving window's title.
            LiveRegion.sayForced(iClosed == 0
                ? "No other windows to close."
                : iClosed + " other window" + (iClosed == 1 ? "" : "s") + " closed.");
        }

        // windowTitles: the children's titles in MdiChildren order,
        // for Current Windows and Say Windows Open.
        public List<string> windowTitles()
        {
            List<string> lsTitles = new List<string>();
            foreach (Form frmChild in this.MdiChildren) lsTitles.Add(frmChild.Text);
            return lsTitles;
        }

        public void activateByTitle(string sTitle)
        {
            foreach (Form frmChild in this.MdiChildren)
            {
                if (frmChild.Text == sTitle) { frmChild.Activate(); return; }
            }
        }
    }

    // DbfReader: a self-contained dBASE (.dbf) reader -- no Office/ACE.
    // Handles dBASE III/IV tables with C/N/F/D/L/I fields and M (memo)
    // fields backed by a .dbt sidecar (dBASE III, 512-byte blocks).
    // Validated in Python against a real .dbf/.dbt sample and a synthetic
    // memo-bearing file. Dates become ISO (YYYY-MM-DD), logicals become
    // true/false, char fields are right-trimmed, deleted records skipped.
    internal static class DbfReader
    {
        internal class Result
        {
            public List<string> Columns = new List<string>();
            public List<string[]> Rows = new List<string[]>();
        }

        internal static Result read(string sDbfPath)
        {
            if (string.IsNullOrEmpty(sDbfPath)) throw new ArgumentException("DbfReader.read requires a path.");
            if (!File.Exists(sDbfPath)) throw new FileNotFoundException("DBF not found.", sDbfPath);
            byte[] d = File.ReadAllBytes(sDbfPath);
            if (d.Length < 33) throw new Exception("Not a valid DBF (too short).");

            int iRecCount = BitConverter.ToInt32(d, 4);
            int iHeaderLen = BitConverter.ToUInt16(d, 8);
            int iRecLen = BitConverter.ToUInt16(d, 10);
            Encoding enc = encodingFor(d.Length > 29 ? d[29] : (byte)0);

            List<string> lNames = new List<string>();
            List<char> lTypes = new List<char>();
            List<int> lLens = new List<int>();
            int iOff = 32;
            while (iOff + 32 <= d.Length && d[iOff] != 0x0D)
            {
                int iNameEnd = 0;
                while (iNameEnd < 11 && d[iOff + iNameEnd] != 0) iNameEnd++;
                lNames.Add(Encoding.ASCII.GetString(d, iOff, iNameEnd).Trim());
                lTypes.Add((char)d[iOff + 11]);
                lLens.Add(d[iOff + 16]);
                iOff += 32;
            }

            Result res = new Result();
            res.Columns = lNames;

            byte[] dbt = null;
            bool bHasMemo = lTypes.Contains('M');
            if (bHasMemo)
            {
                string sBase = Path.Combine(Path.GetDirectoryName(Path.GetFullPath(sDbfPath)),
                    Path.GetFileNameWithoutExtension(sDbfPath));
                foreach (string sE in new string[] { ".dbt", ".DBT" })
                    if (File.Exists(sBase + sE)) { try { dbt = File.ReadAllBytes(sBase + sE); } catch { } break; }
            }

            for (int r = 0; r < iRecCount; r++)
            {
                int b = iHeaderLen + r * iRecLen;
                if (b + iRecLen > d.Length) break;
                if (d[b] == (byte)'*') continue;       // deleted record
                int p = b + 1;
                string[] aRow = new string[lNames.Count];
                for (int f = 0; f < lNames.Count; f++)
                {
                    int iLen = lLens[f];
                    string sRaw = (p + iLen <= d.Length) ? enc.GetString(d, p, iLen) : "";
                    p += iLen;
                    aRow[f] = convertField(lTypes[f], sRaw, dbt, enc);
                }
                res.Rows.Add(aRow);
            }
            return res;
        }

        private static string convertField(char cType, string sRaw, byte[] dbt, Encoding enc)
        {
            switch (cType)
            {
                case 'C': return sRaw.TrimEnd();                 // right-padded with spaces
                case 'N': case 'F': case 'B': case 'I': case 'Y': return sRaw.Trim();
                case 'D':
                {
                    string v = sRaw.Trim();
                    if (v.Length == 8 && allDigits(v) && v != "00000000")
                        return v.Substring(0, 4) + "-" + v.Substring(4, 2) + "-" + v.Substring(6, 2);
                    return "";
                }
                case 'L':
                {
                    string v = sRaw.Trim();
                    char c = v.Length > 0 ? char.ToUpperInvariant(v[0]) : ' ';
                    if (c == 'T' || c == 'Y') return "true";
                    if (c == 'F' || c == 'N') return "false";
                    return "";
                }
                case 'M': return readMemo(sRaw, dbt, enc);
                default: return sRaw.Trim();
            }
        }

        // readMemo: a dBASE III memo pointer is the block number as text;
        // the text lives at block*512 in the .dbt, terminated by 0x1A.
        private static string readMemo(string sPtr, byte[] dbt, Encoding enc)
        {
            string s = sPtr.Trim();
            if (s.Length == 0 || !allDigits(s) || dbt == null) return "";
            int iBlk;
            if (!int.TryParse(s, out iBlk) || iBlk <= 0) return "";
            int iStart = iBlk * 512;
            if (iStart >= dbt.Length) return "";
            int iEnd = iStart;
            while (iEnd < dbt.Length && dbt[iEnd] != 0x1A) iEnd++;
            return enc.GetString(dbt, iStart, iEnd - iStart);
        }

        private static bool allDigits(string s)
        {
            if (s.Length == 0) return false;
            foreach (char c in s) if (c < '0' || c > '9') return false;
            return true;
        }

        // encodingFor: pick a text encoding from the DBF language-driver
        // byte; default to Windows-1252, falling back to Latin-1 (which is
        // byte-lossless) if a code page is unavailable.
        private static Encoding encodingFor(byte bLang)
        {
            int iCp;
            switch (bLang)
            {
                case 0x01: iCp = 437; break;   // US MS-DOS
                case 0x02: iCp = 850; break;   // International MS-DOS
                case 0x03: iCp = 1252; break;  // Windows ANSI
                case 0x64: iCp = 852; break;   // Eastern European MS-DOS
                case 0x65: iCp = 866; break;   // Russian MS-DOS
                case 0x6A: iCp = 737; break;   // Greek MS-DOS
                case 0xC8: iCp = 1250; break;  // Windows EE
                case 0xC9: iCp = 1251; break;  // Russian Windows
                default:   iCp = 1252; break;
            }
            try { return Encoding.GetEncoding(iCp); }
            catch { try { return Encoding.GetEncoding(28591); } catch { return Encoding.ASCII; } }
        }
    }

    // XlsxNpoi: a self-contained .xlsx engine over NPOI -- no Office,
    // no bitness dependency (NPOI is managed/AnyCPU). It does two jobs:
    //   readFirstSheet  -- read the first non-empty worksheet's used
    //                      range into a faithful model (headers, the
    //                      worksheet row index of every data row, and
    //                      the displayed value of every cell).
    //   writeBackData   -- reopen the ORIGINAL workbook and set only
    //                      the data cells the user changed, NEVER a
    //                      formula cell, then flag recalc-on-open and
    //                      save. Because the original workbook is
    //                      reopened and patched (not regenerated), the
    //                      other sheets, charts, formatting, and the
    //                      formulas themselves are preserved -- so the
    //                      file a sighted user opens in Excel stays
    //                      intact, with data edits applied.
    // This class touches NPOI only; it is independent of DbDo's grid
    // and can be exercised on its own. NPOI types are fully qualified
    // so no using-directive changes are needed.
    internal static class XlsxNpoi
    {
        internal class SheetModel
        {
            public string Name;
            public int HeaderRowIndex;
            public int ColCount;
            public List<string> Headers = new List<string>();
            public List<int> WsRowIndexes = new List<int>();   // worksheet row of each data row
            public List<string[]> Rows = new List<string[]>(); // display text, aligned to Headers
        }

        internal class CellWrite
        {
            public int WsRow;
            public int Col;
            public string Value;
        }

        internal static SheetModel readFirstSheet(string sPath)
        {
            NPOI.SS.UserModel.IWorkbook wb = null;
            using (FileStream fs = new FileStream(sPath, FileMode.Open, FileAccess.Read))
                wb = new NPOI.XSSF.UserModel.XSSFWorkbook(fs);  // read fully into memory
            try
            {
                NPOI.SS.UserModel.ISheet sheet = null;
                for (int s = 0; s < wb.NumberOfSheets; s++)
                {
                    NPOI.SS.UserModel.ISheet sh = wb.GetSheetAt(s);
                    if (sh != null && sh.PhysicalNumberOfRows > 0) { sheet = sh; break; }
                }
                if (sheet == null && wb.NumberOfSheets > 0) sheet = wb.GetSheetAt(0);
                if (sheet == null) throw new Exception("The workbook has no worksheets.");

                NPOI.SS.UserModel.DataFormatter fmt = new NPOI.SS.UserModel.DataFormatter();
                SheetModel m = new SheetModel();
                m.Name = sheet.SheetName;
                int iFirst = sheet.FirstRowNum;
                int iLast = sheet.LastRowNum;
                m.HeaderRowIndex = iFirst;

                NPOI.SS.UserModel.IRow headerRow = sheet.GetRow(iFirst);
                int iColCount = 0;
                if (headerRow != null && headerRow.LastCellNum > 0) iColCount = headerRow.LastCellNum;
                m.ColCount = iColCount;
                for (int c = 0; c < iColCount; c++)
                {
                    NPOI.SS.UserModel.ICell hc = (headerRow != null) ? headerRow.GetCell(c) : null;
                    string sH = (hc != null) ? fmt.FormatCellValue(hc) : "";
                    if (string.IsNullOrEmpty(sH)) sH = "column_" + (c + 1);
                    m.Headers.Add(sH);
                }

                for (int r = iFirst + 1; r <= iLast; r++)
                {
                    NPOI.SS.UserModel.IRow row = sheet.GetRow(r);
                    string[] aVals = new string[iColCount];
                    bool bAny = false;
                    for (int c = 0; c < iColCount; c++)
                    {
                        NPOI.SS.UserModel.ICell cell = (row != null) ? row.GetCell(c) : null;
                        string sv = readCellText(cell, fmt);
                        aVals[c] = sv;
                        if (sv.Length > 0) bAny = true;
                    }
                    if (!bAny) continue;
                    m.WsRowIndexes.Add(r);
                    m.Rows.Add(aVals);
                }
                return m;
            }
            finally { try { wb.Close(); } catch { } }
        }

        // writeBackData: returns the number of data cells written. Formula
        // cells are skipped (preserved). The workbook is reopened, patched
        // in memory, written to a sibling temp file, then moved over the
        // original, so a write failure can't truncate the source.
        internal static int writeBackData(string sPath, string sSheetName, List<CellWrite> lWrites)
        {
            NPOI.SS.UserModel.IWorkbook wb = null;
            using (FileStream fs = new FileStream(sPath, FileMode.Open, FileAccess.Read))
                wb = new NPOI.XSSF.UserModel.XSSFWorkbook(fs);
            int iWritten = 0;
            string sTmp = null;
            try
            {
                NPOI.SS.UserModel.ISheet sheet = wb.GetSheet(sSheetName);
                if (sheet == null && wb.NumberOfSheets > 0) sheet = wb.GetSheetAt(0);
                if (sheet == null) throw new Exception("The workbook has no worksheet named " + sSheetName + ".");

                foreach (CellWrite w in lWrites)
                {
                    NPOI.SS.UserModel.IRow row = sheet.GetRow(w.WsRow);
                    if (row == null) row = sheet.CreateRow(w.WsRow);
                    NPOI.SS.UserModel.ICell cell = row.GetCell(w.Col);
                    if (cell == null) cell = row.CreateCell(w.Col);
                    if (cell.CellType == NPOI.SS.UserModel.CellType.Formula) continue; // preserve formula
                    applyValue(cell, w.Value);
                    iWritten++;
                }
                // SetForceFormulaRecalculation lives on the concrete
                // XSSFWorkbook, not the IWorkbook interface, so cast to
                // reach it. wb here is always an XSSFWorkbook (opened as
                // one above). This sets fullCalcOnLoad so Excel
                // recalculates every formula when it opens the file.
                NPOI.XSSF.UserModel.XSSFWorkbook xwb = wb as NPOI.XSSF.UserModel.XSSFWorkbook;
                if (xwb != null) xwb.SetForceFormulaRecalculation(true);

                sTmp = Path.Combine(
                    Path.GetDirectoryName(Path.GetFullPath(sPath)),
                    Path.GetFileNameWithoutExtension(sPath) + ".dbdo-save-" + Guid.NewGuid().ToString("N") + ".tmp");
                using (FileStream fo = new FileStream(sTmp, FileMode.Create, FileAccess.Write))
                    wb.Write(fo);
                try { wb.Close(); } catch { }
                File.Copy(sTmp, sPath, true);
                return iWritten;
            }
            finally
            {
                try { wb.Close(); } catch { }
                try { if (sTmp != null && File.Exists(sTmp)) File.Delete(sTmp); } catch { }
            }
        }

        // readCellText: a clean, round-trippable string for a cell --
        // strings verbatim (so codes like "02143" keep their leading
        // zero), numbers in invariant form, dates as ISO, booleans as
        // true/false, and formulas shown as their cached displayed value.
        private static string readCellText(NPOI.SS.UserModel.ICell cell, NPOI.SS.UserModel.DataFormatter fmt)
        {
            if (cell == null) return "";
            switch (cell.CellType)
            {
                case NPOI.SS.UserModel.CellType.String:
                    return cell.StringCellValue ?? "";
                case NPOI.SS.UserModel.CellType.Boolean:
                    return cell.BooleanCellValue ? "true" : "false";
                case NPOI.SS.UserModel.CellType.Numeric:
                    if (NPOI.SS.UserModel.DateUtil.IsCellDateFormatted(cell))
                    {
                        try { return cell.DateCellValue.ToString("yyyy-MM-dd", System.Globalization.CultureInfo.InvariantCulture); }
                        catch { return fmt.FormatCellValue(cell); }
                    }
                    return cell.NumericCellValue.ToString(System.Globalization.CultureInfo.InvariantCulture);
                case NPOI.SS.UserModel.CellType.Formula:
                    return fmt.FormatCellValue(cell);
                case NPOI.SS.UserModel.CellType.Blank:
                    return "";
                default:
                    return fmt.FormatCellValue(cell);
            }
        }

        // applyValue: set the cell's value while honoring its ORIGINAL
        // type so we don't, say, turn a text ZIP code into a number. If
        // the edited text can't fit the original type, fall back to text.
        private static void applyValue(NPOI.SS.UserModel.ICell cell, string sVal)
        {
            if (sVal == null) sVal = "";
            NPOI.SS.UserModel.CellType t = cell.CellType;
            if (t == NPOI.SS.UserModel.CellType.Numeric)
            {
                if (NPOI.SS.UserModel.DateUtil.IsCellDateFormatted(cell))
                {
                    DateTime dt;
                    if (DateTime.TryParse(sVal, System.Globalization.CultureInfo.InvariantCulture,
                            System.Globalization.DateTimeStyles.None, out dt))
                    { cell.SetCellValue(dt); return; }
                }
                else
                {
                    double d;
                    if (double.TryParse(sVal, System.Globalization.NumberStyles.Any,
                            System.Globalization.CultureInfo.InvariantCulture, out d))
                    { cell.SetCellValue(d); return; }
                }
                cell.SetCellValue(sVal); return;
            }
            if (t == NPOI.SS.UserModel.CellType.Boolean)
            {
                if (sVal.Equals("true", StringComparison.OrdinalIgnoreCase)) { cell.SetCellValue(true); return; }
                if (sVal.Equals("false", StringComparison.OrdinalIgnoreCase)) { cell.SetCellValue(false); return; }
                cell.SetCellValue(sVal); return;
            }
            cell.SetCellValue(sVal);
        }
    }

    public class DbDoForm : Form
    {
        // ------- Constants -------
        private const int InitialFormWidth = 1100;
        private const int InitialFormHeight = 700;

        // ------- Fields -------
        // The recordset/connection manager. PUBLIC so the C# scripting
        // feature (Help > Run C# Script) can reach the current
        // database/table/recordset via frm.db from script code.
        // Scripts get the same view of the data the form has -- no
        // facade in between.
        public DbDoManager db;
        // The main data view. A standard WinForms ListView in
        // Details mode is used instead of DataGridView because
        // screen readers (JAWS, NVDA, Narrator) read DataGridView
        // cells with verbose "row N column M" verbiage that is
        // difficult to suppress. A ListView is announced as a
        // simple "list" with each row being a "list item" -- the
        // same accessibility model as Windows Explorer's file
        // list, which all three readers handle cleanly.
        //
        // Trade-off: per-cell navigation goes away. The user moves
        // row-by-row with up/down arrows, hears the focused row
        // announced as a unit, and uses Show-Object (Enter) for a
        // field-by-field dump of the current row. Sort and column-
        // specific commands (Sort Ascending, Sort Descending, Next
        // Initial Change, Open Cell Value, Jump to Match, etc.)
        // each prompt for the column via a standard LBC dialog,
        // rather than reading a "current column" from Tab state.
        // Tab still moves an announcement-only column cursor that
        // the screen reader speaks as the user hops across cells
        // in a focused row, but Tab no longer targets commands.
        //
        // Virtual mode (VirtualMode=true) is essential. The list
        // never materializes more than a small window of
        // ListViewItems; row text is fetched from the ADO recordset
        // on demand via the RetrieveVirtualItem event. This keeps
        // memory tiny and load time near-zero even for 100K-row
        // tables.
        private LbcListView grid;

        // --- MDI drill linkage (Enter Child / Exit Child) ---------------
        // DbDo's drill is window-based, matching the app's "Open = new
        // window" model: Enter-Child opens the related view in a NEW MDI
        // child (or reactivates an existing one already showing the same
        // table + WHERE). Each drilled child remembers the window and row
        // it was opened FROM, so Exit-Child (Alt+Left / Backspace)
        // reactivates that caller on its original row, and Exit-to-Root
        // (Alt+Home) walks the chain back to the first window.
        public DbDoForm frmDrillCaller;     // window drilled in FROM; null on a root window
        public int      iDrillCallerRow;    // 1-based row to restore in the caller
        public string   sDrillTable = "";   // this window's drill target table (reactivation match)
        public string   sDrillWhere = "";   // this window's drill WHERE clause (reactivation match)
        // dLocalKeyToMenu: this window's own chord -> menu-item table.
        // Command dispatch (ProcessCmdKey) resolves chords here, against
        // THIS window's items, so a command acts on the focused window.
        // The static KeyMap keeps the first-registered binding for help,
        // summaries, and conflict detection only.
        private Dictionary<Keys, ToolStripMenuItem> dLocalKeyToMenu = new Dictionary<Keys, ToolStripMenuItem>();
        private MenuStrip menuMain;
        private StatusStrip statusBar;
        private ToolStripStatusLabel lblStatus;
        private ToolStripStatusLabel lblTable;
        private ContextMenuStrip ctxGrid;

        // Note: an older DataGridView build of DbDo carried a
        // private 'oCurrentData' DataTable here as its data source.
        // The virtual-mode ListView reads rows directly from the
        // ADO recordset via RetrieveVirtualItem, so the DataTable
        // is unused. The field has been removed; if you're reading
        // an older commit and miss it, that's why.
        private bool bSuppressCellChanged;
        // bGridFirstPopulate: true at startup until updateGrid sees a
        // nonzero record count. When the transition from zero to
        // nonzero happens, we explicitly announce row 1's content
        // via LiveRegion so the screen reader hears actual data
        // instead of the empty-list "Unselected" state JAWS reads on
        // the freshly-built listview before any row is selected.
        private bool bGridFirstPopulate = true;
        // sLastGridTable: the table whose data the grid currently
        // shows. updateGrid compares this to db.currentTable and
        // resets bGridFirstPopulate when the table changes -- so the
        // JAWS "Unselected" announcement workaround fires once per
        // table switch, not just on initial database open.
        private string sLastGridTable = "";

        // VirtualCursor: cell-level navigation overlay. The ListView
        // has no per-cell focus, but screen-reader users benefit from
        // table-style cell navigation (the same way JAWS/NVDA expose
        // an HTML or Word table). The virtual cursor is a (row, col)
        // pair that the user moves with Alt+Control+arrow chords;
        // movement triggers an announcement of the cell value plus
        // (when the direction warrants) the column header or row
        // label.
        //
        // Direction-aware announcement: announce the column header
        // ONLY when the column index changed since the last virtual
        // move; announce the row label ("Row N") ONLY when the row
        // index changed. Matches the JAWS table-reading idiom: in
        // vertical movement you hear just the value (assuming the
        // column is implied by context); in horizontal movement you
        // hear the column header first; in jumps to corners you
        // hear both row and column.
        //
        // The cursor is coupled to the ListView's row selection:
        // virtual row changes update the ListView selection (so the
        // user can see the row they're virtually browsing), and
        // ListView selection changes (from normal Down/Up arrows or
        // from a Jump/Find result) update the virtual row.
        private int iVirtualRow = 1;  // 1-based, matches ADO absolutePosition
        // iVirtualCol: the db cursor's column. The storage moved into
        // LbcListView.cursorColumn (the grid owns the cursor concept);
        // this delegating property keeps the established name working
        // at every existing reference. 0-based, matches ListView
        // column index.
        private int iVirtualCol
        {
            get { return (grid != null) ? grid.cursorColumn : 0; }
            set { if (grid != null) grid.cursorColumn = value; }
        }
        private int iPrevVirtualRow = -1;
        private int iPrevVirtualCol = -1;

        // F8 mark-anchor and Alt+F8 unmark-anchor: two independent
        // row-position anchors. Shift+F8 marks every row from the
        // mark anchor to the current row; Alt+Shift+F8 unmarks every
        // row from the unmark anchor to the current row. Direction-
        // agnostic on both: anchor can be above or below the current
        // row. -1 means "no anchor set yet"; both reset to -1 on
        // database close so a stale anchor from a different file
        // never bleeds across.
        private int iMarkAnchor = -1;
        private string sMarkAnchorTable = null;
        private int iUnmarkAnchor = -1;
        private string sUnmarkAnchorTable = null;

        // Spell-on-second-press: tracks the most recent speech-only
        // chord and its timestamp. If the user presses the same
        // chord within DoublePressMillis of the prior press, the
        // helper spells the spoken text instead of repeating it
        // verbatim. This is the convention for
        // their speech-only commands (Say Title, Say Status, etc.)
        //
        // The key is the chord's Keys value cast to int (using
        // System.Windows.Forms.Keys directly here, since this
        // entire form is already importing System.Windows.Forms).
        // Cleared on any non-speech key event so a stray Tab or
        // arrow press resets the double-press state.
        private int  iLastSpeechChord = 0;
        private long iLastSpeechTicks = 0;
        // Maximum gap between the two presses that count as a double-
        // press. NVDA's default multi-press timeout is around 500 ms;
        // JAWS uses a similar threshold for its NumPad5/Insert+T
        // doubles. We deliberately go higher (2,000 ms) so a thinking
        // pause between the first and second press still counts as
        // one gesture rather than two separate commands. The user can
        // always trigger a single-press behavior by waiting longer.
        private const int DoublePressMillis = 2000;

        // True after we've announced "Table has no rows" for the
        // current empty state. Prevents re-announcing on every
        // refresh while the user is still on the empty table.
        // Reset when the table changes OR the row count becomes
        // non-zero.
        private bool bAnnouncedEmpty = false;

        // Search-family state. Three independent search families with
        // separate "last-used" state for each, plus a single
        // sLastSearchKind tracker so F3 / Shift+F3 can repeat
        // whichever family was last invoked (per Jamal's design
        // spec; the "one pair of find-again chords for both
        // plain and regex" generalized to three).
        //
        //   Jump-Record (Control+J / Control+Shift+J): substring
        //   match scoped to ONE user-picked column. Useful for
        //   "show me the row where Email contains 'jamal'." The
        //   dialog has a column listbox and a substring textbox.
        //
        //   Find (Control+F / Control+Shift+F): substring match
        //   across ALL visible columns. Useful for "show me any row
        //   that mentions 'urgent' somewhere." Dialog has just a
        //   substring textbox.
        //
        //   Find-Regex (Control+F3 / Control+Shift+F3): regex match
        //   across ALL visible columns. Dialog has just a regex
        //   textbox.
        //
        // The legacy ADO-Find dialog used to be column-scoped via
        // ADO Find syntax (e.g. "lastName LIKE '%Smith%'") -- that
        // facility is preserved via Invoke-Sql, where users with
        // SQL fluency can run a parameterized WHERE-clause query.
        // The dot-prompt 'find' alias now routes to the new
        // column-listbox Jump-Record dialog.
        private string sLastJumpColumn = "";
        private string sLastJumpSubstring = "";
        private string sLastFindSubstring = "";
        private string sLastFindRegex = "";
        // Case-sensitive flag per search family. Tracks the most
        // recent setting the user chose in each family's dialog.
        // Defaults to false everywhere (the standard "case-
        // insensitive by default" convention).
        private bool bLastJumpCaseSensitive = false;
        private bool bLastFindCaseSensitive = false;
        private bool bLastRegexCaseSensitive = false;
        // sLastSearchKind tracks which family was last invoked:
        // "" (none yet), "jump", "find", "regex".
        private string sLastSearchKind = "";

        // Search-family state for the GUI's three search dialogs.
        // Each family tracks its own "last term" so Control+F, Control+J,
        // and Control+F3 each remember what was typed into them. The
        // unified F3 / Shift+F3 dispatcher reads sLastSearchKind to
        // decide which family's last term to repeat.

