        // ------- Constructor / lifecycle -------
        public DbDoForm() : this(Program.UiMode.Both) { }

        public DbDoForm(Program.UiMode inputMode)
        {
            mode = inputMode;
            db = new DbDoManager();
            initializeForm();
            buildMenus();
            buildGrid();
            buildStatusBar();
            LiveRegion.attach(this);
            // Load Extra-Speech setting from DbDo.inix [General].
            // Default ON (Y) on first launch. Off explicitly via "N".
            string sExtra = IniSession.read("General", "ExtraSpeech");
            LiveRegion.bExtraSpeechEnabled = string.IsNullOrEmpty(sExtra)
                || !sExtra.Equals("N", StringComparison.OrdinalIgnoreCase);
            applyIniOverrides();
            updateMenuEnabled();
            updateStatusBar();
            if (miHelpExtraSpeech != null) miHelpExtraSpeech.Checked = LiveRegion.bExtraSpeechEnabled;
            if (miHelpCommandEcho != null) miHelpCommandEcho.Checked = isCommandEchoOn();
            if (miToggleReadOnly != null && db != null) miToggleReadOnly.Checked = db.readOnly;
        }

        // OnShown fires after the form is first displayed and has a
        // valid window handle. We use it to make a debug live-region
        // announcement so the user can confirm the live-region
        // pipeline is working with their screen reader. If they
        // hear "Live: DbDo ready" on launch, every other live-
        // region announcement throughout the program will work too.
        //
        // We also register the system-wide Alt+Control+GraveAccent
        // toggle hotkey here, because RegisterHotKey requires the
        // window to have a valid HWND -- which is only guaranteed
        // once the form has been shown.
        protected override void OnShown(EventArgs evArgs)
        {
            base.OnShown(evArgs);
            // First child announces readiness (confirming the live-
            // region pipeline); later windows announce their titles,
            // like standard new-window behavior. The system-wide
            // toggle hotkey registers once, on the first child only --
            // RegisterHotKey would fail (or double-fire) if every
            // child registered the same key.
            bool bFirstChild = (this.MdiParent == null) || (this.MdiParent.MdiChildren.Length <= 1);
            if (bFirstChild) LiveRegion.say("DbDo ready");
            // Later windows are NOT announced here. Opening a window makes
            // it the active window, and JAWS speaks the new window's title
            // on that change; saying it again through the live region would
            // be double speech. (The first child keeps its one-time "DbDo
            // ready" cue, which confirms the live-region pipeline rather
            // than repeating a title.)
            if (bFirstChild) registerToggleHotKey();
        }

        // The mode the form was started in. Read by Program.Main right
        // after Application.Run starts so it knows whether to also
        // spawn a console session (uiMode == Both).
        public Program.UiMode uiMode { get { return mode; } }
        private Program.UiMode mode;

        // OnFormClosing: persist per-table state to the RecentFiles
        // ini block so the next launch's Recent Files dialog can
        // restore the user's view. Captures filter / sort / position
        // / virtual column for every table visited during the session,
        // not just the currently-active one. The manager's per-table
        // cache is brought up-to-date for the current table first
        // (via tableCacheEntries), then handed to RecentFiles for one
        // bulk ini write.
        protected override void OnFormClosing(FormClosingEventArgs evArgs)
        {
            // Offer to save unsaved workbook edits before they are dropped.
            if (!confirmSaveWorkbookIfDirty())
            {
                evArgs.Cancel = true;
                base.OnFormClosing(evArgs);
                return;
            }
            try
            {
                if (db != null && db.isOpen() && !string.IsNullOrEmpty(db.filePath))
                {
                    RecentFiles.recordAllTableStates(db.filePath,
                        db.currentTable, db.tableCacheEntries());
                    saveDbSettings();
                }
            }
            catch { /* never block form close */ }
            // Discard the managed-copy working file, if any. Persisting
            // table state above needs the connection open, so this runs
            // after it. Any unsaved workbook edits were already offered for
            // saving by confirmSaveWorkbookIfDirty above.
            cleanupManagedTemp();
            base.OnFormClosing(evArgs);
        }

        // Window identity for sibling queries (Open Table's
        // already-open filter): which database file and table this
        // child is showing, empty when none.
        public string openDatabasePath
        { get { return (db != null && db.isOpen()) ? (db.filePath ?? "") : ""; } }
        public string openTableName
        { get { return (db != null && db.isOpen()) ? (db.currentTable ?? "") : ""; } }

        // currentDbFolder: the folder that holds the open database
        // file, or null when no database is open. A database's own
        // scripts live here, beside its .db file -- this is the heart
        // of the "scripts belong to a database" layout.
        private string currentDbFolder()
        {
            string sPath = openDatabasePath;
            if (string.IsNullOrEmpty(sPath)) return null;
            try { return System.IO.Path.GetDirectoryName(sPath); }
            catch { return null; }
        }

        // dbScopedInixPath: the per-database settings file, named
        // <DbBaseName>.inix and living in the same folder as the database
        // and its scripts (e.g. Northwind.inix beside Northwind.db). This
        // is the database-specific tier of the two-tier settings model:
        // the per-user DbDo.inix holds global defaults, and this file
        // holds settings that belong to one database and should travel
        // with it -- per-table view choices (select columns, sort,
        // filter) plus any [Validation] or [ConnectStrings] overrides
        // specific to this database. Null when no database is open.
        private string dbScopedInixPath()
        {
            string sFolder = currentDbFolder();
            string sPath = openDatabasePath;
            if (string.IsNullOrEmpty(sFolder) || string.IsNullOrEmpty(sPath)) return null;
            try
            {
                return System.IO.Path.Combine(sFolder,
                    System.IO.Path.GetFileNameWithoutExtension(sPath) + ".inix");
            }
            catch { return null; }
        }

        // sActiveDbInixPath: a static mirror of dbScopedInixPath for the
        // most recently opened database, so the static override readers
        // (readConnectStringOverride, typeDefaultRegex) can consult the
        // per-database settings file without a form reference. Set on a
        // successful open, cleared when the database closes.
        internal static string sActiveDbInixPath = null;

        // readPerDbValue: read one key from the active database's
        // <DbBaseName>.inix, the per-database settings tier. Returns ""
        // when no database is open or the key is absent. Used by the
        // override readers so a per-database setting wins over the global
        // DbDo.inix and the compiled default.
        internal static string readPerDbValue(string sSection, string sKey)
        {
            if (string.IsNullOrEmpty(sActiveDbInixPath)) return "";
            try
            {
                if (!File.Exists(sActiveDbInixPath)) return "";
                return DbDoManager.readIniFromFile(sActiveDbInixPath, sSection, sKey);
            }
            catch { return ""; }
        }

        // readPerDbArray: read one key from the active database's
        // <DbName>.inix as an array (the .inix array convention). Unlike
        // readPerDbValue -- which collapses newlines and is meant for a
        // single scalar -- this preserves the one-item-per-line and inline
        // comma forms and returns the items in order. Empty when no
        // database is open, the file is absent, or the key holds nothing.
        internal static List<string> readPerDbArray(string sSection, string sKey)
        {
            List<string> l = new List<string>();
            if (string.IsNullOrEmpty(sActiveDbInixPath)) return l;
            try
            {
                if (!File.Exists(sActiveDbInixPath)) return l;
                foreach (InixCodec.Section sec in InixCodec.read(sActiveDbInixPath))
                    if (string.Equals(sec.Name, sSection, StringComparison.OrdinalIgnoreCase))
                        return sec.getArray(sKey);
            }
            catch { }
            return l;
        }

        // saveTableView: persist the current table's view -- the select
        // columns, sort order, and where filter -- to [Table:<name>] in
        // this database's <DbName>.inix, under the keys SelectFields,
        // OrderFields, and WhereFilter. Called the moment any of the
        // three changes (the same way sort and filter are remembered),
        // so the view is recalled when the table is next opened. No-op
        // when no database is open or the database has no folder.
        private void saveTableView(string sTable)
        {
            if (string.IsNullOrEmpty(sTable)) return;
            if (db == null || !db.isOpen()) return;
            string sInix = dbScopedInixPath();
            if (string.IsNullOrEmpty(sInix)) return;
            try
            {
                string sSelect = db.getSelectList(sTable) ?? "";
                string sOrder  = "";
                string sWhere  = "";
                // Sort and filter are properties of the live recordset,
                // so they only reflect sTable when it is the current
                // table -- which it is at every call site (the change
                // just happened on the open table).
                try { sOrder = db.sort   ?? ""; } catch { }
                try { sWhere = db.filter ?? ""; } catch { }
                writeIniValue(sInix, "Table:" + sTable, "SelectFields", sSelect);
                writeIniValue(sInix, "Table:" + sTable, "OrderFields",  sOrder);
                writeIniValue(sInix, "Table:" + sTable, "WhereFilter",  sWhere);
            }
            catch { }
        }

        // seedDbSettings: apply this database's editable, database-wide
        // settings from the [Database] section of its <DbName>.inix as the
        // starting defaults for the session -- the last (or user-pinned)
        // Find, Jump, Replace, Replace-Regex, and Query text -- so the
        // matching dialog offers that value first. Only non-blank values
        // are applied, so an unset key never clears a live default.
        // InitialTable is handled separately at open time, when the
        // starting table is chosen. Never throws.
        // seedDbSettings: apply this database's editable, database-wide
        // settings from the [Database] section of its <DbName>.inix. The
        // recent-input lists -- Find, Jump, Replace, Replace-Regex, and
        // Query text -- are stored as arrays of up to ten items (most
        // recent first) and are pushed back into the live history so each
        // command's combo box offers them again. InitialTable is handled
        // separately when the starting table is chosen. Never throws.
        private void seedDbSettings()
        {
            try
            {
                seedRecentInto("FindText",     SearchHistory.SectionFind);
                seedRecentInto("JumpText",     SearchHistory.SectionJump);
                seedRecentInto("ReplaceText",  SearchHistory.SectionReplace);
                seedRecentInto("ReplaceRegex", SearchHistory.SectionRegex);
                foreach (string sQ in reversedForRecent(readPerDbArray("Database", "QueryText")))
                    QueryHistory.record(sQ);
            }
            catch { }
        }

        // seedRecentInto: push a database's saved recent list for one search
        // family into the live SearchHistory. Items are recorded oldest
        // first so the most recent ends up at the front of the list.
        private void seedRecentInto(string sKey, string sSection)
        {
            foreach (string s in reversedForRecent(readPerDbArray("Database", sKey)))
                SearchHistory.record(sSection, s, false);
        }

        // reversedForRecent: a copy of the list in reverse order, blanks
        // dropped -- used to replay a most-recent-first array into a history
        // whose record() prepends, so order is preserved.
        private static List<string> reversedForRecent(List<string> l)
        {
            List<string> r = new List<string>();
            if (l == null) return r;
            for (int i = l.Count - 1; i >= 0; i--)
                if (!string.IsNullOrEmpty(l[i])) r.Add(l[i]);
            return r;
        }

        // searchTerms: the recent text entries for one SearchHistory family,
        // most recent first, as a plain string list for the array writer.
        private static List<string> searchTerms(string sSection)
        {
            List<string> l = new List<string>();
            try
            {
                foreach (SearchHistory.Entry e in SearchHistory.load(sSection))
                    if (e != null && !string.IsNullOrEmpty(e.sTerm)) l.Add(e.sTerm);
            }
            catch { }
            return l;
        }

        // saveDbSettings: persist this database's editable, database-wide
        // settings to the [Database] section of its <DbName>.inix. The
        // recent-input lists (Find, Jump, Replace, Replace-Regex, Query)
        // are written as arrays of up to ten items, most recent first,
        // using the .inix array convention -- inline when short, one per
        // line otherwise. A list is written only when it has items, so an
        // unused command never erases a value the user pinned by hand.
        // InitialTable is SEEDED only when absent, so a starting table the
        // user chose is never overwritten. Never throws.
        private void saveDbSettings()
        {
            try
            {
                if (db == null || !db.isOpen()) return;
                string sInix = dbScopedInixPath();
                if (string.IsNullOrEmpty(sInix)) return;

                if (string.IsNullOrEmpty(readPerDbValue("Database", "InitialTable"))
                    && !string.IsNullOrEmpty(db.currentTable))
                    writeIniValue(sInix, "Database", "InitialTable", db.currentTable);

                writeRecentArrayIfAny(sInix, "FindText",     searchTerms(SearchHistory.SectionFind));
                writeRecentArrayIfAny(sInix, "JumpText",     searchTerms(SearchHistory.SectionJump));
                writeRecentArrayIfAny(sInix, "ReplaceText",  searchTerms(SearchHistory.SectionReplace));
                writeRecentArrayIfAny(sInix, "ReplaceRegex", searchTerms(SearchHistory.SectionRegex));
                writeRecentArrayIfAny(sInix, "QueryText",    QueryHistory.load());
            }
            catch { }
        }

        // writeRecentArrayIfAny: write an array-valued setting only when it
        // has at least one item, so a blank runtime list never clears a
        // value the user pinned by hand.
        private void writeRecentArrayIfAny(string sInix, string sKey, List<string> items)
        {
            if (items == null || items.Count == 0) return;
            try { InixCodec.writeArrayValue(sInix, "Database", sKey, items); } catch { }
        }

        // gatherScripts: the scripts available right now, as a map
        // from display name to full path. The open database's own
        // scripts (in its folder) are merged with the generic scripts
        // in %APPDATA%\DbDo\Scripts; on a same-named collision the
        // database-specific script wins. Invoke Script and Edit Script
        // both draw their pick list from this, so a database's scripts
        // appear automatically whenever that database is open and stay
        // out of the way when it is not.
        private System.Collections.Generic.SortedDictionary<string, string> gatherScripts()
        {
            System.Collections.Generic.SortedDictionary<string, string> dMap =
                new System.Collections.Generic.SortedDictionary<string, string>(StringComparer.OrdinalIgnoreCase);
            string sDbFolder = currentDbFolder();
            // A database sitting directly in DbDo's own program directory
            // must not pull DbDo's files (e.g. the DbDo.js build source)
            // into the script list; that directory is never a per-database
            // script location. Databases anywhere else are scanned normally.
            if (!string.IsNullOrEmpty(sDbFolder) && !ScriptHelper.isDbDoInstallFolder(sDbFolder))
                foreach (string sName in ScriptHelper.listScriptsInFolder(sDbFolder))
                    dMap[sName] = System.IO.Path.Combine(sDbFolder, sName);
            string sGeneric = ScriptHelper.getScriptDir();
            foreach (string sName in ScriptHelper.listScriptsInFolder(sGeneric))
                if (!dMap.ContainsKey(sName)) dMap[sName] = System.IO.Path.Combine(sGeneric, sName);
            return dMap;
        }

        // Lifecycle invariant (MDI): each child window owns exactly
        // one DbDoManager, so an open window means an open
        // connection/recordset and a closed window means both are
        // released. Form.Close on a non-modal form disposes it, so
        // every close path -- Close Window, Close All But Current,
        // the title-bar X, frame shutdown -- funnels here and frees
        // the recordset's memory promptly.
        protected override void Dispose(bool bDisposing)
        {
            if (bDisposing) unregisterToggleHotKey();
            if (bDisposing && db != null) { try { db.Dispose(); } catch { } db = null; }
            base.Dispose(bDisposing);
        }

        // ---------------- Single-instance wake-up handling ----------------
        //
        // When a second DbDo.exe is launched with -activate (the desktop
        // hotkey path), it broadcasts the registered "DbDo.WakeUp" message
        // and exits. Every top-level window in the user session receives
        // the message; the first instance's WndProc here recognizes its
        // own ID and brings the window forward.
        //
        // ShowWindow with SW_RESTORE handles the case where the form has
        // been minimized (the user iconified it before pressing the
        // hotkey). SetForegroundWindow then steals focus to the form.
        // Both calls are best-effort: SetForegroundWindow is allowed by
        // Windows only under specific conditions (e.g., when the calling
        // process has foreground rights), but as long as DbDo's own
        // process is invoking it on its own window, it succeeds.
        // ---------------- ----------------

        [DllImport("user32.dll")]
        private static extern bool SetForegroundWindow(IntPtr hWnd);
        [DllImport("user32.dll")]
        private static extern bool ShowWindow(IntPtr hWnd, int iCmdShow);
        [DllImport("user32.dll")]
        private static extern bool IsIconic(IntPtr hWnd);
        [DllImport("user32.dll", SetLastError = true)]
        private static extern bool RegisterHotKey(IntPtr hWnd, int iId, int iModifiers, int iVk);
        [DllImport("user32.dll", SetLastError = true)]
        private static extern bool UnregisterHotKey(IntPtr hWnd, int iId);
        [DllImport("user32.dll")]
        private static extern IntPtr GetForegroundWindow();
        [DllImport("kernel32.dll")]
        private static extern IntPtr GetConsoleWindow();
        private const int SW_RESTORE = 9;

        // Global hotkey: Alt+Control+GraveAccent = "toggle DbDo." From
        // anywhere on Windows it activates either the GUI or the
        // console, whichever is NOT currently foreground -- the global
        // "summon DbDo" chord. Since DbDo is a single-instance app,
        // this one chord covers both directions; the former
        // Alt+GraveAccent console-to-GUI hotkey was dropped as
        // redundant (and to stop reserving a system-wide chord that
        // other applications may want). The pair is now:
        //   Control+GraveAccent       GUI menu hotkey, GUI -> console
        //   Alt+Control+GraveAccent   Global, toggle between them
        //
        // MOD_ALT = 1, MOD_CONTROL = 2 (combinable). VK_OEM_3 (grave/tilde)
        // = 0xC0 in Windows virtual-key terms (Keys.Oemtilde in .NET).
        private const int ModAlt = 0x1;
        private const int ModControl = 0x2;
        private const int VkOemGrave = 0xC0;  // grave accent / tilde, US layout
        // Hotkey ID in the application-reserved 0x0000-0xBFFF range,
        // well above the typical range used by other applications to
        // minimize the chance of a numerical collision.
        private const int HotKeyIdToggleWindow = 0x4422;
        private bool bToggleHotKeyRegistered = false;

        private void registerToggleHotKey()
        {
            try
            {
                IntPtr hWnd = this.Handle;
                if (hWnd == IntPtr.Zero) return;
                bool bOk = RegisterHotKey(hWnd, HotKeyIdToggleWindow,
                                          ModAlt | ModControl, VkOemGrave);
                if (bOk)
                {
                    bToggleHotKeyRegistered = true;
                    DbDoLog.write("Alt+Control+GraveAccent registered as toggle hotkey.");
                }
                else
                {
                    DbDoLog.write("Alt+Control+GraveAccent hotkey could not be registered.");
                }
            }
            catch (Exception ex)
            {
                DbDoLog.write("Hotkey registration error: " + ex.Message);
            }
        }

        private void unregisterToggleHotKey()
        {
            if (bToggleHotKeyRegistered)
            {
                try { UnregisterHotKey(this.Handle, HotKeyIdToggleWindow); } catch { }
                bToggleHotKeyRegistered = false;
            }
        }

        // WM_HOTKEY = 0x0312.
        private const int WmHotKey = 0x0312;

        protected override void WndProc(ref Message msg)
        {
            // Message IDs from RegisterWindowMessage are in the
            // 0xC000-0xFFFF range, which fits in int with no sign issues,
            // but compare as uint to keep the types matched.
            if ((uint)msg.Msg == SingleInstance.WakeUpMessage)
            {
                bringForward();
                return;
            }
            if (msg.Msg == WmHotKey)
            {
                int iId = (int)msg.WParam;
                if (iId == HotKeyIdToggleWindow)
                {
                    // The toggle: foreground is the GUI form (or any
                    // third-party window) -> bring console forward;
                    // foreground IS the console -> bring GUI forward.
                    // Always acts; the whole point is global summoning.
                    IntPtr hFg = GetForegroundWindow();
                    IntPtr hCon = GetConsoleWindow();
                    bool bConsoleIsFg = (hCon != IntPtr.Zero && hFg == hCon);
                    if (bConsoleIsFg)
                    {
                        bringForward();
                    }
                    else
                    {
                        // Bring console forward if it exists; otherwise
                        // there's no console open, so just bring GUI.
                        if (hCon != IntPtr.Zero)
                        {
                            try
                            {
                                ShowWindow(hCon, SW_RESTORE);
                                SetForegroundWindow(hCon);
                            }
                            catch { }
                        }
                        else
                        {
                            bringForward();
                        }
                    }
                    return;
                }
            }
            base.WndProc(ref msg);
        }

        // Restore the window if minimized, then yank it to the foreground.
        // Safe to call from the message-loop thread (WndProc); for cross-
        // thread callers, marshal through Invoke first.
        private void bringForward()
        {
            try
            {
                IntPtr hWnd = this.Handle;
                if (hWnd == IntPtr.Zero) return;
                if (IsIconic(hWnd) || this.WindowState == FormWindowState.Minimized)
                {
                    ShowWindow(hWnd, SW_RESTORE);
                    this.WindowState = FormWindowState.Normal;
                }
                this.Activate();
                SetForegroundWindow(hWnd);
                DbDoLog.write("Brought forward by external wake-up message.");
            }
            catch { }
        }
        // ---------------- ---------------- ----------------

        private void initializeForm()
        {
            this.Text = "(no database)";
            this.AccessibleName = "(no database)";
            // No AccessibleDescription. Screen readers read the title
            // and the focused control on form open; an extra description
            // becomes a "banner" that wastes time before the user can
            // start working.
            this.ClientSize = new Size(InitialFormWidth, InitialFormHeight);
            this.StartPosition = FormStartPosition.CenterScreen;
            this.KeyPreview = true;
            this.KeyDown += new KeyEventHandler(formKeyDown);
        }

        // KeyPreview=true routes every keystroke through this handler
        // BEFORE the focused control sees it. We use it as a backstop
        // for the Control+arrow / Control+Home/End mark-navigation
        // chords and the Shift+Home / Shift+End / Alt+Shift+Home /
        // Alt+Shift+End bulk-mark chords, because either family can
        // be intercepted by the MenuStrip on its way through normal
        // dispatch. Routing them here first guarantees they get to
        // the form-level handlers.
        //
        // For each key handled here, set both Handled=true (stops
        // KeyDown propagation) and SuppressKeyPress=true (prevents
        // the keystroke from reaching the focused control's
        // KeyPress and OnKeyDown overrides).
        //
        // Control+Tab and Control+Shift+Tab are NOT handled here.
        // They are wired as menu shortcuts on Window > Next Window
        // (Control+Tab) and Window > Previous Window
        // (Control+Shift+Tab); the standard ProcessCmdKey -> KeyMap
        // dispatch handles them, and the menu items also give them
        // discoverability and disabled-state announcements through
        // the same mechanism every other hotkey uses. (The visited-
        // table ring that previously owned this pair now lives on
        // Alt+F6 / Alt+Shift+F6.)
        private void formKeyDown(object sender, KeyEventArgs evArgs)
        {
            Keys key = evArgs.KeyData;
            // Db cursor extremes (v1.0.108 redesign): Control+Home
            // moves the db cursor to the first column of the first
            // row; Control+End to the last column of the last row --
            // the universal grid-corner convention (Excel, Access,
            // DataGridView, WPF). The marked-row first/last jumps
            // that previously owned this pair (the tagged-nav
            // convention) moved to Control+Shift+Home/End below;
            // Control+Up/Down remain previous/next marked. The ListView's native handling of these chords
            // is a no-op in our MultiSelect=false config, so nothing
            // visible is stolen.
            if (key == (Keys.Control | Keys.Home))
            { evArgs.Handled = true; evArgs.SuppressKeyPress = true; virtMoveTo(1, 0); return; }
            if (key == (Keys.Control | Keys.End))
            {
                evArgs.Handled = true; evArgs.SuppressKeyPress = true;
                virtMoveTo((db != null && db.hasRecordset()) ? db.recordCount : 1,
                    (grid != null) ? grid.Columns.Count - 1 : 0);
                return;
            }
            if (key == (Keys.Control | Keys.Shift | Keys.Home))
            { evArgs.Handled = true; evArgs.SuppressKeyPress = true; jumpToMarkedRow(MarkJump.First);    return; }
            if (key == (Keys.Control | Keys.Shift | Keys.End))
            { evArgs.Handled = true; evArgs.SuppressKeyPress = true; jumpToMarkedRow(MarkJump.Last);     return; }
            if (key == (Keys.Control | Keys.Up))
            { evArgs.Handled = true; evArgs.SuppressKeyPress = true; jumpToMarkedRow(MarkJump.Previous); return; }
            if (key == (Keys.Control | Keys.Down))
            { evArgs.Handled = true; evArgs.SuppressKeyPress = true; jumpToMarkedRow(MarkJump.Next);     return; }
            // Bare Home/End: db cursor column extremes within the
            // current row (first / last column), per the WPF DataGrid
            // and Access row-extremes convention. Gated on grid focus
            // so text controls elsewhere keep their native Home/End.
            // PageUp/PageDown are deliberately NOT handled anywhere:
            // the ListView's native paging moves the focused row a
            // screenful while the virtual cursor column, stored on
            // the grid itself, is untouched -- the column-preservation
            // principle for free.
            if (key == Keys.Home && grid != null && grid.Focused)
            { evArgs.Handled = true; evArgs.SuppressKeyPress = true; virtMoveTo(iVirtualRow, 0); return; }
            if (key == Keys.End && grid != null && grid.Focused)
            { evArgs.Handled = true; evArgs.SuppressKeyPress = true; virtMoveTo(iVirtualRow, (grid.Columns.Count > 0) ? grid.Columns.Count - 1 : 0); return; }

            // Shift+Home / Shift+End / Alt+Shift+Home / Alt+Shift+End
            // for bulk marking. Shift+Home marks every row from the
            // first up to and including the current; Shift+End marks
            // every row from the current to the last. Alt+Shift+Home
            // and Alt+Shift+End unmark the same spans. The
            // ListView's MultiSelect=false config makes Shift+Home/End
            // a no-op natively, so we are not stealing anything.
            if (key == (Keys.Shift | Keys.Home))
            { evArgs.Handled = true; evArgs.SuppressKeyPress = true; bulkMark(BulkMark.MarkToStart);   return; }
            if (key == (Keys.Shift | Keys.End))
            { evArgs.Handled = true; evArgs.SuppressKeyPress = true; bulkMark(BulkMark.MarkToEnd);     return; }
            if (key == (Keys.Alt | Keys.Shift | Keys.Home))
            { evArgs.Handled = true; evArgs.SuppressKeyPress = true; bulkMark(BulkMark.UnmarkToStart); return; }
            if (key == (Keys.Alt | Keys.Shift | Keys.End))
            { evArgs.Handled = true; evArgs.SuppressKeyPress = true; bulkMark(BulkMark.UnmarkToEnd);   return; }

            // Mark-and-move chords for the data list. The user can
            // mark or unmark the current record and step to the next
            // (or previous) record in a single keystroke. The
            // The > and < bindings were retired in v1.0.74
            // to eliminate conflict with the data list's type-to-
            // search: typing > or < to mark would also enter those
            // characters into the search buffer. The Shift+arrow
            // family is the surviving binding because Shift+arrow has
            // no native meaning on a single-select ListView (so the
            // chord is unambiguous).
            //
            //   Shift+DownArrow         = Mark and next
            //   Shift+UpArrow           = Mark and previous
            //   Alt+Shift+DownArrow     = Unmark and next
            //   Alt+Shift+UpArrow       = Unmark and previous
            bool bGridFocused = (this.ActiveControl == grid);
            if (bGridFocused)
            {
                if (key == (Keys.Shift | Keys.Down))
                { evArgs.Handled = true; evArgs.SuppressKeyPress = true; markAndMove(true,  true);  return; }
                if (key == (Keys.Shift | Keys.Up))
                { evArgs.Handled = true; evArgs.SuppressKeyPress = true; markAndMove(true,  false); return; }
                if (key == (Keys.Alt | Keys.Shift | Keys.Down))
                { evArgs.Handled = true; evArgs.SuppressKeyPress = true; markAndMove(false, true);  return; }
                if (key == (Keys.Alt | Keys.Shift | Keys.Up))
                { evArgs.Handled = true; evArgs.SuppressKeyPress = true; markAndMove(false, false); return; }

                // ? (Shift+Slash) = Show-Where. Speaks the title
                // bar, the status bar, and the current row's
                // displayed columns. The "where am I?" question is
                // a frequent need for screen-reader users; making
                // it a single character keeps the answer fast.
                if (key == (Keys.Shift | Keys.OemQuestion))
                { evArgs.Handled = true; evArgs.SuppressKeyPress = true; sayWhere(); return; }
            }

            // Control+A / Control+Shift+A / Control+I work whether
            // or not the data list has focus, because they don't
            // collide with anything in our edit dialogs (Control+A
            // is "select all" in a text box, but those text boxes
            // are inside modal dialogs that own their own key flow;
            // we only intercept here when the dialog is not up).
            // We still gate by data-list focus to be safe.
            if (bGridFocused)
            {
                if (key == (Keys.Control | Keys.A))
                { evArgs.Handled = true; evArgs.SuppressKeyPress = true; markAll(true);   return; }
                if (key == (Keys.Control | Keys.Shift | Keys.A))
                { evArgs.Handled = true; evArgs.SuppressKeyPress = true; markAll(false);  return; }
                if (key == (Keys.Alt | Keys.Shift | Keys.I))
                { evArgs.Handled = true; evArgs.SuppressKeyPress = true; invertMarks();   return; }
            }
        }

        // ------- Public surface for the CLI thread -------
        public DbDoManager Db { get { return db; } }

        public void invokeRefresh()
        {
            if (this.IsDisposed) return;
            if (this.InvokeRequired)
            {
                try { this.Invoke(new Action(updateGrid)); } catch { }
            }
            else
            {
                updateGrid();
            }
        }

        public void invokeMessage(string sMsg)
        {
            if (this.IsDisposed) return;
            try { this.Invoke(new Action<string>(s => lblStatus.Text = s), new object[] { sMsg }); } catch { }
        }

        // invokeEditConfiguration: public wrapper around the private
        // Edit-Settings click handler so the dot-prompt's
        // edit-configuration verb can pop the GUI dialog when a
        // form is available.
        public void invokeEditConfiguration()
        {
            if (this.IsDisposed) return;
            try { toolsEditConfigClicked(null, EventArgs.Empty); }
            catch (Exception ex) { Console.WriteLine("(error: " + ex.Message + ")"); }
        }

        // buildColumnReportPublic: public wrapper around the private
        // static buildColumnReport so the dot-prompt's measure-column
        // verb can use the same report builder the GUI does.
        public static string buildColumnReportPublic(string sColumn, List<string> lRaw)
        {
            return buildColumnReport(sColumn, lRaw);
        }

        // Public entry points for the dot prompt to trigger drill-down
        // commands on the GUI thread. Both marshal to the form's
        // message loop because the click handlers manipulate UI state
        // (and the drill stack lives on the form). The console wraps
        // these in cmdEnterChild / cmdExitChild.
        //
        // Returns the count of stack entries AFTER the operation, so
        // the console can report depth to the user. Returns -1 if the
        // form is disposed.
        public int invokeEnterChild()
        {
            if (this.IsDisposed) return -1;
            try
            {
                this.Invoke(new Action(() => recEnterChildClicked(this, EventArgs.Empty)));
            }
            catch { }
            return drillDepth();
        }

        public int invokeExitChild()
        {
            if (this.IsDisposed) return -1;
            try
            {
                this.Invoke(new Action(() => recExitChildClicked(this, EventArgs.Empty)));
            }
            catch { }
            return drillDepth();
        }

        // invokeExitChildToRoot: return to the root window and report
        // how many drill levels were unwound. Marshalled to the GUI
        // thread so the CLI's cmdExitChildToRoot can call it.
        public int invokeExitChildToRoot()
        {
            if (this.IsDisposed) return -1;
            int iBefore = drillDepth();
            try
            {
                this.Invoke(new Action(() => recExitChildToRootClicked(this, EventArgs.Empty)));
            }
            catch { }
            return iBefore;
        }

        // True if this window was opened by Enter-Child (i.e., it has a
        // live caller window to return to). Used by the dot prompt's
        // cmdExitChild to give a no-op message without marshaling to the
        // GUI thread first.
        public bool hasDrillStack()
        {
            return frmDrillCaller != null && !frmDrillCaller.IsDisposed;
        }

        // Drop this window's drill linkage. Used when the database
        // changes (open or close) from outside the form's normal click
        // handlers -- the dot prompt's cmdOpenDatabase / cmdCloseDatabase
        // paths in particular -- so a stale caller pointer can't survive
        // into an unrelated database.
        public void clearDrillStack()
        {
            frmDrillCaller = null;
            iDrillCallerRow = 0;
            sDrillTable = "";
            sDrillWhere = "";
        }

        // =====================================================================
        // Menu construction. Every menu item is registered with
        // KeyMap and gets a default hotkey (or Keys.None for items
        // without one). All hotkeys are user-overridable via DbDo.inix.
        // =====================================================================
        private void buildMenus()
        {
            menuMain = new MenuStrip();
            menuMain.AccessibleName = "Main menu";

            // Top-level menu layout: File / Edit /
            // Navigate / Query / Misc / Help. Each leaf item keeps
            // its existing variable name (miRec*, miView*, miSchema*,
            // miTools*) so all the enable/disable code elsewhere in
            // the class continues to work unchanged.

            // ===== File menu: database files + cross-file movement =====
            miFile = addMenu("&File");
            miFileNew     = addItem(miFile, "&New Database...",           "New Database",     Keys.None,                            fileNewClicked);
            miFileAddTable = addItem(miFile, "Add &Table...",              "Add Table",        Keys.None,                            fileAddTableClicked);
            miFileOpen    = addItem(miFile, "&Open Database...",          "Open Database",    Keys.Control | Keys.O,                fileOpenClicked);
            // Open New Recordset: prompt for a SQL SELECT and present
            // its result as the current recordset. The recordset is
            // read-only (no table identity, so Mark/Edit/Delete won't
            // work) but Find / Filter / Sort / Say-X all do. Useful
            // for "give me a join of these tables I want to browse"
            // workflows that don't justify creating a permanent view.
            miFileOpenSelect = addItem(miFile, "Open New &Recordset...", "Open Recordset", Keys.Control | Keys.Shift | Keys.T, fileOpenSelectClicked);
            miFileRecent  = addItem(miFile, "&Recent Files...",           "Recent Files",     Keys.Alt | Keys.R,                    fileRecentClicked);
            // Export Database: primary chord Alt+Shift+E (parallel to
            // Alt+E = Export Data productivity pair). Ctrl+Shift+S was
            // the earlier primary, but the user moved it to Statistics
            // Column for that command's S-letter family.
            miFileSave    = addItem(miFile, "&Save",                     "Save",             Keys.Control | Keys.S,                fileSaveClicked);
            miFileSaveAs  = addItem(miFile, "Save &As...",              "Save As",          Keys.Control | Keys.Shift | Keys.S,   fileSaveAsClicked);
            miFileClose   = addItem(miFile, "&Close Database",            "Close Database",   Keys.None,                            fileCloseClicked);
            addSep(miFile);
            miFileBackup  = addItem(miFile, "&Backup Database...",        "Backup Database",  Keys.None,                            fileBackupClicked);
            miFileCompare = addItem(miFile, "Co&mpare Database...",       "Compare Database", Keys.None,                            fileCompareClicked);
            addSep(miFile);
            // Alt+I = Import (build a new DbDo shell from another file),
            // Alt+M = Merge (rows into the current table), Alt+E = Export
            // Data. The Alt+letter slots are clean one-handed productivity
            // chords. (Ctrl+I and Ctrl+E are already used for Invert Marked
            // and Edit Record, which are high-frequency core operations that
            // should keep their plain-Ctrl chords.)
            miFileImport  = addItem(miFile, "&Import...",                 "Import",           Keys.Alt | Keys.I,                    importClicked);
            miFileMerge   = addItem(miFile, "&Merge Data...",             "Merge",            Keys.Alt | Keys.M,                    mergeClicked);
            addItem(miFile, "&Transfer Import...",       "Transfer Import",  Keys.None,                            importTransferClicked);
            addItem(miFile, "&Run Report...",           "Run Report",       Keys.Alt | Keys.Shift | Keys.R,       produceReportClicked);
            miFileExport  = addItem(miFile, "E&xport Data...",            "Export Data",      Keys.Alt | Keys.X,                    fileExportClicked);
            addSep(miFile);
            miFilePrint   = addItem(miFile, "&Print...",                  "Out Printer",      Keys.Control | Keys.P,                filePrintClicked);
            addSep(miFile);
            // Switch-Table family lives in File because choosing
            // which file/table is on screen is a file-level operation,
            // and the File menu carries Current Windows (F4)
            // by the same logic.
            miSchemaSelectTable = addItem(miFile, "Choose &Table...",           "Select Table",         Keys.F7,                            schemaSelectTableClicked);
            miSchemaSelectView  = addItem(miFile, "Choose &View...",            "Select View",          Keys.None,                          schemaSelectViewClicked);
            miSchemaSwitch      = addItem(miFile, "Next Visited Table",         "Switch Table",         Keys.Alt | Keys.F6,                 schemaSwitchClicked);
            miSchemaSwitchPrev  = addItem(miFile, "Previous Visited Table",     "Switch Previous Table", Keys.Alt | Keys.Shift | Keys.F6,   schemaSwitchPrevClicked);
            miSchemaSwitchAll     = addItem(miFile, "Next Table or View",     "Switch Object",         Keys.Control | Keys.F6,            schemaSwitchAllClicked);
            miSchemaSwitchAllPrev = addItem(miFile, "Previous Table or View", "Switch Previous Object", Keys.Control | Keys.Shift | Keys.F6, schemaSwitchAllPrevClicked);
            addSep(miFile);
            miFileExit    = addItem(miFile, "E&xit DbDo",                "Exit Application", Keys.Alt | Keys.F4,                   fileExitClicked);

            // ===== Edit menu: modify the data =====
            miEdit = addMenu("&Edit");
            miRecNew         = addItem(miEdit, "&New Record...",                          "New Record",          Keys.Control | Keys.N,              recNewClicked);
            miRecSet         = addItem(miEdit, "&Edit View...",                           "Edit View",            Keys.Control | Keys.E,              recSetClicked);
            // Edit Cell: single-field editor for the virtual cell
            // under the Alt+Control+arrow cursor. Same regex
            // validation as Edit Record (via [Validation:<table>]
            // sections of DbDo.inix) but only one field is shown.
            // Mnemonic "F" for field; Shift+F2 since F2 is Edit
            // Record.
            miRecSetCell     = addItem(miEdit, "Edit &Cell...",    "Edit Cell",            Keys.F2,                            recSetCellClicked);
            miRecRemove      = addItem(miEdit, "&Delete Record",      "Delete Record",       Keys.Control | Keys.D,              recRemoveClicked);
            miRecRemoveForce = addItem(miEdit, "Delete Without Confir&mation",            "Delete Record Force",  Keys.Control | Keys.Shift | Keys.D, recRemoveForceClicked);
            miRecCopy        = addItem(miEdit, "Copy &Record", "Copy Record",         Keys.Control | Keys.Shift | Keys.C, recCopyClicked);
            // Append Record: like Copy Record but adds to the
            // existing clipboard contents rather than replacing.
            // Useful for collecting several rows from across the
            // database into one clipboard payload. Each appended
            // record is separated by a blank line.
            miRecAppend      = addItem(miEdit, "Append Recor&d to Clipboard",             "Append Record",       Keys.Alt | Keys.Shift | Keys.C,     recAppendClicked);
            // New Copy: duplicate the current row. Pre-fills the New
            // Record dialog with all visible field values from the
            // current row; the user reviews, edits as needed, and
            // OK inserts as a new row. Primary key and 'prm' are
            // cleared automatically since both must be unique.
            miRecNewCopy     = addItem(miEdit, "Ne&w Copy...", "Copy Record as New",    Keys.Control | Keys.Shift | Keys.N, recNewCopyClicked);
            // Mail Record: build a mailto: URI from the current row.
            // Uses the first email-like column found (looking for
            // 'email', 'e_mail', 'mail') for the address; uses the
            // 'look' column for the subject; uses the 'notes' column
            // for the body. Falls back gracefully if any are missing.
            miRecMail        = addItem(miEdit, "&Mail Record", "Send Mail",  Keys.None, recMailClicked);
            miRecUpdateColumn = addItem(miEdit, "&Replace Column...", "Replace Column", Keys.Control | Keys.R, recUpdateColumnClicked);
            // Regex Replace: same as Update Column but interprets the
            // search text as a .NET regex pattern and supports $1, $2
            // back-references in the replacement. Ctrl+Shift+R as the
            // "power version" companion to Ctrl+R = Update Column.
            miRecRegexReplace = addItem(miEdit, "Re&gex Replace...", "Regex Replace", Keys.Control | Keys.Shift | Keys.R, recRegexReplaceClicked);
            addSep(miEdit);
            // Marks: per-row boolean flags. Control+M / Control+U is
            // the canonical chord pair, chosen for symmetry (mark and
            // unmark differ only by the letter, not by an added
            // modifier).
            miRecMark        = addItem(miEdit, "&Mark Record",                            "Set Mark",            Keys.Control | Keys.M,              recMarkClicked);
            miRecToggleMark  = addItem(miEdit, "&Toggle Marked",          "Toggle Marked",       Keys.Control | Keys.Space,          recToggleMarkClicked);
            miEditNotes      = addItem(miEdit, "Edit &Notes...",          "Edit Notes",          Keys.Alt | Keys.Shift | Keys.N,     editNotesClicked);
            miEditTags       = addItem(miEdit, "Edit Ta&gs...",           "Edit Tags",           Keys.Alt | Keys.Shift | Keys.T,     editTagsClicked);
            miEditUrl        = addItem(miEdit, "Edit &URL...",            "Edit URL",            Keys.Alt | Keys.Shift | Keys.U,     editUrlClicked);
            miRecUnmark      = addItem(miEdit, "&Unmark Record",                          "Clear Mark",          Keys.Control | Keys.Shift | Keys.M, recUnmarkClicked);
            // Bulk mark operations (v1.0.67). All operate on the
            // current filtered view -- they set, clear, or invert the
            // 'marked' column for every row currently visible. The
            // chord pairs follow the standard primary/secondary
            // convention: Ctrl+letter is the primary action, Ctrl+
            // Shift+letter is the variant. Invert Marked is on Alt+Shift+I,
            // off on its own because it doesn't have a paired counterpart.
            ToolStripMenuItem miBulkMark = new ToolStripMenuItem("&Bulk Marking...");
            miBulkMark.AccessibleName = "Bulk Marking";
            miEdit.DropDownItems.Add(miBulkMark);
            miRecMarkAll     = addItem(miBulkMark, "Mark &All",   "Set Mark All",         Keys.Control | Keys.A,              recMarkAllClicked);
            miRecUnmarkAll   = addItem(miBulkMark, "U&nmark All", "Clear Mark All",       Keys.Control | Keys.Shift | Keys.A, recUnmarkAllClicked);
            miRecInvertMarked= addItem(miBulkMark, "&Invert Marked",     "Invert Marked",         Keys.Alt | Keys.Shift | Keys.I, recInvertMarkedClicked);
            // F8 / Shift+F8 / Alt+F8 / Alt+Shift+F8 -- range mark
            // and range unmark families. Two INDEPENDENT anchors:
            // one for marking (F8 to set, Shift+F8 to complete) and
            // one for unmarking (Alt+F8 to set, Alt+Shift+F8 to
            // complete). Each "Complete" command is direction-
            // agnostic: the range from anchor to current row is the
            // same whether the anchor was set above or below.
            //
            // Two distinct anchors let the user
            // build a mark range and an unmark range without one
            // gesture clobbering the other.
            miRecMarkAnchor      = addItem(miBulkMark, "&Start Mark",                  "Start Mark",      Keys.F8,                            recMarkAnchorClicked);
            miRecMarkToAnchor    = addItem(miBulkMark, "Complete &Mark",             "Complete Mark",          Keys.Shift | Keys.F8,               recMarkToAnchorClicked);
            miRecUnmarkAnchor    = addItem(miBulkMark, "Start &Unmark",                 "Start Unmark",    Keys.Alt | Keys.F8,                 recUnmarkAnchorClicked);
            miRecUnmarkToAnchor  = addItem(miBulkMark, "Complete Unmark to Anchor",           "Unmark Range",        Keys.Alt | Keys.Shift | Keys.F8,    recUnmarkToAnchorClicked);
            addSep(miEdit);
            // Bookmarks: the Set/Clear/Go-to Bookmark trio
            // on Control+K / Control+Shift+K / Alt+K. Identical
            // chord family in DbDo.
            // Bookmark commands: B-family chords. v1.0.98 moved these
            // from K to B (B is the rule-compliant first-letter of
            // Bookmark; K was a "booKmark" conventional exception
            // from earlier app conventions). Migrating to B frees
            // the K-family for future use and follows the strict
            // mnemonic rule throughout.
            miRecBookmark    = addItem(miEdit, "&Save Bookmark",                          "Save Bookmark",       Keys.Control | Keys.B,              recBookmarkClicked);
            miRecGotoBookmark= addItem(miEdit, "&List Bookmarks...",                       "List Bookmarks",      Keys.Alt | Keys.B,                  recGotoBookmarkClicked);
            miRecClearBookmark=addItem(miEdit, "&Clear Bookmark",                         "Clear Bookmark",      Keys.Control | Keys.Shift | Keys.B, recClearBookmarkClicked);
            addSep(miEdit);
            // Open Cell Value: open the url, file path, or folder
            // path stored in a cell of the current row.
            miRecOpenCell    = addItem(miEdit, "&Open Cell Value...",       "Open Cell",           Keys.Control | Keys.Enter,          recOpenCellClicked);
            // Open Url: open the row's 'url' column with the system
            // default handler (browser, mail client, file opener).
            // Convenience chord for the most common Open-Cell case --
            // saves the user from having to navigate to the url cell
            // first.
            miRecOpenUrl     = addItem(miEdit, "Open &Url",   "Open URL",            Keys.Control | Keys.Shift | Keys.U, recOpenUrlClicked);
            // Pick Value: v1.0.67 deferred stub. The chord (Ctrl+F2)
            // is reserved so the menu doesn't drift and the user can
            // discover the planned command.
            miRecPickValue   = addItem(miEdit, "Pick &Value", "Pick Value", Keys.Control | Keys.F2,            recPickValueStub);

            // ===== Navigate menu: move around the data =====
            miNavigate = addMenu("&Navigate");
            // Step-Record family: First / Last / Next / Previous.
            // Names follow the standard convention; chords are
            // unset (the listview's arrow keys handle next/previous
            // and Control+Home/End handle first/last natively).
            miNavFirst       = addItem(miNavigate, "&First Record",                          "Step Record First",    Keys.None,                          navFirstClicked);
            miNavLast        = addItem(miNavigate, "&Last Record",                           "Step Record Last",     Keys.None,                          navLastClicked);
            miNavNext        = addItem(miNavigate, "&Next Record",                        "Step Record Next",     Keys.None,                          navNextClicked);
            miNavPrev        = addItem(miNavigate, "&Previous Record",                    "Step Record Previous", Keys.None,                          navPrevClicked);
            miRecGoTo        = addItem(miNavigate, "&Go to Record...",                    "Set Position",         Keys.Control | Keys.G,              recGoToClicked);
            miRecGoToRepeat  = addItem(miNavigate, "Repeat Go &To",                       "Repeat Set Position",  Keys.Alt | Keys.G,                  repeatGoToClicked);
            addSep(miNavigate);
            // Search families. Three distinct families with their
            // own chord pairs, plus a unified F3 / Shift+F3 "repeat
            // last search" dispatcher that routes to whichever
            // family was last used.
            //
            //   Jump to Match (Control+J / Control+Shift+J): substring
            //   match scoped to ONE column the user picks from a
            //   listbox in the prompt dialog. dbDot heritage.
            //
            //   Find (Control+F / Control+Shift+F): substring match
            //   ACROSS ALL visible columns. The universal Office /
            //   browser Control+F idiom.
            //
            //   Find Regex (Control+F3 / Control+Shift+F3): .NET
            //   regex match across ALL visible columns.
            //
            // F3 / Shift+F3 repeat whichever family was most recently
            // invoked; sLastSearchKind routes the dispatch.
            miRecFind         = addItem(miNavigate, "&Find Record...",        "Find",                Keys.Control | Keys.F,              recFindAllClicked);
            miRecFindPrev     = addItem(miNavigate, "&Reverse Find", "Find Previous",      Keys.Control | Keys.Shift | Keys.F, recFindAllPrevClicked);
            miRecJump         = addItem(miNavigate, "&Jump to Record...", "Jump Record",        Keys.Control | Keys.J,              recJumpClicked);
            miRecJumpPrev     = addItem(miNavigate, "Re&verse Jump", "Jump Previous Record", Keys.Control | Keys.Shift | Keys.J, recJumpPrevClicked);
            miRecFindRegex    = addItem(miNavigate, "Find Re&gex...", "Find Regex",       Keys.Control | Keys.F3,             recFindRegexClicked);
            miRecFindRegexPrev = addItem(miNavigate, "Reverse Re&gex Find", "Find Previous Regex", Keys.Control | Keys.Shift | Keys.F3, recFindRegexPrevClicked);
            miRecSearchAgain  = addItem(miNavigate, "Search &Next",   "Search Next",         Keys.F3,                            recSearchNextClicked);
            miRecSearchPrev   = addItem(miNavigate, "&Search Previous", "Search Previous",   Keys.Shift | Keys.F3,               recSearchPrevClicked);
            addSep(miNavigate);
            // Parent-child drill family. Alt+RightArrow enters a
            // child table from the current row's foreign-key target;
            // Alt+LeftArrow exits back to the parent row that drilled
            // in. Alt+Home pops all the way back to the topmost
            // ancestor.
            miRecEnterChild      = addItem(miNavigate, "&Enter Child Table...", "Enter Child",      Keys.Alt | Keys.Right, recEnterChildClicked);
            miRecExitChild       = addItem(miNavigate, "E&xit Child Table",        "Exit Child",       Keys.Alt | Keys.Left,  recExitChildClicked);
            miRecExitChildToRoot = addItem(miNavigate, "Exit to &Root Table",    "Exit Child to Root", Keys.Alt | Keys.Home,  recExitChildToRootClicked);

            // ===== Query menu: read aspects of the data =====
            miQuery = addMenu("&Query");
            // Read-only inspection of current record / table / schema.
            miRecShow        = addItem(miQuery, "&Inspect Record",  "Inspect Record",   Keys.Control | Keys.I,            recShowClicked);
            miSchemaProperties  = addItem(miQuery, "Table &Properties",              "Get Property",  Keys.Alt | Keys.Enter,            schemaPropertiesClicked);
            miRecRelated     = addItem(miQuery, "&Related Records...",   "Show Related",  Keys.None,                        recRelatedClicked);
            miSchemaShow     = addItem(miQuery, "&Show Schema",         "Show Schema",   Keys.None,                        schemaShowClicked);
            addSep(miQuery);
            // Say-X family: speaks state without changing focus or
            // recordset position (the Say-X status family).
            ToolStripMenuItem miSay = new ToolStripMenuItem("&Say...");
            miSay.AccessibleName = "Say announcements";
            miQuery.DropDownItems.Add(miSay);
            miSaySayMark         = addItem(miSay, "&Say Mark Status", "Say Mark", Keys.Shift | Keys.M, saySayMark);
            miSaySayStatus       = addItem(miSay, "Say Status",   "Say Status",       Keys.Shift | Keys.Z,               saySayStatus);
            miSaySayDatabase     = addItem(miSay, "Say &Database",        "Say Database",     Keys.Shift | Keys.D,               saySayDatabase);
            miSaySayOrder        = addItem(miSay, "Say &Order",      "Say Order",        Keys.Shift | Keys.O,               saySayOrder);
            miSaySayGoto         = addItem(miSay, "Say &Goto",      "Say Goto",         Keys.Shift | Keys.G,               saySayGoto);
            // Say Record retired in v1.0.101. Shift+Space is free. The
            // screen reader's built-in line-read command (e.g. JAWS
            // Ins+Down) reads the listview row's columns natively, so
            // a DbDo-specific Say Record was redundant.
            // Say Path retired in v1.0.99 (covered by Say Database on
            // Shift+D, single-press = name, double-press = full path).
            miSaySayYield        = addItem(miSay, "Say &Yield",       "Say Yield",        Keys.Shift | Keys.Y,               saySayYield);
            miSaySayTables       = addItem(miSay, "Say Tables",      "Say Tables",        Keys.Shift | Keys.F7,              saySayTables);
            // Say Marked moved off Shift+L (which is now Say Column from
            // Cursor) to Alt+Shift+M. Mark Record itself uses Control+M.
            miSaySayMarked       = addItem(miSay, "Say &Marked", "Say Marked",      Keys.None,                         saySayMarked);
            // Shift+E: Say Edited -- the 'edited' value, rendered in
            // a human-friendly local-time form, parallel to Shift+A
            // for the 'added' value.
            miSaySayEdited     = addItem(miSay, "Say &Edited", "Say Edited",         Keys.Shift | Keys.E,               saySayEdited);
            // Shift+N: Say Notes -- the 'notes' field of the current row.
            miSaySayNotes        = addItem(miSay, "Say &Notes",  "Say Notes",        Keys.Shift | Keys.N,               saySayNotes);
            // Shift+T: Say Tags -- the 'tags' field of the current row.
            miSaySayTags         = addItem(miSay, "Say &Tags",    "Say Tags",         Keys.Shift | Keys.T,               saySayTags);
            // Shift+L: Say Column from Cursor -- vertical sweep of the
            // current virtual column, starting at the current cell.
            // The Say-X family for multi-cell sweeps uses the L
            // convention -- L for List / Look / Linear-sweep, the
            // same accepted-exception logic that gives bookmark
            // commands the K letter. The first-letter rule wouldn't
            // accept E/G/V/X for these commands (none of those
            // letters appear in "Say Column" or "Say Rows"), and the
            // S/C/R/M letters are all heavily used elsewhere. L
            // names the activity ("linear list down the column" or
            // "linear list across the rows") in the same way K
            // names the bookmark family.
            // Say Column family. Scope: Alt = All (from top), Control =
            // from Current row. Filter: Shift = Marked rows only.
            miSaySayColumnAll       = addItem(miSay, "Say Column &All",                "Say Column All",                Keys.Alt | Keys.L,                  saySayColumnAll);
            miSaySayColumnAllMarked = addItem(miSay, "Say Column All &Marked",         "Say Column All Marked",         Keys.Alt | Keys.Shift | Keys.L,     saySayColumnAllMarked);
            miSaySayColumn          = addItem(miSay, "Say Column from &Current",       "Say Column from Current",       Keys.Control | Keys.L,              saySayColumn);
            miSaySayColumnMarked    = addItem(miSay, "Say Column from Current Mar&ked","Say Column from Current Marked",Keys.Control | Keys.Shift | Keys.L, saySayColumnMarked);
            // Say Records Rest gave up Alt+L to the Say Column All command
            // above; it remains on the menu (and the Alternate Menu) with
            // no chord for now. Say Records Rest Marked keeps Alt+Shift+M.
            miSaySayRows         = addItem(miSay, "Say Rec&ords Rest", "Say Records Rest",        Keys.None,                         saySayRows);
            miSaySayRowsMarked   = addItem(miSay, "Say Records Rest Marked", "Say Records Rest Marked", Keys.Alt | Keys.Shift | Keys.M,    saySayRowsMarked);
            miSaySayMarkedRows   = addItem(miSay, "Say &Marked Rows", "Say Marked Rows", Keys.Shift | Keys.Space, saySayMarkedRows);
            // Shift+K: Say Kin -- speak the 'look' values of every
            // related record (both directions: parents reached by
            // outbound FK columns, and children that point back to
            // this row via inbound FKs). "Kin" is the mnemonic
            // (English noun for relatives), parallels the existing
            // Show-Related GUI command but is read-only and stays in
            // the current table. Single-press speaks via the live
            // region; double-press shows the same content in the
            // multi-line dialog used by other speech-only commands.
            // Say Kin retired in v1.0.101. Shift+K is now free. The
            // foreign-key relationship readout is still available via
            // Say Related (Shift+R), which is a separate command with
            // a clearer name.
            // Shift+8 (the asterisk key) -- Say Sort and Filter. JAWS
            // calls Shift+8 "asterisk"; the symbol evokes "everything
            // about how the data is being shaped" which is what this
            // command reports. Numpad-asterisk (Keys.Multiply) is a
            // hidden alias for users with a numeric keypad.
            miSaySaySortFilter   = addItem(miSay, "Say &Sort and Filter", "Say Sort Filter", Keys.Shift | Keys.D8,         saySaySortFilter);
            // Alt+Delete: JAWS-style "say cursor position." Speaks the
            // current virtual column's header followed by the current
            // (1-based) row number. The single most useful "where am
            // I" probe when reading a wide grid; gives the user a
            // self-orientation anchor without moving focus.
            miSaySayPosition     = addItem(miSay, "Say Position", "Say Position", Keys.Alt | Keys.Delete,            saySayPosition);
            // Alt+Apostrophe (JAWS calls Keys.OemQuotes "Apostrophe"):
            // speak the current Windows clipboard contents. Mirrors
            // the Alt+' = "Clipboard" command in the Query
            // menu. Plain text only; if the clipboard holds files
            // or other shell data, the speech says "(non-text
            // clipboard)" rather than nothing. Double-press opens
            // the read-only memo dialog for line-by-line review.
            miSaySayClipboard    = addItem(miSay, "Say &Clipboard", "Say Clipboard", Keys.Alt | Keys.OemQuotes,    saySayClipboard);
            miSaySayYieldMarked  = addItem(miSay, "Say Marked Yield", "Say Yield Marked",  Keys.None,                          saySayYieldMarked);
            // v1.0.67 Say-X family completions. Each speaks one piece
            // of state without changing recordset position. The chord
            // family is Shift+Letter where Letter is the first letter
            // of the thing being said: Added, Cell, Filter, Id, Look,
            // Related, Url. Long values can be reviewed with a second
            // press (LbcDialog with a multi-line TextBox) via the
            // shared speakOrShow helper.
            miSaySayAdded        = addItem(miSay, "Say A&dded",     "Say Added",   Keys.Shift | Keys.A,                saySayAdded);
            miSaySayCell         = addItem(miSay, "Say Ce&ll",       "Say Cell",    Keys.Shift | Keys.C,                saySayCell);
            miSaySayFilter       = addItem(miSay, "Say &Where Filter",  "Say Where Filter", Keys.Shift | Keys.W,            saySayFilter);
            miSaySayFind         = addItem(miSay, "Say Fi&nd",          "Say Find",    Keys.Shift | Keys.F,                saySayFind);
            miSaySaySelect       = addItem(miSay, "Say &Select Columns", "Say Select",  Keys.Shift | Keys.S,                saySaySelect);
            miSaySayQuery        = addItem(miSay, "Say &Query",          "Say Query",   Keys.Shift | Keys.Q,                saySayQuery);
            miSaySayId           = addItem(miSay, "Say &Id",      "Say ID",      Keys.Shift | Keys.I,                saySayId);
            miSaySayLook         = addItem(miSay, "Say &Look",           "Say Look",    Keys.Shift | Keys.L,                saySayLook);
            miSaySayRelated      = addItem(miSay, "Say &Related", "Say Related", Keys.Shift | Keys.R,           saySayRelated);
            miSaySayUrl          = addItem(miSay, "Say &URL",          "Say URL",      Keys.Shift | Keys.U,                saySayUrl);
            miSaySayPrime        = addItem(miSay, "Say &Prime",        "Say Prime",    Keys.Shift | Keys.P,                saySayPrime);
            addSep(miQuery);
            // Filter / Sort -- data-shaping commands. As of v1.0.86
            // all per-column sort shortcuts are dropped (the
            // Alt+letter / Alt+Shift+letter pattern is retired); the
            // single Sort-Records dialog on Alt+Shift+S handles every
            // sorting case by defaulting to the virtual column and
            // offering an opt-in Descending checkbox.
            miViewSelect     = addItem(miQuery, "&Where Filter...",                                 "Where Filter",       Keys.Control | Keys.W,             viewSelectClicked);
            miViewResetFilter= addItem(miQuery, "Clear &Where",                                     "Clear Where",       Keys.Control | Keys.Shift | Keys.W, viewResetFilterClicked);
            miViewFilterRegex= addItem(miQuery, "Filter by Re&gex...",                                 "Filter Regex",      Keys.None,                          filterRegexClicked);
            addSep(miQuery);
            miViewResetSort  = addItem(miQuery, "Clear Sor&t",                                      "Reset Sort",        Keys.None,                          viewResetSortClicked);
            // Sort Records: the universal sort. Defaults to the
            // current virtual column with an opt-in Descending
            // checkbox. Replaces the entire family of per-column
            // sort shortcuts (Sort-Ascending, Sort-Descending,
            // Sort-Object, Sort-ById, Sort-ByLook, Sort-ByTags,
            // Sort-ByUrl, Sort-OldestFirst, Sort-RecentFirst) that
            // earlier versions provided. Their handlers are removed.
            // Order Records moved to Alt+Shift+O (v1.0.113),
            // vacating Alt+O; Reverse Order retired -- its
            // descending half lives in the dialog's Descending
            // button, per-column.
            miOrderRecords   = addItem(miQuery, "&Order Records...",  "Order Records",   Keys.Alt | Keys.O,                  orderRecordsClicked);
            miReverseOrder   = addItem(miQuery, "&Reverse Order",   "Reverse Order",  Keys.Alt | Keys.Shift | Keys.O,     reverseOrderClicked);

            // ===== Misc menu: utilities, tools, settings =====
            miMisc = addMenu("&Misc");
            miViewUpdate     = addItem(miMisc, "&Refresh View",                          "Update View",       Keys.F5,                            viewUpdateClicked);
            // Toggle Read Only: flip the database between read-write
            // and read-only at runtime. Restored in v1.0.95; v1.0.96
            // moved from Ctrl+Shift+R to Alt+Z per the user's
            // assessment that read-only is a rare-use toggle and the
            // Ctrl+Shift+R slot is better used for the more-common
            // regex-replace operation. Alt+Z is also one-handed which
            // is appropriate for a setting you flip once and forget.
            miToggleReadOnly = addItem(miMisc, "Read &Only Toggle",                       "Read Only Toggle",  Keys.Alt | Keys.Z,                  toggleReadOnlyClicked);
            // v1.0.67 deferred stubs. The chords are reserved so the
            // menu stays stable and the user can discover the planned
            // commands. The handlers display "Not yet implemented."
            miMiscDatabaseSummary = addItem(miMisc, "&Database Summary", "Database Summary", Keys.Alt | Keys.D, miscDatabaseSummaryClicked);
            // Window Summary stub retired v1.0.99. Shift+W is now Say Web.
            // If a future window-info command is added, it should use a
            // chord whose letter appears in its command name.
            addSep(miMisc);
            // Analytical utilities.
            miToolsMeasure   = addItem(miMisc, "&Table Summary",                      "Table Summary",     Keys.Alt | Keys.T,                  toolsMeasureClicked);
            // Describe Column: descriptive statistics for the current
            // virtual column. Numeric columns get Tukey's five-number
            // summary plus mean / SD / mode / skew; date columns get
            // earliest / latest / span / median; boolean-like columns
            // get true / false counts; text columns get a top-N
            // frequency table with shortest / longest / mean length.
            // The report opens in the same Lbc dialog the speech-only
            // commands use on double-press: multi-line read-only
            // TextBox plus an OK button, focus-stealing, Control+C
            // copies the whole report.
            miDescribeColumn = addItem(miMisc, "S&tatistics from Column",     "Statistics from Column", Keys.Alt | Keys.Shift | Keys.S, describeColumnClicked);
            // Select Columns: per-table visibility picker. Alt+S as
            // the S-letter productivity primary; the dialog has one
            // checkbox per column, plus Select All / Select None /
            // OK / Cancel buttons. Persists with the table (uses
            // the existing db.setSelectList mechanism).
            miSelectColumns = addItem(miMisc, "&Select Columns to Display...",  "Select Columns",   Keys.Alt | Keys.S,                  selectColumnsClicked);
            // Plot Column: graphical sibling of Describe Column. Picks
            // a chart type from the column's detected data type --
            // numeric -> histogram or box plot; date -> timeline or
            // by-year or by-month; boolean -> pie; text -> Pareto bar.
            // Writes an .xlsx to the database folder and opens it in
            // Excel, same pattern as the Frequency Chart command.
            miPlotColumn = addItem(miMisc, "&Graphics Column...", "Graphics Column",         Keys.Control | Keys.Shift | Keys.G, plotColumnClicked);
            miToolsChart     = addItem(miMisc, "&Generate from Grid...",  "Generate from Grid",       Keys.Alt | Keys.Shift | Keys.G,     generateFromGridClicked);
            miViewSelectColumn = addItem(miMisc, "Choose &Visible Columns...",           "Select Column",     Keys.None,                          viewSelectColumnClicked);
            // Extract Matches: walk every visible row, find every
            // regex match across every visible column, copy matches
            // to the clipboard. Alt+E ("E for Extract").
            miExtractRegex   = addItem(miMisc, "&Extract with Regex...", "Extract Regex", Keys.Control | Keys.Shift | Keys.X, extractRegexClicked);
            addSep(miMisc);
            // Cell clipboard family. Operate on the virtual cell (the
            // cell under the Alt+Control+arrow cursor). Shift+A appends,
            // Shift+C copies. The companion "Copy Row as TSV" below
            // has no hotkey or mnemonic letter -- the word "Copy" is
            // taken (Control+C) and no other letter in the label is a
            // legitimate Camel-Type mnemonic.
            miCellAppend     = addItem(miMisc, "Append &Cell to Clipboard",                "Append Cell",    Keys.Alt | Keys.C,                  cellAppendClicked);
            miCellCopy       = addItem(miMisc, "&Copy Cell to Clipboard",                  "Copy Cell",      Keys.Control | Keys.C,              cellCopyClicked);
            miCopyRow        = addItem(miMisc, "Copy &Visible Cells as TSV to Clipboard",   "Copy Visible Cells", Keys.None,                          copyRowClicked);
            // Column / whole-grid clipboard. Both walk every row with
            // the cursor suppressed and restore position when done (the
            // gridSearchForVirtualItem full-scan pattern). Unbound --
            // no free Camel-Type mnemonic letter in either label -- so
            // the user assigns chords from the Hotkey editor.
            miCopyColumn     = addItem(miMisc, "Copy Column to Clipboard",                  "Copy Column",        Keys.None,                          copyColumnClicked);
            miCopyGrid       = addItem(miMisc, "Copy Grid as TSV to Clipboard",             "Copy Grid",          Keys.None,                          copyGridClicked);
            miJumpNextInitial = addItem(miMisc, "Jump to Next &Initial...", "Jump Next Initial", Keys.None,                         jumpNextInitialClicked);
            addSep(miMisc);
            addSep(miQuery);
            miToolsInvokeSql = addItem(miQuery, "&Query...",                              "Query",             Keys.Control | Keys.Q,              toolsInvokeSqlClicked);
            miToolsSqlHistory= addItem(miQuery, "Query &History...",                      "Query History",     Keys.Alt | Keys.Shift | Keys.Q,     sqlHistoryClicked);
            miToolsTest      = addItem(miMisc, "&Test Integrity",                        "Test Database",     Keys.None,                          toolsTestClicked);
            miMiscHotkeySummary = addItem(miMisc, "&Hotkey Summary",      "Hotkey Summary",      Keys.Alt | Keys.Shift | Keys.H, hotkeySummaryClicked,
                "List every command with its key and description, then flag any inconsistencies",
                "Joins the command, key, and description tables the menus and Key Help already use into one listing, sorted by command name, then notes duplicate key assignments and commands missing a description. Bound to Alt+Shift+H.");
            miMiscOpenManagedCopy = addItem(miMisc, "Open as Managed &Copy...", "Open Managed Copy", Keys.None, openManagedCopyClicked,
                "Open a SQLite database as a throwaway working copy: edits stay in the copy and the original is untouched until you Save As",
                "The document model: the chosen SQLite database is copied to a temp working file that becomes the live database, so every edit, add, and delete lands in the copy and the original on disk is left alone. Use Save (Control+S), which writes the working copy out to a .db file (a -copy name is suggested, so the source is never overwritten); closing without saving discards the changes. To bring an Excel, Access, dBASE, or CSV file into a new DbDo database instead, use Import. Unbound by default.");
            miMiscDescribeTable = addItem(miQuery, "&Describe Table", "Describe Table", Keys.None, describeTableClicked,
                "Per-column data profile of the current table: declared type and key/null/FK flags, plus live null and distinct counts with min and max values",
                "A profile of the current base table, one column per entry: its declared type and any primary-key, not-null, or foreign-key flags from the schema, then the number of nulls, the number of distinct values, and the minimum and maximum values, each computed in SQL over the whole table. Read-only. It scans once per column, so it can take a moment on very large tables. Unbound by default.");
            miMiscFacetColumn = addItem(miQuery, "&Facet Column...", "Facet Column", Keys.None, facetColumnClicked,
                "List the distinct values in the column under the cursor with their row counts, then filter the grid to a chosen value",
                "Datasette-style faceting: groups the current table by the cursor's column and lists each distinct value with how many rows have it, most common first; picking a value filters the grid to just those rows. An accessible way to hear what a column contains and how it's distributed, then drill in. The value list is capped (1000) so a high-cardinality column can't flood the picker; filtering replaces any current filter, and blank/null and date values aren't filterable yet. Read-only until you pick. Unbound by default.");
            addSep(miMisc);
            ToolStripMenuItem miTools = new ToolStripMenuItem("&Tools...");
            miTools.AccessibleName = "Tools";
            miMisc.DropDownItems.Add(miTools);
            miToolsOpenFolder= addItem(miTools, "Open in E&xplorer",                      "Open File Folder",   Keys.Alt | Keys.OemPipe,            toolsOpenFolderClicked);
            miToolsCommandPrompt = addItem(miTools, "Open Co&mmand Prompt",                 "Command Prompt",    Keys.Control | Keys.OemQuestion,    toolsCommandPromptClicked,
                "Open a Windows command prompt in the folder of the currently-open database",
                "Control+Slash. The prompt opens with its working directory set to the open database's folder, or your user folder when nothing is open. Companion to Open in Explorer (Alt+Backslash), which opens that same folder in the file manager.");
            miToolsConsole   = addItem(miTools, "Open D&ot Prompt",                       "Enter Console",     Keys.Control | Keys.Oemtilde,       toolsConsoleClicked);
            miMiscSqleanConsole = addItem(miTools, "Sqlean &Console",                       "Sqlean Console",    Keys.Control | Keys.Shift | Keys.Oemtilde, sqleanConsoleClicked);
            addSep(miTools);
            // Script family: Invoke / View
            // Script pattern. Scripts are plain files in
            // %APPDATA%\DbDo\Scripts; .js files are executed as
            // JScript .NET via DbDo.dll, all other extensions
            // are displayed as reference text in a MessageBox.
            //
            // No Save-Script command: DbDo is not a text editor, so
            // there is no "current selection" to save. Edit Script
            // handles both modifying an existing script and creating
            // a new one (via a "[New script...]" entry at the top of
            // the pick list).
            miMiscInvokeScript     = addItem(miTools, "In&voke Script...",                     "Invoke Script",     Keys.Alt | Keys.V,                  miscInvokeScriptClicked);
            miMiscEditScript       = addItem(miTools, "Edit Sni&ppet...",                       "Edit Script",       Keys.Alt | Keys.Shift | Keys.V,     miscEditScriptClicked);
            miMiscOpenScriptFolder = addItem(miTools, "Open Script &Folder",                   "Open Script Folder", Keys.None,                          miscOpenScriptFolderClicked);
            miMiscEvaluate         = addItem(miTools, "&Evaluate Expression...",                "Evaluate Expression", Keys.Control | Keys.Oemplus,       miscEvaluateExpressionClicked,
                "Evaluate a one-off expression and hear the result",
                "Control+Equals. Prompts for an expression, evaluates it through DbDo's JScript .NET engine (the same engine behind Invoke Script and the dot prompt -- so 2+2*10 or string operations work), then speaks and shows the result. The last expression is remembered for quick tweaking. The result is shown rather than copied to the clipboard, so it stays reachable even where clipboard access is restricted.");
            addSep(miMisc);
            // Edit-Settings dialog: Alt+Shift+C -- same label, same
            // chord. F12 is kept as a hidden alias via
            // KeyMap.registerAlias below for users with the chord in
            // muscle memory from earlier DbDo versions.
            miToolsEditConfig= addItem(miMisc, "&Edit Settings...",          "Edit Settings", Keys.Alt | Keys.Shift | Keys.E,    toolsEditConfigClicked);

            // ===== Help menu =====
            // ===== Window menu: MDI window management =====
            // Command names and keys: Current
            // Windows (F4), Window Toggle (Shift+W), Next/Previous
            // Window (Control+Tab / Control+Shift+Tab), Say Windows
            // Open (Shift+F4), Close Window (Control+F4), Close All
            // But Current Window (Control+Shift+F4). Open Table is
            // DbDo's Open-versus-Go-to pair:
            // Open = new window, Go to (Choose Table, F6) = same
            // window.
            miWindow = addMenu("&Window");
            miWindowOpenTable     = addItem(miWindow, "&Open Table...",                 "Open Table",            Keys.Control | Keys.Shift | Keys.O,   windowOpenTableClicked);
            miWindowCurrent       = addItem(miWindow, "&Current Windows...",            "Current Windows",       Keys.F4,                              windowCurrentClicked);
            miWindowToggle        = addItem(miWindow, "Window &Toggle",                 "Window Toggle",         Keys.None,                            windowToggleClicked);
            miWindowNext          = addItem(miWindow, "&Next Window",                   "Next Window",           Keys.Control | Keys.Tab,              windowNextClicked);
            miWindowPrevious      = addItem(miWindow, "&Previous Window",               "Previous Window",       Keys.Control | Keys.Shift | Keys.Tab, windowPreviousClicked);
            miWindowSayOpen       = addItem(miWindow, "&Say Windows Open",              "Say Windows Open",      Keys.Shift | Keys.F4,                 windowSayOpenClicked);
            miWindowClose         = addItem(miWindow, "C&lose Window",                  "Close Window",          Keys.Control | Keys.F4,               windowCloseClicked);
            miWindowCloseAllBut   = addItem(miWindow, "Close &All But Current Window",  "Close All But Current Window", Keys.Control | Keys.Shift | Keys.F4, windowCloseAllButClicked);

            // ===== Help menu =====
            miHelp = addMenu("&Help");
            miHelpContents     = addItem(miHelp, "&Documentation",                       "Get Help",          Keys.F1,                            helpContentsClicked);
            // Shift+F1 -- Version History.
            miHelpHistory      = addItem(miHelp, "&History of Changes",                  "Show History",      Keys.Shift | Keys.F1,               helpHistoryClicked);
            miHelpReadme       = addItem(miHelp, "&Readme Guide",                        "Show Readme",       Keys.None,                          helpReadmeClicked);
            // Sample Databases: a tour entry point that lists every .db
            // file in the user's Samples folder (%APPDATA%\DbDo\Samples,
            // seeded once from {app}\Samples) and opens the chosen one
            // via the same code path File > Open Database uses, so all
            // the normal post-open behaviors (sort/filter/position
            // restore, status announcement) apply. The list is built at
            // runtime, so a user's own .db files in that folder appear
            // alongside the bundled samples.
            miHelpSampleDb     = addItem(miHelp, "Sample &Databases...",                "Sample Databases", Keys.None,                        helpSampleDbClicked);
            // The former per-sample items (Open Convention / Northwind /
            // Chinook) were removed: the Sample Databases picker above
            // discovers every .db under the Samples tree at runtime, so
            // the bundled samples appear there without dedicated menu
            // entries. (Samples that ship outside the Samples folder must
            // be placed under it to remain on the list.)
            addSep(miHelp);
            miHelpShowCommand  = addItem(miHelp, "Alternate Menu...",                        "Alternate Menu",    Keys.Alt | Keys.F10,                helpShowCommandClicked);
            // Control+F1 = Key Help toggle: announce on/off via the screen reader,
            // and when on, intercept hotkeys to announce them rather
            // than execute them.
            miHelpTraceCommand = addItem(miHelp, "&Key Describer Toggle",           "Key Describer Toggle", Keys.Control | Keys.F1,             helpTraceCommandClicked);
            miHelpStatus       = addItem(miHelp, "&Where Am I",                            "Show Status",       Keys.None,                          helpStatusClicked);
            miHelpEmailLog     = addItem(miHelp, "&Email Log File...",                   "Email Log",         Keys.None,                          emailLogClicked);
            // Toggle-Extra-Speech: silence DbDo's direct speech
            // messages without affecting the screen reader's natural
            // focus and selection announcements. The "zzz" mnemonic on Alt+Shift+Z reads as a
            // hush -- speech going to sleep. Default ON.
            miHelpExtraSpeech   = addItem(miHelp, "E&xtra Speech Toggle",                "Extra Speech Toggle", Keys.Alt | Keys.Shift | Keys.Z,    helpExtraSpeechClicked);
            // Toggle-Command-Echo: silence the spoken canonical command
            // name that fires from menu/hotkey activations just before
            // the command body runs. Mirrors the Extra Speech toggle's
            // mnemonic (Ctrl+Shift+Z is the keyboard companion to
            // Alt+Shift+Z, both "z for hushed speech"). Default ON.
            miHelpCommandEcho   = addItem(miHelp, "&Command Echo Toggle",                "Command Echo Toggle", Keys.Control | Keys.Shift | Keys.Z, helpCommandEchoClicked);
            addSep(miHelp);
            miHelpLog          = addItem(miHelp, "Show &Log Location",                   "Show Log",          Keys.None,                          helpLogClicked);
            addItem(miHelp, "File GitHub &Issue...", "File GitHub Issue", Keys.None, helpFileIssueClicked);
            miHelpWebSite      = addItem(miHelp, "Open We&bsite",      "Open Website",      Keys.None,                          helpWebSiteClicked);
            // Elevate-Version: check GitHub for a newer DbDo_setup.exe
            // and offer to download / install.
            miHelpElevate      = addItem(miHelp, "&Elevate Version...",                  "Elevate Version",   Keys.F11,                           helpElevateClicked);
            miHelpAbout        = addItem(miHelp, "&About",                                  "About DbDo",       Keys.Alt | Keys.F1,                 helpAboutClicked);

            // Delete key as a secondary binding for Remove-Record.
            // The primary menu shortcut is Control+D (shown next to
            // the menu item); Delete is a long-standing grid-editor
            // idiom (Excel tables, Outlook lists).
            registerLocalAlias(Keys.Delete, miRecRemove);
            registerLocalAlias(Keys.Enter, miRecEnterChild);
            registerLocalAlias(Keys.Back, miRecExitChild);

            // F12: legacy alias for Edit-Settings (now on
            // Alt+Shift+C). Hidden in the menu (Alt+Shift+C is shown there) but
            // continues to work for users with the chord in muscle
            // memory.
            registerLocalAlias(Keys.F12, miToolsEditConfig);

            // Numpad asterisk: alias for Say Sort and Filter, for
            // users with a numpad. The primary chord is Shift+8 on
            // the main row; this lets the same command fire from
            // Numpad-* without the user reaching across the keyboard.
            registerLocalAlias(Keys.Multiply, miSaySaySortFilter);

            // Get-Property: secondary alias on Shift+F6 ("Go to
            // Contents" -- structural where-am-I).

            // Graphics Column: secondary chord Ctrl+Shift+G, parallel
            // to its Alt+G primary. Statistics from Column moved to
            // Alt+Shift+S (its old Ctrl+Shift+S chord is now Save As);
            // Generate from Grid is on Alt+Shift+G. The analytical trio
            // (Statistics, Graphics Column, Generate from Grid) thus lives
            // on the Alt+Shift+letter family.

            // Jump-Record: secondary alias on Shift+J for muscle
            // Shift+J: data-list alias for Jump-Record (single-column
            // substring). Preserves the bare-Shift+Letter family
            // muscle memory from earlier DbDo versions, and parallels
            // the canonical Control+J binding. Note this binds to
            // miRecJump (the new column-listbox Jump-Record), NOT to
            // miRecFind (which is now the across-all-columns Find).
            registerLocalAlias(Keys.Shift | Keys.J, miRecJump);

            // Alt+Letter bindings that don't collide with main-menu
            // accelerators. ProcessCmdKey dispatches form-level chords
            // BEFORE menu accelerators are processed, so even Alt+P
            // (which is Help's menu accelerator) and Alt+E (Edit's)
            // can host commands -- the command wins. But to keep
            // documentation simple and avoid confusion, I prefer
            // Alt+Letter bindings on letters that aren't main-menu
            // accelerators in the first place. The main menus use
            // F (File), E (Edit), N (Navigate), Q (Query), M (Misc),
            // P (Help); the bindings below all use other letters.
            //
            //   Alt+R = Recent-Files (R for Recent) -- the menu item
            //           registration above on miFileRecent binds this
            //           globally; no registerAlias needed here.
            //   Alt+Shift+R = Show-Related (Related uses the modified
            //           form since Recent took the bare Alt+R)
            //   Alt+T = Measure-Table (T for Table)
            //   Alt+C = New-Chart (C for Chart)
            // Alias registrations. The chord on the left side dispatches
            // to the menu item on the right WITHOUT putting the chord
            // on the menu item's ShortcutKeys (so the user-visible
            // menu doesn't show two chords for one item).
            //
            // v1.0.69 cleanup: Alt+T, Alt+C, and Alt+L are no longer
            // aliases. Each of those chords is now the primary chord
            // for one of the new Sort-by-<column> commands (Alt+T =
            // Sort-by-Tags, Alt+C used to be Sort-by-... but the user
            // spec puts Append Cell there directly, Alt+L = Sort-by-
            // Look). The tools they used to alias (Measure-Table,
            // New-Chart, Select-Table) keep their canonical chords
            // and menu locations.
            //
            // Alt+Shift+R now belongs to Run Report. Show Related (Related
            // Records) has no S/R chord available under the mnemonic rule
            // (Ctrl+Shift+R = Regex Replace, Alt+R = Recent Files, Ctrl+R =
            // Replace Column, and every S chord is taken), so it stays
            // reachable from the Query menu (Related Records...) without a
            // keyboard chord.

            // Populate per-command summaries and descriptions. Done
            // in one place rather than at each addItem call site for
            // readability and so the metadata is easy to audit and
            // edit. Any command not listed falls back to its menu
            // label minus ampersand mnemonics, courtesy of the
            // KeyMap.summaryFor helper.
            populateCommandSummaries();

            this.MainMenuStrip = menuMain;
            this.Controls.Add(menuMain);
        }

        // populateCommandSummaries: register the one-line summary
        // and optional multi-line description for each command.
        // Voice convention: verb-first, plain text, one line for
        // the summary; description (when present) gives the why or
        // the gotchas. Commands not listed here fall back to the
        // menu label (KeyMap.summaryFor handles this).
        private void populateCommandSummaries()
        {
            // Helper to keep the table compact.
            Action<string, string, string> add = (sCmd, sSum, sDesc) => {
                if (!string.IsNullOrEmpty(sSum)) KeyMap.dCommandToSummary[sCmd] = sSum;
                if (!string.IsNullOrEmpty(sDesc)) KeyMap.dCommandToDescription[sCmd] = sDesc;
                // Also update the menu item's ToolTipText so screen
                // readers and status bar pick up the explicit
                // summary rather than the menu-label fallback.
                foreach (KeyValuePair<ToolStripMenuItem, string> kv in KeyMap.dMenuToCommand)
                    if (kv.Value == sCmd && !string.IsNullOrEmpty(sSum))
                        kv.Key.ToolTipText = sSum;
            };

            // Context assignments: { canonical command, context }. Any
            // command not listed defaults to "Global" -- live wherever its
            // menu is. Add rows here as the parent/child context taxonomy is
            // settled; the canonical name must match the add(...) call above.
            // Example rows (commented until the taxonomy is confirmed):
            //   new string[] { "Edit Cell",         "Grid" },
            //   new string[] { "Pick Lookup Value", "Cell Editor" },
            string[][] aContext = new string[][] {
            };
            foreach (string[] aPair in aContext)
                if (aPair.Length == 2) KeyMap.dCommandToContext[aPair[0]] = aPair[1];

            // ===== File menu =====
            add("New Database",       "Create a new database file: define the first table's fields and types; the standard columns and the builtin maps and lookups tables are added automatically", "");
            add("Add Table",          "Add another table in the standard shape to the open database", "");
            add("Open Database",      "Open a database file", "");
            add("Close Database",     "Close the currently open database", "");
            // ===== Window menu =====
            add("Open Table",         "Open a chosen table of the current database in a new window",
                "Open Table (Control+Shift+T) makes a new window; Choose Table (F6) changes the table in the same window.");
            add("Current Windows",    "Pick from the list of open recordset windows and activate the chosen one",
                "F4. Each open recordset (typically a table) is an MDI child window.");
            add("Window Toggle",      "Switch between the two most recently used windows",
                "Shift+W.");
            add("Next Window",        "Activate the next open window", "Control+Tab.");
            add("Previous Window",    "Activate the previous open window", "Control+Shift+Tab.");
            add("Say Windows Open",   "Speak the count and titles of open recordset windows, marking the current one",
                "Shift+F4.");
            add("Close Window",       "Close the current recordset window",
                "Control+F4. Closing the last window exits DbDo, since the menu bar lives in the window.");
            add("Close All But Current Window", "Close every window except the current one",
                "Control+Shift+F4.");
            add("Save",             "Save changes to disk (writes an open workbook back to its .xlsx; a .db is already saved as you go)", "");
