        private ToolStripMenuItem addMenu(string sText)
        {
            ToolStripMenuItem mi = new ToolStripMenuItem(sText);
            mi.AccessibleName = sText.Replace("&", "");
            menuMain.Items.Add(mi);
            return mi;
        }

        private ToolStripMenuItem addItem(ToolStripMenuItem miParent, string sText, string sCommand, Keys key, EventHandler evHandler)
        {
            return addItem(miParent, sText, sCommand, key, evHandler, "", "");
        }

        // Extended addItem with summary and optional description.
        // The summary is one line of verb-first plain text shown on
        // the menu status bar when the item has focus, in the Alt+
        // F10 Alternate Menu, and in the Control+F1 Key Help.
        // The description, if non-empty, is the longer form shown in
        // the Alternate Menu's detail pane and in the Key Help
        // trace.
        private ToolStripMenuItem addItem(ToolStripMenuItem miParent, string sText, string sCommand, Keys key, EventHandler evHandler,
            string sSummary, string sDescription)
        {
            ToolStripMenuItem mi = new ToolStripMenuItem(sText);
            mi.Click += (senderA, evA) => { commandEcho(sCommand); evHandler(senderA, evA); };
            miParent.DropDownItems.Add(mi);
            KeyMap.register(key, mi, sCommand);
            if (key != Keys.None) dLocalKeyToMenu[key] = mi;
            attachSummary(mi, sCommand, sSummary, sDescription);
            return mi;
        }

        // registerLocalAlias: bind a secondary chord to a command's menu
        // item, recording it in THIS window's dispatch table as well as
        // the static KeyMap, so the alias acts on the active window too.
        private void registerLocalAlias(Keys key, ToolStripMenuItem mi)
        {
            KeyMap.registerAlias(key, mi);
            if (key != Keys.None) dLocalKeyToMenu[key] = mi;
        }

        private ToolStripMenuItem addItemLocal(ToolStripMenuItem miParent, string sText, string sCommand, Keys key, EventHandler evHandler)
        {
            return addItemLocal(miParent, sText, sCommand, key, evHandler, "", "");
        }
        private ToolStripMenuItem addItemLocal(ToolStripMenuItem miParent, string sText, string sCommand, Keys key, EventHandler evHandler,
            string sSummary, string sDescription)
        {
            ToolStripMenuItem mi = new ToolStripMenuItem(sText);
            mi.Click += (senderA, evA) => { commandEcho(sCommand); evHandler(senderA, evA); };
            miParent.DropDownItems.Add(mi);
            KeyMap.registerDisplayOnly(key, mi, sCommand);
            attachSummary(mi, sCommand, sSummary, sDescription);
            return mi;
        }

        // attachSummary: register summary and description in KeyMap,
        // set the menu item's ToolTipText so screen readers announce
        // it on keyboard navigation, and wire MouseEnter / Select
        // handlers to surface the summary on the form's status bar.
        // The fall-through "summary is empty" case picks the menu
        // label (sans ampersand mnemonics) as a sensible default so
        // every menu item is at least minimally self-describing.
        private void attachSummary(ToolStripMenuItem mi, string sCommand, string sSummary, string sDescription)
        {
            if (!string.IsNullOrEmpty(sSummary))
                KeyMap.dCommandToSummary[sCommand] = sSummary;
            if (!string.IsNullOrEmpty(sDescription))
                KeyMap.dCommandToDescription[sCommand] = sDescription;

            // ToolTipText: shown by screen readers when the menu item
            // has accelerator-key focus. Always populated, falling
            // back to KeyMap.summaryFor's logic.
            string sTip = !string.IsNullOrEmpty(sSummary)
                ? sSummary : stripMnemonic(mi.Text);
            mi.ToolTipText = sTip;

            // Surface on status bar when the item has focus. ToolStrip
            // raises MouseEnter for both mouse hover and keyboard
            // arrow-key navigation (the tracker treats them
            // uniformly), so wiring MouseEnter alone covers both
            // input methods.
            mi.MouseEnter += (s, e) => updateStatusFromMenu(sCommand);
            mi.MouseLeave += (s, e) => updateStatusFromMenu(null);
        }

        // stripMnemonic: render a menu label as plain text for the
        // status bar / tool-tip. Strips ampersand mnemonic markers
        // and trailing "..." that signals a follow-up dialog.
        private static string stripMnemonic(string s)
        {
            if (string.IsNullOrEmpty(s)) return "";
            string sOut = s.Replace("&", "");
            if (sOut.EndsWith("...")) sOut = sOut.Substring(0, sOut.Length - 3).TrimEnd();
            return sOut;
        }

        // updateStatusFromMenu: write the command's summary to the
        // status bar when a menu item has focus. Passes null to
        // restore the previous status text on MouseLeave / when the
        // menu closes.
        private string sPrevStatusBeforeMenu = null;
        private void updateStatusFromMenu(string sCommand)
        {
            if (lblStatus == null) return;
            if (sCommand == null)
            {
                if (sPrevStatusBeforeMenu != null)
                {
                    lblStatus.Text = sPrevStatusBeforeMenu;
                    sPrevStatusBeforeMenu = null;
                }
                return;
            }
            if (sPrevStatusBeforeMenu == null)
                sPrevStatusBeforeMenu = lblStatus.Text;
            string sSummary = KeyMap.summaryFor(sCommand);
            lblStatus.Text = sCommand + ": " + sSummary;
        }


        // Command Echo: speak the canonical command name through the
        // live region just before the command runs. Setting lives in
        // [Options] commandEcho; default Y. Off-by-toggle for users
        // who find the confirmation noisy. Key Help mode (Ctrl+F1)
        // is the more verbose cousin: Key Help announces command,
        // chord, and summary, and SUPPRESSES the command body; echo
        // announces just the name and RUNS the body.
        private static bool bCommandEchoCached = false;
        private static bool bCommandEchoLoaded = false;
        public static bool isCommandEchoOn()
        {
            if (!bCommandEchoLoaded)
            {
                try
                {
                    string sV = readEchoSetting();
                    bCommandEchoCached = !sV.Equals("N", StringComparison.OrdinalIgnoreCase)
                                      && !sV.Equals("No", StringComparison.OrdinalIgnoreCase)
                                      && !sV.Equals("0", StringComparison.Ordinal)
                                      && !sV.Equals("False", StringComparison.OrdinalIgnoreCase);
                }
                catch { bCommandEchoCached = true; }
                bCommandEchoLoaded = true;
            }
            return bCommandEchoCached;
        }
        public static void invalidateCommandEchoCache() { bCommandEchoLoaded = false; }
        private static string readEchoSetting()
        {
            string sV = IniSession.read("Options", "CommandEcho");
            return string.IsNullOrEmpty(sV) ? "Y" : sV;
        }
        private void commandEcho(string sCommand)
        {
            if (!isCommandEchoOn()) return;
            if (string.IsNullOrEmpty(sCommand)) return;
            // A command whose name ends in "Toggle" announces its NEW
            // STATE itself -- the on/off modes say "<Feature> On" / "No
            // <Feature>" via sayToggleState, and Window Toggle names the
            // window it switched to -- so echoing the raw command name
            // here would duplicate that and, worse, would not reflect the
            // resulting state. Skip the raw echo and let that state
            // announcement be the command echo.
            if (sCommand.TrimEnd().EndsWith("Toggle", StringComparison.OrdinalIgnoreCase)) return;
            try { LiveRegion.say(sCommand); } catch { /* swallow */ }
        }

        private void addSep(ToolStripMenuItem miParent)
        {
            miParent.DropDownItems.Add(new ToolStripSeparator());
        }

        // =====================================================================
        // Grid construction. Cell-level keyboard navigation, type-ahead
        // jump, and the cell-changed handler that syncs the recordset's
        // absolutePosition.
        // =====================================================================
        private void buildGrid()
        {
            grid = new LbcListView();
            grid.AccessibleName = "Records";
            grid.AccessibleRole = AccessibleRole.List;
            grid.Dock = DockStyle.Fill;
            grid.View = View.Details;
            grid.FullRowSelect = true;
            grid.MultiSelect = false;
            grid.HideSelection = false;
            grid.GridLines = false;
            grid.HeaderStyle = ColumnHeaderStyle.Nonclickable;
            grid.LabelEdit = false;
            grid.UseCompatibleStateImageBehavior = false;
            grid.ShowItemToolTips = false;
            grid.ContextMenuStrip = buildGridContextMenu();

            // Virtual mode: never materialize ListViewItems for the
            // whole table. The ListView calls RetrieveVirtualItem(N)
            // when it needs row N for display; we move the ADO
            // cursor to that position and build a ListViewItem from
            // the current field values.
            grid.VirtualMode = true;
            grid.VirtualListSize = 0;
            grid.RetrieveVirtualItem += gridRetrieveVirtualItem;
            grid.CacheVirtualItems += gridCacheVirtualItems;

            // Type-ahead search: ObjectListView's IsSearchOnSortColumn
            // pattern. When the user presses a letter inside the
            // list, jump to the next row whose first-displayed
            // column starts with that letter. WinForms' virtual
            // ListView raises SearchForVirtualItem for this; we
            // walk the recordset for the next match.
            grid.SearchForVirtualItem += gridSearchForVirtualItem;

            // Row change: when the focused item changes, move the
            // ADO recordset's cursor to match so commands like
            // Show-Object, Copy-Record, and Set-Mark act on the
            // row the user is reading.
            grid.SelectedIndexChanged += gridSelectedIndexChanged;
            // Assert the cursor-row selection when the grid gains focus.
            // updateGrid sets it during open, but in VirtualMode that
            // state doesn't reliably reach the screen reader until the
            // control is actually focused -- which is when Enter fires.
            grid.Enter += gridEnterEnsureSelection;

            // Column navigation within a row: Tab and Shift+Tab
            // move the virtual cursor (iVirtualCol) one column left
            // or right through virtMoveTo, which announces the new
            // column header and value. iVirtualCol is the SINGLE
            // source of truth for "the current column": Say Cell,
            // type-ahead search, sort defaults, and Show-Related
            // all read it, so what the user last heard is always
            // the column a command acts on.
            grid.KeyDown += gridKeyDown;
            // Tab and Shift+Tab need to fire as KeyDown events on the
            // ListView, but WinForms treats Tab as a focus-traversal
            // chord at a higher level by default. PreviewKeyDown
            // flags Tab as an input key for this control so KeyDown
            // sees it; the actual move logic in gridKeyDown then
            // delegates to virtMoveTo. Control+Tab is excluded so it
            // stays available for Switch-Table.
            grid.PreviewKeyDown += (s, e) => {
                if (e.KeyCode == Keys.Tab && !e.Control)
                    e.IsInputKey = true;
            };

            ctxGrid = new ContextMenuStrip();
            ctxGrid.Items.Add("Show Record", null, recShowClicked);
            ctxGrid.Items.Add("Set-Record...", null, recSetClicked);
            ctxGrid.Items.Add("Delete Record", null, recRemoveClicked);
            ctxGrid.Items.Add("-");
            ctxGrid.Items.Add("Copy Record", null, recCopyClicked);
            grid.ContextMenuStrip = ctxGrid;

            this.Controls.Add(grid);
        }

        // Virtual-mode callbacks: the ListView asks for one row at a
        // time as it scrolls. We move the ADO cursor to row N and
        // build a ListViewItem with one subitem per column.
        // One-shot diagnostic flag: a column/field count mismatch is
        // logged the first time it is seen per session, not per row.
        private bool bLoggedVirtualMismatch = false;

        // miPaddedItem: a ListViewItem whose SubItems count ALWAYS
        // equals the grid's current column count. WinForms throws
        // InvalidOperationException ("needs a list view SubItem for
        // each ListView column") for any virtual item with fewer
        // subitems than columns -- so every exit from the retrieve
        // handler goes through this padding, making that exception
        // structurally impossible. Extra values are truncated; missing
        // ones become "".
        private ListViewItem miPaddedItem(string[] aRow)
        {
            int iCols = 1;
            try { if (grid != null && grid.Columns.Count > 0) iCols = grid.Columns.Count; }
            catch { }
            string[] aFit = new string[iCols];
            for (int i = 0; i < iCols; i++)
                aFit[i] = (aRow != null && i < aRow.Length && aRow[i] != null) ? aRow[i] : "";
            return new ListViewItem(aFit);
        }

        // gridEnterEnsureSelection: when the grid gains focus, make the
        // cursor row the single selected row. With MultiSelect off and
        // Space repurposed to toggle marked (not selection), the focused
        // row then stays selected for the life of the view, so the
        // screen reader never announces it as "Unselected". Re-asserting
        // here -- while the control is genuinely focused -- is what makes
        // the selection state register, which it did not when set during
        // open before the grid held focus.
        // gridEnterEnsureSelection: when the grid regains focus, sync
        // its selection to the recordset's current row -- db.absolutePosition
        // is the authoritative cursor. Re-asserting the grid's OWN prior
        // selection here was wrong: after a command moved the db cursor
        // (Find, Jump, Go To) while focus was in a modal dialog, the
        // virtual ListView can drop its programmatic selection on the
        // focus round-trip, so the old code re-selected row 1 and undid
        // the move -- which looked like "Find didn't move focus."
        // Selecting db.absolutePosition keeps grid and recordset in
        // lockstep and still satisfies the always-selected invariant
        // (a fresh open sits at position 1).
        private void gridEnterEnsureSelection(object sender, EventArgs evArgs)
        {
            if (grid == null || db == null || !db.hasRecordset()) return;
            int iCount = db.recordCount;
            if (iCount <= 0) return;
            int iPos = db.absolutePosition;
            if (iPos < 1 || iPos > iCount) iPos = 1;
            int iIndex = iPos - 1;
            bSuppressCellChanged = true;
            try
            {
                if (iIndex >= 0 && iIndex < grid.VirtualListSize)
                {
                    grid.SelectedIndices.Clear();
                    grid.SelectedIndices.Add(iIndex);
                    grid.EnsureVisible(iIndex);
                    try { grid.FocusedItem = grid.Items[iIndex]; } catch { }
                    grid.selectAndFocusNative(iIndex);
                }
                else grid.ensureCursorRow();
            }
            catch { }
            finally { bSuppressCellChanged = false; }
            try { DbDoLog.write("Grid Enter: synced grid to absolutePosition " + iPos + " of " + iCount + "."); } catch { }
        }

        private void gridRetrieveVirtualItem(object sender, RetrieveVirtualItemEventArgs evArgs)
        {
            if (db == null || !db.hasRecordset())
            {
                evArgs.Item = miPaddedItem(null);
                return;
            }
            try
            {
                // THE SYNCHRONIZATION INVARIANT. Painting a row must
                // not move the user's record. This handler seeks the
                // ADO cursor to whatever row the ListView asks for --
                // which during a repaint is every visible row, ending
                // wherever painting ended, NOT at the selected row.
                // Commands then read "the current record" and get the
                // wrong one (Show Record on Enter showing a different
                // contact; Enter Child drilling from the wrong row).
                // So: seek, read, and in the finally below RESTORE the
                // cursor to the selected row. The client-side cursor
                // makes the extra seek an in-memory operation.
                int iAdoPos = evArgs.ItemIndex + 1; // ADO is 1-based
                int iSelectedPos = -1;
                try
                {
                    if (grid != null && grid.SelectedIndices.Count > 0)
                        iSelectedPos = grid.SelectedIndices[0] + 1;
                }
                catch { }
                if (db.absolutePosition != iAdoPos)
                {
                    bSuppressCellChanged = true;
                    try { db.absolutePosition = iAdoPos; }
                    finally { bSuppressCellChanged = false; }
                }
                List<string> lFields = db.getDisplayFieldNames();
                if (!bLoggedVirtualMismatch && grid != null
                    && grid.Columns.Count > 0 && lFields.Count != grid.Columns.Count)
                {
                    bLoggedVirtualMismatch = true;
                    // Capture the actual lists, not just the counts: a
                    // trailing blank column or a notes/standard column
                    // that renders empty almost always traces to a
                    // display-fields vs grid-columns disagreement, and
                    // the names pinpoint which column is the odd one out.
                    string sFieldList = string.Join(", ", lFields.ToArray());
                    List<string> lHdr = new List<string>();
                    try { foreach (ColumnHeader oCh in grid.Columns) lHdr.Add(oCh.Text); } catch { }
                    DbDoLog.write("Virtual grid mismatch: " + lFields.Count
                        + " display fields vs " + grid.Columns.Count
                        + " columns (table " + (db.currentTable ?? "?") + ")"
                        + "; fields=[" + sFieldList + "]"
                        + "; columns=[" + string.Join(", ", lHdr.ToArray()) + "]");
                }
                string[] aRow = new string[lFields.Count];
                for (int i = 0; i < lFields.Count; i++)
                {
                    // Per-field isolation: one unreadable field blanks
                    // that cell only, never the whole row.
                    try
                    {
                        string sCol = lFields[i];
                        if (db.isFieldBinary(sCol))
                        {
                            int iLen = db.getFieldByteLength(sCol);
                            aRow[i] = (iLen > 0) ? "[BLOB, " + iLen + " bytes]"
                                    : (iLen == 0) ? "" : "[BLOB]";
                        }
                        else
                        {
                            aRow[i] = formatCellValue(db.getFieldValue(sCol));
                        }
                    }
                    catch { aRow[i] = ""; }
                }
                evArgs.Item = miPaddedItem(aRow);
                if (iSelectedPos > 0 && iSelectedPos != iAdoPos
                    && iSelectedPos <= db.recordCount)
                {
                    bSuppressCellChanged = true;
                    try { db.absolutePosition = iSelectedPos; }
                    catch { }
                    finally { bSuppressCellChanged = false; }
                }
            }
            catch
            {
                evArgs.Item = miPaddedItem(null);
            }
        }

        // CacheVirtualItems: the ListView tells us a window of items
        // it is about to need. We could pre-fetch here, but our
        // ADO cursor is a single seek anyway; pre-fetching wouldn't
        // help. Leave as a no-op; RetrieveVirtualItem handles
        // each row as it is asked for.
        private void gridCacheVirtualItems(object sender, CacheVirtualItemsEventArgs evArgs)
        {
            // intentionally empty
        }

        // Type-ahead search: walk the recordset for the next row
        // whose value in the user-selected column (defaulting to
        // the current displayed column under Tab focus, falling
        // back to the first displayed column) starts with the
        // typed text. Inspired by ObjectListView's IsSearchOnSortColumn.
        //
        // Returns the index of the matching row through Index on
        // the event args; the ListView then focuses that row.
        // Returns -1 (Index unset) if no match found.
        private void gridSearchForVirtualItem(object sender, SearchForVirtualItemEventArgs evArgs)
        {
            if (db == null || !db.hasRecordset()) return;
            if (string.IsNullOrEmpty(evArgs.Text)) return;
            string sNeedle = evArgs.Text;
            // Pick the column to search: the column under virtual
            // focus if any, else column 0 (first displayed).
            int iCol = iVirtualCol;
            if (iCol < 0 || iCol >= grid.Columns.Count) iCol = 0;
            string sFieldName = grid.Columns[iCol].Text;
            if (string.IsNullOrEmpty(sFieldName)) return;

            // Walk forward from StartIndex+1, wrapping at the end.
            // Save and restore the cursor position so the search
            // doesn't leave the recordset displaced.
            int iTotal = db.recordCount;
            if (iTotal <= 0) return;
            int iStart = evArgs.StartIndex;
            if (iStart < 0 || iStart >= iTotal) iStart = 0;
            int iSavedPos = db.absolutePosition;
            bSuppressCellChanged = true;
            try
            {
                for (int i = 1; i <= iTotal; i++)
                {
                    int iCheck = (iStart + i) % iTotal;
                    int iAdoPos = iCheck + 1;
                    try { db.absolutePosition = iAdoPos; } catch { continue; }
                    string sValue = "";
                    try { sValue = db.getFieldValue(sFieldName) ?? ""; } catch { }
                    if (sValue.StartsWith(sNeedle, StringComparison.OrdinalIgnoreCase))
                    {
                        evArgs.Index = iCheck;
                        return;
                    }
                }
            }
            finally
            {
                try { if (iSavedPos > 0) db.absolutePosition = iSavedPos; } catch { }
                bSuppressCellChanged = false;
            }
            // Not found: leave evArgs.Index at its default (-1).
        }

        // Aspect-style formatter: produce a readable display string
        // from the raw field value ADO returns. Inspired by
        // ObjectListView's AspectToStringConverter pattern. Three
        // transformations:
        //
        //   null/empty                  -> ""
        //   raw datetime stamp          -> "yyyy-MM-dd HH:mm" if it
        //                                  has time, "yyyy-MM-dd"
        //                                  otherwise
        //   string with trailing newline-> trimmed (newlines confuse
        //                                  screen readers reading a
        //                                  cell value)
        //
        // The recordset's getFieldValue currently returns a string
        // already, so date detection is best-effort: try to parse
        // as DateTime; if successful, reformat.
        private string formatCellValue(string sValue)
        {
            if (sValue == null) return "";
            if (sValue.Length == 0) return "";
            // Reformat values that look unambiguously like dates.
            // Require: length >= 8 (yyyy-m-d minimum), contains
            // at least one of '-' or '/' or ':' (date or time
            // separators). This filters out short numeric strings
            // like "1", "100", or "2024" that DateTime.TryParse
            // would otherwise coerce into the current month/year.
            if (sValue.Length >= 8
                && (sValue.IndexOf('-') >= 0 || sValue.IndexOf('/') >= 0 || sValue.IndexOf(':') >= 0))
            {
                DateTime dt;
                if (DateTime.TryParse(sValue, out dt))
                {
                    if (dt.TimeOfDay.TotalSeconds == 0)
                        return dt.ToString("yyyy-MM-dd");
                    return dt.ToString("yyyy-MM-dd HH:mm");
                }
            }
            // Strip trailing newlines/whitespace so multi-line
            // text values like notes don't bleed into next row.
            return sValue.TrimEnd('\r', '\n', ' ', '\t');
        }

        private void gridSelectedIndexChanged(object sender, EventArgs evArgs)
        {
            if (bSuppressCellChanged) return;
            if (db == null || !db.hasRecordset()) return;
            if (grid.SelectedIndices.Count == 0) return;
            int iRow = grid.SelectedIndices[0];
            try { db.absolutePosition = iRow + 1; } catch { }
            // Keep the virtual cursor's row in sync with the
            // ListView's row selection so plain Down/Up arrows
            // don't desync the two cursors. Column stays put.
            virtSyncFromListSelection();
            updateStatusBar();
        }

        // ListView KeyDown: intercept Tab and Shift+Tab to step
        // through columns within the focused row. The ListView's
        // default behavior is to move focus to the next control;
        // we override it for in-row column navigation, then
        // announce the new column.
        //
        // This handler also recognizes the bare Shift+Letter
        // shortcut family. Because the dispatch lives on the
        // ListView's own KeyDown event, the chord only fires when
        // the data grid has focus. When focus is in a text box,
        // dialog edit field, combo box, or the menu bar, this
        // handler does not run, so capital letters typed into
        // those controls reach them as plain character input --
        // no focus check is needed at the dispatch site. The
        // pattern is the standard MDI child pattern.
        // ListBox_KeyDown.
        //
        // Type-ahead navigation in the data grid is case-
        // insensitive: lowercase letters jump to rows by initial
        // character through the ListView's virtual-mode
        // SearchForVirtualItem event. The Shift+Letter shortcuts
        // override capital letters for those nine specific
        // letters (E F G J M R S U X); lowercase forms of the
        // same letters continue to type-ahead. The user-side
        // convention: lowercase to navigate, uppercase to
        // shortcut.
        private void gridKeyDown(object sender, KeyEventArgs evArgs)
        {
            // View cycle (F6 forward, Shift+F6 back): from the list
            // view, enter the form view (F6) or the show view
            // (Shift+F6) -- the three presentations of the current
            // record cycle list -> edit -> inspect -> list. The
            // Windows F6 "switch pane/view" idiom; Control+E and
            // Control+I jump directly to the edit and inspect views.
            if (evArgs.KeyData == Keys.F6)
            {
                runRecordViews(1, false);
                evArgs.Handled = true; evArgs.SuppressKeyPress = true;
                return;
            }
            if (evArgs.KeyData == (Keys.Shift | Keys.F6))
            {
                runRecordViews(2, false);
                evArgs.Handled = true; evArgs.SuppressKeyPress = true;
                return;
            }

            // Db cursor column movement (v1.0.109):
            //
            //   LeftArrow / RightArrow -- previous / next column in
            //     the CURRENT row, no wrap. Spoken as "header: value"
            //     (no row number; movement stays within the row). At
            //     the row's edge the cursor stays put and the edge is
            //     announced.
            //   Tab / Shift+Tab -- same stepping, but the cursor
            //     CROSSES rows at the row ends: Tab past the last
            //     column lands on the next row's first column,
            //     Shift+Tab past the first column lands on the
            //     previous row's last column. Row-crossing moves are
            //     spoken as "header row N: value" so the new row
            //     number arrives before the cell value. At the very
            //     first and last cells of the table the cursor stops
            //     and announces the boundary.
            //
            // Both families route through virtMoveTo, which owns the
            // row-aware announcement pattern; Up/Down arrows remain
            // the ListView's native row movement.
            //
            // Control+Tab and Control+Shift+Tab remain reserved for
            // Next-Window / Previous-Window and bubble up so the
            // form's ProcessCmdKey dispatches them.
            // Null Value: set the db cursor's cell to SQL NULL.
            if (evArgs.KeyData == (Keys.Control | Keys.Shift | Keys.Back))
            {
                nullCurrentCell();
                evArgs.Handled = true;
                evArgs.SuppressKeyPress = true;
                return;
            }

            // Bare NumPad5 with NumLock off arrives as Keys.Clear;
            // it speaks the current cell, equivalent to Say Cell
            // (Shift+C). The JAWS key map and NVDA add-on pass the
            // key through (it is SayCharacter / review territory by
            // default), so DbDo's handler wins in the data list.
            if (evArgs.KeyData == Keys.Clear)
            {
                saySayCell(this, EventArgs.Empty);
                evArgs.Handled = true;
                evArgs.SuppressKeyPress = true;
                return;
            }

            if (evArgs.KeyCode == Keys.Tab || evArgs.KeyCode == Keys.Right
                || evArgs.KeyCode == Keys.Left)
            {
                if (evArgs.Control || evArgs.Alt) return;
                int iColCount = (grid != null) ? grid.Columns.Count : 0;
                int iRowCount = (db != null && db.hasRecordset()) ? db.recordCount : 0;
                if (iColCount == 0 || iRowCount == 0) return;
                bool bBack = (evArgs.KeyCode == Keys.Left)
                    || (evArgs.KeyCode == Keys.Tab && evArgs.Shift);
                bool bCrossRows = (evArgs.KeyCode == Keys.Tab);
                int iNewCol = iVirtualCol + (bBack ? -1 : 1);
                int iNewRow = iVirtualRow;
                if (iNewCol < 0)
                {
                    if (!bCrossRows) { LiveRegion.say("First column"); iNewRow = -1; }
                    else if (iVirtualRow <= 1) { LiveRegion.say("First cell"); iNewRow = -1; }
                    else { iNewRow = iVirtualRow - 1; iNewCol = iColCount - 1; }
                }
                else if (iNewCol >= iColCount)
                {
                    if (!bCrossRows) { LiveRegion.say("Last column"); iNewRow = -1; }
                    else if (iVirtualRow >= iRowCount) { LiveRegion.say("Last cell"); iNewRow = -1; }
                    else { iNewRow = iVirtualRow + 1; iNewCol = 0; }
                }
                if (iNewRow > 0) virtMoveTo(iNewRow, iNewCol);
                evArgs.Handled = true;
                evArgs.SuppressKeyPress = true;
                return;
            }

            // Bare Shift+Letter shortcut family. Only these letters
            // are bound; any other Shift+Letter falls through to the
            // ListView, which feeds the character to its virtual-mode
            // SearchForVirtualItem for type-ahead navigation. The
            // corresponding menu items have ShortcutKeyDisplayString
            // set so the chord appears in the menu UI and JAWS
            // announces it; the dispatch happens here, not through
            // the form-level KeyMap.
            //
            // Shift+E and Shift+X are deliberately NOT bound -- the
            // Alt+RightArrow / Alt+LeftArrow chords for Enter-Child
            // and Exit-Child obviate the need for any Letter binding
            // on those commands, freeing the E and X slots for
            // future commands. Same reasoning for Shift+M / Shift+U:
            // Set-Mark / Clear-Mark live on Control+M / Control+U
            // for symmetric chord pairing, and the bare Letter slots
            // are reserved.
            if (evArgs.Shift && !evArgs.Control && !evArgs.Alt)
            {
                ToolStripMenuItem target = null;
                switch (evArgs.KeyCode)
                {
                    // Legacy dbDot Shift+Letter dispatch. As of v1.0.65
                    // most Shift+Letter chords are now bound directly to
                    // menu items as their ShortcutKeys (Say-X family),
                    // so the WinForms dispatch fires them and this
                    // parallel handler is no longer needed for those
                    // letters. We keep Shift+J (Jump-Record) for
                    // backward compatibility -- it has a parallel
                    // Control-chord binding (Ctrl+J) so the Shift+Letter
                    // form is the secondary chord. Shift+S → Sort-Object
                    // was dropped in v1.0.86 along with Sort-Object
                    // itself (universal Sort-Records replaced it).
                    case Keys.J: target = miRecJump;          break;
                }
                if (target != null)
                {
                    if (!target.Enabled)
                    {
                        string sCmd = target.Text.Replace("&", "");
                        if (sCmd.EndsWith("...")) sCmd = sCmd.Substring(0, sCmd.Length - 3).TrimEnd();
                        LiveRegion.say(sCmd + " is unavailable right now (open a database file or select a table first)");
                    }
                    else if (KeyMap.bKeyDescriber)
                    {
                        // Key Help mode: announce the (command,
                        // chord, summary) triple via the live region
                        // and SWALLOW the keystroke. Mirrors the
                        // KeyMap.tryDispatch behavior so the Shift+
                        // Letter family is describable too.
                        string sCmd = KeyMap.dMenuToCommand.ContainsKey(target)
                            ? KeyMap.dMenuToCommand[target]
                            : target.Text.Replace("&", "");
                        string sSummary = KeyMap.summaryFor(sCmd);
                        string sChord = "Shift+" + evArgs.KeyCode.ToString();
                        LiveRegion.say(sCmd + ". " + sChord + ". " + sSummary + ".");
                    }
                    else
                    {
                        target.PerformClick();
                    }
                    evArgs.Handled = true;
                    evArgs.SuppressKeyPress = true;
                    return;
                }
            }
        }

        // =====================================================================
        // VirtualCursor: cell-level navigation for screen-reader users.
        // Alt+Control+Home/End/arrows/Numpad5/PageUp/PageDown drive
        // the virtual cursor and announce the resulting cell.
        // =====================================================================

        // virtCurrentColumnName: returns the field-name string of
        // the column currently under virtual focus, or "" if there
        // is no usable column. Used as the default selection in
        // column-prompt LBC dialogs so the user can just press
        // Enter to accept their current virtual column.
        private string virtCurrentColumnName()
        {
            if (grid == null || grid.Columns.Count == 0) return "";
            int iCol = iVirtualCol;
            if (iCol < 0 || iCol >= grid.Columns.Count) iCol = 0;
            return grid.Columns[iCol].Text ?? "";
        }

        // virtCellValue: read the cell at (iRow, iCol) of the
        // currently-displayed recordset view. Returns "" on any
        // failure (out-of-range, type conversion error, COM
        // exception). iRow is 1-based to match ADO absolutePosition.
        private string virtCellValue(int iRow, int iCol)
        {
            if (db == null || !db.hasRecordset()) return "";
            if (grid == null || grid.Columns.Count == 0) return "";
            if (iCol < 0 || iCol >= grid.Columns.Count) return "";
            if (iRow < 1 || iRow > db.recordCount) return "";
            string sHeader = grid.Columns[iCol].Text;
            if (string.IsNullOrEmpty(sHeader)) return "";
            int iSavedPos = db.absolutePosition;
            try
            {
                if (iSavedPos != iRow) db.absolutePosition = iRow;
                return formatCellValue(db.getFieldValue(sHeader)) ?? "";
            }
            catch { return ""; }
        }

        // virtSyncListSelection: move the ListView's row selection
        // to the virtual row, so the user can see the row they are
        // virtually browsing. Suppresses the cell-changed handler's
        // spoken announcement (we'll do our own direction-aware one).
        private void virtSyncListSelection(int iRow)
        {
            if (grid == null) return;
            int iZero = iRow - 1; // ListView is 0-based
            if (iZero < 0 || iZero >= grid.VirtualListSize) return;
            bSuppressCellChanged = true;
            try
            {
                grid.SelectedIndices.Clear();
                grid.SelectedIndices.Add(iZero);
                grid.EnsureVisible(iZero);
                grid.FocusedItem = grid.Items[iZero];
                // Also reposition the ADO cursor so getFieldValue
                // in subsequent calls reads the right row.
                try { db.absolutePosition = iRow; } catch { }
            }
            finally { bSuppressCellChanged = false; }
        }

        // virtResetToTop: place the virtual cursor at row 1, column 0.
        // Called when F5 refreshes the view, or when the user explicitly
        // jumps to the top of the grid. Table-switch paths use
        // virtRestoreOrReset instead so the user returns to their last
        // visited cell.
        public void virtResetToTop()
        {
            iVirtualRow = (db != null && db.hasRecordset() && db.recordCount > 0) ? 1 : 0;
            iVirtualCol = (grid != null && grid.Columns.Count > 0) ? 0 : -1;
            iPrevVirtualRow = -1;
            iPrevVirtualCol = -1;
            // Sync the ListView selection silently. No announcement
            // here -- the table-opened or refresh path handles that
            // through its own message.
            if (iVirtualRow >= 1) virtSyncListSelection(iVirtualRow);
        }

        // virtRestoreOrReset: position the virtual cursor for a freshly-
        // opened table. If the manager has a remembered virtual column
        // for this table (from earlier in this session, or restored
        // from the ini by RecentFiles), we use that. Row is implied
        // by the recordset's current absolutePosition (which selectTable
        // already restored from the cache). Otherwise we fall back to
        // the row-1, column-0 behavior of virtResetToTop.
        public void virtRestoreOrReset()
        {
            if (db == null || !db.hasRecordset() || db.recordCount == 0)
            {
                virtResetToTop();
                return;
            }
            if (grid == null || grid.Columns.Count == 0)
            {
                virtResetToTop();
                return;
            }
            // Row: take from the recordset's current absolutePosition.
            // selectTable() already applied the cached row position
            // before we got here.
            int iRow = db.absolutePosition;
            if (iRow < 1) iRow = 1;
            if (iRow > db.recordCount) iRow = db.recordCount;

            // Column: resolve cached column NAME against the live
            // listview columns. Fall back to 0 if no cached name or
            // the name is not currently visible.
            int iCol = 0;
            string sCached = db.getVirtualColumn(db.currentTable);
            if (!string.IsNullOrEmpty(sCached))
            {
                for (int i = 0; i < grid.Columns.Count; i++)
                {
                    if (string.Equals(grid.Columns[i].Text, sCached,
                        StringComparison.OrdinalIgnoreCase))
                    { iCol = i; break; }
                }
            }
            iVirtualRow = iRow;
            iVirtualCol = iCol;
            iPrevVirtualRow = -1;
            iPrevVirtualCol = -1;
            if (iVirtualRow >= 1) virtSyncListSelection(iVirtualRow);
        }

        // virtSyncFromListSelection: keep the virtual ROW in lockstep
        // with the ListView's row selection when the user moves with
        // regular arrows / mouse / Find / Jump. Virtual COL stays put.
        // Called from gridSelectedIndexChanged.
        private void virtSyncFromListSelection()
        {
            if (grid == null || grid.SelectedIndices.Count == 0) return;
            int iNewRow = grid.SelectedIndices[0] + 1;
            if (iNewRow != iVirtualRow)
            {
                iPrevVirtualRow = iVirtualRow;
                iVirtualRow = iNewRow;
                // Column doesn't change in this path.
            }
        }

        // virtMoveTo: move the virtual cursor to (iRow, iCol) and
        // announce the resulting cell. Column header is spoken when
        // iCol differs from iPrevVirtualCol; row label is spoken
        // when iRow differs from iPrevVirtualRow. If both differ
        // (corner jumps from Home / End), both are spoken.
        private void virtMoveTo(int iRow, int iCol)
        {
            if (db == null || !db.hasRecordset() || db.recordCount == 0)
            {
                LiveRegion.say("No rows");
                return;
            }
            if (grid == null || grid.Columns.Count == 0)
            {
                LiveRegion.say("No columns");
                return;
            }
            // Clamp to valid range.
            if (iRow < 1) iRow = 1;
            if (iRow > db.recordCount) iRow = db.recordCount;
            if (iCol < 0) iCol = 0;
            if (iCol >= grid.Columns.Count) iCol = grid.Columns.Count - 1;

            iPrevVirtualRow = iVirtualRow;
            iPrevVirtualCol = iVirtualCol;
            iVirtualRow = iRow;
            iVirtualCol = iCol;

            // Persist the virtual column NAME (not index) into the
            // manager's per-table cache so a later table switch can
            // restore us to the same column. Indexes are not stable
            // across schema changes or column-visibility tweaks.
            if (db != null && grid != null && !string.IsNullOrEmpty(db.currentTable)
                && iCol >= 0 && iCol < grid.Columns.Count)
            {
                db.setVirtualColumn(db.currentTable, grid.Columns[iCol].Text);
            }

            bool bRowChanged = (iRow != iPrevVirtualRow);
            bool bColChanged = (iCol != iPrevVirtualCol);

            // Sync ListView row selection on any row change.
            if (bRowChanged) virtSyncListSelection(iRow);

            string sHeader = grid.Columns[iCol].Text;
            string sValue = speakableCellText(iRow, iCol);

            // Build the announcement per JAWS table-reading conventions:
            //   horizontal move (col changed only): header + value
            //   vertical move (row changed only):   row label + value
            //   corner jump (both changed):         row + header + value
            //   no change (refresh, Numpad5):       header + value
            // The "Row N" label is the bare row number; tables don't
            // have row headers per se. JAWS speaks the row index in
            // a similar context.
            string sSpoken;
            if (bRowChanged && bColChanged)
            {
                // Row-crossing column move (Tab wrap, corner jumps):
                // header first, then "row N", then the value -- the
                // same pattern as Say Cell, so every cell read leads
                // with its most distinguishing token.
                sSpoken = sHeader + " row " + iRow + ": " + sValue;
            }
            else if (bColChanged)
            {
                sSpoken = sHeader + ": " + sValue;
            }
            else if (bRowChanged)
            {
                sSpoken = "Row " + iRow + ": " + sValue;
            }
            else
            {
                // No change -- happens on Numpad5 single-press, or
                // when the user hits the same arrow at the edge.
                sSpoken = sHeader + ": " + sValue;
            }
            LiveRegion.say(sSpoken);
        }

        // virtSayCurrent: announce the current virtual cell. On a
        // second press within DoublePressMillis, spell the value
        // instead of saying it -- the
        // user gets verbatim on one press and character-by-character
        // on two presses. Triggered by Alt+Control+Numpad5.
        //
        // The chord identity is the Keys value of the key combo so
        // each speech-only chord has its own double-press timer.
        private void virtSayCurrent(int iChordKey)
        {
            string sHeader = (grid != null && iVirtualCol >= 0 && iVirtualCol < grid.Columns.Count)
                ? grid.Columns[iVirtualCol].Text : "";
            string sValue = speakableCellText(iVirtualRow, iVirtualCol);
            long iNow = DateTime.UtcNow.Ticks / TimeSpan.TicksPerMillisecond;
            bool bDouble = (iChordKey == iLastSpeechChord)
                        && (iNow - iLastSpeechTicks < DoublePressMillis);
            iLastSpeechChord = iChordKey;
            iLastSpeechTicks = iNow;
            if (bDouble)
            {
                // Spell the value: insert spaces between characters
                // so the screen reader pronounces each one separately.
                // No leading "Spelling: " word -- the spaced-out
                // characters are themselves a clear cue that this
                // is a spelling, and the prefix only adds noise.
                System.Text.StringBuilder sb = new System.Text.StringBuilder();
                foreach (char ch in sValue)
                {
                    if (sb.Length > 0) sb.Append(' ');
                    if (char.IsLetterOrDigit(ch)) sb.Append(ch);
                    else if (ch == ' ') sb.Append("space");
                    else sb.Append(ch);
                }
                LiveRegion.say(sb.ToString());
            }
            else
            {
                // Cell speech pattern (v1.0.108): header, the word
                // "row" with the row number, then the value -- the
                // header leads so a column-oriented ear hears the
                // most distinguishing token first.
                LiveRegion.say(sHeader + " row " + iVirtualRow + ": " + sValue);
            }
        }

        // speakOrShow: shared helper for the speech-only commands
        // (Say Status, Say Path, Say Yield, etc.). One press of the
        // chord speaks the text through the screen reader without
        // moving keyboard focus. A second press of the same chord
        // within DoublePressMillis opens a read-only LbcDialog with
        // the text in a multi-line TextBox and an OK button. This
        // lets the user review long text comfortably and copy from
        // it (the TextBox is read-only but supports clipboard
        // copy via Control+C).
        //
        // The chord identity is the iChordKey value the helper was
        // called from. Two callers using the same key collude into
        // each other's double-press count; pick distinct values per
        // command (the existing convention is the 101-108 range).
        private void speakOrShow(string sTitle, string sText, int iChordKey)
        {
            if (string.IsNullOrEmpty(sText)) return;
            long iNow = DateTime.UtcNow.Ticks / TimeSpan.TicksPerMillisecond;
            bool bDouble = (iChordKey == iLastSpeechChord)
                        && (iNow - iLastSpeechTicks < DoublePressMillis);
            iLastSpeechChord = iChordKey;
            iLastSpeechTicks = iNow;
            if (bDouble)
            {
                showInfoDialog(sTitle ?? "Information", sText);
            }
            else
            {
                LiveRegion.say(sText);
            }
        }

        // speakOrShowParts: the multi-unit form of speakOrShow. Single
        // press speaks each unit as its own queued message, so logical
        // units are heard with a natural pause between them; double
        // press shows them in the dialog, one unit per line. Empty
        // units are dropped so a missing piece adds neither a dead
        // pause nor a blank line. Shares the double-press timing state
        // with speakOrShow, so the two interoperate on the same chord.
        private void speakOrShowParts(string sTitle, List<string> lParts, int iChordKey)
        {
            if (lParts == null || lParts.Count == 0) return;
            List<string> lClean = new List<string>();
            foreach (string sPart in lParts)
                if (!string.IsNullOrEmpty(sPart)) lClean.Add(sPart);
            if (lClean.Count == 0) return;
            long iNow = DateTime.UtcNow.Ticks / TimeSpan.TicksPerMillisecond;
            bool bDouble = (iChordKey == iLastSpeechChord)
                        && (iNow - iLastSpeechTicks < DoublePressMillis);
            iLastSpeechChord = iChordKey;
            iLastSpeechTicks = iNow;
            if (bDouble)
                showInfoDialog(sTitle ?? "Information", string.Join("\r\n", lClean.ToArray()));
            else
                LiveRegion.sayParts(lClean);
        }

        // showInfoDialog: open an LbcDialog with a single multi-line
        // read-only TextBox containing sBody, plus an OK button. The
        // dialog steals focus until the user dismisses it with Enter
        // (OK) or Escape. Used as the double-press follow-through for
        // every speech-only command.
        private void showInfoDialog(string sTitle, string sBody)
        {
            try
            {
                using (LbcDialog dlg = new LbcDialog(sTitle ?? "Information", this))
                {
                    TextBox tb = dlg.addMemoBox("&Information:", sBody ?? "", null);
                    tb.ReadOnly = true;
                    // We do not need to capture an OK/Cancel result --
                    // either button just closes the dialog. runWithButtons
                    // returns the label; we ignore it.
                    dlg.runWithButtons(new string[] { "OK" });
                }
            }
            catch
            {
                // If the dialog fails for any reason, fall back to
                // speaking the text again so the user still gets some
                // confirmation.
                LiveRegion.say(sBody ?? "");
            }
        }

        private void buildStatusBar()
        {
            statusBar = new StatusStrip();
            // Left section: filter and sort indicators when active.
            // The filename and current-table name are now in the
            // window title, not the status bar.
            lblTable = new ToolStripStatusLabel("");
            lblTable.AccessibleName = "View state";
            lblTable.Spring = true;
            lblTable.TextAlign = ContentAlignment.MiddleLeft;

            // Right section: row position and marked status. Read
            // via the screen reader's "say status bar" hotkey
            // (JAWS Insert+PageDown, NVDA NVDA+End), or by Tab-
            // navigating to the status strip.
            lblStatus = new ToolStripStatusLabel("");
            lblStatus.AccessibleName = "Row position";
            lblStatus.Spring = true;
            lblStatus.TextAlign = ContentAlignment.MiddleRight;

            statusBar.Items.Add(lblTable);
            statusBar.Items.Add(lblStatus);
            this.Controls.Add(statusBar);
        }

        // =====================================================================
        // updateGrid: rebuild the ListView's columns from the current
        // recordset's field metadata, set the virtual size to the
        // recordset's row count, and position selection at the
        // current record. No full materialization -- row data is
        // pulled on demand by gridRetrieveVirtualItem as the
        // ListView scrolls. Suppresses the SelectedIndexChanged
        // event during the rebuild so we don't echo our own
        // programmatic position changes back to the recordset.
        // =====================================================================
        private void updateGrid()
        {
            bSuppressCellChanged = true;
            try
            {
                if (db == null || !db.isOpen() || !db.hasRecordset())
                {
                    grid.VirtualListSize = 0;
                    grid.Columns.Clear();
                    sLastGridTable = "";
                    updateStatusBar();
                    updateMenuEnabled();
                    return;
                }

                // Detect table change. When the user switches to a
                // different table, we want the JAWS "Unselected"
                // workaround to fire again -- the listview repaints
                // and JAWS reads the new state.
                string sCurTable = db.currentTable ?? "";
                if (!string.Equals(sCurTable, sLastGridTable, StringComparison.OrdinalIgnoreCase))
                {
                    bGridFirstPopulate = true;
                    sLastGridTable = sCurTable;
                }

                List<string> lFields = db.getDisplayFieldNames();

                // Rebuild columns only if the display-field set
                // changed (different table or schema change).
                // Rebuilding when not needed clears the user's
                // manual column widths, which is annoying.
                bool bColumnsMatch = (grid.Columns.Count == lFields.Count);
                if (bColumnsMatch)
                {
                    for (int i = 0; i < lFields.Count; i++)
                    {
                        if (!string.Equals(grid.Columns[i].Text, lFields[i],
                                StringComparison.Ordinal))
                        { bColumnsMatch = false; break; }
                    }
                }
                if (!bColumnsMatch)
                {
                    grid.Columns.Clear();
                    foreach (string sCol in lFields)
                    {
                        ColumnHeader oCh = new ColumnHeader();
                        oCh.Text = sCol;
                        oCh.Name = sCol;
                        oCh.Width = 150;
                        grid.Columns.Add(oCh);
                    }
                }

                int iCount = db.recordCount;
                grid.VirtualListSize = (iCount > 0) ? iCount : 0;
                // Db cursor invariant: a non-empty list always has
                // exactly one row carrying focus and selection.
                grid.ensureCursorRow();

                // Empty-list announcement: borrow from ObjectListView's
                // "Displays a 'list is empty' message" feature. The
                // standard ListView has no built-in empty-state UI,
                // so we announce it through the live region. Fires
                // only when the count is freshly zero (a table was
                // selected and turned out to have no rows), not on
                // every refresh.
                if (iCount == 0 && !bAnnouncedEmpty)
                {
                    bAnnouncedEmpty = true;
                    LiveRegion.say("Table has no rows");
                }
                else if (iCount > 0)
                {
                    bAnnouncedEmpty = false;
                }

                // Position selection at the recordset's current row.
                // If the recordset is somehow at BOF (absolutePosition
                // <= 0) but rows exist, fall back to row 1 -- the
                // ListView should ALWAYS have a selection when there
                // is at least one row, so the user always has a
                // meaningful "current" item to operate on.
                int iPos = db.absolutePosition; // 1-based
                if (iCount > 0 && (iPos < 1 || iPos > iCount))
                {
                    // Cursor not on a valid row but rows exist; move
                    // both the ADO cursor and the listview to row 1.
                    try { db.absolutePosition = 1; iPos = 1; }
                    catch { iPos = 1; }
                }
                if (iPos >= 1 && iPos <= iCount)
                {
                    int iIndex = iPos - 1;
                    try
                    {
                        grid.SelectedIndices.Clear();
                        if (iIndex >= 0 && iIndex < grid.VirtualListSize)
                        {
                            // Virtual ListView: SelectedIndices.Add
                            // is the API that actually persists the
                            // selection; grid.Items[i].Selected on a
                            // virtual item returns a placeholder and
                            // doesn't stick. FocusedItem is set after
                            // selection so the listview's UIA cursor
                            // is on the correct row.
                            grid.SelectedIndices.Add(iIndex);
                            grid.EnsureVisible(iIndex);
                            try { grid.FocusedItem = grid.Items[iIndex]; } catch { }
                            // Force the native selected/focused state so
                            // JAWS reads the row as selected rather than
                            // "Unselected" on first open and after every
                            // programmatic move.
                            grid.selectAndFocusNative(iIndex);
                        }
                    }
                    catch { }

                    // First-populate workaround: when the listview
                    // transitions from empty to non-empty (initial
                    // database open), JAWS may have already read the
                    // listview's prior empty state as "Unselected" and
                    // not re-announce when the selection lands. We
                    // explicitly announce the first row's content via
                    // LiveRegion so the user hears actual data rather
                    // than silence following "Unselected."
                    if (bGridFirstPopulate && iCount > 0)
                    {
                        bGridFirstPopulate = false;
                        try { DbDoLog.write("Grid first populate: row 1 of " + iCount + " selected with native focus/selection state forced."); } catch { }
                        try
                        {
                            string sFirstColValue = "";
                            if (grid.Columns.Count > 0)
                            {
                                string sHeader = grid.Columns[0].Text;
                                sFirstColValue = db.getFieldValue(sHeader) ?? "";
                            }
                            // Use a short announcement -- just the
                            // first column's value plus the row count
                            // -- so the user gets immediate context
                            // without a lengthy speech blob.
                            string sAnnounce = "Row 1 of " + iCount;
                            if (!string.IsNullOrEmpty(sFirstColValue))
                                sAnnounce = sFirstColValue + ", " + sAnnounce;
                            LiveRegion.say(sAnnounce);
                        }
                        catch { }
                    }
                }

                // No materialized data cache here; the ListView is
                // the single source of truth and pulls rows on
                // demand from the recordset via RetrieveVirtualItem.
            }
            finally
            {
                bSuppressCellChanged = false;
                updateStatusBar();
                updateMenuEnabled();
            }
        }

        // Legacy hook from when the field type was DataGridView.
        // Selection-changed routing now goes through
        // gridSelectedIndexChanged (registered in buildGrid). This
        // empty method is kept so old call sites that referenced it
        // by name still compile; can be removed once those are
        // migrated.
        private void gridCurrentCellChanged(object sender, EventArgs evArgs)
        {
            // no-op
        }

        private void updateStatusBar()
        {
            if (db == null || !db.isOpen())
            {
                this.Text = "(no database)";
                this.AccessibleName = this.Text;
                lblTable.Text = "";
                lblStatus.Text = "";
                return;
            }
            // Window title format:
            //   "DbDo - <database> [ (read-only) ] - <table> [ ReadOnly ]"
            // The program name is first so screen-reader title announcements
            // and Alt+Tab previews start with "DbDo". A USER-chosen read-only
            // safeguard (Alt+Z) sits by the database name. A result that ADO
            // and SQLite cannot update -- a multi-table or expression query,
            // or a view -- is flagged "ReadOnly" after the table name at the
            // far right, where editability of the shown data is most relevant.
            // A custom query that maps to no single base table reads as
            // "Custom" in place of a table name.
            // When a workbook (.xlsx) is open for editing, the live file
            // is a hidden working copy, so the title shows the workbook
            // the user actually opened and the sheet they are editing --
            // not the temp database. A leading "*" is the standard
            // modified marker (every editor uses it), so Alt+Tab and a
            // JAWS title read both convey unsaved state.
            bool bWorkbook = !string.IsNullOrEmpty(sWorkbookOriginPath);
            bool bWbDirty = bWorkbook && db.bDataModified;
            string sBaseName = bWorkbook
                ? Path.GetFileName(sWorkbookOriginPath)
                : Path.GetFileName(db.filePath);
            if (bWbDirty) sBaseName = "*" + sBaseName;
            string sTable = bWorkbook && !string.IsNullOrEmpty(sWorkbookSheetName)
                ? sWorkbookSheetName
                : (string.IsNullOrEmpty(db.currentTable) ? "(no table)"
                   : (db.currentIsCustomQuery ? "Custom" : db.currentTable));
            bool bForcedReadOnly = db.readOnlyInnate || db.currentIsView;
            string sToggleReadOnly = (db.readOnly && !bForcedReadOnly) ? " (read-only)" : "";
            string sForcedReadOnly = bForcedReadOnly ? " ReadOnly" : "";
            // Child title carries no "DbDo" prefix: the MDI parent
            // frame is already titled "DbDo", and a maximized child's
            // caption is merged by Windows into "DbDo - [child]".
            // Repeating it here made JAWS+T read "DbDo" twice. The
            // parent supplies the app name; the child supplies the
            // database and table. AccessibleName tracks the caption so
            // the two never diverge.
            this.Text = sBaseName + sToggleReadOnly + " - " + sTable + sForcedReadOnly;
            this.AccessibleName = this.Text;

            if (!db.hasRecordset())
            {
                lblTable.Text = "";
                lblStatus.Text = "";
                return;
            }

            // Left status: filter and sort indicators when active.
            string sFilter = string.IsNullOrEmpty(db.filter) ? "" : "filter: " + db.filter;
            string sSort = string.IsNullOrEmpty(db.sort) ? "" : "sort: " + db.sort;
            string sViewState = "";
            if (sFilter.Length > 0 && sSort.Length > 0) sViewState = sFilter + "  " + sSort;
            else if (sFilter.Length > 0) sViewState = sFilter;
            else if (sSort.Length > 0) sViewState = sSort;
            lblTable.Text = sViewState;

            // Right status. Order (user-specified): marked (only
            // when true), relative position, updated date.
            //
            //   marked     - the boolean 'marked' standard field;
            //                appears only when true so the user
            //                hears it as a noteworthy signal.
            //   row N of M - the row-of-total counter.
            //   edited     - the date portion of the 'edited'
            //                standard field (yyyy-MM-dd, no time).
            //
            // All three sections are separated by two spaces so the
            // screen reader pauses naturally between them when
            // reading the status bar.
            string sMarked = "";
            if (db.hasField(Metadata.MarkedColumn))
            {
                try
                {
                    string sVal = db.getFieldValue(Metadata.MarkedColumn) ?? "";
                    sVal = sVal.Trim().ToLowerInvariant();
                    bool bMarked = (sVal == "1" || sVal == "true" || sVal == "yes" || sVal == "-1");
                    if (bMarked) sMarked = "marked";
                }
                catch { }
            }

            string sEdited = "";
            if (db.hasField("edited"))
            {
                try
                {
                    string sRaw = db.getFieldValue("edited") ?? "";
                    if (sRaw.Length > 0)
                    {
                        DateTime dt;
                        if (DateTime.TryParse(sRaw, out dt))
                            sEdited = "edited " + dt.ToString("yyyy-MM-dd");
                        else
                        {
                            // Fall back to first 10 characters if
                            // the value is already in yyyy-MM-dd
                            // form but TryParse didn't accept it
                            // (e.g. unusual culture settings).
                            if (sRaw.Length >= 10) sEdited = "edited " + sRaw.Substring(0, 10);
                        }
                    }
                }
                catch { }
            }

            List<string> lParts = new List<string>();
            // Save-state first, so a screen-reader user querying the status
            // bar hears it immediately. Shown only while a workbook working
            // copy is open (a directly-opened .db is always already saved,
            // so the token would be noise). "saved" is shown explicitly,
            // not just "unsaved", so the user can confirm there is nothing
            // pending and need not press Save out of habit.
            if (bWorkbook) lParts.Add(bWbDirty ? "unsaved" : "saved");
            if (sMarked.Length > 0)  lParts.Add(sMarked);
            lParts.Add(string.Format("row {0} of {1}", db.absolutePosition, db.recordCount));
            if (sEdited.Length > 0) lParts.Add(sEdited);
            lblStatus.Text = string.Join("  ", lParts.ToArray());
        }

        private void updateMenuEnabled()
        {
            bool bOpen = db != null && db.isOpen();
            bool bHasTable = bOpen && db.hasRecordset();
            bool bWritable = bOpen && !db.readOnly;

            miFileSave.Enabled = bOpen;
            miFileSaveAs.Enabled = bOpen;
            miFileClose.Enabled = bOpen;
            miFileBackup.Enabled = bOpen;
            miFileCompare.Enabled = bOpen;
            miFileMerge.Enabled = bWritable;
            miFileExport.Enabled = bHasTable;
            miFilePrint.Enabled = bHasTable;

            miRecNew.Enabled = bWritable && bHasTable;
            miRecSet.Enabled = bWritable && bHasTable;
            if (miRecSetCell != null) miRecSetCell.Enabled = bWritable && bHasTable;
            miRecRemove.Enabled = bWritable && bHasTable;
            if (miEditNotes != null) miEditNotes.Enabled = bWritable && bHasTable;
            if (miEditTags != null) miEditTags.Enabled = bWritable && bHasTable;
            if (miEditUrl != null) miEditUrl.Enabled = bWritable && bHasTable;
            miRecShow.Enabled = bHasTable;
            miRecCopy.Enabled = bHasTable;
            miRecFind.Enabled = bHasTable;
            miRecFindPrev.Enabled = bHasTable && sLastFindSubstring.Length > 0;
            miRecJump.Enabled = bHasTable;
            miRecJumpPrev.Enabled = bHasTable && sLastJumpSubstring.Length > 0;
            miRecFindRegex.Enabled = bHasTable;
            miRecFindRegexPrev.Enabled = bHasTable && sLastFindRegex.Length > 0;
            // Search-Next / Search-Previous (F3 / Shift+F3) repeat
            // whichever search family was most recently invoked.
            // Enabled whenever any of the three families has state.
            bool bAnySearch = sLastJumpSubstring.Length > 0
                           || sLastFindSubstring.Length > 0
                           || sLastFindRegex.Length > 0;
            miRecSearchAgain.Enabled = bHasTable && bAnySearch;
            miRecSearchPrev.Enabled  = bHasTable && bAnySearch;
            miRecMark.Enabled = bWritable && bHasTable;
            if (miSaySayMark != null) miSaySayMark.Enabled = bHasTable;
            miRecUnmark.Enabled = bWritable && bHasTable;
            if (miRecMarkAnchor != null) miRecMarkAnchor.Enabled = bWritable && bHasTable;
            if (miRecMarkToAnchor != null) miRecMarkToAnchor.Enabled = bWritable && bHasTable;
            if (miRecUnmarkAnchor != null) miRecUnmarkAnchor.Enabled = bWritable && bHasTable;
            if (miRecUnmarkToAnchor != null) miRecUnmarkToAnchor.Enabled = bWritable && bHasTable;
            miRecUpdateColumn.Enabled = bWritable && bHasTable;
            if (miRecRegexReplace != null) miRecRegexReplace.Enabled = bWritable && bHasTable;
            miRecRelated.Enabled = bHasTable;
            miRecEnterChild.Enabled = bHasTable;
            // Exit-Child is enabled only on a window that Enter-Child
            // opened -- i.e. one with a live caller window to return to.
            miRecExitChild.Enabled = bHasTable && frmDrillCaller != null && !frmDrillCaller.IsDisposed;
            miRecExitChildToRoot.Enabled = bHasTable && frmDrillCaller != null && !frmDrillCaller.IsDisposed;
            miRecGoTo.Enabled = bHasTable;
            miRecBookmark.Enabled = bHasTable;
            miRecGotoBookmark.Enabled = bHasTable && lBookmarks.Count > 0;
            miRecClearBookmark.Enabled = lBookmarks.Count > 0;
            miRecOpenCell.Enabled = bHasTable;

            miViewSelect.Enabled = bHasTable;
            if (miViewFilterRegex != null) miViewFilterRegex.Enabled = bHasTable;
            miViewResetFilter.Enabled = bHasTable && db.filter.Length > 0;
            miViewResetSort.Enabled = bHasTable && db.sort.Length > 0;
            miViewUpdate.Enabled = bHasTable;
            // Order / Reverse Order: explicit enable so the listbox
            // dialog is reachable both via menu and chord whenever a
            // recordset is loaded.
            if (miOrderRecords != null) miOrderRecords.Enabled = bHasTable;
            if (miReverseOrder != null) miReverseOrder.Enabled = bHasTable;
            if (miFileOpenSelect != null) miFileOpenSelect.Enabled = bOpen;

            miSchemaSelectTable.Enabled = bOpen;
            miSchemaSelectView.Enabled = bOpen;
            miSchemaSwitch.Enabled = bOpen;
            miSchemaSwitchPrev.Enabled = bOpen;
            miSchemaSwitchAll.Enabled = bOpen;
            miSchemaSwitchAllPrev.Enabled = bOpen;
            miSchemaShow.Enabled = bOpen;

            miToolsTest.Enabled = bOpen;
            miToolsMeasure.Enabled = bHasTable;
            miToolsChart.Enabled = bHasTable;
            if (miDescribeColumn != null) miDescribeColumn.Enabled = bHasTable;
            if (miSelectColumns != null) miSelectColumns.Enabled = bHasTable;
            if (miPlotColumn != null) miPlotColumn.Enabled = bHasTable;
            miToolsInvokeSql.Enabled = bOpen;
            if (miToolsSqlHistory != null) miToolsSqlHistory.Enabled = bOpen;
            // miToolsOpenFolder and miToolsConsole are always enabled.
        }

        // =====================================================================
        // ProcessCmdKey: the universal keystroke dispatcher. Consults
        // KeyMap.dKeyToMenu to find a menu item to PerformClick(). This
        // bypasses ToolStripMenuItem.ShortcutKeys validation, so plain
        // Enter, Insert, Delete, Tab, Escape, Backspace, Alt+F4 are
        // all bindable.
        //
        // Special-cased keys that don't go through KeyMap because they
        // operate at the session level (no menu home) but should work
        // anywhere in the form, including from inside the data list:
        //   - Control+Tab        => cycle to next previously-opened table
        //   - Control+Shift+Tab  => cycle to previous previously-opened table
        //   - Control+Page Down  => same as Control+Tab
        //   - Control+Page Up    => same as Control+Shift+Tab
        //   - Control+Home       => first marked row
        //   - Control+End        => last marked row
        //   - Control+Up         => previous marked row
        //   - Control+Down       => next marked row
        //   - Shift+Home         => mark from first row through current
        //   - Shift+End          => mark from current row through last
        //   - Alt+Shift+Home     => unmark from first row through current
        //   - Alt+Shift+End      => unmark from current row through last
        //
        // The Control+ family for marked-row navigation matches
        // The convention for tagged-record nav. Our ListView is
        // MultiSelect=false with FullRowSelect=true, where the native
        // meanings of Control+Home/End/Up/Down are: in MultiSelect
        // off, Control+Home/End behave identically to Home/End
        // (Control is a no-op there), and Control+Up/Down move only
        // the focus rectangle without changing the selected row --
        // invisible to a screen reader since the selection didn't
        // change. So commandeering these chords doesn't conflict
        // with anything the user can observe. Shift+Home / Shift+End
        // similarly need MultiSelect=true to do anything natively,
        // and Alt+Shift+ chords have no native ListView meaning.
        //
        // Tables without a 'marked' column ignore mark-related
        // keystrokes with a brief live-region notice. Bulk-mark
        // chords also no-op cleanly when the database is read-only.
        //
        // Record stepping in the data list still uses the arrow keys (the
        // grid's native behavior); record-level next/previous does not
        // need a global hotkey.
        // =====================================================================
        protected override bool ProcessCmdKey(ref Message msg, Keys keyData)
        {
            // Key Describer mode intercepts EVERY key before any command
            // or grid navigation runs. A key bound to a command is
            // described (its command, chord, and summary) through
            // dispatchMenuItem; any other key (Home, an arrow, a plain
            // letter) is simply named so the user knows the describer is
            // active and that key carries no DbDo command. Either way the
            // key is swallowed, so nothing executes and the grid never
            // moves. The sole exception is the Key Describer toggle chord
            // itself: dispatchMenuItem runs it so the mode can be exited.
            // Bare modifier presses are ignored so real chords still form.
            if (KeyMap.bKeyDescriber)
            {
                Keys kCode = keyData & Keys.KeyCode;
                if (kCode != Keys.ControlKey && kCode != Keys.ShiftKey
                    && kCode != Keys.Menu && kCode != Keys.None)
                {
                    ToolStripMenuItem miDesc;
                    if (dLocalKeyToMenu.TryGetValue(keyData, out miDesc))
                        return KeyMap.dispatchMenuItem(miDesc, keyData);
                    LiveRegion.say(KeyMap.friendlyKey(keyData)
                        + ". No DbDo command is bound to this key.");
                    return true;
                }
            }

            // VirtualCursor chords (Alt+Control + Home/End/arrows/
            // Numpad5/PageDown/PageUp). These are the screen-reader
            // table-navigation conventions: Alt+Control+Home jumps to
            // top-left, End to bottom-right, arrows move one cell at
            // a time, Numpad5 announces the current cell (twice to
            // spell), PageDown/PageUp jump to the last/first row of
            // the current column. Per Jamal's spec, Alt+Control is
            // OK for these because the extended arrow / numpad keys
            // don't make sense as Windows global hotkeys, so the
            // usual "no Alt+Control for in-app commands" rule has
            // an exception for this navigation family.
            if (keyData == (Keys.Alt | Keys.Control | Keys.Home))
            { virtMoveTo(1, 0); return true; }
            if (keyData == (Keys.Alt | Keys.Control | Keys.End))
            {
                int iLastRow = (db != null && db.hasRecordset()) ? db.recordCount : 1;
                int iLastCol = (grid != null) ? grid.Columns.Count - 1 : 0;
                virtMoveTo(iLastRow, iLastCol);
                return true;
            }
            if (keyData == (Keys.Alt | Keys.Control | Keys.Right))
            { virtMoveTo(iVirtualRow, iVirtualCol + 1); return true; }
            if (keyData == (Keys.Alt | Keys.Control | Keys.Left))
            { virtMoveTo(iVirtualRow, iVirtualCol - 1); return true; }
            if (keyData == (Keys.Alt | Keys.Control | Keys.Down))
            { virtMoveTo(iVirtualRow + 1, iVirtualCol); return true; }
            if (keyData == (Keys.Alt | Keys.Control | Keys.Up))
            { virtMoveTo(iVirtualRow - 1, iVirtualCol); return true; }
            if (keyData == (Keys.Alt | Keys.Control | Keys.PageDown))
            {
                int iLastRow = (db != null && db.hasRecordset()) ? db.recordCount : 1;
                virtMoveTo(iLastRow, iVirtualCol);
                return true;
            }
            if (keyData == (Keys.Alt | Keys.Control | Keys.PageUp))
            { virtMoveTo(1, iVirtualCol); return true; }
            // Numpad5: in Windows the key generates Keys.Clear when
            // NumLock is off; the standard JAWS / NVDA convention
            // accepts both encodings. Some keyboards also surface
            // Numpad5 as Keys.NumPad5 when NumLock is on. Accept
            // either to cover both modes.
            if (keyData == (Keys.Alt | Keys.Control | Keys.Clear))
            { virtSayCurrent((int)keyData); return true; }
            if (keyData == (Keys.Alt | Keys.Control | Keys.NumPad5))
            { virtSayCurrent((int)keyData); return true; }

            // Control+PageDown / Control+PageUp (v1.0.110): move the
            // db cursor to the last / first row of the CURRENT
            // column -- the column-preserving vertical extremes,
            // standard chords for the Alt+Control+PageDown/PageUp
            // pair that remains for screen-reader-layer symmetry.
            // (These keys were previously aliases for the visited-
            // table ring, whose primary Alt+F6 / Alt+Shift+F6
            // bindings remain.)
            if (keyData == (Keys.Control | Keys.PageDown))
            {
                virtMoveTo((db != null && db.hasRecordset()) ? db.recordCount : 1, iVirtualCol);
                return true;
            }
            if (keyData == (Keys.Control | Keys.PageUp))
            {
                virtMoveTo(1, iVirtualCol);
                return true;
            }
            // Control+Home/End/Up/Down for marked-row navigation.
            // The tagged-record convention. The
            // formKeyDown handler is the primary intercept; this
            // ProcessCmdKey hook is a safety backstop because the
            // menu strip can sometimes consume modifier+key chords
            // during the routing dance.
            if (keyData == (Keys.Control | Keys.Home))
            {
                virtMoveTo(1, 0);
                return true;
            }
            if (keyData == (Keys.Control | Keys.End))
            {
                virtMoveTo((db != null && db.hasRecordset()) ? db.recordCount : 1,
                    (grid != null) ? grid.Columns.Count - 1 : 0);
                return true;
            }
            if (keyData == (Keys.Control | Keys.Shift | Keys.Home))
            {
                jumpToMarkedRow(MarkJump.First);
                return true;
            }
            if (keyData == (Keys.Control | Keys.Shift | Keys.End))
            {
                jumpToMarkedRow(MarkJump.Last);
                return true;
            }
            if (keyData == (Keys.Control | Keys.Up))
            {
                jumpToMarkedRow(MarkJump.Previous);
                return true;
            }
            if (keyData == (Keys.Control | Keys.Down))
            {
                jumpToMarkedRow(MarkJump.Next);
                return true;
            }

            // Bulk-mark span chords. Same backstop pattern as the
            // marked-nav block above.
            if (keyData == (Keys.Shift | Keys.Home))
            {
                bulkMark(BulkMark.MarkToStart);
                return true;
            }
            if (keyData == (Keys.Shift | Keys.End))
            {
                bulkMark(BulkMark.MarkToEnd);
                return true;
            }
            if (keyData == (Keys.Alt | Keys.Shift | Keys.Home))
            {
                bulkMark(BulkMark.UnmarkToStart);
                return true;
            }
            if (keyData == (Keys.Alt | Keys.Shift | Keys.End))
            {
                bulkMark(BulkMark.UnmarkToEnd);
                return true;
            }

            ToolStripMenuItem miLocal;
            if (dLocalKeyToMenu.TryGetValue(keyData, out miLocal))
            { KeyMap.dispatchMenuItem(miLocal, keyData); return true; }
            return base.ProcessCmdKey(ref msg, keyData);
        }

        // Mark-navigation directions. Used by jumpToMarkedRow to share
        // the precondition checks (table open, has marked column, has
        // any marked rows) across the four hotkey paths.
        private enum MarkJump { First, Last, Next, Previous }

        // Move the row pointer to a marked row in the requested
        // direction. Refuses gracefully (no exception, brief live-
        // region notice) when the table has no 'marked' column or no
        // rows are currently marked.
        private void jumpToMarkedRow(MarkJump jumpDir)
        {
            if (db == null || !db.hasRecordset()) return;
            if (!db.hasField(Metadata.MarkedColumn))
            {
                LiveRegion.say("This table has no marked column");
                return;
            }
            int iTarget = findMarkedRowPosition(jumpDir);
            if (iTarget <= 0)
            {
                LiveRegion.say("No marked rows");
                return;
            }
            try
            {
                db.absolutePosition = iTarget;
                invokeRefresh();
                LiveRegion.say("Marked row " + iTarget);
            }
            catch (Exception ex)
            {
                ErrorDialog.show(this, "Marked Row", ex.Message);
            }
        }

        // Walk the current recordset to find the next marked-row
        // position in the given direction. Returns 0 if no marked row
        // exists in that direction.
        //
        // The walk respects the recordset's current Filter and Sort,
        // because we step through ADO's view, not the underlying
        // table. So Control+Up after a Sort-Object sort moves to the
        // previous marked row IN SORTED ORDER, which matches user
        // intent.
        //
        // We save and restore the bookmark around the walk so the
        // pointer ends up exactly where we want it (at the target
        // row), with no flicker visible to the screen reader.
        private int findMarkedRowPosition(MarkJump jumpDir)
        {
            int iStart = db.absolutePosition;
            int iCount = db.recordCount;
            if (iCount <= 0) return 0;

            // Compute the iteration plan: where to start, what step,
            // when to stop.
            int iFrom, iStep, iEnd;
            switch (jumpDir)
            {
                case MarkJump.First:
                    iFrom = 1; iStep = 1; iEnd = iCount + 1; break;
                case MarkJump.Last:
                    iFrom = iCount; iStep = -1; iEnd = 0; break;
                case MarkJump.Next:
                    iFrom = iStart + 1; iStep = 1; iEnd = iCount + 1; break;
                case MarkJump.Previous:
                    iFrom = iStart - 1; iStep = -1; iEnd = 0; break;
                default:
                    return 0;
            }

            // Save the original position so we don't leave the cursor
            // somewhere unexpected if no marked row is found.
            object original = null;
            try { original = db.bookmark; } catch { }

            int iFound = 0;
            try
            {
                for (int i = iFrom; i != iEnd; i += iStep)
                {
                    if (i < 1 || i > iCount) continue;
                    db.absolutePosition = i;
                    string sValue = db.getFieldValue(Metadata.MarkedColumn);
                    if (isMarkedTrue(sValue))
                    {
                        iFound = i;
                        break;
                    }
                }
            }
            catch { /* fall through; restore happens below */ }

            // Restore the original position if we didn't find a target.
            if (iFound == 0 && original != null)
            {
                try { db.bookmark = original; } catch { }
            }
            return iFound;
        }

        // containsIgnoreCase: ordinal case-insensitive membership
        // test. List<T>.Contains takes no comparer and System.Linq's
        // comparer overload isn't imported, so this stands in.
        private static bool containsIgnoreCase(IEnumerable<string> lsList, string sValue)
        {
            if (lsList == null) return false;
            foreach (string sItem in lsList)
                if (string.Equals(sItem, sValue, StringComparison.OrdinalIgnoreCase)) return true;
            return false;
        }

        // The 'marked' column's truthy values across the database
        // engines DbDo speaks: SQLite stores it as integer 0/1,
        // Jet/ACE as BIT True/False. ADO normalizes BIT to "True"/
        // "False" string when read through the dynamic late-bound
        // path. Normalize all of these to a single boolean.
        private static bool isMarkedTrue(string sValue)
        {
            if (string.IsNullOrEmpty(sValue)) return false;
            sValue = sValue.Trim();
            if (sValue == "1") return true;
            if (string.Equals(sValue, "True", StringComparison.OrdinalIgnoreCase)) return true;
            if (string.Equals(sValue, "Yes",  StringComparison.OrdinalIgnoreCase)) return true;
            return false;
        }

        // Bulk-mark span directions. MarkToStart/MarkToEnd set the
        // 'marked' column TRUE on every row from the first up to
        // and including the current (MarkToStart), or from the
        // current to the last (MarkToEnd). UnmarkToStart and
        // UnmarkToEnd do the same in reverse, setting marked FALSE.
        //
        // The chord family follows the tagged-record convention:
        // Shift+Home to tag from start, Shift+End to tag to end,
        // Alt+Shift+Home / Alt+Shift+End to untag the same spans.
        private enum BulkMark { MarkToStart, MarkToEnd, UnmarkToStart, UnmarkToEnd }

        // Apply a bulk-marking operation across a contiguous span
        // of the current filtered/sorted view. The span is anchored
        // at the current row. Rows are walked in ADO order (the
        // recordset's current Filter and Sort apply), so the span
        // makes sense in the user's current arrangement.
        //
        // The cursor returns to the row it started on. Speaks a
        // brief live-region summary ("Marked 14 rows", etc.) so the
        // screen reader confirms the operation.
        private void bulkMark(BulkMark jumpDir)
        {
            if (db == null || !db.hasRecordset()) return;
            if (!db.hasField(Metadata.MarkedColumn))
            {
                LiveRegion.say("This table has no marked column");
                return;
            }
            if (db.readOnly)
            {
                LiveRegion.say("Database is read-only");
                return;
            }

            int iStart = db.absolutePosition;
            int iCount = db.recordCount;
            if (iCount <= 0 || iStart < 1) return;

            int iFrom, iTo;
            bool bMark;
            string sVerb;
            switch (jumpDir)
            {
                case BulkMark.MarkToStart:
                    iFrom = 1; iTo = iStart; bMark = true; sVerb = "Marked"; break;
                case BulkMark.MarkToEnd:
                    iFrom = iStart; iTo = iCount; bMark = true; sVerb = "Marked"; break;
                case BulkMark.UnmarkToStart:
                    iFrom = 1; iTo = iStart; bMark = false; sVerb = "Unmarked"; break;
                case BulkMark.UnmarkToEnd:
                    iFrom = iStart; iTo = iCount; bMark = false; sVerb = "Unmarked"; break;
                default:
                    return;
            }

            object original = null;
            try { original = db.bookmark; } catch { }
            int iChanged = 0;
            int iSkipped = 0;
            try
            {
                for (int i = iFrom; i <= iTo; i++)
                {
                    try
                    {
                        db.absolutePosition = i;
                        string sValue = db.getFieldValue(Metadata.MarkedColumn);
                        bool bCurrent = isMarkedTrue(sValue);
                        if (bCurrent == bMark) { iSkipped++; continue; }
                        db.setFieldValue(Metadata.MarkedColumn, bMark ? "true" : "false");
                        db.update();
                        iChanged++;
                    }
                    catch
                    {
                        // Per-row errors don't stop the run; the user
                        // gets a count of what succeeded at the end.
                        iSkipped++;
                    }
                }
            }
            finally
            {
                if (original != null)
                {
                    try { db.bookmark = original; } catch { }
                }
            }
            invokeRefresh();
            string sMsg = sVerb + " " + iChanged + " row"
                        + (iChanged == 1 ? "" : "s")
                        + (iSkipped > 0 ? "; " + iSkipped + " already in that state" : "");
            LiveRegion.say(sMsg);
            DbDoLog.write("BulkMark " + jumpDir + ": " + sMsg);
        }

        // markAndMove: set or clear the 'marked' column on the
        // current row, then move the cursor to the next or previous
        // row. The tag-and-next pattern lets the user walk
        // a list and decide row by row whether to mark it, with the
        // focus advancing automatically after each decision. The
        // screen reader announces the new row as the ListView's
        // focused item changes -- no extra speech from DbDo is
        // needed for the move itself.
        //
        // Bound to:
        //   >                  (Shift+OemPeriod) = Mark and next
        //   <                  (Shift+Oemcomma) = Unmark and next
        //   Shift+DownArrow                       = Mark and next
        //   Shift+UpArrow                         = Mark and previous
        //   Alt+Shift+DownArrow                   = Unmark and next
        //   Alt+Shift+UpArrow                     = Unmark and previous
        //
        // If the current row is already in the requested state, the
        // marked column is left untouched (no needless UPDATE).
        // Movement still happens. At the end of the recordset, the
        // cursor stays put rather than walking off into BOF/EOF.
        private void markAndMove(bool bMark, bool bForward)
        {
            if (db == null || !db.hasRecordset()) return;
            if (db.recordCount <= 0) return;
            if (!db.hasField(Metadata.MarkedColumn))
            {
                LiveRegion.say("This table has no marked column");
                return;
            }
            if (db.readOnly)
            {
                LiveRegion.say("Database is read-only");
                return;
            }
            try
            {
                string sValue = db.getFieldValue(Metadata.MarkedColumn);
                bool bCurrent = isMarkedTrue(sValue);
                if (bCurrent != bMark)
                {
                    db.setFieldValue(Metadata.MarkedColumn, bMark ? "true" : "false");
                    db.update();
                }
            }
            catch (Exception ex)
            {
                LiveRegion.say("Mark error: " + ex.Message);
                return;
            }
            // Move cursor one row in the requested direction; stay
            // put at the boundaries so the screen reader doesn't
            // announce an out-of-range condition.
            int iPos = db.absolutePosition;
            int iCount = db.recordCount;
            if (bForward && iPos < iCount) iPos++;
            else if (!bForward && iPos > 1) iPos--;
            try { db.absolutePosition = iPos; } catch { }
            invokeRefresh();
        }

        // markAll: set or clear the 'marked' column on every row in
        // the current filtered view. Control+A / Control+
        // Shift+A pattern: select all / clear all. We keep the
        // cursor position via bookmark across the bulk update.
        private void markAll(bool bMark)
        {
            if (db == null || !db.hasRecordset()) return;
            if (!db.hasField(Metadata.MarkedColumn))
            {
                LiveRegion.say("This table has no marked column");
                return;
            }
            if (db.readOnly)
            {
                LiveRegion.say("Database is read-only");
                return;
            }
            int iCount = db.recordCount;
            if (iCount <= 0) return;

            object original = null;
            try { original = db.bookmark; } catch { }
            int iChanged = 0;
            int iSkipped = 0;
            try
            {
                for (int i = 1; i <= iCount; i++)
                {
                    try
                    {
                        db.absolutePosition = i;
                        bool bCurrent = isMarkedTrue(db.getFieldValue(Metadata.MarkedColumn));
                        if (bCurrent == bMark) { iSkipped++; continue; }
                        db.setFieldValue(Metadata.MarkedColumn, bMark ? "true" : "false");
                        db.update();
                        iChanged++;
                    }
                    catch { iSkipped++; }
                }
            }
            finally
            {
                if (original != null) try { db.bookmark = original; } catch { }
            }
            invokeRefresh();
            string sVerb = bMark ? "Marked" : "Unmarked";
            string sMsg = sVerb + " " + iChanged + " row" + (iChanged == 1 ? "" : "s")
                        + (iSkipped > 0 ? "; " + iSkipped + " already in that state" : "");
            LiveRegion.say(sMsg);
            DbDoLog.write("MarkAll " + bMark + ": " + sMsg);
        }

        // invertMarks: flip the marked-state of every row in the
        // current filtered view.
        // Useful for "give me everything I didn't already pick."
        // Cursor preserved by bookmark.
        private void invertMarks()
        {
            if (db == null || !db.hasRecordset()) return;
            if (!db.hasField(Metadata.MarkedColumn))
            {
                LiveRegion.say("This table has no marked column");
                return;
            }
            if (db.readOnly)
            {
                LiveRegion.say("Database is read-only");
                return;
            }
            int iCount = db.recordCount;
            if (iCount <= 0) return;

            object original = null;
            try { original = db.bookmark; } catch { }
            int iFlipped = 0;
            try
            {
                for (int i = 1; i <= iCount; i++)
                {
                    try
                    {
                        db.absolutePosition = i;
                        bool bCurrent = isMarkedTrue(db.getFieldValue(Metadata.MarkedColumn));
                        db.setFieldValue(Metadata.MarkedColumn, bCurrent ? "false" : "true");
                        db.update();
                        iFlipped++;
                    }
                    catch { /* skip row */ }
                }
            }
            finally
            {
                if (original != null) try { db.bookmark = original; } catch { }
            }
            invokeRefresh();
            string sMsg = "Inverted marks on " + iFlipped + " row"
                        + (iFlipped == 1 ? "" : "s");
            LiveRegion.say(sMsg);
            DbDoLog.write("InvertMarks: " + sMsg);
        }

        // sayWhere: Show-Where -- read out the title bar, the
        // status bar, and the current row's displayed columns.
        // Bound to ? (Shift+Slash) from the data list.
        //
        // The "where am I" question is one screen-reader users hit
        // constantly. JAWS has Insert+T for title, Insert+PageDown
        // for status bar, and various row-readers, but they're
        // three separate gestures and the result is announced in
        // the screen reader's own voice and order. A single chord
        // that DbDo composes itself gives the user a consistent
        // summary in DbDo's own LiveRegion path -- title, then
        // status, then per-column values for the current row,
        // separated by " | " so JAWS' pause-on-punctuation pacing
        // is natural.
        //
        // Only displayed columns are included (Select-Column's
        // user override, or DbDo's default visible columns); the
        // primary key and bookkeeping fields are not. To inspect
        // every column, including hidden ones, use Show-Object
        // (Enter) instead.
        private void sayWhere()
        {
            StringBuilder sb = new StringBuilder();
            string sTitle = this.Text ?? "";
            if (sTitle.Length > 0) sb.Append(sTitle);

            // Both status labels, joined with a space if both have
            // text. If either is empty we skip it cleanly.
            string sStatusLeft = (lblTable != null) ? (lblTable.Text ?? "") : "";
            string sStatusRight = (lblStatus != null) ? (lblStatus.Text ?? "") : "";
            string sStatus = (sStatusLeft + " " + sStatusRight).Trim();
            if (sStatus.Length > 0)
            {
                if (sb.Length > 0) sb.Append(" | ");
                sb.Append(sStatus);
            }

            // Current row's displayed columns. If no recordset is
            // open or the recordset is empty, this section is
            // simply omitted.
            if (db != null && db.hasRecordset() && db.recordCount > 0)
            {
                try
                {
                    List<string> lCols = db.getDisplayFieldNames();
                    foreach (string sCol in lCols)
                    {
                        string sV = db.getFieldValue(sCol);
                        if (sV == null) sV = "";
                        if (sb.Length > 0) sb.Append(" | ");
                        sb.Append(sCol);
                        sb.Append(": ");
                        sb.Append(sV);
                    }
                }
                catch { /* speak what we have */ }
            }

            string sMsg = sb.ToString();
            if (sMsg.Length == 0) sMsg = "DbDo, no database open";
            LiveRegion.say(sMsg);
        }

        // =======================================================================
        // Speech-only commands. Each builds a string from current state
        // and pushes it through LiveRegion.say() without changing focus,
        // selection, recordset position, or any other state. Modeled on
        // The "Say X" status family (Say-Date, Say-Path, Say-Size, etc.)
        // and an Alt+Letter status-query family (Address, Block,
        // Path, Yield, Status). Live in the Query menu by convention.
        // =======================================================================

        // saySayStatus: Shift+Z. Speak status info, leading with the
        // marked state when the current record is marked (so the user
        // hears "Marked" first if it applies, before the other status
        // details). Z is the conventional exception letter for "ZZZ /
        // bottom of the UI" status-bar commands.
        //
        // Output format:
        //   "Marked. <table> row N of M; filter: ...; sort: ..."
        //   "<table> row N of M; filter: ...; sort: ..."   (unmarked)
        //
        // The screen reader user can interrupt at any point with their
        // reader's silence key, so even verbose status is fine.
        private void saySayStatus(object sender, EventArgs evArgs)
        {
            if (db == null || !db.isOpen())
            { LiveRegion.say("No database open"); return; }
            if (!db.hasRecordset())
            { speakOrShow("Status", db.filePath ?? "Database open, no table selected", 101); return; }
            StringBuilder sb = new StringBuilder();
            // Marked state at the front so the user hears it first.
            // Only announce when true (matching the status bar
            // convention of showing 'marked' only when set).
            if (db.hasField(Metadata.MarkedColumn))
            {
                try
                {
                    string sM = db.getFieldValue(Metadata.MarkedColumn) ?? "";
                    if (isMarkedTrue(sM)) sb.Append("Marked. ");
                }
                catch { }
            }
            sb.Append(db.currentTable ?? "(no table)");
            sb.Append(" row ").Append(db.absolutePosition).Append(" of ").Append(db.recordCount);
            if (db.filter.Length > 0) sb.Append("; filter: ").Append(db.filter);
            if (db.sort.Length > 0) sb.Append("; sort: ").Append(db.sort);
            speakOrShow("Status", sb.ToString(), 101);
        }

        // saySayDatabase: Shift+D. Speak the database name (single-
        // press) or full path (double-press). Replaces Say Path on
        // Shift+P. The name-then-path pattern follows speakOrShow's
        // toggleable single-tap / double-tap convention.
        private void saySayDatabase(object sender, EventArgs evArgs)
        {
            if (db == null || !db.isOpen())
            { LiveRegion.say("No database open"); return; }
            string sPath = db.filePath ?? "(unknown)";
            string sName = Path.GetFileName(sPath);
            // Single-press: name only. Double-press: full path
            // (speakOrShow's standard memo dialog handles this).
            speakOrShow("Database", sName + " -- full path: " + sPath, 124);
        }

        // saySayOrder: Shift+O. Speak the active sort/order
        // expression. Counterpart to Say Where Filter (Shift+W).
        private void saySayOrder(object sender, EventArgs evArgs)
        {
            if (db == null || !db.isOpen())
            { LiveRegion.say("No database open"); return; }
            if (!db.hasRecordset())
            { LiveRegion.say("No table selected"); return; }
            string s = db.sort ?? "";
            if (s.Length == 0)
            { LiveRegion.say("No order applied"); return; }
            speakOrShow("Order", "order: " + s, 125);
        }

        // saySayGoto: Shift+G. Speak the most recently used Jump
        // Record search string (the substring used by Ctrl+J to
        // navigate within a column). Companion to Say Filter and Say
        // Order; reveals the current state of the column-substring
        // search target. Reports a clear no-state message when the
        // user has not yet performed a Jump.
        private void saySayGoto(object sender, EventArgs evArgs)
        {
            if (string.IsNullOrEmpty(sLastJumpSubstring))
            { LiveRegion.say("No jump search active"); return; }
            string sCol = string.IsNullOrEmpty(sLastJumpColumn) ? "(any column)" : sLastJumpColumn;
            speakOrShow("Goto", sCol + ": \"" + sLastJumpSubstring + "\"", 127);
        }

        // saySayPath: Shift+P retired in v1.0.99 (replaced by Say
        // Database on Shift+D, which gives both the name and the
        // path via the single-press / double-press dialog
        // convention). The handler remains for callers who may
        // reference it, but the chord and menu item are gone.
        private void saySayPath(object sender, EventArgs evArgs)
        {
            saySayDatabase(sender, evArgs);
        }

        // saySayYield: Alt+Y. Speak the record count and any active
        // filter. Alt+Y = "Yield" (record count).
        // Alt+Y = "Yield Files" (file count).
        private void saySayYield(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset())
            { LiveRegion.say("No table selected"); return; }
            StringBuilder sb = new StringBuilder();
            sb.Append(db.recordCount).Append(" row").Append(db.recordCount == 1 ? "" : "s");
            if (db.filter.Length > 0) sb.Append(" (filter: ").Append(db.filter).Append(")");
            speakOrShow("Yield", sb.ToString(), 103);
        }

        // saySayTables: Shift+F4. Speak the names of tables that
        // have been opened in this DbDo session. Shift+F4 =
        // "Say Windows Open." Speech-only -- does NOT open a picker.
        // The picker (Select-Table) is F4 (Current Windows
        // convention. Shift+F4 is the "tell me without changing
        // anything" variant.
        private void saySayTables(object sender, EventArgs evArgs)
        {
            if (db == null || !db.isOpen())
            { LiveRegion.say("No database open"); return; }
            List<string> lTables = db.visitedTableNames();
            if (lTables == null || lTables.Count == 0)
            { LiveRegion.say("No tables visited yet in this session"); return; }
            StringBuilder sb = new StringBuilder();
            sb.Append(lTables.Count).Append(" table").Append(lTables.Count == 1 ? "" : "s").Append(": ");
            for (int i = 0; i < lTables.Count; i++)
            {
                if (i > 0) sb.Append(", ");
                sb.Append(lTables[i]);
            }
            speakOrShow("Visited Tables", sb.ToString(), 104);
        }

        // saySayMark (Shift+M): speak the current record's mark
        // status, "Marked" or "Unmarked" -- the say half of the M
        // mark family (Control+M marks, Control+Shift+M unmarks).
        private void saySayMark(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset() || db.recordCount == 0)
            { LiveRegion.say("No record selected"); return; }
            if (!db.hasField(Metadata.MarkedColumn))
            { LiveRegion.say("This table has no marked column"); return; }
            bool bMarked;
            try { bMarked = isMarkedTrue(db.getFieldValue(Metadata.MarkedColumn) ?? ""); }
            catch { bMarked = false; }
            LiveRegion.sayForced(bMarked ? "Marked" : "Unmarked");
        }

        // saySayMarked: Shift+L. Speak the look-column values of every
        // row whose 'marked' column is true. Shift+L =
        // "List Tagged." Limited to the first 25 marked rows with a
        // "(plus N more)" footer if the list is longer, to keep the
        // announcement tractable.
        private void saySayMarked(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset())
            { LiveRegion.say("No table selected"); return; }
            if (!db.hasField(Metadata.MarkedColumn))
            { LiveRegion.say("This table has no marked column"); return; }

            object original = null;
            try { original = db.bookmark; } catch { }
            // No cap: every marked row's look value is spoken;
            // JAWS queues them and the user presses Control to stop.
            List<string> lLooks = new List<string>();
            int iTotal = 0;
            try
            {
                for (int i = 1; i <= db.recordCount; i++)
                {
                    try
                    {
                        db.absolutePosition = i;
                        if (!isMarkedTrue(db.getFieldValue(Metadata.MarkedColumn))) continue;
                        iTotal++;
                        string sLook = db.getFieldValue("look");
                        if (string.IsNullOrEmpty(sLook)) sLook = "row " + i;
                        lLooks.Add(sLook);
                    }
                    catch { }
                }
            }
            finally
            {
                if (original != null) try { db.bookmark = original; } catch { }
            }
            if (iTotal == 0)
            { LiveRegion.say("No marked rows"); return; }
            StringBuilder sb = new StringBuilder();
            sb.Append(iTotal).Append(" marked row").Append(iTotal == 1 ? "" : "s").Append(": ");
            for (int i = 0; i < lLooks.Count; i++)
            {
                if (i > 0) sb.Append("; ");
                sb.Append(lLooks[i]);
            }
            if (iTotal > lLooks.Count)
                sb.Append("; plus ").Append(iTotal - lLooks.Count).Append(" more");
            speakOrShow("Marked Rows", sb.ToString(), 105);
        }

        // saySayEdited: Shift+E. Speak the 'edited' value of the
        // current row in a human-friendly local-time form. The
        // underlying SQLite text (e.g., "2026-05-15 13:42:00") is
        // never modified -- this only affects speech output.
        //
        // Format rules:
        //   - date only       -> "April 15, 2020"
        //   - date + time     -> "April 15, 2020 at 5:42 AM"
        //   - seconds dropped from any time portion
        //   - non-date string -> spoken verbatim as a fallback
        //
        // If the table has no 'edited' column we fall back to
        // 'added' (the other standard date column).
        private void saySayEdited(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset() || db.recordCount == 0)
            { LiveRegion.say("No record selected"); return; }
            string sCol = db.hasField("edited") ? "edited" : (db.hasField("added") ? "added" : null);
            if (sCol == null)
            { LiveRegion.say("No date column in this table"); return; }
            string sVal = db.getFieldValue(sCol);
            string sSpoken = formatDateHumanFriendly(sVal);
            if (string.IsNullOrEmpty(sSpoken)) sSpoken = "blank";
            speakOrShow("Edited", sCol + ": " + sSpoken, 106);
        }

        // formatDateHumanFriendly: parse the SQLite-text date / datetime
        // and re-render it in a long, screen-reader-friendly form using
        // the user's local time zone and culture preferences. Returns
        // the input verbatim if it doesn't parse as a date.
        private static string formatDateHumanFriendly(string sRaw)
        {
            if (string.IsNullOrEmpty(sRaw)) return "";
            DateTime dt;
            if (!DateTime.TryParse(sRaw, System.Globalization.CultureInfo.CurrentCulture,
                System.Globalization.DateTimeStyles.AssumeLocal, out dt))
            {
                // Fall back to invariant culture for ISO-like "2026-05-15"
                if (!DateTime.TryParse(sRaw, System.Globalization.CultureInfo.InvariantCulture,
                    System.Globalization.DateTimeStyles.AssumeLocal, out dt))
                {
                    return sRaw;
                }
            }
            // Render in local time. DateTime.TryParse returns Local
            // kind when AssumeLocal is requested.
            DateTime dtLocal = (dt.Kind == DateTimeKind.Utc) ? dt.ToLocalTime() : dt;
            // Distinguish "date only" from "date plus time" by checking
            // whether the input string contains anything beyond the
            // date portion. SQLite text format is typically
            // "yyyy-MM-dd" or "yyyy-MM-dd HH:mm[:ss]".
            bool bHasTime = sRaw.IndexOf(':') >= 0;
            string sLongDate = dtLocal.ToString("MMMM d, yyyy",
                System.Globalization.CultureInfo.CurrentCulture);
            if (!bHasTime) return sLongDate;
            // Time portion: short time (no seconds), local culture.
            string sShortTime = dtLocal.ToString("h:mm tt",
                System.Globalization.CultureInfo.CurrentCulture);
            return sLongDate + " at " + sShortTime;
        }

        // saySayYieldMarked: Shift+Y. Speak the count of marked rows.
        // Shift+Y = "Yield Tagged."
        private void saySayYieldMarked(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset())
            { LiveRegion.say("No table selected"); return; }
            if (!db.hasField(Metadata.MarkedColumn))
            { LiveRegion.say("This table has no marked column"); return; }
            object original = null;
            try { original = db.bookmark; } catch { }
            int iCount = 0;
            try
            {
                for (int i = 1; i <= db.recordCount; i++)
                {
                    try
                    {
                        db.absolutePosition = i;
                        if (isMarkedTrue(db.getFieldValue(Metadata.MarkedColumn))) iCount++;
                    }
                    catch { }
                }
            }
            finally
            {
                if (original != null) try { db.bookmark = original; } catch { }
            }
            speakOrShow("Marked Yield", iCount + " marked row" + (iCount == 1 ? "" : "s"), 108);
        }

        // saySayNotes: Shift+N. Speak the 'notes' field of the current
        // row. If the table has no 'notes' column, say so. Long notes
        // can be reviewed with a second press (LbcDialog with a
        // multi-line TextBox), which is helpful for notes that
        // overflow what the screen reader speaks comfortably.
        private void saySayNotes(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset() || db.recordCount == 0)
            { LiveRegion.say("No record selected"); return; }
            if (!db.hasField("notes"))
            { LiveRegion.say("This table has no notes column"); return; }
            string sVal = db.getFieldValue("notes");
            if (string.IsNullOrEmpty(sVal)) sVal = "blank";
            speakOrShow("Notes", "notes: " + sVal, 109);
        }

        // saySayTags: Shift+T. Speak the 'tags' field of the current
        // row. If the table has no 'tags' column, say so.
        private void saySayTags(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset() || db.recordCount == 0)
            { LiveRegion.say("No record selected"); return; }
            if (!db.hasField("tags"))
            { LiveRegion.say("This table has no tags column"); return; }
            string sVal = db.getFieldValue("tags");
            if (string.IsNullOrEmpty(sVal)) sVal = "blank";
            speakOrShow("Tags", "tags: " + sVal, 110);
        }

        // --- v1.0.67 Say-X family completions ---
        // saySayAdded: Shift+A. Speak the 'added' timestamp of the
        // current row in the same human-friendly local-time form as
        // Say Edited (Shift+E) -- "April 15, 2026 at 5:42 PM" -- via
        // the shared formatDateHumanFriendly helper. The stored
        // SQLite text is never modified; this only affects speech.
        private void saySayAdded(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset() || db.recordCount == 0)
            { LiveRegion.say("No record selected"); return; }
            if (!db.hasField("added"))
            { LiveRegion.say("This table has no added column"); return; }
            string sVal = db.getFieldValue("added");
            string sSpoken = formatDateHumanFriendly(sVal);
            if (string.IsNullOrEmpty(sSpoken)) sSpoken = "blank";
            speakOrShow("Added", "added: " + sSpoken, 116);
        }

        // saySayCell: speak the value of the cell under the virtual
        // cursor -- the SAME (row, column) pair that Tab, Shift+Tab,
        // and the Alt+Control chords announce, read through the same
        // virtCellValue path. This is the synchronization guarantee:
        // Shift+C always repeats the cell the user last heard.
        private void saySayCell(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset() || db.recordCount == 0)
            { LiveRegion.say("No record selected"); return; }
            string sCol = virtCurrentColumnName();
            if (string.IsNullOrEmpty(sCol)) { LiveRegion.say("No virtual column at cursor"); return; }
            string sVal = virtCellValue(iVirtualRow, iVirtualCol);
            if (string.IsNullOrEmpty(sVal)) sVal = "blank";
            // Cell speech pattern: the column header, the word "row"
            // with the row number, then the value -- each its own
            // queued message so they are heard with a natural pause
            // between them rather than as one run-on string.
            speakOrShowParts("Cell",
                new List<string> { sCol, "row " + iVirtualRow, sVal }, 117);
        }

        // saySayFilter: speak the active ADO filter expression. Empty
        // string means "no filter is active."
        // saySaySelect (Shift+S): speak the columns currently shown
        // in the data list -- the selection made with Select Columns
        // (Alt+S) -- the column counterpart of Say Order (Shift+O)
        // and Say Where Filter (Shift+W).
        // saySayQuery (Shift+Q): speak the query behind the current
        // recordset -- the exact SELECT/WITH for a custom query
        // (Control+Q), or the equivalent "SELECT * FROM <table>" for a
        // directly-opened table or view. Filter and order in effect are
        // reported separately by Say Where Filter (Shift+W) and Say Order
        // (Shift+O).
        private void saySayQuery(object sender, EventArgs evArgs)
        {
            if (db == null || !db.isOpen())
            { LiveRegion.say("No database open"); return; }
            if (!db.hasRecordset())
            { LiveRegion.say("No table selected"); return; }
            string sQuery;
            if (!string.IsNullOrEmpty(db.sourceSql))
                sQuery = db.sourceSql;
            else
                sQuery = "SELECT * FROM " + (db.currentTable ?? "");
            speakOrShow("Query", "query: " + sQuery, 111);
        }

        private void saySaySelect(object sender, EventArgs evArgs)
        {
            if (db == null || !db.isOpen())
            { LiveRegion.say("No database open"); return; }
            if (!db.hasRecordset())
            { LiveRegion.say("No table selected"); return; }
            List<string> lsCols = new List<string>();
            if (grid != null)
                foreach (ColumnHeader oCol in grid.Columns) lsCols.Add(oCol.Text);
            if (lsCols.Count == 0)
            { LiveRegion.say("No columns shown"); return; }
            // One queued message per column, for a natural pause
            // between column names rather than a run-on list.
            speakOrShowParts("Columns", lsCols, 123);
        }

        private void saySayFilter(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset())
            { LiveRegion.say("No recordset open"); return; }
            string sFilter = db.filter ?? "";
            if (string.IsNullOrEmpty(sFilter))
            { LiveRegion.say("No filter active"); return; }
            speakOrShow("Filter", "filter: " + sFilter, 118);
        }

        // saySayFind: speak the current Find search string. Shift+F.
        // Reports the most recent Find substring; if none was entered
        // this session, falls back to the last regex Find, then to the
        // persisted Find history. Says "No find string" when nothing is
        // remembered. Companion to Say Where Filter (Shift+W).
        private void saySayFind(object sender, EventArgs evArgs)
        {
            string sFind = sLastFindSubstring ?? "";
            if (string.IsNullOrEmpty(sFind)) sFind = sLastFindRegex ?? "";
            if (string.IsNullOrEmpty(sFind))
            {
                try { sFind = SearchHistory.lastText(SearchHistory.SectionFind) ?? ""; } catch { }
            }
            if (string.IsNullOrEmpty(sFind))
            { LiveRegion.say("No find string"); return; }
            speakOrShow("Find", "find: " + sFind, 126);
        }

        // saySayId: speak the primary-key value of the current row.
        // Uses computePrimaryKeyColumn to determine which column holds
        // the key for this table (typically <table>_id).
        private void saySayId(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset() || db.recordCount == 0)
            { LiveRegion.say("No record selected"); return; }
            string sPk = "";
            try
            {
                sPk = computePrimaryKeyColumn(db.currentTable, db.getFieldNames());
            }
            catch { }
            if (string.IsNullOrEmpty(sPk))
            { LiveRegion.say("This table has no detected primary key"); return; }
            string sVal = "";
            try { sVal = db.getFieldValue(sPk) ?? ""; } catch { }
            if (string.IsNullOrEmpty(sVal)) sVal = "blank";
            speakOrShow("Id", sPk + ": " + sVal, 119);
        }

        // saySayLook: speak the 'look' field of the current row.
        // The standard display nickname for the row.
        private void saySayLook(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset() || db.recordCount == 0)
            { LiveRegion.say("No record selected"); return; }
            if (!db.hasField("look"))
            { LiveRegion.say("This table has no look column"); return; }
            string sVal = db.getFieldValue("look");
            if (string.IsNullOrEmpty(sVal)) sVal = "blank";
            speakOrShow("Look", "look: " + sVal, 120);
        }

        // saySayRelated: speak the foreign-key relationships of the
        // current row. Brief version (single press): the related-
        // record summary line. Detailed version (double press, via
        // speakOrShow's dialog mode): the same content as the
        // multi-line textbox at the end of the Edit Record dialog.
        private void saySayRelated(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset() || db.recordCount == 0)
            { LiveRegion.say("No record selected"); return; }
            // Reuse the Show-Related machinery to get a textual
            // summary. For the brief form, just count the FK
            // neighbors; for the detailed form, show their look
            // values. We borrow the same logic Say-Kin uses (kin =
            // related). The text we display is the brief Kin form.
            string sSummary = buildRelatedSummary();
            if (string.IsNullOrEmpty(sSummary)) sSummary = "(no related records found)";
            speakOrShow("Related", sSummary, 121);
        }

        // Related-summary builder. Lists parents (via outbound *_id
        // columns) by look value, then child records (tables whose FK
        // column matches the current table's primary-key name) with
        // one look line per related record, capped per table. Falls
        // back to PK value if no look column. Returns "" if nothing
        // found.
        private string buildRelatedSummary()
        {
            const int c_iChildCap = 5;
            StringBuilder sb = new StringBuilder();
            try
            {
                List<string> lAllTables = db.getTableAndViewNames();
                List<string> lFields = db.getFieldNames();
                string sCurrentPk = db.actualPrimaryKey(db.currentTable);
                foreach (string sCol in lFields)
                {
                    if (string.Equals(sCol, sCurrentPk, StringComparison.OrdinalIgnoreCase))
                        continue;
                    if (!sCol.EndsWith(Metadata.PrimaryKeySuffix, StringComparison.OrdinalIgnoreCase))
                        continue;
                    string sFkValue = "";
                    try { sFkValue = db.getFieldValue(sCol) ?? ""; } catch { }
                    if (string.IsNullOrEmpty(sFkValue)) continue;
                    string sParentTable = findParentTableForFk(sCol, lAllTables);
                    if (string.IsNullOrEmpty(sParentTable)) continue;
                    int iFound;
                    List<string> lLook = db.queryColumnValues(
                        sParentTable, "look", sCol, sFkValue, 1, out iFound);
                    string sLookVal = (lLook.Count > 0 && !string.IsNullOrEmpty(lLook[0]))
                                      ? lLook[0] : "(no look)";
                    sb.AppendLine(sParentTable + ": " + sLookVal);
                }
                // Child records: any table carrying a column named the
                // same as this table's primary key (the contact_id-in-
                // both-places convention). One look line per record.
                string sPkValue = "";
                if (!string.IsNullOrEmpty(sCurrentPk))
                    try { sPkValue = db.getFieldValue(sCurrentPk) ?? ""; } catch { }
                if (!string.IsNullOrEmpty(sPkValue))
                {
                    foreach (string sChildTable in lAllTables)
                    {
                        if (string.Equals(sChildTable, db.currentTable, StringComparison.OrdinalIgnoreCase))
                            continue;
                        bool bHasFk = false;
                        foreach (string sChildCol in db.getColumnsOfTable(sChildTable))
                            if (string.Equals(sChildCol, sCurrentPk, StringComparison.OrdinalIgnoreCase))
                            { bHasFk = true; break; }
                        if (!bHasFk) continue;
                        int iFound;
                        List<string> lLook = db.queryColumnValues(
                            sChildTable, "look", sCurrentPk, sPkValue, c_iChildCap, out iFound);
                        if (iFound <= 0) continue;
                        sb.AppendLine(sChildTable + " (" + Str.plural("record", iFound) + "):");
                        foreach (string sLook in lLook)
                            sb.AppendLine("  " + (string.IsNullOrEmpty(sLook) ? "(no look)" : sLook));
                        if (iFound > lLook.Count)
                            sb.AppendLine("  ... and " + (iFound - lLook.Count) + " more");
                    }
                }

                // Maps associations: generic typed relations stored in
                // the standard maps table, identified by (table, prm)
                // pairs. Both directions are reported; 'to' marks
                // relations where this record is the subject, 'from'
                // where it is the object. One look line per related
                // record, the same convention as the FK sections.
                string sPrmValue = sCurrentPrmValue();
                if (!string.IsNullOrEmpty(sPrmValue) && db.hasMapsTable())
                {
                    List<string[]> lRelations = db.lMapsRelations(
                        db.currentTable, sPrmValue, 200);
                    // Group by (kind, other table, direction).
                    Dictionary<string, List<string[]>> dGroups =
                        new Dictionary<string, List<string[]>>();
                    List<string> lOrder = new List<string>();
                    foreach (string[] aRel in lRelations)
                    {
                        string sKey = aRel[0] + "\x01" + aRel[1] + "\x01" + aRel[3];
                        if (!dGroups.ContainsKey(sKey))
                        { dGroups[sKey] = new List<string[]>(); lOrder.Add(sKey); }
                        dGroups[sKey].Add(aRel);
                    }
                    foreach (string sKey in lOrder)
                    {
                        string[] aParts = sKey.Split('\x01');
                        string sKind = aParts[0], sOther = aParts[1], sDir = aParts[2];
                        List<string[]> lGroup = dGroups[sKey];
                        // Header names how the tables relate: "<table>
                        // via <kind>", " incoming" when this record is
                        // the object. Shown every time (not only to
                        // disambiguate), matching the Enter drill picker.
                        sb.AppendLine(sOther + " via " + sKind
                            + ((sDir == "object") ? " incoming" : "")
                            + " (" + lGroup.Count + "):");
                        int iShown = 0;
                        foreach (string[] aRel in lGroup)
                        {
                            if (iShown >= c_iChildCap)
                            {
                                sb.AppendLine("  ... and "
                                    + (lGroup.Count - iShown) + " more");
                                break;
                            }
                            int iLookFound;
                            List<string> lLookVals = db.queryColumnValues(
                                sOther, "look", Metadata.PrimeColumn, aRel[2], 1, out iLookFound);
                            string sLine = (lLookVals.Count > 0
                                && !string.IsNullOrEmpty(lLookVals[0]))
                                ? lLookVals[0] : aRel[2];
                            if (!string.IsNullOrEmpty(aRel[4]))
                                sLine += " (" + aRel[4] + ")";
                            sb.AppendLine("  " + sLine);
                            iShown++;
                        }
                    }
                }

                // Two-hop associations: related through an intermediate
                // record (a contact's locations via the events they
                // present). Grouped as "<target> via <viaTable>";
                // direct relations above stay the closer view, so a
                // target table already reported directly is skipped.
                if (!string.IsNullOrEmpty(sPrmValue) && db.hasMapsTable())
                {
                    List<string[]> lTwoHop = db.lMapsTwoHop(db.currentTable, sPrmValue, 200);
                    Dictionary<string, List<string>> dHop = new Dictionary<string, List<string>>();
                    List<string> lHopOrder = new List<string>();
                    HashSet<string> hsDirectTables = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
                    foreach (string[] aRel in db.lMapsRelations(db.currentTable, sPrmValue, 200))
                        hsDirectTables.Add(aRel[1]);
                    foreach (string[] aHop in lTwoHop)
                    {
                        if (hsDirectTables.Contains(aHop[1])) continue;
                        string sKey = aHop[1] + "\x01" + aHop[0];
                        if (!dHop.ContainsKey(sKey)) { dHop[sKey] = new List<string>(); lHopOrder.Add(sKey); }
                        if (!dHop[sKey].Contains(aHop[2])) dHop[sKey].Add(aHop[2]);
                    }
                    foreach (string sKey in lHopOrder)
                    {
                        string[] aParts = sKey.Split('\x01');
                        string sTarget = aParts[0], sVia = aParts[1];
                        List<string> lPrms = dHop[sKey];
                        // Two-hop groups never share a table name with a
                        // direct group (those are skipped above), so the
                        // bare table name is unambiguous here.
                        sb.AppendLine(sTarget + " (" + lPrms.Count + "):");
                        int iShown = 0;
                        foreach (string sTu in lPrms)
                        {
                            if (iShown >= c_iChildCap)
                            {
                                sb.AppendLine("  ... and " + (lPrms.Count - iShown) + " more");
                                break;
                            }
                            int iLookFound;
                            List<string> lLookVals = db.queryColumnValues(
                                sTarget, "look", Metadata.PrimeColumn, sTu, 1, out iLookFound);
                            sb.AppendLine("  " + ((lLookVals.Count > 0
                                && !string.IsNullOrEmpty(lLookVals[0])) ? lLookVals[0] : sTu));
                            iShown++;
                        }
                    }
                }
            }
            catch { }
            return sb.ToString().Trim();
        }

        // sCurrentPrmValue: the prm value of the current row, or ""
        // when the table has no prm column or no current row. The
        // (table, prm) pair is a record's identity in the maps model.
        //
        // Two-tier read: the recordset field when present, else a
        // direct SQL lookup keyed on the row's primary key. The SQL
        // fallback covers recordsets opened with a column subset
        // (per-table select lists) and any provider that omits
        // generated columns from the field collection.
        private string sCurrentPrmValue()
        {
            if (db == null || !db.hasRecordset() || db.recordCount == 0) return "";
            try
            {
                // Read the prm column straight from the open recordset.
                if (db.hasField(Metadata.PrimeColumn))
                {
                    string sFromRecordset = db.getFieldValue(Metadata.PrimeColumn) ?? "";
                    if (!string.IsNullOrEmpty(sFromRecordset)) return sFromRecordset;
                }
                // Fallback: SELECT prm FROM <table> WHERE <pk> = <value>.
                // Covers recordsets opened with a column subset and providers
                // that omit generated columns from the field collection.
                string sTable = db.currentTable;
                if (string.IsNullOrEmpty(sTable)) return "";
                string sPk = computePrimaryKeyColumn(sTable, db.getFieldNames());
                if (string.IsNullOrEmpty(sPk)) return "";
                string sPkValue = db.getFieldValue(sPk) ?? "";
                if (string.IsNullOrEmpty(sPkValue)) return "";
                try
                {
                    int iFound;
                    List<string> lVals = db.queryColumnValues(
                        sTable, Metadata.PrimeColumn, sPk, sPkValue, 1, out iFound);
                    if (lVals.Count > 0 && !string.IsNullOrEmpty(lVals[0]))
                    {
                        DbDoLog.write("sCurrentPrmValue: SQL fallback via prm"
                            + " for " + sTable + "." + sPk + "=" + sPkValue);
                        return lVals[0];
                    }
                }
                catch { /* prm column absent on this table */ }
                return "";
            }
            catch (Exception ex)
            {
                try { DbDoLog.write("sCurrentPrmValue failed: " + ex.Message); } catch { }
                return "";
            }
        }

        // saySayUrl: speak the 'url' field of the current record.
        // Shift+U. The 'url' column is the standard one DbDo
        // recognizes; tables without it report so.
        private void saySayUrl(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset() || db.recordCount == 0)
            { LiveRegion.say("No record selected"); return; }
            if (!db.hasField(Metadata.UrlColumn))
            { LiveRegion.say("This table has no url column"); return; }
            string sVal = db.getFieldValue(Metadata.UrlColumn);
            if (string.IsNullOrEmpty(sVal)) sVal = "blank";
            speakOrShow("URL", Metadata.UrlColumn + ": " + sVal, 122);
        }

        // saySayPrime: speak the 'prm' field -- the unique/primary-key
        // expression -- of the current record. Shift+P. Falls back to the
        // legacy 'prm' column for databases not yet migrated to 'prm';
        // tables with neither report so.
        private void saySayPrime(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset() || db.recordCount == 0)
            { LiveRegion.say("No record selected"); return; }
            string sField = db.hasField(Metadata.PrimeColumn) ? Metadata.PrimeColumn
                          : (db.hasField(Metadata.PrimeColumn) ? Metadata.PrimeColumn : null);
            if (sField == null)
            { LiveRegion.say("This table has no prime column"); return; }
            string sVal = db.getFieldValue(sField);
            if (string.IsNullOrEmpty(sVal)) sVal = "blank";
            speakOrShow("Prime", sField + ": " + sVal, 123);
        }

        // The Say-Column family sweeps the current virtual column and
        // speaks each cell. Two axes: scope (Alt = All rows from the top;
        // Control = from the Current row down) and filter (Shift = Marked
        // rows only). Position and virtual cursor are left unchanged; the
        // spoken list is paced one value per queued message. Double-press
        // shows the full list in a dialog.
        //   Alt+L            Say Column All
        //   Alt+Shift+L      Say Column All Marked
        //   Control+L        Say Column from Current
        //   Control+Shift+L  Say Column from Current Marked
        private void saySayColumnAll(object sender, EventArgs evArgs)
        {
            saySayColumnCommon(false, false);
        }

        private void saySayColumnAllMarked(object sender, EventArgs evArgs)
        {
            saySayColumnCommon(true, false);
        }

        private void saySayColumn(object sender, EventArgs evArgs)
        {
            saySayColumnCommon(false, true);
        }

        private void saySayColumnMarked(object sender, EventArgs evArgs)
        {
            saySayColumnCommon(true, true);
        }

        private void saySayColumnCommon(bool bMarkedOnly, bool bFromCurrent)
        {
            if (db == null || !db.hasRecordset() || db.recordCount == 0)
            { LiveRegion.say("No row selected"); return; }
            if (grid == null || iVirtualCol < 0 || iVirtualCol >= grid.Columns.Count)
            { LiveRegion.say("No column under virtual cursor"); return; }
            if (bMarkedOnly && !db.hasField(Metadata.MarkedColumn))
            { LiveRegion.say("This table has no marked column"); return; }

            string sHeader = grid.Columns[iVirtualCol].Text;
            // Alt (All) starts at row 1; Control (Current) starts at the
            // current virtual row and reads the rest of the column down.
            int iStart = bFromCurrent ? ((iVirtualRow >= 1) ? iVirtualRow : 1) : 1;
            object oOriginal = null;
            try { oOriginal = db.bookmark; } catch { }
            // No cap: every value from the cursor down is spoken.
            List<string> lValues = new List<string>();
            int iTotal = 0;
            try
            {
                for (int i = iStart; i <= db.recordCount; i++)
                {
                    try
                    {
                        db.absolutePosition = i;
                        if (bMarkedOnly)
                        {
                            if (!isMarkedTrue(db.getFieldValue(Metadata.MarkedColumn))) continue;
                        }
                        iTotal++;
                        lValues.Add(speakableValue(sHeader));
                    }
                    catch { lValues.Add("(error)"); }
                }
            }
            finally
            {
                if (oOriginal != null) try { db.bookmark = oOriginal; } catch { }
            }
            if (iTotal == 0)
            {
                string sNone = bFromCurrent
                    ? (bMarkedOnly ? "No marked rows from here." : "No rows visible from here.")
                    : (bMarkedOnly ? "No marked rows in this column." : "No rows in this column.");
                LiveRegion.say(sNone);
                return;
            }
            // Header lead-in, then each value as its own queued message
            // so the column reads as a paced sequence rather than a
            // run-on string.
            string sScope = (bFromCurrent ? "from current" : "all") + (bMarkedOnly ? " marked" : "");
            string sCmd = "Say Column " + (bFromCurrent ? "from Current" : "All") + (bMarkedOnly ? " Marked" : "");
            List<string> lParts = new List<string>();
            lParts.Add(sHeader + " (" + sScope + ")");
            lParts.AddRange(lValues);
            speakOrShowParts(sCmd, lParts, bMarkedOnly ? 112 : 111);
        }

        // saySayRows: Shift+V. Speak every visible row in full -- each
        // row's value across every displayed column, formatted as
        // "col1: val1; col2: val2; ..." for one row, then a newline
        // between rows. Capped at 25 rows; double-press shows full.
        // Position and virtual cursor are left unchanged.
        // speakableValue: the spoken form of the named field at the
        // current cursor position -- "null" for SQL NULL, "blank" for
        // the empty string, the stored value otherwise. getFieldValue
        // collapses NULL and "" to the same empty string, so the NULL
        // test must come first.
        private string speakableValue(string sCol)
        {
            if (db == null) return "blank";
            if (db.isFieldNull(sCol)) return "null";
            string sVal = db.getFieldValue(sCol);
            return string.IsNullOrEmpty(sVal) ? "blank" : sVal;
        }

        // saySayMarkedRows: Shift+Space. Speak every marked row in the
        // recordset, scanning from the FIRST row down (unlike Say Records
        // Rest Marked, which starts at the cursor). Each row reads
        // "Row N -- col1: val1; col2: val2; ..." with null/blank for SQL
        // NULL / empty values. The cursor position is saved and restored,
        // so the command never moves the user. Single press speaks the
        // rows as a paced sequence; double press shows them in the
        // read-only review dialog.
        private void saySayMarkedRows(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset() || db.recordCount == 0)
            { LiveRegion.say("No row selected"); return; }
            if (!db.hasField(Metadata.MarkedColumn))
            { LiveRegion.say("This table has no marked column"); return; }
            List<string> lDispCols = db.getDisplayFieldNames();
            if (lDispCols.Count == 0)
            { LiveRegion.say("No columns visible"); return; }
            object oOriginal = null;
            try { oOriginal = db.bookmark; } catch { }
            List<string> lParts = new List<string>();
            try
            {
                for (int i = 1; i <= db.recordCount; i++)
                {
                    try
                    {
                        db.absolutePosition = i;
                        if (!isMarkedTrue(db.getFieldValue(Metadata.MarkedColumn))) continue;
                        StringBuilder sbRow = new StringBuilder();
                        sbRow.Append("Row ").Append(i).Append(" -- ");
                        for (int j = 0; j < lDispCols.Count; j++)
                        {
                            if (j > 0) sbRow.Append("; ");
                            sbRow.Append(lDispCols[j]).Append(": ").Append(speakableValue(lDispCols[j]));
                        }
                        lParts.Add(sbRow.ToString());
                    }
                    catch { lParts.Add("(error)"); }
                }
            }
            finally
            {
                if (oOriginal != null) try { db.bookmark = oOriginal; } catch { }
            }
            if (lParts.Count == 0)
            { LiveRegion.say("No marked rows."); return; }
            speakOrShowParts("Say Marked Rows", lParts, 128);
        }

        private void saySayRows(object sender, EventArgs evArgs)
        {
            saySayRowsCommon(false);
        }

        // saySayRowsMarked: Shift+X. Like saySayRows but only marked.
        private void saySayRowsMarked(object sender, EventArgs evArgs)
        {
            saySayRowsCommon(true);
        }

        private void saySayRowsCommon(bool bMarkedOnly)
        {
            if (db == null || !db.hasRecordset() || db.recordCount == 0)
            { LiveRegion.say("No row selected"); return; }
            if (bMarkedOnly && !db.hasField(Metadata.MarkedColumn))
            { LiveRegion.say("This table has no marked column"); return; }

            List<string> lDispCols = db.getDisplayFieldNames();
            if (lDispCols.Count == 0)
            { LiveRegion.say("No columns visible"); return; }
            // v1.0.99: start at the current row (the "Rest" in the
            // command name). Renamed from Say Rows to Say Records Rest
            // for consistency with the rest of DbDo's entity vocabulary.
            int iStart = (iVirtualRow >= 1) ? iVirtualRow : 1;
            object oOriginal = null;
            try { oOriginal = db.bookmark; } catch { }
            // No cap: every row from the cursor down is spoken.
            List<string> lRows = new List<string>();
            int iTotal = 0;
            try
            {
                for (int i = iStart; i <= db.recordCount; i++)
                {
                    try
                    {
                        db.absolutePosition = i;
                        if (bMarkedOnly)
                        {
                            if (!isMarkedTrue(db.getFieldValue(Metadata.MarkedColumn))) continue;
                        }
                        iTotal++;
                        StringBuilder sbRow = new StringBuilder();
                        for (int j = 0; j < lDispCols.Count; j++)
                        {
                            if (j > 0) sbRow.Append("; ");
                            sbRow.Append(lDispCols[j]).Append(": ").Append(speakableValue(lDispCols[j]));
                        }
                        lRows.Add(sbRow.ToString());
                    }
                    catch { lRows.Add("(error)"); }
                }
            }
            finally
            {
                if (oOriginal != null) try { db.bookmark = oOriginal; } catch { }
            }
            if (iTotal == 0)
            {
                LiveRegion.say(bMarkedOnly ? "No marked rows from here." : "No rows visible from here.");
                return;
            }
            // One queued message per row so the rows are spoken as a
            // paced sequence with a natural pause between records.
            List<string> lParts = new List<string>();
            for (int i = 0; i < lRows.Count; i++)
                lParts.Add("Row " + (iStart + i) + " -- " + lRows[i]);
            speakOrShowParts(bMarkedOnly ? "Say Records Rest Marked" : "Say Records Rest",
                lParts, bMarkedOnly ? 114 : 113);
        }

        // saySayPosition: Alt+Delete. JAWS-style "say cursor position":
        // speaks the current virtual column's header followed by the
        // 1-based row number. Pattern is "Column: <header>, Row: <N>"
        // so the user gets the header BEFORE the row number, matching
        // the JAWS spoken form ("Column Name, Row 30"). Single press
        // speaks via the screen reader; double press shows the same
        // info in the multi-line LbcDialog used by other speech-only
        // commands, in case the column header is long.
        private void saySayPosition(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset() || db.recordCount == 0)
            { LiveRegion.say("No record selected"); return; }
            if (grid == null || iVirtualCol < 0 || iVirtualCol >= grid.Columns.Count)
            { LiveRegion.say("No column under virtual cursor"); return; }
            string sHeader = grid.Columns[iVirtualCol].Text;
            if (string.IsNullOrEmpty(sHeader)) sHeader = "(unnamed)";
            int iRow = iVirtualRow >= 1 ? iVirtualRow : db.absolutePosition;
            speakOrShow("Position", "Column: " + sHeader + ", Row: " + iRow, 112);
        }

        // saySayClipboard: Alt+Apostrophe. Speak the current Windows
        // clipboard text. The Alt+' = "Clipboard" Say
        // command in the Query menu. Plain text only; if the
        // clipboard holds files, images, or other shell data, the
        // speech says "(non-text clipboard)". If the clipboard is
        // empty, says "(clipboard is empty)". Double-press opens
        // the read-only memo dialog for line-by-line review of long
        // pasted content.
        //
        // Why no file-drop-list handling: DbDo is a
        // database tool, not a file manager. Copying file paths to
        // DbDo is not a meaningful workflow. The plain-text path
        // covers every common DbDo scenario (the user copies a row
        // value with Shift+C, or pastes some text from another
        // app's window) and the simpler implementation has fewer
        // failure modes.
        private void saySayClipboard(object sender, EventArgs evArgs)
        {
            string sText;
            try
            {
                if (Clipboard.ContainsText())
                {
                    sText = Clipboard.GetText() ?? "";
                    if (sText.Length == 0) sText = "(clipboard is empty)";
                }
                else
                {
                    sText = "(non-text clipboard)";
                }
            }
            catch (Exception ex)
            {
                // Clipboard access can throw on RDP, secure desktop,
                // or when another app holds the clipboard open.
                sText = "(clipboard unavailable: " + ex.Message + ")";
            }
            speakOrShow("Clipboard", sText, 115);
        }

        // saySaySortFilter: Shift+8. Speaks the active sort order
        // and filter criteria for the current table. Either or both
        // may be empty; the speech makes that explicit ("no sort",
        // "no filter") so the user gets confirmation rather than
        // silence. Single press speaks; double press shows the same
        // text in the multi-line LbcDialog used by the other
        // speech-only commands (helpful for long filter strings).
        private void saySaySortFilter(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset())
            { LiveRegion.say("No table open"); return; }
            string sSort = db.sort ?? "";
            string sFilter = db.filter ?? "";
            StringBuilder sb = new StringBuilder();
            sb.Append("Sort: ").Append(string.IsNullOrEmpty(sSort) ? "(none)" : sSort);
            sb.Append("; Filter: ").Append(string.IsNullOrEmpty(sFilter) ? "(none)" : sFilter);
            speakOrShow("Sort and Filter", sb.ToString(), 113);
        }

        // saySayKin: Shift+K. Speak the 'look' field of every related
        // record -- both directions. For each FK column on the
        // current row (e.g., teacher_id), look up the parent's look
        // value. For each other table that has an FK pointing back to
        // this row's primary key, list each child's look value (up
        // to a cap). Modeled on the parent+child walks in
        // Show-Object (recShowObjectClicked) but condensed for
        // speech: one announcement, parent and child sections
        // separated by "; Children:", individual values separated by
        // semicolons. Single-press speaks; double-press opens the
        // multi-line dialog used by other speech-only commands
        // (helpful for rows with many children).
        private void saySayKin(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset() || db.recordCount == 0)
            { LiveRegion.say("No record selected"); return; }
            if (db.eof || db.bof)
            { LiveRegion.say("No record selected"); return; }

            string sCurrentTable = db.currentTable;
            if (string.IsNullOrEmpty(sCurrentTable))
            { LiveRegion.say("No table open"); return; }

            // Use static helpers so logic is shared with the existing
            // Show-Object code; we replicate the parent/child walks
            // here in compact form.
            List<string> lAllTables = db.getTableAndViewNames();
            List<string> lCurrentCols = db.getFieldNames();
            string sCurrentPk = db.actualPrimaryKey(sCurrentTable);

            // PARENTS: every FK column on this row -> parent.look
            // Build a list of (parent-table, parent-look) pairs.
            List<string> lParentLines = new List<string>();
            foreach (string sCol in lCurrentCols)
            {
                if (string.Equals(sCol, sCurrentPk, StringComparison.OrdinalIgnoreCase))
                    continue;
                if (!sCol.EndsWith(Metadata.PrimaryKeySuffix, StringComparison.OrdinalIgnoreCase))
                    continue;
                string sFkValue = "";
                try { sFkValue = db.getFieldValue(sCol) ?? ""; }
                catch { sFkValue = ""; }
                if (string.IsNullOrEmpty(sFkValue)) continue;
                string sParentTable = findParentTableForFk(sCol, lAllTables);
                if (string.IsNullOrEmpty(sParentTable)) continue;
                int iFound;
                List<string> lLook = db.queryColumnValues(
                    sParentTable, "look", sCol, sFkValue, 1, out iFound);
                string sLookVal = (lLook.Count > 0 && !string.IsNullOrEmpty(lLook[0]))
                                  ? lLook[0]
                                  : "(no look)";
                lParentLines.Add(sParentTable + ": " + sLookVal);
            }

            // CHILDREN: every other base table with an FK column
            // matching our PK -> their look values.
            string sCurrentPkValue = "";
            if (!string.IsNullOrEmpty(sCurrentPk))
            {
                try { sCurrentPkValue = db.getFieldValue(sCurrentPk) ?? ""; }
                catch { sCurrentPkValue = ""; }
            }
            List<string> lChildLines = new List<string>();
            int iMaxPerChild = 25;
            if (!string.IsNullOrEmpty(sCurrentPk) && !string.IsNullOrEmpty(sCurrentPkValue))
            {
                foreach (string sChildTable in lAllTables)
                {
                    if (string.Equals(sChildTable, sCurrentTable, StringComparison.OrdinalIgnoreCase))
                        continue;
                    List<string> lChildCols = db.getColumnsOfTable(sChildTable);
                    bool bHasFk = false;
                    foreach (string sChildCol in lChildCols)
                    {
                        if (string.Equals(sChildCol, sCurrentPk, StringComparison.OrdinalIgnoreCase))
                        { bHasFk = true; break; }
                    }
                    if (!bHasFk) continue;
                    int iFound;
                    List<string> lLook = db.queryColumnValues(
                        sChildTable, "look", sCurrentPk, sCurrentPkValue,
                        iMaxPerChild, out iFound);
                    if (iFound == 0) continue;
                    StringBuilder sbChild = new StringBuilder();
                    sbChild.Append(sChildTable).Append(" (").Append(iFound).Append("): ");
                    if (lLook.Count == 0)
                        sbChild.Append("(no look column)");
                    else
                    {
                        for (int i = 0; i < lLook.Count; i++)
                        {
                            if (i > 0) sbChild.Append(", ");
                            sbChild.Append(string.IsNullOrEmpty(lLook[i]) ? "blank" : lLook[i]);
                        }
                        if (iFound > lLook.Count)
                            sbChild.Append(", ... ").Append(iFound - lLook.Count).Append(" more");
                    }
                    lChildLines.Add(sbChild.ToString());
                }
            }

            if (lParentLines.Count == 0 && lChildLines.Count == 0)
            {
                speakOrShow("Kin", "No related records", 114);
                return;
            }

            StringBuilder sb = new StringBuilder();
            if (lParentLines.Count > 0)
            {
                sb.Append("Parents: ");
                for (int i = 0; i < lParentLines.Count; i++)
                {
                    if (i > 0) sb.Append("; ");
                    sb.Append(lParentLines[i]);
                }
            }
            if (lChildLines.Count > 0)
            {
                if (sb.Length > 0) sb.Append(". ");
                sb.Append("Children: ");
                for (int i = 0; i < lChildLines.Count; i++)
                {
                    if (i > 0) sb.Append("; ");
                    sb.Append(lChildLines[i]);
                }
            }
            speakOrShow("Kin", sb.ToString(), 114);
        }

        // cellAppendClicked: Shift+A. Append the current virtual cell's
        // text to the Windows clipboard, separated from existing content
        // by two CRLF (one blank line). If the clipboard is empty or
        // not text, just set it to the cell value. Echoes a brief
        // confirmation through the live region.
        private void cellAppendClicked(object sender, EventArgs evArgs)
        {
            string sCell = virtCellValue(iVirtualRow, iVirtualCol);
            if (sCell == null) sCell = "";
            string sExisting = "";
            try { if (Clipboard.ContainsText()) sExisting = Clipboard.GetText() ?? ""; }
            catch { sExisting = ""; }
            string sNew = string.IsNullOrEmpty(sExisting)
                        ? sCell
                        : sExisting + "\r\n\r\n" + sCell;
            try { Clipboard.SetText(sNew); LiveRegion.say("Appended cell"); }
            catch (Exception ex) { LiveRegion.say("Clipboard error: " + ex.Message); }
        }

        // cellCopyClicked: Shift+C. Copy the current virtual cell's
        // text to the Windows clipboard, replacing existing content.
        private void cellCopyClicked(object sender, EventArgs evArgs)
        {
            string sCell = virtCellValue(iVirtualRow, iVirtualCol);
            if (sCell == null) sCell = "";
            try { Clipboard.SetText(sCell); LiveRegion.say("Copied cell"); }
            catch (Exception ex) { LiveRegion.say("Clipboard error: " + ex.Message); }
        }

        // =======================================================================
        // Describe Column: descriptive statistics for the current
        // virtual column. Walks the column once, sorts values into
        // numeric / date / boolean / text buckets, picks a dominant
        // type, computes the appropriate statistics, and shows the
        // report in a read-only multi-line LbcDialog.
        //
        // Statistics chosen per data type:
        //   - Numeric: count, non-empty, unique, min, max, range,
        //     mean, median, sample SD, Q1, Q3, IQR, mode (if
        //     unambiguous), and a one-line skew interpretation.
        //     Combines Tukey's five-number summary (Wikipedia, Penn
        //     State STAT 200) with mean + SD (the R summary() / SAS
        //     PROC UNIVARIATE convention).
        //   - Date: count, non-empty, unique, earliest, latest, span,
        //     median, mode (if unambiguous). Span is rendered as days
        //     and as years + months when long.
        //   - Boolean-like: count, non-empty, true / false counts and
        //     percentages.
        //   - Text: count, non-empty, unique, shortest / longest /
        //     mean string length, plus a top-10 frequency table with
        //     counts and percentages (or all values if fewer than 10
        //     unique).
        //
        // Type detection: per-value parsing with TryParse, then
        // majority vote among non-empty values with an 80% threshold.
        // Mixed columns fall back to text but the report notes the
        // mix in the header.
        //
        // Presentation: linearized label-and-value lines, one per
        // line, ordered count-then-center-then-spread-then-shape.
        // No multi-column tables (screen readers linearize them
        // anyway, and linear-prose is more navigable).
        // =======================================================================

        // selectColumnsClicked: Alt+S. Show a dialog with one
        // checkbox per column in the current table; the user picks
        // which columns are visible in the grid. The result is
        // stored via db.setSelectList(), which the existing
        // db.getDisplayFieldNames() consults when populating the
        // grid. Persists with the table.
        //
        // Behavior:
        //   - "Select All" button (Alt+A) checks every box.
        //   - "Select None" button (Alt+N) clears every box; equivalent
        //     to "revert to default visible columns" because the rule-
        //     based default applies when no select list is stored.
        //   - "OK" applies the selection.
        //   - "Cancel" leaves the current selection unchanged.
        //
        // The dialog is built with LbcDialog and one addCheckBox call
        // per column. For tables with many columns, the dialog scrolls.
        private void selectColumnsClicked(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset())
            {
                LiveRegion.say("No database open.");
                return;
            }
            string sTable = db.currentTable;
            if (string.IsNullOrEmpty(sTable))
            {
                LiveRegion.say("No table selected.");
                return;
            }
            List<string> lAllColumns = db.getFieldNames();

            // Build the named field sets:
            //   Distinct = the summary/key columns (look + prm)
            //   Edit     = the editable fields (everything that isn't an
            //              admin or computed column -- the nonstandard
            //              columns plus notes/tags/url)
            //   All      = every field, in natural order
            List<string> lDistinct = new List<string>();
            List<string> lEdit = new List<string>();
            foreach (string sN in lAllColumns)
            {
                if (Metadata.isDistinctColumn(sN)) lDistinct.Add(sN);
                if (!Metadata.isAdminColumn(sN, sTable)) lEdit.Add(sN);
            }

            // Chooser: Custom (the exact-sequence picker), Distinct,
            // Edit, or All. Custom is first.
            string sBtn;
            using (LbcDialog dlg = new LbcDialog("Select Columns", this))
            {
                dlg.addLabel("Which columns should the listview show for " + sTable + "?");
                dlg.addLabel("Custom = pick an exact sequence. Distinct = look + prm.");
                dlg.addLabel("Edit = the editable fields. All = every field.");
                sBtn = dlg.runWithButtons(new string[]
                    { "&Custom...", "&Edit", "&Distinct", "&All", "Cancel" });
            }
            if (string.IsNullOrEmpty(sBtn)
                || string.Equals(sBtn, "Cancel", StringComparison.OrdinalIgnoreCase))
                return;

            // The three named sets apply immediately and persist.
            if (!string.Equals(sBtn, "Custom...", StringComparison.OrdinalIgnoreCase))
            {
                List<string> lPick = string.Equals(sBtn, "Distinct", StringComparison.OrdinalIgnoreCase) ? lDistinct
                                   : string.Equals(sBtn, "Edit",     StringComparison.OrdinalIgnoreCase) ? lEdit
                                   : lAllColumns;
                string sStored = db.setSelectList(sTable, string.Join(", ", lPick.ToArray()));
                invokeRefresh();
                persistCurrentTableState();
                LiveRegion.sayForced(sBtn + ": "
                    + (string.IsNullOrEmpty(sStored) ? "(no matching columns)" : sStored));
                return;
            }

            // Custom: the Names/Picks sequence picker. The Picks order IS
            // the column sequence the grid shows, so this controls ORDER
            // as well as visibility. The form opens with every column in
            // Names (natural order, db cursor's column preselected) and
            // Picks empty -- the user states the wanted sequence anew.
            using (ColumnSequenceDialog dlg = new ColumnSequenceDialog(
                "Pick Fields to Display", lAllColumns,
                virtCurrentColumnName(), null, false))
            {
                if (dlg.ShowDialog(this) != DialogResult.OK) return;
                if (dlg.lChosenColumns.Count == 0)
                {
                    DialogResult res = MessageBox.Show(this,
                        "No columns chosen. Reset to default visible columns?",
                        "Select Columns",
                        MessageBoxButtons.YesNo, MessageBoxIcon.Question);
                    if (res != DialogResult.Yes) return;
                    db.setSelectList(sTable, "");
                    invokeRefresh();
                    persistCurrentTableState();
                    LiveRegion.sayForced("Reset to default visible columns.");
                    return;
                }
                db.setSelectList(sTable, dlg.sChosenCsv);
                invokeRefresh();
                persistCurrentTableState();
                LiveRegion.sayForced("Showing " + dlg.lChosenColumns.Count
                    + " column" + (dlg.lChosenColumns.Count == 1 ? "" : "s")
                    + ": " + dlg.sChosenCsv);
            }
        }

        private void describeColumnClicked(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset() || db.recordCount == 0)
            { LiveRegion.say("No record selected"); return; }
            if (grid == null || iVirtualCol < 0 || iVirtualCol >= grid.Columns.Count)
            { LiveRegion.say("No column under virtual cursor"); return; }
            string sColumn = grid.Columns[iVirtualCol].Text;
            if (string.IsNullOrEmpty(sColumn))
            { LiveRegion.say("Column has no name"); return; }

            // Walk the column once. Use a bookmark sentinel like the
            // other column-sweep commands so the user's row position
            // is restored when we're done.
            object bookmarkSaved = null;
            try { bookmarkSaved = db.bookmark; } catch { }

            List<string> lRaw = new List<string>();
            try
            {
                int iCount = db.recordCount;
                for (int i = 1; i <= iCount; i++)
                {
                    try { db.absolutePosition = i; }
                    catch { continue; }
                    string sVal = "";
                    try { sVal = db.getFieldValue(sColumn) ?? ""; }
                    catch { sVal = ""; }
                    lRaw.Add(sVal);
                }
            }
            finally
            {
                if (bookmarkSaved != null) try { db.bookmark = bookmarkSaved; } catch { }
            }

            string sReport = buildColumnReport(sColumn, lRaw);
            // Show in the same LbcDialog used for speech-on-double-press.
            // The report is multi-line; the dialog's read-only textbox
            // supports Control+C copy for the user who wants to save
            // the report.
            showInfoDialog("Statistics from Column: " + sColumn, sReport);
        }

        // plotColumnClicked: Control+Shift+P. Graphical sibling of
        // Describe Column. Walks the current virtual column, detects
        // its dominant data type using the same rules Describe Column
        // uses, then chooses an Excel chart shape:
        //
        //   - boolean -> pie of true / false slices  (auto, single
        //                                            option)
        //   - text    -> horizontal Pareto bar of top 15 frequencies
        //                (auto, single option)
        //   - numeric -> histogram OR box-and-whisker (prompts)
        //   - date    -> timeline (count by year-month line),
        //                counts-by-year (column), or counts-by-month
        //                (column, seasonal). Prompts among the three.
        //   - empty   -> message; nothing to plot
        //
        // Writes an .xlsx to <database-folder>/<table>-<col>-<kind>.xlsx
        // and opens it with the registered Excel handler. Same I/O
        // pattern as the existing Frequency Chart command.
        private void plotColumnClicked(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset() || db.recordCount == 0)
            { LiveRegion.say("No record selected"); return; }
            if (grid == null || iVirtualCol < 0 || iVirtualCol >= grid.Columns.Count)
            { LiveRegion.say("No column under virtual cursor"); return; }
            string sColumn = grid.Columns[iVirtualCol].Text;
            if (string.IsNullOrEmpty(sColumn))
            { LiveRegion.say("Column has no name"); return; }

            // Walk the column once. Reuse the same bookmark-save
            // pattern Describe Column uses so the user's row
            // position is restored when we're done.
            object bookmarkSaved = null;
            try { bookmarkSaved = db.bookmark; } catch { }

            List<string> lRaw = new List<string>();
            try
            {
                int iRows = db.recordCount;
                for (int i = 1; i <= iRows; i++)
                {
                    try { db.absolutePosition = i; }
                    catch { continue; }
                    string sVal = "";
                    try { sVal = db.getFieldValue(sColumn) ?? ""; }
                    catch { sVal = ""; }
                    if (!string.IsNullOrEmpty(sVal) && !string.IsNullOrEmpty(sVal.Trim()))
                        lRaw.Add(sVal);
                }
            }
            finally
            {
                if (bookmarkSaved != null) try { db.bookmark = bookmarkSaved; } catch { }
            }

            if (lRaw.Count == 0)
            {
                showInfoDialog("Plot Column: " + sColumn,
                    "Column \"" + sColumn + "\" has no non-empty values to plot.");
                return;
            }

            string sType = detectColumnDominantType(lRaw);

            // Pick chart kind. Auto for boolean and text; prompt for
            // numeric and date when multiple shapes make sense.
            string sKind = null;
            if (sType == "boolean")
            {
                sKind = "pie";
            }
            else if (sType == "text")
            {
                sKind = "pareto";
            }
            else if (sType == "numeric")
            {
                sKind = chooseChartKind("Plot Column: " + sColumn,
                    "Numeric column. Two visualizations work well; pick one.",
                    new string[] { "Histogram (distribution shape with auto bins)",
                                   "Box and whisker (Tukey five-number summary)" },
                    new string[] { "histogram", "boxwhisker" });
            }
            else if (sType == "date")
            {
                sKind = chooseChartKind("Plot Column: " + sColumn,
                    "Date column. Three views are useful; pick one.",
                    new string[] { "Timeline (count by month or day -- trend over time)",
                                   "By year (count per calendar year -- column chart)",
                                   "By month of year (seasonal pattern -- column chart)" },
                    new string[] { "timeline", "byyear", "bymonth" });
            }
            if (string.IsNullOrEmpty(sKind)) return; // user canceled

            // Build destination filename next to the database file,
            // same convention as the existing Frequency Chart command.
            string sDbPath = db.filePath ?? "";
            string sFolder = string.IsNullOrEmpty(sDbPath)
                ? Environment.GetFolderPath(Environment.SpecialFolder.MyDocuments)
                : Path.GetDirectoryName(sDbPath);
            string sTable = db.currentTable ?? "table";
            string sCleanCol = sColumn.Replace(" ", "_").Replace("/", "_");
            string sDest = Path.Combine(sFolder,
                sTable + "-" + sCleanCol + "-" + sKind + ".xlsx");

            try
            {
                int iPlotted = db.exportColumnChart(sColumn, sKind, sDest);
                if (iPlotted == 0)
                {
                    showInfoDialog("Plot Column: " + sColumn,
                        "No usable data to plot for column \"" + sColumn + "\".");
                    return;
                }
                LiveRegion.say("Plot saved (" + sKind + ", " + iPlotted + " points); opening in Excel");
                try { System.Diagnostics.Process.Start(sDest); } catch { }
            }
            catch (Exception ex)
            {
                ErrorDialog.show(this, "Graphics Column", "Could not create plot:\r\n\r\n" + ex.Message
                    + "\r\n\r\nNote: Plot Column requires Excel to be installed.");
            }
        }

        // chooseChartKind: small LbcDialog that prompts the user to
        // pick one of several chart shapes via a radio-button-style
        // listbox. Returns the matching value from aValues, or null
        // if the user canceled. aLabels and aValues are parallel
        // arrays of the same length.
        private string chooseChartKind(string sTitle, string sPrompt,
            string[] aLabels, string[] aValues)
        {
            if (aLabels == null || aValues == null) return null;
            if (aLabels.Length != aValues.Length) return null;
            if (aLabels.Length == 0) return null;
            if (aLabels.Length == 1) return aValues[0]; // no need to ask
            string sPicked;
            using (LbcDialog dlg = new LbcDialog(sTitle, this))
            {
                dlg.addLabel(sPrompt);
                dlg.addSeparator();
                List<string> lOpts = new List<string>(aLabels);
                ComboBox cb = dlg.addComboPickBox("Chart type:",
                    lOpts, aLabels[0],
                    "Choose the chart shape best matched to your data");
                if (!dlg.runOkCancel()) return null;
                sPicked = (cb.SelectedItem ?? "").ToString();
            }
            for (int i = 0; i < aLabels.Length; i++)
                if (string.Equals(aLabels[i], sPicked, StringComparison.Ordinal))
                    return aValues[i];
            return null;
        }

        // buildColumnReport: dispatch on detected dominant type and
        // assemble the linearized report string. Pure -- no side
        // effects on the recordset (the caller already did the walk).
        private static string buildColumnReport(string sColumn, List<string> lRaw)
        {
            int iCount = (lRaw != null) ? lRaw.Count : 0;
            if (iCount == 0)
            {
                return "Column: " + sColumn + "\r\n"
                     + "Count: 0 rows.\r\n";
            }

            // Partition into empty / non-empty.
            int iEmpty = 0;
            List<string> lNonEmpty = new List<string>();
            foreach (string s in lRaw)
            {
                if (string.IsNullOrEmpty(s) || string.IsNullOrEmpty(s.Trim())) iEmpty++;
                else lNonEmpty.Add(s);
            }

            // Type detection: count how many non-empty values parse
            // as each type. We classify by precedence: boolean wins
            // if every non-empty is in the boolean lexicon AND there
            // are at least 2 such values (a single "0" should not
            // tag a column as boolean if the rest of the table makes
            // it look numeric -- but we're looking at only one column
            int iN = lNonEmpty.Count;
            string sType = detectColumnDominantType(lNonEmpty);

            StringBuilder sb = new StringBuilder();
            sb.Append("Column: ").Append(sColumn).Append("\r\n");
            sb.Append("Detected type: ").Append(sType).Append("\r\n");
            sb.Append("Count: ").Append(iCount).Append(" rows");
            if (iEmpty > 0)
            {
                sb.Append("; ").Append(iEmpty).Append(" empty");
                sb.Append("; ").Append(iN).Append(" non-empty");
            }
            sb.Append(".\r\n");
            // Populated percentage -- a quick data-quality read.
            if (iCount > 0)
                sb.Append("Populated: ").Append(iN).Append(" of ").Append(iCount)
                  .Append(" (").Append(formatNumber(iN * 100.0 / iCount)).Append("%)\r\n");
            sb.Append("\r\n");

            if (sType == "numeric")     describeNumeric(sb, lNonEmpty);
            else if (sType == "date")   describeDate(sb, lNonEmpty);
            else if (sType == "boolean") describeBoolean(sb, lNonEmpty);
            else                         describeText(sb, lNonEmpty);

            return sb.ToString();
        }

        // detectColumnDominantType: shared type-detection helper used
        // by both Describe Column and Plot Column. Given a list of
        // non-empty string values, returns one of "numeric", "date",
        // "boolean", or "text" based on a majority vote. Boolean
        // wins if every value is in the boolean lexicon AND there
        // are at most 3 distinct values. Numeric and date each
        // require >= 80% of values to parse as that type. Mixed
        // columns fall back to "text".
        private static string detectColumnDominantType(List<string> lNonEmpty)
        {
            if (lNonEmpty == null || lNonEmpty.Count == 0) return "text";
            int iNumeric = 0, iDate = 0, iBoolish = 0;
            foreach (string s in lNonEmpty)
            {
                if (isBooleanLiteral(s)) iBoolish++;
                if (isDateLiteral(s)) iDate++;
                else if (isNumericLiteral(s)) iNumeric++;
            }
            int iN = lNonEmpty.Count;
            HashSet<string> hsDistinctLowered = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
            foreach (string s in lNonEmpty) hsDistinctLowered.Add(s);
            if (iN > 0 && iBoolish == iN && hsDistinctLowered.Count <= 3) return "boolean";
            if (iN > 0 && iDate * 5 >= iN * 4) return "date";
            if (iN > 0 && iNumeric * 5 >= iN * 4) return "numeric";
            return "text";
        }

        // ----- Type-test helpers (return true if string parses cleanly) -----

        private static bool isBooleanLiteral(string s)
        {
            if (string.IsNullOrEmpty(s)) return false;
            string t = s.Trim().ToLowerInvariant();
            return t == "0" || t == "1" || t == "-1"
                || t == "true" || t == "false"
                || t == "yes" || t == "no"
                || t == "y" || t == "n"
                || t == "t" || t == "f";
        }

        private static bool isDateLiteral(string s)
        {
            if (string.IsNullOrEmpty(s)) return false;
            // Cheap pre-filter: must contain a date-shaped separator.
            // Avoids treating "42" or "3.14" as a one-digit date.
            if (s.IndexOf('-') < 0 && s.IndexOf('/') < 0) return false;
            DateTime dt;
            return DateTime.TryParse(s,
                System.Globalization.CultureInfo.InvariantCulture,
                System.Globalization.DateTimeStyles.AssumeLocal, out dt)
                || DateTime.TryParse(s,
                System.Globalization.CultureInfo.CurrentCulture,
                System.Globalization.DateTimeStyles.AssumeLocal, out dt);
        }

        private static bool isNumericLiteral(string s)
        {
            if (string.IsNullOrEmpty(s)) return false;
            double d;
            return double.TryParse(s,
                System.Globalization.NumberStyles.Any,
                System.Globalization.CultureInfo.InvariantCulture, out d)
                || double.TryParse(s,
                System.Globalization.NumberStyles.Any,
                System.Globalization.CultureInfo.CurrentCulture, out d);
        }

        private static bool tryParseDouble(string s, out double dValue)
        {
            return double.TryParse(s,
                System.Globalization.NumberStyles.Any,
                System.Globalization.CultureInfo.InvariantCulture, out dValue)
                || double.TryParse(s,
                System.Globalization.NumberStyles.Any,
                System.Globalization.CultureInfo.CurrentCulture, out dValue);
        }

        private static bool tryParseDate(string s, out DateTime dt)
        {
            return DateTime.TryParse(s,
                System.Globalization.CultureInfo.InvariantCulture,
                System.Globalization.DateTimeStyles.AssumeLocal, out dt)
                || DateTime.TryParse(s,
                System.Globalization.CultureInfo.CurrentCulture,
                System.Globalization.DateTimeStyles.AssumeLocal, out dt);
        }

        private static bool isBooleanTrue(string s)
        {
            if (string.IsNullOrEmpty(s)) return false;
            string t = s.Trim().ToLowerInvariant();
            return t == "1" || t == "-1" || t == "true" || t == "yes" || t == "y" || t == "t";
        }

        // ----- Per-type describer functions; each appends to sb -----

        private static void describeNumeric(StringBuilder sb, List<string> lNonEmpty)
        {
            // Parse to doubles, drop unparseable rows (rare under the
            // 80% rule but possible in mixed columns).
            List<double> lValues = new List<double>(lNonEmpty.Count);
            foreach (string s in lNonEmpty)
            {
                double d;
                if (tryParseDouble(s, out d)) lValues.Add(d);
            }
            if (lValues.Count == 0)
            { sb.Append("No numeric values to summarize.\r\n"); return; }

            // Sort for quantiles.
            lValues.Sort();
            int n = lValues.Count;
            HashSet<double> hsDistinct = new HashSet<double>(lValues);

            double dMin = lValues[0];
            double dMax = lValues[n - 1];
            double dRange = dMax - dMin;
            double dSum = 0;
            foreach (double d in lValues) dSum += d;
            double dMean = dSum / n;
            double dMedian = percentileSorted(lValues, 0.50);
            double dQ1     = percentileSorted(lValues, 0.25);
            double dQ3     = percentileSorted(lValues, 0.75);
            double dIqr = dQ3 - dQ1;
            // Sample standard deviation (n-1 denominator). Use a
            // numerically-stable two-pass approach: we already have
            // mean, so just sum squared deviations.
            double dSqSum = 0;
            foreach (double d in lValues) { double dD = d - dMean; dSqSum += dD * dD; }
            double dSd = (n >= 2) ? Math.Sqrt(dSqSum / (n - 1)) : 0.0;

            sb.Append("Unique values: ").Append(hsDistinct.Count).Append("\r\n");
            sb.Append("Minimum: ").Append(formatNumber(dMin)).Append("\r\n");
            sb.Append("Maximum: ").Append(formatNumber(dMax)).Append("\r\n");
            sb.Append("Range:   ").Append(formatNumber(dRange)).Append("\r\n");
            sb.Append("Mean:    ").Append(formatNumber(dMean)).Append("\r\n");
            sb.Append("Median:  ").Append(formatNumber(dMedian)).Append("\r\n");
            if (n >= 2)
                sb.Append("Standard deviation (sample): ").Append(formatNumber(dSd)).Append("\r\n");
            sb.Append("Q1 (25th percentile): ").Append(formatNumber(dQ1)).Append("\r\n");
            sb.Append("Q3 (75th percentile): ").Append(formatNumber(dQ3)).Append("\r\n");
            sb.Append("IQR (Q3 - Q1):        ").Append(formatNumber(dIqr)).Append("\r\n");
            // Additional spread / shape metadata, all from values already
            // computed above so this stays cheap.
            sb.Append("Sum:      ").Append(formatNumber(dSum)).Append("\r\n");
            if (n >= 2)
            {
                double dVar = dSd * dSd;  // sample variance (SD squared)
                sb.Append("Variance (sample): ").Append(formatNumber(dVar)).Append("\r\n");
                if (Math.Abs(dMean) > 1e-12)
                {
                    double dCv = Math.Abs(dSd / dMean) * 100.0;
                    sb.Append("Coefficient of variation: ").Append(formatNumber(dCv)).Append("%\r\n");
                }
            }
            // Tukey outliers: values beyond 1.5 x IQR past Q1 / Q3. Report
            // the fences and a count so a screen-reader user gets the same
            // "are there outliers" answer a box plot would show a sighted one.
            double dLoFence = dQ1 - 1.5 * dIqr;
            double dHiFence = dQ3 + 1.5 * dIqr;
            int iOutliers = 0;
            foreach (double d in lValues) if (d < dLoFence || d > dHiFence) iOutliers++;
            sb.Append("Outlier fences (1.5 x IQR): below ").Append(formatNumber(dLoFence))
              .Append(" or above ").Append(formatNumber(dHiFence)).Append("\r\n");
            sb.Append("Outliers: ").Append(iOutliers);
            if (n > 0) sb.Append(" (").Append(formatNumber(iOutliers * 100.0 / n)).Append("%)");
            sb.Append("\r\n");

            // Mode: only report when there's an unambiguous single
            // value of frequency >= 2. Otherwise mode is misleading
            // for continuous data.
            Dictionary<double, int> dFreq = new Dictionary<double, int>();
            foreach (double d in lValues)
            {
                int c;
                dFreq[d] = dFreq.TryGetValue(d, out c) ? c + 1 : 1;
            }
            int iTopFreq = 0;
            double dTopValue = 0;
            int iTopCount = 0;
            foreach (KeyValuePair<double, int> kv in dFreq)
            {
                if (kv.Value > iTopFreq) { iTopFreq = kv.Value; dTopValue = kv.Key; iTopCount = 1; }
                else if (kv.Value == iTopFreq) { iTopCount++; }
            }
            if (iTopFreq >= 2 && iTopCount == 1)
                sb.Append("Mode: ").Append(formatNumber(dTopValue))
                  .Append(" (occurs ").Append(iTopFreq).Append(" times)\r\n");

            // Skew indicator: mean vs. median, with a threshold tied
            // to the standard deviation so small differences on big
            // numbers don't look like skew. Only meaningful for n>=10
            // and non-zero spread.
            if (n >= 10 && dSd > 0)
            {
                double dGap = dMean - dMedian;
                double dThreshold = 0.1 * dSd;
                string sShape;
                if (dGap > dThreshold)       sShape = "Right-skewed (mean > median)";
                else if (dGap < -dThreshold) sShape = "Left-skewed (mean < median)";
                else                          sShape = "Approximately symmetric";
                sb.Append("Shape: ").Append(sShape).Append("\r\n");
            }
        }

        private static void describeDate(StringBuilder sb, List<string> lNonEmpty)
        {
            List<DateTime> lDates = new List<DateTime>(lNonEmpty.Count);
            foreach (string s in lNonEmpty)
            {
                DateTime dt;
                if (tryParseDate(s, out dt)) lDates.Add(dt);
            }
            if (lDates.Count == 0)
            { sb.Append("No date values to summarize.\r\n"); return; }
            lDates.Sort();
            int n = lDates.Count;
            HashSet<DateTime> hsDistinct = new HashSet<DateTime>(lDates);
            DateTime dtMin = lDates[0];
            DateTime dtMax = lDates[n - 1];
            DateTime dtMedian = lDates[n / 2]; // approximate middle
            TimeSpan tsSpan = dtMax - dtMin;
            sb.Append("Unique dates: ").Append(hsDistinct.Count).Append("\r\n");
            sb.Append("Earliest: ").Append(dtMin.ToString("MMMM d, yyyy")).Append("\r\n");
            sb.Append("Latest:   ").Append(dtMax.ToString("MMMM d, yyyy")).Append("\r\n");
            sb.Append("Median:   ").Append(dtMedian.ToString("MMMM d, yyyy")).Append("\r\n");
            sb.Append("Span:     ").Append(formatTimeSpan(tsSpan)).Append("\r\n");

            // Mode if unambiguous.
            Dictionary<DateTime, int> dFreq = new Dictionary<DateTime, int>();
            foreach (DateTime dt in lDates)
            {
                int c;
                dFreq[dt] = dFreq.TryGetValue(dt, out c) ? c + 1 : 1;
            }
            int iTopFreq = 0;
            DateTime dtTopValue = dtMin;
            int iTopCount = 0;
            foreach (KeyValuePair<DateTime, int> kv in dFreq)
            {
                if (kv.Value > iTopFreq) { iTopFreq = kv.Value; dtTopValue = kv.Key; iTopCount = 1; }
                else if (kv.Value == iTopFreq) { iTopCount++; }
            }
            if (iTopFreq >= 2 && iTopCount == 1)
                sb.Append("Mode: ").Append(dtTopValue.ToString("MMMM d, yyyy"))
                  .Append(" (occurs ").Append(iTopFreq).Append(" times)\r\n");
        }

        private static void describeBoolean(StringBuilder sb, List<string> lNonEmpty)
        {
            int iTrue = 0, iFalse = 0;
            foreach (string s in lNonEmpty)
            {
                if (isBooleanTrue(s)) iTrue++;
                else iFalse++;
            }
            int n = lNonEmpty.Count;
            sb.Append("True values:  ").Append(iTrue)
              .Append(" (").Append(formatPercent(iTrue, n)).Append(")\r\n");
            sb.Append("False values: ").Append(iFalse)
              .Append(" (").Append(formatPercent(iFalse, n)).Append(")\r\n");
        }

        private static void describeText(StringBuilder sb, List<string> lNonEmpty)
        {
            int n = lNonEmpty.Count;
            int iMinLen = int.MaxValue, iMaxLen = 0;
            long iLenSum = 0;
            Dictionary<string, int> dFreq = new Dictionary<string, int>(StringComparer.Ordinal);
            foreach (string s in lNonEmpty)
            {
                int iLen = s.Length;
                if (iLen < iMinLen) iMinLen = iLen;
                if (iLen > iMaxLen) iMaxLen = iLen;
                iLenSum += iLen;
                int c;
                dFreq[s] = dFreq.TryGetValue(s, out c) ? c + 1 : 1;
            }
            double dMeanLen = (n > 0) ? ((double)iLenSum) / n : 0;
            sb.Append("Unique values: ").Append(dFreq.Count);
            if (dFreq.Count == n) sb.Append(" (every value is unique)");
            else if (dFreq.Count == 1) sb.Append(" (every value is identical)");
            sb.Append("\r\n");
            sb.Append("Shortest length: ").Append(iMinLen).Append("\r\n");
            sb.Append("Longest length:  ").Append(iMaxLen).Append("\r\n");
            sb.Append("Mean length:     ").Append(dMeanLen.ToString("0.0")).Append("\r\n");

            // Top-N frequency table. If unique < count there are
            // repeats worth listing; show up to 10 in descending
            // frequency, with percent of non-empty.
            if (dFreq.Count < n)
            {
                List<KeyValuePair<string, int>> lTop = new List<KeyValuePair<string, int>>(dFreq);
                lTop.Sort(compareByFreqDesc);
                sb.Append("\r\nMost frequent values:\r\n");
                int iShown = 0;
                int iMaxToShow = (dFreq.Count <= 10) ? dFreq.Count : 10;
                foreach (KeyValuePair<string, int> kv in lTop)
                {
                    if (iShown >= iMaxToShow) break;
                    sb.Append("  ").Append(kv.Value)
                      .Append(" (").Append(formatPercent(kv.Value, n)).Append("):  ")
                      .Append(truncateForReport(kv.Key, 80))
                      .Append("\r\n");
                    iShown++;
                }
                if (dFreq.Count > iMaxToShow)
                    sb.Append("  ... plus ").Append(dFreq.Count - iMaxToShow)
                      .Append(" more value").Append(dFreq.Count - iMaxToShow == 1 ? "" : "s").Append(".\r\n");
            }
        }

        private static int compareByFreqDesc(KeyValuePair<string, int> a, KeyValuePair<string, int> b)
        {
            int c = b.Value.CompareTo(a.Value);
            if (c != 0) return c;
            return string.Compare(a.Key, b.Key, StringComparison.OrdinalIgnoreCase);
        }

        // ----- Formatting helpers -----

        private static string formatNumber(double d)
        {
            // Pick fixed-point precision that fits the magnitude.
            // Integer values render as integers; small fractional
            // values get more precision; large values get fewer
            // decimals to keep the report compact.
            if (Math.Abs(d - Math.Round(d)) < 1e-9) return d.ToString("0");
            double dAbs = Math.Abs(d);
            if (dAbs >= 1000)   return d.ToString("0.00");
            if (dAbs >= 1)      return d.ToString("0.0000");
            return d.ToString("0.000000");
        }

        private static string formatPercent(int iPart, int iWhole)
        {
            if (iWhole == 0) return "0%";
            double dPct = 100.0 * iPart / iWhole;
            return dPct.ToString("0.0") + "%";
        }

        private static string formatTimeSpan(TimeSpan ts)
        {
            int iDays = (int)Math.Round(ts.TotalDays);
            if (iDays < 31)  return iDays + " day" + (iDays == 1 ? "" : "s");
            int iMonths = iDays / 30; // approximate
            if (iMonths < 12) return iMonths + " month" + (iMonths == 1 ? "" : "s") + " (" + iDays + " days)";
            int iYears = iMonths / 12;
            int iLeftMonths = iMonths % 12;
            string sYear = iYears + " year" + (iYears == 1 ? "" : "s");
            if (iLeftMonths == 0) return sYear + " (" + iDays + " days)";
            return sYear + ", " + iLeftMonths + " month" + (iLeftMonths == 1 ? "" : "s") + " (" + iDays + " days)";
        }

        private static string truncateForReport(string s, int iMaxLen)
        {
            if (s == null) return "";
            if (s.Length <= iMaxLen) return s;
            return s.Substring(0, iMaxLen - 3) + "...";
        }

        // percentileSorted: linear-interpolation percentile against a
        // pre-sorted ascending list. Matches the R Type-7 quantile
        // convention (the same one Excel's PERCENTILE uses). Returns
        // 0 for an empty list.
        private static double percentileSorted(List<double> lSorted, double dFraction)
        {
            int n = lSorted.Count;
            if (n == 0) return 0;
            if (n == 1) return lSorted[0];
            double dPos = dFraction * (n - 1);
            int iLower = (int)Math.Floor(dPos);
            int iUpper = (int)Math.Ceiling(dPos);
            if (iLower < 0) iLower = 0;
            if (iUpper >= n) iUpper = n - 1;
            double dFrac = dPos - iLower;
            return lSorted[iLower] + dFrac * (lSorted[iUpper] - lSorted[iLower]);
        }

        // =======================================================================
        // Action commands new in this turn (not speech-only). Extract,
        // Copy Row, Jump Next Initial, plus the wrapper handlers for
        // menu items that route to them.
        // =======================================================================

        // copyRow: copy the current row's visible columns to the
        // clipboard as tab-separated values. No hotkey or trigger
        // letter -- "Copy Row as TSV to Clipboard" has no Camel-Type
        // mnemonic letter that is not mid-word. Pastes cleanly into
        // Excel, Word tables, and chat clients.
        private void copyRowClicked(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset() || db.recordCount == 0)
            { LiveRegion.say("No record selected"); return; }
            try
            {
                List<string> lFields = db.getDisplayFieldNames();
                StringBuilder sb = new StringBuilder();
                for (int i = 0; i < lFields.Count; i++)
                {
                    if (i > 0) sb.Append('\t');
                    string sV = db.getFieldValue(lFields[i]) ?? "";
                    // Tab and newline are TSV-killers; replace with
                    // space and a slash-n marker respectively.
                    sV = sV.Replace('\t', ' ').Replace("\r\n", "\\n").Replace("\n", "\\n").Replace("\r", "\\n");
                    sb.Append(sV);
                }
                Clipboard.SetText(sb.ToString());
                LiveRegion.say("Row copied to clipboard");
            }
            catch (Exception ex) { LiveRegion.say("Copy Row: " + ex.Message); }
        }

        // copyColumnClicked: copy every value in the column under the
        // virtual cursor to the clipboard, one value per line, with the
        // column name as a header line -- the spreadsheet analog of
        // pasting a single column. Walks all rows with the cursor
        // suppressed and restores position when done, the same safe
        // full-scan pattern as gridSearchForVirtualItem.
        private void copyColumnClicked(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset() || db.recordCount == 0)
            { LiveRegion.say("No record selected"); return; }
            try
            {
                List<string> lFields = db.getDisplayFieldNames();
                if (lFields == null || lFields.Count == 0) { LiveRegion.say("No columns"); return; }
                string sField = virtCurrentColumnName();
                if (string.IsNullOrEmpty(sField) || !lFields.Contains(sField)) sField = lFields[0];
                int iSavedPos = db.absolutePosition;
                int iTotal = db.recordCount;
                StringBuilder sb = new StringBuilder();
                sb.Append(sField);
                bSuppressCellChanged = true;
                try
                {
                    for (int iPos = 1; iPos <= iTotal; iPos++)
                    {
                        try { db.absolutePosition = iPos; } catch { continue; }
                        string sV = "";
                        try { sV = db.getFieldValue(sField) ?? ""; } catch { }
                        sV = sV.Replace('\t', ' ').Replace("\r\n", "\\n").Replace("\n", "\\n").Replace("\r", "\\n");
                        sb.Append("\r\n").Append(sV);
                    }
                }
                finally
                {
                    try { db.absolutePosition = iSavedPos; } catch { }
                    bSuppressCellChanged = false;
                }
                Clipboard.SetText(sb.ToString());
                LiveRegion.say("Column " + sField + " copied, " + iTotal + (iTotal == 1 ? " value" : " values"));
            }
            catch (Exception ex) { LiveRegion.say("Copy Column: " + ex.Message); }
        }

        // copyGridClicked: copy the whole visible grid to the clipboard
        // as TSV -- a header row of visible column names, then every
        // row. Hidden columns are skipped (the getDisplayFieldNames
        // set, same as Copy Visible Cells). For a file on disk, Export
        // Data is the right tool; this is the quick "paste the table
        // into a spreadsheet" path.
        private void copyGridClicked(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset() || db.recordCount == 0)
            { LiveRegion.say("No record selected"); return; }
            try
            {
                List<string> lFields = db.getDisplayFieldNames();
                if (lFields == null || lFields.Count == 0) { LiveRegion.say("No columns"); return; }
                int iCols = lFields.Count;
                int iSavedPos = db.absolutePosition;
                int iTotal = db.recordCount;
                StringBuilder sb = new StringBuilder();
                for (int iCol = 0; iCol < iCols; iCol++)
                {
                    if (iCol > 0) sb.Append('\t');
                    sb.Append(lFields[iCol]);
                }
                bSuppressCellChanged = true;
                try
                {
                    for (int iPos = 1; iPos <= iTotal; iPos++)
                    {
                        try { db.absolutePosition = iPos; } catch { continue; }
                        sb.Append("\r\n");
                        for (int iCol = 0; iCol < iCols; iCol++)
                        {
                            if (iCol > 0) sb.Append('\t');
                            string sV = "";
                            try { sV = db.getFieldValue(lFields[iCol]) ?? ""; } catch { }
                            sV = sV.Replace('\t', ' ').Replace("\r\n", "\\n").Replace("\n", "\\n").Replace("\r", "\\n");
                            sb.Append(sV);
                        }
                    }
                }
                finally
                {
                    try { db.absolutePosition = iSavedPos; } catch { }
                    bSuppressCellChanged = false;
                }
                Clipboard.SetText(sb.ToString());
                LiveRegion.say("Grid copied, " + iTotal + (iTotal == 1 ? " row, " : " rows, ") + iCols + (iCols == 1 ? " column" : " columns"));
            }
            catch (Exception ex) { LiveRegion.say("Copy Grid: " + ex.Message); }
        }

        // jumpNextInitial: jump to the next row whose value in a
        // user-picked column differs in its first character from the
        // current row. Shift+I = "Initial Change." Useful
        // for skipping through alphabetically sorted data: jump from
        // all "A..." rows past the last A to the first B.
        //
        // The column is prompted via LBC dialog rather than read from
        // any Tab-tracked state -- the listview doesn't visually
        // highlight a "current column" so reading it from a state
        // var would be a hidden coupling that screen-reader users
        // can't see.
        private void jumpNextInitialClicked(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset() || db.recordCount == 0)
            { LiveRegion.say("No record selected"); return; }
            List<string> lFields = db.getDisplayFieldNames();
            if (lFields == null || lFields.Count == 0)
            { LiveRegion.say("No columns"); return; }
            LbcDialog dlg = new LbcDialog("Next Initial Change", this);
            string sColName;
            try
            {
                string sDefault = virtCurrentColumnName();
                if (string.IsNullOrEmpty(sDefault) || !lFields.Contains(sDefault)) sDefault = lFields[0];
                ListBox lb = dlg.addPickBox(
                    "&Column to track for an initial-letter change:",
                    lFields, sDefault,
                    "The command jumps to the next row whose value in this column starts with a different letter");
                if (!dlg.runOkCancel()) return;
                if (lb.SelectedItem == null) return;
                sColName = lb.SelectedItem.ToString();
            }
            finally { dlg.Dispose(); }
            try
            {
                string sCurrent = db.getFieldValue(sColName) ?? "";
                char chCurrent = sCurrent.Length > 0
                    ? char.ToUpperInvariant(sCurrent[0])
                    : '\0';
                int iStart = db.absolutePosition;
                for (int iPos = iStart + 1; iPos <= db.recordCount; iPos++)
                {
                    db.absolutePosition = iPos;
                    string sV = db.getFieldValue(sColName) ?? "";
                    char ch = sV.Length > 0 ? char.ToUpperInvariant(sV[0]) : '\0';
                    if (ch != chCurrent)
                    {
                        invokeRefresh();
                        LiveRegion.say("Initial: " + (sV.Length > 0 ? sV.Substring(0, Math.Min(40, sV.Length)) : "blank"));
                        return;
                    }
                }
                // No change found; put cursor back.
                db.absolutePosition = iStart;
                LiveRegion.say("No further initial change in " + sColName);
            }
            catch (Exception ex) { LiveRegion.say("Next Initial Change: " + ex.Message); }
        }

        // extractRegex: Control+Shift+E. Prompt for a .NET regex,
        // walk every visible row, and copy to the clipboard every
        // matching substring from every visible column.
        // Control+Shift+E = "Extract with Regular Expression."
        // Each match goes on its
        // own line. Useful for pulling email addresses, urls, IDs,
        // or any pattern out of free-text columns.
        private void extractRegexClicked(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset() || db.recordCount == 0)
            { LiveRegion.say("No table selected"); return; }
            string sPattern;
            using (LbcDialog dlg = new LbcDialog("Extract Regex", this))
            {
                dlg.addLabel("Extract every match of a .NET regex from every visible cell");
                dlg.addLabel("in the current filtered view. Matches go to the clipboard,");
                dlg.addLabel("one per line. Useful for pulling emails, urls, or IDs out");
                dlg.addLabel("of free-text columns.");
                dlg.addSeparator();
                TextBox tbPat = dlg.addInlineInputBox("Regex pattern",
                    "", "A standard .NET regex (e.g. \\b\\w+@\\w+\\.\\w+\\b for emails)");
                if (!dlg.runOkCancel()) return;
                sPattern = tbPat.Text ?? "";
            }
            if (sPattern.Length == 0) return;
            System.Text.RegularExpressions.Regex re;
            try
            {
                re = new System.Text.RegularExpressions.Regex(sPattern,
                    System.Text.RegularExpressions.RegexOptions.IgnoreCase);
            }
            catch (Exception ex)
            {
                MessageBox.Show(this, "Invalid regex: " + ex.Message,
                    "Extract Regex", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                return;
            }

            // Per spec v1.0.65, Extract searches the FULL field set
            // (not just displayed columns), so hidden columns like
            // notes, tags, url, and bookkeeping timestamps are
            // included in the harvest.
            List<string> lFields = db.getFieldNames();
            object original = null;
            try { original = db.bookmark; } catch { }
            int iMatches = 0;
            StringBuilder sbOut = new StringBuilder();
            try
            {
                for (int i = 1; i <= db.recordCount; i++)
                {
                    try
                    {
                        db.absolutePosition = i;
                        foreach (string sCol in lFields)
                        {
                            string sV = db.getFieldValue(sCol) ?? "";
                            if (sV.Length == 0) continue;
                            foreach (System.Text.RegularExpressions.Match match in re.Matches(sV))
                            {
                                sbOut.AppendLine(match.Value);
                                iMatches++;
                            }
                        }
                    }
                    catch { }
                }
            }
            finally
            {
                if (original != null) try { db.bookmark = original; } catch { }
            }
            invokeRefresh();
            if (iMatches == 0)
            { LiveRegion.say("No matches found"); return; }
            try
            {
                Clipboard.SetText(sbOut.ToString());
                LiveRegion.say(iMatches + " match" + (iMatches == 1 ? "" : "es") + " copied to clipboard");
            }
            catch (Exception ex) { LiveRegion.say("Extract Regex clipboard error: " + ex.Message); }
        }

        // Cycle through the list of tables visited in this session.
        // bForward=true moves to the next table; false to the previous.
        // Wraps around at the ends. Does nothing if fewer than two
        // tables have been visited.
        private void cycleVisitedTable(bool bForward)
        {
            if (db == null || !db.isOpen())
            {
                LiveRegion.say("No database file open; press Control+O to open one");
                return;
            }
            List<string> lVisited = db.visitedTableNames();
            if (lVisited.Count < 2) { LiveRegion.say("Only one table visited; press F4 to pick another table"); return; }
            string sCurrent = db.currentTable;
            int iCurrent = -1;
            for (int i = 0; i < lVisited.Count; i++)
            {
                if (string.Equals(lVisited[i], sCurrent, StringComparison.OrdinalIgnoreCase))
                { iCurrent = i; break; }
            }
            if (iCurrent < 0) iCurrent = 0;
            int iNext = bForward
                ? (iCurrent + 1) % lVisited.Count
                : (iCurrent - 1 + lVisited.Count) % lVisited.Count;
            string sNext = lVisited[iNext];
            try
            {
                db.selectTable(sNext);
                invokeRefresh();
                // Announce with ring position so the user can hear the
                // wraparound. "table X, position 3 of 3, 142 rows" then
                // the next Control+Tab says "position 1 of 3" -- the
                // user knows wraparound works because the position
                // number cycles.
                int iCount = db.recordCount;
                string sPosOf = "position " + (iNext + 1) + " of " + lVisited.Count;
                string sRows = ", " + iCount + (iCount == 1 ? " row" : " rows");
                LiveRegion.say(sNext + ", " + sPosOf + sRows);
            }
            catch (Exception ex)
            {
                ErrorDialog.show(this, "Choose Table", ex.Message);
            }
        }

        // Speak the current table name and row count through the live
        // region. Called whenever a table is freshly selected (via the
        // Select-Table dialog, the dot-prompt 'use' command, or the
        // Control+Tab cycle).
        private void announceTableOpened()
        {
            if (db == null || !db.isOpen() || string.IsNullOrEmpty(db.currentTable)) return;
            // Restore the virtual cursor to the user's last visited
            // (row, column) for this table, if remembered. Falls back
            // to row 1, column 0 if there is no remembered column.
            // The F5 path uses virtResetToTop explicitly because F5
            // is documented as resetting the virtual cursor.
            virtRestoreOrReset();
            int iCount = db.recordCount;
            string sTable = db.currentTable;
            string sMsg = sTable + ", " + iCount + (iCount == 1 ? " row" : " rows");
            LiveRegion.say(sMsg);
        }

        // =====================================================================
        // db.ini override application. Reads [Keys] section pairs and
        // calls KeyMap.overrideKey for each. Reports unknown commands,
        // parse failures, and conflicts in a single startup dialog.
        // =====================================================================
        // applyIniOverrides: read DbDo.inix's [Hotkeys] section and
        // apply each Command Name=Chord, Description line as a
        // DESCRIPTION-ONLY override. The chord field is documentation
        // only -- the actual bindings are compiled into addItem
        // calls; .ini parsing imposes startup overhead and these
        // bindings are not user-configurable in practice. Editing
        // descriptions in the .ini and restarting picks up the new
        // wording without a rebuild, which is the workflow we want.
        //
        // Each line's part after the first comma (that isn't followed
        // by " or " for alternate-chord syntax) becomes the command's
        // status-bar / key-describer text via KeyMap.dCommandToSummary.
        //
        // The historical [Keys] section name is also accepted, for
        // any older DbDo.inix files; the modern section is [Hotkeys]
        //.
        private void applyIniOverrides()
        {
            string sIniPath = Path.Combine(
                Path.GetDirectoryName(Application.ExecutablePath) ?? ".",
                "DbDo.inix");
            if (!File.Exists(sIniPath)) return;

            string[] aLines = null;
            try { aLines = File.ReadAllLines(sIniPath); } catch { return; }

            bool bInHotkeys = false;
            foreach (string sLine in aLines)
            {
                string sTrim = sLine.Trim();
                if (sTrim.Length == 0) continue;
                if (sTrim.StartsWith(";") || sTrim.StartsWith("#")) continue;
                if (sTrim.StartsWith("["))
                {
                    bInHotkeys = sTrim.Equals("[Hotkeys]", StringComparison.OrdinalIgnoreCase)
                                 || sTrim.Equals("[Keys]", StringComparison.OrdinalIgnoreCase);
                    continue;
                }
                if (!bInHotkeys) continue;
                int iEq = sTrim.IndexOf('=');
                if (iEq <= 0) continue;
                string sCommand = sTrim.Substring(0, iEq).Trim();
                string sRest    = sTrim.Substring(iEq + 1).Trim();
                // Extract description after the first chord/description
                // separator comma. If no comma, the line is chord-only
                // (no description override) and we skip.
                int iComma = findChordCommaSplit(sRest);
                if (iComma <= 0) continue;
                string sDescr = sRest.Substring(iComma + 1).Trim();
                if (sDescr.EndsWith(".")) sDescr = sDescr.Substring(0, sDescr.Length - 1);
                if (!string.IsNullOrEmpty(sDescr))
                    KeyMap.dCommandToSummary[sCommand] = sDescr;
            }
        }

        // findChordCommaSplit: locate the comma that separates the
        // chord from the description. Skip any comma immediately
        // followed by " or " (alternate-chord syntax for the
        // Hotkeys.ini). Returns -1 if no separator comma is present.
        private static int findChordCommaSplit(string sRest)
        {
            int i = 0;
            while (i < sRest.Length)
            {
                int iComma = sRest.IndexOf(',', i);
                if (iComma < 0) return -1;
                int j = iComma + 1;
                while (j < sRest.Length && char.IsWhiteSpace(sRest[j])) j++;
                if (j + 2 < sRest.Length
                    && (sRest[j] == 'o' || sRest[j] == 'O')
                    && (sRest[j+1] == 'r' || sRest[j+1] == 'R')
                    && char.IsWhiteSpace(sRest[j+2]))
                {
                    i = iComma + 1;
                    continue;
                }
                return iComma;
            }
            return -1;
        }

        // =====================================================================
        // Session persistence: DbDo.inix stores the last database file
        // opened and the last table within it. On launch with no
        // command-line arguments specifying a different file, the
        // saved database is reopened automatically and the saved
        // table is selected.
        //
        // The [Session] section is a simple key=value store managed by
        // IniSession (below). It coexists with the [Keys] and
        // [General] sections in the same DbDo.inix file. Writing
        // preserves other sections; we only rewrite the [Session]
        // block.
        //
        // Save points:
        //   - After Open-Database succeeds (sets lastDatabase, clears lastTable)
        //   - After Select-Table succeeds (sets lastTable)
        //   - On Close-Database (clears both)
        //   - On form close (final flush, in case earlier writes were missed)
        // =====================================================================
        public static class IniSession
        {
            // Session state -- the user's last-opened database and
            // table -- is stored in a user-writable location so it
            // survives across launches even when DbDo.exe lives in
            // a read-only directory (Program Files, network share,
            // user-locked install).
            //
            // Location: %LOCALAPPDATA%\DbDo\DbDo.inix. Created on
            // first write. Read order on launch: if the per-user
            // file exists, use it; otherwise consult the EXE-dir
            // DbDo.inix for legacy installs.
            //
            // Why per-user: Program Files write attempts get UAC-
            // virtualized into VirtualStore (silently, sometimes,
            // depending on the process manifest), or fail outright
            // when running elevated, or succeed-then-vanish across
            // user accounts. Per-user is the only reliable answer.
            //
            // The [Keys] section and [General] uiMode setting still
            // live next to the EXE in the deployed DbDo.inix -- those
            // are configuration shipped with the install, not user
            // session state. Only [Session] migrated here.
            private static string iniPath()
            {
                string sBase = Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData);
                if (string.IsNullOrEmpty(sBase))
                {
                    // Extremely unusual: %LOCALAPPDATA% undefined.
                    // Fall back to EXE dir so we at least try.
                    return Path.Combine(
                        Path.GetDirectoryName(Application.ExecutablePath) ?? ".",
                        "DbDo.inix");
                }
                string sDir = Path.Combine(sBase, "DbDo");
                try { if (!Directory.Exists(sDir)) Directory.CreateDirectory(sDir); }
                catch { }
                return Path.Combine(sDir, "DbDo.inix");
            }

            // Legacy read fallback: an older DbDo may have written
            // the [Session] section next to the EXE. If the per-user
            // file is absent or doesn't have a Session value, look
            // there too.
            private static string legacyIniPath()
            {
                return Path.Combine(
                    Path.GetDirectoryName(Application.ExecutablePath) ?? ".",
                    "DbDo.inix");
            }

            public static string read(string sKey)
            {
                return read("Session", sKey);
            }

            // Read a key from any section in the per-user ini.
            // Falls back to the legacy EXE-dir ini if the per-user
            // file has no value. Used by IniSession for [Session]
            // and by IniFolders for [Folders]; both share the
            // same physical file.
            public static string read(string sSection, string sKey)
            {
                string sResult = readFrom(iniPath(), sSection, sKey);
                if (!string.IsNullOrEmpty(sResult)) return sResult;
                return readFrom(legacyIniPath(), sSection, sKey);
            }

            private static string readFrom(string sPath, string sSection, string sKey)
            {
                if (!File.Exists(sPath)) return "";
                try
                {
                    foreach (InixCodec.Section sec in InixCodec.read(sPath))
                    {
                        if (!string.Equals(sec.Name, sSection, StringComparison.OrdinalIgnoreCase)) continue;
                        string sFound = sec.get(sKey);
                        if (sFound == null) return "";
                        if (sFound.IndexOf('\n') < 0) sFound = sFound.Trim();
                        return sFound;
                    }
                }
                catch { }
                return "";
            }

            // Write to the per-user file. Creates DbDo.inix in
            // %LOCALAPPDATA%\DbDo\ if absent. Preserves any other
            // sections that may already exist. Writes the [Session]
            // section, replacing the key if present, adding it if
            // not, removing it if value is empty.
            public static void write(string sKey, string sValue)
            {
                write("Session", sKey, sValue);
            }

            // Write a key=value into any section of the per-user
            // ini. Preserves any other sections that may already
            // exist. Removes the key if value is empty.
            public static void write(string sSection, string sKey, string sValue)
            {
                if (!InixCodec.writeValue(iniPath(), sSection, sKey, sValue))
                {
                    try { DbDoLog.write("IniSession.write FAILED: " + iniPath()); } catch { }
                }
            }

            public static string lastDatabase { get { return read("LastDatabase"); } set { write("LastDatabase", value); } }
            public static string lastTable    { get { return read("LastTable");    } set { write("LastTable",    value); } }

            // Upper bound on any history (queries, searches, recent
            // files) and the loop ceiling for clearing stale slots
            // when the count shrinks.
            public const int HistoryCeiling = 100;

            // historyCount: how many entries each history keeps,
            // from [General] historyCount in DbDo.inix. Defaults to
            // 10 -- the common recent-list length (Windows MRU and
            // most editors) and short enough for a screen-reader
            // user to arrow through quickly. Clamped to 1..100.
            public static int historyCount()
            {
                string s = read("General", "HistoryCount");
                int i;
                if (!string.IsNullOrEmpty(s) && int.TryParse(s.Trim(), out i)
                    && i >= 1 && i <= HistoryCeiling) return i;
                return 10;
            }
        }

        // =====================================================================
        // QueryHistory: the custom SQL statements run via Query
        // (Control+Q), persisted to the [RecentQuery] section of
        // DbDo.inix as q1..qN with q1 the most recent. Re-running a
        // statement moves it to the front rather than duplicating it.
        // Query History (Alt+Shift+Q) shows the list to pick from.
        // Multi-line statements survive the round-trip because
        // InixCodec.writeValue fences any value that spans lines or
        // contains '=' (which most WHERE clauses do).
        // =====================================================================
        public static class QueryHistory
        {
            public const string Section = "RecentQuery";

            // The stored statements, most recent first; empty if none.
            public static List<string> load()
            {
                int iMax = IniSession.historyCount();
                List<string> l = new List<string>();
                for (int i = 1; i <= iMax; i++)
                {
                    string s = IniSession.read(Section, "q" + i);
                    if (string.IsNullOrEmpty(s)) break;
                    l.Add(s);
                }
                return l;
            }

            // Record a statement, moving an identical one to the front
            // rather than duplicating it; truncates to the history count.
            public static void record(string sSql)
            {
                if (string.IsNullOrEmpty(sSql)) return;
                string sTrim = sSql.Trim();
                if (sTrim.Length == 0) return;
                List<string> l = load();
                l.RemoveAll(delegate(string s)
                {
                    return string.Equals(s.Trim(), sTrim, StringComparison.OrdinalIgnoreCase);
                });
                l.Insert(0, sTrim);
                int iMax = IniSession.historyCount();
                if (l.Count > iMax) l.RemoveRange(iMax, l.Count - iMax);
                save(l);
            }

            // Serialize back, clearing stale slots beyond the new length.
            public static void save(List<string> l)
            {
                for (int i = 1; i <= l.Count; i++)
                    IniSession.write(Section, "q" + i, l[i - 1] ?? "");
                // Clear slots left by a previously larger history,
                // stopping at the first already-empty one (entries are
                // contiguous), so a shrunk count cannot resurface later.
                for (int i = l.Count + 1; i <= IniSession.HistoryCeiling; i++)
                {
                    if (string.IsNullOrEmpty(IniSession.read(Section, "q" + i))) break;
                    IniSession.write(Section, "q" + i, "");
                }
            }
        }

        // =====================================================================
        // SearchHistory: per-family recent-search list persisted to
        // DbDo.inix. Each family has its own section ([RecentJump],
        // [RecentFind], [RecentFindRegex]) holding up to 10 entries.
        // Each entry is a (term, caseSensitive) pair stored as two
        // keys: termN and caseN where N is 1..10. Entry 1 is the
        // most recent.
        //
        // The dialog shows the listbox of terms; selecting one
        // auto-populates the text input AND auto-sets the case-
        // sensitive checkbox to how the term was last used.
        //
        // The list is move-to-front: if the user re-uses a term
        // it shifts to the top rather than appearing twice.
        // =====================================================================
        public static class SearchHistory
        {
            public const string SectionJump    = "RecentJump";
            public const string SectionFind    = "RecentFind";
            public const string SectionRegex   = "RecentFindRegex";
            public const string SectionGoTo    = "RecentGoTo";
            public const string SectionReplace = "RecentReplace";
            public const string SectionReplaceWith = "RecentReplaceWith";

            // lastText: the most recent saved input for a section
            // (entries are stored newest-first), or "" when none.
            public static string lastText(string sSection)
            {
                List<Entry> l = load(sSection);
                return (l.Count > 0) ? (l[0].sTerm ?? "") : "";
            }
            // Result of a load: parallel lists of terms and the
            // case-sensitive flags that were active when each term
            // was used.
            public class Entry
            {
                public string sTerm;
                public bool   bCaseSensitive;
            }

            // Load the recent list for the given family section.
            // Returns an empty list if the section is absent.
            public static List<Entry> load(string sSection)
            {
                int iMax = IniSession.historyCount();
                List<Entry> l = new List<Entry>();
                for (int i = 1; i <= iMax; i++)
                {
                    string sTerm = IniSession.read(sSection, "term" + i);
                    if (string.IsNullOrEmpty(sTerm)) break;
                    string sCase = IniSession.read(sSection, "case" + i);
                    Entry e = new Entry();
                    e.sTerm = sTerm;
                    e.bCaseSensitive = !string.IsNullOrEmpty(sCase)
                                    && (sCase.Equals("Y", StringComparison.OrdinalIgnoreCase)
                                     || sCase.Equals("Yes", StringComparison.OrdinalIgnoreCase)
                                     || sCase.Equals("1", StringComparison.Ordinal)
                                     || sCase.Equals("True", StringComparison.OrdinalIgnoreCase));
                    l.Add(e);
                }
                return l;
            }

            // Record a search. Moves the term to the front if it
            // already exists (with the new caseSensitive value),
            // otherwise prepends. Truncates to the history count.
            public static void record(string sSection, string sTerm, bool bCaseSensitive)
            {
                if (string.IsNullOrEmpty(sTerm)) return;
                List<Entry> l = load(sSection);
                // Remove any existing entry with the same term
                // (case-insensitive comparison; the case-sensitivity
                // setting is per-search not per-term identity).
                l.RemoveAll(delegate(Entry e)
                {
                    return string.Equals(e.sTerm, sTerm, StringComparison.OrdinalIgnoreCase);
                });
                Entry entryNew = new Entry();
                entryNew.sTerm = sTerm;
                entryNew.bCaseSensitive = bCaseSensitive;
                l.Insert(0, entryNew);
                int iMax = IniSession.historyCount();
                if (l.Count > iMax) l.RemoveRange(iMax, l.Count - iMax);
                save(sSection, l);
            }

            // Serialize the list back to the ini section. Clears
            // any stale entries beyond the new list's length.
            public static void save(string sSection, List<Entry> l)
            {
                for (int i = 1; i <= l.Count; i++)
                {
                    IniSession.write(sSection, "term" + i, l[i - 1].sTerm ?? "");
                    IniSession.write(sSection, "case" + i, l[i - 1].bCaseSensitive ? "Y" : "N");
                }
                // Clear slots from a previously larger history, stopping
                // at the first already-empty term.
                for (int i = l.Count + 1; i <= IniSession.HistoryCeiling; i++)
                {
                    if (string.IsNullOrEmpty(IniSession.read(sSection, "term" + i))) break;
                    IniSession.write(sSection, "term" + i, "");
                    IniSession.write(sSection, "case" + i, "");
                }
            }
        }

        // =====================================================================
        // RecentFiles: persists up to 10 recently opened database
        // file paths plus per-file state (last-active table, and
        // per-table filter / sort / position). All stored in the
        // per-user DbDo.inix, one section per file:
        //
        //   [RecentFile1]                  <- index 1 = most recent
        //   path        = C:\path\to\file.db
        //   lastTable   = transactions
        //   t1_name     = transactions     <- per-table state, indexed
        //   t1_filter   = LOWER(memo) LIKE '%coffee%'
        //   t1_sort     = updated DESC
        //   t1_position = 47
        //   t2_name     = categories
        //   t2_position = 12
        //
        //   [RecentFile2] ... etc
        //
        // The "table state" is stored under indexed t1_/t2_/... keys
        // rather than the table name directly, because table names
        // can contain characters that are inconvenient for ini keys
        // (spaces, brackets, equals signs). The per-section index
        // is rebuilt on each save by enumerating the in-memory
        // dictionary.
        //
        // Restore strategy: when reopening a recent file, attempt
        // to set lastTable; if that table no longer exists, silently
        // fall back to the database's first table. For each table
        // we have state for, try to apply filter / sort / position;
        // any individual failure (column missing, position out of
        // range) is silently skipped.
        // =====================================================================
        public static class RecentFiles
        {
            public class TableState
            {
                public string sName;
                public string sFilter;
                public string sSort;
                public int    iPosition;
                // Last virtual-cell column name visited in this table
                // before the session ended. Restored when the file is
                // reopened from the Recent Files dialog.
                public string sVirtualColumn = "";
                // User-set comma-separated list of columns to show in
                // the listview, per the Select Columns command
                // (Alt+S). Empty string means "use the default rule-
                // based selection." Persisted to DbDo.inix as
                // t<n>_selectlist under the RecentFile section.
                public string sSelectList = "";
            }
            public class FileState
            {
                public string sPath;
                public string sLastTable;
                public Dictionary<string, TableState> dTables = new Dictionary<string, TableState>(StringComparer.OrdinalIgnoreCase);
            }

            private static string sectionFor(int iIndex) { return "RecentFile" + iIndex; }

            // Load all recent file entries in recency order. Empty
            // section breaks the loop -- gaps mean "no more recents."
            public static List<FileState> loadAll()
            {
                int iMax = IniSession.historyCount();
                List<FileState> l = new List<FileState>();
                for (int i = 1; i <= iMax; i++)
                {
                    string sPath = IniSession.read(sectionFor(i), "path");
                    if (string.IsNullOrEmpty(sPath)) break;
                    FileState f = loadSection(sectionFor(i));
                    if (f != null) l.Add(f);
                }
                return l;
            }

            private static FileState loadSection(string sSection)
            {
                string sPath = IniSession.read(sSection, "path");
                if (string.IsNullOrEmpty(sPath)) return null;
                FileState f = new FileState();
                f.sPath = sPath;
                f.sLastTable = IniSession.read(sSection, "LastTable") ?? "";
                // Enumerate t1_, t2_, ... up to a sensible cap (32
                // tables-per-file is more than enough for typical use).
                for (int t = 1; t <= 32; t++)
                {
                    string sName = IniSession.read(sSection, "t" + t + "_name");
                    if (string.IsNullOrEmpty(sName)) break;
                    TableState ts = new TableState();
                    ts.sName     = sName;
                    ts.sFilter   = IniSession.read(sSection, "t" + t + "_filter");
                    ts.sSort     = IniSession.read(sSection, "t" + t + "_sort");
                    string sPos  = IniSession.read(sSection, "t" + t + "_position");
                    int iPos;
                    ts.iPosition = (!string.IsNullOrEmpty(sPos) && int.TryParse(sPos, out iPos)) ? iPos : 1;
                    ts.sVirtualColumn = IniSession.read(sSection, "t" + t + "_vcol") ?? "";
                    ts.sSelectList    = IniSession.read(sSection, "t" + t + "_selectlist") ?? "";
                    f.dTables[sName] = ts;
                }
                return f;
            }

            // Find an existing entry by path (case-insensitive), or
            // null if not present.
            public static FileState findByPath(List<FileState> l, string sPath)
            {
                if (l == null || string.IsNullOrEmpty(sPath)) return null;
                foreach (FileState f in l)
                {
                    if (string.Equals(f.sPath, sPath, StringComparison.OrdinalIgnoreCase))
                        return f;
                }
                return null;
            }

            // Promote the file to the front of the recent list,
            // updating its state in place. Truncates to the history count.
            public static void recordOpen(string sPath)
            {
                if (string.IsNullOrEmpty(sPath)) return;
                List<FileState> l = loadAll();
                FileState existing = findByPath(l, sPath);
                if (existing != null) l.Remove(existing);
                FileState f = existing ?? new FileState();
                f.sPath = sPath;
                l.Insert(0, f);
                int iMax = IniSession.historyCount();
                if (l.Count > iMax) l.RemoveRange(iMax, l.Count - iMax);
                saveAll(l);
            }

            // Update a single table's state inside a file. The file
            // entry is found by path; if absent it's created (and
            // promoted to the front via recordOpen).
            public static void recordTableState(string sPath, string sTable, string sFilter, string sSort, int iPosition, string sVirtualColumn, string sSelectList)
            {
                if (string.IsNullOrEmpty(sPath) || string.IsNullOrEmpty(sTable)) return;
                List<FileState> l = loadAll();
                FileState f = findByPath(l, sPath);
                if (f == null)
                {
                    recordOpen(sPath);
                    l = loadAll();
                    f = findByPath(l, sPath);
                    if (f == null) return;
                }
                TableState ts;
                if (!f.dTables.TryGetValue(sTable, out ts))
                {
                    ts = new TableState(); ts.sName = sTable;
                    f.dTables[sTable] = ts;
                }
                ts.sFilter        = sFilter ?? "";
                ts.sSort          = sSort   ?? "";
                ts.iPosition      = iPosition;
                ts.sVirtualColumn = sVirtualColumn ?? "";
                ts.sSelectList    = sSelectList ?? "";
                f.sLastTable = sTable;
                saveAll(l);
            }

            // Persist every entry in a per-table cache to the given
            // file's section, with one ini write at the end. This is
            // what the form's OnFormClosing path calls to capture
            // every visited table's state in one shot, rather than
            // calling recordTableState (with its loadAll + saveAll
            // pair) per table.
            public static void recordAllTableStates(string sPath, string sCurrentTable,
                IEnumerable<KeyValuePair<string, DbDoManager.TableSettings>> cacheEntries)
            {
                if (string.IsNullOrEmpty(sPath) || cacheEntries == null) return;
                List<FileState> l = loadAll();
                FileState f = findByPath(l, sPath);
                if (f == null)
                {
                    recordOpen(sPath);
                    l = loadAll();
                    f = findByPath(l, sPath);
                    if (f == null) return;
                }
                foreach (KeyValuePair<string, DbDoManager.TableSettings> kvCache in cacheEntries)
                {
                    string sTable = kvCache.Key;
                    DbDoManager.TableSettings cache = kvCache.Value;
                    if (string.IsNullOrEmpty(sTable) || cache == null) continue;
                    TableState ts;
                    if (!f.dTables.TryGetValue(sTable, out ts))
                    {
                        ts = new TableState(); ts.sName = sTable;
                        f.dTables[sTable] = ts;
                    }
                    ts.sFilter        = cache.sFilter         ?? "";
                    ts.sSort          = cache.sSort           ?? "";
                    ts.iPosition      = cache.iAbsolutePosition;
                    ts.sVirtualColumn = cache.sVirtualColumn  ?? "";
                    ts.sSelectList    = cache.sSelectList     ?? "";
                }
                if (!string.IsNullOrEmpty(sCurrentTable)) f.sLastTable = sCurrentTable;
                saveAll(l);
            }

            // Persist the entire in-memory list. Older slots beyond
            // the current list size are cleared.
            public static void saveAll(List<FileState> l)
            {
                // Write at least the original 10 slots so lowering the
                // history count below 10 still clears the stale ones; a
                // higher count widens the range to persist every entry.
                int iSpan = IniSession.historyCount();
                if (iSpan < 10) iSpan = 10;
                for (int i = 1; i <= iSpan; i++)
                {
                    string sSection = sectionFor(i);
                    if (i <= l.Count)
                    {
                        FileState f = l[i - 1];
                        IniSession.write(sSection, "path", f.sPath ?? "");
                        IniSession.write(sSection, "LastTable", f.sLastTable ?? "");
                        // Write each table's state under sequential t1_ / t2_ keys.
                        int iT = 1;
                        foreach (KeyValuePair<string, TableState> kv in f.dTables)
                        {
                            if (iT > 32) break;
                            TableState ts = kv.Value;
                            IniSession.write(sSection, "t" + iT + "_name",     ts.sName ?? "");
                            IniSession.write(sSection, "t" + iT + "_filter",   ts.sFilter ?? "");
                            IniSession.write(sSection, "t" + iT + "_sort",     ts.sSort ?? "");
                            IniSession.write(sSection, "t" + iT + "_position", ts.iPosition.ToString());
                            IniSession.write(sSection, "t" + iT + "_vcol",     ts.sVirtualColumn ?? "");
                            IniSession.write(sSection, "t" + iT + "_selectlist", ts.sSelectList ?? "");
                            iT++;
                        }
                        // Clear unused indexes from prior writes (up to 32).
                        for (int j = iT; j <= 32; j++)
                        {
                            IniSession.write(sSection, "t" + j + "_name", "");
                            IniSession.write(sSection, "t" + j + "_filter", "");
                            IniSession.write(sSection, "t" + j + "_sort", "");
                            IniSession.write(sSection, "t" + j + "_position", "");
                            IniSession.write(sSection, "t" + j + "_vcol", "");
                            IniSession.write(sSection, "t" + j + "_selectlist", "");
                        }
                    }
                    else
                    {
                        // Empty slot: clear path so loadAll's
                        // empty-section-breaks-the-loop semantic
                        // works. Don't bother zeroing every key.
                        IniSession.write(sSection, "path", "");
                        IniSession.write(sSection, "LastTable", "");
                    }
                }
            }
        }

        // =====================================================================
        // IniFolders: persists the last-used folder for each kind
        // of file dialog (Open, Save-As, Import, Export), so the
        // next invocation of the same dialog opens in the same
        // place the user worked in last. Uses the same per-user
        // DbDo.inix that IniSession uses, but a [Folders] section.
        //
        // Kinds:
        //   open       -- New-Database, Open-Database, Save-DatabaseAs,
        //                 Backup-Database. All four operate on
        //                 whole-database files; one shared "open"
        //                 folder is more useful than four separate
        //                 ones because users typically keep all
        //                 their databases together.
        //   import     -- Import-Data source files (Markdown).
        //   export     -- Export-Data target files.
        //
        // If no remembered value exists, callers fall back to
        // (in order): the folder of the currently-open database,
        // the user's Documents folder.
        // =====================================================================
        public static class IniFolders
        {
            public static string openFolder
            {
                get { return IniSession.read("Folders", "open"); }
                set { IniSession.write("Folders", "open", value ?? ""); }
            }
            public static string importFolder
            {
                get { return IniSession.read("Folders", "import"); }
                set { IniSession.write("Folders", "import", value ?? ""); }
            }
            public static string exportFolder
            {
                get { return IniSession.read("Folders", "export"); }
                set { IniSession.write("Folders", "export", value ?? ""); }
            }

            // bestDirectory: choose a sensible initial directory for
            // a dialog, given a preferred remembered folder, the
            // folder of the currently-open database (if any), and
            // the user's Documents folder as last resort. Returns
            // the first option that actually exists on disk.
            public static string bestDirectory(string sRemembered, string sFallbackDbPath)
            {
                if (!string.IsNullOrEmpty(sRemembered) && Directory.Exists(sRemembered))
                    return sRemembered;
                if (!string.IsNullOrEmpty(sFallbackDbPath))
                {
                    string sParent = Path.GetDirectoryName(sFallbackDbPath);
                    if (!string.IsNullOrEmpty(sParent) && Directory.Exists(sParent))
                        return sParent;
                }
                try
                {
                    string sDocs = Environment.GetFolderPath(Environment.SpecialFolder.MyDocuments);
                    if (!string.IsNullOrEmpty(sDocs) && Directory.Exists(sDocs))
                        return sDocs;
                }
                catch { }
                return ""; // let Windows pick
            }
        }

        // =====================================================================
        // FILE menu handlers
        // =====================================================================
        // The field types offered when defining a table, alphabetical.
        // These double as the lookups seed (src 'DbDo', fld 'type') so
        // later picklists can draw the same vocabulary from lookups.
        private static readonly string[] c_aFieldTypes = new string[]
        { "BLOB", "BOOLEAN", "INTEGER", "REAL", "TEXT", "TEXTLINE", "TEXTMARKDOWN", "TEXTMEMO", "TEXTTIME" };
        private const int c_iMaxNewFields = 10;

        // bPromptTableDefinition: the shared definition form for New
        // Database and Add Table. A table name plus up to ten field
        // slots, each a name textbox and a type pick-combo (the
        // Control+F2-style picklist). Blank field names are unused
        // slots. Names normalize to lower_snake_case. Returns false
        // on cancel or when nothing valid was entered.
        private bool bPromptTableDefinition(string sTitle, out string sTableName, out List<string[]> lFieldDefs)
        {
            sTableName = "";
            lFieldDefs = new List<string[]>();
            using (LbcDialog dlg = new LbcDialog(sTitle, this))
            {
                dlg.addLabel("&Table name (plural noun, e.g. contacts):");
                TextBox tbTable = dlg.addTextBox("", "Lower-case plural noun; the primary key becomes its singular plus _id.");
                List<TextBox> lNames = new List<TextBox>();
                List<ComboBox> lTypes = new List<ComboBox>();
                for (int i = 1; i <= c_iMaxNewFields; i++)
                {
                    dlg.addLabel("Field " + i + " &name (blank if unused):");
                    lNames.Add(dlg.addTextBox("", "Lower_snake_case field name."));
                    lTypes.Add(dlg.addComboPickBox("Field " + i + " t&ype:", c_aFieldTypes, "TEXTLINE",
                        "Pick the field's type."));
                }
                string sBtn = dlg.runWithButtons(new string[] { "OK", "Cancel" });
                if (!string.Equals(sBtn, "OK", StringComparison.OrdinalIgnoreCase)) return false;
                sTableName = sNormalizeIdentifier(tbTable.Text);
                for (int i = 0; i < lNames.Count; i++)
                {
                    string sN = sNormalizeIdentifier(lNames[i].Text);
                    if (sN.Length == 0) continue;
                    string sT = lTypes[i].SelectedItem != null ? lTypes[i].SelectedItem.ToString() : "TEXTLINE";
                    lFieldDefs.Add(new string[] { sN, sT });
                }
            }
            if (string.IsNullOrEmpty(sTableName))
            { LiveRegion.say("No table name entered"); return false; }
            if (lFieldDefs.Count == 0)
            { LiveRegion.say("No fields entered"); return false; }
            return true;
        }

        // sNormalizeIdentifier: trim, spaces and hyphens to
        // underscores, lower-case; strip anything else non-word.
        private static string sNormalizeIdentifier(string sRaw)
        {
            if (sRaw == null) return "";
            StringBuilder sb = new StringBuilder();
            foreach (char ch in sRaw.Trim().ToLowerInvariant())
            {
                if (char.IsLetterOrDigit(ch) || ch == '_') sb.Append(ch);
                else if (ch == ' ' || ch == '-') sb.Append('_');
            }
            return sb.ToString();
        }

        // lStandardTableDdl: the CREATE statements for one table in
        // the standard shape -- the user's distinct fields surrounded
        // by the standard columns: <singular>_id, added, edited
        // BEFORE them; notes, tags, look, prm, marked AFTER. look is
        // a skip-empty concatenation of every distinct field; prm is
        // the positional concatenation; the edited trigger bumps only
        // on a real data change; the prm index is UNIQUE.
        private static List<string> lStandardTableDdl(string sTable, List<string[]> lFieldDefs)
        {
            string sSingular = sTable.EndsWith("s") ? sTable.Substring(0, sTable.Length - 1) : sTable;
            string sPk = sSingular + "_id";
            List<string> lCols = new List<string>();
            foreach (string[] aF in lFieldDefs) lCols.Add(aF[0]);

            StringBuilder sbLook = new StringBuilder("rtrim(");
            StringBuilder sbPrm = new StringBuilder();
            for (int i = 0; i < lCols.Count; i++)
            {
                string sC = "\"" + lCols[i] + "\"";
                if (i > 0) { sbLook.Append(" || "); sbPrm.Append("||'|'||"); }
                sbLook.Append("iif(" + sC + " IS NOT NULL AND length(CAST(" + sC
                    + " AS TEXT))>0, CAST(" + sC + " AS TEXT) || ' | ', '')");
                sbPrm.Append("coalesce(CAST(" + sC + " AS TEXT),'')");
            }
            sbLook.Append(", ' | ')");

            StringBuilder sbCreate = new StringBuilder();
            sbCreate.Append("CREATE TABLE \"" + sTable + "\" (");
            sbCreate.Append("\"" + sPk + "\" INTEGER PRIMARY KEY AUTOINCREMENT, ");
            sbCreate.Append("added TEXTTIME NOT NULL DEFAULT CURRENT_TIMESTAMP, ");
            sbCreate.Append("edited TEXTTIME NOT NULL DEFAULT CURRENT_TIMESTAMP, ");
            foreach (string[] aF in lFieldDefs)
                sbCreate.Append("\"" + aF[0] + "\" " + aF[1] + ", ");
            sbCreate.Append("notes TEXTMARKDOWN, tags TEXTMEMO, ");
            sbCreate.Append("look TEXT GENERATED ALWAYS AS (" + sbLook + ") STORED, ");
            sbCreate.Append("prm TEXT GENERATED ALWAYS AS (" + sbPrm + ") STORED, ");
            sbCreate.Append("marked INTEGER NOT NULL DEFAULT 0)");

            List<string> lTrigCols = new List<string>(lCols);
            lTrigCols.Add("notes"); lTrigCols.Add("tags");
            List<string> lOf = new List<string>();
            List<string> lWhen = new List<string>();
            foreach (string sC in lTrigCols)
            {
                lOf.Add("\"" + sC + "\"");
                lWhen.Add("OLD.\"" + sC + "\" IS NOT NEW.\"" + sC + "\"");
            }
            string sTrigger = "CREATE TRIGGER \"trg_" + sTable + "_edited\" AFTER UPDATE OF "
                + string.Join(", ", lOf.ToArray()) + " ON \"" + sTable
                + "\" FOR EACH ROW WHEN " + string.Join(" OR ", lWhen.ToArray())
                + " BEGIN UPDATE \"" + sTable + "\" SET edited = CURRENT_TIMESTAMP WHERE \""
                + sPk + "\" = NEW.\"" + sPk + "\"; END";

            List<string> lDdl = new List<string>();
            lDdl.Add(sbCreate.ToString());
            lDdl.Add(sTrigger);
            lDdl.Add("CREATE UNIQUE INDEX \"idx_" + sTable + "_prm\" ON \"" + sTable + "\" (prm)");
            return lDdl;
        }

        // lInfraDdl: the builtin maps and lookups tables every DbDo
        // database carries, plus the lookups seed rows -- including
        // the field-type vocabulary, so future Add Table picklists
        // can draw types from lookups.
        private static List<string> lInfraDdl(bool bMaps, bool bLookups)
        {
            List<string> lDdl = new List<string>();
            if (bMaps)
            {
                List<string[]> lMapFields = new List<string[]>();
                foreach (string sC in new string[] { "tbl1", "prm1", "kind", "tbl2", "prm2" })
                    lMapFields.Add(new string[] { sC, "TEXTLINE" });
                lDdl.AddRange(lStandardTableDdl("maps", lMapFields));
                lDdl.Add("CREATE INDEX idx_maps_side1 ON maps (tbl1, prm1)");
                lDdl.Add("CREATE INDEX idx_maps_side2 ON maps (tbl2, prm2)");
            }
            if (bLookups)
            {
                List<string[]> lLkFields = new List<string[]>();
                lLkFields.Add(new string[] { "src", "TEXTLINE" });
                lLkFields.Add(new string[] { "tbl", "TEXTLINE" });
                lLkFields.Add(new string[] { "fld", "TEXTLINE" });
                lLkFields.Add(new string[] { "val", "TEXTLINE" });
                lLkFields.Add(new string[] { "ordinal", "INTEGER" });
                lLkFields.Add(new string[] { "descrip", "TEXTMEMO" });
                lLkFields.Add(new string[] { "url", "TEXTLINE" });
                lDdl.AddRange(lStandardTableDdl("lookups", lLkFields));
                int iOrd = 0;
                foreach (string sType in c_aFieldTypes)
                {
                    iOrd++;
                    lDdl.Add("INSERT INTO lookups (src, tbl, fld, val, ordinal) VALUES "
                        + "('DbDo', '*', 'type', '" + sType + "', " + iOrd + ")");
                }
                // Seed a generic maps.kind vocabulary so F4 offers sensible
                // association kinds when the user adds a mapping in a new
                // database. Domain databases (e.g. the NFB convention) seed
                // their own richer set; the user can add to or replace these.
                if (bMaps)
                {
                    int iKindOrd = 0;
                    foreach (string sKind in new string[] { "related_to", "part_of", "located_at", "member_of", "affiliated_with" })
                    {
                        iKindOrd++;
                        lDdl.Add("INSERT INTO lookups (src, tbl, fld, val, ordinal) VALUES "
                            + "('DbDo', 'maps', 'kind', '" + sKind + "', " + iKindOrd + ")");
                    }
                }
            }
            return lDdl;
        }

        private void fileNewClicked(object sender, EventArgs evArgs)
        {
            using (SaveFileDialog dlgFile = new SaveFileDialog())
            {
                dlgFile.Title = "New Database";
                prepareFileDialog(dlgFile);
                dlgFile.Filter = "SQLite Database (*.db)|*.db|All Files (*.*)|*.*";
                dlgFile.DefaultExt = "db";
                // Initial folder: last folder the user opened or saved
                // a database from, falling back to the current
                // database's folder, then Documents.
                string sCurDb = (db != null) ? db.filePath : null;
                dlgFile.InitialDirectory = IniFolders.bestDirectory(IniFolders.openFolder, sCurDb);
                if (dlgFile.ShowDialog(this) != DialogResult.OK) return;
                IniFolders.openFolder = Path.GetDirectoryName(dlgFile.FileName);

                string sTableName;
                List<string[]> lFieldDefs;
                if (!bPromptTableDefinition("New Database: First Table", out sTableName, out lFieldDefs))
                    return;
                try
                {
                    if (File.Exists(dlgFile.FileName)) File.Delete(dlgFile.FileName);
                    using (FileStream fs = File.Create(dlgFile.FileName)) { }
                    db.openDatabase(dlgFile.FileName, null, false);
                    foreach (string sSql in lStandardTableDdl(sTableName, lFieldDefs))
                        db.invokeSql(sSql, null);
                    foreach (string sSql in lInfraDdl(true, true))
                        db.invokeSql(sSql, null);
                    db.refreshTableList();
                    db.selectTable(sTableName);
                    invokeRefresh();
                    LiveRegion.say("Database created with tables " + sTableName + ", maps, and lookups");
                }
                catch (Exception ex)
                {
                    ErrorDialog.show(this, "New Database", ex.Message);
                }
            }
        }

        // Add Table (File menu): define one more table, in the same
        // standard shape, inside the OPEN database. Creates the maps
        // and lookups infrastructure too when the database predates
        // it.
        private void fileAddTableClicked(object sender, EventArgs evArgs)
        {
            if (db == null || !db.isOpen())
            { LiveRegion.say("No database open"); return; }
            if (db.readOnly)
            { LiveRegion.say("Database is read-only"); return; }
            string sTableName;
            List<string[]> lFieldDefs;
            if (!bPromptTableDefinition("Add Table", out sTableName, out lFieldDefs)) return;
            try
            {
                bool bHasMaps = false, bHasLookups = false;
                foreach (string sT in db.getTableNames())
                {
                    if (string.Equals(sT, "maps", StringComparison.OrdinalIgnoreCase)) bHasMaps = true;
                    if (string.Equals(sT, "lookups", StringComparison.OrdinalIgnoreCase)) bHasLookups = true;
                    if (string.Equals(sT, sTableName, StringComparison.OrdinalIgnoreCase))
                    {
                        ErrorDialog.show(this, "Add Table", "Table '" + sTableName + "' already exists.");
                        return;
                    }
                }
                foreach (string sSql in lStandardTableDdl(sTableName, lFieldDefs))
                    db.invokeSql(sSql, null);
                foreach (string sSql in lInfraDdl(!bHasMaps, !bHasLookups))
                    db.invokeSql(sSql, null);
                db.refreshTableList();
                db.selectTable(sTableName);
                invokeRefresh();
                LiveRegion.say("Table " + sTableName + " created");
            }
            catch (Exception ex)
            {
                ErrorDialog.show(this, "Add Table", ex.Message);
            }
        }

        // prepareFileDialog: always use the classic Win32 file dialog
        // rather than the Vista-style IFileDialog. Two reasons: (1)
        // screen-reader users generally prefer the older, simpler, more
        // predictable dialog, and a single consistent dialog across every
        // Open/Save is less surprising; (2) the IFileDialog COM modal loop
        // deadlocks against an open ACE OLEDB connection on this STA
        // thread, which would otherwise freeze Open/Save while an
        // Access/Excel/dBASE/Text database is open. AutoUpgradeEnabled =
        // false selects the classic dialog. Applied to every file dialog
        // DbDo raises.
        private void prepareFileDialog(FileDialog dlg)
        {
            dlg.AutoUpgradeEnabled = false;
        }

        private void fileOpenClicked(object sender, EventArgs evArgs)
        {
            using (OpenFileDialog dlgFile = new OpenFileDialog())
            {
                dlgFile.Title = "Open Database";
                prepareFileDialog(dlgFile);
                dlgFile.Filter = "All supported|*.db;*.sqlite;*.sqlite3;*.mdb;*.accdb;*.xlsx;*.xls;*.dbf;*.csv;*.tsv;*.txt;*.inix"
                           + "|SQLite (*.db;*.sqlite;*.sqlite3)|*.db;*.sqlite;*.sqlite3"
                           + "|Access (*.mdb;*.accdb)|*.mdb;*.accdb"
                           + "|Excel (*.xlsx;*.xls)|*.xlsx;*.xls"
                           + "|dBASE (*.dbf)|*.dbf"
                           + "|CSV / Text (*.csv;*.tsv;*.txt)|*.csv;*.tsv;*.txt"
                           + "|Inix record file (*.inix)|*.inix"
                           + "|All Files (*.*)|*.*";
                // Initial folder: last folder the user opened a
                // database from, falling back to the currently-open
                // database's folder, then Documents. If the user
                // already opened a file last session, we also fill
                // in its name as the suggested filename for one-
                // press re-open (rare workflow, but the user is
                // free to clear it).
                string sCurDb = (db != null) ? db.filePath : null;
                dlgFile.InitialDirectory = IniFolders.bestDirectory(IniFolders.openFolder, sCurDb);
                if (dlgFile.ShowDialog(this) != DialogResult.OK) return;
                if (!confirmSaveWorkbookIfDirty()) return;
                IniFolders.openFolder = Path.GetDirectoryName(dlgFile.FileName);
                string sOpenPath = dlgFile.FileName;
                // Inix record files are not an ADO provider type;
                // they convert to a SQLite database alongside the
                // source (<name>.inix.db), which then opens normally.
                if (string.Equals(Path.GetExtension(sOpenPath), ".inix", StringComparison.OrdinalIgnoreCase))
                {
                    try { sOpenPath = importInixRecordFile(sOpenPath); }
                    catch (Exception ex)
                    { ErrorDialog.show(this, "Open Database", "Could not convert the inix file: " + ex.Message); return; }
                }
                // An .xlsx opens for editing through NPOI (no Office): one
                // worksheet is mirrored into a faithful temp .db that
                // becomes the live database, and the workbook origin is
                // remembered so Save Workbook can write data edits back
                // (formulas preserved). This is the standalone-Excel-
                // alternative path; it needs no ACE and no matching Office
                // bitness.
                if (string.Equals(Path.GetExtension(sOpenPath), ".xlsx", StringComparison.OrdinalIgnoreCase))
                {
                    WorkbookOpen wo;
                    try { wo = openWorkbookForEditing(sOpenPath); }
                    catch (Exception ex)
                    { ErrorDialog.show(this, "Open Database", "Could not open the workbook: " + ex.Message); return; }
                    string sPrevTempWb = sManagedTempPath;
                    try { openDatabaseAndApplyState(wo.TempDb, null); }
                    catch (Exception ex)
                    {
                        ErrorDialog.show(this, "Open Database", ex.Message);
                        try { if (File.Exists(wo.TempDb)) File.Delete(wo.TempDb); } catch { }
                        return;
                    }
                    if (!string.IsNullOrEmpty(sPrevTempWb) && !string.Equals(sPrevTempWb, wo.TempDb, StringComparison.OrdinalIgnoreCase))
                    { try { if (File.Exists(sPrevTempWb)) File.Delete(sPrevTempWb); } catch { } }
                    sManagedOriginPath = wo.Origin;   // for Save-As naming
                    sManagedTempPath = wo.TempDb;     // for cleanup
                    sWorkbookOriginPath = wo.Origin;  // set AFTER open (open clears these)
                    sWorkbookSheetName = wo.Sheet;
                    sWorkbookTable = wo.Table;
                    lWorkbookColumns = wo.Columns;
                    LiveRegion.say("Opened workbook " + Path.GetFileName(sOpenPath)
                        + " for editing. Edit data cells; formulas are preserved. Press Control+S to save your changes back to the file.");
                    return;
                }
                // Reapply the per-table sort / filter / position this
                // file was last left with. Without looking up the saved
                // state here, a normal Open Database (as opposed to the
                // Recent Files list) dropped the sort, so the user had
                // to re-sort on every open. State is written on close in
                // OnFormClosing; null is fine for a never-seen file.
                RecentFiles.FileState stOpen = RecentFiles.findByPath(RecentFiles.loadAll(), sOpenPath);
                openDatabaseAndApplyState(sOpenPath, stOpen);
            }
        }

        // openManagedCopyClicked: open a SQLite database as a managed
        // (throwaway) working copy -- the document model. The chosen
        // file is duplicated to a temp .db that becomes the live
        // database, so every edit lands in the copy while the original
        // is left untouched until the user runs Save Database. This is
        // the first concrete step of the in-memory Open / Save As
        // model. The substrate is a temp *file*, not a pure :memory:
        // database, on purpose: the live editing path is ADODB over
        // the ch-werner ODBC driver, which needs a real path to open,
        // and a :memory: database would be private to whatever
        // connection created it. The temp file gives the same
        // open/edit/save semantics while every existing recordset and
        // editing command keeps working unchanged. SQLite sources only;
        // foreign formats (Excel, Access, dBASE, CSV) are brought in by
        // the separate Import command (see importToShell), which builds a
        // fresh DbDo shell rather than mounting a live driver.
        private void openManagedCopyClicked(object sender, EventArgs evArgs)
        {
            using (OpenFileDialog dlgFile = new OpenFileDialog())
            {
                dlgFile.Title = "Open as Managed Copy";
                prepareFileDialog(dlgFile);
                dlgFile.Filter = "SQLite (*.db;*.sqlite;*.sqlite3)|*.db;*.sqlite;*.sqlite3|All Files (*.*)|*.*";
                string sCurDb = (db != null) ? db.filePath : null;
                dlgFile.InitialDirectory = IniFolders.bestDirectory(IniFolders.openFolder, sCurDb);
                if (dlgFile.ShowDialog(this) != DialogResult.OK) return;
                IniFolders.openFolder = Path.GetDirectoryName(dlgFile.FileName);
                string sOrigin = dlgFile.FileName;
                string sExt = Path.GetExtension(sOrigin).TrimStart('.').ToLowerInvariant();
                if (sExt != "db" && sExt != "sqlite" && sExt != "sqlite3")
                {
                    ErrorDialog.show(this, "Open as Managed Copy",
                        "Managed Copy is for SQLite databases (.db, .sqlite, .sqlite3). To bring an Excel, Access, dBASE, or CSV file into a DbDo database, use Import instead.");
                    return;
                }
                string sTemp = Path.Combine(Path.GetTempPath(),
                    "DbDo_managed_" + Guid.NewGuid().ToString("N") + ".db");
                try { File.Copy(sOrigin, sTemp, true); }
                catch (Exception ex)
                {
                    ErrorDialog.show(this, "Open as Managed Copy", "Could not create the working copy: " + ex.Message);
                    return;
                }
                // Open the working copy. openDatabaseAndApplyState
                // closes any current connection first, so a previous
                // managed temp (if any) is unlocked afterward and can
                // be deleted.
                string sPrevTemp = sManagedTempPath;
                try { openDatabaseAndApplyState(sTemp, null); }
                catch (Exception ex)
                {
                    ErrorDialog.show(this, "Open as Managed Copy", ex.Message);
                    try { if (File.Exists(sTemp)) File.Delete(sTemp); } catch { }
                    return;
                }
                if (!string.IsNullOrEmpty(sPrevTemp) && !string.Equals(sPrevTemp, sTemp, StringComparison.OrdinalIgnoreCase))
                { try { if (File.Exists(sPrevTemp)) File.Delete(sPrevTemp); } catch { } }
                sManagedOriginPath = sOrigin;
                sManagedTempPath = sTemp;
                LiveRegion.say("Opened managed copy of " + Path.GetFileName(sManagedOriginPath)
                    + ". Edits stay in the working copy; the original is untouched until you Save As.");
            }
        }

        // cleanupManagedTemp: close the live connection (if any) and
        // delete the managed working file, clearing the managed state.
        // Called at form close so a managed copy's temp doesn't linger.
        // A SQLite file can't be deleted while the connection holds it,
        // so the close has to come first.
        private void cleanupManagedTemp()
        {
            if (string.IsNullOrEmpty(sManagedTempPath)) return;
            try { if (db != null && db.isOpen()) db.close(); } catch { }
            try { if (File.Exists(sManagedTempPath)) File.Delete(sManagedTempPath); } catch { }
            sManagedOriginPath = null;
            sManagedTempPath = null;
            sWorkbookOriginPath = null;
            sWorkbookSheetName = null;
            sWorkbookTable = null;
            lWorkbookColumns = null;
        }

        // openWorkbookForEditing: read one worksheet of an .xlsx (via
        // NPOI, no Office) into a faithful temp .db -- one row per
        // worksheet data row, one TEXT column per worksheet column,
        // plus a hidden dbdo_ws_row key holding each row's worksheet
        // index so Save Workbook can write edits back to the exact
        // cells. Returns the metadata the caller stores; it does NOT
        // touch the form's workbook fields (the caller sets those after
        // the open succeeds, because openDatabaseAndApplyState clears
        // them). Formula cells show their computed value and are
        // preserved on save regardless of any edit.
        private class WorkbookOpen
        {
            public string TempDb;
            public string Origin;
            public string Sheet;
            public string Table;
            public List<string> Columns;
        }

        private WorkbookOpen openWorkbookForEditing(string sXlsxPath)
        {
            XlsxNpoi.SheetModel model = XlsxNpoi.readFirstSheet(sXlsxPath);
            string sDbPath = Path.Combine(Path.GetTempPath(),
                "DbDo_managed_" + Guid.NewGuid().ToString("N") + ".db");
            if (File.Exists(sDbPath)) File.Delete(sDbPath);
            using (FileStream fs = File.Create(sDbPath)) { }

            string sTable = sNormalizeIdentifier(model.Name);
            if (sTable.Length == 0) sTable = "sheet_1";
            if (char.IsDigit(sTable[0])) sTable = "t_" + sTable;
            List<string> lCols = new List<string>();

            try
            {
                using (DbDoManager mgr = new DbDoManager())
                {
                    mgr.openDatabase(sDbPath, null, false);

                    List<string> lUsed = new List<string>();
                    lUsed.Add("dbdo_ws_row");
                    StringBuilder sbCreate = new StringBuilder();
                    sbCreate.Append("CREATE TABLE \"" + sTable + "\" (\"dbdo_ws_row\" INTEGER PRIMARY KEY");
                    foreach (string sHdr in model.Headers)
                    {
                        string sC = sNormalizeIdentifier(sHdr);
                        if (sC.Length == 0) sC = "column_" + (lCols.Count + 1);
                        if (char.IsDigit(sC[0])) sC = "c_" + sC;
                        if (sC == "dbdo_ws_row") sC = sC + "_in";
                        string sBaseC = sC; int iDupC = 1;
                        while (lUsed.Contains(sC)) { iDupC++; sC = sBaseC + "_" + iDupC; }
                        lUsed.Add(sC); lCols.Add(sC);
                        sbCreate.Append(", \"" + sC + "\" TEXT");
                    }
                    sbCreate.Append(")");
                    mgr.invokeSql(sbCreate.ToString(), null);

                    for (int i = 0; i < model.Rows.Count; i++)
                    {
                        string[] aVals = model.Rows[i];
                        StringBuilder sbIns = new StringBuilder();
                        sbIns.Append("INSERT INTO \"" + sTable + "\" (\"dbdo_ws_row\"");
                        foreach (string sC in lCols) sbIns.Append(", \"" + sC + "\"");
                        sbIns.Append(") VALUES (" + model.WsRowIndexes[i]);
                        for (int c = 0; c < lCols.Count; c++)
                        {
                            string sv = (c < aVals.Length) ? (aVals[c] ?? "") : "";
                            sbIns.Append(", '" + sv.Replace("'", "''") + "'");
                        }
                        sbIns.Append(")");
                        mgr.invokeSql(sbIns.ToString(), null);
                    }
                }
                try { DbDoLog.write("Opened workbook " + sXlsxPath + " sheet '" + model.Name + "' -> " + sDbPath + " (" + model.Rows.Count + " row(s))"); } catch { }
            }
            catch
            {
                try { if (File.Exists(sDbPath)) File.Delete(sDbPath); } catch { }
                throw;
            }

            WorkbookOpen wo = new WorkbookOpen();
            wo.TempDb = sDbPath; wo.Origin = sXlsxPath; wo.Sheet = model.Name;
            wo.Table = sTable; wo.Columns = lCols;
            return wo;
        }

        // saveWorkbookToDisk: write the user's data edits back to the
        // original .xlsx via NPOI. Formula cells are never overwritten,
        // and the workbook is patched in place (other sheets, charts,
        // and formatting survive), so the file can be handed back to a
        // sighted Excel user intact.
        // fileSaveClicked: Save (Ctrl+S) means "write my work to disk."
        // For a workbook working copy that is a write-back to the .xlsx.
        // For a directly-opened SQLite database, every add and edit has
        // already been committed to the file as it was made, so there is
        // nothing held back to flush; we say so plainly and point to Save
        // As for a separate copy. This is the fix for the old confusion
        // where Save tried to copy the open database over itself and hung
        // on the file lock.
        private void fileSaveClicked(object sender, EventArgs evArgs)
        {
            if (db == null || !db.isOpen()) return;
            if (!string.IsNullOrEmpty(sWorkbookOriginPath))
            {
                saveWorkbookToDisk();
                return;
            }
            if (!string.IsNullOrEmpty(sManagedTempPath))
            {
                // A managed working copy (Open Managed Copy) lives only in a
                // temp file, so Save routes to Save As to choose a permanent
                // destination. Save As writes a fresh file and never over the
                // open one, so it cannot hit the save-over-self lock hang.
                fileSaveAsClicked(sender, evArgs);
                return;
            }
            LiveRegion.say("All changes are already saved. Use Save As to make a copy under a new name or format.");
        }

        // saveWorkbookToDisk: write the working copy's data back to the
        // original .xlsx via NPOI (formulas preserved), then clear the
        // unsaved-changes flag and refresh the indicator.
        private void saveWorkbookToDisk()
        {
            if (string.IsNullOrEmpty(sWorkbookOriginPath) || string.IsNullOrEmpty(sWorkbookTable)
                || lWorkbookColumns == null || db == null || !db.isOpen())
            {
                MessageBox.Show(this,
                    "Save writes your changes back to the Excel workbook (.xlsx) opened for editing. "
                    + "No workbook is open for editing right now.",
                    "Save", MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }
            try
            {
                StringBuilder sbSel = new StringBuilder("SELECT \"dbdo_ws_row\"");
                foreach (string sC in lWorkbookColumns) sbSel.Append(", \"" + sC + "\"");
                sbSel.Append(" FROM \"" + sWorkbookTable + "\" ORDER BY \"dbdo_ws_row\"");

                int iFound;
                List<string[]> lRows = db.queryRowsSql(sbSel.ToString(), int.MaxValue, out iFound);

                List<XlsxNpoi.CellWrite> lWrites = new List<XlsxNpoi.CellWrite>();
                foreach (string[] aRow in lRows)
                {
                    if (aRow.Length == 0) continue;
                    int iWsRow;
                    if (!int.TryParse(aRow[0], out iWsRow)) continue;
                    for (int c = 0; c < lWorkbookColumns.Count; c++)
                    {
                        string sv = (c + 1 < aRow.Length) ? (aRow[c + 1] ?? "") : "";
                        lWrites.Add(new XlsxNpoi.CellWrite { WsRow = iWsRow, Col = c, Value = sv });
                    }
                }

                int iWritten = XlsxNpoi.writeBackData(sWorkbookOriginPath, sWorkbookSheetName, lWrites);
                db.bDataModified = false;   // working copy now matches the .xlsx on disk
                updateStatusBar();          // flip the indicator to "saved"
                try { DbDoLog.write("Save: wrote " + iWritten + " data cell(s) to " + sWorkbookOriginPath + " (formulas preserved)."); } catch { }
                LiveRegion.say("Saved your changes to " + Path.GetFileName(sWorkbookOriginPath)
                    + ". Formulas and other sheets were preserved.");
            }
            catch (Exception ex)
            {
                ErrorDialog.show(this, "Save",
                    "Could not save your changes back to the workbook: " + ex.Message);
            }
        }

        // confirmSaveWorkbookIfDirty: when a workbook working copy has
        // unsaved edits, ask before they are discarded (Excel-style). The
        // explicit-save model means edits live in the working copy until
        // Save writes them back, so closing without this prompt would lose
        // them silently. Returns true if the caller may proceed (the user
        // saved or chose to discard), false to abort the close (Cancel).
        private bool confirmSaveWorkbookIfDirty()
        {
            if (string.IsNullOrEmpty(sWorkbookOriginPath) || db == null || !db.bDataModified)
                return true;
            DialogResult res = MessageBox.Show(this,
                "You have unsaved changes to " + Path.GetFileName(sWorkbookOriginPath)
                + ". Save them before closing?",
                "Unsaved changes", MessageBoxButtons.YesNoCancel, MessageBoxIcon.Warning);
            if (res == DialogResult.Cancel) return false;
            if (res == DialogResult.Yes) saveWorkbookToDisk();
            return true;
        }

        // importInixRecordFile: open an .inix file written in the
        // record-format convention -- each [section] heading starts a
        // record; key=value lines beneath it are the record's fields
        // -- by converting it to a SQLite database next to the
        // source, named <file>.inix.db, and returning that path for
        // the normal SQLite open. The table is named after the
        // file's base name; its columns are the union of keys in
        // first-encountered order, all TEXTLINE, wrapped in the
        // standard-table scaffolding (id, prm, marked, edited
        // trigger) plus the builtin maps and lookups tables, so the
        // import is a first-class DbDo database. Each record's prm
        // is its section heading, suffixed when repeated. The
        // conversion uses its own short-lived manager so this
        // window's open database is untouched until the converted
        // file opens.
        // internal (not private) so the static Main launcher, which
        // lives in a separate class within this same assembly, can run
        // the .inix -> .db conversion for a command-line / double-click
        // launch the same way File > Open does.
        internal string importInixRecordFile(string sInixPath)
        {
            const string c_sQuote = "\"";
            int iSeq = 0;
            string sTable = Path.GetFileNameWithoutExtension(sInixPath).ToLowerInvariant();
            System.Text.StringBuilder sbName = new System.Text.StringBuilder();
            foreach (char ch in sTable)
                sbName.Append(char.IsLetterOrDigit(ch) ? ch : '_');
            sTable = sbName.ToString();
            if (sTable.Length == 0 || char.IsDigit(sTable[0])) sTable = "t_" + sTable;

            List<string> lsKeys = new List<string>();
            List<string> lsPrms = new List<string>();
            List<Dictionary<string, string>> lRecords = new List<Dictionary<string, string>>();
            Dictionary<string, string> dCurrent = null;
            foreach (string sRaw in File.ReadAllLines(sInixPath))
            {
                string sLine = sRaw.Trim();
                if (sLine.Length == 0 || sLine.StartsWith(";") || sLine.StartsWith("#")) continue;
                if (sLine.StartsWith("[") && sLine.EndsWith("]"))
                {
                    dCurrent = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
                    lRecords.Add(dCurrent);
                    iSeq++;
                    string sPrm = sLine.Substring(1, sLine.Length - 2).Trim();
                    if (sPrm.Length == 0) sPrm = "record " + iSeq;
                    while (lsPrms.Contains(sPrm)) sPrm += " +";
                    lsPrms.Add(sPrm);
                    continue;
                }
                int iEq = sLine.IndexOf('=');
                if (iEq <= 0 || dCurrent == null) continue;
                string sKey = sLine.Substring(0, iEq).Trim().ToLowerInvariant().Replace(' ', '_');
                System.Text.StringBuilder sbKey = new System.Text.StringBuilder();
                foreach (char ch in sKey)
                    sbKey.Append(char.IsLetterOrDigit(ch) || ch == '_' ? ch : '_');
                sKey = sbKey.ToString();
                if (sKey.Length == 0) continue;
                dCurrent[sKey] = sLine.Substring(iEq + 1).Trim();
                if (!lsKeys.Contains(sKey)) lsKeys.Add(sKey);
            }
            if (lRecords.Count == 0 || lsKeys.Count == 0)
                throw new InvalidOperationException("No [section] records with key=value lines found.");

            string sDbPath = sInixPath + ".db";
            if (File.Exists(sDbPath)) File.Delete(sDbPath);
            using (FileStream fs = File.Create(sDbPath)) { }
            using (DbDoManager managerImport = new DbDoManager())
            {
                managerImport.openDatabase(sDbPath, null, false);
                List<string[]> lFieldDefs = new List<string[]>();
                foreach (string sKey in lsKeys)
                    lFieldDefs.Add(new string[] { sKey, "TEXTLINE" });
                foreach (string sSql in lStandardTableDdl(sTable, lFieldDefs))
                    managerImport.invokeSql(sSql, null);
                foreach (string sSql in lInfraDdl(true, true))
                    managerImport.invokeSql(sSql, null);
                for (int i = 0; i < lRecords.Count; i++)
                {
                    System.Text.StringBuilder sbCols = new System.Text.StringBuilder();
                    System.Text.StringBuilder sbVals = new System.Text.StringBuilder();
                    bool bFirstCol = true;
                    foreach (KeyValuePair<string, string> pair in lRecords[i])
                    {
                        if (!bFirstCol) { sbCols.Append(", "); sbVals.Append(", "); }
                        sbCols.Append(c_sQuote + pair.Key + c_sQuote);
                        sbVals.Append("'" + pair.Value.Replace("'", "''") + "'");
                        bFirstCol = false;
                    }
                    if (sbCols.Length == 0) continue;
                    managerImport.invokeSql("INSERT INTO " + c_sQuote + sTable + c_sQuote
                        + " (" + sbCols + ") VALUES (" + sbVals + ")", null);
                }
            }
            LiveRegion.say("Converted " + lRecords.Count + " record"
                + (lRecords.Count == 1 ? "" : "s") + " to " + Path.GetFileName(sDbPath));
            return sDbPath;
        }

        // importWorkbookFile: read an Excel workbook (.xlsx / .xls) via
        // Excel.Application COM automation and build a temporary SQLite
        // database in the standard DbDo shape -- one table per worksheet,
        // each sheet's first row taken as the field names and the rows
        // below as data, wrapped in the standard columns, plus the builtin
        // maps and lookups tables. Returns the temp .db path for the
        // normal SQLite open; the caller treats it as a managed copy whose
        // origin is the workbook, so the workbook is only ever read.
        //
        // COM is used, NOT the ACE OLE DB provider, on purpose: Excel
        // automation is out-of-process, so a 64-bit DbDo reads a workbook
        // through whatever Excel is installed (even 32-bit) with no
        // provider-bitness or Office-architecture conflict. The only
        // requirement is that Excel itself is present.
        //
        // A sheet header that collides with a standard column is handled,
        // not duplicated: "notes" and "tags" route their data into the
        // standard notes/tags columns; the rest of the reserved set is
        // renamed with an "_in" suffix.
        internal string importWorkbookFile(string sXlsxPath)
        {
            if (string.IsNullOrEmpty(sXlsxPath)) throw new ArgumentException("importWorkbookFile requires a path.");
            if (!File.Exists(sXlsxPath)) throw new FileNotFoundException("Workbook not found: " + sXlsxPath);

            string[] aReservedRename = new string[] { "added", "edited", "look", "prm", "prm", "marked" };
            string sDbPath = Path.Combine(Path.GetTempPath(),
                "DbDo_managed_" + Guid.NewGuid().ToString("N") + ".db");

            dynamic oApp = null;
            dynamic oBook = null;
            int iSheetsImported = 0;
            int iRowsImported = 0;
            try
            {
                oApp = ComAutomation.createApp("Excel.Application");
                // Suppress every prompt BEFORE opening -- the export path
                // does the same. A hidden, automated Excel cannot show a
                // dialog, so if Open would raise one -- a file-in-use notice
                // (the workbook already open elsewhere), a Protected View
                // block (the file arrived as an email attachment, carrying
                // the mark-of-the-web), or a link/data prompt -- the call
                // leaves an invalid workbook reference whose next use throws
                // COM 0x80010114, "the requested object does not exist."
                oApp.Visible = false;
                oApp.DisplayAlerts = false;
                try { oApp.ScreenUpdating = false; } catch { }
                try { oApp.AskToUpdateLinks = false; } catch { }
                try { oApp.AutomationSecurity = 1 /* msoAutomationSecurityLow */; } catch { }
                // Open(Filename, UpdateLinks, ReadOnly): read-only.
                oBook = oApp.Workbooks.Open(sXlsxPath, 0, true);
                if (oBook == null)
                    throw new InvalidOperationException("Excel could not open " + Path.GetFileName(sXlsxPath)
                        + ". If the workbook is open in Excel, please close it and try again.");

                if (File.Exists(sDbPath)) File.Delete(sDbPath);
                using (FileStream fs = File.Create(sDbPath)) { }
                using (DbDoManager managerImport = new DbDoManager())
                {
                    managerImport.openDatabase(sDbPath, null, false);
                    List<string> lTableNames = new List<string>();
                    int iSheetCount = (int)oBook.Worksheets.Count;
                    for (int iSheet = 1; iSheet <= iSheetCount; iSheet++)
                    {
                        dynamic oSheet = oBook.Worksheets[iSheet];
                        string sSheetName = (string)oSheet.Name;
                        // One COM call pulls the whole used range as a
                        // 1-based 2-D array; null when the sheet is empty
                        // or holds a single blank cell.
                        object oVals = oSheet.UsedRange.Value;
                        object[,] aCells = oVals as object[,];
                        if (aCells == null) continue;
                        int iR0 = aCells.GetLowerBound(0), iR1 = aCells.GetUpperBound(0);
                        int iC0 = aCells.GetLowerBound(1), iC1 = aCells.GetUpperBound(1);
                        if (iR1 <= iR0 || iC1 < iC0) continue; // need a header row plus at least one data row

                        // Find the header row. Some sheets begin with a
                        // sparse title/metadata row (Richard's, for example,
                        // opens with "Updated 2026/03/18" above the real
                        // column names). The header is the first row whose
                        // count of non-empty cells is at least 60% of the
                        // widest row in the opening stretch of the sheet; any
                        // rows above it are preamble and are skipped.
                        int iScanEnd = Math.Min(iR1, iR0 + 14);
                        int iWidest = 0;
                        for (int r = iR0; r <= iScanEnd; r++)
                        {
                            int iFilled = 0;
                            for (int c = iC0; c <= iC1; c++) if (sCellToString(aCells[r, c]).Length > 0) iFilled++;
                            if (iFilled > iWidest) iWidest = iFilled;
                        }
                        int iThreshold = Math.Max(2, (iWidest * 6) / 10);
                        int iHdr = iR0;
                        for (int r = iR0; r <= iScanEnd; r++)
                        {
                            int iFilled = 0;
                            for (int c = iC0; c <= iC1; c++) if (sCellToString(aCells[r, c]).Length > 0) iFilled++;
                            if (iFilled >= iThreshold) { iHdr = r; break; }
                        }
                        if (iHdr >= iR1) continue; // a header but no data rows beneath it

                        // Table name from the sheet name, made a safe,
                        // unique snake_case identifier.
                        string sTable = sNormalizeIdentifier(sSheetName);
                        if (sTable.Length == 0) sTable = "sheet_" + iSheet;
                        if (char.IsDigit(sTable[0])) sTable = "t_" + sTable;
                        string sBaseT = sTable; int iDupT = 1;
                        while (lTableNames.Contains(sTable)) { iDupT++; sTable = sBaseT + "_" + iDupT; }
                        lTableNames.Add(sTable);
                        string sSingular = sTable.EndsWith("s") ? sTable.Substring(0, sTable.Length - 1) : sTable;
                        string sPk = sSingular + "_id";

                        // Plan the columns from the header row. lColTarget
                        // holds, per source column, the SQL column it writes
                        // (or null to skip); lFieldDefs are the distinct data
                        // fields handed to lStandardTableDdl.
                        List<string[]> lFieldDefs = new List<string[]>();
                        List<string> lColTarget = new List<string>();
                        List<string> lUsedNames = new List<string>();
                        for (int iCol = iC0; iCol <= iC1; iCol++)
                        {
                            string sHdr = sNormalizeIdentifier(sCellToString(aCells[iHdr, iCol]));
                            if (sHdr.Length == 0) sHdr = "column_" + (iCol - iC0 + 1);
                            if (char.IsDigit(sHdr[0])) sHdr = "c_" + sHdr;
                            if (sHdr == "notes") { lColTarget.Add("notes"); continue; }
                            if (sHdr == "tags") { lColTarget.Add("tags"); continue; }
                            if (sHdr == sPk || Array.IndexOf(aReservedRename, sHdr) >= 0) sHdr = sHdr + "_in";
                            string sBaseH = sHdr; int iDupH = 1;
                            while (lUsedNames.Contains(sHdr)) { iDupH++; sHdr = sBaseH + "_" + iDupH; }
                            lUsedNames.Add(sHdr);
                            lFieldDefs.Add(new string[] { sHdr, "TEXTLINE" });
                            lColTarget.Add(sHdr);
                        }
                        // Guarantee at least one distinct field so look/prm
                        // are well-formed even for an all-notes/tags sheet.
                        if (lFieldDefs.Count == 0) lFieldDefs.Add(new string[] { "value", "TEXTLINE" });

                        foreach (string sSql in lStandardTableDdl(sTable, lFieldDefs))
                            managerImport.invokeSql(sSql, null);

                        for (int iRow = iHdr + 1; iRow <= iR1; iRow++)
                        {
                            List<string> lCols = new List<string>();
                            List<string> lVals = new List<string>();
                            bool bAny = false;
                            int iColIdx = 0;
                            for (int iCol = iC0; iCol <= iC1; iCol++, iColIdx++)
                            {
                                string sTarget = lColTarget[iColIdx];
                                if (sTarget == null) continue;
                                string sCell = sCellToString(aCells[iRow, iCol]);
                                if (sCell.Length > 0) bAny = true;
                                lCols.Add("\"" + sTarget + "\"");
                                lVals.Add("'" + sCell.Replace("'", "''") + "'");
                            }
                            if (!bAny) continue; // skip a wholly-empty row
                            string sInsert = "INSERT INTO \"" + sTable + "\" ("
                                + string.Join(", ", lCols.ToArray()) + ") VALUES ("
                                + string.Join(", ", lVals.ToArray()) + ")";
                            try { managerImport.invokeSql(sInsert, null); iRowsImported++; }
                            catch (Exception exRow)
                            {
                                // A duplicate prm (an identical data row) trips
                                // the UNIQUE index; skip it, keep importing.
                                try { DbDoLog.write("importWorkbookFile skipped a row in " + sTable + ": " + exRow.Message); } catch { }
                            }
                        }
                        iSheetsImported++;
                    }

                    if (iSheetsImported == 0)
                        throw new InvalidOperationException("No worksheets with a header row and data rows were found in " + Path.GetFileName(sXlsxPath) + ".");

                    foreach (string sSql in lInfraDdl(true, true))
                        managerImport.invokeSql(sSql, null);
                }

                try { DbDoLog.write("Imported workbook " + sXlsxPath + ": " + iSheetsImported
                    + " sheet(s), " + iRowsImported + " row(s) -> " + sDbPath); } catch { }
                return sDbPath;
            }
            catch
            {
                try { if (File.Exists(sDbPath)) File.Delete(sDbPath); } catch { }
                throw;
            }
            finally
            {
                // Excel never attaches to a running instance (see
                // ComAutomation); close the workbook without saving and
                // quit the hidden process, then release the COM objects.
                try { if (oBook != null) oBook.Close(false); } catch { }
                try { if (oApp != null) oApp.Quit(); } catch { }
                if (oBook != null) { try { Marshal.FinalReleaseComObject(oBook); } catch { } }
                if (oApp != null) { try { Marshal.FinalReleaseComObject(oApp); } catch { } }
            }
        }

        // sCellToString: render one Excel cell value (from a UsedRange
        // .Value array) as a trimmed string. Empty cells arrive as null;
        // numbers as double (whole numbers without a trailing ".0"); dates
        // as DateTime (ISO, with a time only when present); else ToString.
        private static string sCellToString(object oVal)
        {
            if (oVal == null) return "";
            if (oVal is string) return ((string)oVal).Trim();
            if (oVal is bool) return ((bool)oVal) ? "true" : "false";
            if (oVal is DateTime)
            {
                DateTime dt = (DateTime)oVal;
                return (dt.TimeOfDay == TimeSpan.Zero) ? dt.ToString("yyyy-MM-dd") : dt.ToString("yyyy-MM-dd HH:mm:ss");
            }
            if (oVal is double)
            {
                double d = (double)oVal;
                if (!double.IsInfinity(d) && d == Math.Floor(d) && Math.Abs(d) < 1e15)
                    return ((long)d).ToString(System.Globalization.CultureInfo.InvariantCulture);
                return d.ToString(System.Globalization.CultureInfo.InvariantCulture);
            }
            return oVal.ToString().Trim();
        }

        // ================= Native .xlsx reading (no Excel, no COM) =======
        // An .xlsx is a ZIP of XML parts, so DbDo reads it directly: a tiny
        // ZIP reader (central directory + DeflateStream, both already in
        // System.dll) unpacks the parts and System.Xml parses them. This is
        // why Import no longer needs Excel installed and is immune to the
        // Office/DbDo bitness mismatch -- the COM failure (0x80010114, a
        // 32-bit Excel automated by 64-bit DbDo) is gone because no second
        // process is involved.

        // XlsxZip: minimal read-only ZIP accessor over a file held in
        // memory. Parses the central directory once; reads named entries on
        // demand, inflating DEFLATE entries. No ZIP64 / no encryption (an
        // Office package needs neither).
        private class XlsxZip
        {
            private byte[] aData;
            private Dictionary<string, int[]> dEntries = new Dictionary<string, int[]>(); // name -> {localOffset, method, compSize}

            public XlsxZip(string sPath)
            {
                aData = File.ReadAllBytes(sPath);
                int iEocd = -1;
                for (int i = aData.Length - 22; i >= 0; i--) { if (u32(i) == 0x06054b50) { iEocd = i; break; } }
                if (iEocd < 0) throw new InvalidOperationException("Not a valid .xlsx file (no ZIP end-of-directory record).");
                int iCount = u16(iEocd + 10);
                int p = (int)u32(iEocd + 16);
                for (int n = 0; n < iCount && p + 46 <= aData.Length; n++)
                {
                    if (u32(p) != 0x02014b50) break;
                    int iMethod = u16(p + 10);
                    int iComp = (int)u32(p + 20);
                    int iNameLen = u16(p + 28), iExtraLen = u16(p + 30), iCommentLen = u16(p + 32);
                    int iLocalOff = (int)u32(p + 42);
                    string sName = Encoding.UTF8.GetString(aData, p + 46, iNameLen);
                    if (!dEntries.ContainsKey(sName)) dEntries.Add(sName, new int[] { iLocalOff, iMethod, iComp });
                    p += 46 + iNameLen + iExtraLen + iCommentLen;
                }
            }

            public bool has(string sName) { return dEntries.ContainsKey(sName); }

            public string readText(string sName)
            {
                if (!dEntries.ContainsKey(sName)) return null;
                int[] e = dEntries[sName];
                int iOff = e[0], iMethod = e[1], iComp = e[2];
                int iNameLen = u16(iOff + 26), iExtraLen = u16(iOff + 28);
                int iStart = iOff + 30 + iNameLen + iExtraLen;
                byte[] aRaw;
                if (iMethod == 0)
                {
                    aRaw = new byte[iComp];
                    Array.Copy(aData, iStart, aRaw, 0, iComp);
                }
                else
                {
                    using (MemoryStream msIn = new MemoryStream(aData, iStart, iComp))
                    using (System.IO.Compression.DeflateStream ds = new System.IO.Compression.DeflateStream(msIn, System.IO.Compression.CompressionMode.Decompress))
                    using (MemoryStream msOut = new MemoryStream())
                    {
                        ds.CopyTo(msOut);
                        aRaw = msOut.ToArray();
                    }
                }
                int iSkip = (aRaw.Length >= 3 && aRaw[0] == 0xEF && aRaw[1] == 0xBB && aRaw[2] == 0xBF) ? 3 : 0;
                return Encoding.UTF8.GetString(aRaw, iSkip, aRaw.Length - iSkip);
            }

            private int u16(int i) { return aData[i] | (aData[i + 1] << 8); }
            private long u32(int i) { return (uint)(aData[i] | (aData[i + 1] << 8) | (aData[i + 2] << 16) | (aData[i + 3] << 24)); }
        }

        // importXlsxNative: parse an .xlsx workbook with no Excel and build a
        // temp DbDo shell -- one standard-shape table per worksheet, plus
        // maps and lookups. Shared strings are resolved, dates (by cell
        // style) are rendered ISO, and an empty sheet is skipped.
        internal string importXlsxNative(string sXlsxPath)
        {
            if (string.IsNullOrEmpty(sXlsxPath)) throw new ArgumentException("importXlsxNative requires a path.");
            if (!File.Exists(sXlsxPath)) throw new FileNotFoundException("Workbook not found: " + sXlsxPath);

            XlsxZip zip = new XlsxZip(sXlsxPath);

            // Shared strings: cells of type "s" hold an index into this list.
            List<string> lShared = new List<string>();
            if (zip.has("xl/sharedStrings.xml"))
            {
                System.Xml.XmlDocument docSs = new System.Xml.XmlDocument();
                docSs.LoadXml(zip.readText("xl/sharedStrings.xml"));
                foreach (System.Xml.XmlNode si in docSs.DocumentElement.ChildNodes)
                {
                    if (!localIs(si, "si")) continue;
                    StringBuilder sb = new StringBuilder();
                    appendXmlText(si, sb);
                    lShared.Add(sb.ToString());
                }
            }

            // Styles: which style indices are date/time formatted.
            List<bool> lStyleIsDate = new List<bool>();
            if (zip.has("xl/styles.xml"))
            {
                System.Xml.XmlDocument docSt = new System.Xml.XmlDocument();
                docSt.LoadXml(zip.readText("xl/styles.xml"));
                Dictionary<int, string> dNumFmt = new Dictionary<int, string>();
                System.Xml.XmlNode oNumFmts = firstLocal(docSt.DocumentElement, "numFmts");
                if (oNumFmts != null)
                    foreach (System.Xml.XmlNode nf in oNumFmts.ChildNodes)
                    {
                        if (!localIs(nf, "numFmt")) continue;
                        int iId; if (int.TryParse(xmlAttr(nf, "numFmtId"), out iId)) dNumFmt[iId] = xmlAttr(nf, "formatCode") ?? "";
                    }
                System.Xml.XmlNode oXfs = firstLocal(docSt.DocumentElement, "cellXfs");
                if (oXfs != null)
                    foreach (System.Xml.XmlNode xf in oXfs.ChildNodes)
                    {
                        if (!localIs(xf, "xf")) continue;
                        int iFmt; int.TryParse(xmlAttr(xf, "numFmtId") ?? "0", out iFmt);
                        lStyleIsDate.Add(bIsDateFormat(iFmt, dNumFmt));
                    }
            }

            // Sheet order/names from workbook.xml; r:id -> part path from rels.
            Dictionary<string, string> dRel = new Dictionary<string, string>();
            if (zip.has("xl/_rels/workbook.xml.rels"))
            {
                System.Xml.XmlDocument docR = new System.Xml.XmlDocument();
                docR.LoadXml(zip.readText("xl/_rels/workbook.xml.rels"));
                foreach (System.Xml.XmlNode rel in docR.DocumentElement.ChildNodes)
                    if (localIs(rel, "Relationship")) dRel[xmlAttr(rel, "Id") ?? ""] = xmlAttr(rel, "Target") ?? "";
            }
            List<string[]> lSheets = new List<string[]>(); // {name, partPath}
            System.Xml.XmlDocument docW = new System.Xml.XmlDocument();
            docW.LoadXml(zip.readText("xl/workbook.xml"));
            System.Xml.XmlNode oSheets = firstLocal(docW.DocumentElement, "sheets");
            if (oSheets != null)
                foreach (System.Xml.XmlNode sh in oSheets.ChildNodes)
                {
                    if (!localIs(sh, "sheet")) continue;
                    string sName = xmlAttr(sh, "name") ?? "sheet";
                    string sRid = xmlAttrLocal(sh, "id"); // r:id
                    string sTarget = (sRid != null && dRel.ContainsKey(sRid)) ? dRel[sRid] : null;
                    if (string.IsNullOrEmpty(sTarget)) continue;
                    sTarget = sTarget.StartsWith("/") ? sTarget.TrimStart('/') : "xl/" + sTarget.TrimStart('.', '/');
                    lSheets.Add(new string[] { sName, sTarget });
                }

            string sDbPath = Path.Combine(Path.GetTempPath(), "DbDo_managed_" + Guid.NewGuid().ToString("N") + ".db");
            int iSheetsImported = 0, iRowsImported = 0;
            try
            {
                if (File.Exists(sDbPath)) File.Delete(sDbPath);
                using (FileStream fs = File.Create(sDbPath)) { }
                using (DbDoManager managerImport = new DbDoManager())
                {
                    managerImport.openDatabase(sDbPath, null, false);
                    List<string> lTableNames = new List<string>();
                    foreach (string[] aSheet in lSheets)
                    {
                        if (!zip.has(aSheet[1])) continue;
                        List<string[]> aGrid = lGridFromSheet(zip.readText(aSheet[1]), lShared, lStyleIsDate);
                        int iAdded = buildShellTableFromGrid(managerImport, aSheet[0], aGrid, lTableNames);
                        if (iAdded >= 0) { iRowsImported += iAdded; iSheetsImported++; }
                    }
                    if (iSheetsImported == 0)
                        throw new InvalidOperationException("No worksheets with a header row and data rows were found in " + Path.GetFileName(sXlsxPath) + ".");
                    foreach (string sSql in lInfraDdl(true, true)) managerImport.invokeSql(sSql, null);
                }
                try { DbDoLog.write("Imported workbook (native) " + sXlsxPath + ": " + iSheetsImported
                    + " sheet(s), " + iRowsImported + " row(s) -> " + sDbPath); } catch { }
                return sDbPath;
            }
            catch
            {
                try { if (File.Exists(sDbPath)) File.Delete(sDbPath); } catch { }
                throw;
            }
        }

        // lGridFromSheet: turn one worksheet's XML into a rectangular grid of
        // strings (row 0..n, each a string[] of column values), resolving
        // shared strings and date styles via sCellXmlValue.
        private static List<string[]> lGridFromSheet(string sSheetXml, List<string> lShared, List<bool> lStyleIsDate)
        {
            List<string[]> lResult = new List<string[]>();
            if (string.IsNullOrEmpty(sSheetXml)) return lResult;
            System.Xml.XmlDocument doc = new System.Xml.XmlDocument();
            doc.LoadXml(sSheetXml);
            System.Xml.XmlNode oData = firstLocal(doc.DocumentElement, "sheetData");
            if (oData == null) return lResult;
            List<Dictionary<int, string>> lRows = new List<Dictionary<int, string>>();
            int iMaxCol = 0;
            foreach (System.Xml.XmlNode oRow in oData.ChildNodes)
            {
                if (!localIs(oRow, "row")) continue;
                Dictionary<int, string> dRow = new Dictionary<int, string>();
                foreach (System.Xml.XmlNode oC in oRow.ChildNodes)
                {
                    if (!localIs(oC, "c")) continue;
                    int iCol = iColFromRef(xmlAttr(oC, "r") ?? "");
                    if (iCol <= 0) continue;
                    string sVal = sCellXmlValue(oC, lShared, lStyleIsDate);
                    if (sVal.Length > 0) { dRow[iCol] = sVal; if (iCol > iMaxCol) iMaxCol = iCol; }
                }
                lRows.Add(dRow);
            }
            foreach (Dictionary<int, string> dRow in lRows)
            {
                string[] aRow = new string[iMaxCol];
                for (int c = 1; c <= iMaxCol; c++) aRow[c - 1] = dRow.ContainsKey(c) ? dRow[c] : "";
                lResult.Add(aRow);
            }
            return lResult;
        }

        // sCellXmlValue: render one <c> cell as a trimmed string. Shared
        // strings and inline strings are resolved; booleans become
        // true/false; numbers whose cell style is a date format are rendered
        // ISO (with time only when present); other numbers drop a trailing .0.
        private static string sCellXmlValue(System.Xml.XmlNode oC, List<string> lShared, List<bool> lStyleIsDate)
        {
            string sT = xmlAttr(oC, "t");
            if (sT == "inlineStr")
            {
                System.Xml.XmlNode oIs = firstLocal(oC, "is");
                if (oIs == null) return "";
                StringBuilder sb = new StringBuilder(); appendXmlText(oIs, sb); return sb.ToString().Trim();
            }
            System.Xml.XmlNode oV = firstLocal(oC, "v");
            string sV = (oV != null) ? oV.InnerText : "";
            if (sT == "s")
            {
                int iIdx;
                if (int.TryParse(sV, out iIdx) && iIdx >= 0 && iIdx < lShared.Count) return lShared[iIdx].Trim();
                return "";
            }
            if (sT == "str" || sT == "e") return (sV ?? "").Trim();
            if (sT == "b") return (sV == "1") ? "true" : "false";
            if (sV.Length == 0) return "";
            bool bDate = false;
            int iStyle;
            string sS = xmlAttr(oC, "s");
            if (sS != null && int.TryParse(sS, out iStyle) && iStyle >= 0 && iStyle < lStyleIsDate.Count) bDate = lStyleIsDate[iStyle];
            double d;
            if (double.TryParse(sV, System.Globalization.NumberStyles.Any, System.Globalization.CultureInfo.InvariantCulture, out d))
            {
                if (bDate)
                {
                    try
                    {
                        DateTime dt = DateTime.FromOADate(d);
                        return (dt.TimeOfDay == TimeSpan.Zero) ? dt.ToString("yyyy-MM-dd") : dt.ToString("yyyy-MM-dd HH:mm:ss");
                    }
                    catch { }
                }
                if (!double.IsInfinity(d) && d == Math.Floor(d) && Math.Abs(d) < 1e15)
                    return ((long)d).ToString(System.Globalization.CultureInfo.InvariantCulture);
                return d.ToString(System.Globalization.CultureInfo.InvariantCulture);
            }
            return sV.Trim();
        }

        // buildShellTableFromGrid: create one standard-shape table from a
        // parsed grid and insert its data rows. The header row is detected
        // (a sparse title/metadata row above the column names is skipped); a
        // notes/tags column routes into the standard column, other standard-
        // name collisions get an "_in" suffix, and a duplicate row that would
        // trip the UNIQUE prm index is skipped. Returns rows inserted, or -1
        // if there was no usable header-plus-data and no table was made.
        private static int buildShellTableFromGrid(DbDoManager managerImport, string sSheetName,
            List<string[]> aGrid, List<string> lTableNames)
        {
            if (aGrid == null || aGrid.Count < 2) return -1;
            string[] aReservedRename = new string[] { "added", "edited", "look", "prm", "prm", "marked" };

            int iScan = Math.Min(aGrid.Count - 1, 14);
            int iWidest = 0;
            for (int r = 0; r <= iScan; r++) { int f = iFilledCells(aGrid[r]); if (f > iWidest) iWidest = f; }
            int iThreshold = Math.Max(2, (iWidest * 6) / 10);
            int iHdr = 0;
            for (int r = 0; r <= iScan; r++) { if (iFilledCells(aGrid[r]) >= iThreshold) { iHdr = r; break; } }
            if (iHdr >= aGrid.Count - 1) return -1;

            string sTable = sNormalizeIdentifier(sSheetName);
            if (sTable.Length == 0) sTable = "sheet";
            if (char.IsDigit(sTable[0])) sTable = "t_" + sTable;
            string sBaseT = sTable; int iDupT = 1;
            while (lTableNames.Contains(sTable)) { iDupT++; sTable = sBaseT + "_" + iDupT; }
            lTableNames.Add(sTable);
            string sSingular = sTable.EndsWith("s") ? sTable.Substring(0, sTable.Length - 1) : sTable;
            string sPk = sSingular + "_id";

            string[] aHeader = aGrid[iHdr];
            List<string[]> lFieldDefs = new List<string[]>();
            List<string> lColTarget = new List<string>();
            List<string> lUsedNames = new List<string>();
            List<string> lUsedPass = new List<string>();
            for (int c = 0; c < aHeader.Length; c++)
            {
                string sHdr = sNormalizeIdentifier(aHeader[c] ?? "");
                if (sHdr.Length == 0) sHdr = "column_" + (c + 1);
                if (char.IsDigit(sHdr[0])) sHdr = "c_" + sHdr;
                if (sHdr == "notes" || sHdr == "tags")
                {
                    if (lUsedPass.Contains(sHdr)) { lColTarget.Add(null); continue; }
                    lUsedPass.Add(sHdr); lColTarget.Add(sHdr); continue;
                }
                if (sHdr == sPk || Array.IndexOf(aReservedRename, sHdr) >= 0) sHdr = sHdr + "_in";
                string sBaseH = sHdr; int iDupH = 1;
                while (lUsedNames.Contains(sHdr)) { iDupH++; sHdr = sBaseH + "_" + iDupH; }
                lUsedNames.Add(sHdr);
                lFieldDefs.Add(new string[] { sHdr, "TEXTLINE" });
                lColTarget.Add(sHdr);
            }
            if (lFieldDefs.Count == 0) lFieldDefs.Add(new string[] { "value", "TEXTLINE" });

            foreach (string sSql in lStandardTableDdl(sTable, lFieldDefs)) managerImport.invokeSql(sSql, null);

            int iRows = 0;
            for (int r = iHdr + 1; r < aGrid.Count; r++)
            {
                string[] aRow = aGrid[r];
                List<string> lCols = new List<string>();
                List<string> lVals = new List<string>();
                bool bAny = false;
                for (int c = 0; c < lColTarget.Count; c++)
                {
                    string sTarget = lColTarget[c];
                    if (sTarget == null) continue;
                    string sCell = (c < aRow.Length && aRow[c] != null) ? aRow[c] : "";
                    if (sCell.Length > 0) bAny = true;
                    lCols.Add("\"" + sTarget + "\"");
                    lVals.Add("'" + sCell.Replace("'", "''") + "'");
                }
                if (!bAny) continue;
                string sInsert = "INSERT INTO \"" + sTable + "\" (" + string.Join(", ", lCols.ToArray())
                    + ") VALUES (" + string.Join(", ", lVals.ToArray()) + ")";
                try { managerImport.invokeSql(sInsert, null); iRows++; }
                catch (Exception exRow) { try { DbDoLog.write("Import skipped a row in " + sTable + ": " + exRow.Message); } catch { } }
            }
            return iRows;
        }

        private static int iFilledCells(string[] aRow)
        {
            int n = 0;
            if (aRow != null) foreach (string s in aRow) if (!string.IsNullOrEmpty(s)) n++;
            return n;
        }

        // Small System.Xml helpers (match by local name so namespaces and
        // prefixes do not matter).
        private static bool localIs(System.Xml.XmlNode n, string sLocal)
        { return n != null && n.NodeType == System.Xml.XmlNodeType.Element && n.LocalName == sLocal; }

        private static System.Xml.XmlNode firstLocal(System.Xml.XmlNode parent, string sLocal)
        {
            if (parent == null) return null;
            foreach (System.Xml.XmlNode ch in parent.ChildNodes) if (localIs(ch, sLocal)) return ch;
            return null;
        }

        private static string xmlAttr(System.Xml.XmlNode n, string sName)
        {
            if (n == null || n.Attributes == null) return null;
            System.Xml.XmlNode a = n.Attributes.GetNamedItem(sName);
            return (a != null) ? a.Value : null;
        }

        private static string xmlAttrLocal(System.Xml.XmlNode n, string sLocal)
        {
            if (n == null || n.Attributes == null) return null;
            foreach (System.Xml.XmlNode a in n.Attributes) if (a.LocalName == sLocal) return a.Value;
            return null;
        }

        // iColFromRef: 1-based column number from a cell reference's letter
        // prefix ("A"->1, "Z"->26, "AA"->27); ignores the row digits.
        private static int iColFromRef(string sRef)
        {
            int n = 0;
            foreach (char ch in sRef)
            {
                if (ch >= 'A' && ch <= 'Z') n = n * 26 + (ch - 'A' + 1);
                else if (ch >= 'a' && ch <= 'z') n = n * 26 + (ch - 'a' + 1);
                else break;
            }
            return n;
        }

        private static void appendXmlText(System.Xml.XmlNode n, StringBuilder sb)
        {
            foreach (System.Xml.XmlNode ch in n.ChildNodes)
            {
                if (localIs(ch, "t")) sb.Append(ch.InnerText);
                else if (ch.HasChildNodes) appendXmlText(ch, sb);
            }
        }

        private static bool bIsDateFormat(int iFmt, Dictionary<int, string> dNumFmt)
        {
            if ((iFmt >= 14 && iFmt <= 22) || (iFmt >= 45 && iFmt <= 47) || (iFmt >= 27 && iFmt <= 36) || (iFmt >= 50 && iFmt <= 58)) return true;
            string sCode;
            if (!dNumFmt.TryGetValue(iFmt, out sCode) || sCode == null) return false;
            StringBuilder sb = new StringBuilder();
            bool bInBracket = false, bInQuote = false;
            for (int i = 0; i < sCode.Length; i++)
            {
                char c = sCode[i];
                if (bInQuote) { if (c == '"') bInQuote = false; continue; }
                if (bInBracket) { if (c == ']') bInBracket = false; continue; }
                if (c == '"') { bInQuote = true; continue; }
                if (c == '[') { bInBracket = true; continue; }
                if (c == '\\') { i++; continue; }
                sb.Append(char.ToLowerInvariant(c));
            }
            string s = sb.ToString();
            return s.IndexOf('y') >= 0 || s.IndexOf('d') >= 0 || s.IndexOf('h') >= 0 || s.IndexOf('s') >= 0;
        }

        // importToShell: build a fresh DbDo database -- a temporary "shell"
        // carrying the standard columns plus the maps and lookups tables --
        // from another file, one standard-shape table per table found in
        // the source. This is the "import" verb: unlike Open (which mounts
        // a live ADO driver on the file as-is), Import transfers the data
        // into DbDo's own structure. Excel workbooks are read through Excel
        // COM (out-of-process, so 64-bit DbDo reads any Excel with no ACE
        // and no Office-bitness conflict); every other supported format is
        // read through a short-lived ADO connection. Returns the temp .db
        // path; the caller opens it as a managed copy, so the source file
        // is only ever read.
        internal string importToShell(string sSourcePath)
        {
            if (string.IsNullOrEmpty(sSourcePath)) throw new ArgumentException("importToShell requires a path.");
            string sExt = Path.GetExtension(sSourcePath).TrimStart('.').ToLowerInvariant();
            if (sExt == "xlsx") return importXlsxNative(sSourcePath);
            if (sExt == "xls") return importWorkbookFile(sSourcePath); // legacy binary; read via Excel COM
            if (sExt == "dbf") return importDbfToShell(sSourcePath);   // native dBASE reader; no ACE
            if (sExt == "csv") return importDelimitedToShell(sSourcePath, ',');
            if (sExt == "tsv" || sExt == "tab") return importDelimitedToShell(sSourcePath, '\t');
            return importAdoToShell(sSourcePath);
        }

        // importDelimitedToShell: read a CSV/TSV into a fresh standard
        // shell using the native RFC 4180 parser (no ACE text driver).
        // The first non-empty record is the header; the shaping matches
        // importAdoToShell / importDbfToShell.
        internal string importDelimitedToShell(string sSourcePath, char cDelim)
        {
            if (string.IsNullOrEmpty(sSourcePath)) throw new ArgumentException("importDelimitedToShell requires a path.");
            string sText;
            try { sText = File.ReadAllText(sSourcePath, Encoding.UTF8); }
            catch (Exception ex) { throw new Exception("Could not read " + sSourcePath + ": " + ex.Message, ex); }
            List<string[]> lRecords = DbDoManager.parseDelimited(sText, cDelim);

            // First non-empty record is the header.
            List<string> lCols = null;
            List<string[]> lRows = new List<string[]>();
            foreach (string[] aRec in lRecords)
            {
                bool bEmpty = true;
                foreach (string s in aRec) if (!string.IsNullOrEmpty(s) && s.Trim().Length > 0) { bEmpty = false; break; }
                if (bEmpty) continue;
                if (lCols == null) { lCols = new List<string>(aRec); continue; }
                lRows.Add(aRec);
            }
            if (lCols == null) throw new InvalidOperationException("No header row was found in " + Path.GetFileName(sSourcePath) + ".");

            string[] aReservedRename = new string[] { "added", "edited", "look", "prm", "prm", "marked" };
            string sDbPath = Path.Combine(Path.GetTempPath(),
                "DbDo_managed_" + Guid.NewGuid().ToString("N") + ".db");
            try
            {
                if (File.Exists(sDbPath)) File.Delete(sDbPath);
                using (FileStream fs = File.Create(sDbPath)) { }
                using (DbDoManager managerDest = new DbDoManager())
                {
                    managerDest.openDatabase(sDbPath, null, false);
                    string sTable = sNormalizeIdentifier(Path.GetFileNameWithoutExtension(sSourcePath));
                    if (sTable.Length == 0) sTable = "table_1";
                    if (char.IsDigit(sTable[0])) sTable = "t_" + sTable;
                    string sSingular = sTable.EndsWith("s") ? sTable.Substring(0, sTable.Length - 1) : sTable;
                    string sPk = sSingular + "_id";

                    List<string[]> lFieldDefs = new List<string[]>();
                    List<string> lColTarget = new List<string>();
                    List<string> lUsedNames = new List<string>();
                    foreach (string sCol in lCols)
                    {
                        string sHdr = sNormalizeIdentifier(sCol);
                        if (sHdr.Length == 0) sHdr = "column_" + (lColTarget.Count + 1);
                        if (char.IsDigit(sHdr[0])) sHdr = "c_" + sHdr;
                        if (sHdr == "notes") { lColTarget.Add("notes"); continue; }
                        if (sHdr == "tags") { lColTarget.Add("tags"); continue; }
                        if (sHdr == sPk || Array.IndexOf(aReservedRename, sHdr) >= 0) sHdr = sHdr + "_in";
                        string sBaseH = sHdr; int iDupH = 1;
                        while (lUsedNames.Contains(sHdr)) { iDupH++; sHdr = sBaseH + "_" + iDupH; }
                        lUsedNames.Add(sHdr);
                        lFieldDefs.Add(new string[] { sHdr, "TEXTLINE" });
                        lColTarget.Add(sHdr);
                    }
                    if (lFieldDefs.Count == 0) lFieldDefs.Add(new string[] { "value", "TEXTLINE" });
                    foreach (string sSql in lStandardTableDdl(sTable, lFieldDefs))
                        managerDest.invokeSql(sSql, null);

                    int iRows = 0;
                    foreach (string[] aRow in lRows)
                    {
                        List<string> lInsCols = new List<string>();
                        List<string> lVals = new List<string>();
                        bool bAny = false;
                        for (int i = 0; i < lCols.Count && i < aRow.Length; i++)
                        {
                            string sTarget = (i < lColTarget.Count) ? lColTarget[i] : null;
                            if (sTarget == null) continue;
                            string sCell = aRow[i] ?? "";
                            if (sCell.Length > 0) bAny = true;
                            lInsCols.Add("\"" + sTarget + "\"");
                            lVals.Add("'" + sCell.Replace("'", "''") + "'");
                        }
                        if (bAny)
                        {
                            string sInsert = "INSERT INTO \"" + sTable + "\" ("
                                + string.Join(", ", lInsCols.ToArray()) + ") VALUES ("
                                + string.Join(", ", lVals.ToArray()) + ")";
                            try { managerDest.invokeSql(sInsert, null); iRows++; }
                            catch (Exception exRow) { try { DbDoLog.write("importDelimitedToShell skipped a row: " + exRow.Message); } catch { } }
                        }
                    }
                    foreach (string sSql in lInfraDdl(true, true))
                        managerDest.invokeSql(sSql, null);
                    try { DbDoLog.write("Imported delimited " + sSourcePath + ": " + iRows + " row(s) -> " + sDbPath); } catch { }
                }
                return sDbPath;
            }
            catch
            {
                try { if (File.Exists(sDbPath)) File.Delete(sDbPath); } catch { }
                throw;
            }
        }

        // importDbfToShell: read a dBASE (.dbf, with its .dbt memo
        // sidecar if present) into a fresh standard shell -- the native
        // counterpart of importAdoToShell for dBASE, so dbf import needs
        // no Office/ACE. One .dbf is one table; the shaping (notes/tags
        // routing, reserved-name suffixing, empty-row skipping) matches
        // importAdoToShell.
        internal string importDbfToShell(string sDbfPath)
        {
            if (string.IsNullOrEmpty(sDbfPath)) throw new ArgumentException("importDbfToShell requires a path.");
            DbfReader.Result res = DbfReader.read(sDbfPath);
            string[] aReservedRename = new string[] { "added", "edited", "look", "prm", "prm", "marked" };
            string sDbPath = Path.Combine(Path.GetTempPath(),
                "DbDo_managed_" + Guid.NewGuid().ToString("N") + ".db");
            try
            {
                if (File.Exists(sDbPath)) File.Delete(sDbPath);
                using (FileStream fs = File.Create(sDbPath)) { }
                using (DbDoManager managerDest = new DbDoManager())
                {
                    managerDest.openDatabase(sDbPath, null, false);

                    string sTable = sNormalizeIdentifier(Path.GetFileNameWithoutExtension(sDbfPath));
                    if (sTable.Length == 0) sTable = "table_1";
                    if (char.IsDigit(sTable[0])) sTable = "t_" + sTable;
                    string sSingular = sTable.EndsWith("s") ? sTable.Substring(0, sTable.Length - 1) : sTable;
                    string sPk = sSingular + "_id";

                    List<string[]> lFieldDefs = new List<string[]>();
                    List<string> lColTarget = new List<string>();
                    List<string> lUsedNames = new List<string>();
                    foreach (string sCol in res.Columns)
                    {
                        string sHdr = sNormalizeIdentifier(sCol);
                        if (sHdr.Length == 0) sHdr = "column_" + (lColTarget.Count + 1);
                        if (char.IsDigit(sHdr[0])) sHdr = "c_" + sHdr;
                        if (sHdr == "notes") { lColTarget.Add("notes"); continue; }
                        if (sHdr == "tags") { lColTarget.Add("tags"); continue; }
                        if (sHdr == sPk || Array.IndexOf(aReservedRename, sHdr) >= 0) sHdr = sHdr + "_in";
                        string sBaseH = sHdr; int iDupH = 1;
                        while (lUsedNames.Contains(sHdr)) { iDupH++; sHdr = sBaseH + "_" + iDupH; }
                        lUsedNames.Add(sHdr);
                        lFieldDefs.Add(new string[] { sHdr, "TEXTLINE" });
                        lColTarget.Add(sHdr);
                    }
                    if (lFieldDefs.Count == 0) lFieldDefs.Add(new string[] { "value", "TEXTLINE" });
                    foreach (string sSql in lStandardTableDdl(sTable, lFieldDefs))
                        managerDest.invokeSql(sSql, null);

                    int iRows = 0;
                    foreach (string[] aRow in res.Rows)
                    {
                        List<string> lInsCols = new List<string>();
                        List<string> lVals = new List<string>();
                        bool bAny = false;
                        for (int i = 0; i < res.Columns.Count && i < aRow.Length; i++)
                        {
                            string sTarget = (i < lColTarget.Count) ? lColTarget[i] : null;
                            if (sTarget == null) continue;
                            string sCell = aRow[i] ?? "";
                            if (sCell.Length > 0) bAny = true;
                            lInsCols.Add("\"" + sTarget + "\"");
                            lVals.Add("'" + sCell.Replace("'", "''") + "'");
                        }
                        if (bAny)
                        {
                            string sInsert = "INSERT INTO \"" + sTable + "\" ("
                                + string.Join(", ", lInsCols.ToArray()) + ") VALUES ("
                                + string.Join(", ", lVals.ToArray()) + ")";
                            try { managerDest.invokeSql(sInsert, null); iRows++; }
                            catch (Exception exRow) { try { DbDoLog.write("importDbfToShell skipped a row: " + exRow.Message); } catch { } }
                        }
                    }
                    foreach (string sSql in lInfraDdl(true, true))
                        managerDest.invokeSql(sSql, null);
                    try { DbDoLog.write("Imported DBF " + sDbfPath + ": " + iRows + " row(s) -> " + sDbPath); } catch { }
                }
                return sDbPath;
            }
            catch
            {
                try { if (File.Exists(sDbPath)) File.Delete(sDbPath); } catch { }
                throw;
            }
        }

        // importAdoToShell: read every table of an ADO-accessible source
        // (SQLite .db/.sqlite/.sqlite3, Access .mdb/.accdb, dBASE .dbf, or
        // CSV/TSV/TXT) through a short-lived read-only manager and build a
        // temp DbDo shell. The source's own maps/lookups tables are skipped
        // -- the shell supplies fresh ones. The per-table shaping mirrors
        // importWorkbookFile, so the result is identical whatever the source
        // format: a column named notes or tags routes into the standard
        // column, other standard-name collisions get an "_in" suffix, and a
        // duplicate row that would trip the UNIQUE prm index is skipped.
        internal string importAdoToShell(string sSourcePath)
        {
            if (string.IsNullOrEmpty(sSourcePath)) throw new ArgumentException("importAdoToShell requires a path.");
            string[] aReservedRename = new string[] { "added", "edited", "look", "prm", "prm", "marked" };
            string sDbPath = Path.Combine(Path.GetTempPath(),
                "DbDo_managed_" + Guid.NewGuid().ToString("N") + ".db");
            int iTablesImported = 0, iRowsImported = 0;
            try
            {
                if (File.Exists(sDbPath)) File.Delete(sDbPath);
                using (FileStream fs = File.Create(sDbPath)) { }
                using (DbDoManager managerSrc = new DbDoManager())
                using (DbDoManager managerDest = new DbDoManager())
                {
                    managerSrc.openDatabase(sSourcePath, null, true);   // read-only source
                    managerDest.openDatabase(sDbPath, null, false);
                    List<string> lTableNames = new List<string>();
                    foreach (string sSrcTable in managerSrc.getTableNames())
                    {
                        string sNorm = sNormalizeIdentifier(sSrcTable);
                        if (sNorm == "maps" || sNorm == "lookups") continue; // shell supplies its own
                        managerSrc.selectTable(sSrcTable);
                        List<string> lCols = managerSrc.getColumnsOfTable(sSrcTable);
                        if (lCols.Count == 0) continue;

                        string sTable = sNorm.Length == 0 ? "table_" + (iTablesImported + 1) : sNorm;
                        if (char.IsDigit(sTable[0])) sTable = "t_" + sTable;
                        string sBaseT = sTable; int iDupT = 1;
                        while (lTableNames.Contains(sTable)) { iDupT++; sTable = sBaseT + "_" + iDupT; }
                        lTableNames.Add(sTable);
                        string sSingular = sTable.EndsWith("s") ? sTable.Substring(0, sTable.Length - 1) : sTable;
                        string sPk = sSingular + "_id";

                        List<string[]> lFieldDefs = new List<string[]>();
                        List<string> lColTarget = new List<string>();
                        List<string> lUsedNames = new List<string>();
                        foreach (string sCol in lCols)
                        {
                            string sHdr = sNormalizeIdentifier(sCol);
                            if (sHdr.Length == 0) sHdr = "column_" + (lColTarget.Count + 1);
                            if (char.IsDigit(sHdr[0])) sHdr = "c_" + sHdr;
                            if (sHdr == "notes") { lColTarget.Add("notes"); continue; }
                            if (sHdr == "tags") { lColTarget.Add("tags"); continue; }
                            if (sHdr == sPk || Array.IndexOf(aReservedRename, sHdr) >= 0) sHdr = sHdr + "_in";
                            string sBaseH = sHdr; int iDupH = 1;
                            while (lUsedNames.Contains(sHdr)) { iDupH++; sHdr = sBaseH + "_" + iDupH; }
                            lUsedNames.Add(sHdr);
                            lFieldDefs.Add(new string[] { sHdr, "TEXTLINE" });
                            lColTarget.Add(sHdr);
                        }
                        if (lFieldDefs.Count == 0) lFieldDefs.Add(new string[] { "value", "TEXTLINE" });
                        foreach (string sSql in lStandardTableDdl(sTable, lFieldDefs))
                            managerDest.invokeSql(sSql, null);

                        managerSrc.moveFirst();
                        while (!managerSrc.eof)
                        {
                            List<string> lInsCols = new List<string>();
                            List<string> lVals = new List<string>();
                            bool bAny = false;
                            for (int i = 0; i < lCols.Count; i++)
                            {
                                string sTarget = lColTarget[i];
                                if (sTarget == null) continue;
                                string sCell = managerSrc.getFieldValue(lCols[i]) ?? "";
                                if (sCell.Length > 0) bAny = true;
                                lInsCols.Add("\"" + sTarget + "\"");
                                lVals.Add("'" + sCell.Replace("'", "''") + "'");
                            }
                            if (bAny)
                            {
                                string sInsert = "INSERT INTO \"" + sTable + "\" ("
                                    + string.Join(", ", lInsCols.ToArray()) + ") VALUES ("
                                    + string.Join(", ", lVals.ToArray()) + ")";
                                try { managerDest.invokeSql(sInsert, null); iRowsImported++; }
                                catch (Exception exRow) { try { DbDoLog.write("importAdoToShell skipped a row in " + sTable + ": " + exRow.Message); } catch { } }
                            }
                            managerSrc.moveNext();
                        }
                        iTablesImported++;
                    }
                    if (iTablesImported == 0)
                        throw new InvalidOperationException("No importable tables were found in " + Path.GetFileName(sSourcePath) + ".");
                    foreach (string sSql in lInfraDdl(true, true))
                        managerDest.invokeSql(sSql, null);
                }
                try { DbDoLog.write("Imported " + sSourcePath + ": " + iTablesImported
                    + " table(s), " + iRowsImported + " row(s) -> " + sDbPath); } catch { }
                return sDbPath;
            }
            catch
            {
                try { if (File.Exists(sDbPath)) File.Delete(sDbPath); } catch { }
                throw;
            }
        }

        // Recent Files (Alt+R / File > Recent Files): show an LBC
        // dialog listing up to the last 10 database files the user
        // has opened. Selecting one re-opens it, restoring the
        // last-active table (if it still exists) and that table's
        // filter / sort / position (silently skipping any piece
        // that no longer applies). The list is populated from the
        // [RecentFile1..10] sections of DbDo.inix.
        private void fileRecentClicked(object sender, EventArgs evArgs)
        {
            List<RecentFiles.FileState> l = RecentFiles.loadAll();
            if (l.Count == 0)
            {
                MessageBox.Show(this,
                    "No recent database files yet. Open a database from the File menu to start the list.",
                    "Recent Files", MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }
            LbcDialog dlg = new LbcDialog("Recent Files", this);
            try
            {
                List<string> lDisplay = new List<string>();
                foreach (RecentFiles.FileState f in l)
                {
                    string sDisp = f.sPath;
                    if (!string.IsNullOrEmpty(f.sLastTable))
                        sDisp += "   (last table: " + f.sLastTable + ")";
                    lDisplay.Add(sDisp);
                }
                ListBox lb = dlg.addPickBox(
                    "&Recent database files (Enter to open):",
                    lDisplay, lDisplay[0],
                    "Each entry shows the path and the last table that was active. Opening restores the table, filter, sort, and position.");
                if (!dlg.runOkCancel()) return;
                int iIdx = lb.SelectedIndex;
                if (iIdx < 0 || iIdx >= l.Count) return;
                openDatabaseAndApplyState(l[iIdx].sPath, l[iIdx]);
            }
            finally { dlg.Dispose(); }
        }

        // openDatabaseAndApplyState: shared open path used by both
        // File > Open and File > Recent Files. Opens the file,
        // applies any saved per-table state from a FileState (or
        // none if null), records the open in RecentFiles, and
        // updates IniSession's last-opened pointers. Failures at
        // the per-table-state restore step are silently swallowed
        // per the spec ("if something is missing so cannot be
        // configured ... just silently skip the incongruity").
        //
        // All previously-visited tables are pre-seeded into the
        // manager's in-session cache so a later switch to any of
        // them (via Choose Table, Control+Tab, or dot prompt) lands
        // on the user's last filter / sort / position / virtual
        // column for that table.
        private void openDatabaseAndApplyState(string sPath, RecentFiles.FileState state)
        {
            try
            {
                DbDoLog.write("Opening: " + sPath);
                clearDrillStack();
                // A new open ends any prior workbook-edit session. The
                // .xlsx path in fileOpenClicked re-sets these AFTER this
                // returns; every other open (a .db, Recent Files, etc.)
                // leaves them cleared so Save Workbook stays inert.
                sWorkbookOriginPath = null;
                sWorkbookSheetName = null;
                sWorkbookTable = null;
                lWorkbookColumns = null;
                // Reset the first-populate flag so the JAWS "Unselected"
                // workaround fires once for this new database.
                bGridFirstPopulate = true;
                // Session-lifetime bookmarks: clear on database open.
                lBookmarks.Clear();
                db.openDatabase(sPath, null, false);
                // Heads-up for formats whose in-place writes are best-
                // effort: the user can edit, but ACE may coerce or drop
                // values. The detail goes to the log; a short spoken note
                // tells the screen-reader user without a dialog to dismiss.
                string sOpenExt = Path.GetExtension(sPath).TrimStart('.').ToLowerInvariant();
                string sOpenLimit = describeFormatLimitations(sOpenExt);
                if (sOpenLimit.Length > 0)
                {
                    DbDoLog.write("Opened editable ." + sOpenExt + " (in-place edits best-effort): " + sOpenLimit);
                    LiveRegion.say("Note: edits to this " + sOpenExt + " file are best effort and may not all save back exactly.");
                }

                // Pre-seed the manager's in-session per-table cache
                // from EVERY entry in state.dTables. This way, switching
                // to a different table later in the session picks up
                // its saved filter / sort / position / virtual column,
                // not just the table we open initially. The seeding is
                // pure data movement, no recordset open per table.
                if (state != null && state.dTables != null)
                {
                    foreach (KeyValuePair<string, RecentFiles.TableState> kv in state.dTables)
                    {
                        RecentFiles.TableState ts = kv.Value;
                        if (ts == null) continue;
                        db.seedTableSettings(kv.Key, ts.sFilter, ts.sSort,
                            ts.iPosition, ts.sVirtualColumn, ts.sSelectList);
                    }
                }

                // Pick the table: saved lastTable if it still exists,
                // else first base table, else first view.
                string sDesiredTable = (state != null) ? state.sLastTable : null;
                List<string> lTables = db.getTableNames();
                if (lTables == null || lTables.Count == 0) lTables = db.getViewNames();
                if (lTables == null) lTables = new List<string>();
                if (string.IsNullOrEmpty(sDesiredTable) || !lTables.Contains(sDesiredTable))
                {
                    // Prefer a real data table over DbDo's infrastructure
                    // tables. getTableNames() is alphabetical, so without this
                    // an imported book list (table "sheet1") loses to "lookups"
                    // and "maps" and the user lands on the 14-row lookups table
                    // -- which looks exactly like an import that only read 14
                    // records. Fall back to the first table only if every table
                    // is infrastructure.
                    sDesiredTable = null;
                    foreach (string sT in lTables)
                    {
                        if (string.Equals(sT, "maps", StringComparison.OrdinalIgnoreCase)) continue;
                        if (string.Equals(sT, "lookups", StringComparison.OrdinalIgnoreCase)) continue;
                        sDesiredTable = sT; break;
                    }
                    if (sDesiredTable == null) sDesiredTable = lTables.Count > 0 ? lTables[0] : null;
                }
                // A table pinned as InitialTable in this database's
                // <DbName>.inix [Database] section wins over the remembered
                // or first-table choice, so the database always opens on the
                // starting window the user chose. Read directly from the
                // scoped path here because sActiveDbInixPath is not set until
                // just below. Other windows are opened later via Ctrl+Shift+O.
                try
                {
                    string sPinInix = dbScopedInixPath();
                    if (!string.IsNullOrEmpty(sPinInix) && File.Exists(sPinInix))
                    {
                        string sPin = DbDoManager.readIniFromFile(sPinInix, "Database", "InitialTable");
                        if (!string.IsNullOrEmpty(sPin) && lTables.Contains(sPin))
                            sDesiredTable = sPin;
                    }
                }
                catch { }
                if (!string.IsNullOrEmpty(sDesiredTable))
                {
                    // selectTable will consult the per-table cache we
                    // just seeded and apply that table's filter, sort,
                    // and position automatically.
                    try { db.selectTable(sDesiredTable); } catch { }
                }
                invokeRefresh();
                DbDoLog.write("Open succeeded. Table: " + (db.currentTable ?? "(none)"));
                sActiveDbInixPath = dbScopedInixPath();
                seedDbSettings();
                IniSession.lastDatabase = sPath;
                IniSession.lastTable    = db.currentTable ?? "";
                // Record into Recent Files list (move-to-front).
                RecentFiles.recordOpen(sPath);
                announceTableOpened();
            }
            catch (Exception ex)
            {
                DbDoLog.write("Open failed: " + ex.Message);
                ErrorDialog.show(this, "Open Database", ex.Message);
            }
        }

        private void fileSaveAsClicked(object sender, EventArgs evArgs) { saveAsCommon("Save As"); }
        private void fileBackupClicked(object sender, EventArgs evArgs) { saveAsCommon("Backup Database"); }

        // helpSampleDbClicked: the Sample Databases command. Lists every
        // .db file in the user's Samples folder at runtime
        // (%APPDATA%\DbDo\Samples, seeded once from {app}\Samples) and
        // opens the chosen one through the normal state-restoring open
        // path, so its remembered per-table sort, filter, and position
        // come back exactly as they do for Open Database and Recent
        // Files. The folder is discovered dynamically: the user can drop
        // their own databases into it to add them to the list, and new
        // bundled samples appear without any code change here.
        private void helpSampleDbClicked(object sender, EventArgs evArgs)
        {
            string[] aPaths = ScriptHelper.listSampleDatabases();
            if (aPaths.Length == 0)
            {
                MessageBox.Show(this,
                    "No sample databases found in:\n\n" + ScriptHelper.getSampleDir()
                    + "\n\nEach sample lives in its own subfolder there (for example, "
                    + "Samples\\music\\music.db). Drop a database into such a subfolder and try again.",
                    "Sample Databases", MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }
            // Show each database by its root name (its folder), mapping
            // the label back to the full path. On the rare chance two
            // roots collide, fall back to "<folder>\<file>".
            System.Collections.Generic.SortedDictionary<string, string> dMap =
                new System.Collections.Generic.SortedDictionary<string, string>(StringComparer.OrdinalIgnoreCase);
            foreach (string sP in aPaths)
            {
                string sLabel = System.IO.Path.GetFileNameWithoutExtension(sP);
                if (dMap.ContainsKey(sLabel))
                    sLabel = System.IO.Path.GetFileName(System.IO.Path.GetDirectoryName(sP))
                           + "\\" + System.IO.Path.GetFileName(sP);
                dMap[sLabel] = sP;
            }
            List<string> lNames = new List<string>(dMap.Keys);
            string sChosen = promptListChoice("Sample Databases",
                "Choose a sample database to open:", lNames, lNames[0]);
            if (string.IsNullOrEmpty(sChosen)) return;
            string sPath = dMap[sChosen];
            if (!System.IO.File.Exists(sPath))
            {
                ErrorDialog.show(this, "Sample Databases", "The chosen database no longer exists: " + sPath);
                return;
            }
            try
            {
                RecentFiles.FileState stSample = RecentFiles.findByPath(RecentFiles.loadAll(), sPath);
                openDatabaseAndApplyState(sPath, stSample);
            }
            catch (Exception ex)
            {
                ErrorDialog.show(this, "Sample Databases", ex.Message);
            }
        }

        // The per-sample openers (Northwind / Chinook / Convention) were
        // removed with their menu items; the Sample Databases picker
        // (helpSampleDbClicked) discovers and opens every bundled .db
        // under the Samples tree at runtime. openInstallSampleDb is kept
        // below for any caller that opens a known bundled file by name.

        // openInstallSampleDb: shared open path for the bundled sample
        // databases. Looks for the named file next to the executable
        // and opens it via openDatabaseAndApplyState so the normal
        // post-open behaviors apply (filter restore, status
        // announcement, etc.). If the file is missing, the user sees
        // a clean message instead of an opaque exception.
        private void openInstallSampleDb(string sFileName, string sTitle)
        {
            string sAppDir = Path.GetDirectoryName(
                System.Reflection.Assembly.GetExecutingAssembly().Location) ?? "";
            // New layout: {app}\Samples\<root>\<file>. Fall back to the
            // older flat {app}\<file> when the per-database folder is
            // absent, so the command works under either layout.
            string sRoot = Path.GetFileNameWithoutExtension(sFileName);
            string sPath = Path.Combine(sAppDir, "Samples", sRoot, sFileName);
            if (!File.Exists(sPath)) sPath = Path.Combine(sAppDir, sFileName);
            if (!File.Exists(sPath))
            {
                MessageBox.Show(this,
                    sFileName + " not found in the DbDo install folder:\n\n" + sPath
                    + "\n\nIf you installed DbDo via the regular installer the sample is normally placed here automatically.",
                    sTitle, MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }
            try
            {
                RecentFiles.FileState st = RecentFiles.findByPath(RecentFiles.loadAll(), sPath);
                openDatabaseAndApplyState(sPath, st);
            }
            catch (Exception ex)
            {
                ErrorDialog.show(this, sTitle, ex.Message);
            }
        }

        // describeFormatLimitations: a plain-language summary of what a
        // target file format cannot faithfully store, used by the
        // lossy-save notifications. Returns "" for formats that round-
        // trip cleanly (SQLite, Access, and report/snapshot formats the
        // user already knows are one-way, like JSON/Markdown/HTML).
        private static string describeFormatLimitations(string sExt)
        {
            switch ((sExt ?? "").ToLowerInvariant())
            {
                case "xlsx": case "xls": case "xlsm": case "xlsb":
                    return "Excel stores cell values but not column data types, so types are re-guessed when the file is reopened; "
                         + "a column that mixes text and numbers can read back with some cells blank, and formulas and formatting are not preserved.";
                case "csv": case "tsv": case "tab": case "txt":
                    return "Text files store no data types (every column reads back as text) and no keys, indexes, or relationships.";
                case "dbf":
                    return "dBASE shortens table and field names and limits column types and field sizes; long names and unsupported types are truncated or changed.";
                default:
                    return "";
            }
        }

        // confirmLossyConversion: a Word-style heads-up shown before
        // writing to a format that cannot store everything. Returns true
        // to proceed. When the target round-trips cleanly and the single-
        // table caveat does not apply, there is nothing to warn about and
        // it proceeds without prompting. The capability is never blocked
        // -- the user is informed and chooses.
        private bool confirmLossyConversion(string sTitle, string sTargetExt, bool bIncludeSingleTable)
        {
            string sLimit = describeFormatLimitations(sTargetExt);
            if (sLimit.Length == 0 && !bIncludeSingleTable) return true;
            StringBuilder sb = new StringBuilder();
            sb.Append("Saving as ." + (sTargetExt ?? "").ToLowerInvariant() + " is a lossy conversion:\n\n");
            if (bIncludeSingleTable)
                sb.Append("\u2022 Only the current table is written; other tables in the database are not included.\n");
            if (sLimit.Length > 0)
                sb.Append("\u2022 " + sLimit + "\n");
            sb.Append("\nSave in this format anyway?");
            DbDoLog.write("confirmLossyConversion: prompting for ." + (sTargetExt ?? "") + " (singleTable=" + bIncludeSingleTable + ").");
            DialogResult res = MessageBox.Show(this, sb.ToString(), sTitle,
                MessageBoxButtons.YesNo, MessageBoxIcon.Warning);
            return res == DialogResult.Yes;
        }

        private void saveAsCommon(string sTitle)
        {
            if (db == null || !db.isOpen()) return;
            using (SaveFileDialog dlgFile = new SaveFileDialog())
            {
                dlgFile.Title = sTitle;
                prepareFileDialog(dlgFile);
                string sExt = Path.GetExtension(db.filePath).TrimStart('.');
                dlgFile.Filter = "Same format (*." + sExt + ")|*." + sExt + "|All Files (*.*)|*.*";
                dlgFile.DefaultExt = sExt;
                // Default folder = the currently-open database's folder
                // (the Save-As is typically a copy alongside the
                // original). Default filename = the source file's
                // name, leaving the user one keystroke from a
                // sensible "FooBackup.db" or similar by editing it.
                dlgFile.InitialDirectory = IniFolders.bestDirectory("", db.filePath);
                // For a managed copy (e.g. an imported workbook) the live
                // file is a temp GUID name; suggest the origin's name
                // instead. The extension still follows db.filePath (.db),
                // so a workbook-backed copy is never written over the xlsx.
                string sNameSource = !string.IsNullOrEmpty(sManagedOriginPath) ? sManagedOriginPath : db.filePath;
                string sLeaf = Path.GetFileNameWithoutExtension(sNameSource);
                if (!string.IsNullOrEmpty(sLeaf))
                {
                    // Suggest "<original>-copy" so we don't overwrite
                    // the original by mistake when the user just
                    // presses Enter.
                    string sSuggest = sLeaf + "-copy";
                    if (sTitle.IndexOf("Backup", StringComparison.OrdinalIgnoreCase) >= 0)
                        sSuggest = sLeaf + "-backup-" + DateTime.Now.ToString("yyyyMMdd");
                    dlgFile.FileName = sSuggest;
                }
                if (dlgFile.ShowDialog(this) != DialogResult.OK) return;
                // Guard the "save over the open database" case before we
                // try anything. It is a copy-onto-itself that stalls on
                // the live file lock (the "I hit Yes and it stopped
                // responding" report), and it is not what the user needs:
                // the Alt+S column order and other display choices are a
                // per-table view preference already saved in DbDo.inix,
                // not in the .db file, so no file save is required to
                // keep them. Save Database is only for a separate copy.
                try
                {
                    if (string.Equals(Path.GetFullPath(dlgFile.FileName), Path.GetFullPath(db.filePath),
                                      StringComparison.OrdinalIgnoreCase))
                    {
                        MessageBox.Show(this,
                            "That is the database that is already open, so there is nothing to copy over it.\n\n"
                            + "Your column order and other display choices are saved automatically as you make them, "
                            + "so you do not need to save the file to keep them. To make a separate copy, choose a "
                            + "different file name.",
                            sTitle, MessageBoxButtons.OK, MessageBoxIcon.Information);
                        return;
                    }
                }
                catch { /* path compare failed; fall through to the normal save */ }
                // Word-style lossy-conversion heads-up: a same-format
                // Save As is a clean file copy, but a different target
                // format is a conversion (single-table, plus the format's
                // own limits). Inform, don't block.
                string sTargetExt = Path.GetExtension(dlgFile.FileName).TrimStart('.');
                if (!string.Equals(sTargetExt, sExt, StringComparison.OrdinalIgnoreCase)
                    && !confirmLossyConversion(sTitle, sTargetExt, true))
                    return;
                IniFolders.openFolder = Path.GetDirectoryName(dlgFile.FileName);
                try
                {
                    db.saveAs(dlgFile.FileName);
                    invokeRefresh();
                    MessageBox.Show(this, "Saved to: " + dlgFile.FileName, sTitle, MessageBoxButtons.OK, MessageBoxIcon.Information);
                }
                catch (Exception ex)
                {
                    ErrorDialog.show(this, sTitle, ex.Message);
                }
            }
        }

        private void fileCloseClicked(object sender, EventArgs evArgs)
        {
            if (db == null) return;
            if (!confirmSaveWorkbookIfDirty()) return;
            try { db.close(); } catch { }
            sActiveDbInixPath = null;
            // Reset the drill linkage so navigation state doesn't leak
            // across databases. The TableSettings cache inside
            // DbDoManager is cleared by db.close() itself.
            clearDrillStack();
            iMarkAnchor = -1;
            sMarkAnchorTable = null;
            iUnmarkAnchor = -1;
            sUnmarkAnchorTable = null;
            invokeRefresh();
            // Clear session persistence so the next launch starts
            // empty rather than reopening the just-closed file.
            IniSession.lastDatabase = "";
            IniSession.lastTable    = "";
        }

        private void fileCompareClicked(object sender, EventArgs evArgs)
        {
            MessageBox.Show(this, "Compare Database is not yet implemented.",
                "Compare Database", MessageBoxButtons.OK, MessageBoxIcon.Information);
        }

        private void mergeClicked(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset())
            {
                MessageBox.Show(this, "Open a database and pick a target table first.",
                    "Merge", MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }
            using (OpenFileDialog dlgFile = new OpenFileDialog())
            {
                dlgFile.Title = "Merge into " + (db.currentTable ?? "current table");
                prepareFileDialog(dlgFile);
                dlgFile.Filter = "Markdown table (*.md;*.markdown)|*.md;*.markdown"
                           + "|CSV (*.csv)|*.csv"
                           + "|TSV (*.tsv;*.tab)|*.tsv;*.tab"
                           + "|JSON (*.json)|*.json"
                           + "|Inix file (*.inix)|*.inix"
                           + "|All Files (*.*)|*.*";
                dlgFile.DefaultExt = "md";
                // Default folder: last import folder, else the
                // current database's folder, else Documents.
                dlgFile.InitialDirectory = IniFolders.bestDirectory(IniFolders.importFolder, db.filePath);
                if (dlgFile.ShowDialog(this) != DialogResult.OK) return;
                IniFolders.importFolder = Path.GetDirectoryName(dlgFile.FileName);
                try
                {
                    string sExt = Path.GetExtension(dlgFile.FileName).TrimStart('.').ToLowerInvariant();
                    int iCount;
                    if (sExt == "inix")
                        iCount = db.importInix(dlgFile.FileName);
                    else if (sExt == "json")
                        iCount = db.importJson(dlgFile.FileName);
                    else if (sExt == "csv")
                        iCount = db.importDelimited(dlgFile.FileName, ',');
                    else if (sExt == "tsv" || sExt == "tab")
                        iCount = db.importDelimited(dlgFile.FileName, '\t');
                    else
                        iCount = db.importMarkdown(dlgFile.FileName);
                    DbDoLog.write("Merged " + iCount + " row(s) from " + dlgFile.FileName);
                    invokeRefresh();
                    MessageBox.Show(this,
                        "Merged " + iCount + " row(s) into " + db.currentTable + ".",
                        "Merge", MessageBoxButtons.OK, MessageBoxIcon.Information);
                }
                catch (Exception ex)
                {
                    ErrorDialog.show(this, "Merge", ex.Message);
                }
            }
        }

        // Transfer Import: bring records in from an external source file
        // (.dbf, .mdb/.accdb, .db) into the current table through a
        // transfer map (.inix), renaming and optionally transforming
        // each field with a JScript expression. This is the modern heir
        // of the legacy DbDialog transfer.ini -- useful, for instance,
        // to import a DOS-era CTS dBASE file into a DbDo contact table,
        // reformatting its packed YYYYMMDD dates along the way.
        private void importTransferClicked(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset())
            {
                MessageBox.Show(this, "Open a database and pick a destination table first.",
                    "Transfer Import", MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }

            // 1. Choose the transfer map.
            string sInix;
            using (OpenFileDialog dlgMap = new OpenFileDialog())
            {
                dlgMap.Title = "Choose a transfer map";
                prepareFileDialog(dlgMap);
                dlgMap.Filter = "Transfer map (*.inix)|*.inix|All Files (*.*)|*.*";
                dlgMap.DefaultExt = "inix";
                dlgMap.InitialDirectory = IniFolders.bestDirectory(IniFolders.importFolder, db.filePath);
                if (dlgMap.ShowDialog(this) != DialogResult.OK) return;
                sInix = dlgMap.FileName;
                IniFolders.importFolder = Path.GetDirectoryName(sInix);
            }

            // 2. Choose the mapping section within it.
            List<string> lSections = new List<string>();
            try
            {
                foreach (InixCodec.Section s in InixCodec.read(sInix))
                    if (!string.Equals(s.Name, "Global", StringComparison.OrdinalIgnoreCase))
                        lSections.Add(s.Name);
            }
            catch (Exception ex) { ErrorDialog.show(this, "Transfer Import", ex.Message); return; }
            if (lSections.Count == 0)
            {
                MessageBox.Show(this, "That .inix has no mapping sections.",
                    "Transfer Import", MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }
            string sSection = (lSections.Count == 1)
                ? lSections[0]
                : promptListChoice("Transfer Import", "Choose the mapping to apply:", lSections, lSections[0]);
            if (string.IsNullOrEmpty(sSection)) return;

            // 3. Choose the source file.
            string sSource;
            using (OpenFileDialog dlgSrc = new OpenFileDialog())
            {
                dlgSrc.Title = "Choose the source file to import from";
                prepareFileDialog(dlgSrc);
                dlgSrc.Filter = "Source databases (*.dbf;*.mdb;*.accdb;*.db;*.sqlite;*.sqlite3)"
                    + "|*.dbf;*.mdb;*.accdb;*.db;*.sqlite;*.sqlite3|All Files (*.*)|*.*";
                dlgSrc.InitialDirectory = IniFolders.bestDirectory(IniFolders.importFolder, db.filePath);
                if (dlgSrc.ShowDialog(this) != DialogResult.OK) return;
                sSource = dlgSrc.FileName;
            }

            // 4. Run it.
            try
            {
                int iCount = db.importWithTransferMap(sSource, sInix, sSection);
                invokeRefresh();
                MessageBox.Show(this,
                    "Imported " + iCount + " row(s) into " + db.currentTable + " using [" + sSection + "].",
                    "Transfer Import", MessageBoxButtons.OK, MessageBoxIcon.Information);
            }
            catch (Exception ex)
            {
                ErrorDialog.show(this, "Transfer Import", ex.Message);
            }
        }

        // Produce Report: render a report template (.inix) over the
        // current filtered set to a Markdown file and open it. The
        // template language is documented in DbDo.md ("Report
        // templates"); it reuses the same $field / {{ jscript }}
        // substitution as transfer maps, and Markdown output converts
        // cleanly to HTML, DOCX, or plain text with your own tools.
        // Run Report (Alt+Shift+R): render a saved report definition over
        // the whole PHYSICAL table to a Markdown file and open it. Report
        // definitions live in a report.inix (or *.report.inix /
        // *.reports.inix) file beside the database; each [section] is one
        // report. We discover those files automatically and present a
        // pick-list, falling back to a file browser only when none are
        // found. This is the reproducible, definition-driven counterpart to
        // Generate from Grid (Alt+Shift+G), which is ad-hoc over the grid view.
        private void produceReportClicked(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset())
            {
                MessageBox.Show(this, "Open a database and pick a table first.",
                    "Run Report", MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }

            // 1. Find report definitions in the expected location and pick one.
            string sInix = null, sSection = null;
            List<string[]> lReports = discoverReports();   // each: {label, file, section}
            if (lReports.Count > 0)
            {
                List<string> lLabels = new List<string>();
                foreach (string[] r in lReports) lLabels.Add(r[0]);
                string sPicked = (lLabels.Count == 1)
                    ? lLabels[0]
                    : promptListChoice("Run Report", "Choose a report:", lLabels, lLabels[0]);
                if (string.IsNullOrEmpty(sPicked)) return;
                int iIdx = lLabels.IndexOf(sPicked);
                if (iIdx < 0) return;
                sInix = lReports[iIdx][1];
                sSection = lReports[iIdx][2];
            }
            else
            {
                // No report.inix beside the database -- let the user browse.
                using (OpenFileDialog dlgMap = new OpenFileDialog())
                {
                    dlgMap.Title = "Choose a report definition (no report.inix found beside this database)";
                    prepareFileDialog(dlgMap);
                    dlgMap.Filter = "Report definition (*.inix)|*.inix|All Files (*.*)|*.*";
                    dlgMap.DefaultExt = "inix";
                    dlgMap.InitialDirectory = IniFolders.bestDirectory(IniFolders.importFolder, db.filePath);
                    if (dlgMap.ShowDialog(this) != DialogResult.OK) return;
                    sInix = dlgMap.FileName;
                    IniFolders.importFolder = Path.GetDirectoryName(sInix);
                }
                List<string> lSections = new List<string>();
                try
                {
                    foreach (InixCodec.Section s in InixCodec.read(sInix))
                        if (!string.Equals(s.Name, "Global", StringComparison.OrdinalIgnoreCase) && sectionHasBand(s))
                            lSections.Add(s.Name);
                }
                catch (Exception ex) { ErrorDialog.show(this, "Run Report", ex.Message); return; }
                if (lSections.Count == 0)
                {
                    MessageBox.Show(this, "That .inix has no report sections.",
                        "Run Report", MessageBoxButtons.OK, MessageBoxIcon.Information);
                    return;
                }
                sSection = (lSections.Count == 1)
                    ? lSections[0]
                    : promptListChoice("Run Report", "Choose a report:", lSections, lSections[0]);
                if (string.IsNullOrEmpty(sSection)) return;
            }

            // 2. Render over the physical table to Markdown.
            string sMarkdown;
            try { sMarkdown = db.generateReport(sInix, sSection); }
            catch (Exception ex) { ErrorDialog.show(this, "Run Report", ex.Message); return; }

            // 3. Save the Markdown and open it in the editor.
            using (SaveFileDialog dlgOut = new SaveFileDialog())
            {
                dlgOut.Title = "Save report as Markdown";
                dlgOut.Filter = "Markdown (*.md)|*.md|All Files (*.*)|*.*";
                dlgOut.DefaultExt = "md";
                dlgOut.FileName = sSection + ".md";
                dlgOut.InitialDirectory = IniFolders.bestDirectory(IniFolders.exportFolder, db.filePath);
                if (dlgOut.ShowDialog(this) != DialogResult.OK) return;
                IniFolders.exportFolder = Path.GetDirectoryName(dlgOut.FileName);
                try
                {
                    File.WriteAllText(dlgOut.FileName, sMarkdown, new UTF8Encoding(true));
                    DbDoLog.write("Run Report: [" + sSection + "] -> " + dlgOut.FileName);
                    ScriptHelper.openInEditor(dlgOut.FileName);
                }
                catch (Exception ex) { ErrorDialog.show(this, "Run Report", ex.Message); }
            }
        }

        // discoverReports: scan the database's folder for report-definition
        // files (report.inix, *.report.inix, *.reports.inix) and return one
        // entry per report section, {label, file, section}. When more than
        // one file contributes, the label is disambiguated with the file
        // name. A section counts as a report only if it has at least one
        // band, so a stray [Global] or settings section is never listed.
        private List<string[]> discoverReports()
        {
            List<string[]> lFound = new List<string[]>();
            string sDb = (db != null) ? db.filePath : null;
            if (string.IsNullOrEmpty(sDb)) return lFound;
            string sFolder = Path.GetDirectoryName(sDb);
            if (string.IsNullOrEmpty(sFolder) || !Directory.Exists(sFolder)) return lFound;

            // Every .inix beside the database is a candidate. A file is a
            // report file when its [Global] section declares FileTask =
            // report -- that is the convention that lets one folder hold
            // several .inix files for different tasks (reports, transfer
            // maps, settings) and still show only the right ones here.
            // Files that predate the FileTask convention are still accepted
            // when they declare no task at all yet carry report bands, so
            // existing report.inix definitions keep working; a file that
            // declares some other task is never offered as a report.
            List<string> lFiles = new List<string>();
            try
            {
                foreach (string sF in Directory.GetFiles(sFolder, "*.inix"))
                    if (!lFiles.Contains(sF)) lFiles.Add(sF);
            }
            catch { }

            // First pass: decide which files are reports and keep their
            // parsed sections so the label pass does not re-read them.
            List<string> lReportFiles = new List<string>();
            Dictionary<string, List<InixCodec.Section>> dSecs =
                new Dictionary<string, List<InixCodec.Section>>();
            foreach (string sFile in lFiles)
            {
                List<InixCodec.Section> lSecs;
                try { lSecs = InixCodec.read(sFile); } catch { continue; }
                string sTask = InixCodec.fileTask(lSecs);
                bool bIsReport;
                if (sTask.Length > 0)
                    bIsReport = string.Equals(sTask, "report", StringComparison.OrdinalIgnoreCase);
                else
                {
                    bIsReport = false;
                    foreach (InixCodec.Section sec in lSecs)
                        if (!string.Equals(sec.Name, "Global", StringComparison.OrdinalIgnoreCase)
                            && sectionHasBand(sec)) { bIsReport = true; break; }
                }
                if (!bIsReport) continue;
                lReportFiles.Add(sFile);
                dSecs[sFile] = lSecs;
            }

            bool bMulti = lReportFiles.Count > 1;
            foreach (string sFile in lReportFiles)
            {
                foreach (InixCodec.Section sec in dSecs[sFile])
                {
                    if (string.Equals(sec.Name, "Global", StringComparison.OrdinalIgnoreCase)) continue;
                    if (!sectionHasBand(sec)) continue;
                    string sLabel = bMulti ? (sec.Name + "  (" + Path.GetFileName(sFile) + ")") : sec.Name;
                    lFound.Add(new string[] { sLabel, sFile, sec.Name });
                }
            }
            return lFound;
        }

        // sectionHasBand: true when an .inix section carries at least one
        // report band, which is how a report is told apart from an ordinary
        // settings section.
        private static bool sectionHasBand(InixCodec.Section sec)
        {
            string[] aBands = { "detail", "header", "footer", "group_header", "group_footer" };
            foreach (string b in aBands) if (!string.IsNullOrEmpty(sec.get(b))) return true;
            return false;
        }

        // Import (Alt+I): build a brand-new DbDo database from another file
        // -- one standard-shape table per source table, plus maps and
        // lookups -- and open it. This is distinct from Open (which mounts a
        // live ADO driver on the file as-is) and from Merge (which adds rows
        // to the current table). The new database is a managed temp copy:
        // the source file is only read, and Save Database keeps the result
        // as a .db. No open database is required.
        private void importClicked(object sender, EventArgs evArgs)
        {
            using (OpenFileDialog dlgFile = new OpenFileDialog())
            {
                dlgFile.Title = "Import into a new DbDo database";
                prepareFileDialog(dlgFile);
                dlgFile.Filter = "All supported (*.xlsx;*.xls;*.mdb;*.accdb;*.dbf;*.csv;*.tsv;*.txt;*.db;*.sqlite;*.sqlite3)|*.xlsx;*.xls;*.mdb;*.accdb;*.dbf;*.csv;*.tsv;*.txt;*.db;*.sqlite;*.sqlite3"
                           + "|Excel workbook (*.xlsx;*.xls)|*.xlsx;*.xls"
                           + "|Access (*.mdb;*.accdb)|*.mdb;*.accdb"
                           + "|dBASE (*.dbf)|*.dbf"
                           + "|CSV / text (*.csv;*.tsv;*.txt)|*.csv;*.tsv;*.txt"
                           + "|SQLite (*.db;*.sqlite;*.sqlite3)|*.db;*.sqlite;*.sqlite3"
                           + "|All Files (*.*)|*.*";
                string sCurDb = (db != null) ? db.filePath : null;
                dlgFile.InitialDirectory = IniFolders.bestDirectory(IniFolders.importFolder, sCurDb);
                if (dlgFile.ShowDialog(this) != DialogResult.OK) return;
                IniFolders.importFolder = Path.GetDirectoryName(dlgFile.FileName);
                string sOrigin = dlgFile.FileName;
                string sTemp;
                try { sTemp = importToShell(sOrigin); }
                catch (Exception ex)
                {
                    ErrorDialog.show(this, "Import", ex.Message);
                    return;
                }
                // Open the shell as the live database, managed like a
                // working copy: a previous managed temp (if any) is unlocked
                // by the open and then deleted.
                string sPrevTemp = sManagedTempPath;
                try { openDatabaseAndApplyState(sTemp, null); }
                catch (Exception ex)
                {
                    ErrorDialog.show(this, "Import", ex.Message);
                    try { if (File.Exists(sTemp)) File.Delete(sTemp); } catch { }
                    return;
                }
                if (!string.IsNullOrEmpty(sPrevTemp) && !string.Equals(sPrevTemp, sTemp, StringComparison.OrdinalIgnoreCase))
                { try { if (File.Exists(sPrevTemp)) File.Delete(sPrevTemp); } catch { } }
                sManagedOriginPath = sOrigin;
                sManagedTempPath = sTemp;
                invokeRefresh();
                LiveRegion.say("Imported " + Path.GetFileName(sOrigin)
                    + " into a new DbDo database. Save As to keep it as a .db; the original file is unchanged.");
            }
        }

        // emailLogFile: make it easy to send DbDo.log for troubleshooting.
        // The clipboard is sometimes unavailable (the error dialog's Copy
        // button can report "could not access the clipboard"), so this does
        // not rely on it: it opens the folder containing the log with the
        // file selected, and starts a new email with the log's full path in
        // the body, ready for the sender to attach. Shared by the Help menu
        // and the error dialog's Email Log button.
        internal static void emailLogFile(IWin32Window owner)
        {
            string sLog = DbDoLog.getLogPath();
            if (string.IsNullOrEmpty(sLog) || !File.Exists(sLog))
            {
                MessageBox.Show(owner, "There is no DbDo.log file to send yet.", "Email Log File",
                    MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }
            // Reveal the log in the file manager, selected and ready to attach.
            try { System.Diagnostics.Process.Start("explorer.exe", "/select,\"" + sLog + "\""); }
            catch (Exception ex) { try { DbDoLog.write("emailLogFile reveal failed: " + ex.Message); } catch { } }
            // Start a new email pointing at the log (mailto cannot attach a
            // file, so the path goes in the body).
            try
            {
                string sBody = "Please attach the DbDo log file, which is located here:\r\n"
                    + sLog + "\r\n\r\nBriefly, what were you doing when the problem happened?\r\n";
                System.Diagnostics.Process.Start("mailto:?subject=" + Uri.EscapeDataString("DbDo.log")
                    + "&body=" + Uri.EscapeDataString(sBody));
            }
            catch (Exception ex) { try { DbDoLog.write("emailLogFile mailto failed: " + ex.Message); } catch { } }
            try { LiveRegion.say("Opened your email program and the folder holding DbDo.log. Attach the file at "
                + sLog + " to your message."); } catch { }
        }

        private void emailLogClicked(object sender, EventArgs evArgs)
        {
            emailLogFile(this);
        }

        private void fileExportClicked(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset()) return;
            using (SaveFileDialog dlgFile = new SaveFileDialog())
            {
                dlgFile.Title = "Export Data";
                prepareFileDialog(dlgFile);
                // Export targets the current grid (a table or a Ctrl+Q
                // query result), so it offers file formats only. Whole-
                // database targets (.db/.accdb/.dbf) belong to Save
                // Database, which copies the physical database.
                dlgFile.Filter = "Excel workbook (*.xlsx)|*.xlsx"
                           + "|Word document (*.docx)|*.docx"
                           + "|HTML, filtered (*.html)|*.html"
                           + "|Markdown table (*.md)|*.md"
                           + "|JSON (*.json)|*.json"
                           + "|Inix file (*.inix)|*.inix"
                           + "|CSV (*.csv)|*.csv"
                           + "|TSV (*.tsv)|*.tsv"
                           + "|All Files (*.*)|*.*";
                dlgFile.DefaultExt = "xlsx";
                // Default folder: last export folder, else current
                // database's folder, else Documents.
                dlgFile.InitialDirectory = IniFolders.bestDirectory(IniFolders.exportFolder, db.filePath);
                // Suggest a filename based on the current table.
                if (!string.IsNullOrEmpty(db.currentTable))
                    dlgFile.FileName = db.currentTable;
                if (dlgFile.ShowDialog(this) != DialogResult.OK) return;
                // Lossy-format heads-up for structured targets that don't
                // round-trip (Excel/CSV/TSV/dBASE). Report and snapshot
                // formats (md/html/json/docx) and clean ones (db/accdb)
                // pass through without a prompt.
                string sTargetExt = Path.GetExtension(dlgFile.FileName).TrimStart('.');
                if (!confirmLossyConversion("Export Data", sTargetExt, false)) return;
                IniFolders.exportFolder = Path.GetDirectoryName(dlgFile.FileName);
                try
                {
                    db.exportData(dlgFile.FileName);
                    DbDoLog.write("Exported to " + dlgFile.FileName);
                    // Open the result in its default application so
                    // the user sees their export immediately, matching
                    // dbDot's behavior.
                    ComAutomation.shellOpen(dlgFile.FileName);
                }
                catch (Exception ex)
                {
                    ErrorDialog.show(this, "Export Data", ex.Message);
                }
            }
        }

        private void filePrintClicked(object sender, EventArgs evArgs)
        {
            MessageBox.Show(this, "Print is not yet implemented. Use Export Data to HTML and print from a browser.",
                "Print", MessageBoxButtons.OK, MessageBoxIcon.Information);
        }

        // Exit DbDo (Alt+F4): close the whole application, not just
        // this window. In MDI, this.Close() would close only the
        // active child and leave the frame's merged menu bar showing
        // with no listview (requiring a second Alt+F4); closing the
        // frame ends Application.Run and disposes every child. Close
        // Window (Control+F4) remains the close-just-this-window verb.
        private void fileExitClicked(object sender, EventArgs evArgs)
        {
            if (DbDoFrame.frame != null) DbDoFrame.frame.Close();
            else this.Close();
        }

        // =====================================================================
        // RECORD menu handlers
        // =====================================================================
        private void recNewClicked(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset()) return;
            if (blockIfReadOnly("This command")) return;
            if (db.currentIsView) {
                MessageBox.Show(this, "Cannot insert into a view (read-only).",
                    "New Record", MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }
            // New Record presents only the editable fields. The admin
            // fields (the primary key, added, edited, look, prm,
            // marked) are filled by the database itself: the key
            // auto-increments, added/edited default to
            // current_timestamp, look/prm are generated expressions,
            // and marked defaults to 0.
            List<string> lFields = db.getEditableFieldNames();
            Dictionary<string, string> dInitial = new Dictionary<string, string>();
            List<bool> lEditable = new List<bool>();
            foreach (string s in lFields)
            {
                dInitial[s] = "";
                lEditable.Add(true);
            }
            // Loop so a duplicate-identity rejection can return the user to
            // the editor with their entries intact -- to change a content
            // field and try again -- instead of discarding the work behind a
            // raw ADO error. Any other error still shows the diagnostic dialog.
            Dictionary<string, string> dEntry = dInitial;
            while (true)
            {
                using (RecordEditDialog dlg = new RecordEditDialog("New Record", lFields, dEntry, lEditable, db))
                {
                    if (dlg.showDialog(this) != DialogResult.OK) return;
                    dEntry = dlg.dValues;   // preserve entries for a possible retry
                    try
                    {
                        db.addNew();
                        foreach (KeyValuePair<string, string> kv in dlg.dValues)
                            if (!string.IsNullOrEmpty(kv.Value))
                                db.setFieldValue(kv.Key, kv.Value);
                        db.update();
                        invokeRefresh();
                        return;
                    }
                    catch (Exception ex)
                    {
                        try { db.cancelUpdate(); } catch { }
                        if (db.isPrmViolation(ex))
                        { warnDuplicateIdentity("New Record", dlg.dValues); continue; }
                        ErrorDialog.show(this, "New Record", ex, db);
                        return;
                    }
                }
            }
        }

        // recSetClicked (Control+E): the Edit View entry point --
        // start the view cycle at the edit view.
        private void recSetClicked(object sender, EventArgs evArgs)
        { runRecordViews(1, true); }

        // warnDuplicateIdentity: a New / New-Copy insert was rejected
        // because the record's identity -- the generated prm field, built
        // from a specific combination of content fields -- duplicates an
        // existing record. That is an ordinary data condition, not a
        // malfunction and not a sign that adding records is broken, so this
        // explains it plainly: it names the exact fields the identity is
        // built from (read from the table's prm definition, so it is right
        // even when only some fields count) and shows the values entered for
        // them, which is what is duplicated. The caller then reopens the
        // editor with the entries intact so one field can be changed and the
        // insert retried. No raw ADO text or stack trace.
        private void warnDuplicateIdentity(string sTitle, Dictionary<string, string> dValues)
        {
            List<string> lComp = db.getPrmComponentFields();
            System.Text.StringBuilder sb = new System.Text.StringBuilder();
            sb.AppendLine("This record was not added because another record in this table "
                + "already has the same identifying values, so it would be a duplicate.");
            sb.AppendLine();
            sb.AppendLine("Records here are kept distinct by the combination of these fields, "
                + "and you entered:");
            foreach (string sF in lComp)
            {
                string sV;
                if (dValues == null || !dValues.TryGetValue(sF, out sV) || string.IsNullOrEmpty(sV))
                    sV = "(blank)";
                sb.AppendLine("    " + sF + " = " + sV);
            }
            sb.AppendLine();
            sb.Append("Change one of those fields so the record is distinct, then choose OK to "
                + "try again -- or choose Cancel in the editor to abandon it.");
            MessageBox.Show(this, sb.ToString(), sTitle,
                MessageBoxButtons.OK, MessageBoxIcon.Information);
        }

        // runRecordViews: the three-view controller. iView is the
        // first non-list view to show (1 form, 2 show); the form and
        // show loops return the next view (list ends the cycle).
        // bDirect marks a direct invoke (Control+E / Enter) versus a
        // cycle hop, so a read-only table pops the explanatory
        // message only on a direct Edit Record, not mid-cycle.
        private void runRecordViews(int iView, bool bDirect)
        {
            if (db == null || !db.hasRecordset()) return;
            while (iView == 1 || iView == 2)
            {
                iView = (iView == 1) ? runFormViewLoop(bDirect) : runShowViewLoop();
                bDirect = false;
            }
            if (grid != null) grid.Focus();
        }

        // runFormViewLoop: the form view (Edit Record). Returns the
        // next view -- 0 (list) on normal close or Shift+F6, 2 (show)
        // on F6. Record navigation (Control+PageDown/PageUp) and
        // delete stay internal to the loop. A read-only table or
        // view cannot be edited: a direct invoke says so and returns
        // to the list; a cycle hop skips silently to the show view.
        private int runFormViewLoop(bool bDirect)
        {
            // A read-only table or view (db.readOnly covers the
            // innate view/query case too) cannot be edited. A direct
            // Edit Record explains why and returns to the list; a
            // cycle hop skips silently to the show view so F6 keeps
            // flowing.
            if (db.readOnly)
            {
                if (bDirect) { blockIfReadOnly("Edit Record"); return 0; }
                return 2;
            }
            if (db.eof || db.bof) return 0;

            int iFocusIdx = 0;
            while (true)
            {
                // Present ONLY the editable fields (admin fields are
                // program-maintained and viewable via Show Record).
                List<string> lDistinct = db.getEditableFieldNames();
                List<string> lFields = new List<string>();
                lFields.AddRange(lDistinct);
                Dictionary<string, string> dInitial = new Dictionary<string, string>();
                List<bool> lEditable = new List<bool>();
                List<string> lsInitialNull = new List<string>();
                foreach (string s in lDistinct)
                {
                    dInitial[s] = db.getFieldValue(s);
                    lEditable.Add(true);
                    if (db.isFieldNull(s)) lsInitialNull.Add(s);
                }
                int iNav = 0;
                int iVS = 0;
                using (RecordEditDialog dlg = new RecordEditDialog(
                    "Edit View (record " + db.absolutePosition + " of " + db.recordCount + ")",
                    lFields, dInitial, lEditable, db))
                {
                    dlg.applyFormViewSetup(iFocusIdx, lsInitialNull);
                    DialogResult res = dlg.showDialog(this);
                    iNav = dlg.iNavigate;
                    iVS = dlg.iViewSwitch;
                    iFocusIdx = dlg.iFocusIndex;
                    if (res == DialogResult.OK)
                    {
                        try
                        {
                            foreach (string sCol in lDistinct)
                            {
                                if (dlg.lsNullFields.Contains(sCol))
                                    db.setFieldNull(sCol);
                                else if (dlg.dValues.ContainsKey(sCol))
                                    db.setFieldValue(sCol, dlg.dValues[sCol]);
                            }
                            db.update();
                            invokeRefresh();
                        }
                        catch (Exception ex)
                        {
                            try { db.cancelUpdate(); } catch { }
                            ErrorDialog.show(this, "Edit Record", ex, db);
                            iNav = 0; iVS = 0;
                        }
                    }
                    else if (iNav != 2) return 0;  // plain Cancel / Escape -> list
                }
                // A view switch (saved above) leaves the form now.
                if (iVS != 0) return (iVS == 1) ? 2 : 0;
                if (iNav == 1)
                {
                    if (db.absolutePosition >= db.recordCount)
                    { LiveRegion.sayForced("Last record"); return 0; }
                    db.absolutePosition = db.absolutePosition + 1;
                }
                else if (iNav == -1)
                {
                    if (db.absolutePosition <= 1)
                    { LiveRegion.sayForced("First record"); return 0; }
                    db.absolutePosition = db.absolutePosition - 1;
                }
                else if (iNav == 2)
                {
                    try { db.deleteCurrent(); }
                    catch (Exception ex)
                    { ErrorDialog.show(this, "Delete Record", ex, db); return 0; }
                    invokeRefresh();
                    if (db.recordCount == 0 || db.eof)
                    { LiveRegion.sayForced("Record deleted; no records remain"); return 0; }
                    LiveRegion.sayForced("Record deleted");
                }
                else return 0;
                virtSyncListSelection(db.absolutePosition);
            }
        }

        // recSetCellClicked: Shift+F2. Edit just the field under the
        // virtual cursor (the cell highlighted by Alt+Control+arrow).
        // Smaller, faster path than F2 Edit Record when the user only
        // needs to change one value. Applies the same regex
        // validation Edit Record uses, via the [Validation:<table>]
        // section of DbDo.inix -- if a pattern is configured for the
        // current column, the new value must match it or the dialog
        // refuses with an error message.
        //
        // Metadata columns (added, edited) are not editable; if the
        // virtual cursor is on one of those, the dialog opens
        // read-only with a clear note. The 'marked' boolean column
        // routes to the existing Mark Record / Unmark Record commands
        // instead of a textbox.
        private void recSetCellClicked(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset()) return;
            if (blockIfReadOnly("This command")) return;
            if (db.currentIsView) {
                MessageBox.Show(this, "Cannot edit a view (read-only).",
                    "Edit Cell", MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }
            if (db.eof || db.bof) return;
            if (grid == null || iVirtualCol < 0 || iVirtualCol >= grid.Columns.Count)
            { LiveRegion.say("No column under virtual cursor"); return; }
            string sColumn = grid.Columns[iVirtualCol].Text;
            if (string.IsNullOrEmpty(sColumn))
            { LiveRegion.say("Column has no name"); return; }
            if (!db.hasField(sColumn))
            { LiveRegion.say("Field not in current table: " + sColumn); return; }

            // Refuse on metadata fields (system-managed) and route
            // 'marked' to the proper toggle commands.
            string sColLower = sColumn.ToLowerInvariant();
            if (Metadata.isAdminColumn(sColumn, db.currentTable)
                && sColLower != "marked")
            {
                MessageBox.Show(this,
                    "Field \"" + sColumn + "\" is system-managed and cannot be edited directly.\r\n\r\n"
                    + "The database updates it automatically.",
                    "Edit Cell", MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }
            if (sColLower == "marked")
            {
                MessageBox.Show(this,
                    "Use Mark Record (Control+M) or Unmark Record (Control+U) to change the \"marked\" field.",
                    "Edit Cell", MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }

            string sOriginal;
            // Defense-in-depth: explicitly position the recordset on
            // iVirtualRow before reading the field. The normal sync
            // paths (virtSyncListSelection from virtMoveTo, and
            // virtSyncFromListSelection from gridSelectedIndexChanged)
            // should already keep db.absolutePosition aligned with
            // iVirtualRow, but if any code path desyncs them (e.g.
            // a filter or sort applied since the last virtual move,
            // a stale selection event during refresh), the user's F2
            // would edit the wrong row silently. This guard makes
            // F2 always edit the virtual cell the user can hear.
            try
            {
                if (iVirtualRow >= 1 && iVirtualRow <= db.recordCount
                    && db.absolutePosition != iVirtualRow)
                {
                    db.absolutePosition = iVirtualRow;
                }
            }
            catch { /* if positioning fails, fall through and let getFieldValue throw or return empty */ }
            sOriginal = db.getFieldValue(sColumn) ?? "";
            string sConfiguredRegex = null;
            try { sConfiguredRegex = IniValidation.lookup(db.currentTable, sColumn); }
            catch { sConfiguredRegex = null; }

            string sNewValue;
            using (LbcDialog dlg = new LbcDialog("Edit Cell", this))
            {
                dlg.addLabel("Editing field \"" + sColumn + "\" of row "
                    + db.absolutePosition + " of " + db.recordCount + ".");
                if (!string.IsNullOrEmpty(sConfiguredRegex))
                    dlg.addLabel("Required pattern (DbDo.inix): " + sConfiguredRegex);
                dlg.addSeparator();
                // Single-line for short values, memo box for long ones.
                // The Camel-Type rule prefers a single-line input
                // unless the original spans multiple lines; in that
                // case a memo is appropriate.
                // Lookups-driven pick list: if the builtin lookups table
                // offers values for this table+field (e.g. maps.kind,
                // projects.kind), F4 / Alt+DownArrow opens an alphabetical
                // pick list in the value editbox.
                List<string> lsCellLookups = null;
                try { lsCellLookups = db.getLookupValues(db.currentTable, sColumn, 500); }
                catch (Exception exLk) { try { DbDoLog.write("Edit Cell lookups failed: " + exLk.Message); } catch { } }
                bool bHasLookups = lsCellLookups != null && lsCellLookups.Count > 0;
                string sBaseTip = "New value for the field. Tab to OK to commit; Cancel to discard.";
                string sFullTip = bHasLookups
                    ? sBaseTip + " F4 picks from " + lsCellLookups.Count
                        + (lsCellLookups.Count == 1 ? " value." : " values.")
                    : sBaseTip;
                TextBox tb;
                if (sOriginal.IndexOf('\n') >= 0 || sOriginal.Length > 100)
                    tb = dlg.addMemoBox("&Value:", sOriginal, sFullTip);
                else
                    tb = dlg.addInputBox("&Value:", sOriginal, sFullTip);
                LbcTextBox tbLbc = tb as LbcTextBox;
                if (tbLbc != null && bHasLookups) tbLbc.lsLookupValues = lsCellLookups;
                if (!dlg.runOkCancel()) return;
                sNewValue = tb.Text ?? "";
            }

            if (string.Equals(sNewValue, sOriginal, StringComparison.Ordinal))
            {
                LiveRegion.say("No change");
                return;
            }

            // Regex check (same logic RecordEditDialog uses).
            if (!string.IsNullOrEmpty(sConfiguredRegex) && sNewValue.Length > 0)
            {
                bool bMatch = false;
                try { bMatch = System.Text.RegularExpressions.Regex.IsMatch(sNewValue, sConfiguredRegex); }
                catch (Exception exRegex)
                {
                    ErrorDialog.show(this, "Edit Cell", "The validation pattern in DbDo.inix is invalid:\r\n\r\n"
                        + exRegex.Message + "\r\n\r\nPattern: " + sConfiguredRegex);
                    return;
                }
                if (!bMatch)
                {
                    MessageBox.Show(this,
                        "Value does not match the required pattern for \"" + sColumn + "\":\r\n\r\n"
                        + sConfiguredRegex,
                        "Edit Cell", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                    return;
                }
            }

            try
            {
                // Resync the recordset to iVirtualRow once more, in
                // case the dialog being open let any background event
                // (refresh, sort, filter) shift the cursor while we
                // waited for the user.
                try
                {
                    if (iVirtualRow >= 1 && iVirtualRow <= db.recordCount
                        && db.absolutePosition != iVirtualRow)
                    {
                        db.absolutePosition = iVirtualRow;
                    }
                }
                catch { /* fall through */ }
                db.setFieldValue(sColumn, sNewValue);
                db.update();
                invokeRefresh();
                LiveRegion.say("Field updated");
            }
            catch (Exception ex)
            {
                try { db.cancelUpdate(); } catch { }
                ErrorDialog.show(this, "Edit Cell", ex.Message);
            }
        }

        // countMarkedInFilter: count records whose 'marked' column
        // value is truthy WITHIN the currently filtered set. The
        // counting iterates the recordset (which already reflects
        // the active filter), then restores the position. Returns 0
        // if the current table has no 'marked' column.
        //
        // Used by every Category B command (scope-flexible commands
        // like Remove Record, Copy Record, Send Mail, etc.) to decide
        // whether to offer the marks-vs-current scope choice.
        private int countMarkedInFilter()
        {
            if (db == null || !db.hasRecordset()) return 0;
            if (!db.hasField(Metadata.MarkedColumn)) return 0;
            // Fast path: the manager's ADO-clone count, O(matching)
            // against the in-memory rowset with the marked-column
            // index maintained on the SQLite side. The position walk
            // below remains as the fallback when the clone path
            // reports failure (-1).
            int iFast = db.countMarked();
            if (iFast >= 0) return iFast;
            int iCount = 0;
            object oOriginal = null;
            try { oOriginal = db.bookmark; } catch { }
            try
            {
                int iCap = db.recordCount;
                for (int i = 1; i <= iCap; i++)
                {
                    try
                    {
                        db.absolutePosition = i;
                        if (isMarkedTrue(db.getFieldValue(Metadata.MarkedColumn))) iCount++;
                    }
                    catch { }
                }
            }
            finally
            {
                if (oOriginal != null) try { db.bookmark = oOriginal; } catch { }
            }
            return iCount;
        }

        // ScopeChoice: result type for promptScope.
        public enum ScopeChoice { Current, Marked, Cancel }

        // promptScope: marks-aware scope chooser for Category B
        // commands (those that can act on a single record OR on the
        // set of marked records). The design rule applied throughout
        // DbDo:
        //
        //   If no records are marked in the current filtered view,
        //   the command acts on the current record with no prompt.
        //
        //   If marks exist, present a numbered choice with the
        //   current-record option as the default (the safer / smaller
        //   scope, especially for destructive operations):
        //
        //       Remove Record:
        //         1. Current record only (default)
        //         2. All 7 marked records
        //         3. Cancel
        //
        //   The user can type the number, type a unique word from a
        //   choice ("current", "marked", "cancel"), or just press
        //   Enter to accept the default.
        //
        // This is the GUI version (uses LBC dialog buttons). The
        // dot-prompt CLI uses promptChoiceCli with the same labels
        // and ordering for consistency across surfaces.
        //
        // sCommandName: shown in the dialog title (e.g., "Remove
        // Record") so the user always sees which command is about to
        // run.
        private ScopeChoice promptScope(string sCommandName)
        {
            int iMarked = countMarkedInFilter();
            if (iMarked == 0) return ScopeChoice.Current;

            using (LbcDialog dlg = new LbcDialog(sCommandName, this))
            {
                dlg.addLabel("Marks are present. Choose the scope:");
                string sMarkedLabel = (iMarked == 1)
                    ? "&Marked record (1 record)"
                    : "&Marked records (" + iMarked + " records)";
                string sBtn = dlg.runWithButtons(new string[] {
                    "&Current record (default)",
                    sMarkedLabel,
                    "Ca&ncel"
                });
                if (string.IsNullOrEmpty(sBtn) || sBtn.IndexOf("ancel", StringComparison.OrdinalIgnoreCase) >= 0)
                    return ScopeChoice.Cancel;
                if (sBtn.IndexOf("arked", StringComparison.OrdinalIgnoreCase) >= 0)
                    return ScopeChoice.Marked;
                return ScopeChoice.Current;
            }
        }

        // recRemoveClicked: delete a record (or marked records) with
        // confirmation. Ctrl+D. The marks-aware scope prompt fires
        // only when marks exist; if no marks are set, the command
        // proceeds with the current-record interpretation directly,
        // showing only the standard "Delete the current record?"
        // confirmation.
        //
        // For deleting marked records, a second confirmation includes
        // the count -- e.g., "Delete 7 marked records?" -- because
        // bulk deletes are higher-stakes than single-record deletes.
        // The user must explicitly type the count or click Yes; there
        // is no "force" option in the GUI bulk path.
        //
        // Implementation note: marked records are deleted in reverse
        // absolute-position order so deletions don't shift indices
        // of records-not-yet-processed.
        private void recRemoveClicked(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset()) return;
            if (blockIfReadOnly("This command")) return;
            if (db.eof || db.bof) return;

            ScopeChoice scope = promptScope("Delete Record");
            if (scope == ScopeChoice.Cancel) return;

            if (scope == ScopeChoice.Current)
            {
                DialogResult res = MessageBox.Show(this,
                    "Delete the current record?", "Delete Record",
                    MessageBoxButtons.YesNo, MessageBoxIcon.Warning);
                if (res != DialogResult.Yes) return;
                try
                {
                    db.deleteCurrent();
                    invokeRefresh();
                }
                catch (Exception ex)
                {
                    ErrorDialog.show(this, "Delete Record", ex, db);
                }
                return;
            }

            // Marked-records path.
            int iMarked = countMarkedInFilter();
            DialogResult res2 = MessageBox.Show(this,
                "Delete " + iMarked + " marked record" + (iMarked == 1 ? "" : "s") + "?\n\n"
                + "This cannot be undone.",
                "Delete Marked Records",
                MessageBoxButtons.YesNo, MessageBoxIcon.Warning);
            if (res2 != DialogResult.Yes) return;
            try
            {
                List<int> lMarkedPositions = new List<int>();
                object oOriginal = null;
                try { oOriginal = db.bookmark; } catch { }
                try
                {
                    int iCap = db.recordCount;
                    for (int i = 1; i <= iCap; i++)
                    {
                        db.absolutePosition = i;
                        if (isMarkedTrue(db.getFieldValue(Metadata.MarkedColumn)))
                            lMarkedPositions.Add(i);
                    }
                }
                finally
                {
                    if (oOriginal != null) try { db.bookmark = oOriginal; } catch { }
                }
                // Delete in reverse so earlier positions remain valid.
                lMarkedPositions.Sort();
                lMarkedPositions.Reverse();
                int iDeleted = 0;
                foreach (int iPos in lMarkedPositions)
                {
                    try { db.absolutePosition = iPos; db.deleteCurrent(); iDeleted++; }
                    catch { }
                }
                invokeRefresh();
                LiveRegion.sayForced("Deleted " + iDeleted + " marked record" + (iDeleted == 1 ? "" : "s") + ".");
            }
            catch (Exception ex)
            {
                ErrorDialog.show(this, "Delete Marked Records", ex.Message);
            }
        }

        // Show-Object: open a read-only, multi-line view of the
        // currently-selected row. Three sections, separated by a
        // blank line:
        //
        //   1. The fields visible in the listview, one per line,
        //      in the form "field-name = value".
        //   2. For each PARENT row reached via outbound foreign-key
        //      column on this row: "Related <parent-table>:" header
        //      followed by the parent's look value indented under it.
        //      Skipped if this table has no FK columns.
        //   3. For each CHILD TABLE that references this row: a
        //      "Related <child-table>:" header followed by the look
        //      values of every matching child row, one per line.
        //      Capped at 25 per table with an "(N more)" footer so
        //      a heavily-related parent doesn't produce a wall of
        //      text. The user can press Shift+E to drill in for
        //      the full list.
        //
        // The look column is DbDo's standard "summary" calculated
        // column -- a SQLite stored-generated text that concatenates
        // a handful of substantive fields with " | " separators,
        // designed to be a screen-reader-friendly one-line
        // representation of a record. Tables without a look column
        // fall back to "(no look column)" placeholders.
        //
        // The dialog is dismissed by OK (Enter) or Escape.
        //
        // Bound to Enter from the data grid for one-key access.
        // Get-Property (Alt+Enter) remains the way to see EVERY
        // field including hidden bookkeeping columns.
        // recShowClicked (Control+I): the Inspect Record entry point
        // -- start the view cycle at the inspect (details) view.
        private void recShowClicked(object sender, EventArgs evArgs)
        { runRecordViews(2, true); }

        // runShowViewLoop: the show view -- a read-only field display
        // of the current record plus its related records. Returns the
        // next view: 0 (list) on close or F6, 1 (form) on Shift+F6.
        // Control+PageDown / Control+PageUp move records within the
        // view (the show display rebuilds for the new record).
        private int runShowViewLoop()
        {
            if (db == null || !db.hasRecordset() || db.eof || db.bof) return 0;
            while (true)
            {
                syncAdoCursorToSelection();
                if (db.eof || db.bof) return 0;

                // Inspect Record shows the EDITABLE fields of the row --
                // the substantive columns a user maintains -- skipping any
                // that are null or blank, so the reader hears only the
                // fields that actually carry information. Admin columns
                // (the key, added/edited, look/prm, marked) are omitted.
                List<string> lFields = db.getEditableFieldNames();
                if (lFields.Count == 0)
                {
                    lFields = db.getDisplayFieldNames();
                }
                StringBuilder sb = new StringBuilder();
                foreach (string sCol in lFields)
                {
                    string sRaw = db.getFieldValue(sCol);
                    if (string.IsNullOrWhiteSpace(sRaw)) continue;   // skip null/blank
                    string sValue = formatFieldValueForDisplay(sRaw, sCol);
                    sb.Append(sCol); sb.Append(" = "); sb.AppendLine(sValue);
                }
                // A blank line divides the fields from the related records,
                // which are presented exactly as Say Related (Shift+R) shows
                // them: one line per related record, each by its look value.
                string sRelated = buildRelatedSummary();
                if (!string.IsNullOrEmpty(sRelated))
                {
                    sb.AppendLine();
                    sb.Append(sRelated);
                }

                int v = HelpDialog.showRecordView(this,
                    "Inspect Record (row " + db.absolutePosition + " of " + db.recordCount + ")",
                    sb.ToString());
                if (v == 3)
                {
                    if (db.absolutePosition < db.recordCount)
                    { db.absolutePosition = db.absolutePosition + 1; virtSyncListSelection(db.absolutePosition); }
                    else LiveRegion.sayForced("Last record");
                    continue;
                }
                if (v == 4)
                {
                    if (db.absolutePosition > 1)
                    { db.absolutePosition = db.absolutePosition - 1; virtSyncListSelection(db.absolutePosition); }
                    else LiveRegion.sayForced("First record");
                    continue;
                }
                if (v == 2) return 1;  // Shift+F6 -> form
                return 0;              // close or F6 -> list
            }
        }

        // appendRelatedRecords: extend a Show-Object output with
        // the related-records sections. Two passes:
        //   (a) Outbound FKs on the current row -- columns named
        //       "<parent>_id" or "<plural-parent>_id". For each,
        //       fetch the single parent row's look value and emit
        //       it under a "Related <parent-table>:" header.
        //   (b) Other base tables that reference the current row
        //       via a column named like this table's PK. For each,
        //       fetch up to 25 look values matching the FK and emit
        //       them under a "Related <child-table>:" header.
        //
        // The query path is DbDoManager.queryColumnValues, which
        // issues a direct SELECT on the live connection so SQLite
        // can use its own indexes (if any are defined on the FK
        // columns) -- much cheaper than loading the whole child
        // recordset to client-side and filtering.
        private void appendRelatedRecords(StringBuilder sb)
        {
            const int iMaxPerSection = 25;
            const string sNoLook = "(no look column on this table)";

            string sCurrentTable = db.currentTable ?? "";
            if (string.IsNullOrEmpty(sCurrentTable)) return;
            List<string> lCurrentCols = db.getFieldNames();
            if (lCurrentCols.Count == 0) return;

            // Try schema metadata first for the current table's PK,
            // then fall back to the naming convention. This makes
            // Show-Object's child-section work even for tables
            // whose names have irregular English plurals
            // (e.g. classes -> class_id, cities -> city_id).
            string sCurrentPk = db.actualPrimaryKey(sCurrentTable);
            if (string.IsNullOrEmpty(sCurrentPk))
                sCurrentPk = computePrimaryKeyColumn(sCurrentTable, lCurrentCols);
            string sCurrentPkValue = "";
            if (!string.IsNullOrEmpty(sCurrentPk))
            {
                try { sCurrentPkValue = db.getFieldValue(sCurrentPk) ?? ""; }
                catch { sCurrentPkValue = ""; }
            }

            List<string> lAllTables = db.getTableNames();

            // -------------------------------------------------------
            // SECTION 2: outbound FKs -> parents. For every column on
            // the current row whose name ends in "_id" and matches
            // some other table's PK, fetch that parent's look value.
            // -------------------------------------------------------
            bool bAnyParent = false;
            foreach (string sCol in lCurrentCols)
            {
                if (string.Equals(sCol, sCurrentPk, StringComparison.OrdinalIgnoreCase))
                    continue;  // skip our own PK
                if (!sCol.EndsWith(Metadata.PrimaryKeySuffix, StringComparison.OrdinalIgnoreCase))
                    continue;  // not an FK by naming convention

                // The FK value on the current row.
                string sFkValue = "";
                try { sFkValue = db.getFieldValue(sCol) ?? ""; }
                catch { sFkValue = ""; }
                if (string.IsNullOrEmpty(sFkValue)) continue;

                // Find the parent table. The convention: an FK named
                // "<parent_singular>_id" points to table "<parent_plural>"
                // (e.g. teacher_id -> teachers). We also accept
                // "<parent_table>_id" without pluralization.
                string sParentTable = findParentTableForFk(sCol, lAllTables);
                if (string.IsNullOrEmpty(sParentTable)) continue;

                // Fetch the parent's look value via direct SQL.
                int iFound;
                List<string> lLook = db.queryColumnValues(
                    sParentTable, "look", sCol, sFkValue, 1, out iFound);

                if (!bAnyParent)
                {
                    if (sb.Length > 0) sb.AppendLine();  // blank separator
                    bAnyParent = true;
                }
                sb.Append("Related ");
                sb.Append(sParentTable);
                sb.AppendLine(":");
                if (iFound == 0)
                    sb.AppendLine("  (parent not found)");
                else if (lLook.Count > 0 && !string.IsNullOrEmpty(lLook[0]))
                    sb.AppendLine("  " + lLook[0]);
                else
                    sb.AppendLine("  " + sNoLook);
            }

            // -------------------------------------------------------
            // SECTION 3: child tables -> records pointing to me. For
            // every other base table that has a column named the
            // same as MY primary key, list its look values where
            // <fk> = <my-pk-value>.
            // -------------------------------------------------------
            if (string.IsNullOrEmpty(sCurrentPk) || string.IsNullOrEmpty(sCurrentPkValue))
                return;  // no PK -> no children to find

            foreach (string sChildTable in lAllTables)
            {
                if (string.Equals(sChildTable, sCurrentTable, StringComparison.OrdinalIgnoreCase))
                    continue;
                List<string> lChildCols = db.getColumnsOfTable(sChildTable);
                bool bHasFk = false;
                foreach (string sChildCol in lChildCols)
                {
                    if (string.Equals(sChildCol, sCurrentPk, StringComparison.OrdinalIgnoreCase))
                    { bHasFk = true; break; }
                }
                if (!bHasFk) continue;

                // Issue the query.
                int iFound;
                List<string> lLook = db.queryColumnValues(
                    sChildTable, "look", sCurrentPk, sCurrentPkValue,
                    iMaxPerSection, out iFound);
                if (iFound == 0) continue;  // no related rows; skip

                sb.AppendLine();
                sb.Append("Related ");
                sb.Append(sChildTable);
                sb.AppendLine(":");
                if (lLook.Count == 0)
                {
                    // Found rows but couldn't fetch look values --
                    // child table is missing the look column.
                    // Emit a placeholder count so the user knows.
                    sb.AppendLine("  (" + iFound + " row(s) -- " + sNoLook + ")");
                }
                else
                {
                    foreach (string sLook in lLook)
                    {
                        if (string.IsNullOrEmpty(sLook))
                            sb.AppendLine("  (empty look)");
                        else
                            sb.AppendLine("  " + sLook);
                    }
                    if (iFound > lLook.Count)
                    {
                        int iMore = iFound - lLook.Count;
                        sb.AppendLine("  (... " + iMore + " more; use Enter-Child to see all)");
                    }
                }
            }
        }

        // findParentTableForFk: given an FK column like "teacher_id"
        // or "class_id", find which table it points to. Inverts
        // the lookup by asking each candidate table whether its
        // actual primary-key column is the FK we're looking up.
        //
        // Uses actualPrimaryKey() to read the schema's own metadata
        // (PRAGMA table_info for SQLite, ADOX.Keys for Access),
        // so it works for any English plural irregularity --
        // "classes" -> "class_id", "cities" -> "city_id" -- as
        // long as the schema actually defines a PK. Falls back to
        // the naming-convention rule computePrimaryKeyColumn for
        // tables with no declared PK.
        private string findParentTableForFk(string sFkColumn, List<string> lAllTables)
        {
            if (string.IsNullOrEmpty(sFkColumn)) return null;
            foreach (string sT in lAllTables)
            {
                string sPk = db.actualPrimaryKey(sT);
                if (string.IsNullOrEmpty(sPk))
                {
                    List<string> lCols = db.getColumnsOfTable(sT);
                    sPk = computePrimaryKeyColumn(sT, lCols);
                }
                if (!string.IsNullOrEmpty(sPk)
                    && string.Equals(sPk, sFkColumn, StringComparison.OrdinalIgnoreCase))
                    return sT;
            }
            return null;
        }

        // Format a field value for display in Show-Object. The recordset
        // returns BLOBs as System.Byte[] which stringifies unhelpfully;
        // we render them as a size summary instead. Long text values
        // are kept as-is (newlines preserved by the multi-line dialog).
        private string formatFieldValueForDisplay(string sRaw, string sCol)
        {
            if (string.IsNullOrEmpty(sRaw)) return "";
            if (sRaw == "System.Byte[]")
            {
                // Try to get the actual blob length from the field.
                try
                {
                    int iLen = db.getFieldByteLength(sCol);
                    return "[BLOB, " + iLen + " bytes]";
                }
                catch { return "[BLOB]"; }
            }
            return sRaw;
        }

        private void recCopyClicked(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset()) return;
            if (db.eof || db.bof) return;
            List<string> lV = new List<string>();
            foreach (string sCol in db.getFieldNames()) lV.Add(db.getFieldValue(sCol));
            try { Clipboard.SetText(string.Join("\t", lV)); }
            catch { /* clipboard unavailable */ }
        }

        // --- v1.0.69 wave-2 record-level commands ---

        // Append Record (Alt+Shift+C): like recCopyClicked but adds
        // to existing clipboard contents instead of replacing. Each
        // record is rendered as "field: value" lines, with a blank
        // line separating one record from the next. Useful for
        // collecting several rows from across the database into one
        // clipboard payload.
        private void recAppendClicked(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset()) return;
            if (db.eof || db.bof) { LiveRegion.say("No record selected"); return; }
            string sExisting;
            try { sExisting = Clipboard.GetText() ?? ""; }
            catch { sExisting = ""; }
            StringBuilder sb = new StringBuilder();
            if (sExisting.Length > 0)
            {
                sb.Append(sExisting);
                if (!sExisting.EndsWith("\n")) sb.Append("\r\n");
                sb.Append("\r\n");  // blank-line separator
            }
            foreach (string sCol in db.getFieldNames())
            {
                string sVal = db.getFieldValue(sCol) ?? "";
                sb.Append(sCol).Append(": ").Append(sVal).Append("\r\n");
            }
            try
            {
                Clipboard.SetText(sb.ToString());
                LiveRegion.say("Appended record to clipboard");
            }
            catch
            {
                LiveRegion.say("Could not append to clipboard");
            }
        }

        // New Copy (Ctrl+Shift+N): duplicate the current row. Opens
        // the New Record dialog pre-filled with the current row's
        // distinct (substantive) field values. The primary key,
        // 'prm', 'look' generated columns, and timestamps are NOT
        // pre-filled -- they regenerate from the column defaults
        // and the trigger system. The user can edit any field
        // before pressing OK to insert.
        private void recNewCopyClicked(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset()) return;
            if (blockIfReadOnly("This command")) return;
            if (db.currentIsView)
            {
                MessageBox.Show(this, "Cannot insert into a view (read-only).",
                    "New Copy", MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }
            if (db.eof || db.bof) { LiveRegion.say("No record to copy"); return; }
            List<string> lFields = db.getEditableFieldNames();
            Dictionary<string, string> dInitial = new Dictionary<string, string>();
            List<bool> lEditable = new List<bool>();
            // Pre-fill every editable (non-admin) field with the
            // current row's value -- the multiple-employees-at-one-
            // company case: most values carry over, the user edits
            // the few that differ. Admin fields (the key, added,
            // edited, look, prm, marked) are never in this list and
            // regenerate from defaults, triggers, and expressions.
            foreach (string s in lFields)
            {
                string sVal = "";
                try { sVal = db.getFieldValue(s) ?? ""; } catch { }
                dInitial[s] = sVal;
                lEditable.Add(true);
            }
            Dictionary<string, string> dEntry = dInitial;
            while (true)
            {
                using (RecordEditDialog dlg = new RecordEditDialog("New Copy", lFields, dEntry, lEditable, db))
                {
                    if (dlg.showDialog(this) != DialogResult.OK) return;
                    dEntry = dlg.dValues;   // preserve entries for a possible retry
                    try
                    {
                        db.addNew();
                        foreach (KeyValuePair<string, string> kv in dlg.dValues)
                            if (!string.IsNullOrEmpty(kv.Value))
                                db.setFieldValue(kv.Key, kv.Value);
                        db.update();
                        invokeRefresh();
                        LiveRegion.say("New copy inserted");
                        return;
                    }
                    catch (Exception ex)
                    {
                        try { db.cancelUpdate(); } catch { }
                        if (db.isPrmViolation(ex))
                        { warnDuplicateIdentity("New Copy", dlg.dValues); continue; }
                        ErrorDialog.show(this, "New Copy", ex, db);
                        return;
                    }
                }
            }
        }

        // Mail Record (Ctrl+Shift+M): build a mailto: URI from the
        // current row. Scans for an email-like column (any column
        // whose name contains 'email', 'e_mail', or 'mail' case-
        // insensitively); uses the 'look' column for the subject;
        // uses 'notes' for the body. Falls back gracefully if any
        // of the three are absent.
        private void recMailClicked(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset() || db.recordCount == 0)
            { LiveRegion.say("No record selected"); return; }
            if (db.eof || db.bof) { LiveRegion.say("No record selected"); return; }
            string sEmailCol = null;
            foreach (string sCol in db.getFieldNames())
            {
                string sLow = sCol.ToLowerInvariant();
                if (sLow.Contains("email") || sLow.Contains("e_mail") || sLow.Contains("mail"))
                { sEmailCol = sCol; break; }
            }
            if (sEmailCol == null)
            {
                MessageBox.Show(this,
                    "This table has no email-like column. Mail Record needs a field whose name contains 'email', 'e_mail', or 'mail'.",
                    "Mail Record", MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }
            string sTo = (db.getFieldValue(sEmailCol) ?? "").Trim();
            if (sTo.Length == 0) { LiveRegion.say("Email field is empty"); return; }
            string sSubject = "";
            if (db.hasField("look")) sSubject = db.getFieldValue("look") ?? "";
            string sBody = "";
            if (db.hasField("notes")) sBody = db.getFieldValue("notes") ?? "";
            // Build mailto: with URI-encoded subject and body. We use
            // Uri.EscapeDataString for the subject and body, but
            // leave the address untouched (email addresses are not
            // URI-encoded in mailto: per RFC 6068).
            StringBuilder sb = new StringBuilder();
            sb.Append("mailto:").Append(sTo);
            string sQuery = "";
            if (sSubject.Length > 0)
                sQuery += (sQuery.Length == 0 ? "?" : "&") + "subject=" + Uri.EscapeDataString(sSubject);
            if (sBody.Length > 0)
                sQuery += (sQuery.Length == 0 ? "?" : "&") + "body=" + Uri.EscapeDataString(sBody);
            sb.Append(sQuery);
            try
            {
                System.Diagnostics.Process.Start(sb.ToString());
                LiveRegion.say("Opening mail to " + sTo);
            }
            catch (Exception ex)
            {
                ErrorDialog.show(this, "Mail Record", "Could not launch mail client: " + ex.Message);
            }
        }

        // Open-Cell: take the value in the currently focused grid cell
        // and try to open it. Behavior:
        //   - url (starts with http://, https://, file://, mailto:): open
        //     in the system default browser via Process.Start.
        //   - Existing file path: open in its default associated app
        //     (Process.Start lets the shell pick the handler).
        //   - Existing folder path: open in Windows Explorer.
        //   - Anything else: show a brief message in the live region
        //     and do nothing.
        // Bound to Control+Enter.
        private void recOpenCellClicked(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset()) return;
            List<string> lFields = db.getDisplayFieldNames();
            if (lFields == null || lFields.Count == 0)
            { LiveRegion.say("No columns"); return; }
            // Prompt for the column whose cell value to open. The
            // default is the column under virtual focus -- pressing
            // Enter accepts it. Listview has no per-column focus,
            // so the virtual cursor is what stands in for "the
            // column the user means by 'this one'."
            string sColName;
            LbcDialog dlg = new LbcDialog("Open Cell Value", this);
            try
            {
                string sDefault = virtCurrentColumnName();
                if (string.IsNullOrEmpty(sDefault) || !lFields.Contains(sDefault)) sDefault = lFields[0];
                ListBox lb = dlg.addPickBox(
                    "&Column whose cell value to open:",
                    lFields, sDefault,
                    "The command opens the url, file path, or folder path stored in this column of the current record");
                if (!dlg.runOkCancel()) return;
                if (lb.SelectedItem == null) return;
                sColName = lb.SelectedItem.ToString();
            }
            finally { dlg.Dispose(); }
            string sValue = "";
            try { sValue = (db.getFieldValue(sColName) ?? "").Trim(); }
            catch { }
            if (sValue.Length == 0)
            {
                LiveRegion.say("Cell is empty");
                return;
            }
            try
            {
                bool bIsUrl = sValue.StartsWith("http://", StringComparison.OrdinalIgnoreCase)
                           || sValue.StartsWith("https://", StringComparison.OrdinalIgnoreCase)
                           || sValue.StartsWith("file://", StringComparison.OrdinalIgnoreCase)
                           || sValue.StartsWith("mailto:", StringComparison.OrdinalIgnoreCase);
                if (bIsUrl || File.Exists(sValue) || Directory.Exists(sValue))
                {
                    System.Diagnostics.Process.Start(sValue);
                    LiveRegion.say("Opened: " + sValue);
                }
                else
                {
                    LiveRegion.say("Not a url, file, or folder: " + sValue);
                }
            }
            catch (Exception ex)
            {
                MessageBox.Show(this, "Could not open: " + sValue + "\n\n" + ex.Message,
                    "Open Cell Value", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            }
        }

        // ===============================================================
        // Search families. Three families with separate state and
        // separate forward / reverse handler pairs, plus a unified
        // F3 / Shift+F3 "search again" dispatcher that routes to
        // whichever family was last invoked.
        //
        // Jump (Control+J / Control+Shift+J): substring within one
        // user-picked column. The dialog has a column listbox and
        // a substring textbox. Uses the manager's findRecord with
        // an ADO Find expression like "col LIKE '%text%'".
        //
        // Find (Control+F / Control+Shift+F): substring across all
        // visible columns. The dialog has just a substring textbox.
        // Walks the recordset in C# checking every cell.
        //
        // Find-Regex (Control+F3 / Control+Shift+F3): regex across
        // all visible columns. The dialog has just a regex textbox.
        // Walks the recordset in C# applying Regex.IsMatch.
        // ===============================================================

        // Jump-Record (Control+J): prompt for column + substring,
        // jump to the next row whose value in that column contains
        // the substring (case-insensitive).
        private void recJumpClicked(object sender, EventArgs evArgs)
        {
            doJump(true, false);
        }

        private void recJumpPrevClicked(object sender, EventArgs evArgs)
        {
            doJump(false, false);
        }

        // doJump: shared between primary chord (prompts the dialog)
        // and the "again" path (uses cached state). When bAgain is
        // true the dialog is skipped.
        private void doJump(bool bForward, bool bAgain)
        {
            if (db == null || !db.hasRecordset()) return;
            if (!bAgain)
            {
                // v1.0.108 db-cursor centralization: Jump searches the
                // db cursor's column, period. No column picker -- the
                // user positions the cursor (Tab, Alt+Control+arrows,
                // type-ahead) and Jump targets that column, the same
                // way Say Cell and Sort do. Matching is substring and
                // case-insensitive by definition. F3 / Shift+F3
                // repeats stay in the column captured here, so moving
                // the cursor between repeats does not silently change
                // what is being searched.
                //
                // Recordset.Find was evaluated for this: the ADO
                // client cursor supports Find("col LIKE '*text*'"),
                // but its case behavior follows provider collation
                // rather than a guaranteed OrdinalIgnoreCase, and it
                // cannot anchor the our-own-wraparound announcement
                // pattern. The deterministic scan in jumpInColumn is
                // kept; the cost is negligible against the client-
                // side cursor's in-memory rows.
                string sCursorCol = virtCurrentColumnName();
                if (string.IsNullOrEmpty(sCursorCol))
                {
                    LiveRegion.sayForced("No column at the db cursor.");
                    return;
                }
                // Remember the last input across sessions: when this
                // session hasn't jumped yet, seed from the persisted Jump
                // history (DbDo.inix) so the box opens pre-filled.
                if (string.IsNullOrEmpty(sLastJumpSubstring))
                    sLastJumpSubstring = SearchHistory.lastText(SearchHistory.SectionJump);
                SearchDialogResult res = runSearchDialog(
                    "Jump to Match (column: " + sCursorCol + ")",
                    "Substring (case-insensitive) in column " + sCursorCol + ":",
                    sLastJumpSubstring,
                    false,
                    SearchHistory.SectionJump,
                    null,
                    null,
                    false);
                if (res == null) return;
                sLastJumpColumn = sCursorCol;
                sLastJumpSubstring = res.sText;
                bLastJumpCaseSensitive = false;
                SearchHistory.record(SearchHistory.SectionJump, res.sText, false);
                sLastSearchKind = "jump";
            }
            if (string.IsNullOrEmpty(sLastJumpColumn) || string.IsNullOrEmpty(sLastJumpSubstring)) return;
            try
            {
                bool bFound = jumpInColumn(sLastJumpColumn, sLastJumpSubstring, bLastJumpCaseSensitive, bForward, bAgain);
                if (bFound)
                {
                    int iMatch = db.absolutePosition;
                    invokeRefresh();
                    finalizeSearchLanding(iMatch);
                }
                else
                {
                    invokeRefresh();
                    LiveRegion.sayForced("Not found");
                }
            }
            catch (Exception ex)
            {
                ErrorDialog.show(this, "Jump to Match", ex.Message);
            }
        }

        // jumpInColumn: walk the recordset checking only one column
        // for substring containment. Returns true if a match was
        // found (cursor on the matched row); false otherwise (cursor
        // restored). The case-sensitive flag toggles between
        // Ordinal and OrdinalIgnoreCase comparison.
        private bool jumpInColumn(string sCol, string sSub, bool bCaseSensitive, bool bForward, bool bFromCurrent)
        {
            if (string.IsNullOrEmpty(sCol) || string.IsNullOrEmpty(sSub)) return false;
            int iCount = db.recordCount;
            if (iCount == 0) return false;
            int iStart = db.absolutePosition;
            int iFrom = bFromCurrent ? iStart : (bForward ? 1 : iCount);
            int iStep = bForward ? 1 : -1;
            int iPos = bFromCurrent ? iFrom + iStep : iFrom;
            object original = null;
            try { original = db.bookmark; } catch { }
            StringComparison cmp = bCaseSensitive
                ? StringComparison.Ordinal
                : StringComparison.OrdinalIgnoreCase;
            while (iPos >= 1 && iPos <= iCount)
            {
                try
                {
                    db.absolutePosition = iPos;
                    string sVal = db.getFieldValue(sCol) ?? "";
                    if (sVal.IndexOf(sSub, cmp) >= 0)
                    {
                        try { DbDoLog.write("Jump: matched '" + sSub + "' in column " + sCol + " at position " + iPos + " of " + iCount + "."); } catch { }
                        return true;
                    }
                }
                catch { }
                iPos += iStep;
            }
            // No match; restore.
            if (original != null) try { db.bookmark = original; } catch { }
            try { DbDoLog.write("Jump: no match for '" + sSub + "' in column " + sCol + " scanning " + iCount + " rows."); } catch { }
            return false;
        }

        // finalizeSearchLanding: make the matched record the authoritative
        // landing spot. Focusing a virtual ListView can reset its selected
        // item to row 1, and that reset would otherwise fire
        // gridSelectedIndexChanged and clobber absolutePosition back to 1
        // ("focus changed, but to the wrong record"). Doing the focus and
        // re-selection under bSuppressCellChanged blocks that clobber, and
        // re-asserting iPos last guarantees grid + cursor agree. The
        // screen reader announces the row itself off the genuine focus
        // change, so we do NOT speak here -- only log the landed state
        // (cursor vs grid row vs focus) so any future desync is visible.
        private void finalizeSearchLanding(int iPos)
        {
            if (db == null || !db.hasRecordset()) return;
            int iCount = db.recordCount;
            if (iCount <= 0) return;
            if (iPos < 1) iPos = 1;
            if (iPos > iCount) iPos = iCount;
            int iIndex = iPos - 1;
            bSuppressCellChanged = true;
            try
            {
                if (grid != null && !grid.Focused) grid.Focus();
                if (grid != null && iIndex >= 0 && iIndex < grid.VirtualListSize)
                {
                    grid.SelectedIndices.Clear();
                    grid.SelectedIndices.Add(iIndex);
                    grid.EnsureVisible(iIndex);
                    try { grid.FocusedItem = grid.Items[iIndex]; } catch { }
                    grid.selectAndFocusNative(iIndex);
                }
                db.absolutePosition = iPos;
                virtSyncFromListSelection();
            }
            catch { }
            finally { bSuppressCellChanged = false; }
            int iGridRow = -1;
            try { if (grid != null && grid.SelectedIndices.Count > 0) iGridRow = grid.SelectedIndices[0] + 1; } catch { }
            try { DbDoLog.write("finalizeSearchLanding: absolutePosition=" + db.absolutePosition + " of " + db.recordCount + ", gridRow=" + iGridRow + ", grid.Focused=" + (grid != null && grid.Focused) + "."); } catch { }
        }

        // Find (Control+F): prompt for substring, match across all
        // visible columns.
        private void recFindAllClicked(object sender, EventArgs evArgs)
        {
            doFind(true, false);
        }

        private void recFindAllPrevClicked(object sender, EventArgs evArgs)
        {
            doFind(false, false);
        }

        private void doFind(bool bForward, bool bAgain)
        {
            if (db == null || !db.hasRecordset()) return;
            if (!bAgain)
            {
                // Remember the last input across sessions: when this
                // session hasn't searched yet, seed from the persisted
                // Find history (DbDo.inix) so the box opens pre-filled
                // with the last substring used.
                if (string.IsNullOrEmpty(sLastFindSubstring))
                    sLastFindSubstring = SearchHistory.lastText(SearchHistory.SectionFind);
                SearchDialogResult res = runSearchDialog(
                    "Find",
                    "Substring (case-insensitive) across all fields:",
                    sLastFindSubstring,
                    false,
                    SearchHistory.SectionFind,
                    null, // no column picker for Find
                    null,
                    false);
                if (res == null) return;
                sLastFindSubstring = res.sText;
                bLastFindCaseSensitive = false;
                SearchHistory.record(SearchHistory.SectionFind, res.sText, res.bCaseSensitive);
                sLastSearchKind = "find";
            }
            if (string.IsNullOrEmpty(sLastFindSubstring)) return;
            try
            {
                bool bFound = findAcrossColumns(sLastFindSubstring, bLastFindCaseSensitive, bForward, bAgain);
                if (bFound)
                {
                    int iMatch = db.absolutePosition;
                    invokeRefresh();
                    finalizeSearchLanding(iMatch);
                }
                else
                {
                    invokeRefresh();
                    LiveRegion.sayForced("Not found");
                }
            }
            catch (Exception ex)
            {
                ErrorDialog.show(this, "Find", ex.Message);
            }
        }

        // findAcrossColumns: walk the recordset checking EVERY column
        // (displayed OR hidden) for substring containment. Per spec
        // v1.0.65: Find / Reverse Find / Extract / Regex Find / Reverse
        // Regex Find search the FULL field set so hidden columns like
        // notes, tags, url, and the bookkeeping timestamps are
        // reachable by Find. The Replace and Jump families remain
        // current-virtual-column-only. Case sensitivity is per-user
        // choice via the dialog checkbox.
        private bool findAcrossColumns(string sSub, bool bCaseSensitive, bool bForward, bool bFromCurrent)
        {
            if (string.IsNullOrEmpty(sSub)) return false;
            int iCount = db.recordCount;
            if (iCount == 0) return false;
            List<string> lFields = db.getFieldNames();
            if (lFields == null || lFields.Count == 0) return false;
            int iStart = db.absolutePosition;
            int iStep = bForward ? 1 : -1;
            int iFrom = bFromCurrent ? iStart : (bForward ? 1 : iCount);
            int iPos = bFromCurrent ? iFrom + iStep : iFrom;
            object original = null;
            try { original = db.bookmark; } catch { }
            StringComparison cmp = bCaseSensitive
                ? StringComparison.Ordinal
                : StringComparison.OrdinalIgnoreCase;
            while (iPos >= 1 && iPos <= iCount)
            {
                try
                {
                    db.absolutePosition = iPos;
                    foreach (string sCol in lFields)
                    {
                        string sVal = db.getFieldValue(sCol) ?? "";
                        if (sVal.Length == 0) continue;
                        if (sVal.IndexOf(sSub, cmp) >= 0)
                        {
                            try { DbDoLog.write("Find: matched '" + sSub + "' at position " + iPos + " of " + iCount + " (column " + sCol + ")."); } catch { }
                            return true;
                        }
                    }
                }
                catch { }
                iPos += iStep;
            }
            if (original != null) try { db.bookmark = original; } catch { }
            try { DbDoLog.write("Find: no match for '" + sSub + "' scanning " + iCount + " rows."); } catch { }
            return false;
        }

        // Find-Regex (Control+F3): prompt for regex, match across all
        // visible columns.
        private void recFindRegexClicked(object sender, EventArgs evArgs)
        {
            doFindRegex(true, false);
        }

        private void recFindRegexPrevClicked(object sender, EventArgs evArgs)
        {
            doFindRegex(false, false);
        }

        private void doFindRegex(bool bForward, bool bAgain)
        {
            if (db == null || !db.hasRecordset()) return;
            if (!bAgain)
            {
                // Remember the last input across sessions: when this
                // session hasn't run a regex yet, seed from the persisted
                // Find Regex history (DbDo.inix) so the box pre-fills.
                if (string.IsNullOrEmpty(sLastFindRegex))
                    sLastFindRegex = SearchHistory.lastText(SearchHistory.SectionRegex);
                SearchDialogResult res = runSearchDialog(
                    "Find Regex",
                    ".NET regular expression (case-insensitive unless Case sensitive is checked):",
                    sLastFindRegex,
                    bLastRegexCaseSensitive,
                    SearchHistory.SectionRegex,
                    null, // no column picker for Find-Regex
                    null,
                    true);
                if (res == null) return;
                // Pre-compile to validate; bad regex surfaces here
                // rather than crashing inside the walk.
                try
                {
                    System.Text.RegularExpressions.RegexOptions reOpts =
                        res.bCaseSensitive
                            ? System.Text.RegularExpressions.RegexOptions.None
                            : System.Text.RegularExpressions.RegexOptions.IgnoreCase;
                    new System.Text.RegularExpressions.Regex(res.sText, reOpts);
                }
                catch (Exception exRe)
                {
                    MessageBox.Show(this, "Invalid regex: " + exRe.Message,
                        "Find Regex", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                    return;
                }
                sLastFindRegex = res.sText;
                bLastRegexCaseSensitive = res.bCaseSensitive;
                SearchHistory.record(SearchHistory.SectionRegex, res.sText, res.bCaseSensitive);
                sLastSearchKind = "regex";
            }
            if (string.IsNullOrEmpty(sLastFindRegex)) return;
            try
            {
                bool bFound = findRegexAcrossColumns(sLastFindRegex, bLastRegexCaseSensitive, bForward, bAgain);
                if (bFound)
                {
                    int iMatch = db.absolutePosition;
                    invokeRefresh();
                    finalizeSearchLanding(iMatch);
                }
                else
                {
                    invokeRefresh();
                    LiveRegion.sayForced("Not found");
                }
            }
            catch (Exception ex)
            {
                ErrorDialog.show(this, "Find Regex", ex.Message);
            }
        }

        // findRegexAcrossColumns: walk every visible row, check every
        // column (displayed OR hidden) with Regex.IsMatch. Per spec
        // v1.0.65, Find-Regex / Reverse Regex Find search the FULL
        // field set. Case sensitivity is controlled by the
        // RegexOptions flag.
        private bool findRegexAcrossColumns(string sPattern, bool bCaseSensitive, bool bForward, bool bFromCurrent)
        {
            if (string.IsNullOrEmpty(sPattern)) return false;
            int iCount = db.recordCount;
            if (iCount == 0) return false;
            List<string> lFields = db.getFieldNames();
            if (lFields == null || lFields.Count == 0) return false;
            System.Text.RegularExpressions.Regex re;
            try
            {
                System.Text.RegularExpressions.RegexOptions reOpts =
                    bCaseSensitive
                        ? System.Text.RegularExpressions.RegexOptions.None
                        : System.Text.RegularExpressions.RegexOptions.IgnoreCase;
                re = new System.Text.RegularExpressions.Regex(sPattern, reOpts);
            }
            catch { return false; }
            int iStart = db.absolutePosition;
            int iStep = bForward ? 1 : -1;
            int iFrom = bFromCurrent ? iStart : (bForward ? 1 : iCount);
            int iPos = bFromCurrent ? iFrom + iStep : iFrom;
            object original = null;
            try { original = db.bookmark; } catch { }
            while (iPos >= 1 && iPos <= iCount)
            {
                try
                {
                    db.absolutePosition = iPos;
                    foreach (string sCol in lFields)
                    {
                        string sVal = db.getFieldValue(sCol) ?? "";
                        if (sVal.Length == 0) continue;
                        if (re.IsMatch(sVal)) return true;
                    }
                }
                catch { }
                iPos += iStep;
            }
            if (original != null) try { db.bookmark = original; } catch { }
            return false;
        }

        // SearchDialogResult: captures everything the search-family
        // dialogs need to return -- the user's text, the case-
        // sensitive flag, and (for Jump-Record only) the selected
        // column.
        private class SearchDialogResult
        {
            public string sText;
            public bool   bCaseSensitive;
            public string sColumn;
        }

        // runSearchDialog: shared dialog implementation for the three
        // search families. Builds an LBC-style modal dialog with:
        //
        //   - Optional column listbox (only when lCols != null)
        //   - Text input populated with the prior term
        //   - Recent list -- up to 10 most-recent terms from the
        //     family's history section. Selecting an entry copies
        //     its text to the input AND sets the case-sensitive
        //     checkbox to how that term was used.
        //   - Case-sensitive checkbox (off by default)
        //   - OK / Cancel buttons
        //
        // Returns null if the user cancelled or entered no text.
        private SearchDialogResult runSearchDialog(
            string sTitle,
            string sTextLabel,
            string sInitialText,
            bool   bInitialCase,
            string sHistorySection,
            List<string> lCols,
            string sInitialCol,
            bool   bAllowCase)
        {
            // The dialog is a standalone Form rather than an
            // LbcDialog because we need event wiring on the Recent
            // listbox (SelectedIndexChanged) that updates other
            // controls. LbcDialog's API exposes its widgets but the
            // event wiring is cleaner inline. The visual layout
            // mirrors LbcDialog conventions (label above field,
            // status-bar focus-tip, 12-pixel margin) so a screen-
            // reader user gets the same Tab-order experience.
            using (Form dlg = new LbcForm())
            {
                dlg.Text = sTitle;
                dlg.StartPosition = FormStartPosition.CenterParent;
                dlg.FormBorderStyle = FormBorderStyle.FixedDialog;
                dlg.MaximizeBox = false;
                dlg.MinimizeBox = false;
                dlg.ShowInTaskbar = false;
                dlg.KeyPreview = true;
                dlg.ClientSize = new Size(560, lCols != null ? 280 : (bAllowCase ? 210 : 175));

                int iY = 12;
                int iLineHeight = 24;
                int iLabelHeight = 18;
                int iControlWidth = 536;

                // Optional column picker. Only present for the Jump
                // family; Find and Find-Regex omit it.
                ComboBox cbCol = null;
                if (lCols != null && lCols.Count > 0)
                {
                    Label lblCol = new Label();
                    lblCol.Text = "&Column to search:";
                    lblCol.Location = new Point(12, iY);
                    lblCol.Size = new Size(iControlWidth, iLabelHeight);
                    dlg.Controls.Add(lblCol);
                    iY += iLabelHeight + 2;

                    cbCol = new ComboBox();
                    cbCol.DropDownStyle = ComboBoxStyle.DropDownList;
                    cbCol.Location = new Point(12, iY);
                    cbCol.Size = new Size(iControlWidth, iLineHeight);
                    foreach (string sC in lCols) cbCol.Items.Add(sC);
                    string sDefaultCol = (!string.IsNullOrEmpty(sInitialCol) && lCols.Contains(sInitialCol))
                        ? sInitialCol : lCols[0];
                    cbCol.SelectedItem = sDefaultCol;
                    cbCol.AccessibleName = "Column to search";
                    dlg.Controls.Add(cbCol);
                    iY += iLineHeight + 8;
                }

                // Text input as an editable history combobox: the box
                // pre-fills with the last value (sInitialText), and the
                // dropdown holds up to 10 recent entries, most recent
                // first. The user can type a new value or press Down /
                // Alt+Down to browse history -- the same pattern as the
                // Windows Run dialog, which screen readers present as a
                // single "edit combo" control. History is the persisted
                // SearchHistory for this section; selecting an entry also
                // restores the case-sensitive flag it was used with.
                Label lblText = new Label();
                lblText.Text = "&Text (type, or Down arrow for up to 10 recent): " + sTextLabel;
                lblText.Location = new Point(12, iY);
                lblText.Size = new Size(iControlWidth, iLabelHeight * 2);
                dlg.Controls.Add(lblText);
                iY += lblText.Height + 2;

                List<SearchHistory.Entry> lHistory = SearchHistory.load(sHistorySection);
                ComboBox cbText = new ComboBox();
                cbText.DropDownStyle = ComboBoxStyle.DropDown; // editable
                cbText.Location = new Point(12, iY);
                cbText.Size = new Size(iControlWidth, iLineHeight);
                cbText.AccessibleName = "Text";
                int iHistMax = Math.Min(10, lHistory.Count);
                for (int iH = 0; iH < iHistMax; iH++)
                    cbText.Items.Add(lHistory[iH].sTerm ?? "");
                cbText.Text = sInitialText ?? "";
                dlg.Controls.Add(cbText);
                iY += iLineHeight + 8;

                // Case-sensitive checkbox. Only offered where the
                // command's semantics allow it (regex searches); the
                // Jump and Find commands are case-insensitive by
                // definition, so the checkbox is omitted there rather
                // than shown-but-ignored.
                CheckBox cbCase = new CheckBox();
                cbCase.Text = "Case &sensitive";
                cbCase.Checked = bAllowCase && bInitialCase;
                cbCase.Location = new Point(12, iY);
                cbCase.Size = new Size(iControlWidth, iLineHeight);
                cbCase.AccessibleName = "Case sensitive";
                if (bAllowCase)
                {
                    dlg.Controls.Add(cbCase);
                    iY += iLineHeight + 8;
                }

                // Buttons: OK and Cancel
                Button btnOk = new Button();
                btnOk.Text = "&OK";
                btnOk.DialogResult = DialogResult.OK;
                btnOk.Size = new Size(90, 28);
                btnOk.Location = new Point(360, iY);
                dlg.Controls.Add(btnOk);

                Button btnCancel = new Button();
                btnCancel.Text = "&Cancel";
                btnCancel.DialogResult = DialogResult.Cancel;
                btnCancel.Size = new Size(90, 28);
                btnCancel.Location = new Point(456, iY);
                dlg.Controls.Add(btnCancel);

                dlg.AcceptButton = btnOk;
                dlg.CancelButton = btnCancel;

                // When a history entry is chosen from the dropdown, the
                // combobox sets its Text to that entry; also restore the
                // case-sensitive flag it was used with -- but only where
                // the command honors case, so Find/Jump aren't forced
                // case-sensitive by an old entry.
                cbText.SelectedIndexChanged += delegate(object senderA, EventArgs evA)
                {
                    int iIdx = cbText.SelectedIndex;
                    if (iIdx < 0 || iIdx >= iHistMax || iIdx >= lHistory.Count) return;
                    if (bAllowCase) cbCase.Checked = lHistory[iIdx].bCaseSensitive;
                };

                // Initial focus on the combobox with its text selected,
                // so typing immediately replaces the pre-filled value.
                dlg.Shown += delegate(object senderA, EventArgs evA)
                {
                    cbText.Focus();
                    cbText.SelectionStart = 0;
                    cbText.SelectionLength = (cbText.Text ?? "").Length;
                };

                if (dlg.ShowDialog(this) != DialogResult.OK) return null;
                string sText = (cbText.Text ?? "").Trim();
                if (string.IsNullOrEmpty(sText)) return null;
                SearchDialogResult result = new SearchDialogResult();
                result.sText = sText;
                result.bCaseSensitive = cbCase.Checked;
                result.sColumn = (cbCol != null && cbCol.SelectedItem != null) ? cbCol.SelectedItem.ToString() : "";
                return result;
            }
        }

        // Search-Next (F3): repeat whichever search family was last
        // invoked, forward. Shift+F3 is the reverse counterpart.
        // F3 / Shift+F3 are "find again" -- DbDo
        // generalizes this to also include the Jump family.
        private void recSearchNextClicked(object sender, EventArgs evArgs)
        {
            recSearchAgain(true);
        }

        private void recSearchPrevClicked(object sender, EventArgs evArgs)
        {
            recSearchAgain(false);
        }

        private void recSearchAgain(bool bForward)
        {
            switch (sLastSearchKind)
            {
                case "jump":
                    doJump(bForward, true);
                    break;
                case "find":
                    doFind(bForward, true);
                    break;
                case "regex":
                    doFindRegex(bForward, true);
                    break;
                default:
                    LiveRegion.sayForced("No previous search. Use Find, Jump, or Find Regex first.");
                    break;
            }
        }

        // Set-Position: jump to a numbered row (1-based). Prompts for the
        // target row number. Bound to Control+G, the convention for
        // "Go to Percent" (the closest editor analog to "go to row N").
        private void recGoToClicked(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset()) return;
            int iCount = db.recordCount;
            if (iCount <= 0) { LiveRegion.say("No rows."); return; }
            string sInput = promptText("Set Position",
                "Row number (1 to " + iCount + "), percent (50%), relative (+10, -25%), or column text:",
                (db.absolutePosition).ToString());
            if (string.IsNullOrEmpty(sInput)) return;
            applyGoTo(sInput, true);
        }

        // repeatGoToClicked (Alt+G): rerun Go To with the most
        // recently saved input, no prompt. Every Go To input -- like
        // every search input -- persists in DbDo.inix, so the repeat
        // works across sessions too.
        private void repeatGoToClicked(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset()) return;
            string sLast = SearchHistory.lastText(SearchHistory.SectionGoTo);
            if (string.IsNullOrEmpty(sLast))
            { LiveRegion.sayForced("No previous Go To input."); return; }
            applyGoTo(sLast, false);
        }

        // applyGoTo: the Go To interpreter. The input decides the
        // meaning:
        //   42      absolute row 42
        //   50%     the row at 50 percent of the recordset,
        //           rounded to the nearest row (never below 1)
        //   +10     forward 10 rows;  -10  back 10 rows
        //   +25%    forward by a quarter of the recordset;  -25%
        //           back likewise (sign means relative, percent
        //           means scaled by the row count)
        //   text    anything with a letter: move the db cursor to
        //           the next COLUMN -- searching cyclically,
        //           starting with the current column -- whose
        //           header name contains the text; when no header
        //           matches, the current row's cell VALUES are
        //           tried the same way. (Interpretation note:
        //           "column containing the substring" is read as
        //           header-first, values as fallback.)
        // Row moves keep the cursor's column; the column move keeps
        // the row. bSave records the input in the Go To history.
        private void applyGoTo(string sInput, bool bSave)
        {
            int iCount = db.recordCount;
            sInput = (sInput ?? "").Trim();
            if (sInput.Length == 0 || iCount <= 0) return;
            if (bSave) SearchHistory.record(SearchHistory.SectionGoTo, sInput, false);

            bool bHasAlpha = false;
            foreach (char ch in sInput) if (char.IsLetter(ch)) { bHasAlpha = true; break; }
            if (bHasAlpha)
            {
                int iColCount = (grid != null) ? grid.Columns.Count : 0;
                if (iColCount == 0) return;
                // Header pass, then current-row value pass; each
                // cyclic from the current column inclusive.
                for (int iPass = 0; iPass < 2; iPass++)
                {
                    for (int iStep = 0; iStep < iColCount; iStep++)
                    {
                        int iCol = (iVirtualCol + iStep) % iColCount;
                        string sHay = (iPass == 0)
                            ? grid.Columns[iCol].Text
                            : virtCellValue(iVirtualRow, iCol);
                        if ((sHay ?? "").IndexOf(sInput, StringComparison.OrdinalIgnoreCase) >= 0)
                        { virtMoveTo(iVirtualRow, iCol); return; }
                    }
                }
                LiveRegion.sayForced("No column matching " + sInput);
                return;
            }

            bool bRelative = sInput.StartsWith("+") || sInput.StartsWith("-");
            bool bNegative = sInput.StartsWith("-");
            bool bPercent = sInput.EndsWith("%");
            string sDigits = sInput.TrimStart('+', '-').TrimEnd('%').Trim();
            double nNumber;
            if (!double.TryParse(sDigits, out nNumber) || nNumber < 0)
            { LiveRegion.sayForced("Enter a row number, percent, relative offset, or column text."); return; }

            int iAmount = bPercent
                ? (int)Math.Round(iCount * nNumber / 100.0, MidpointRounding.AwayFromZero)
                : (int)Math.Round(nNumber, MidpointRounding.AwayFromZero);
            int iTarget = bRelative
                ? db.absolutePosition + (bNegative ? -iAmount : iAmount)
                : iAmount;
            if (iTarget < 1) iTarget = 1;
            if (iTarget > iCount) iTarget = iCount;
            try { virtMoveTo(iTarget, iVirtualCol); }
            catch (Exception ex) { ErrorDialog.show(this, "Set Position", ex, db); }
        }

        // Multi-bookmark support (v1.0.101). Each bookmark records
        // the table name, the ADO bookmark variant (which lets us
        // jump back to the record within the same recordset), and
        // the look-value at the time of save (for display in the
        // Bookmarks listbox). Session-lifetime only: when the
        // database is closed or a table is switched, bookmarks for
        // the abandoned recordset become stale; we clear them at
        // database-open time to avoid the user picking a stale one.
        private class BookmarkEntry
        {
            public string sTable;
            public object oBookmark;
            public string sLook;        // look-value at save time
            public int    iRowAtSave;   // 1-based row number when saved
        }
        private List<BookmarkEntry> lBookmarks = new List<BookmarkEntry>();
        // Step-Record menu items. Each fires the manager's
        // corresponding navigation method, then refreshes the
        // ListView and announces position via the status bar.
        // These give the Navigate menu first-class home for what
        // the dot prompt already does via "first", "last", "next",
        // "previous" -- they should be parallel everywhere.
        private void navFirstClicked(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset()) return;
            try { db.moveFirst(); invokeRefresh(); }
            catch (Exception ex) { LiveRegion.say("Step Record First: " + ex.Message); }
        }

        private void navLastClicked(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset()) return;
            try { db.moveLast(); invokeRefresh(); }
            catch (Exception ex) { LiveRegion.say("Step Record Last: " + ex.Message); }
        }

        private void navNextClicked(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset()) return;
            try
            {
                if (db.absolutePosition < db.recordCount) db.absolutePosition = db.absolutePosition + 1;
                invokeRefresh();
            }
            catch (Exception ex) { LiveRegion.say("Step Record Next: " + ex.Message); }
        }

        private void navPrevClicked(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset()) return;
            try
            {
                if (db.absolutePosition > 1) db.absolutePosition = db.absolutePosition - 1;
                invokeRefresh();
            }
            catch (Exception ex) { LiveRegion.say("Step Record Previous: " + ex.Message); }
        }

        // Save-Bookmark (Ctrl+B): add the current record to the
        // bookmark list. The look-value (if available) is captured
        // for display in the bookmark listbox; otherwise we fall
        // back to "row N" as the bookmark's identifier.
        private void recBookmarkClicked(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset()) return;
            try
            {
                BookmarkEntry be = new BookmarkEntry();
                be.sTable = db.currentTable;
                be.oBookmark = db.bookmark;
                be.iRowAtSave = db.absolutePosition;
                if (db.hasField(Metadata.LookColumn))
                    try { be.sLook = db.getFieldValue(Metadata.LookColumn) ?? ""; } catch { be.sLook = ""; }
                else
                    be.sLook = "";
                lBookmarks.Add(be);
                string sLabel = string.IsNullOrEmpty(be.sLook)
                    ? ("row " + be.iRowAtSave)
                    : be.sLook;
                string sMsg = "Bookmark saved: " + sLabel + " (" + lBookmarks.Count + " total)";
                lblStatus.Text = sMsg;
                LiveRegion.say(sMsg);
            }
            catch (Exception ex) { ErrorDialog.show(this, "Save Bookmark", ex.Message); }
        }

        // List-Bookmarks (Alt+B): show the bookmark list in a listbox
        // dialog. Each entry shows "table -- look-value (row N)".
        // Selecting one and pressing OK navigates to that record.
        private void recGotoBookmarkClicked(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset()) return;
            if (lBookmarks.Count == 0)
            {
                MessageBox.Show(this, "No bookmarks saved yet.",
                    "List Bookmarks", MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }
            // Build display strings -- one per bookmark. Format:
            //   "<table> -- <look> (row N)"
            // If no look-value, omit the dash:
            //   "<table> (row N)"
            List<string> lDisplay = new List<string>();
            foreach (BookmarkEntry be in lBookmarks)
            {
                string sLook = string.IsNullOrEmpty(be.sLook) ? "" : (" -- " + be.sLook);
                lDisplay.Add(be.sTable + sLook + " (row " + be.iRowAtSave + ")");
            }
            int iChosen = -1;
            using (LbcDialog dlg = new LbcDialog("List Bookmarks", this))
            {
                dlg.addLabel("Select a bookmark to navigate to:");
                ListBox lb = dlg.addListBox("Bookmarks", lDisplay, lDisplay[0]);
                if (!dlg.runOkCancel()) return;
                iChosen = lb.SelectedIndex;
            }
            if (iChosen < 0 || iChosen >= lBookmarks.Count) return;
            BookmarkEntry chosen = lBookmarks[iChosen];
            // If we're on a different table, switch tables first.
            if (!string.Equals(chosen.sTable, db.currentTable, StringComparison.OrdinalIgnoreCase))
            {
                try { db.selectTable(chosen.sTable); }
                catch (Exception ex)
                {
                    ErrorDialog.show(this, "List Bookmarks", "Could not switch to table '" + chosen.sTable + "': " + ex.Message);
                    return;
                }
            }
            try
            {
                db.bookmark = chosen.oBookmark;
                invokeRefresh();
                LiveRegion.say("Returned to row " + db.absolutePosition + " in " + chosen.sTable);
            }
            catch (Exception ex)
            {
                ErrorDialog.show(this, "List Bookmarks", ex.Message);
            }
        }

        // Clear-Bookmark (Ctrl+Shift+B): if one bookmark, clear it
        // directly. If multiple, show a chooser (Clear All as
        // default; or pick one to clear).
        private void recClearBookmarkClicked(object sender, EventArgs evArgs)
        {
            if (lBookmarks.Count == 0)
            {
                LiveRegion.say("No bookmarks to clear");
                return;
            }
            if (lBookmarks.Count == 1)
            {
                lBookmarks.Clear();
                lblStatus.Text = "Bookmark cleared.";
                LiveRegion.say("Bookmark cleared");
                return;
            }
            // Multiple: chooser
            List<string> lDisplay = new List<string>();
            foreach (BookmarkEntry be in lBookmarks)
            {
                string sLookText = string.IsNullOrEmpty(be.sLook) ? "" : (" -- " + be.sLook);
                lDisplay.Add(be.sTable + sLookText + " (row " + be.iRowAtSave + ")");
            }
            int iChosen = -1;
            string sBtn = null;
            using (LbcDialog dlg = new LbcDialog("Clear Bookmark", this))
            {
                dlg.addLabel("Clear all bookmarks (default), or select one to clear:");
                ListBox lb = dlg.addListBox("Bookmarks", lDisplay, lDisplay[0]);
                sBtn = dlg.runWithButtons(new string[] {
                    "Clear &All",
                    "Clear &Selected",
                    "Ca&ncel"
                });
                if (string.IsNullOrEmpty(sBtn)
                    || sBtn.IndexOf("ancel", StringComparison.OrdinalIgnoreCase) >= 0)
                    return;
                if (sBtn.IndexOf("All", StringComparison.OrdinalIgnoreCase) >= 0)
                {
                    int n = lBookmarks.Count;
                    lBookmarks.Clear();
                    lblStatus.Text = "Bookmarks cleared (" + n + ").";
                    LiveRegion.say("Cleared " + n + " bookmarks");
                    return;
                }
                iChosen = lb.SelectedIndex;
            }
            if (iChosen < 0 || iChosen >= lBookmarks.Count) return;
            BookmarkEntry removed = lBookmarks[iChosen];
            lBookmarks.RemoveAt(iChosen);
            string sLook = string.IsNullOrEmpty(removed.sLook)
                ? ("row " + removed.iRowAtSave) : removed.sLook;
            string sMsg = "Bookmark cleared: " + sLook + " (" + lBookmarks.Count + " remaining)";
            lblStatus.Text = sMsg;
            LiveRegion.say(sMsg);
        }

        // Helper: prompt for a single line of text. Returns null if the
        // user cancels. Used by Set-Position and any other quick-input
        // command.
        private string promptText(string sTitle, string sPrompt, string sInitial)
        {
            using (Form dlg = new LbcForm())
            {
                dlg.Text = sTitle;
                dlg.AccessibleName = sTitle;
                dlg.StartPosition = FormStartPosition.CenterParent;
                dlg.ClientSize = new Size(420, 140);
                dlg.FormBorderStyle = FormBorderStyle.FixedDialog;
                dlg.MaximizeBox = false;
                dlg.MinimizeBox = false;
                dlg.ShowInTaskbar = false;
                dlg.KeyPreview = true;

                Label lbl = new Label();
                lbl.Text = sPrompt;
                lbl.Location = new Point(12, 12);
                lbl.Size = new Size(396, 36);
                dlg.Controls.Add(lbl);

                TextBox tb = new TextBox();
                tb.AccessibleName = sPrompt;
                tb.Location = new Point(12, 56);
                tb.Size = new Size(396, 23);
                tb.Text = sInitial ?? "";
                tb.SelectAll();
                dlg.Controls.Add(tb);

                Button btnOk = new Button();
                btnOk.Text = "&OK";
                btnOk.DialogResult = DialogResult.OK;
                btnOk.Size = new Size(90, 28);
                btnOk.Location = new Point(218, 96);
                dlg.Controls.Add(btnOk);

                Button btnCancel = new Button();
                btnCancel.Text = "&Cancel";
                btnCancel.DialogResult = DialogResult.Cancel;
                btnCancel.Size = new Size(90, 28);
                btnCancel.Location = new Point(316, 96);
                dlg.Controls.Add(btnCancel);

                dlg.AcceptButton = btnOk;
                dlg.CancelButton = btnCancel;
                dlg.ActiveControl = tb;

                if (dlg.ShowDialog(this) != DialogResult.OK) return null;
                return tb.Text;
            }
        }

        // =====================================================================
        // VIEW menu handlers
        // =====================================================================
        // viewSelectClicked (Alt+Shift+F): Filter Records via the
        // same field form as Edit Record. One textbox per editable
        // field; a bare value is an exact match, a leading % is a
        // case-insensitive substring (LIKE), and a leading operator
        // (= <= >= < > <> !=) compares instead. Several filled fields
        // AND together. When no filter is active the form opens
        // straight away (focus on the first field); when one is
        // active a chooser first offers Clear (default) / And / Or /
        // New / Edit / Cancel, which decide the form's initial values
        // and whether the result replaces or combines with the
        // current filter.

        // viewSelectClicked: Alt+Shift+F. Two-phase design:
        //   Phase 1: when a filter is already active, show a chooser
        //     dialog with action buttons (Clear / And / Or / Edit /
        //     Reset / Cancel). Clear is the default (Enter).
        //   Phase 2: based on the action, possibly open the
        //     field-by-field form (And/Or = blank, Edit = pre-
        //     populated, Reset = blank).
        //
        // The And/Or actions wrap the EXISTING db.filter SQL expression
        // and the newly-built one in parens, joining with " AND " or
        // " OR " to compose more complex filters incrementally.
        //
        // When no filter is currently active, the chooser doesn't
        // appear (there's nothing to clear / combine with). We go
        // directly to the blank field form (Reset behavior).
        // filterRegexClicked: Filter Regex. Restricts the current table
        // to rows whose CURRENT column matches a regular expression,
        // using SQLean's server-side REGEXP operator. Because the result
        // is still a single-base-table SELECT (SELECT * FROM t WHERE
        // "col" REGEXP '...'), it opens through selectTableFiltered and
        // stays editable. An empty pattern clears the filter by reopening
        // the table. This complements the client-side regex Find and the
        // ADO-filter Filter Records, neither of which can do REGEXP.
        // Requires sqlean.dll beside the executable (auto-loaded); a
        // missing bundle surfaces as a clear error in the dialog.
        private void filterRegexClicked(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset()) return;
            if (db.currentIsCustomQuery)
            { LiveRegion.sayForced("Filter Regex applies to a table, not a query window."); return; }
            string sCol = virtCurrentColumnName();
            if (string.IsNullOrEmpty(sCol)) { LiveRegion.sayForced("No current column."); return; }

            string sPattern;
            using (LbcDialog dlg = new LbcDialog("Filter Regex", this))
            {
                TextBox tbPat = dlg.addInputBox("Regex for column " + sCol, "",
                    "Show only rows where " + sCol + " matches this regular expression. "
                    + "Leave empty to clear the filter.");
                if (!dlg.runOkCancel()) return;
                sPattern = tbPat.Text ?? "";
            }

            try
            {
                if (sPattern.Length == 0)
                {
                    db.selectTable(db.currentTable);
                    invokeRefresh();
                    LiveRegion.sayForced("Regex filter cleared. " + db.recordCount + " records.");
                    return;
                }
                string sWhere = "\"" + sCol.Replace("\"", "\"\"") + "\" REGEXP '"
                    + sPattern.Replace("'", "''") + "'";
                db.selectTableFiltered(db.currentTable, sWhere);
                invokeRefresh();
                LiveRegion.sayForced("Regex filter applied. " + db.recordCount + " matching records.");
            }
            catch (Exception ex) { ErrorDialog.show(this, "Filter Regex", ex.Message); }
        }

        private void viewSelectClicked(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset()) return;

            string sExistingFilter = db.filter ?? "";
            bool bFilterActive = !string.IsNullOrEmpty(sExistingFilter);

            string sAction = "Reset"; // default when no filter active

            if (bFilterActive)
            {
                using (LbcDialog dlg = new LbcDialog("Where Filter", this))
                {
                    dlg.addLabel("A filter is active:");
                    dlg.addLabel(sExistingFilter);
                    dlg.addLabel("");
                    dlg.addLabel("Choose an action:");
                    // Exactly these six buttons (Help suppressed). Clear
                    // is the default. And/Or open a blank form and
                    // combine the new filter with the old; New opens a
                    // blank form and replaces; Edit opens the form
                    // pre-filled with the last values typed and
                    // replaces.
                    string sBtn = dlg.runWithButtons(new string[] {
                        "&Edit", "&And", "&Or", "&New", "&Clear", "Cance&l"
                    }, false);
                    if (string.IsNullOrEmpty(sBtn)) return;
                    string sB = sBtn.Replace("&", "");
                    if (sB.Equals("Cancel", StringComparison.OrdinalIgnoreCase)) return;
                    else if (sB.Equals("Clear", StringComparison.OrdinalIgnoreCase)) sAction = "Clear";
                    else if (sB.Equals("And", StringComparison.OrdinalIgnoreCase)) sAction = "And";
                    else if (sB.Equals("Or", StringComparison.OrdinalIgnoreCase)) sAction = "Or";
                    else if (sB.Equals("New", StringComparison.OrdinalIgnoreCase)) sAction = "New";
                    else if (sB.Equals("Edit", StringComparison.OrdinalIgnoreCase)) sAction = "Edit";
                    else return;
                }
            }

            // Phase 2: handle the chosen action.
            if (sAction == "Clear")
            {
                try
                {
                    db.filter = "";
                    invokeRefresh();
                    persistCurrentTableState();
                    LiveRegion.sayForced("Filter cleared. " + db.recordCount + " records visible.");
                }
                catch (Exception ex)
                {
                    ErrorDialog.show(this, "Where Filter", ex.Message);
                }
                return;
            }

            // Field-based filter entry, the same form as Edit Record
            // (Control+E): one textbox per editable field, blank by
            // default (pre-filled only for Edit). See
            // sBuildFieldPredicate for the per-field operator syntax.
            // Values typed into several fields combine with AND.
            bool bPrePopulate = (sAction == "Edit");
            List<string> lFields = db.getEditableFieldNames();
            Dictionary<string, string> dInitial = new Dictionary<string, string>();
            List<bool> lEditable = new List<bool>();
            foreach (string sF in lFields)
            {
                string sPrev;
                dInitial[sF] = (bPrePopulate && dLastFilterValues.TryGetValue(sF, out sPrev))
                    ? sPrev : "";
                lEditable.Add(true);
            }
            using (RecordEditDialog dlg = new RecordEditDialog("Where Filter", lFields, dInitial, lEditable, db))
            {
                if (dlg.showDialog(this) != DialogResult.OK) return;
                dLastFilterValues = new Dictionary<string, string>(dlg.dValues);

                List<string> lPredicates = new List<string>();
                foreach (string sF in lFields)
                {
                    string sVal;
                    if (!dlg.dValues.TryGetValue(sF, out sVal)) continue;
                    sVal = (sVal ?? "").Trim();
                    if (sVal.Length == 0) continue;
                    string sPred = sBuildFieldPredicate(sF, sVal);
                    if (!string.IsNullOrEmpty(sPred)) lPredicates.Add(sPred);
                }
                string sNewExpr = string.Join(" AND ", lPredicates.ToArray());

                // Combine with existing filter for And/Or; otherwise
                // the new expression replaces the old.
                string sFinalExpr;
                if (sAction == "And" && !string.IsNullOrEmpty(sNewExpr))
                    sFinalExpr = "(" + sExistingFilter + ") AND (" + sNewExpr + ")";
                else if (sAction == "Or" && !string.IsNullOrEmpty(sNewExpr))
                    sFinalExpr = "(" + sExistingFilter + ") OR (" + sNewExpr + ")";
                else
                    sFinalExpr = sNewExpr;

                try
                {
                    db.filter = sFinalExpr;
                    invokeRefresh();
                    persistCurrentTableState();
                    if (string.IsNullOrEmpty(sFinalExpr))
                        LiveRegion.sayForced("No filter applied. " + db.recordCount + " records visible.");
                    else
                        LiveRegion.sayForced("Filter applied. " + db.recordCount + " records match.");
                }
                catch (Exception ex)
                {
                    ErrorDialog.show(this, "Where Filter", ex.Message);
                }
            }
        }

        // Last per-field filter values, for the Edit action's
        // pre-population. Session-scoped.
        private Dictionary<string, string> dLastFilterValues = new Dictionary<string, string>();

        // sBuildFieldPredicate: turn one field's filter entry into one
        // ADO Filter predicate. An optional leading SYMBOL selects the
        // kind of match; when no symbol is given, "=" (exact match) is
        // implicit:
        //   value      no symbol -> field = 'value'   (exact, implicit =)
        //   =value     field = 'value'                (explicit exact)
        //   !=value    field <> 'value'   (ADO spells not-equal as <>)
        //   >value     field > value
        //   >=value    field >= value
        //   <value     field < value
        //   <=value    field <= value
        //   %value     field LIKE '*value*'  (value is a SUBSTRING)
        // Symbols are matched longest-first so ">=" beats ">" and "<="
        // beats "<". Numeric operands are emitted bare so the compare is
        // numeric; text operands are quoted (embedded single quotes are
        // doubled). ADO's client-side cursor compares strings case-
        // insensitively, so matches are case-insensitive where the
        // provider allows. Note the wildcard: ADO Filter's LIKE uses '*'
        // (not SQL's '%'), so the user-facing '%' prefix is translated to
        // a pair of '*' wildcards around the value.
        private static string sBuildFieldPredicate(string sField, string sValue)
        {
            string sV = (sValue ?? "").Trim();
            if (sV.Length == 0) return "";

            // '%' prefix: case-insensitive substring match.
            if (sV.StartsWith("%"))
            {
                string sSub = sV.Substring(1).Trim();
                if (sSub.Length == 0) return "";
                return sField + " LIKE '*" + sSub.Replace("'", "''") + "*'";
            }

            // Explicit comparison symbols, longest first so two-character
            // operators win over their single-character prefixes.
            string sOp = null;
            string sRest = null;
            foreach (string sCand in new string[] { ">=", "<=", "!=", "=", ">", "<" })
            {
                if (sV.StartsWith(sCand))
                { sOp = sCand; sRest = sV.Substring(sCand.Length).Trim(); break; }
            }

            string sEmitOp;
            string sOperand;
            if (sOp == null)
            {
                // No symbol: exact equals is implicit.
                sEmitOp = "=";
                sOperand = sV;
            }
            else
            {
                sEmitOp = (sOp == "!=") ? "<>" : sOp;
                sOperand = sRest;
            }
            if (sOperand.Length == 0) return "";

            double dN;
            bool bNumeric = double.TryParse(sOperand,
                System.Globalization.NumberStyles.Any,
                System.Globalization.CultureInfo.InvariantCulture, out dN);
            return sField + " " + sEmitOp + " "
                + (bNumeric ? sOperand : "'" + sOperand.Replace("'", "''") + "'");
        }

        // Translate the dialog's three controls into an ADO Filter expression.
        // ADO Filter syntax: "col LIKE '%text%'", "col = 'text'", optionally
        // chained with AND. For "All columns", we OR the predicates.
        private static string buildFilterExpression(string sText, string sCol, string sMode, List<string> lAllColumns)
        {
            if (string.IsNullOrEmpty(sText)) return "";
            string sEsc = sText.Replace("'", "''");
            string sPattern;
            switch (sMode ?? "Contains")
            {
                case "Equals":     sPattern = "= '" + sEsc + "'"; break;
                case "Starts with":sPattern = "LIKE '" + sEsc + "%'"; break;
                default:           sPattern = "LIKE '%" + sEsc + "%'"; break;
            }
            if (string.IsNullOrEmpty(sCol) || sCol == "All columns")
            {
                List<string> lOr = new List<string>();
                foreach (string sN in lAllColumns) lOr.Add(sN + " " + sPattern);
                return string.Join(" OR ", lOr);
            }
            return sCol + " " + sPattern;
        }

        private void viewResetFilterClicked(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset()) return;
            db.resetFilter();
            invokeRefresh();
            persistCurrentTableState();
        }

        // viewFormatClicked, viewSortAscClicked, viewSortDescClicked,
        // viewSortRecentClicked, viewSortOldestClicked, sortByPickedColumn,
        // sortByDateColumn, pickDateColumn -- all removed in v1.0.86
        // along with their menu items. The universal Sort-Records
        // command (Alt+Shift+S, sortRecordsClicked elsewhere in this
        // file) handles every sort case by defaulting to the current
        // virtual column and offering an opt-in Descending checkbox.

        private void viewResetSortClicked(object sender, EventArgs evArgs)
