        // --- Sort Records (Alt+Shift+S) ---
        // Sort by the CURRENT virtual column. A small dialog with a
        // single Ascending checkbox (default OFF -- descending is
        // the typical use case: "show the largest values first").
        // Distinct from Sort-Ascending / Sort-Descending which prompt
        // for the column. This command takes its column from the
        // current virtual cursor's position so it's a "sort this
        // column right now" gesture.
        // persistCurrentTableState: write the current table's filter,
        // sort, position, and virtual column straight to the RecentFiles
        // ini block now, instead of waiting for form close. DbDo opens
        // each database/table in its own MDI window with its own
        // manager, so a close handler is fragile -- closing the database
        // (not the window), or one window persisting over another, can
        // drop the change. Writing here means the LAST sort (and filter)
        // is saved the instant it is set and restored on the next open.
        // Never allowed to throw: persistence must not break a command.
        private void persistCurrentTableState()
        {
            try
            {
                if (db == null || !db.isOpen()
                    || string.IsNullOrEmpty(db.filePath)
                    || string.IsNullOrEmpty(db.currentTable)) return;
                RecentFiles.recordTableState(db.filePath, db.currentTable,
                    db.filter ?? "", db.sort ?? "", db.absolutePosition,
                    virtCurrentColumnName() ?? "", db.getSelectList(db.currentTable) ?? "");
                // Also write the view to the per-database <DbName>.inix
                // [Table:<name>] section (SelectFields / OrderFields /
                // WhereFilter) so it travels with the database and is
                // recalled on open via applyTableSettings.
                saveTableView(db.currentTable);
                saveDbSettings();
                try { DbDoLog.write("Saved table state for '" + db.currentTable
                    + "': sort=[" + (db.sort ?? "") + "]"); } catch { }
            }
            catch { /* never let persistence break the command */ }
        }

        // reverseOrderClicked (Alt+Shift+O): reverse the current sort
        // by flipping each clause's direction -- ASC becomes DESC,
        // DESC becomes ASC, and a clause with no explicit direction
        // (implicitly ASC) becomes DESC. The clause order and the
        // columns are unchanged; only the directions invert, so the
        // records run in the exact reverse of the current order.
        private void reverseOrderClicked(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset()) return;
            string sCurrent = (db.sort ?? "").Trim();
            if (sCurrent.Length == 0)
            { LiveRegion.sayForced("No order to reverse."); return; }
            List<string> lFlipped = new List<string>();
            foreach (string sPart in sCurrent.Split(','))
            {
                string sClause = sPart.Trim();
                if (sClause.Length == 0) continue;
                if (sClause.EndsWith(" DESC", StringComparison.OrdinalIgnoreCase))
                    lFlipped.Add(sClause.Substring(0, sClause.Length - 5).Trim() + " ASC");
                else if (sClause.EndsWith(" ASC", StringComparison.OrdinalIgnoreCase))
                    lFlipped.Add(sClause.Substring(0, sClause.Length - 4).Trim() + " DESC");
                else
                    lFlipped.Add(sClause + " DESC");  // implicit ASC -> DESC
            }
            string sNew = string.Join(", ", lFlipped.ToArray());
            try
            {
                db.sort = sNew;
                invokeRefresh();
                persistCurrentTableState();
                LiveRegion.sayForced("Order reversed: " + sNew + ". " + db.recordCount + " records.");
            }
            catch (Exception ex) { ErrorDialog.show(this, "Reverse Order", ex, db); }
        }

        // orderRecordsClicked: Alt+O. Sort records by a chosen column
        // ascending. The dialog shows an alpha-sorted listbox of ALL
        // field names (including hidden columns -- the user can sort
        // by columns they don't currently display), focused on the
        // current virtual column. Press Enter to sort by the focused
        // (default) column, or arrow + Enter to pick another.
        //
        // Sorting by hidden columns is the key feature: today users
        // need to display a column, sort, then optionally hide it
        // again. The all-fields listbox eliminates that workflow.
        private void orderRecordsClicked(object sender, EventArgs evArgs)
        {
            // Order Records (Alt+Shift+O): the Names/Picks dialog in
            // sort mode. The active sort pre-loads into Picks as
            // "name asc" / "name desc" entries, so editing,
            // reordering by remove-and-re-add, and clearing (empty
            // Picks) are all the same gesture; the Picks order is
            // the sort precedence, applied via the ADO
            // Recordset.Sort property.
            if (db == null || !db.hasRecordset()) return;
            List<string> lAllFields = db.getFieldNames();
            if (lAllFields == null || lAllFields.Count == 0)
            { LiveRegion.say("No columns to sort by"); return; }

            List<string> lInitial = new List<string>();
            foreach (string sPart in (db.sort ?? "").Split(','))
            {
                string sP = sPart.Trim();
                if (sP.Length == 0) continue;
                bool bDesc = sP.EndsWith(" DESC", StringComparison.OrdinalIgnoreCase);
                string sName = sP;
                if (bDesc) sName = sP.Substring(0, sP.Length - 5).Trim();
                else if (sP.EndsWith(" ASC", StringComparison.OrdinalIgnoreCase))
                    sName = sP.Substring(0, sP.Length - 4).Trim();
                lInitial.Add(sName + (bDesc ? " desc" : " asc"));
            }

            using (ColumnSequenceDialog dlg = new ColumnSequenceDialog(
                "Pick Fields for Sort Order", lAllFields, virtCurrentColumnName(), lInitial, true))
            {
                if (dlg.ShowDialog(this) != DialogResult.OK) return;
                List<string> lClauses = new List<string>();
                foreach (string sPick in dlg.lChosenColumns)
                {
                    int iSpace = sPick.LastIndexOf(' ');
                    if (iSpace <= 0) continue;
                    bool bDesc = sPick.Substring(iSpace + 1)
                        .Equals("desc", StringComparison.OrdinalIgnoreCase);
                    lClauses.Add(sPick.Substring(0, iSpace) + (bDesc ? " DESC" : " ASC"));
                }
                string sFinal = string.Join(", ", lClauses.ToArray());
                try
                {
                    db.sort = sFinal;
                    invokeRefresh();
                    // Persist the new sort for this table immediately,
                    // rather than only on form close (see
                    // persistCurrentTableState) -- the "I have to re-sort
                    // every time I open it" report.
                    persistCurrentTableState();
                    LiveRegion.sayForced(lClauses.Count == 0
                        ? "Sort cleared. " + db.recordCount + " records in original order."
                        : "Ordered by " + sFinal + ". " + db.recordCount + " records.");
                }
                catch (Exception ex) { ErrorDialog.show(this, "Order Records", ex, db); }
            }
        }

        private void sortRecordsClicked(object sender, EventArgs evArgs)
        {
            orderRecordsClicked(sender, evArgs);
        }

        // --- Misc deferred stubs ---
        // --- Database Summary (Alt+D) ---
        // Memo dialog listing every table with its record count, then
        // its related tables (those connected via foreign keys, in
        // either direction). Plain text, no schema jargon -- the goal
        // is a fast human/screen-reader overview of what's in the
        // database and how the tables relate.
        //
        // Relations follow DbDo's column-naming convention rather
        // than walking PRAGMA foreign_key_list, so the same algorithm
        // works for .db, .xlsx, .csv, and any other tabular source
        // where the convention has been adopted. Two directions:
        //
        //   - Outbound: this table has a column named '<other>_id'
        //     and a table named '<other>s' or '<other>' exists.
        //     Those are this table's parents (each row of this table
        //     points to one row of the other).
        //   - Inbound: another table has a column named '<this_
        //     singular>_id'. Those are this table's children (rows
        //     of the other table point back to rows here).
        //
        // The current table is the first one listed for screen-
        // reader convenience -- the user opens the dialog already
        // thinking about it.
        private void miscDatabaseSummaryClicked(object sender, EventArgs evArgs)
        {
            if (db == null || !db.isOpen())
            { LiveRegion.say("No database open"); return; }
            List<string> lAllTables = db.getTableAndViewNames();
            if (lAllTables == null || lAllTables.Count == 0)
            { LiveRegion.say("Database has no tables"); return; }

            // Order: current table first, then the rest alphabetically.
            string sCurrent = db.currentTable ?? "";
            List<string> lOrdered = new List<string>();
            if (!string.IsNullOrEmpty(sCurrent) && lAllTables.Contains(sCurrent))
                lOrdered.Add(sCurrent);
            List<string> lRest = new List<string>();
            foreach (string s in lAllTables)
                if (!string.Equals(s, sCurrent, StringComparison.OrdinalIgnoreCase))
                    lRest.Add(s);
            lRest.Sort(StringComparer.OrdinalIgnoreCase);
            lOrdered.AddRange(lRest);

            // Database-level metadata, by DbDo convention the --!
            // doc block of the builtin lookups table (every DbDo
            // database has one; the database has no CREATE statement
            // of its own to carry comments). Collected here and
            // emitted by the output pass below via sDbDocPrefix.
            string sDbDocPrefix = "";
            {
                List<string[]> lsDbDoc;
                List<string[]> lsDbColDocs;
                if (db.getSchemaDoc("lookups", out lsDbDoc, out lsDbColDocs) && lsDbDoc.Count > 0)
                {
                    StringBuilder sbDoc = new StringBuilder();
                    sbDoc.AppendLine("Database documentation:");
                    foreach (string[] aPair in lsDbDoc)
                        sbDoc.AppendLine("  " + (aPair[0].Length > 0
                            ? aPair[0] + ": " + aPair[1] : aPair[1]));
                    sbDoc.AppendLine();
                    sDbDocPrefix = sbDoc.ToString();
                }
            }

            // Precompute row counts and PK-stems for every table so the
            // inbound-FK pass can use cached values.
            Dictionary<string, long> dCounts = new Dictionary<string, long>();
            Dictionary<string, string> dPkStem = new Dictionary<string, string>();  // table -> singular stem (e.g. "classes" -> "class")
            Dictionary<string, List<string>> dCols = new Dictionary<string, List<string>>();
            foreach (string sT in lAllTables)
            {
                dCounts[sT] = db.countRowsOfTable(sT);
                List<string> lTcols = db.getColumnsOfTable(sT);
                dCols[sT] = lTcols;
                string sPk = db.actualPrimaryKey(sT);
                if (string.IsNullOrEmpty(sPk)) sPk = computePrimaryKeyColumn(sT, lTcols);
                if (!string.IsNullOrEmpty(sPk) && sPk.EndsWith(Metadata.PrimaryKeySuffix, StringComparison.OrdinalIgnoreCase))
                    dPkStem[sT] = sPk.Substring(0, sPk.Length - Metadata.PrimaryKeySuffix.Length);
                else
                    dPkStem[sT] = "";
            }

            // Maps associations, aggregated once for the whole
            // database: every (subject table, kind, object table)
            // group with its row count. This is the SAME query
            // machinery (queryRowsSql over the ADO connection) that
            // the Enter Child picker uses, so this summary doubles
            // as a health check for maps-based navigation: if maps
            // lines appear here, the maps query path works.
            List<string[]> lMapGroups = new List<string[]>();
            if (db.hasMapsTable())
            {
                int iMapGroupsFound;
                lMapGroups = db.queryRowsSql(
                    "SELECT tbl1, kind, tbl2, count(*) FROM maps GROUP BY tbl1, kind, tbl2",
                    500, out iMapGroupsFound);
                DbDoLog.write("Database Summary: " + lMapGroups.Count + " maps groups");
            }

            StringBuilder sb = new StringBuilder();
            // Resolve to full path. Reporting the actual filesystem
            // location (not the relative path passed to openDatabase)
            // matches what the user expects to read in this summary.
            string sShownPath = db.filePath ?? "";
            try
            {
                if (!string.IsNullOrEmpty(sShownPath))
                    sShownPath = Path.GetFullPath(sShownPath);
            }
            catch { }
            sb.AppendLine("Database: " + sShownPath);
            // If the file doesn't exist at that resolved path, note
            // it -- this catches the case where the path stored on
            // the manager is no longer reachable on disk.
            try
            {
                if (!string.IsNullOrEmpty(sShownPath) && !File.Exists(sShownPath))
                    sb.AppendLine("  (file not found at this path)");
            }
            catch { }
            sb.AppendLine("Tables: " + lAllTables.Count);
            // Engine and driver identity, from the live connection's
            // dynamic ADO properties -- the SQLite version and the ODBC
            // driver build, neither of which the per-table summaries
            // carry. Only entries the provider actually fills are shown
            // (the thin SQLite ODBC driver leaves most others blank), and
            // read-only is noted only when the source really is read-only.
            string sDbmsName = db.connectionProperty("DBMS Name");
            string sDbmsVer  = db.connectionProperty("DBMS Version");
            string sDrvName  = db.connectionProperty("Driver Name");
            string sDrvVer   = db.connectionProperty("Driver Version");
            if (sDbmsName.Length > 0 || sDbmsVer.Length > 0)
                sb.AppendLine("Engine: " + (sDbmsName + " " + sDbmsVer).Trim());
            if (sDrvName.Length > 0 || sDrvVer.Length > 0)
                sb.AppendLine("Driver: " + (sDrvName + " " + sDrvVer).Trim());
            if (db.connectionProperty("Read-Only Data Source").Equals("True", StringComparison.OrdinalIgnoreCase))
                sb.AppendLine("Access: read-only");
            sb.AppendLine();
            if (sDbDocPrefix.Length > 0) sb.Append(sDbDocPrefix);
            foreach (string sT in lOrdered)
            {
                long nCount = dCounts.ContainsKey(sT) ? dCounts[sT] : -1;
                string sCountStr = (nCount < 0) ? "?" : nCount.ToString();
                sb.AppendLine(sT + " (" + sCountStr + " record" + (nCount == 1 ? "" : "s") + ")");

                // Outbound: this table's columns named "<other>_id" pointing to a known table.
                List<string> lOutbound = new List<string>();
                List<string> lMyCols = dCols.ContainsKey(sT) ? dCols[sT] : new List<string>();
                string sMyPk = db.actualPrimaryKey(sT);
                foreach (string sCol in lMyCols)
                {
                    if (string.Equals(sCol, sMyPk, StringComparison.OrdinalIgnoreCase)) continue;
                    if (!sCol.EndsWith(Metadata.PrimaryKeySuffix, StringComparison.OrdinalIgnoreCase)) continue;
                    string sParent = findParentTableForFk(sCol, lAllTables);
                    if (string.IsNullOrEmpty(sParent)) continue;
                    if (string.Equals(sParent, sT, StringComparison.OrdinalIgnoreCase)) continue;
                    if (!lOutbound.Contains(sParent)) lOutbound.Add(sParent);
                }

                // Inbound: other tables have a column named "<this_stem>_id".
                List<string> lInbound = new List<string>();
                string sMyStem = dPkStem.ContainsKey(sT) ? dPkStem[sT] : "";
                if (!string.IsNullOrEmpty(sMyStem))
                {
                    string sFkLookFor = sMyStem + Metadata.PrimaryKeySuffix;
                    foreach (string sOther in lAllTables)
                    {
                        if (string.Equals(sOther, sT, StringComparison.OrdinalIgnoreCase)) continue;
                        List<string> lOtherCols = dCols.ContainsKey(sOther) ? dCols[sOther] : new List<string>();
                        foreach (string sCol in lOtherCols)
                        {
                            if (string.Equals(sCol, sFkLookFor, StringComparison.OrdinalIgnoreCase))
                            { lInbound.Add(sOther); break; }
                        }
                    }
                }

                // Maps associations touching this table. Per DbDo's
                // relation-label convention, each line names the OTHER
                // table -- the kind ("offers", "presents") is internal
                // jargon, not a table, so it is never shown as one. The
                // kind is appended only to disambiguate when the same
                // other table is reached by more than one kind (e.g.
                // contacts relates to events via both "presents" and
                // "sponsors"). Direction and the "maps"/"to"/"from"
                // wording are dropped. Edges are collected from both
                // sides so a record found as subject or object counts.
                List<string[]> lMapEdges = new List<string[]>(); // (otherTable, kind, count)
                foreach (string[] aGroup in lMapGroups)
                {
                    if (string.Equals(aGroup[0], sT, StringComparison.OrdinalIgnoreCase))
                        lMapEdges.Add(new string[] { aGroup[2], aGroup[1], aGroup[3] });
                    else if (string.Equals(aGroup[2], sT, StringComparison.OrdinalIgnoreCase))
                        lMapEdges.Add(new string[] { aGroup[0], aGroup[1], aGroup[3] });
                }
                Dictionary<string, int> dOtherCount = new Dictionary<string, int>();
                foreach (string[] aEdge in lMapEdges)
                {
                    string sKey = aEdge[0].ToLowerInvariant();
                    dOtherCount[sKey] = (dOtherCount.ContainsKey(sKey) ? dOtherCount[sKey] : 0) + 1;
                }
                List<string> lMapsLines = new List<string>();
                foreach (string[] aEdge in lMapEdges)
                {
                    bool bNeedKind = dOtherCount[aEdge[0].ToLowerInvariant()] > 1;
                    lMapsLines.Add("  " + aEdge[0]
                        + (bNeedKind ? " via " + aEdge[1] : "")
                        + " (" + aEdge[2] + ")");
                }
                lMapsLines.Sort(StringComparer.OrdinalIgnoreCase);

                if (lOutbound.Count == 0 && lInbound.Count == 0 && lMapsLines.Count == 0)
                {
                    sb.AppendLine("  (no related tables)");
                }
                else
                {
                    lOutbound.Sort(StringComparer.OrdinalIgnoreCase);
                    lInbound.Sort(StringComparer.OrdinalIgnoreCase);
                    foreach (string sParent in lOutbound)
                    {
                        long n = dCounts.ContainsKey(sParent) ? dCounts[sParent] : -1;
                        string sN = (n < 0) ? "?" : n.ToString();
                        sb.AppendLine("  parent: " + sParent + " (" + sN + ")");
                    }
                    foreach (string sChild in lInbound)
                    {
                        long n = dCounts.ContainsKey(sChild) ? dCounts[sChild] : -1;
                        string sN = (n < 0) ? "?" : n.ToString();
                        sb.AppendLine("  child:  " + sChild + " (" + sN + ")");
                    }
                    foreach (string sMapsLine in lMapsLines)
                        sb.AppendLine(sMapsLine);
                }
                sb.AppendLine();
            }

            using (LbcDialog dlg = new LbcDialog("Database Summary", this))
            {
                dlg.addMemoBox("&Summary", sb.ToString().TrimEnd(),
                    "Read-only overview. Each table shows its record count and its related tables, with the related tables' record counts in parentheses.");
                dlg.runWithButtons(new string[] { "OK" });
            }
        }
        private void miscWindowSummaryStub(object sender, EventArgs evArgs)
        {
            LiveRegion.say("Window Summary is deferred; not yet implemented");
        }

        // The per-column sort handlers (sortByFixedColumn,
        // getCurrentPrimaryKey, sortByIdClicked, sortByIdRevClicked,
        // sortByLookClicked, sortByLookRevClicked, sortByTagsClicked,
        // sortByTagsRevClicked, sortByUrlClicked, sortByUrlRevClicked)
        // were removed in v1.0.86 along with their menu items. The
        // universal Sort-Records dialog (Alt+Shift+S) replaces them.

        // --- Open New Recordset (Ctrl+Shift+O) ---
        // Prompt for an arbitrary SQL SELECT and open its result as a
        // recordset for browsing. The recordset is READ-ONLY because
        // it has no underlying table identity -- joins, expressions,
        // and aggregates make the result set non-updatable. Find /
        // Filter / Sort / Say-X family commands all work; Mark / Edit
        // / Delete refuse with a clear message.
        //
        // This is the user's "ad-hoc view" workflow: write a SELECT,
        // browse the rows row-by-row with all the normal navigation
        // commands, and dismiss when done. The underlying database's
        // table-bound recordset is preserved -- closing the ad-hoc
        // recordset restores the prior view.
        private void fileOpenSelectClicked(object sender, EventArgs evArgs)
        {
            if (db == null || !db.isOpen())
            { LiveRegion.say("No database open"); return; }
            string sSql;
            using (LbcDialog dlg = new LbcDialog("Open New Recordset", this))
            {
                dlg.addLabel("Enter a SQL SELECT statement. The result will open as a");
                dlg.addLabel("read-only recordset that you can browse with all the");
                dlg.addLabel("normal navigation commands. Mark / Edit / Delete will");
                dlg.addLabel("not work because the result set has no table identity.");
                dlg.addSeparator();
                TextBox tb = dlg.addMemoBox("SQL S&ELECT", "SELECT * FROM ",
                    "A full SELECT statement. Use SELECT * FROM <table> for a simple view, or write a JOIN or any other valid SELECT.");
                if (!dlg.runOkCancel()) return;
                sSql = tb.Text ?? "";
            }
            sSql = sSql.Trim();
            if (sSql.Length == 0) return;
            // Sanity-check that the statement is a SELECT (no UPDATE
            // / INSERT / DELETE etc. by accident).
            string sLow = sSql.ToLowerInvariant().TrimStart();
            if (!sLow.StartsWith("select") && !sLow.StartsWith("with"))
            {
                MessageBox.Show(this,
                    "Open New Recordset only accepts SELECT or WITH statements. "
                    + "Use File > Run SQL for other statement types.",
                    "Open New Recordset", MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }
            try
            {
                db.openSqlRecordset(sSql);
                invokeRefresh();
                LiveRegion.say("Recordset opened. " + db.recordCount + " row"
                    + (db.recordCount == 1 ? "" : "s") + ". Read-only.");
            }
            catch (Exception ex)
            {
                ErrorDialog.show(this, "Open New Recordset", "Could not open recordset: " + ex.Message);
            }
        }

        // F8 / Shift+F8 / Alt+F8 / Alt+Shift+F8 family. Two
        // independent anchors -- one for marking, one for unmarking
        // -- so the user can stage a mark range and an unmark range
        // without one gesture overwriting the other.
        //
        // F8         -> Start Mark Anchor: store current row.
        // Shift+F8   -> Complete Mark to Anchor: mark every row
        //               from the mark anchor to the current row.
        //               Direction-agnostic; anchor can be above or
        //               below the current row.
        // Alt+F8     -> Start Unmark Anchor: store current row in
        //               the separate unmark anchor.
        // Alt+Shift+F8 -> Complete Unmark to Anchor: unmark every
        //               row from the unmark anchor to the current
        //               row, also direction-agnostic.
        //
        // Both anchors are per-form transient state. They reset on
        // database close. Each "Complete" command refuses with a
        // clear message if its own anchor was set on a different
        // table than the currently open one.

        private void recMarkAnchorClicked(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset() || db.recordCount == 0)
            { LiveRegion.say("No record selected"); return; }
            iMarkAnchor = db.absolutePosition;
            sMarkAnchorTable = db.currentTable;
            LiveRegion.say("Mark anchor at row " + iMarkAnchor);
        }

        private void recUnmarkAnchorClicked(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset() || db.recordCount == 0)
            { LiveRegion.say("No record selected"); return; }
            iUnmarkAnchor = db.absolutePosition;
            sUnmarkAnchorTable = db.currentTable;
            LiveRegion.say("Unmark anchor at row " + iUnmarkAnchor);
        }

        private void recMarkToAnchorClicked(object sender, EventArgs evArgs)
        {
            applyAnchorRange(true);
        }

        private void recUnmarkToAnchorClicked(object sender, EventArgs evArgs)
        {
            applyAnchorRange(false);
        }

        // applyAnchorRange: shared body for the two "Complete"
        // commands. Reads from iMarkAnchor + sMarkAnchorTable when
        // bMark is true, or iUnmarkAnchor + sUnmarkAnchorTable when
        // bMark is false. Iterates from min(anchor, current) to
        // max(anchor, current) inclusive, setting the marked column
        // accordingly. Restores the user's row position when done.
        private void applyAnchorRange(bool bMark)
        {
            string sVerb = bMark ? "Complete Mark" : "Unmark Range";
            int iAnchor = bMark ? iMarkAnchor : iUnmarkAnchor;
            string sAnchorTable = bMark ? sMarkAnchorTable : sUnmarkAnchorTable;
            string sKindWord = bMark ? "mark" : "unmark";

            if (db == null || !db.hasRecordset() || db.readOnly)
            { LiveRegion.say("No table open or read-only"); return; }
            if (db.currentIsView)
            {
                MessageBox.Show(this, "Cannot mark rows of a view (read-only).",
                    sVerb, MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }
            if (!db.hasField(Metadata.MarkedColumn))
            {
                MessageBox.Show(this,
                    "Current table has no '" + Metadata.MarkedColumn + "' column.",
                    sVerb, MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }
            if (iAnchor < 1)
            {
                LiveRegion.say("No " + sKindWord + " anchor set; press "
                    + (bMark ? "F8" : "Alt+F8") + " first");
                return;
            }
            if (!string.Equals(sAnchorTable, db.currentTable,
                StringComparison.OrdinalIgnoreCase))
            {
                LiveRegion.say("Anchor was set on a different table; press "
                    + (bMark ? "F8" : "Alt+F8") + " to set a new one");
                if (bMark) { iMarkAnchor = -1; sMarkAnchorTable = null; }
                else       { iUnmarkAnchor = -1; sUnmarkAnchorTable = null; }
                return;
            }

            int iCur = db.absolutePosition;
            int iFrom = Math.Min(iAnchor, iCur);
            int iTo   = Math.Max(iAnchor, iCur);
            if (iFrom < 1) iFrom = 1;
            if (iTo > db.recordCount) iTo = db.recordCount;

            object bookmarkSaved = null;
            try { bookmarkSaved = db.bookmark; } catch { }

            int iChanged = 0;
            try
            {
                for (int i = iFrom; i <= iTo; i++)
                {
                    try
                    {
                        db.absolutePosition = i;
                        string sCurVal = db.getFieldValue(Metadata.MarkedColumn) ?? "";
                        string sTarget = bMark ? "1" : "0";
                        bool bAlready = string.Equals(sCurVal.Trim(), sTarget, StringComparison.Ordinal)
                                      || (bMark && (sCurVal.Equals("true", StringComparison.OrdinalIgnoreCase)
                                                || sCurVal.Equals("-1", StringComparison.Ordinal)))
                                      || (!bMark && (sCurVal.Equals("false", StringComparison.OrdinalIgnoreCase)
                                                  || string.IsNullOrEmpty(sCurVal.Trim())));
                        if (bAlready) continue;
                        db.setFieldValue(Metadata.MarkedColumn, sTarget);
                        db.update();
                        iChanged++;
                    }
                    catch { try { db.cancelUpdate(); } catch { } }
                }
            }
            finally
            {
                if (bookmarkSaved != null) try { db.bookmark = bookmarkSaved; } catch { }
            }
            invokeRefresh();
            int iRange = iTo - iFrom + 1;
            string sAction = bMark ? "Marked" : "Unmarked";
            LiveRegion.say(sAction + " " + iChanged
                + " of " + iRange + " row" + (iRange == 1 ? "" : "s")
                + " (rows " + iFrom + " to " + iTo + ")");
        }

        // =====================================================================
        // Show-Related: pick a foreign key on the current row and open
        // a child form filtered to the related rows.
        //
        // For the moment, this is a name-based heuristic: any column
        // ending in _id (other than the table's own primary key) is
        // assumed to be a foreign key whose target table is the column
        // name without the _id suffix. So 'app_id' on a 'screens' row
        // means "show me apps where app_id = N", and 'screen_id' on an
        // 'issues' row means "show me screens where screen_id = N".
        //
        // A future version could read PRAGMA foreign_key_list(<table>)
        // to be authoritative; the heuristic works for any schema that
        // follows the <table>_id naming convention.
        // =====================================================================
        private void recRelatedClicked(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset()) return;
            if (db.eof || db.bof) return;

            // Build a list of candidate FK columns: every column ending
            // in _id except the current table's own primary key column.
            string sOwnPk = (db.currentTable ?? "") + Metadata.PrimaryKeySuffix;
            List<string> lCandidates = new List<string>();
            foreach (string sCol in db.getFieldNames())
            {
                if (sCol.ToLowerInvariant() == sOwnPk.ToLowerInvariant()) continue;
                if (sCol.ToLowerInvariant().EndsWith(Metadata.PrimaryKeySuffix))
                    lCandidates.Add(sCol);
            }
            if (lCandidates.Count == 0)
            {
                MessageBox.Show(this,
                    "No foreign-key columns found on the current row.\n\n"
                    + "Show-Related uses the convention that any column ending "
                    + "in '_id' (other than the table's own primary key) refers "
                    + "to another table by the prefix.",
                    "Show Related", MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }

            // Default to the current column if it's a candidate.
            string sCurrent = virtCurrentColumnName();
            if (!lCandidates.Contains(sCurrent)) sCurrent = lCandidates[0];

            string sChosen = promptListChoice("Show Related",
                "Choose a foreign-key column:", lCandidates, sCurrent);
            if (string.IsNullOrEmpty(sChosen)) return;

            // Compute target table: column name minus '_id' suffix.
            string sValue = db.getFieldValue(sChosen);
            string sTarget = sChosen.Substring(0,
                sChosen.Length - Metadata.PrimaryKeySuffix.Length);

            // Verify the target exists.
            List<string> lAllTables = db.getTableAndViewNames();
            string sTargetActual = null;
            foreach (string sT in lAllTables)
            {
                if (sT.ToLowerInvariant() == sTarget.ToLowerInvariant())
                { sTargetActual = sT; break; }
            }
            // Try plural -> singular trim if not found, else give up.
            if (sTargetActual == null && sTarget.EndsWith("s"))
            {
                string sSingular = sTarget.Substring(0, sTarget.Length - 1);
                foreach (string sT in lAllTables)
                {
                    if (sT.ToLowerInvariant() == sSingular.ToLowerInvariant())
                    { sTargetActual = sT; break; }
                }
            }
            if (sTargetActual == null)
            {
                MessageBox.Show(this,
                    "Cannot find target table for column '" + sChosen + "'.\n\n"
                    + "Looked for table named '" + sTarget + "'.",
                    "Show Related", MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }

            // Switch to the target table and apply a filter on the
            // matching column. The FK target column on the target table
            // is conventionally the same name as the FK column on this
            // table (so 'screens.app_id' joins to 'apps.app_id').
            try
            {
                db.selectTable(sTargetActual);
                if (!string.IsNullOrEmpty(sValue))
                    db.applyFilter(sChosen + " = " + sValue);
                invokeRefresh();
            }
            catch (Exception ex)
            {
                ErrorDialog.show(this, "Show Related", "Could not navigate to related rows: " + ex.Message);
            }
        }

        // =====================================================================
        // Enter-Child / Exit-Child: parent-to-child drill-down across
        // MDI windows. Distinct from Show-Related (which goes child to
        // parent via the row's foreign-key columns); these commands
        // operate in the opposite direction.
        //
        // On Enter-Child, DbDo finds every other table that has a
        // column matching the current table's primary-key name (the
        // dbDot convention <singular>_id), plus any maps-based and
        // two-hop relations. If exactly one target exists it opens
        // directly; if several, the user picks from a listbox.
        //
        // The chosen related view opens in a NEW MDI child (or an
        // existing child showing the same table + WHERE is reactivated)
        // via openDrillChild, following the app's "Open = new window"
        // model. Each drilled child stores its caller window and row
        // (frmDrillCaller / iDrillCallerRow), so Exit-Child returns to
        // that window on that row and Exit-to-Root walks the chain back
        // to the first window. Closing a database clears a window's
        // drill linkage (clearDrillStack).
        // =====================================================================

        // Given a table name, compute the actual primary-key column
        // name. Schema-truth FIRST (via db.actualPrimaryKey, which
        // reads PRAGMA table_info on SQLite or the ADOX Keys
        // collection on Access). If schema lookup returns nothing,
        // fall back to the dbDot naming convention as a heuristic.
        //
        // The schema-first approach matters because English-plural
        // rules are irregular: "categories" -> "category_id" (not
        // "categorie_id"), "cities" -> "city_id" (not "citie_id"),
        // "people" -> "person_id" (not derivable at all from the
        // table name). Reading the real metadata avoids enumerating
        // every irregular plural rule.
        private string computePrimaryKeyColumn(string sTable, List<string> lCols)
        {
            if (string.IsNullOrEmpty(sTable)) return null;
            // Schema-truth first: ask the database what the PK is.
            try
            {
                string sFromSchema = db.actualPrimaryKey(sTable);
                if (!string.IsNullOrEmpty(sFromSchema)) return sFromSchema;
            }
            catch { /* fall through to heuristic */ }

            // Heuristic fallback for providers that expose neither
            // PRAGMA nor ADOX Keys reliably. Tries the dbDot naming
            // conventions in priority order.
            string sLowerTable = sTable.ToLowerInvariant();
            // English plural -> singular: -ies -> -y, -ses/-xes/-ches/
            // -shes -> drop -es, plain -s -> drop -s. Not exhaustive
            // (no "people" -> "person") but covers the common cases
            // when the schema lookup is unavailable.
            string sSingular = sLowerTable;
            if (sLowerTable.EndsWith("ies") && sLowerTable.Length > 3)
                sSingular = sLowerTable.Substring(0, sLowerTable.Length - 3) + "y";
            else if (sLowerTable.EndsWith("ses") || sLowerTable.EndsWith("xes")
                  || sLowerTable.EndsWith("ches") || sLowerTable.EndsWith("shes"))
                sSingular = sLowerTable.Substring(0, sLowerTable.Length - 2);
            else if (sLowerTable.EndsWith("s") && !sLowerTable.EndsWith("ss") && sLowerTable.Length > 1)
                sSingular = sLowerTable.Substring(0, sLowerTable.Length - 1);

            string sPkSingular = sSingular + Metadata.PrimaryKeySuffix;
            foreach (string sCol in lCols)
            {
                if (sCol.ToLowerInvariant() == sPkSingular) return sCol;
            }
            // Bare <table>_id (no plural stripping).
            string sPkBare = sLowerTable + Metadata.PrimaryKeySuffix;
            foreach (string sCol in lCols)
            {
                if (sCol.ToLowerInvariant() == sPkBare) return sCol;
            }
            // Last resort: a column named 'id'.
            foreach (string sCol in lCols)
            {
                if (sCol.ToLowerInvariant() == "id") return sCol;
            }
            return null;
        }

        // Build the ADO Filter expression for "<column> = <value>".
        // Strings get single-quoted (with embedded quotes doubled);
        // anything that parses as a number is left bare. Empty values
        // produce "<column> IS NULL".
        private string buildFkFilter(string sColumn, string sValue)
        {
            if (string.IsNullOrEmpty(sValue)) return sColumn + " IS NULL";
            double dN;
            if (double.TryParse(sValue, System.Globalization.NumberStyles.Any,
                    System.Globalization.CultureInfo.InvariantCulture, out dN))
                return sColumn + " = " + sValue;
            // Quote as string, doubling embedded single quotes.
            return sColumn + " = '" + sValue.Replace("'", "''") + "'";
        }

        // drillDepth: how many caller windows lie between this window
        // and the root (0 on a root window). Reported to the CLI lane.
        private int drillDepth()
        {
            int iDepth = 0;
            DbDoForm frm = this;
            int iGuard = 0;
            while (frm.frmDrillCaller != null && !frm.frmDrillCaller.IsDisposed && iGuard++ < 256)
            { iDepth++; frm = frm.frmDrillCaller; }
            return iDepth;
        }

        // focusOwnRow: put keyboard/screen-reader focus on this window's
        // grid and ensure the ADO cursor's current row carries the
        // selection, so the screen reader reads the right row on arrival
        // or reactivation.
        public void focusOwnRow()
        {
            try
            {
                if (grid == null) return;
                grid.Focus();
                if (db == null || !db.hasRecordset() || db.recordCount == 0) return;
                int iPos = db.absolutePosition;
                if (iPos < 1) iPos = 1;
                int iIndex = iPos - 1;
                if (iIndex < 0 || iIndex >= grid.VirtualListSize) return;
                try
                {
                    grid.SelectedIndices.Clear();
                    grid.SelectedIndices.Add(iIndex);
                    grid.EnsureVisible(iIndex);
                    grid.FocusedItem = grid.Items[iIndex];
                    grid.selectAndFocusNative(iIndex);
                }
                catch { }
            }
            catch { }
        }

        // restoreRow: position this window on a specific 1-based row and
        // refresh, so a returning Exit-Child lands the caller on the row
        // the user drilled from rather than row 1.
        public void restoreRow(int iRow)
        {
            try
            {
                if (db == null || !db.hasRecordset() || db.recordCount == 0) return;
                if (iRow < 1) iRow = 1;
                if (iRow > db.recordCount) iRow = db.recordCount;
                try { db.absolutePosition = iRow; } catch { }
                invokeRefresh();
                focusOwnRow();
            }
            catch { }
        }

        // openDrillChild: open the chosen related view in a NEW MDI child
        // on the same database file -- or, if a child is already showing
        // that exact (table, WHERE), reactivate it instead of opening a
        // duplicate. The new child records this window and row as its
        // caller so Exit-Child can return here. An empty related view is
        // not left on screen: the child is closed and focus stays put.
        private void openDrillChild(string sTargetTable, string sWhereSql)
        {
            DbDoFrame frame = mdiFrame();
            if (frame == null) return;
            string sFile = "";
            try { sFile = db.filePath ?? ""; } catch { }
            string sWhere = sWhereSql ?? "";

            // Capture the caller row so Exit-Child can restore it.
            syncAdoCursorToSelection();
            int iCallerRow = 0;
            try { iCallerRow = db.absolutePosition; } catch { }

            // Reactivate an existing child already showing this exact
            // (file, table, WHERE), rather than stacking duplicates.
            DbDoForm frmExisting = frame.findDrillChild(sFile, sTargetTable, sWhere, this);
            if (frmExisting != null)
            {
                try { DbDoLog.write("Drill: reactivating existing window for '" + sTargetTable + "'."); } catch { }
                frmExisting.frmDrillCaller = this;
                frmExisting.iDrillCallerRow = iCallerRow;
                try { frmExisting.Activate(); } catch { }
                frmExisting.focusOwnRow();
                LiveRegion.say(sTargetTable + ": already open");
                return;
            }

            // Open a fresh child on the same file, then the filtered view
            // (its own manager -- one manager per window, as Open Table).
            DbDoForm frmChild = new DbDoForm(Program.UiMode.Gui);
            frmChild.MdiParent = frame;
            try
            {
                if (!string.IsNullOrEmpty(sFile)) frmChild.Db.openDatabase(sFile, null, false);
                frmChild.Db.selectTableFiltered(sTargetTable, sWhere);
            }
            catch (Exception ex)
            {
                try { frmChild.Close(); } catch { }
                try { DbDoLog.write("Drill: could not open related table '" + sTargetTable + "': " + ex.Message); } catch { }
                ErrorDialog.show(this, "Enter Child", "Could not open related table: " + ex.Message);
                return;
            }
            frmChild.frmDrillCaller = this;
            frmChild.iDrillCallerRow = iCallerRow;
            frmChild.sDrillTable = sTargetTable;
            frmChild.sDrillWhere = sWhere;
            frmChild.invokeRefresh();
            frmChild.Show();
            frmChild.Activate();

            int iCount = 0;
            try { iCount = frmChild.Db.recordCount; } catch { }
            if (iCount == 0)
            {
                // Empty related view: don't strand the user in a blank
                // window. Close the child and stay on this row.
                try { DbDoLog.write("Drill: no related records in '" + sTargetTable + "'; closing child, staying."); } catch { }
                try { frmChild.Close(); } catch { }
                try { this.Activate(); } catch { }
                focusOwnRow();
                LiveRegion.say("No related records in " + sTargetTable + "; staying here");
                return;
            }
            try { DbDoLog.write("Drill: opened window for '" + sTargetTable + "' (" + iCount + " rows)."); } catch { }
            frmChild.focusOwnRow();
            LiveRegion.say(sTargetTable + ": " + Str.plural("related record", iCount));
        }

        // finishDrillArrival: shared landing logic for every drill
        // kind. Announces where the user is and how many related
        // records the view holds; when the view is EMPTY, returns to
        // the parent row automatically (an empty grid with focus
        // nowhere useful is exactly the confusion this prevents).
        private void finishDrillArrival(string sTargetTable)
        {
            // Quiesce the virtual list before any repositioning: with
            // size 0 the ListView cannot request items against the
            // old column set while the recordset has already moved on.
            // updateGrid (via invokeRefresh) rebuilds columns and then
            // sets the correct size.
            try { if (grid != null) grid.VirtualListSize = 0; } catch { }
            try { db.moveFirst(); } catch { }
            invokeRefresh();
            int iCount = 0;
            try { iCount = db.recordCount; } catch { }
            if (iCount == 0)
            {
                LiveRegion.say("No related records in " + sTargetTable + "; returning");
                recExitChildClicked(null, null);
                return;
            }
            try { if (grid != null) grid.Focus(); } catch { }
            LiveRegion.say(sTargetTable + ": " + Str.plural("related record", iCount));
        }

        // syncAdoCursorToSelection: belt-and-braces companion to the
        // restore-after-read invariant in gridRetrieveVirtualItem.
        // Row-identity-critical commands call this first, so even if
        // some paint path slips past the invariant, the command acts
        // on the visually selected row.
        private void syncAdoCursorToSelection()
        {
            try
            {
                if (db == null || !db.hasRecordset()) return;
                if (grid == null || grid.SelectedIndices.Count == 0) return;
                int iPos = grid.SelectedIndices[0] + 1;
                if (iPos >= 1 && iPos <= db.recordCount && db.absolutePosition != iPos)
                {
                    bSuppressCellChanged = true;
                    try { db.absolutePosition = iPos; }
                    finally { bSuppressCellChanged = false; }
                }
            }
            catch { }
        }

        private void recEnterChildClicked(object sender, EventArgs evArgs)
        {
            syncAdoCursorToSelection();
            if (db == null || !db.hasRecordset()) return;
            if (db.eof || db.bof)
            {
                // The grid can show a focused row while the ADO cursor
                // sits at EOF/BOF (after certain filter or refresh
                // paths). Resync from the virtual row before bailing.
                if (db.recordCount > 0 && iVirtualRow >= 1 && iVirtualRow <= db.recordCount)
                {
                    try { db.absolutePosition = iVirtualRow; } catch { }
                }
                if (db.eof || db.bof)
                {
                    MessageBox.Show(this, "No current row to drill from.",
                        "Enter Child", MessageBoxButtons.OK, MessageBoxIcon.Information);
                    return;
                }
            }

            string sParentTable = db.currentTable ?? "";
            if (string.IsNullOrEmpty(sParentTable)) return;

            // Compute the parent's primary-key column.
            List<string> lParentCols = db.getFieldNames();
            string sParentPk = computePrimaryKeyColumn(sParentTable, lParentCols);
            if (string.IsNullOrEmpty(sParentPk))
            {
                MessageBox.Show(this,
                    "Cannot determine the primary-key column for '" + sParentTable + "'.\n\n"
                    + "Enter-Child uses the convention '<table>_id' (or 'id') for the\n"
                    + "primary key. The current table has no column matching this pattern.",
                    "Enter Child", MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }

            string sParentPkValue;
            try { sParentPkValue = db.getFieldValue(sParentPk) ?? ""; }
            catch { sParentPkValue = ""; }
            if (string.IsNullOrEmpty(sParentPkValue))
            {
                MessageBox.Show(this,
                    "The current row has no value for '" + sParentPk + "'.\n\n"
                    + "Enter-Child requires the parent row to have a primary-key value.",
                    "Enter Child", MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }

            // Find every other table that has a column named the same as
            // the parent's PK column -- those are the candidate children.
            // Views are excluded; you drill into base tables only.
            List<string> lAllTables = db.getTableNames();
            List<string> lChildren = new List<string>();
            foreach (string sCandidate in lAllTables)
            {
                if (string.Equals(sCandidate, sParentTable, StringComparison.OrdinalIgnoreCase))
                    continue;
                List<string> lCols = db.getColumnsOfTable(sCandidate);
                foreach (string sCol in lCols)
                {
                    if (string.Equals(sCol, sParentPk, StringComparison.OrdinalIgnoreCase))
                    {
                        lChildren.Add(sCandidate);
                        break;
                    }
                }
            }
            lChildren.Sort(StringComparer.OrdinalIgnoreCase);

            // Maps targets: when the database has a maps table and the
            // current row has a prm identity, every distinct (kind,
            // other-table, direction) group becomes a drill choice,
            // labeled "<table> via <kind>" -- with "(incoming)" marking
            // relations where this record is the OBJECT. So on a
            // contact the picker offers "events via presents (12
            // records)"; on an event, "contacts via presents
            // (incoming, 3 records)" and "locations via located_at
            // (1 record)".
            const int c_iMapsDrillCap = 200;
            List<string> lChoices = new List<string>(lChildren);
            Dictionary<string, string[]> dMapsChoices = new Dictionary<string, string[]>();
            Dictionary<string, string[]> dTwoHopChoices = new Dictionary<string, string[]>();
            string sPrmValue = sCurrentPrmValue();
            DbDoLog.write("Enter Child: table=" + sParentTable + " pk=" + sParentPk
                + "=" + sParentPkValue + " fkChildren=" + lChildren.Count
                + " prm=" + (string.IsNullOrEmpty(sPrmValue) ? "(none)" : "present")
                + " maps=" + (db.hasMapsTable() ? "yes" : "no"));
            if (!string.IsNullOrEmpty(sPrmValue) && db.hasMapsTable())
            {
                List<string[]> lRelations = db.lMapsRelations(sParentTable, sPrmValue, c_iMapsDrillCap);
                DbDoLog.write("Enter Child: " + lRelations.Count + " maps relations found");
                Dictionary<string, int> dCounts = new Dictionary<string, int>();
                List<string> lOrder = new List<string>();
                foreach (string[] aRel in lRelations)
                {
                    string sKey = aRel[0] + "\x01" + aRel[1] + "\x01" + aRel[3];
                    if (!dCounts.ContainsKey(sKey)) { dCounts[sKey] = 0; lOrder.Add(sKey); }
                    dCounts[sKey]++;
                }
                // Label every maps relation as "<table> via <kind>",
                // with " incoming" added when this record is the OBJECT
                // of the relation. The kind is useful orientation -- it
                // names HOW the tables relate ("events via presents",
                // "contacts via presents incoming") -- so it is always
                // shown, not only when needed to disambiguate. The
                // dMapsChoices guard still drops any exact duplicate.
                foreach (string sKey in lOrder)
                {
                    string[] aParts = sKey.Split('\x01');
                    string sKind = aParts[0], sOther = aParts[1], sDir = aParts[2];
                    string sLabel = sOther + " via " + sKind
                        + ((sDir == "object") ? " incoming" : "")
                        + " (" + dCounts[sKey] + ")";
                    if (!dMapsChoices.ContainsKey(sLabel))
                    {
                        dMapsChoices[sLabel] = new string[] { sKind, sOther, sDir };
                        lChoices.Add(sLabel);
                    }
                }

                // Two-hop targets: records related THROUGH an
                // intermediate -- a contact's locations via the events
                // they present, a location's contacts via the events
                // held there. Skip a target table already offered as a
                // direct relation; the direct view is the closer one.
                List<string[]> lTwoHop = db.lMapsTwoHop(sParentTable, sPrmValue, 500);
                Dictionary<string, int> dHopCounts = new Dictionary<string, int>();
                List<string> lHopOrder = new List<string>();
                foreach (string[] aHop in lTwoHop)
                {
                    string sKey = aHop[0] + "\x01" + aHop[1];
                    if (!dHopCounts.ContainsKey(sKey)) { dHopCounts[sKey] = 0; lHopOrder.Add(sKey); }
                    dHopCounts[sKey]++;
                }
                foreach (string sKey in lHopOrder)
                {
                    string[] aParts = sKey.Split('\x01');
                    string sVia = aParts[0], sTarget = aParts[1];
                    bool bAlreadyDirect = false;
                    foreach (string[] aSel in dMapsChoices.Values)
                        if (string.Equals(aSel[1], sTarget, StringComparison.OrdinalIgnoreCase))
                        { bAlreadyDirect = true; break; }
                    if (bAlreadyDirect) continue;
                    // Always name the intermediate as "<table> via
                    // <intermediate>", matching the maps relations above:
                    // the path is the useful orientation, so it is shown
                    // every time, not only to break a collision.
                    string sLabel = sTarget + " via " + sVia + " (" + dHopCounts[sKey] + ")";
                    if (!dTwoHopChoices.ContainsKey(sLabel))
                    {
                        dTwoHopChoices[sLabel] = new string[] { sVia, sTarget };
                        lChoices.Add(sLabel);
                    }
                }
            }

            if (lChoices.Count == 0)
            {
                // Self-diagnosing empty message: each line names a
                // requirement and whether THIS row met it, plus the
                // database file actually open -- so a stale file or a
                // schema mismatch is visible in the dialog itself.
                string sDbPath = "";
                try { sDbPath = db.filePath ?? ""; } catch { }
                // Presented through ErrorDialog so the diagnostics can
                // be copied (Alt+C) and pasted for debugging verbatim.
                ErrorDialog.show(this, "Enter Child",
                    "No related tables found for this row.\r\n\r\n"
                    + "Database file: " + (string.IsNullOrEmpty(sDbPath) ? "(unknown)" : sDbPath) + "\r\n"
                    + "Table: " + sParentTable + "; primary key " + sParentPk + " = " + sParentPkValue + "\r\n"
                    + "Tables referencing " + sParentPk + ": none\r\n"
                    + "maps table present: " + (db.hasMapsTable() ? "yes" : "NO") + "\r\n"
                    + "This row's prm value: " + (string.IsNullOrEmpty(sPrmValue) ? "MISSING" : sPrmValue) + "\r\n"
                    + "maps rows touching this record: 0\r\n\r\n"
                    + "If the database file above is not the one you expect, open the\r\n"
                    + "intended file; DbDo reopens the last file used.");
                return;
            }

            string sChosen;
            if (lChoices.Count == 1)
            {
                sChosen = lChoices[0];
            }
            else
            {
                sChosen = promptListChoice("Enter Child",
                    "Choose a related table to drill into:", lChoices, lChoices[0]);
                if (string.IsNullOrEmpty(sChosen)) return;
            }

            // No same-window stack push here: the drill opens an MDI
            // child, and that child records this window + row as its
            // caller (see openDrillChild) so Exit-Child can return.

            string[] aMapsSel;
            string[] aTwoHopSel;
            dMapsChoices.TryGetValue(sChosen, out aMapsSel);
            dTwoHopChoices.TryGetValue(sChosen, out aTwoHopSel);
            try
            {
                if (aTwoHopSel != null)
                {
                    // Two-hop drill: the target table opens through
                    // selectTableFiltered with an IN-subquery WHERE --
                    // maps joined to maps through inline derived
                    // edge tables (both directions of every map row),
                    // landing on the target prm set. Single-base-table
                    // SELECT, so the view stays updatable; no row cap
                    // and no client-side Filter involved.
                    string sVia = aTwoHopSel[0], sTarget = aTwoHopSel[1];
                    string sEdges = "(SELECT tbl1 ft, prm1 fu, tbl2 tt, prm2 tu FROM maps"
                        + " UNION ALL SELECT tbl2, prm2, tbl1, prm1 FROM maps)";
                    string sWhere = db.primeColumnFor(sTarget) + " IN (SELECT e2.tu FROM " + sEdges + " e1"
                        + " JOIN " + sEdges + " e2 ON e2.ft = e1.tt AND e2.fu = e1.tu"
                        + " WHERE e1.ft = " + DbDoManager.sQuoteSqlLiteral(sParentTable)
                        + " AND e1.fu = " + DbDoManager.sQuoteSqlLiteral(sPrmValue)
                        + " AND e1.tt = " + DbDoManager.sQuoteSqlLiteral(sVia)
                        + " AND e2.tt = " + DbDoManager.sQuoteSqlLiteral(sTarget)
                        + " AND NOT (e2.tt = " + DbDoManager.sQuoteSqlLiteral(sParentTable)
                        + " AND e2.tu = " + DbDoManager.sQuoteSqlLiteral(sPrmValue) + "))";
                    openDrillChild(sTarget, sWhere);
                }
                else if (aMapsSel != null)
                {
                    // Maps drill: the target table opens through
                    // selectTableFiltered with the IN-subquery this
                    // architecture was designed around -- the WHERE
                    // selects the prm values on the other side of the
                    // matching map rows. Single-base-table SELECT, so
                    // the related view stays UPDATABLE; the previous
                    // approach (ADO client-side Filter as an OR
                    // chain) is gone, along with its row cap.
                    string sKind = aMapsSel[0], sOther = aMapsSel[1], sDir = aMapsSel[2];
                    string sPrimeCol = db.primeColumnFor(sOther);
                    string sWhere = (sDir == "subject")
                        ? sPrimeCol + " IN (SELECT prm2 FROM maps WHERE tbl1 = "
                          + DbDoManager.sQuoteSqlLiteral(sParentTable)
                          + " AND prm1 = " + DbDoManager.sQuoteSqlLiteral(sPrmValue)
                          + " AND kind = " + DbDoManager.sQuoteSqlLiteral(sKind)
                          + " AND tbl2 = " + DbDoManager.sQuoteSqlLiteral(sOther) + ")"
                        : sPrimeCol + " IN (SELECT prm1 FROM maps WHERE tbl2 = "
                          + DbDoManager.sQuoteSqlLiteral(sParentTable)
                          + " AND prm2 = " + DbDoManager.sQuoteSqlLiteral(sPrmValue)
                          + " AND kind = " + DbDoManager.sQuoteSqlLiteral(sKind)
                          + " AND tbl1 = " + DbDoManager.sQuoteSqlLiteral(sOther) + ")";
                    openDrillChild(sOther, sWhere);
                }
                else
                {
                    // Foreign-key drill: the same selectTableFiltered
                    // mechanism, with the FK equality as the WHERE
                    // (buildFkFilter emits valid SQL: numeric values
                    // bare, strings quoted with doubled apostrophes).
                    string sFkFilter = buildFkFilter(sParentPk, sParentPkValue);
                    openDrillChild(sChosen, sFkFilter);
                }
            }
            catch (Exception ex)
            {
                ErrorDialog.show(this, "Enter Child", "Could not open related table: " + ex.Message);
            }
        }

        private void recExitChildClicked(object sender, EventArgs evArgs)
        {
            // Window-based exit: return to the window this related view
            // was drilled in from, on the row that was focused there.
            DbDoForm frmCaller = (frmDrillCaller != null && !frmDrillCaller.IsDisposed) ? frmDrillCaller : null;
            if (frmCaller == null)
            {
                MessageBox.Show(this,
                    "Nothing to exit -- this window was not opened by Enter-Child.\n\n"
                    + "Exit-Child returns to the window a related view was drilled in from.",
                    "Exit Child", MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }
            int iRow = iDrillCallerRow;
            try { DbDoLog.write("Exit Child: reactivating caller window at row " + iRow + "."); } catch { }
            try { frmCaller.Activate(); } catch { }
            frmCaller.restoreRow(iRow);
        }

        // recExitChildToRootClicked (Alt+Home): walk the caller chain
        // back to the first (root) window of the drill and activate it
        // on the row the chain started from. Alt+Home "go all
        // the way back to the root" generalizes here from folder
        // hierarchy to drill windows.
        private void recExitChildToRootClicked(object sender, EventArgs evArgs)
        {
            if (frmDrillCaller == null || frmDrillCaller.IsDisposed)
            {
                MessageBox.Show(this,
                    "Already at the root -- this window was not opened by Enter-Child.",
                    "Exit Child to Root", MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }
            DbDoForm frmRoot = this;
            int iRow = -1;
            int iLevels = 0;
            int iGuard = 0;
            while (frmRoot.frmDrillCaller != null && !frmRoot.frmDrillCaller.IsDisposed && iGuard++ < 256)
            {
                iRow = frmRoot.iDrillCallerRow;
                frmRoot = frmRoot.frmDrillCaller;
                iLevels++;
            }
            try { DbDoLog.write("Exit to Root: activating root window, " + iLevels + " level(s) up."); } catch { }
            try { frmRoot.Activate(); } catch { }
            if (iRow >= 1) frmRoot.restoreRow(iRow);
            LiveRegion.say("Returned to root (" + iLevels + " level" + (iLevels == 1 ? "" : "s") + ")");
        }

        // =====================================================================
        // Update-Field: replace values across rows in a chosen column.
        // Asks for column, find string, replace string, scope (current
        // row, filtered rows, or all rows). Logs every change.
        //
        // Implemented as ADO recordset iteration with field assignment;
        // does not generate SQL UPDATE. This means it goes through the
        // same update triggers as a Set-Record edit.
        // =====================================================================
        // recUpdateColumnClicked: substring find-and-replace within
        // the current virtual column, applied to all visible rows
        // (i.e., respects the active filter and sort). Prompts for
        // a search text and a replacement text via a small LBC dialog
        // with a Case-Sensitive checkbox and a Dry-Run checkbox.
        // Result message reports the count of cells affected.
        //
        // Scope clarification: this command operates ONLY on the
        // currently filtered rows. To replace across all rows, the
        // user should clear the filter first (Alt+Shift+F, Alt+C).
        //
        // For regex replacement, see recRegexReplaceClicked (bound
        // to Ctrl+Shift+R).
        private void recUpdateColumnClicked(object sender, EventArgs evArgs)
        {
            recReplaceCommon(false);
        }

        // recRegexReplaceClicked: .NET-regex find-and-replace within
        // the current virtual column, applied to all visible rows.
        // Identical UX to Update Column but interprets the search
        // text as a regex pattern and supports back-references in
        // the replacement ($1, $2, etc.).
        private void recRegexReplaceClicked(object sender, EventArgs evArgs)
        {
            recReplaceCommon(true);
        }

        // recReplaceCommon: shared implementation for Update Column
        // and Regex Replace. The only difference is whether the
        // search text is interpreted as a literal substring or a
        // .NET regex pattern.
        private void recReplaceCommon(bool bIsRegex)
        {
            if (db == null || !db.hasRecordset())
            {
                LiveRegion.sayForced("No database open.");
                return;
            }
            if (db.readOnly)
            {
                LiveRegion.sayForced("Database is read-only. Press Alt+Z to toggle read-only off, then try again.");
                return;
            }
            if (db.currentIsView)
            {
                MessageBox.Show(this, "Cannot update cells of a view (read-only).",
                    bIsRegex ? "Regex Replace" : "Replace Column",
                    MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }
            string sColumn = currentVirtualColumnName();
            if (string.IsNullOrEmpty(sColumn))
            {
                LiveRegion.sayForced("No virtual column selected.");
                return;
            }

            string sTitle = bIsRegex ? "Regex Replace" : "Replace Column";
            string sSearchLabel = bIsRegex ? "Regex pattern" : "Find text";

            // Target scope (data-changing command policy): with no
            // marks present, the current record alone is the target;
            // with marks present, the user chooses Current, Marked,
            // or Cancel -- which doubles as the confirmation prompt.
            // (Before v1.0.111 the replace family spanned every
            // filtered row; the scope model supersedes that.)
            ScopeChoice scope = promptScope(sTitle);
            if (scope == ScopeChoice.Cancel) return;

            using (LbcDialog dlg = new LbcDialog(sTitle + " (column: " + sColumn + ")", this))
            {
                TextBox tbFind = dlg.addInputBox(sSearchLabel + ":",
                    SearchHistory.lastText(SearchHistory.SectionReplace));
                TextBox tbRepl = dlg.addInputBox("Replace with"
                    + (bIsRegex ? " (use $1, $2 for groups)" : "")
                    + ":", SearchHistory.lastText(SearchHistory.SectionReplaceWith));
                // Replace Column is substring and case-insensitive by
                // definition (v1.0.108 centralization); only the regex
                // flavor offers a case choice.
                CheckBox cbCase = bIsRegex
                    ? dlg.addCheckBox("Case-&sensitive", false, null)
                    : null;
                CheckBox cbDry  = dlg.addCheckBox("&Dry run (count only, no changes)", false,
                    "Run the replacement but do not write changes. Useful for sanity-checking how many cells would be affected before committing.");
                string sBtn = dlg.runWithButtons(new string[] { "OK", "Cancel" });
                if (!string.Equals(sBtn, "OK", StringComparison.OrdinalIgnoreCase)) return;

                string sFind = tbFind.Text ?? "";
                string sRepl = tbRepl.Text ?? "";
                if (sFind.Length == 0)
                {
                    LiveRegion.sayForced("Find text empty. Nothing to do.");
                    return;
                }
                bool bCase = (cbCase != null) && cbCase.Checked;
                bool bDry  = cbDry.Checked;
                // Like every search command, the inputs persist in
                // DbDo.inix for prefill and cross-session recall.
                SearchHistory.record(SearchHistory.SectionReplace, sFind, bCase);
                if (sRepl.Length > 0)
                    SearchHistory.record(SearchHistory.SectionReplaceWith, sRepl, false);

                int iChanged = 0;
                int iScanned = 0;
                try
                {
                    System.Text.RegularExpressions.Regex regex = null;
                    if (bIsRegex)
                    {
                        System.Text.RegularExpressions.RegexOptions opts =
                            System.Text.RegularExpressions.RegexOptions.None;
                        if (!bCase) opts |= System.Text.RegularExpressions.RegexOptions.IgnoreCase;
                        regex = new System.Text.RegularExpressions.Regex(sFind, opts);
                    }

                    // Scope (v1.0.108 centralization): Replace Column
                    // works the db cursor's column only; Regex Replace
                    // works ALL display fields of every record. The
                    // dialog title named the cursor column for the
                    // former; the latter iterates lScanFields below.
                    List<string> lScanFields = new List<string>();
                    if (bIsRegex) lScanFields.AddRange(db.getDisplayFieldNames());
                    else lScanFields.Add(sColumn);

                    int iSavePos = db.absolutePosition;
                    db.moveFirst();
                    while (!db.eof)
                    {
                        // Scope gate: skip rows outside the target set.
                        if (scope == ScopeChoice.Current
                            && db.absolutePosition != iSavePos)
                        { db.moveNext(); continue; }
                        if (scope == ScopeChoice.Marked
                            && !isMarkedTrue(db.getFieldValue(Metadata.MarkedColumn)))
                        { db.moveNext(); continue; }
                        iScanned++;
                        bool bRowChanged = false;
                        foreach (string sScanCol in lScanFields)
                        {
                            string sCur = db.getFieldValue(sScanCol) ?? "";
                            string sNew;
                            bool bMatch;
                            if (bIsRegex)
                            {
                                bMatch = regex.IsMatch(sCur);
                                sNew = bMatch ? regex.Replace(sCur, sRepl) : sCur;
                            }
                            else
                            {
                                bMatch = sCur.IndexOf(sFind, StringComparison.OrdinalIgnoreCase) >= 0;
                                sNew = bMatch ? stringReplace(sCur, sFind, sRepl, StringComparison.OrdinalIgnoreCase) : sCur;
                            }
                            if (bMatch && sNew != sCur)
                            {
                                iChanged++;
                                if (!bDry)
                                {
                                    db.setFieldValue(sScanCol, sNew);
                                    bRowChanged = true;
                                }
                            }
                        }
                        if (bRowChanged) db.update();
                        db.moveNext();
                    }
                    if (iSavePos >= 0) db.absolutePosition = iSavePos;
                    invokeRefresh();

                    string sResult = (bDry ? "Dry run: " : "")
                        + iChanged + " of " + iScanned + " cells "
                        + (bDry ? "would be" : "were")
                        + " changed.";
                    LiveRegion.sayForced(sResult);
                    MessageBox.Show(this, sResult, sTitle,
                        MessageBoxButtons.OK, MessageBoxIcon.Information);
                }
                catch (ArgumentException exRx)
                {
                    // ArgumentException covers regex parse failures
                    // in .NET Framework 4.8 (RegexParseException was
                    // not added until .NET 7).
                    ErrorDialog.show(this, sTitle, "Invalid regex: " + exRx.Message);
                }
                catch (Exception ex)
                {
                    ErrorDialog.show(this, sTitle, ex.Message);
                }
            }
        }

        // stringReplace: case-aware substring replace helper. String.
        // Replace doesn't take a StringComparison argument until .NET
        // Standard 2.1; on .NET Framework 4.8 we implement it manually.
        private static string stringReplace(string sIn, string sFind, string sRepl, StringComparison sc)
        {
            if (string.IsNullOrEmpty(sFind)) return sIn;
            System.Text.StringBuilder sb = new System.Text.StringBuilder();
            int iStart = 0;
            while (true)
            {
                int i = sIn.IndexOf(sFind, iStart, sc);
                if (i < 0) { sb.Append(sIn.Substring(iStart)); break; }
                sb.Append(sIn.Substring(iStart, i - iStart));
                sb.Append(sRepl);
                iStart = i + sFind.Length;
            }
            return sb.ToString();
        }

        // currentVirtualColumnName: returns the name of the column the
        // virtual cell cursor is currently on, or "" if no virtual
        // column is selected. Falls back to the first visible column
        // if the cursor is off.
        // buildGridContextMenu: the data list's Shift+F10 / Apps-key
        // menu. The design follows the platform guidance: only
        // contextually relevant commands, kept inside the 5-10 item
        // comfort range; every item mirrors an existing command with
        // its shortcut displayed (nothing lives ONLY here); related
        // commands grouped by separators; the default action (Edit
        // Record) first and bold. WinForms positions and dispatches
        // the menu for keyboard (Shift+F10 / Applications key) and
        // mouse alike, and menu mode is natively screen-reader
        // friendly -- arrow keys, mnemonics, and Escape all work.
        private ContextMenuStrip buildGridContextMenu()
        {
            ContextMenuStrip cms = new ContextMenuStrip();
            addContextItem(cms, "&Edit Record...", "Control+E", recSetClicked, true);
            addContextItem(cms, "&New Record...", "Control+N", recNewClicked, false);
            addContextItem(cms, "Copy Record as Ne&w...", "Control+Shift+N", recNewCopyClicked, false);
            addContextItem(cms, "&Delete Record", "Control+D", recRemoveClicked, false);
            cms.Items.Add(new ToolStripSeparator());
            addContextItem(cms, "&Toggle Marked", "Control+Space", recToggleMarkClicked, false);
            addContextItem(cms, "Null &Value", "Control+Shift+Backspace",
                delegate(object o, EventArgs e) { nullCurrentCell(); }, false);
            addContextItem(cms, "Say &Cell", "Shift+C", saySayCell, false);
            cms.Items.Add(new ToolStripSeparator());
            addContextItem(cms, "Enter Child Ta&ble...", "Alt+RightArrow", recEnterChildClicked, false);
            addContextItem(cms, "Table &Properties...", "Alt+Enter", schemaPropertiesClicked, false);
            return cms;
        }

        // addContextItem: one context-menu entry -- label with
        // mnemonic, the mirrored shortcut shown beside it (JAWS
        // reads both), the existing command handler, and bold for
        // the default action.
        private void addContextItem(ContextMenuStrip cms, string sText,
            string sKeyDisplay, EventHandler onClick, bool bDefault)
        {
            ToolStripMenuItem item = new ToolStripMenuItem(sText);
            item.ShortcutKeyDisplayString = sKeyDisplay;
            item.Click += onClick;
            if (bDefault)
                item.Font = new System.Drawing.Font(item.Font, System.Drawing.FontStyle.Bold);
            cms.Items.Add(item);
        }

        // Direct edits of the common non-administrative columns, so
        // the user reaches a single field without opening the full
        // record. Notes is a Markdown memo (multi-line); tags and
        // url are single-line. Each routes through editStandardField.
        private void editNotesClicked(object sender, EventArgs evArgs)
        { editStandardField(Metadata.NotesColumn, "Edit Notes"); }
        private void editTagsClicked(object sender, EventArgs evArgs)
        { editStandardField(Metadata.TagsColumn, "Edit Tags"); }
        private void editUrlClicked(object sender, EventArgs evArgs)
        { editStandardField(Metadata.UrlColumn, "Edit URL"); }

        // editStandardField: edit one named field of the current
        // record in a focused dialog. The widget matches the
        // column's declared type -- a Markdown/memo column gets a
        // multi-line box, anything else a single line. Saves only
        // that field; the edited trigger and look/prm regenerate as
        // usual on update.
        private void editStandardField(string sColumn, string sTitle)
        {
            if (db == null || !db.hasRecordset() || db.eof || db.bof) return;
            if (blockIfReadOnly(sTitle)) return;
            if (!db.hasField(sColumn))
            { LiveRegion.sayForced("This table has no " + sColumn + " column."); return; }
            string sTable = db.currentTable;
            bool bMarkdown = db.isMarkdownColumn(sTable, sColumn);
            bool bMultiline = db.isMultilineColumn(sTable, sColumn);
            string sCurrent = db.getFieldValue(sColumn) ?? "";
            using (LbcDialog dlg = new LbcDialog(sTitle, this))
            {
                TextBox tb;
                string sTip = bMarkdown ? "Markdown text." : null;
                if (bMultiline) tb = dlg.addMemoBox(sColumn + ":", sCurrent, sTip);
                else            tb = dlg.addInputBox(sColumn + ":", sCurrent);
                tb.AccessibleName = sColumn;
                if (!string.Equals(dlg.runWithButtons(new string[] { "OK", "Cancel" }),
                        "OK", StringComparison.OrdinalIgnoreCase))
                    return;
                try
                {
                    db.setFieldValue(sColumn, tb.Text);
                    db.update();
                    invokeRefresh();
                    LiveRegion.sayForced(sColumn + " saved.");
                }
                catch (Exception ex)
                {
                    try { db.cancelUpdate(); } catch { }
                    ErrorDialog.show(this, sTitle, ex, db);
                }
            }
        }

        // sayToggleState: spoken confirmation for a command whose
        // canonical name ends in "Toggle". The feature name (the
        // command name with the trailing "Toggle" removed) is spoken
        // with " On" appended when the new state is on, or with "No "
        // prefixed when off: "Extra Speech On" versus "No Extra
        // Speech". The point is positional -- a screen-reader user
        // hears the distinguishing word first ("No ...") or last
        // ("... On") and need not parse the whole phrase.
        private static void sayToggleState(string sCommandName, bool bOn)
        {
            string sFeature = (sCommandName ?? "").Trim();
            if (sFeature.EndsWith("Toggle", StringComparison.OrdinalIgnoreCase))
                sFeature = sFeature.Substring(0, sFeature.Length - 6).Trim();
            LiveRegion.sayForced(bOn ? sFeature + " On" : "No " + sFeature);
        }

        // blockIfReadOnly: the friendly gate every data-changing
        // command runs first. Returns true (block) when the open
        // recordset is read-only, explaining WHICH layer applies:
        // innate (a view or a query result ADO cannot update --
        // nothing can unlock it) versus the user's safeguard toggle
        // (Alt+Z turns it off).
        private bool blockIfReadOnly(string sCommandName)
        {
            if (db == null || db.readOnly == false) return false;
            if (db.readOnlyInnate || db.currentIsView)
                LiveRegion.sayForced(sCommandName + " is unavailable: this "
                    + (db.currentIsView ? "view" : "query result")
                    + " is read-only by nature, and that cannot be changed. "
                    + "Open the underlying table to make changes.");
            else
                LiveRegion.sayForced(sCommandName + " is unavailable: the read-only "
                    + "safeguard is on. Press Alt+Z to turn it off, then try again.");
            return true;
        }

        // speakableCellText: the spoken form of a cell -- its value,
        // or "null" for SQL NULL versus "blank" for a stored empty
        // string. The distinction is determinable when the asked-for
        // row is the live record under the db cursor; otherwise an
        // empty display defaults to "blank".
        private string speakableCellText(int iRow, int iCol)
        {
            string sValue = virtCellValue(iRow, iCol);
            if (!string.IsNullOrEmpty(sValue)) return sValue;
            bool bNull = false;
            try
            {
                if (db != null && db.absolutePosition == iRow
                    && grid != null && iCol >= 0 && iCol < grid.Columns.Count)
                    bNull = db.isFieldNull(grid.Columns[iCol].Text);
            }
            catch { }
            return bNull ? "null" : "blank";
        }

        // nullCurrentCell: Null Value (Control+Shift+Backspace) in
        // the data list -- write SQL NULL (not the empty string)
        // into the db cursor's cell. Editable fields only; the admin
        // fields are program-maintained.
        private void nullCurrentCell()
        {
            if (db == null || !db.hasRecordset() || db.eof || db.bof) return;
            if (db.readOnly) { LiveRegion.sayForced("Database is read-only."); return; }
            if (db.currentIsView) { LiveRegion.sayForced("Cannot update a view."); return; }
            string sColumn = currentVirtualColumnName();
            if (string.IsNullOrEmpty(sColumn)) return;
            if (!containsIgnoreCase(db.getEditableFieldNames(), sColumn))
            { LiveRegion.sayForced(sColumn + " is program-maintained."); return; }
            try
            {
                db.setFieldNull(sColumn);
                db.update();
                invokeRefresh();
                LiveRegion.sayForced(sColumn + ": null");
            }
            catch (Exception ex)
            {
                try { db.cancelUpdate(); } catch { }
                ErrorDialog.show(this, "Null Value", ex, db);
            }
        }

        private string currentVirtualColumnName()
        {
            if (db == null || !db.hasRecordset()) return "";
            int iCol = iVirtualCol;
            if (iCol < 0) iCol = 0;
            List<string> lCols = db.getFieldNames();
            if (lCols == null || lCols.Count == 0) return "";
            if (iCol >= lCols.Count) iCol = lCols.Count - 1;
            return lCols[iCol];
        }

        // =====================================================================
        // Get-Property: show schema details for the current table:
        // columns and types, indexes, and any inferred foreign-key
        // relationships (columns ending in _id that match another
        // table's name).
        // =====================================================================
        private void schemaPropertiesClicked(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset()) return;
            string sTable = db.currentTable;
            if (string.IsNullOrEmpty(sTable)) return;

            StringBuilder sb = new StringBuilder();
            sb.AppendLine((db.currentIsView ? "View" : "Table") + ": " + sTable);
            sb.AppendLine();

            // Schema documentation embedded as comments in the CREATE
            // statement (--! table lines, --- column lines; see the
            // manager's getSchemaDoc). Shown first: a description is
            // the most orienting fact about a table.
            List<string[]> lsTableDoc;
            List<string[]> lsColumnDocs;
            if (db.getSchemaDoc(sTable, out lsTableDoc, out lsColumnDocs))
            {
                if (lsTableDoc.Count > 0)
                {
                    sb.AppendLine("Documentation:");
                    foreach (string[] aPair in lsTableDoc)
                        sb.AppendLine("  " + (aPair[0].Length > 0
                            ? aPair[0] + ": " + aPair[1] : aPair[1]));
                    sb.AppendLine();
                }
                if (lsColumnDocs.Count > 0)
                {
                    sb.AppendLine("Column documentation:");
                    foreach (string[] aPair in lsColumnDocs)
                        sb.AppendLine("  " + aPair[0] + ": " + aPair[1]);
                    sb.AppendLine();
                }
            }

            // Columns
            sb.AppendLine("Columns:");
            List<string> lDistinct = db.getEditableFieldNames();
            List<string> lMetadata = db.getAdminFieldNames();
            foreach (string sCol in lDistinct)
            {
                int iType = db.getFieldType(sCol);
                int iSize = db.getFieldDefinedSize(sCol);
                sb.AppendLine("  " + sCol
                    + "  [" + db.getFieldTypeName(sCol) + "]"
                    + (iSize > 0 && iSize < 0x7FFFFFFF ? " size=" + iSize : ""));
            }
            if (lMetadata.Count > 0)
            {
                sb.AppendLine();
                sb.AppendLine("metadata columns:");
                foreach (string sCol in lMetadata)
                    sb.AppendLine("  " + sCol + "  [" + db.getFieldTypeName(sCol) + "]");
            }

            // Inferred foreign keys (columns ending in _id, excluding own PK)
            string sOwnPk = sTable + Metadata.PrimaryKeySuffix;
            List<string> lFks = new List<string>();
            foreach (string sCol in db.getFieldNames())
            {
                if (sCol.ToLowerInvariant() == sOwnPk.ToLowerInvariant()) continue;
                if (sCol.ToLowerInvariant().EndsWith(Metadata.PrimaryKeySuffix))
                    lFks.Add(sCol);
            }
            if (lFks.Count > 0)
            {
                sb.AppendLine();
                sb.AppendLine("Inferred foreign keys (by name convention):");
                foreach (string sFk in lFks)
                {
                    string sTarget = sFk.Substring(0, sFk.Length - Metadata.PrimaryKeySuffix.Length);
                    sb.AppendLine("  " + sFk + " -> " + sTarget);
                }
            }

            sb.AppendLine();
            sb.AppendLine("Row count: " + db.recordCount);

            HelpDialog.show(this, "Get-Property: " + sTable, sb.ToString());
        }

        // =====================================================================
        // Select-Column: choose which columns are visible in the
        // ListView. The user edits a comma-separated list of column
        // names in a text box. Each name is validated against the
        // current recordset; unknown names are dropped silently.
        // An empty list reverts to the rule-based default.
        //
        // PowerShell-canonical alias: Select-Object (which in
        // PowerShell takes -Property to pick fields). Persisted
        // per-table for the session via TableSettings.sSelectList.
        // =====================================================================
        private void viewSelectColumnClicked(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset())
            {
                MessageBox.Show(this, "No table is open.", "Choose Visible Columns",
                    MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }
            string sCurrentTable = db.currentTable;
            // Pre-fill: existing select-list if set, otherwise the
            // current effective display list (so the user can edit
            // the default rather than start from blank).
            string sInitial = db.getSelectList(sCurrentTable);
            if (string.IsNullOrEmpty(sInitial))
                sInitial = string.Join(", ", db.getDisplayFieldNames().ToArray());

            string sResult = promptSelectList(sInitial);
            if (sResult == null) return;  // user cancelled

            // setSelectList validates and stores. Empty string
            // clears the override.
            string sStored = db.setSelectList(sCurrentTable, sResult);
            persistCurrentTableState();

            // Compute dropped names so we can tell the user.
            List<string> lRequested = DbDoManager.parseSelectList(sResult);
            List<string> lAccepted = DbDoManager.parseSelectList(sStored);
            List<string> lDropped = new List<string>();
            HashSet<string> hAccepted = new HashSet<string>(lAccepted, StringComparer.OrdinalIgnoreCase);
            foreach (string sName in lRequested)
                if (!hAccepted.Contains(sName)) lDropped.Add(sName);

            invokeRefresh();

            if (lDropped.Count > 0)
            {
                string sMsg = "Dropped (not column names of this table): "
                    + string.Join(", ", lDropped.ToArray());
                LiveRegion.say(sMsg);
                MessageBox.Show(this, sMsg, "Select Column",
                    MessageBoxButtons.OK, MessageBoxIcon.Information);
            }
            else
            {
                LiveRegion.say("Visible columns updated");
            }
        }

        // Modal dialog with a single-line text box pre-filled with
        // the comma-separated column list. OK accepts, Cancel
        // returns null. Empty-string return is meaningful: it
        // clears the user override and reverts to default rules.
        private string promptSelectList(string sInitial)
        {
            using (Form dlg = new LbcForm())
            {
                dlg.Text = "Select-Column (visible columns)";
                dlg.AccessibleName = "Select Column";
                dlg.StartPosition = FormStartPosition.CenterParent;
                dlg.ClientSize = new Size(560, 160);
                dlg.FormBorderStyle = FormBorderStyle.Sizable;
                dlg.MaximizeBox = false;
                dlg.MinimizeBox = false;
                dlg.ShowInTaskbar = false;
                dlg.KeyPreview = true;

                Label lbl = new Label();
                lbl.Text = "Comma-separated list of column names to display "
                         + "(empty clears the override and uses defaults):";
                lbl.Location = new Point(12, 12);
                lbl.Size = new Size(536, 36);
                lbl.AutoSize = false;
                dlg.Controls.Add(lbl);

                TextBox txt = new TextBox();
                txt.Text = sInitial ?? "";
                txt.Location = new Point(12, 56);
                txt.Size = new Size(536, 22);
                txt.AccessibleName = "Comma-separated column names";
                txt.Anchor = AnchorStyles.Top | AnchorStyles.Left | AnchorStyles.Right;
                dlg.Controls.Add(txt);

                Button btnOk = new Button();
                btnOk.Text = "OK";
                btnOk.DialogResult = DialogResult.OK;
                btnOk.Location = new Point(372, 92);
                btnOk.Size = new Size(80, 28);
                btnOk.Anchor = AnchorStyles.Top | AnchorStyles.Right;
                dlg.Controls.Add(btnOk);

                Button btnCancel = new Button();
                btnCancel.Text = "Cancel";
                btnCancel.DialogResult = DialogResult.Cancel;
                btnCancel.Location = new Point(460, 92);
                btnCancel.Size = new Size(88, 28);
                btnCancel.Anchor = AnchorStyles.Top | AnchorStyles.Right;
                dlg.Controls.Add(btnCancel);

                dlg.AcceptButton = btnOk;
                dlg.CancelButton = btnCancel;

                if (dlg.ShowDialog(this) != DialogResult.OK) return null;
                return txt.Text.Trim();
            }
        }
        // =====================================================================

        private string promptListChoice(string sTitle, string sPrompt, List<string> lItems, string sCurrent)
        {
            using (Form dlg = new LbcForm())
            {
                dlg.Text = sTitle;
                dlg.AccessibleName = sTitle;
                dlg.StartPosition = FormStartPosition.CenterParent;
                dlg.ClientSize = new Size(420, 360);
                dlg.FormBorderStyle = FormBorderStyle.Sizable;
                dlg.MaximizeBox = true;
                dlg.MinimizeBox = false;
                dlg.ShowInTaskbar = false;
                dlg.KeyPreview = true;

                Label lbl = new Label();
                lbl.Text = sPrompt;
                lbl.Location = new Point(12, 12);
                lbl.Size = new Size(396, 20);
                dlg.Controls.Add(lbl);

                ListBox lb = new ListBox();
                lb.AccessibleName = sPrompt;
                lb.Location = new Point(12, 36);
                lb.Size = new Size(396, 270);
                lb.Anchor = AnchorStyles.Top | AnchorStyles.Left | AnchorStyles.Right | AnchorStyles.Bottom;
                foreach (string s in lItems) lb.Items.Add(s);
                if (sCurrent != null && lb.Items.Contains(sCurrent)) lb.SelectedItem = sCurrent;
                else if (lb.Items.Count > 0) lb.SelectedIndex = 0;
                lb.DoubleClick += (s, e) => { dlg.DialogResult = DialogResult.OK; dlg.Close(); };
                dlg.Controls.Add(lb);

                Button btnOk = new Button();
                btnOk.Text = "&OK";
                btnOk.DialogResult = DialogResult.OK;
                btnOk.Size = new Size(90, 28);
                btnOk.Location = new Point(218, 320);
                btnOk.Anchor = AnchorStyles.Bottom | AnchorStyles.Right;
                dlg.Controls.Add(btnOk);

                Button btnCancel = new Button();
                btnCancel.Text = "&Cancel";
                btnCancel.DialogResult = DialogResult.Cancel;
                btnCancel.Size = new Size(90, 28);
                btnCancel.Location = new Point(316, 320);
                btnCancel.Anchor = AnchorStyles.Bottom | AnchorStyles.Right;
                dlg.Controls.Add(btnCancel);

                dlg.AcceptButton = btnOk;
                dlg.CancelButton = btnCancel;
                dlg.ActiveControl = lb;

                if (dlg.ShowDialog(this) != DialogResult.OK) return null;
                return lb.SelectedItem as string;
            }
        }

        // Test-Database integrity. Runs PRAGMA integrity_check (SQLite)
        // or a driver-equivalent. The result is "ok" on a healthy
        // database (one line, typically), or a list of corruption
        // findings. We pick the presentation by size:
        //
        //   - Short result (under ~10 lines, under ~400 chars): a
        //     standard MessageBox is sufficient and dismissable with
        //     Enter / Escape / OK.
        //   - Long result: HelpDialog with a read-only multi-line
        //     TextBox and an OK button.
        //
        // This pattern is the project-wide rule: short feedback uses
        // MessageBox, extensive output uses HelpDialog. Both have a
        // dismiss button so the user knows how to close them.
        private void toolsTestClicked(object sender, EventArgs evArgs)
        {
            if (db == null || !db.isOpen()) return;
            try
            {
                StringWriter sbOut = new StringWriter();
                db.invokeSql("PRAGMA integrity_check", sbOut);
                string sResult = sbOut.ToString();
                if (isShortResult(sResult))
                    MessageBox.Show(this, sResult.Trim(), "Test Database",
                        MessageBoxButtons.OK, MessageBoxIcon.Information);
                else
                    HelpDialog.show(this, "Test Database", sResult);
            }
            catch (Exception ex)
            {
                ErrorDialog.show(this, "Test Database", ex.Message);
            }
        }

        // True if a result string is brief enough that a MessageBox
        // suffices. Threshold tuned for typical Windows MessageBox
        // legibility: roughly 10 lines or 400 characters.
        private static bool isShortResult(string sText)
        {
            if (string.IsNullOrEmpty(sText)) return true;
            if (sText.Length > 400) return false;
            int iLines = 0;
            for (int i = 0; i < sText.Length; i++)
                if (sText[i] == '\n') iLines++;
            return iLines < 10;
        }

        // toolsMeasureClicked: Table Summary (Alt+T). Lists the
        // current table's columns in natural (schema-defined) order.
        // Each line packs maximum info: name (type, [constraints]).
        // For screen-reader users, this is the structural overview
        // they reach for when first opening a table or returning to
        // an unfamiliar one. Output goes to the multi-line dialog so
        // it can be reviewed line-by-line.
        //
        // Constraints noted (when available from schema):
        //   - primary key
        //   - not null
        //   - foreign key references (showing target table)
        //   - default value
        //
        // Per the screen-reader-first rule: maximum info per line,
        // never cryptic, but no superfluous words.
        private void toolsMeasureClicked(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset()) return;
            string sTable = db.currentTable;
            if (string.IsNullOrEmpty(sTable)) return;
            StringBuilder sb = new StringBuilder();
            sb.Append("Table: ").Append(sTable).AppendLine();
            sb.AppendLine();
            sb.Append("Records: ").Append(db.recordCount);
            if (db.filter.Length > 0) sb.Append(" (after filter)");
            sb.AppendLine();
            sb.AppendLine();
            sb.AppendLine("Columns (in natural order):");

            // Collect column info. The DbDoManager keeps a list of
            // schema metadata per table; for SQLite this is taken
            // from PRAGMA table_info. We render one line per column.
            try
            {
                List<DbDoManager.SchemaColumn> lCols = db.getSchemaColumns(sTable);
                if (lCols == null || lCols.Count == 0)
                {
                    sb.AppendLine("  (no column metadata available)");
                }
                else
                {
                    foreach (DbDoManager.SchemaColumn sc in lCols)
                    {
                        List<string> lParts = new List<string>();
                        if (!string.IsNullOrEmpty(sc.dataType)) lParts.Add(sc.dataType);
                        if (sc.isPrimaryKey) lParts.Add("primary key");
                        if (sc.notNull) lParts.Add("not null");
                        if (!string.IsNullOrEmpty(sc.foreignKeyRef))
                            lParts.Add("foreign key -> " + sc.foreignKeyRef);
                        if (!string.IsNullOrEmpty(sc.defaultValue))
                            lParts.Add("default " + sc.defaultValue);
                        string sLine = "  " + sc.name;
                        if (lParts.Count > 0)
                            sLine += " (" + string.Join(", ", lParts.ToArray()) + ")";
                        sb.AppendLine(sLine);

                        // If the field has lookup values registered in the
                        // builtin lookups table, list them under the field
                        // (count first, then up to 20 values). Guarded so a
                        // database without a lookups table just shows none.
                        List<string> lLook = null;
                        try { lLook = db.getLookupValues(sTable, sc.name, 200); }
                        catch (Exception exLk)
                        { try { DbDoLog.write("Table Summary lookups for " + sc.name + ": " + exLk.Message); } catch { } }
                        if (lLook != null && lLook.Count > 0)
                        {
                            int iShow = Math.Min(lLook.Count, 20);
                            string sVals = string.Join(", ", lLook.GetRange(0, iShow).ToArray());
                            if (lLook.Count > iShow) sVals += ", ...";
                            sb.Append("      lookups (").Append(lLook.Count).Append("): ").AppendLine(sVals);
                        }
                    }
                }
            }
            catch (Exception ex)
            {
                sb.AppendLine("  (error reading schema: " + ex.Message + ")");
            }
            HelpDialog.show(this, "Table Summary", sb.ToString());
        }

        // New-Chart: produce a frequency bar chart of how often each
        // distinct value appears in one column of the current
        // filtered view. The result is an .xlsx with a Data sheet
        // and a Chart sheet, opened in Excel.
        //
        // No hotkey by default; reached through Tools > New-Chart
        // or the dot prompt's New-Chart command. Sample workflows
        // worth trying with sample.db:
        //   - On enrollments: New-Chart grade           (A, B+, etc.)
        //   - On students:    New-Chart year            (Sophomore...)
        //   - On students:    New-Chart major           (CS, Bio...)
        //   - On teachers:    New-Chart department
        //
        // For meaningful charts, the column should be categorical
        // (a small number of distinct values relative to the row
        // count). Charting a unique-per-row column like a name
        // produces a bar per row with count 1 -- valid output,
        // but not informative. The dialog warns when distinct-value
        // count equals row count.
        // ===================================================================
        // Generate from Grid (Alt+Shift+G): profile the grid's columns by data
        // type, then offer a pick-list of outputs matched to what the data
        // supports. Native outputs (summary statistics, frequency table,
        // cross-tab, Markdown table) always work and show in a memo or a
        // saved file. Chart outputs use Excel (out-of-process COM, so
        // bitness does not matter) and fail gracefully -- pointing back to
        // the native outputs -- when Excel is not installed. Built for the
        // blind data scientist who needs to hand a sighted colleague a
        // meaningful visualization or table.
        // ===================================================================
        private void generateFromGridClicked(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset())
            {
                MessageBox.Show(this, "Open a table first.",
                    "Generate from Grid", MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }
            if (db.recordCount == 0)
            {
                MessageBox.Show(this, "No records in the current filter to work with.",
                    "Generate from Grid", MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }

            List<string> lCols = db.getDisplayFieldNames();
            if (lCols.Count == 0) lCols = db.getFieldNames();
            if (lCols.Count == 0) return;

            // One sweep over the filtered view collects every displayed
            // column's values (cursor saved and restored). This single pass
            // powers every output, so we never walk the data twice.
            Dictionary<string, List<string>> dValues = new Dictionary<string, List<string>>();
            foreach (string sC in lCols) dValues[sC] = new List<string>();
            object bookmarkSaved = null;
            try { bookmarkSaved = db.bookmark; } catch { }
            try
            {
                int iRows = db.recordCount;
                for (int i = 1; i <= iRows; i++)
                {
                    try { db.absolutePosition = i; } catch { continue; }
                    foreach (string sC in lCols)
                    {
                        string sV = "";
                        try { sV = db.getFieldValue(sC) ?? ""; } catch { sV = ""; }
                        dValues[sC].Add(sV);
                    }
                }
            }
            finally { if (bookmarkSaved != null) try { db.bookmark = bookmarkSaved; } catch { } }

            // Classify each column by dominant data type.
            List<string> lNumeric = new List<string>();
            List<string> lDate    = new List<string>();
            List<string> lBoolean = new List<string>();
            List<string> lText    = new List<string>();
            foreach (string sC in lCols)
            {
                List<string> lNonEmpty = new List<string>();
                foreach (string s in dValues[sC])
                    if (!string.IsNullOrEmpty(s) && s.Trim().Length > 0) lNonEmpty.Add(s);
                string sT = detectColumnDominantType(lNonEmpty);
                if (sT == "numeric") lNumeric.Add(sC);
                else if (sT == "date") lDate.Add(sC);
                else if (sT == "boolean") lBoolean.Add(sC);
                else lText.Add(sC);
            }
            try { DbDoLog.write("Generate from Grid: profiled " + lCols.Count + " columns over "
                + db.recordCount + " rows (numeric=" + lNumeric.Count + " date=" + lDate.Count
                + " boolean=" + lBoolean.Count + " text=" + lText.Count + ")."); } catch { }

            // Assemble the applicable output menu (parallel id/label lists).
            List<string> lIds = new List<string>();
            List<string> lLabels = new List<string>();
            lIds.Add("summary_all"); lLabels.Add("Summary statistics of all columns (memo)");
            lIds.Add("freq_table");  lLabels.Add("Frequency table of a column (memo)");
            if (lCols.Count >= 2) { lIds.Add("crosstab"); lLabels.Add("Cross-tab: one column by another (memo)"); }
            lIds.Add("md_table");    lLabels.Add("Markdown table of the grid (save to file)");
            lIds.Add("bar");         lLabels.Add("Bar chart: frequencies of a column (Excel)");
            if (lText.Count > 0)    { lIds.Add("pareto"); lLabels.Add("Pareto chart of a text column (Excel)"); }
            if (lBoolean.Count > 0) { lIds.Add("pie");    lLabels.Add("Pie chart of a boolean column (Excel)"); }
            if (lNumeric.Count > 0) { lIds.Add("histogram"); lLabels.Add("Histogram of a numeric column (Excel)");
                                      lIds.Add("box");        lLabels.Add("Box-and-whisker of a numeric column (Excel)"); }
            if (lNumeric.Count >= 2){ lIds.Add("scatter"); lLabels.Add("Scatter plot: two numeric columns (Excel)"); }
            if (lDate.Count > 0)    { lIds.Add("datechart"); lLabels.Add("Date chart: timeline / by year / by month (Excel)"); }

            string sId = null;
            using (LbcDialog dlg = new LbcDialog("Generate from Grid", this))
            {
                dlg.addLabel("Choose an output. Memo results open in a read-only dialog you");
                dlg.addLabel("can copy from; Markdown and charts are written to files.");
                dlg.addSeparator();
                ListBox lb = dlg.addPickBox("&Output (Enter to produce):", lLabels, lLabels[0],
                    "Options are filtered to what your columns' data types support. Excel charts need Excel; the memo and Markdown outputs do not.");
                if (!dlg.runOkCancel()) return;
                int iIdx = lb.SelectedIndex;
                if (iIdx < 0 || iIdx >= lIds.Count) return;
                sId = lIds[iIdx];
            }
            if (string.IsNullOrEmpty(sId)) return;
            try { DbDoLog.write("Generate from Grid: chose " + sId); } catch { }

            if (sId == "summary_all")
            {
                StringBuilder sb = new StringBuilder();
                foreach (string sC in lCols)
                {
                    sb.Append(buildColumnReportPublic(sC, dValues[sC]));
                    sb.Append("\r\n----------------------------------------\r\n\r\n");
                }
                showInfoDialog("Summary statistics: " + (db.currentTable ?? "table"), sb.ToString());
            }
            else if (sId == "freq_table")
            {
                string sC = pickOneColumn("Frequency Table", "Pick a column to tabulate:", lCols, currentVirtualColumnName());
                if (sC == null) return;
                showInfoDialog("Frequency: " + sC, buildFrequencyReport(sC, dValues[sC]));
            }
            else if (sId == "crosstab")
            {
                string sA = pickOneColumn("Cross-tab", "Pick the ROW column:", lCols, null);
                if (sA == null) return;
                List<string> lOther = new List<string>(lCols); lOther.Remove(sA);
                string sB = pickOneColumn("Cross-tab", "Pick the COLUMN column:", lOther, null);
                if (sB == null) return;
                showInfoDialog("Cross-tab: " + sA + " by " + sB, buildCrosstabReport(sA, dValues[sA], sB, dValues[sB]));
            }
            else if (sId == "md_table")
            {
                saveMarkdownTable(lCols, dValues);
            }
            else if (sId == "bar")
            {
                string sC = pickOneColumn("Bar Chart", "Pick a column to chart frequencies:", lCols, currentVirtualColumnName());
                if (sC == null) return;
                runColumnChart(sC, "frequency");
            }
            else if (sId == "pareto")
            {
                string sC = pickOneColumn("Pareto Chart", "Pick a text column:", lText, null);
                if (sC == null) return;
                runColumnChart(sC, "pareto");
            }
            else if (sId == "pie")
            {
                string sC = pickOneColumn("Pie Chart", "Pick a boolean column:", lBoolean, null);
                if (sC == null) return;
                runColumnChart(sC, "pie");
            }
            else if (sId == "histogram")
            {
                string sC = pickOneColumn("Histogram", "Pick a numeric column:", lNumeric, null);
                if (sC == null) return;
                runColumnChart(sC, "histogram");
            }
            else if (sId == "box")
            {
                string sC = pickOneColumn("Box-and-whisker", "Pick a numeric column:", lNumeric, null);
                if (sC == null) return;
                runColumnChart(sC, "boxwhisker");
            }
            else if (sId == "scatter")
            {
                string sX = pickOneColumn("Scatter Plot", "Pick the X (horizontal) numeric column:", lNumeric, null);
                if (sX == null) return;
                List<string> lYs = new List<string>(lNumeric); lYs.Remove(sX);
                string sY = pickOneColumn("Scatter Plot", "Pick the Y (vertical) numeric column:", lYs, null);
                if (sY == null) return;
                runScatterChart(sX, sY);
            }
            else if (sId == "datechart")
            {
                string sC = pickOneColumn("Date Chart", "Pick a date column:", lDate, null);
                if (sC == null) return;
                string sKind = chooseChartKind("Date Chart: " + sC, "Pick a date view:",
                    new string[] { "Timeline (count by month or day)",
                                   "By year (column chart)",
                                   "By month of year (seasonal pattern)" },
                    new string[] { "timeline", "byyear", "bymonth" });
                if (string.IsNullOrEmpty(sKind)) return;
                runColumnChart(sC, sKind);
            }
        }

        // pickOneColumn: small combo-pick dialog returning the chosen
        // column name, or null if the user canceled or the list was empty.
        private string pickOneColumn(string sTitle, string sPrompt, List<string> lCandidates, string sDefault)
        {
            if (lCandidates == null || lCandidates.Count == 0) return null;
            if (string.IsNullOrEmpty(sDefault) || !lCandidates.Contains(sDefault)) sDefault = lCandidates[0];
            using (LbcDialog dlg = new LbcDialog(sTitle, this))
            {
                dlg.addLabel(sPrompt);
                dlg.addSeparator();
                ComboBox cb = dlg.addComboPickBox("Column:", lCandidates, sDefault, "Pick a column");
                if (!dlg.runOkCancel()) return null;
                string s = (cb.SelectedItem ?? "").ToString();
                return string.IsNullOrEmpty(s) ? null : s;
            }
        }

        // buildFrequencyReport: value / count / percentage table for one
        // column, blanks folded to "blank", sorted by count then value.
        private static string buildFrequencyReport(string sColumn, List<string> lValues)
        {
            int iTotal = (lValues != null) ? lValues.Count : 0;
            Dictionary<string, int> dCount = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
            List<string> lOrder = new List<string>();
            if (lValues != null)
                foreach (string s0 in lValues)
                {
                    string s = (string.IsNullOrEmpty(s0) || s0.Trim().Length == 0) ? "blank" : s0;
                    int c;
                    if (!dCount.TryGetValue(s, out c)) { dCount[s] = 0; lOrder.Add(s); }
                    dCount[s] = dCount[s] + 1;
                }
            lOrder.Sort(delegate(string a, string b)
            {
                int cmp = dCount[b].CompareTo(dCount[a]);
                if (cmp != 0) return cmp;
                return string.Compare(a, b, StringComparison.OrdinalIgnoreCase);
            });
            StringBuilder sb = new StringBuilder();
            sb.Append("Frequency of ").Append(sColumn).Append(" (").Append(iTotal)
              .Append(" rows, ").Append(lOrder.Count).Append(" distinct):\r\n\r\n");
            foreach (string val in lOrder)
            {
                int cnt = dCount[val];
                double pct = (iTotal > 0) ? cnt * 100.0 / iTotal : 0;
                sb.Append("  ").Append(val).Append(": ").Append(cnt)
                  .Append(" (").Append(pct.ToString("0.0")).Append("%)\r\n");
            }
            return sb.ToString();
        }

        // buildCrosstabReport: contingency counts of colA (rows) by colB
        // (columns), linearized one row-value per line (screen readers
        // flatten grids anyway), with column totals and a grand total.
        private static string buildCrosstabReport(string sColA, List<string> lA, string sColB, List<string> lB)
        {
            int n = Math.Min((lA != null) ? lA.Count : 0, (lB != null) ? lB.Count : 0);
            Dictionary<string, Dictionary<string, int>> dCells =
                new Dictionary<string, Dictionary<string, int>>(StringComparer.OrdinalIgnoreCase);
            List<string> lAVals = new List<string>();
            List<string> lBVals = new List<string>();
            HashSet<string> hsA = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
            HashSet<string> hsB = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
            for (int i = 0; i < n; i++)
            {
                string a = (string.IsNullOrEmpty(lA[i]) || lA[i].Trim().Length == 0) ? "blank" : lA[i];
                string b = (string.IsNullOrEmpty(lB[i]) || lB[i].Trim().Length == 0) ? "blank" : lB[i];
                if (hsA.Add(a)) lAVals.Add(a);
                if (hsB.Add(b)) lBVals.Add(b);
                Dictionary<string, int> row;
                if (!dCells.TryGetValue(a, out row)) { row = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase); dCells[a] = row; }
                int c; row[b] = row.TryGetValue(b, out c) ? c + 1 : 1;
            }
            lAVals.Sort(StringComparer.OrdinalIgnoreCase);
            lBVals.Sort(StringComparer.OrdinalIgnoreCase);
            StringBuilder sb = new StringBuilder();
            sb.Append("Cross-tab: ").Append(sColA).Append(" (rows) by ").Append(sColB).Append(" (columns)\r\n\r\n");
            Dictionary<string, int> dColTot = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
            foreach (string a in lAVals)
            {
                Dictionary<string, int> row = dCells[a];
                int rowtot = 0; foreach (int v in row.Values) rowtot += v;
                sb.Append("  ").Append(a).Append(" (total ").Append(rowtot).Append("): ");
                List<string> parts = new List<string>();
                foreach (string b in lBVals)
                {
                    int c; int cv = row.TryGetValue(b, out c) ? c : 0;
                    parts.Add(b + "=" + cv);
                    int ct; dColTot[b] = (dColTot.TryGetValue(b, out ct) ? ct : 0) + cv;
                }
                sb.Append(string.Join(", ", parts.ToArray())).Append("\r\n");
            }
            sb.Append("\r\n  Column totals: ");
            List<string> ctparts = new List<string>();
            int grand = 0;
            foreach (string b in lBVals) { int c; int cv = dColTot.TryGetValue(b, out c) ? c : 0; ctparts.Add(b + "=" + cv); grand += cv; }
            sb.Append(string.Join(", ", ctparts.ToArray())).Append("\r\n");
            sb.Append("  Grand total: ").Append(grand).Append("\r\n");
            return sb.ToString();
        }

        // mdEscape: make a value safe inside a GitHub-flavored Markdown
        // table cell (escape pipes, flatten newlines).
        private static string mdEscape(string s)
        {
            if (string.IsNullOrEmpty(s)) return "";
            return s.Replace("|", "\\|").Replace("\r", " ").Replace("\n", " ");
        }

        // saveMarkdownTable: write the current filtered view as a GFM table
        // to a .md file the user names, then open it. Markdown is the same
        // portable target the report-template design settled on -- a screen
        // reader reads it directly and pandoc converts it to HTML/DOCX/PDF.
        private void saveMarkdownTable(List<string> lCols, Dictionary<string, List<string>> dValues)
        {
            int iMax = 0;
            foreach (string sC in lCols) if (dValues[sC].Count > iMax) iMax = dValues[sC].Count;

            StringBuilder sb = new StringBuilder();
            sb.Append("| ");
            for (int c = 0; c < lCols.Count; c++) { if (c > 0) sb.Append(" | "); sb.Append(mdEscape(lCols[c])); }
            sb.Append(" |\r\n| ");
            for (int c = 0; c < lCols.Count; c++) { if (c > 0) sb.Append(" | "); sb.Append("---"); }
            sb.Append(" |\r\n");
            for (int r = 0; r < iMax; r++)
            {
                sb.Append("| ");
                for (int c = 0; c < lCols.Count; c++)
                {
                    if (c > 0) sb.Append(" | ");
                    List<string> col = dValues[lCols[c]];
                    string v = (r < col.Count) ? col[r] : "";
                    sb.Append(mdEscape(v));
                }
                sb.Append(" |\r\n");
            }

            using (SaveFileDialog dlg = new SaveFileDialog())
            {
                prepareFileDialog(dlg);
                dlg.Title = "Save Markdown Table";
                dlg.Filter = "Markdown (*.md)|*.md|All files (*.*)|*.*";
                dlg.DefaultExt = "md";
                string sTable = db.currentTable ?? "table";
                dlg.FileName = sTable + "-table.md";
                if (dlg.ShowDialog(this) != DialogResult.OK) return;
                try
                {
                    File.WriteAllText(dlg.FileName, sb.ToString(), new UTF8Encoding(false));
                    try { DbDoLog.write("Generate from Grid: wrote Markdown table " + dlg.FileName + " (" + iMax + " rows)."); } catch { }
                    LiveRegion.say("Saved Markdown table with " + iMax + " rows; opening in your editor.");
                    try { System.Diagnostics.Process.Start(dlg.FileName); } catch { }
                }
                catch (Exception ex)
                {
                    ErrorDialog.show(this, "Generate from Grid", "Could not write the Markdown file: " + ex.Message);
                }
            }
        }

        // runColumnChart: build a destination path next to the database and
        // dispatch to the existing single-column chart engine, opening the
        // result in Excel; Excel-absent failures are reported gracefully.
        private void runColumnChart(string sColumn, string sKind)
        {
            string sDbPath = db.filePath ?? "";
            string sFolder = string.IsNullOrEmpty(sDbPath)
                ? Environment.GetFolderPath(Environment.SpecialFolder.MyDocuments)
                : Path.GetDirectoryName(sDbPath);
            string sTable = db.currentTable ?? "table";
            string sCleanCol = sColumn.Replace(" ", "_").Replace("/", "_");
            string sDest = Path.Combine(sFolder, sTable + "-" + sCleanCol + "-" + sKind + ".xlsx");
            try
            {
                int iN = (sKind == "frequency")
                    ? db.exportFrequencyChart(sColumn, sDest)
                    : db.exportColumnChart(sColumn, sKind, sDest);
                if (iN == 0) { showInfoDialog("Generate from Grid", "No usable data to chart in column \"" + sColumn + "\"."); return; }
                LiveRegion.say("Chart saved (" + sKind + ", " + iN + "); opening in Excel.");
                try { System.Diagnostics.Process.Start(sDest); } catch { }
            }
            catch (Exception ex) { showExcelFailure("chart", ex); }
        }

        // runScatterChart: destination path + dispatch to the scatter engine.
        private void runScatterChart(string sColX, string sColY)
        {
            string sDbPath = db.filePath ?? "";
            string sFolder = string.IsNullOrEmpty(sDbPath)
                ? Environment.GetFolderPath(Environment.SpecialFolder.MyDocuments)
                : Path.GetDirectoryName(sDbPath);
            string sTable = db.currentTable ?? "table";
            string sCleanX = sColX.Replace(" ", "_").Replace("/", "_");
            string sCleanY = sColY.Replace(" ", "_").Replace("/", "_");
            string sDest = Path.Combine(sFolder, sTable + "-" + sCleanY + "-vs-" + sCleanX + "-scatter.xlsx");
            try
            {
                int iN = db.exportScatterChart(sColX, sColY, sDest);
                if (iN == 0) { showInfoDialog("Generate from Grid", "No rows where both \"" + sColX + "\" and \"" + sColY + "\" are numeric."); return; }
                LiveRegion.say("Scatter saved (" + iN + " points); opening in Excel.");
                try { System.Diagnostics.Process.Start(sDest); } catch { }
            }
            catch (Exception ex) { showExcelFailure("scatter chart", ex); }
        }

        // showExcelFailure: a chart output needs Excel; when it is missing
        // (or errors), say so and steer the user to the native outputs.
        private void showExcelFailure(string sWhat, Exception ex)
        {
            try { DbDoLog.write("Generate from Grid " + sWhat + " failed: " + ex.Message); } catch { }
            ErrorDialog.show(this, "Generate from Grid",
                "Could not create the " + sWhat + ":\r\n\r\n" + ex.Message
                + "\r\n\r\nExcel charts require Microsoft Excel. The native outputs "
                + "(summary statistics, frequency table, cross-tab, and Markdown table) "
                + "do not need Excel -- try one of those instead.");
        }

        private void toolsChartClicked(object sender, EventArgs evArgs)
        {
            if (db == null || !db.hasRecordset())
            {
                MessageBox.Show(this, "Open a table first.",
                    "Graphics Grid", MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }
            if (db.recordCount == 0)
            {
                MessageBox.Show(this, "No records to chart in the current filter.",
                    "Graphics Grid", MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }

            // Build the column picker dialog with LbcDialog. The
            // user picks a visible column (we include all display
            // fields, not just textline-typed ones, so they can
            // chart any column they can see in the data list).
            List<string> lCols = db.getDisplayFieldNames();
            if (lCols.Count == 0) lCols = db.getFieldNames();
            if (lCols.Count == 0) return;

            string sColumn;
            using (LbcDialog dlg = new LbcDialog("Graphics Grid", this))
            {
                dlg.addLabel("Choose a column to chart. The chart will show how often");
                dlg.addLabel("each distinct value appears in the current filtered view.");
                dlg.addSeparator();
                // Default to the db cursor's column (cursor
                // conformance): charting starts where the user is.
                string sDefaultCol = currentVirtualColumnName();
                if (string.IsNullOrEmpty(sDefaultCol) || !lCols.Contains(sDefaultCol))
                    sDefaultCol = lCols[0];
                ComboBox cbCol = dlg.addComboPickBox("Column:",
                    lCols, sDefaultCol,
                    "Pick a categorical column with a few distinct values");
                if (!dlg.runOkCancel()) return;
                sColumn = (cbCol.SelectedItem ?? "").ToString();
            }
            if (string.IsNullOrEmpty(sColumn)) return;

            // Build destination filename next to the database file.
            // Pattern: <database-folder>\<table>-by-<column>-chart.xlsx
            string sDbPath = db.filePath ?? "";
            string sFolder = string.IsNullOrEmpty(sDbPath)
                ? Environment.GetFolderPath(Environment.SpecialFolder.MyDocuments)
                : Path.GetDirectoryName(sDbPath);
            string sTable = db.currentTable ?? "table";
            string sCleanCol = sColumn.Replace(" ", "_").Replace("/", "_");
            string sDest = Path.Combine(sFolder,
                sTable + "-by-" + sCleanCol + "-chart.xlsx");

            try
            {
                int iDistinct = db.exportFrequencyChart(sColumn, sDest);
                LiveRegion.say("Chart saved with " + iDistinct + " distinct values; opening in Excel");
                try { System.Diagnostics.Process.Start(sDest); } catch { }
            }
            catch (Exception ex)
            {
                ErrorDialog.show(this, "Graphics Grid", "Could not create chart:\n\n" + ex.Message
                    + "\n\nNote: New-Chart requires Excel to be installed.");
            }
        }

        private void toolsInvokeSqlClicked(object sender, EventArgs evArgs)
        {
            // Query (Control+Q): prompt for SQL, then run it.
            if (db == null || !db.isOpen()) return;
            string sSql = promptInvokeSql();
            runCustomSql(sSql);
        }

        // sqlHistoryClicked (Alt+Shift+Q): pick a previously-run custom
        // query from the persisted history and run it again. The list
        // is newest-first; running re-records it to the front.
        private void sqlHistoryClicked(object sender, EventArgs evArgs)
        {
            if (db == null || !db.isOpen()) return;
            List<string> lHistory = QueryHistory.load();
            if (lHistory.Count == 0)
            {
                MessageBox.Show(this,
                    "No custom queries yet. Run one with Query (Control+Q) to start the history.",
                    "Query History", MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }
            // Display each statement on one line (newlines collapsed)
            // so the listbox stays readable; the full statement still
            // runs from the stored value.
            List<string> lDisplay = new List<string>();
            foreach (string s in lHistory)
                lDisplay.Add(System.Text.RegularExpressions.Regex.Replace(s, @"\s+", " ").Trim());
            LbcDialog dlg = new LbcDialog("Query History", this);
            try
            {
                ListBox lb = dlg.addPickBox(
                    "&Recent custom queries (Enter to run):",
                    lDisplay, lDisplay[0],
                    "The list is newest first and holds up to 20 statements. Running one moves it back to the top.");
                if (!dlg.runOkCancel()) return;
                int iIdx = lb.SelectedIndex;
                if (iIdx < 0 || iIdx >= lHistory.Count) return;
                runCustomSql(lHistory[iIdx]);
            }
            finally { dlg.Dispose(); }
        }

        // runCustomSql: the shared dispatch for a custom statement,
        // used by both Query (Control+Q) and Query History
        // (Alt+Shift+Q). It records the statement, then:
        //   SELECT / WITH  -> opens the result as a recordset in a NEW
        //                     window. A single-base-table SELECT stays
        //                     editable; a join or expression result is
        //                     read-only by nature.
        //   anything else  -> executes it. ADO does not parse the SQL;
        //                     it relies on the provider returning rows
        //                     (a Recordset) for queries versus a
        //                     records-affected count for action
        //                     statements (INSERT / UPDATE / DELETE) and
        //                     DDL. An action count is spoken directly
        //                     and the data list refreshed; text output
        //                     (PRAGMA / EXPLAIN) is shown in a dialog.
        private void runCustomSql(string sSql)
        {
            if (string.IsNullOrEmpty(sSql)) return;
            QueryHistory.record(sSql);
            string sLow = sSql.TrimStart().ToLowerInvariant();
            if (sLow.StartsWith("select") || sLow.StartsWith("with"))
            {
                DbDoFrame frame = mdiFrame();
                if (frame == null) return;
                DbDoForm frmQuery = frame.openQueryWindow(db.filePath, sSql);
                if (frmQuery != null && frmQuery.Db != null)
                {
                    bool bRO = frmQuery.Db.readOnlyInnate;
                    LiveRegion.sayForced("Query opened: " + frmQuery.Db.recordCount
                        + " row" + (frmQuery.Db.recordCount == 1 ? "" : "s")
                        + (bRO ? ". Read-only by nature."
                               : ". Editable (single-table result)."));
                }
                return;
            }
            try
            {
                StringWriter sbOut = new StringWriter();
                int iAffected = db.invokeSql(sSql, sbOut);
                string sResult = sbOut.ToString().Trim();
                if (iAffected >= 0)
                {
                    // Action statement (INSERT / UPDATE / DELETE / DDL):
                    // no rows returned, just a count. Speak it and
                    // refresh so any change to the current table shows.
                    LiveRegion.sayForced(iAffected + " record"
                        + (iAffected == 1 ? "" : "s") + " affected.");
                    invokeRefresh();
                }
                else
                {
                    // Row-returning text result (PRAGMA / EXPLAIN).
                    if (sResult.Length == 0) sResult = "(no rows)";
                    if (isShortResult(sResult))
                        MessageBox.Show(this, sResult, "Query",
                            MessageBoxButtons.OK, MessageBoxIcon.Information);
                    else
                        HelpDialog.show(this, "Query", sResult);
                }
            }
            catch (Exception ex)
            {
                ErrorDialog.show(this, "Query", ex, db);
            }
        }

        private string promptInvokeSql()
        {
            using (Form dlg = new LbcForm())
            {
                dlg.Text = "Invoke SQL";
                dlg.AccessibleName = "Invoke SQL";
                dlg.StartPosition = FormStartPosition.CenterParent;
                dlg.ClientSize = new Size(640, 320);
                dlg.FormBorderStyle = FormBorderStyle.Sizable;
                dlg.MaximizeBox = true;
                dlg.MinimizeBox = false;
                dlg.ShowInTaskbar = false;
                dlg.KeyPreview = true;

                Label lbl = new Label();
                lbl.Text = "Enter a &SQL command (Ctrl+Enter to run):";
                lbl.Location = new Point(12, 12);
                lbl.Size = new Size(616, 20);
                dlg.Controls.Add(lbl);

                TextBox tb = new TextBox();
                tb.AccessibleName = "SQL command";
                tb.Multiline = true;
                tb.ScrollBars = ScrollBars.Vertical;
                tb.AcceptsReturn = true;
                tb.AcceptsTab = false;
                tb.Font = new Font(FontFamily.GenericMonospace, 10f);
                tb.Location = new Point(12, 36);
                tb.Size = new Size(616, 230);
                // Remember the last input: pre-fill with the most recent
                // statement (DbDo.inix, via QueryHistory) so re-invoking
                // Query shows the last query ready to edit or re-run. The
                // text is selected, so typing immediately replaces it.
                List<string> lQueryHist = QueryHistory.load();
                if (lQueryHist.Count > 0) { tb.Text = lQueryHist[0]; tb.SelectAll(); }
                tb.Anchor = AnchorStyles.Top | AnchorStyles.Left | AnchorStyles.Right | AnchorStyles.Bottom;
                tb.KeyDown += (s, e) => {
                    if (e.Control && e.KeyCode == Keys.Enter)
                    {
                        dlg.DialogResult = DialogResult.OK;
                        dlg.Close();
                        e.Handled = true;
                        e.SuppressKeyPress = true;
                    }
                };
                dlg.Controls.Add(tb);

                Button btnOk = new Button();
                btnOk.Text = "&OK";
                btnOk.DialogResult = DialogResult.OK;
                btnOk.Size = new Size(90, 28);
                btnOk.Location = new Point(440, 280);
                btnOk.Anchor = AnchorStyles.Bottom | AnchorStyles.Right;
                dlg.Controls.Add(btnOk);

                Button btnCancel = new Button();
                btnCancel.Text = "&Cancel";
                btnCancel.DialogResult = DialogResult.Cancel;
                btnCancel.Size = new Size(90, 28);
                btnCancel.Location = new Point(536, 280);
                btnCancel.Anchor = AnchorStyles.Bottom | AnchorStyles.Right;
                dlg.Controls.Add(btnCancel);

                dlg.AcceptButton = btnOk;
                dlg.CancelButton = btnCancel;
                dlg.ActiveControl = tb;

                if (dlg.ShowDialog(this) != DialogResult.OK) return null;
                return tb.Text;
            }
        }

