        // facetColumnClicked: Datasette-style faceting for the column
        // under the virtual cursor. Groups the current table by that
        // column and lists each distinct value with its row count, most
        // common first; the user picks one and DbDo filters the grid to
        // it. The accessible form of "what's in this column, how is it
        // distributed -- now show me just those rows." The value scan is
        // capped (c_iFacetMax) so a high-cardinality column can't flood
        // the picker, per the Datasette lesson that an unbounded
        // distinct-value scan is a trap. The query, the distinct count,
        // and the applied filter are logged so a misbehaving facet is
        // diagnosable from the log rather than by guesswork.
        private void facetColumnClicked(object sender, EventArgs evArgs)
        {
            const int c_iFacetMax = 1000;
            if (db == null || !db.hasRecordset() || db.recordCount == 0)
            { LiveRegion.say("No record selected"); return; }
            string sTable = db.currentTable;
            if (string.IsNullOrEmpty(sTable))
            { LiveRegion.say("Facet Column works on a table, not a custom query"); return; }
            List<string> lFields = db.getFieldNames();
            if (lFields == null || lFields.Count == 0) { LiveRegion.say("No columns"); return; }
            string sField = virtCurrentColumnName();
            if (string.IsNullOrEmpty(sField) || !lFields.Contains(sField)) sField = lFields[0];

            string sQTable = "\"" + sTable.Replace("\"", "\"\"") + "\"";
            string sQCol = "\"" + sField.Replace("\"", "\"\"") + "\"";
            string sSql = "SELECT " + sQCol + ", count(*) AS n FROM " + sQTable
                + " GROUP BY " + sQCol + " ORDER BY n DESC, " + sQCol
                + " LIMIT " + (c_iFacetMax + 1);
            try { DbDoLog.write("Facet Column: table=" + sTable + " col=" + sField + " SQL=" + sSql); } catch { }

            int iFound;
            List<string[]> lRows;
            try { lRows = db.queryRowsSql(sSql, c_iFacetMax, out iFound); }
            catch (Exception ex)
            {
                ErrorDialog.show(this, "Facet Column", "Could not read column values: " + ex.Message);
                return;
            }
            if (lRows.Count == 0) { LiveRegion.say("No values in " + sField); return; }

            // Build the picker: "value (count)" lines, with a map back
            // to the raw value. GROUP BY keys are distinct, so the
            // displays are unique. A blank display marks SQL NULL or an
            // empty string.
            bool bTruncated = iFound > c_iFacetMax;
            List<string> lDisplay = new List<string>();
            Dictionary<string, string> dDisplayToValue = new Dictionary<string, string>();
            foreach (string[] aRow in lRows)
            {
                string sValue = (aRow.Length > 0) ? (aRow[0] ?? "") : "";
                string sCount = (aRow.Length > 1) ? (aRow[1] ?? "") : "";
                string sLabel = (sValue.Length == 0 ? "(blank)" : sValue) + " (" + sCount + ")";
                if (!dDisplayToValue.ContainsKey(sLabel))
                {
                    lDisplay.Add(sLabel);
                    dDisplayToValue[sLabel] = sValue;
                }
            }

            string sPrompt = "Values in " + sField + ", most common first"
                + (bTruncated ? " (showing the first " + c_iFacetMax + ")" : "")
                + " -- pick one to filter:";
            string sChosen = promptListChoice("Facet " + sField, sPrompt, lDisplay, null);
            if (string.IsNullOrEmpty(sChosen) || !dDisplayToValue.ContainsKey(sChosen)) return;
            string sPicked = dDisplayToValue[sChosen];

            if (sPicked.Length == 0)
            {
                LiveRegion.say("Filtering to blank or null values is not supported yet");
                try { DbDoLog.write("Facet Column: blank/null bucket chosen for " + sField + "; filter not applied."); } catch { }
                return;
            }

            // Quote by column type: numeric bare, everything else as a
            // single-quoted string with embedded quotes doubled. ADO's
            // Filter is limited with embedded quotes and dates, so a
            // rejected expression is caught and reported rather than
            // left half-applied.
            int iType = db.getFieldType(sField);
            bool bNumeric = (iType == 2 || iType == 3 || iType == 4 || iType == 5
                || iType == 6 || iType == 17 || iType == 18 || iType == 19
                || iType == 20 || iType == 131);
            string sExpr = bNumeric
                ? sField + " = " + sPicked
                : sField + " = '" + sPicked.Replace("'", "''") + "'";
            try
            {
                db.applyFilter(sExpr);
                invokeRefresh();
                LiveRegion.say("Filtered " + sField + " to " + sPicked
                    + ", " + db.recordCount + (db.recordCount == 1 ? " row" : " rows"));
                try { DbDoLog.write("Facet applied: " + sExpr + " -> " + db.recordCount + " rows."); } catch { }
            }
            catch (Exception ex)
            {
                ErrorDialog.show(this, "Facet Column",
                    "Could not filter to that value: " + ex.Message + "\r\nFilter tried: " + sExpr);
                try { DbDoLog.write("Facet filter rejected: " + sExpr + " -- " + ex.Message); } catch { }
            }
        }

        private void toolsTestDriverClicked(object sender, EventArgs evArgs)
        {
            StringBuilder sb = new StringBuilder();
            sb.AppendLine("Test-Driver: probing registered ODBC drivers and OLE DB providers.");
            sb.AppendLine();

            // ODBC drivers: HKLM\SOFTWARE\ODBC\ODBCINST.INI\ODBC Drivers
            sb.AppendLine("=== ODBC drivers ===");
            try
            {
                Microsoft.Win32.RegistryKey key = Microsoft.Win32.Registry.LocalMachine.OpenSubKey(
                    @"SOFTWARE\ODBC\ODBCINST.INI\ODBC Drivers");
                if (key != null)
                {
                    foreach (string sName in key.GetValueNames())
                        sb.AppendLine("  " + sName + " = " + key.GetValue(sName));
                    key.Close();
                }
                else sb.AppendLine("  (no drivers registry key)");
            }
            catch (Exception ex) { sb.AppendLine("  (error: " + ex.Message + ")"); }

            // SQLite ODBC presence
            sb.AppendLine();
            sb.AppendLine("=== SQLite ODBC Driver ===");
            bool bSqlite = checkOdbcDriver("SQLite3 ODBC Driver");
            if (bSqlite)
                sb.AppendLine("  PRESENT - .db / .sqlite / .sqlite3 files will work.");
            else
            {
                sb.AppendLine("  MISSING - .db / .sqlite / .sqlite3 files cannot be opened.");
                sb.AppendLine("  Install: download sqliteodbc_w64.exe from");
                sb.AppendLine("           http://www.ch-werner.de/sqliteodbc/");
                sb.AppendLine("  (No WinGet or Chocolatey package exists for this driver.)");
            }

            // ACE OLE DB Provider presence
            sb.AppendLine();
            sb.AppendLine("=== Microsoft Access Database Engine (ACE OLE DB) ===");
            bool bAce = checkClsId("Microsoft.ACE.OLEDB.16.0") || checkClsId("Microsoft.ACE.OLEDB.12.0");
            if (bAce)
                sb.AppendLine("  PRESENT - .mdb / .accdb / .xlsx / .xls / .dbf / .csv files will work.");
            else
            {
                sb.AppendLine("  MISSING - .mdb / .accdb / .xlsx / .xls / .dbf / .csv files cannot be opened.");
                sb.AppendLine("  Install (any of these works):");
                sb.AppendLine("    winget install --id Microsoft.AccessDatabaseEngine.2016 --silent");
                sb.AppendLine("    choco install made-2016 -y");
                sb.AppendLine("  Or download accessdatabaseengine_X64.exe and run with /passive from:");
                sb.AppendLine("    https://www.microsoft.com/en-us/download/details.aspx?id=54920");
            }

            HelpDialog.show(this, "Test Driver", sb.ToString());
        }

        private static bool checkOdbcDriver(string sName)
        {
            try
            {
                Microsoft.Win32.RegistryKey key = Microsoft.Win32.Registry.LocalMachine.OpenSubKey(
                    @"SOFTWARE\ODBC\ODBCINST.INI\ODBC Drivers");
                if (key == null) return false;
                object objV = key.GetValue(sName);
                key.Close();
                return objV != null;
            }
            catch { return false; }
        }

        private static bool checkClsId(string sProgId)
        {
            try
            {
                Type comType = Type.GetTypeFromProgID(sProgId);
                return comType != null;
            }
            catch { return false; }
        }

        private void toolsConsoleClicked(object sender, EventArgs evArgs)
        {
            DotPromptHost.enter(this);
        }

        private void sqleanConsoleClicked(object sender, EventArgs evArgs)
        {
            launchSqleanConsole();
        }

        // launchSqleanConsole: open the bundled sqlean.exe interactively
        // in its own console window -- the full SQLite / SQLean shell
        // (.tables, .schema, .dump, REGEXP, median(), and the rest). Opens
        // the current database read-only so it cannot contend with DbDo's
        // writer; with no database open it starts on an in-memory database.
        // Bound to Control+Shift+GraveAccent. Mirrors the path lookup of
        // the '!' dot-prompt pass-through (cmdSqleanShell) but launches
        // interactively instead of round-tripping a single line.
        private void launchSqleanConsole()
        {
            string sExeDir = Path.GetDirectoryName(System.Reflection.Assembly.GetExecutingAssembly().Location);
            string sShell = Path.Combine(sExeDir ?? ".", "sqlean.exe");
            if (!File.Exists(sShell))
            {
                ErrorDialog.show(this, "Sqlean Console",
                    "sqlean.exe was not found beside DbDo.exe.\n\n"
                    + "The sqlean.exe shell ships with DbDo; place it in the program "
                    + "folder (or reinstall) to use the Sqlean Console.");
                try { DbDoLog.write("Sqlean Console: sqlean.exe missing at " + sShell); } catch { }
                return;
            }
            string sDbPath = (db != null) ? (db.filePath ?? "") : "";
            try
            {
                // Host the shell inside a cmd.exe window (/k) rather than
                // launching sqlean.exe directly. A GUI process spawning a
                // console app can hand it a console where the shell's
                // interactive .quit / .exit do not cleanly close the
                // window; inside cmd the shell gets a normal interactive
                // console, and when it does exit, cmd remains so the
                // window is never orphaned -- type exit or close it. The
                // banner states how to leave.
                string sDbArg = (sDbPath.Length > 0) ? (" -readonly \"" + sDbPath + "\"") : "";
                System.Diagnostics.ProcessStartInfo psi = new System.Diagnostics.ProcessStartInfo();
                psi.FileName = "cmd.exe";
                psi.Arguments = "/k title Sqlean Console"
                    + " & echo To leave the sqlean shell: type .quit or .exit"
                    + " (then close this window or type exit)."
                    + " & echo. & \"" + sShell + "\"" + sDbArg;
                psi.UseShellExecute = true;
                psi.WorkingDirectory = sExeDir ?? ".";
                System.Diagnostics.Process.Start(psi);
                LiveRegion.say(sDbPath.Length > 0
                    ? "Sqlean console opened read only on the current database."
                    : "Sqlean console opened.");
                try { DbDoLog.write("Sqlean Console launched: " + sShell + " " + sDbArg); } catch { }
            }
            catch (Exception ex)
            {
                ErrorDialog.show(this, "Sqlean Console", "Could not start sqlean.exe.\n\n" + ex.Message);
                try { DbDoLog.write("Sqlean Console error: " + ex.Message); } catch { }
            }
        }

        // Edit-Settings: open a Settings dialog
        // with one control per common option. The dialog uses the
        // Layout by Code (LbcDialog) helper for consistent layout
        // and accessibility. OK writes the changes to the per-user
        // DbDo.inix at %LOCALAPPDATA%\DbDo\DbDo.inix and reminds
        // the user that some changes take effect on next launch.
        // An "Open file..." button is provided for raw editing,
        // useful for [Keys] overrides and other settings the GUI
        // doesn't expose yet.
        //
        // Bound to F12.
        //
        // Common settings exposed in the GUI:
        //   - uiMode (gui / cli / both)
        //   - default Markdown reading level for exports (informational)
        //   - "Open file..." escape hatch to the raw .ini
        //
        // Settings deliberately not exposed (managed automatically
        // or only relevant for power users):
        //   - [Session] last-opened state (DbDo writes it itself)
        //   - [Folders] last-used directories (DbDo writes it itself)
        //   - [Keys] hotkey overrides (rare; raw editing is fine)
        // toolsEditConfigClicked: the Settings command (Alt+Shift+E /
        // F12). Presents a category chooser; each choice opens a
        // record-edit-style dialog of labeled text boxes for that
        // category, so a pick always leads to an editable form (the old
        // flow stopped at a mode pick list). The categories span the two
        // settings tiers:
        //   General Options        -> per-user DbDo.inix
        //   Field Regex by Type    -> [Validation]    (global or per-db)
        //   Connection Strings     -> [ConnectStrings](global or per-db)
        //   This Table's View      -> [Table:<name>]  (per-db only)
        // plus escape hatches to per-field validation and the raw file.
        private void toolsEditConfigClicked(object sender, EventArgs evArgs)
        {
            string sUserIni = configIniPath();
            if (string.IsNullOrEmpty(sUserIni)) return;
            ensureConfigIniExists(sUserIni);

            const string sGeneral  = "General Options";
            const string sRegex    = "Field Regex by Type";
            const string sConnStr  = "Connection Strings by File Type";
            const string sTableVw  = "This Table's View (columns, sort, filter)";
            const string sLookPrm  = "This Table's Look/Prm Fields (rebuilds the table)";
            const string sPerField = "Field Validation for This Table";
            const string sRawFile  = "Open the .inix File in a Text Editor";

            while (true)
            {
                List<string> lCats = new List<string>
                    { sGeneral, sRegex, sConnStr, sTableVw, sLookPrm, sPerField, sRawFile };
                string sPick;
                LbcDialog dlg = new LbcDialog("Settings", this);
                try
                {
                    dlg.addLabel("Choose what to edit, then press Edit.");
                    string sDbInix = dbScopedInixPath();
                    if (!string.IsNullOrEmpty(sDbInix))
                        dlg.addLabel("This database's file: " + sDbInix);
                    dlg.addLabel("Global file: " + sUserIni);
                    dlg.addSeparator();
                    ListBox lb = dlg.addListBox("Settings category:", lCats, sGeneral);
                    string sBtn = dlg.runWithButtons(new string[] { "&Edit...", "Close" });
                    if (!string.Equals(sBtn, "Edit...", StringComparison.OrdinalIgnoreCase))
                        return;
                    sPick = (lb.SelectedItem ?? sGeneral).ToString();
                }
                finally { dlg.Dispose(); }

                if (sPick == sGeneral)       editGeneralOptions();
                else if (sPick == sRegex)    editAffinityRegex();
                else if (sPick == sConnStr)  editConnectionStrings();
                else if (sPick == sTableVw)  editTableView();
                else if (sPick == sLookPrm)  editLookPrmFields();
                else if (sPick == sPerField) openFieldValidationDialog(sUserIni);
                else if (sPick == sRawFile)  openIniInTextEditor(sUserIni);
            }
        }

        // settingsScopeChoice: ask whether a setting is saved to this
        // database's <DbName>.inix (an override that travels with the
        // file) or the global per-user DbDo.inix (the default for all
        // databases). Returns the chosen path, or null if cancelled.
        // When no database is open, only the global file is available.
        private string settingsScopeChoice(string sTitle, string sUserIni, out bool bPerDb)
        {
            bPerDb = false;
            string sDbInix = dbScopedInixPath();
            if (string.IsNullOrEmpty(sDbInix)) return sUserIni;
            LbcDialog dlg = new LbcDialog(sTitle, this);
            try
            {
                dlg.addLabel("Save these settings where?");
                string sThisDb = "This database (" + System.IO.Path.GetFileName(sDbInix) + ")";
                string sAllDb  = "All databases (DbDo.inix)";
                ComboBox cb = dlg.addComboPickBox("Scope:",
                    new string[] { sAllDb, sThisDb }, sAllDb,
                    "All databases = the global default. This database = an override that travels with this .db file.");
                string sBtn = dlg.runWithButtons(new string[] { "OK", "Cancel" });
                if (!string.Equals(sBtn, "OK", StringComparison.OrdinalIgnoreCase)) return null;
                bPerDb = (cb.SelectedItem ?? "").ToString().StartsWith("This database");
                return bPerDb ? sDbInix : sUserIni;
            }
            finally { dlg.Dispose(); }
        }

        // editAffinityRegex: edit the default validation regex for each
        // data type / affinity -- the [Validation] section keyed by type
        // name. A blank box means "no pattern" (the compiled fallbacks
        // for the numeric/boolean/time types still apply). Patterns are
        // .NET regex, the same syntax Edit Record uses. Saved to the
        // scope the user picks; a per-database value overrides the
        // global one at validation time.
        private void editAffinityRegex()
        {
            string sUserIni = configIniPath();
            if (string.IsNullOrEmpty(sUserIni)) return;
            bool bPerDb;
            string sTarget = settingsScopeChoice("Field Regex by Type", sUserIni, out bPerDb);
            if (sTarget == null) return;

            string[] aTypes = { "BOOLEAN", "INTEGER", "REAL", "NUMERIC", "TEXTTIME",
                                "TEXTLINE", "TEXTMEMO", "TEXTMARKDOWN", "TEXT", "BLOB" };

            LbcDialog dlg = new LbcDialog("Field Regex by Type", this);
            try
            {
                dlg.addLabel("A .NET regex applied to every field of that declared type.");
                dlg.addLabel("Blank = no pattern (built-in numeric/time checks still apply).");
                dlg.addLabel("Saving to: " + sTarget);
                dlg.addSeparator();
                Dictionary<string, TextBox> dBox = new Dictionary<string, TextBox>();
                foreach (string sType in aTypes)
                    dBox[sType] = dlg.addTextLine(sType + ":", readIniValue(sTarget, "Validation", sType, ""));
                string sBtn = dlg.runWithButtons(new string[] { "OK", "Cancel" });
                if (string.Equals(sBtn, "OK", StringComparison.OrdinalIgnoreCase))
                {
                    int iSaved = 0;
                    foreach (string sType in aTypes)
                    {
                        string sNew = (dBox[sType].Text ?? "").Trim();
                        string sOld = readIniValue(sTarget, "Validation", sType, "");
                        if (sNew != sOld) { writeIniValue(sTarget, "Validation", sType, sNew); iSaved++; }
                    }
                    try { IniValidation.reset(); } catch { }
                    LiveRegion.say("Regex settings saved");
                    DbDoLog.write("Edit-Settings regex: " + iSaved + " saved to " + sTarget);
                    MessageBox.Show(this, iSaved + " pattern(s) saved to:\n" + sTarget,
                        "Field Regex by Type", MessageBoxButtons.OK, MessageBoxIcon.Information);
                }
            }
            finally { dlg.Dispose(); }
        }

        // editConnectionStrings: edit the connection-string template for
        // each database file type -- the [ConnectStrings] section keyed
        // by extension. {path} is replaced with the file's full path and
        // {folder} with its directory at connect time. A blank box means
        // "use DbDo's built-in default" for that type. Saved to the scope
        // the user picks; a per-database value overrides the global one.
        private void editConnectionStrings()
        {
            string sUserIni = configIniPath();
            if (string.IsNullOrEmpty(sUserIni)) return;
            bool bPerDb;
            string sTarget = settingsScopeChoice("Connection Strings by File Type", sUserIni, out bPerDb);
            if (sTarget == null) return;

            string[] aExt = { "db", "sqlite", "sqlite3", "mdb", "accdb",
                              "xlsx", "xls", "dbf", "csv", "tsv", "txt" };

            LbcDialog dlg = new LbcDialog("Connection Strings by File Type", this);
            try
            {
                dlg.addLabel("Override the connection string used to open each file type.");
                dlg.addLabel("Placeholders: {path} = full file path, {folder} = its directory.");
                dlg.addLabel("Blank = use DbDo's built-in default. Saving to: " + sTarget);
                dlg.addSeparator();
                Dictionary<string, TextBox> dBox = new Dictionary<string, TextBox>();
                foreach (string sExt in aExt)
                    dBox[sExt] = dlg.addMemoBox("." + sExt + ":", readIniValue(sTarget, "ConnectStrings", sExt, ""),
                        "Connection string template for ." + sExt + " files. Use {path} and {folder}.");
                string sBtn = dlg.runWithButtons(new string[] { "OK", "Cancel" });
                if (string.Equals(sBtn, "OK", StringComparison.OrdinalIgnoreCase))
                {
                    int iSaved = 0;
                    foreach (string sExt in aExt)
                    {
                        string sNew = (dBox[sExt].Text ?? "").Replace("\r\n", " ").Replace("\n", " ").Trim();
                        string sOld = readIniValue(sTarget, "ConnectStrings", sExt, "");
                        if (sNew != sOld) { writeIniValue(sTarget, "ConnectStrings", sExt, sNew); iSaved++; }
                    }
                    LiveRegion.say("Connection settings saved");
                    DbDoLog.write("Edit-Settings connstrings: " + iSaved + " saved to " + sTarget);
                    MessageBox.Show(this, iSaved + " template(s) saved to:\n" + sTarget
                        + "\n\nChanges take effect the next time a file of that type is opened.",
                        "Connection Strings by File Type", MessageBoxButtons.OK, MessageBoxIcon.Information);
                }
            }
            finally { dlg.Dispose(); }
        }

        // editTableView: edit the displayed columns, sort, and filter for
        // the current table. Applied live and saved to [Table:<name>] in
        // this database's <DbName>.inix, so the view travels with the
        // database. Per-database only -- requires an open base table.
        private void editTableView()
        {
            if (db == null || !db.hasRecordset() || db.currentIsView
                || string.IsNullOrEmpty(db.currentTable))
            {
                MessageBox.Show(this,
                    "Open a base table first; these view settings are per-table.",
                    "This Table's View", MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }
            string sDbInix = dbScopedInixPath();
            if (string.IsNullOrEmpty(sDbInix))
            {
                MessageBox.Show(this,
                    "This database has no folder to hold a settings file.",
                    "This Table's View", MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }
            string sTable = db.currentTable;

            // Current values: select list from the table cache, sort and
            // filter from the live recordset.
            string sCurSelect = "";
            foreach (KeyValuePair<string, DbDoManager.TableSettings> kv in db.tableCacheEntries())
                if (string.Equals(kv.Key, sTable, StringComparison.OrdinalIgnoreCase))
                { sCurSelect = kv.Value.sSelectList ?? ""; break; }
            string sCurSort = "";
            string sCurFilter = "";
            try { sCurSort = db.sort ?? ""; } catch { }
            try { sCurFilter = db.filter ?? ""; } catch { }

            LbcDialog dlg = new LbcDialog("This Table's View: " + sTable, this);
            try
            {
                dlg.addLabel("These choices apply now and are saved with the database");
                dlg.addLabel("in " + System.IO.Path.GetFileName(sDbInix) + " under [Table:" + sTable + "].");
                dlg.addSeparator();
                TextBox tbSelect = dlg.addMemoBox("Columns to display (comma-separated; blank = all):",
                    sCurSelect, "The exact columns to show, in order. Blank uses DbDo's default visibility rules.");
                TextBox tbSort = dlg.addTextLine("Sort (e.g. last_name ASC, first_name ASC):", sCurSort);
                TextBox tbFilter = dlg.addTextLine("Filter (a WHERE-style expression; blank = none):", sCurFilter);
                string sBtn = dlg.runWithButtons(new string[] { "OK", "Cancel" });
                if (string.Equals(sBtn, "OK", StringComparison.OrdinalIgnoreCase))
                {
                    // Normalize the column list to a clean comma-separated
                    // string (the box accepts commas or one-per-line).
                    string sSelectRaw = (tbSelect.Text ?? "").Replace("\r\n", ",").Replace("\n", ",");
                    List<string> lCols = new List<string>();
                    foreach (string c in sSelectRaw.Split(','))
                    { string t = c.Trim(); if (t.Length > 0) lCols.Add(t); }
                    string sSelect = string.Join(",", lCols.ToArray());
                    string sSort = (tbSort.Text ?? "").Trim();
                    string sFilter = (tbFilter.Text ?? "").Trim();

                    // Apply live (best-effort; a stale expression is
                    // skipped rather than fatal).
                    try { db.setSelectList(sTable, sSelect); } catch { }
                    try { db.filter = sFilter; } catch { }
                    try { db.sort = sSort; } catch { }
                    invokeRefresh();

                    // Persist to the per-database settings file, under the
                    // same keys pass-one's auto-save and recall use.
                    writeIniValue(sDbInix, "Table:" + sTable, "SelectFields", sSelect);
                    writeIniValue(sDbInix, "Table:" + sTable, "OrderFields", sSort);
                    writeIniValue(sDbInix, "Table:" + sTable, "WhereFilter", sFilter);
                    LiveRegion.say("View settings saved");
                    DbDoLog.write("Edit-Settings view: [Table:" + sTable + "] saved to " + sDbInix);
                    MessageBox.Show(this, "View saved to:\n" + sDbInix,
                        "This Table's View", MessageBoxButtons.OK, MessageBoxIcon.Information);
                }
            }
            finally { dlg.Dispose(); }
        }

        // editLookPrmFields: reconfigure which component fields build the
        // current table's 'look' summary and 'prm' unique key. Because both
        // are STORED generated columns, a change rebuilds the table (the
        // safe create-new / copy / drop / rename sequence) and re-points any
        // maps references whose prm changed. The chosen lists are saved to
        // [Table:<name>] LookFields / PrmFields in the per-database file.
        private void editLookPrmFields()
        {
            if (db == null || !db.hasRecordset() || db.currentIsView
                || string.IsNullOrEmpty(db.currentTable))
            {
                MessageBox.Show(this,
                    "Open a base table first; look and prm are per-table.",
                    "Look/Prm Fields", MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }
            string sDbInix = dbScopedInixPath();
            if (string.IsNullOrEmpty(sDbInix))
            {
                MessageBox.Show(this,
                    "This database has no folder to hold a settings file.",
                    "Look/Prm Fields", MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }
            string sTable = db.currentTable;

            // Current component lists: the saved [Table] config wins; else a
            // best-effort parse of the live generated expressions.
            string sCurLook = readPerDbValue("Table:" + sTable, "LookFields");
            string sCurPrm  = readPerDbValue("Table:" + sTable, "PrmFields");
            if (string.IsNullOrEmpty(sCurLook))
                sCurLook = string.Join(", ", db.lParseGeneratedFields(sTable, "look").ToArray());
            if (string.IsNullOrEmpty(sCurPrm))
                sCurPrm = string.Join(", ", db.lParseGeneratedFields(sTable, "prm").ToArray());

            LbcDialog dlg = new LbcDialog("Look/Prm Fields: " + sTable, this);
            try
            {
                dlg.addLabel("Choose the fields that build this table's look and prm.");
                dlg.addLabel("look is the readable summary; prm is the unique key.");
                dlg.addLabel("Saving a change REBUILDS the table to recompute them.");
                dlg.addSeparator();
                TextBox tbLook = dlg.addTextLine("Look fields (comma-separated, in order):", sCurLook);
                TextBox tbPrm  = dlg.addTextLine("Prm fields (comma-separated, in order):", sCurPrm);
                string sBtn = dlg.runWithButtons(new string[] { "OK", "Cancel" });
                if (!string.Equals(sBtn, "OK", StringComparison.OrdinalIgnoreCase)) return;

                List<string> lLook = splitFieldList(tbLook.Text);
                List<string> lPrm  = splitFieldList(tbPrm.Text);
                if (lPrm.Count == 0)
                {
                    MessageBox.Show(this, "At least one Prm field is required.",
                        "Look/Prm Fields", MessageBoxButtons.OK, MessageBoxIcon.Information);
                    return;
                }

                // No-op if nothing changed.
                bool bLookSame = string.Equals(string.Join(", ", lLook.ToArray()),
                    string.Join(", ", splitFieldList(sCurLook).ToArray()), StringComparison.OrdinalIgnoreCase);
                bool bPrmSame = string.Equals(string.Join(", ", lPrm.ToArray()),
                    string.Join(", ", splitFieldList(sCurPrm).ToArray()), StringComparison.OrdinalIgnoreCase);
                if (bLookSame && bPrmSame)
                {
                    LiveRegion.say("No change to look or prm fields.");
                    return;
                }

                // Confirm the rebuild; warn about maps re-pointing when prm changes.
                string sMsg = "This rebuilds table '" + sTable + "' to recompute look and prm.";
                if (!bPrmSame)
                    sMsg += "\n\nBecause the prm key changes, existing relationship references in "
                          + "maps will be updated to match the new prm.";
                sMsg += "\n\nContinue?";
                if (MessageBox.Show(this, sMsg, "Rebuild Table",
                        MessageBoxButtons.OKCancel, MessageBoxIcon.Warning) != DialogResult.OK)
                    return;

                string sErr; int iMaps;
                bool bOk = db.rebuildGeneratedColumns(sTable, lLook, lPrm, out sErr, out iMaps);
                if (!bOk)
                {
                    ErrorDialog.show(this, "Rebuild Table", sErr);
                    return;
                }

                // Persist the new component lists and reopen the rebuilt table.
                writeIniValue(sDbInix, "Table:" + sTable, "LookFields", string.Join(", ", lLook.ToArray()));
                writeIniValue(sDbInix, "Table:" + sTable, "PrmFields",  string.Join(", ", lPrm.ToArray()));
                try { db.selectTable(sTable); } catch { }
                invokeRefresh();
                DbDoLog.write("Look/Prm rebuilt for [Table:" + sTable + "]; maps re-pointed=" + iMaps);
                string sDone = "Rebuilt '" + sTable + "'.";
                if (iMaps > 0) sDone += " " + iMaps + " map reference" + (iMaps == 1 ? "" : "s") + " updated.";
                LiveRegion.sayForced(sDone);
                MessageBox.Show(this, sDone, "Rebuild Table", MessageBoxButtons.OK, MessageBoxIcon.Information);
            }
            finally { dlg.Dispose(); }
        }

        // splitFieldList: parse a comma- (or newline-) separated field list
        // into trimmed, non-empty names.
        private static List<string> splitFieldList(string sRaw)
        {
            List<string> lResult = new List<string>();
            if (string.IsNullOrEmpty(sRaw)) return lResult;
            foreach (string sPart in sRaw.Replace("\r\n", ",").Replace("\n", ",").Split(','))
            { string sT = sPart.Trim(); if (sT.Length > 0) lResult.Add(sT); }
            return lResult;
        }

        // editGeneralOptions: the General category of the Settings
        // dialog -- launch UI mode, command echo, extra speech, and the
        // read-only toggle, plus escape-hatch buttons to per-field
        // validation and the raw .inix file. Reached from the Settings
        // category chooser (toolsEditConfigClicked).
        private void editGeneralOptions()
        {
            string sUserIni = configIniPath();
            if (string.IsNullOrEmpty(sUserIni)) return;
            ensureConfigIniExists(sUserIni);

            // Read current values from the ini, with sensible defaults
            // if the keys are missing.
            string sCurrentUiMode = readIniValue(sUserIni, "General", "UiMode", "gui");
            string sCurrentEcho   = readIniValue(sUserIni, "Options", "CommandEcho", "Y");
            string sCurrentExtra  = readIniValue(sUserIni, "General", "ExtraSpeech", "Y");
            bool bCurrentEcho = !(sCurrentEcho.Equals("N", StringComparison.OrdinalIgnoreCase)
                              || sCurrentEcho.Equals("No", StringComparison.OrdinalIgnoreCase)
                              || sCurrentEcho.Equals("0", StringComparison.Ordinal)
                              || sCurrentEcho.Equals("False", StringComparison.OrdinalIgnoreCase));
            bool bCurrentExtra = !(sCurrentExtra.Equals("N", StringComparison.OrdinalIgnoreCase)
                              || sCurrentExtra.Equals("No", StringComparison.OrdinalIgnoreCase)
                              || sCurrentExtra.Equals("0", StringComparison.Ordinal)
                              || sCurrentExtra.Equals("False", StringComparison.OrdinalIgnoreCase));

            LbcDialog dlg = new LbcDialog("Settings", this);
            try
            {
                dlg.addLabel("Settings stored in: " + sUserIni);
                dlg.addLabel("Most changes take effect the next time DbDo starts.");
                dlg.addSeparator();

                // uiMode is a pick-from-three -- ComboBox is perfect.
                // The focus-tip string appears in the status bar at
                // the bottom of the dialog when the user tabs in.
                ComboBox cbUiMode = dlg.addComboPickBox(
                    "UI mode at launch (overridden by -cli / -gui / -both):",
                    new string[] { "both", "gui", "cli" },
                    sCurrentUiMode,
                    "both = GUI + console, gui = window only, cli = dot prompt only");

                // Command Echo toggle. ON by default; speaks the
                // canonical command name through the live region
                // just before each command runs.
                // 'ExtraSpeech=Y' setting is the model. Takes effect
                // on the next command, no restart needed. Also bound
                // to Ctrl+Shift+Z on the Help menu.
                CheckBox cbEcho = dlg.addCheckBox(
                    "Command Echo (speak each command name as it runs)",
                    bCurrentEcho,
                    "When ON, every menu/hotkey command announces its name through the screen reader before executing. Off-by-toggle for users who prefer less speech. Has no effect in CLI / dot-prompt mode.");

                // Extra Speech toggle. ON by default; controls whether
                // DbDo's status messages, cell readouts, and the
                // command echo itself reach the screen reader. When
                // OFF, the screen reader still narrates focus and
                // selection changes -- the toggle silences only the
                // commentary DbDo adds on top. Also bound to
                // Alt+Shift+Z on the Help menu.
                CheckBox cbExtra = dlg.addCheckBox(
                    "Extra Speech (DbDo's status messages and cell readouts)",
                    bCurrentExtra,
                    "When ON, DbDo speaks status messages, command echo, and virtual-cell readouts through the screen reader. When OFF, the screen reader still announces focus and selection changes naturally but DbDo's commentary is suppressed.");

                // Read-Only toggle (v1.0.95). Mirrors the
                // -readonly command-line flag so the CLI startup
                // option and the runtime setting are at parity.
                // The checkbox reflects the CURRENT database's
                // read-only status; toggling it applies immediately
                // by reopening the database in the new mode.
                bool bCurrentReadOnly = (db != null && db.isOpen()) ? db.readOnly : false;
                CheckBox cbReadOnly = dlg.addCheckBox(
                    "Read Only (protect open database from edits)",
                    bCurrentReadOnly,
                    "When ON, the database is opened read-only and edit commands fail with a clear error message. Use this to browse data without risk of accidental edits. Also bound to Ctrl+Shift+R on the Misc menu. Takes effect immediately by reopening the connection.");

                dlg.addSeparator();
                dlg.addLabel("For [Keys] overrides and advanced settings, use the");
                dlg.addLabel("\"Open file...\" button to edit DbDo.inix directly.");
                if (db != null && db.hasRecordset() && !db.currentIsView
                    && !string.IsNullOrEmpty(db.currentTable))
                {
                    dlg.addLabel("Per-field input regex patterns for the current table");
                    dlg.addLabel("(\"" + db.currentTable + "\") can be edited from the");
                    dlg.addLabel("\"Field Validation...\" button.");
                }

                string sResult = dlg.runWithButtons(
                    new string[] { "OK", "Field &Validation...", "Open file...", "Cancel" });
                if (string.Equals(sResult, "OK", StringComparison.OrdinalIgnoreCase))
                {
                    string sNewUiMode = (cbUiMode.SelectedItem ?? "both").ToString();
                    string sNewEcho = cbEcho.Checked ? "Y" : "N";
                    string sNewExtra = cbExtra.Checked ? "Y" : "N";
                    writeIniValue(sUserIni, "General", "UiMode", sNewUiMode);
                    writeIniValue(sUserIni, "Options", "CommandEcho", sNewEcho);
                    writeIniValue(sUserIni, "General", "ExtraSpeech", sNewExtra);
                    invalidateCommandEchoCache();
                    LiveRegion.bExtraSpeechEnabled = cbExtra.Checked;
                    if (miHelpExtraSpeech != null) miHelpExtraSpeech.Checked = LiveRegion.bExtraSpeechEnabled;
                    if (miHelpCommandEcho != null) miHelpCommandEcho.Checked = isCommandEchoOn();
                    // Read-Only delta: if the dialog setting differs
                    // from the current connection state, reopen the
                    // database with the new flag. Skip if no db open.
                    if (db != null && db.isOpen() && cbReadOnly.Checked != db.readOnly)
                    {
                        toggleReadOnlyClicked(null, EventArgs.Empty);
                    }
                    LiveRegion.say("Configuration saved");
                    DbDoLog.write("Edit-Settings saved: uiMode=" + sNewUiMode
                        + "; commandEcho=" + sNewEcho
                        + "; extraSpeech=" + sNewExtra
                        + "; readOnly=" + (cbReadOnly.Checked ? "Y" : "N"));
                    MessageBox.Show(this,
                        "Configuration saved to " + sUserIni
                        + "\n\nuiMode takes effect on next DbDo launch."
                        + "\nCommand Echo, Extra Speech, and Read Only take effect immediately.",
                        "Edit Settings",
                        MessageBoxButtons.OK, MessageBoxIcon.Information);
                }
                else if (string.Equals(sResult, "Field Validation...",
                            StringComparison.OrdinalIgnoreCase))
                {
                    openFieldValidationDialog(sUserIni);
                }
                else if (string.Equals(sResult, "Open file...", StringComparison.OrdinalIgnoreCase))
                {
                    openIniInTextEditor(sUserIni);
                }
                // Cancel / Escape / close: do nothing.
            }
            finally
            {
                dlg.Dispose();
            }
        }

        // openFieldValidationDialog: sub-dialog for editing the
        // [Validation:<table>] section of DbDo.inix for the current
        // table. Each editable field gets one labeled input. The
        // input takes a .NET regex pattern (the same syntax used by
        // the Edit Record and Edit Cell validators) -- empty means
        // no constraint. OK saves; Cancel discards.
        //
        // Why regex and not a simpler "picture" syntax: DbDo already
        // uses .NET regex for validation under the covers, and regex
        // is the established, powerful pattern syntax. A separate
        // mask-language would mean translating one of dBASE PICTURE,
        // WinForms MaskedTextBox masks, or a homegrown DSL, all of
        // which are less expressive than regex and require teaching
        // an extra vocabulary.
        private void openFieldValidationDialog(string sUserIni)
        {
            if (db == null || !db.hasRecordset() || string.IsNullOrEmpty(db.currentTable))
            {
                MessageBox.Show(this,
                    "Open a table first; field validation rules are per-table.",
                    "Field Validation", MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }
            if (db.currentIsView)
            {
                MessageBox.Show(this,
                    "Field validation rules apply to tables, not views.",
                    "Field Validation", MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }

            string sTable = db.currentTable;
            // Editable fields = all fields minus the system metadata
            // (added, edited, marked) that the user never types into.
            List<string> lAllFields = db.getFieldNames();
            List<string> lEditableFields = new List<string>();
            foreach (string sCol in lAllFields)
            {
                string sLow = sCol.ToLowerInvariant();
                if (sLow == "added" || sLow == "edited" || sLow == "marked") continue;
                lEditableFields.Add(sCol);
            }
            if (lEditableFields.Count == 0)
            {
                MessageBox.Show(this,
                    "Table \"" + sTable + "\" has no user-editable fields.",
                    "Field Validation", MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }

            // Build a parallel list of TextBox controls so we can pull
            // values out after OK without having to track names.
            List<TextBox> lTextBoxes = new List<TextBox>(lEditableFields.Count);
            string sSection = "Validation:" + sTable;
            using (LbcDialog dlg = new LbcDialog("Field Validation: " + sTable, this))
            {
                dlg.addLabel("Each field accepts a .NET regex pattern.");
                dlg.addLabel("Empty = no constraint. Examples below.");
                dlg.addLabel("  Email:       ^[^@\\s]+@[^@\\s]+\\.[a-z]+$");
                dlg.addLabel("  US phone:    ^\\d{3}-\\d{3}-\\d{4}$");
                dlg.addLabel("  ISO date:    ^\\d{4}-\\d{2}-\\d{2}$");
                dlg.addLabel("  Year choice: ^(Freshman|Sophomore|Junior|Senior)$");
                dlg.addSeparator();
                foreach (string sCol in lEditableFields)
                {
                    string sExisting = "";
                    try { sExisting = readIniValue(sUserIni, sSection, sCol, ""); }
                    catch { sExisting = ""; }
                    TextBox tb = dlg.addInputBox(sCol + ":", sExisting,
                        "Regex pattern that values for \"" + sCol + "\" must match. Empty for no constraint.");
                    lTextBoxes.Add(tb);
                }
                if (!dlg.runOkCancel()) return;

                // Save: write every non-empty pattern; remove keys that
                // the user emptied. We test each regex compiles before
                // writing so we can warn on bad input.
                List<string> lWarnings = new List<string>();
                for (int i = 0; i < lEditableFields.Count; i++)
                {
                    string sCol = lEditableFields[i];
                    string sNewVal = (lTextBoxes[i].Text ?? "").Trim();
                    if (sNewVal.Length > 0)
                    {
                        try { new System.Text.RegularExpressions.Regex(sNewVal); }
                        catch (Exception exRx)
                        {
                            lWarnings.Add(sCol + ": " + exRx.Message);
                            continue;
                        }
                        writeIniValue(sUserIni, sSection, sCol, sNewVal);
                    }
                    else
                    {
                        // Empty -> remove the key if it was previously set.
                        try { writeIniValue(sUserIni, sSection, sCol, ""); }
                        catch { }
                    }
                }
                // Invalidate the cache so subsequent Edit Record /
                // Edit Cell dialogs pick up the new regexes.
                try { IniValidation.reset(); } catch { }
                LiveRegion.say("Field validation saved");
                if (lWarnings.Count > 0)
                {
                    StringBuilder sbWarn = new StringBuilder();
                    sbWarn.Append("Some patterns did not compile and were skipped:\r\n\r\n");
                    foreach (string s in lWarnings) sbWarn.Append("  ").Append(s).Append("\r\n");
                    MessageBox.Show(this, sbWarn.ToString(),
                        "Field Validation", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                }
            }
        }

        // Helper: path of the per-user DbDo.inix. Returns null and
        // shows an error dialog if %LOCALAPPDATA% is unavailable.
        private string configIniPath()
        {
            string sBase = Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData);
            if (string.IsNullOrEmpty(sBase))
            {
                MessageBox.Show(this,
                    "%LOCALAPPDATA% is not set. Cannot locate per-user DbDo.inix.",
                    "Settings", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                return null;
            }
            string sDir = Path.Combine(sBase, "DbDo");
            try { if (!Directory.Exists(sDir)) Directory.CreateDirectory(sDir); }
            catch { }
            return Path.Combine(sDir, "DbDo.inix");
        }

        // Helper: ensure DbDo.inix exists at the given path. Seeds
        // from the shipped template next to the EXE if available,
        // otherwise writes a minimal stub.
        private void ensureConfigIniExists(string sUserIni)
        {
            if (File.Exists(sUserIni)) return;
            string sShipped = Path.Combine(
                Path.GetDirectoryName(Application.ExecutablePath) ?? ".",
                "DbDo.inix");
            if (File.Exists(sShipped))
            {
                try { File.Copy(sShipped, sUserIni, false); }
                catch (Exception exC)
                {
                    DbDoLog.write("Edit-Settings: could not copy shipped ini: " + exC.Message);
                }
            }
            if (!File.Exists(sUserIni))
            {
                try
                {
                    File.WriteAllText(sUserIni,
                        "; DbDo per-user configuration." + Environment.NewLine +
                        "; Edit this file to change uiMode, override hotkeys," + Environment.NewLine +
                        "; or inspect remembered Session/Folders state." + Environment.NewLine +
                        "; Restart DbDo for changes to take effect." + Environment.NewLine +
                        Environment.NewLine +
                        "[General]" + Environment.NewLine +
                        "uiMode = gui" + Environment.NewLine +
                        Environment.NewLine +
                        "[Keys]" + Environment.NewLine +
                        "; Command-Name = Key+Combo" + Environment.NewLine);
                }
                catch (Exception exW)
                {
                    ErrorDialog.show(this, "Settings", "Could not create " + sUserIni + ": " + exW.Message);
                }
            }
        }

        // Open the configuration .ini in the system default handler.
        // Falls back to Notepad if the shell call fails. Shared by
        // the "Open file..." button and (for backward compat) any
        // CLI/menu entry that wants to bypass the dialog.
        private void openIniInTextEditor(string sUserIni)
        {
            try
            {
                System.Diagnostics.Process.Start(sUserIni);
                LiveRegion.say("Opened DbDo.inix for editing");
                DbDoLog.write("Edit-Settings opened: " + sUserIni);
            }
            catch
            {
                try { System.Diagnostics.Process.Start("notepad.exe", "\"" + sUserIni + "\""); }
                catch (Exception ex2)
                {
                    ErrorDialog.show(this, "Settings", "Could not open the file in Notepad: " + ex2.Message);
                }
            }
        }

        // Read one value from the ini. Returns sDefault if the key
        // doesn't exist, the file is unreadable, or the value is
        // empty. Section is matched case-insensitively (the ini may
        // be hand-written with mixed case).
        private static string readIniValue(string sPath, string sSection, string sKey, string sDefault)
        {
            if (!File.Exists(sPath)) return sDefault;
            try
            {
                foreach (InixCodec.Section sec in InixCodec.read(sPath))
                {
                    if (!string.Equals(sec.Name, sSection, StringComparison.OrdinalIgnoreCase)) continue;
                    string sValue = sec.get(sKey);
                    if (sValue == null) return sDefault;
                    if (sValue.IndexOf('\n') < 0) sValue = sValue.Trim();
                    return string.IsNullOrEmpty(sValue) ? sDefault : sValue;
                }
            }
            catch { }
            return sDefault;
        }

        // Write one value into the settings file, preserving every
        // other section, comment, and line. Delegates to the shared
        // Inix-aware writer: multi-line values (and values containing
        // '=' or a leading '[') go out in the fenced form, existing
        // fenced values are replaced or removed as whole blocks, and
        // the key scan never misreads a key= line inside a fenced
        // value. Pass "" to clear a setting back to the default.
        private static void writeIniValue(string sPath, string sSection, string sKey, string sValue)
        {
            if (!InixCodec.writeValue(sPath, sSection, sKey, sValue))
                DbDoLog.write("writeIniValue FAILED: " + sPath);
        }

        // Open-FileFolder: open Windows Explorer at the folder containing
        // the currently open database file. Standard convention
        // (Alt+Backslash). If no database is open, opens %USERPROFILE%
        // as a sensible fallback. Selects the database file in the
        // resulting Explorer window so the user can see exactly which
        // file is open.
        private void toolsOpenFolderClicked(object sender, EventArgs evArgs)
        {
            try
            {
                string sPath = (db != null && db.isOpen()) ? db.filePath : null;
                if (!string.IsNullOrEmpty(sPath) && File.Exists(sPath))
                {
                    // explorer.exe /select,"path" highlights the file
                    System.Diagnostics.Process.Start("explorer.exe", "/select,\"" + sPath + "\"");
                    LiveRegion.say("Opened folder: " + Path.GetDirectoryName(sPath));
                }
                else
                {
                    string sHome = Environment.GetFolderPath(Environment.SpecialFolder.UserProfile);
                    System.Diagnostics.Process.Start("explorer.exe", sHome);
                    LiveRegion.say("No database open; opened user folder");
                }
            }
            catch (Exception ex)
            {
                MessageBox.Show(this, ex.Message, "Open File Folder", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            }
        }

        // toolsCommandPromptClicked: Control+Slash. Open a Windows
        // command prompt whose working directory is the folder of the
        // currently-open database (or the user's folder when nothing is
        // open). Standard convention, and the
        // shell-side companion to Open in Explorer (Alt+Backslash),
        // which reveals the same folder in the file manager.
        private void toolsCommandPromptClicked(object sender, EventArgs evArgs)
        {
            try
            {
                string sPath = (db != null && db.isOpen()) ? db.filePath : null;
                string sDir = (!string.IsNullOrEmpty(sPath) && File.Exists(sPath))
                    ? Path.GetDirectoryName(sPath)
                    : Environment.GetFolderPath(Environment.SpecialFolder.UserProfile);

                System.Diagnostics.ProcessStartInfo psi =
                    new System.Diagnostics.ProcessStartInfo("cmd.exe");
                psi.WorkingDirectory = sDir;
                psi.UseShellExecute = true;   // open an interactive console window
                System.Diagnostics.Process.Start(psi);

                if (!string.IsNullOrEmpty(sPath) && File.Exists(sPath))
                    LiveRegion.say("Command prompt at " + sDir);
                else
                    LiveRegion.say("No database open; command prompt at user folder");
            }
            catch (Exception ex)
            {
                MessageBox.Show(this, ex.Message, "Command Prompt", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            }
        }

        // =====================================================================
        // HELP menu handlers
        // =====================================================================
        private void helpContentsClicked(object sender, EventArgs evArgs)
        {
            // F1 opens the HTML version of the user guide in the
            // default browser. The HTML lives next to DbDo.exe and is
            // generated by buildDbDo.cmd via Pandoc from DbDo.md.
            // Browsers expose far better navigation (heading-by-
            // heading, links, search, font scaling, screen-reader
            // table-of-contents) than an in-app TextBox could.
            //
            // If DbDo.htm is missing (e.g., somebody copied DbDo.exe
            // alone), fall back to a brief text pointer rather than
            // failing silently.
            string sPath = System.IO.Path.Combine(
                Application.StartupPath, "DbDo.htm");
            if (System.IO.File.Exists(sPath))
            {
                try
                {
                    System.Diagnostics.Process.Start(sPath);
                    return;
                }
                catch (Exception ex)
                {
                    MessageBox.Show(this,
                        "Could not open the user guide:\n\n" + ex.Message
                        + "\n\nThe file exists at:\n" + sPath,
                        "Help Contents",
                        MessageBoxButtons.OK, MessageBoxIcon.Warning);
                }
            }
            else
            {
                MessageBox.Show(this,
                    "DbDo.htm was not found next to DbDo.exe.\n\n"
                    + "Expected location:\n" + sPath + "\n\n"
                    + "If you installed DbDo via the setup, the file "
                    + "should already be there. Otherwise, copy "
                    + "DbDo.htm from the bundle into the program folder.",
                    "Help Contents",
                    MessageBoxButtons.OK, MessageBoxIcon.Information);
            }
        }

        // Show-Readme: open README.htm (the quick-start / summary
