        // Show-Status / Where am I: speak the current database file,
        // table, row position, filter, and sort through the live
        // region. The user presses Control+F1 at any time and hears
        // a one-sentence summary -- this is the "Where am I?" key.
        //
        // Doubles as a live-region pipeline test: if Show-Status
        // doesn't speak, the live region is broken regardless of
        // other announcements; if it does, every other live-region
        // call in DbDo will too.
        private void helpStatusClicked(object sender, EventArgs evArgs)
        {
            string sMsg = buildStatusMessage();
            LiveRegion.say(sMsg);
            // Also dump to the StatusStrip label so the user can
            // tab-navigate to it (or use the screen reader's "say
            // status bar" hotkey -- JAWS Insert+PageDown) and have
            // the same text as a fallback path.
            try
            {
                if (lblStatus != null) lblStatus.Text = sMsg;
            }
            catch { }
        }

        // Build the one-sentence status string. Used by helpStatusClicked
        // and reused by other contexts that want the same summary.
        private string buildStatusMessage()
        {
            if (db == null || !db.isOpen())
                return "No database file open. Press Control+O to open one.";
            string sFile = db.filePath ?? "";
            string sBase = string.IsNullOrEmpty(sFile)
                ? "Database open"
                : "Database " + System.IO.Path.GetFileName(sFile);
            if (string.IsNullOrEmpty(db.currentTable))
                return sBase + ", no table selected. Press F4 to choose a table.";
            int iCount = db.recordCount;
            int iPos = db.absolutePosition;
            string sRow = (iCount > 0 && iPos > 0)
                ? "row " + iPos + " of " + iCount
                : "no rows";
            string sFilter = "";
            try { sFilter = db.filter ?? ""; } catch { }
            string sSort = "";
            try { sSort = db.sort ?? ""; } catch { }
            StringBuilder sb = new StringBuilder();
            sb.Append(sBase);
            sb.Append(", table " + db.currentTable);
            if (db.currentIsView) sb.Append(" (view)");
            else if (db.readOnly) sb.Append(" (read-only)");
            sb.Append(", " + sRow);
            if (!string.IsNullOrEmpty(sFilter)) sb.Append(", filter: " + sFilter);
            if (!string.IsNullOrEmpty(sSort))   sb.Append(", sort: "   + sSort);
            return sb.ToString();
        }

        // Test-Reader: speak a probe message through say() so the user
        // hears it, then display the diagnostic in a dialog so the
        // user can read which detection path was taken. The two
        // pieces together let the user confirm what's working:
        // they hear the speech (or not), AND they can read which
        // path reported success.
        private void helpTestReaderClicked(object sender, EventArgs evArgs)
        {
            // Use sayForced: Test-Reader's whole purpose is to verify
            // speech, so it must speak even when Extra-Speech is off.
            LiveRegion.sayForced("Speech path test. If you hear this, the speech pipeline is working.");
            string sDiag = LiveRegion.speechDiagnostic();
            MessageBox.Show(this, sDiag, "Test Reader",
                MessageBoxButtons.OK, MessageBoxIcon.Information);
        }

        // helpExtraSpeechClicked: toggle whether DbDo emits its own
        // direct speech messages (status announcements, command echo,
        // virtual-cell readouts) through the screen reader. When OFF
        // the screen reader still hears DbDo via its own natural
        // focus and selection announcements; the toggle suppresses
        // only the additional commentary DbDo adds on top. The setting is
        // persisted in DbDo.inix [General] extraSpeech.
        private void helpExtraSpeechClicked(object sender, EventArgs evArgs)
        {
            LiveRegion.bExtraSpeechEnabled = !LiveRegion.bExtraSpeechEnabled;
            miHelpExtraSpeech.Checked = LiveRegion.bExtraSpeechEnabled;
            string sUserIni = Path.Combine(Path.GetDirectoryName(
                System.Reflection.Assembly.GetExecutingAssembly().Location) ?? "", "DbDo.inix");
            try { writeIniValue(sUserIni, "General", "ExtraSpeech", LiveRegion.bExtraSpeechEnabled ? "Y" : "N"); }
            catch { /* best-effort persist; the runtime state is the source of truth */ }
            // Force-speak the new state so the user hears confirmation
            // even when they just turned speech off.
            sayToggleState("Extra Speech Toggle", LiveRegion.bExtraSpeechEnabled);
        }

        // helpCommandEchoClicked: toggle whether DbDo speaks the
        // canonical command name through the live region just before
        // each menu/hotkey command runs. Mirrors helpExtraSpeechClicked
        // -- same pattern of runtime toggle, persistent ini write, and
        // forced confirmation announcement. The setting is persisted
        // in DbDo.inix [Options] commandEcho. CLI/dot-prompt commands
        // don't go through the addItem wrappers that fire commandEcho,
        // so this toggle has no effect there -- intentional, since the
        // user explicitly typed the command and shouldn't need it
        // echoed back at them.
        private void helpCommandEchoClicked(object sender, EventArgs evArgs)
        {
            string sUserIni = Path.Combine(Path.GetDirectoryName(
                System.Reflection.Assembly.GetExecutingAssembly().Location) ?? "", "DbDo.inix");
            bool bNew = !isCommandEchoOn();
            try { writeIniValue(sUserIni, "Options", "CommandEcho", bNew ? "Y" : "N"); }
            catch { /* best-effort persist */ }
            invalidateCommandEchoCache();
            miHelpCommandEcho.Checked = bNew;
            sayToggleState("Command Echo Toggle", bNew);
        }

        // toggleReadOnlyClicked: flip the open database between
        // read-write and read-only at runtime. Restored in v1.0.95
        // after being removed in v1.0.91. The reasoning for restoring:
        // the -readonly command-line flag was kept, so the feature
        // exists; making it inaccessible from the GUI was inconsistent.
        // Anyone running DbDo can already edit data they have write
        // access to; the read-only toggle is for the user's own
        // protection against accidental edits while browsing.
        //
        // Implementation: close the connection, reopen at the new
        // read-only setting. Drill stack from the previous open is
        // invalid in the new connection, so clear it. The current
        // table is preserved.
        private void toggleReadOnlyClicked(object sender, EventArgs evArgs)
        {
            if (db == null || !db.isOpen())
            {
                LiveRegion.sayForced("No database open. Use Open Database first.");
                return;
            }
            if (db.readOnlyInnate)
            {
                LiveRegion.sayForced("This recordset is read-only by nature "
                    + "(a view or a query result that cannot be updated); "
                    + "the read-only setting cannot be changed here. "
                    + "Open the underlying table to make changes.");
                return;
            }
            string sPath = db.filePath;
            string sTable = db.currentTable;
            bool bWasReadOnly = db.readOnly;
            try
            {
                db.close();
                db.openDatabase(sPath, sTable, !bWasReadOnly);
                clearDrillStack();
                invokeRefresh();
                bool bNowRO = db.readOnly;
                if (miToggleReadOnly != null) miToggleReadOnly.Checked = bNowRO;
                sayToggleState("Read Only Toggle", bNowRO);
            }
            catch (Exception ex)
            {
                ErrorDialog.show(this, "Toggle Read Only", ex.Message);
            }
        }

        // =====================================================================
        // Script commands. The Invoke / View Script pattern
        // adapted for DbDo. The user manages scripts as plain files
        // in %APPDATA%\DbDo\Scripts\, edited in their own choice of
        // external editor (Notepad by default; override via DbDo.inix
        // [Scripts] editor=). .js files are executed as JScript .NET
        // against the running DbDoForm; everything else is shown as
        // plain text in a MessageBox.
        //
        // No Save-Script command (DbDo has no analogous "save
        // selected text" workflow since it is not a text editor).
        // Edit Script handles both editing an existing file and
        // creating a new one via a "[New script...]" entry at the
        // top of the pick list.
        // =====================================================================

        // Sentinel string for the "create new" pick-list entry. Square
        // brackets are conventional in screen-reader UI to mark a
        // non-data option in a list (JAWS reads "left bracket new
        // script right bracket"); they also sort before any real
        // filename in OrdinalIgnoreCase order so the entry stays at
        // the top of the list.
        private const string NewScriptSentinel = "[New script...]";

        // miscInvokeScriptClicked: pick a script from the folder
        // and run it. .js -> JScript .NET execution via DbDo.dll;
        // everything else -> show file contents in a MessageBox as
        // reference text. Output (last expression value or
        // "ERROR: ..." string) is shown in a MessageBox so the screen
        // reader reads it through the standard dialog focus path.
        private void miscInvokeScriptClicked(object sender, EventArgs args)
        {
            System.Collections.Generic.SortedDictionary<string, string> dScripts = gatherScripts();
            if (dScripts.Count == 0)
            {
                string sWhere = ScriptHelper.getScriptDir();
                string sDbFolder = currentDbFolder();
                if (!string.IsNullOrEmpty(sDbFolder)) sWhere = sDbFolder + "\n  or\n" + sWhere;
                MessageBox.Show(this,
                    "No scripts found in:\n\n" + sWhere
                    + "\n\nUse Edit Script to create one, or Open Script Folder to manage files in Explorer.",
                    "Invoke Script", MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }

            // Standard LbcDialog pick; native ListBox under the hood,
            // read line-by-line by every screen reader. The list merges
            // the open database's own scripts with the generic ones.
            string[] aNames = new List<string>(dScripts.Keys).ToArray();
            using (LbcDialog dlg = new LbcDialog("Invoke Script", this))
            {
                dlg.addLabel("&Script:");
                ListBox lb = dlg.addListBox(aNames, aNames[0], null);
                if (!dlg.runOkCancel()) return;
                if (lb.SelectedItem == null) return;
                string sName = lb.SelectedItem.ToString();
                string sPath = dScripts[sName];
                string sResult = ScriptHelper.runScript(sPath, this, this.db);
                bool bIsError = sResult != null && sResult.StartsWith("ERROR:");
                string sBody = string.IsNullOrEmpty(sResult) ? "(no output)" : sResult;
                // Script output can be arbitrarily long and the user
                // commonly wants to read it line-by-line, word-by-
                // word, or character-by-character with a screen
                // reader. MessageBox is unsuitable for that
                // exploration. We use the same multi-line read-only
                // dialog the speech-only commands use on double-
                // press: a memo box with an OK button. The dialog
                // honors Escape as OK by the LbcDialog convention.
                // Short results (one line, no errors) still go to
                // MessageBox since the brevity matches its idiom.
                if (bIsError || !isShortResult(sBody))
                {
                    showInfoDialog("Invoke Script: " + sName, sBody);
                }
                else
                {
                    MessageBox.Show(this, sBody,
                        "Invoke Script: " + sName,
                        MessageBoxButtons.OK,
                        MessageBoxIcon.Information);
                }
            }
        }

        // miscEditScriptClicked: edit an existing script OR create
        // a new one. If scripts already exist, the pick list shows
        // them with "[New script...]" at the top. If the folder is
        // empty, jump straight to the new-file workflow. Either way
        // the chosen path is then opened in the user's editor.
        private void miscEditScriptClicked(object sender, EventArgs args)
        {
            System.Collections.Generic.SortedDictionary<string, string> dExisting = gatherScripts();
            string sPath;

            if (dExisting.Count == 0)
            {
                // No scripts yet: skip the pick and go straight to
                // the Save File dialog so the user can name the new
                // file. A new script lands in the open database's
                // folder when one is open, else the generic folder.
                sPath = promptForNewScriptPath(currentDbFolder());
                if (string.IsNullOrEmpty(sPath)) return;
            }
            else
            {
                // Build a pick list with "[New script...]" at the top
                // followed by the merged db-local and generic script
                // names (already alphabetical from gatherScripts).
                List<string> lExisting = new List<string>(dExisting.Keys);
                string[] aChoices = new string[lExisting.Count + 1];
                aChoices[0] = NewScriptSentinel;
                lExisting.CopyTo(aChoices, 1);

                string sPicked;
                using (LbcDialog dlg = new LbcDialog("Edit Script", this))
                {
                    dlg.addLabel("&Script:");
                    ListBox lb = dlg.addListBox(aChoices, aChoices[0], null);
                    if (!dlg.runOkCancel()) return;
                    if (lb.SelectedItem == null) return;
                    sPicked = lb.SelectedItem.ToString();
                }

                if (sPicked == NewScriptSentinel)
                {
                    sPath = promptForNewScriptPath(currentDbFolder());
                    if (string.IsNullOrEmpty(sPath)) return;
                }
                else
                {
                    sPath = dExisting[sPicked];
                }
            }

            if (!ScriptHelper.openInEditor(sPath))
            {
                ErrorDialog.show(this, "Edit Script", "Could not launch the editor. Set [Scripts] editor= in DbDo.inix to a working editor path.");
            }
        }

        // promptForNewScriptPath: standard Save File dialog seeded
        // to the Scripts folder. Returns the chosen path, or empty
        // string on cancel. Used by miscEditScriptClicked when the
        // user wants a new script.
        //
        // The filter list orders the three DbDo script extensions
        // by frequency of expected use: JScript first (most
        // computational power), SQL second (most familiar), DuoBatch
        // third (DbDo-specific). The SaveFileDialog automatically
        // appends the matching extension when the user types a name
        // without one.
        //
        // After the file is created (Save dialog returns a path),
        // we seed it with a starter template appropriate to the
        // extension. The template is a few lines of header comments
        // with one example construct, so the user opens a fresh
        // editor onto something that already runs successfully and
        // can be extended in place rather than a blank file.
        private string promptForNewScriptPath(string sInitialDir)
        {
            string sPath;
            using (SaveFileDialog sfd = new SaveFileDialog())
            {
                sfd.Title = "New Script";
                prepareFileDialog(sfd);
                sfd.InitialDirectory = string.IsNullOrEmpty(sInitialDir) ? ScriptHelper.getScriptDir() : sInitialDir;
                sfd.Filter =
                      "JScript .NET (*.js)|*.js"
                    + "|SQL batch (*.sql)|*.sql"
                    + "|DbDo command batch (*.dbdo)|*.dbdo"
                    + "|All Files (*.*)|*.*";
                sfd.DefaultExt = "js";
                sfd.AddExtension = true;
                sfd.OverwritePrompt = true;
                if (sfd.ShowDialog(this) != DialogResult.OK) return "";
                sPath = sfd.FileName;
            }
            // Seed the new file with a starter template based on its
            // extension. Only do this if the file didn't already
            // exist (or is zero-bytes) -- never clobber existing
            // content.
            try
            {
                System.IO.FileInfo fi = new System.IO.FileInfo(sPath);
                if (!fi.Exists || fi.Length == 0)
                {
                    System.IO.File.WriteAllText(sPath, starterTemplateFor(sPath));
                }
            }
            catch { /* tolerate -- the editor will open an empty file */ }
            return sPath;
        }

        // starterTemplateFor: return the boilerplate body for a
        // newly-created script of the given extension. Each
        // template is short (a few lines), begins with a one-line
        // "Description:" comment slot the user can fill in, and
        // contains one example construct so the file runs out of
        // the box even before editing.
        private static string starterTemplateFor(string sPath)
        {
            string sExt = System.IO.Path.GetExtension(sPath).ToLowerInvariant();
            switch (sExt)
            {
                case ".js":
                    return
                        "// Description: \r\n"
                      + "// JScript .NET script. Host objects available: db (DbDoManager), frm (DbDoForm).\r\n"
                      + "// Returns: the value of the last expression, displayed in the result dialog.\r\n"
                      + "\r\n"
                      + "var sb = new System.Text.StringBuilder();\r\n"
                      + "sb.AppendLine(\"Script ran successfully.\");\r\n"
                      + "sb.AppendLine(\"Current table: \" + db.currentTable);\r\n"
                      + "sb.ToString();\r\n";
                case ".sql":
                    return
                        "-- Description: \r\n"
                      + "-- SQL batch. Statements separated by ';' run in order.\r\n"
                      + "-- SELECT results, DML row counts, and PRAGMA output all appear in the result dialog.\r\n"
                      + "\r\n"
                      + "SELECT 1 AS placeholder;\r\n";
                case ".dbdo":
                    return
                        "# Description: \r\n"
                      + "# DbDo command batch. Each non-blank, non-comment line is dispatched\r\n"
                      + "# as if you had typed it at the dot prompt -- using the natural\r\n"
                      + "# dot-prompt language (path, status, sort-filter, table <name>,\r\n"
                      + "# filter <expr>, sort <expr>, etc.), not the underlying canonical\r\n"
                      + "# PowerShell-style verbs. Either form works; the natural form is\r\n"
                      + "# shorter and matches what you type interactively.\r\n"
                      + "# Comments start with '#' or '--'. A leading '?' on a line means 'continue on error'.\r\n"
                      + "\r\n"
                      + "status\r\n";
                default:
                    return "";
            }
        }

        // miscOpenScriptFolderClicked: shellexec the Scripts folder
        // so the user can manage files in Explorer. The folder is
        // created on first access by ScriptHelper.getScriptDir() so
        // this command never fails for a "folder does not exist"
        // reason.
        private void miscOpenScriptFolderClicked(object sender, EventArgs args)
        {
            // Open the open database's own folder when one is open --
            // that is where its scripts live, beside the .db file --
            // otherwise the generic script folder.
            string sDbFolder = currentDbFolder();
            string sDir = string.IsNullOrEmpty(sDbFolder) ? ScriptHelper.getScriptDir() : sDbFolder;
            try
            {
                System.Diagnostics.ProcessStartInfo psi =
                    new System.Diagnostics.ProcessStartInfo(sDir);
                psi.UseShellExecute = true;
                System.Diagnostics.Process.Start(psi);
            }
            catch (Exception ex)
            {
                ErrorDialog.show(this, "Open Script Folder", "Could not open the script folder:\n\n" + sDir + "\n\n" + ex.Message);
            }
        }

        // miscEvaluateExpressionClicked: Control+Equals. Evaluate a
        // one-off expression through DbDo's JScript .NET engine -- the
        // inline calculator/evaluator.
        // The engine returns the value of the last expression, so a bare
        // "2+2*10" yields "22". The result is spoken and shown (not
        // copied to the clipboard, which some testers cannot access),
        // and the last expression is remembered for quick iteration.
        private static string sLastEvaluateExpr = "";
        private void miscEvaluateExpressionClicked(object sender, EventArgs evArgs)
        {
            string sExpr;
            using (LbcDialog dlg = new LbcDialog("Evaluate Expression", this))
            {
                TextBox tb = dlg.addInputBox("&Expression:", sLastEvaluateExpr,
                    "A JScript .NET expression to evaluate, for example 2+2*10 or "
                    + "\"abc\".toUpperCase(). The current window (frm) and table (db) are "
                    + "available to the engine, the same as Invoke Script.");
                if (!dlg.runOkCancel()) return;
                sExpr = (tb.Text ?? "").Trim();
            }
            if (sExpr.Length == 0) return;
            sLastEvaluateExpr = sExpr;

            string sResult;
            try { sResult = ScriptHelper.evaluateExpression(sExpr, this, this.db); }
            catch (Exception ex) { sResult = "ERROR: " + ex.Message; }
            if (string.IsNullOrEmpty(sResult)) sResult = "(no result)";

            LiveRegion.say(sResult);
            MessageBox.Show(this, sExpr + " =\n\n" + sResult, "Evaluate Expression",
                MessageBoxButtons.OK, MessageBoxIcon.Information);
        }

        // helpTraceCommandClicked: Ctrl+F1 toggles Key Help mode.
        // When the mode flips, announce the new state via the live
        // region (NO MessageBox, NO dialog -- the announcement is the
        // entire user feedback). The menu item's Checked state mirrors
        // the flag so a sighted glance at the Help menu shows whether
        // Key Help is currently on.
        //
        // Method name retains the historical "helpTraceCommandClicked"
        // because that's what the menu builder wires it to; the user-
        // facing name is "Key Help" everywhere.
        private void helpTraceCommandClicked(object sender, EventArgs evArgs)
        {
            KeyMap.bKeyDescriber = !KeyMap.bKeyDescriber;
            miHelpTraceCommand.Checked = KeyMap.bKeyDescriber;
            sayToggleState("Key Describer Toggle", KeyMap.bKeyDescriber);
        }

        private void helpLogClicked(object sender, EventArgs evArgs)
        {
            string sLogPath = DbDoLog.getLogPath();
            if (string.IsNullOrEmpty(sLogPath))
            {
                MessageBox.Show(this,
                    "Logging is disabled (no writable location).",
                    "Show Log", MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }
            string sExists = File.Exists(sLogPath) ? "(exists)" : "(not yet written)";
            string sMsg = "DbDo log file:\n\n" + sLogPath + "\n\n" + sExists
                        + "\n\nThe log is truncated to empty at every program startup, so it always\n"
                        + "reflects only the current session. Significant events (database opens,\n"
                        + "table switches, errors) are recorded with timestamps.";
            DialogResult res = MessageBox.Show(this,
                sMsg + "\n\nOpen the log file in Notepad now?",
                "Show Log", MessageBoxButtons.YesNo, MessageBoxIcon.Information);
            if (res == DialogResult.Yes && File.Exists(sLogPath))
            {
                try { System.Diagnostics.Process.Start("notepad.exe", "\"" + sLogPath + "\""); }
                catch (Exception ex)
                {
                    ErrorDialog.show(this, "Show Log", "Could not open Notepad: " + ex.Message);
                }
            }
        }

        // Open-WebSite: open the DbDo project page in the system's
        // default browser. The url is the same one referenced from
        // the About dialog and the License/README. No tracking;
        // straight Process.Start("https://...") which on Windows
        // delegates to the default HTTP handler.
        private void helpWebSiteClicked(object sender, EventArgs evArgs)
        {
            const string sUrl = "https://github.com/JamalMazrui/DbDo";
            try
            {
                System.Diagnostics.Process.Start(sUrl);
                LiveRegion.say("Opened DbDo on GitHub");
                DbDoLog.write("Open-WebSite: " + sUrl);
            }
            catch (Exception ex)
            {
                ErrorDialog.show(this, "Open Website", "Could not open the browser:\n\n" + ex.Message
                    + "\n\nThe url is:\n" + sUrl);
            }
        }

        private void helpFileIssueClicked(object sender, EventArgs evArgs)
        {
            const string sUrl = "https://github.com/JamalMazrui/DbDo/issues/new";
            try
            {
                System.Diagnostics.Process.Start(sUrl);
                LiveRegion.say("Opened the DbDo issue form on GitHub. If it does not recognize you, sign in to GitHub to post.");
                DbDoLog.write("File-GitHub-Issue: " + sUrl);
            }
            catch (Exception ex)
            {
                ErrorDialog.show(this, "File GitHub Issue", "Could not open the browser:\n\n" + ex.Message
                    + "\n\nThe url is:\n" + sUrl);
            }
        }

        private void helpAboutClicked(object sender, EventArgs evArgs)
        {
            // The About dialog is the right place for the long-form
            // tagline because it is on-demand (Alt+F1), not part of
            // launch or routine navigation. Keep the rest of the UI
            // -- window title, status bar, column announcements,
            // menu tooltips -- terse.
            HelpDialog.show(this, "About DbDo",
                "DbDo " + BuildInfo.VersionString + "\n"
                + "\n"
                + "An accessible, keyboard-first database manager for Windows.\n"
                + "Opens SQLite, Microsoft Access, Excel, dBASE, and delimited\n"
                + "text through one set of PowerShell-flavored commands, in a\n"
                + "GUI window and a dot-prompt console at the same time.\n"
                + "\n"
                + "Designed for screen-reader use from the ground up. JAWS,\n"
                + "NVDA, and Narrator are all first-class through dedicated\n"
                + "speech paths. Table-style cell navigation, direction-aware\n"
                + "announcements, and the double-press-spells convention\n"
                + "familiar across DbDo.\n"
                + "\n"
                + "C# / .NET Framework 4.8 / x64 / WinForms.\n"
                + "Database access via ADODB COM interop.\n"
                + "Built around Microsoft's PowerShell verb taxonomy.\n"
                + "\n"
                + "https://github.com/JamalMazrui/DbDo\n"
                + "MIT License.\n");
        }

        // Elevate-Version (F11): check the GitHub Releases API for
        // a newer DbDo version, and if found, download the latest
        // DbDo_setup.exe and run it. The Inno Setup installer
        // detects the running DbDo and offers to close it, so
        // no manual exit is required.
        private void helpElevateClicked(object sender, EventArgs evArgs)
        {
            ElevateVersion.run();
        }
    }

    // =====================================================================
    // DotPromptHost: dBase-tradition dot-prompt CLI in a side-by-side
    // Win32 console window.
    //
    // Synchronization: every command operates on DbDoForm.Db, which
    // is the same DbDoManager the GUI is rendering. After any state
    // change, we call form.invokeRefresh() to redraw the grid. The
    // recordset is the single source of truth.
    //
    // Console allocation: AllocConsole gives this winexe process its
    // own console window. We rebind Console.In and Console.Out so
    // .NET's standard Read/Write functions work. SetConsoleCtrlHandler
    // catches the X-button so closing the console doesn't kill the
    // GUI.
    // =====================================================================
    public static class DotPromptHost
    {
        [DllImport("kernel32.dll", SetLastError = true)]
        private static extern bool AllocConsole();
        [DllImport("kernel32.dll", SetLastError = true)]
        private static extern bool FreeConsole();
        [DllImport("kernel32.dll", SetLastError = true)]
        private static extern IntPtr GetConsoleWindow();
        [DllImport("user32.dll")]
        private static extern bool SetWindowText(IntPtr hWnd, string sText);
        [DllImport("user32.dll")]
        private static extern bool SetForegroundWindow(IntPtr hWnd);

        private const int CTRL_C_EVENT = 0;
        private const int CTRL_BREAK_EVENT = 1;
        private const int CTRL_CLOSE_EVENT = 2;
        private delegate bool ConsoleCtrlDelegate(int iCtrlType);
        private static ConsoleCtrlDelegate ctrlHandler;
        [DllImport("kernel32.dll")]
        private static extern bool SetConsoleCtrlHandler(ConsoleCtrlDelegate evHandler, bool bAdd);

        private static bool bAllocated = false;
        private static bool bShouldExit = false;
        private static System.Threading.Thread inputThread;
        private static DbDoForm frm;

        // ----- Context resolution (MDI) -----
        // By convention the single prompt FOLLOWS the most recently
        // active table window: switch windows in the GUI and the
        // prompt's current table/recordset context switches with you.
        // [Console] followActiveWindow=N in DbDo.inix makes the
        // binding sticky instead: the prompt stays on the window that
        // invoked Enter-Console, until Enter-Console is invoked again
        // from another window (which re-pins it). Convention over
        // configuration: Y is the default and needs no entry.
        private static bool followActiveWindow()
        {
            string sValue = DbDoForm.IniSession.read("Console", "followActiveWindow");
            return string.IsNullOrEmpty(sValue)
                || !sValue.Equals("N", StringComparison.OrdinalIgnoreCase);
        }

        // contextForm: the table window whose database, recordset,
        // and drill stack the prompt's commands act on. Falls back to
        // the pinned window, then null (CLI-only mode).
        private static DbDoForm contextForm()
        {
            DbDoForm frmFollow;
            if (followActiveWindow() && DbDoFrame.frame != null)
            {
                frmFollow = DbDoFrame.frame.recentChild();
                if (frmFollow != null && !frmFollow.IsDisposed) return frmFollow;
            }
            if (frm != null && !frm.IsDisposed) return frm;
            return null;
        }
        // When running in CLI-only mode (Program.UiMode.Cli), there is
        // no DbDoForm. The host owns the DbDoManager directly via
        // inputMgr. The 'db' accessor below returns the form's manager
        // when a form exists, otherwise this one.
        private static DbDoManager inputMgr;
        private static string sLastFindCriteria = "";
        private static string sLastFindRegexCli = "";
        private static string sLastFindRegexColumnCli = "";
        // sLastFindKindCli mirrors the GUI's sLastFindKind: "plain",
        // "regex", or "" (no Find issued yet). jump-recordagain /
        // jump-recordprevious dispatch on this so the same chord
        // family repeats whichever was last fired.
        private static string sLastFindKindCli = "";

        // ====================================================================
        // runStandalone: CLI-only mode. The caller (Program.runCliOnly) has
        // already attached or allocated the console and rebound .NET's
        // Console handles. We run the dot-prompt loop on the calling
        // thread (the main thread, since there is no GUI message loop)
        // until the user enters Quit.
        //
        // The recordset state lives in mgr; there is no form to refresh.
        // ====================================================================
        public static void runStandalone(DbDoManager mgr)
        {
            inputMgr = mgr;
            frm = null;
            bAllocated = false;     // we don't own the console; caller does
            bShouldExit = false;
            inputLoop();
        }

        // ====================================================================
        // enter: GUI-mode entry to the dot prompt. Called either at program
        // startup when uiMode == Both (auto-spawn) or interactively from
        // the Tools > Enter-Console menu item.
        //
        // AllocConsole creates a fresh console window for this process and
        // SetConsoleCtrlHandler intercepts the X-button close so closing
        // the console does not terminate the GUI. The dot-prompt loop
        // runs on a background thread; the GUI keeps its own message loop.
        // ====================================================================

        public static void enter(DbDoForm owner)
        {
            frm = owner;
            if (bAllocated)
            {
                IntPtr hWnd = GetConsoleWindow();
                if (hWnd != IntPtr.Zero) SetForegroundWindow(hWnd);
                return;
            }

            if (!AllocConsole())
            {
                ErrorDialog.show(owner, "Enter Console", "Could not allocate console window.");
                return;
            }
            bAllocated = true;
            bShouldExit = false;

            ctrlHandler = delegate(int iCtrlType) { bShouldExit = true; return true; };
            SetConsoleCtrlHandler(ctrlHandler, true);

            try
            {
                System.IO.Stream sbOut = Console.OpenStandardOutput();
                System.IO.StreamWriter writer = new System.IO.StreamWriter(sbOut) { AutoFlush = true };
                Console.SetOut(writer);
                System.IO.Stream inStream = Console.OpenStandardInput();
                System.IO.StreamReader reader = new System.IO.StreamReader(inStream);
                Console.SetIn(reader);
            }
            catch { }

            IntPtr hWnd2 = GetConsoleWindow();
            if (hWnd2 != IntPtr.Zero)
            {
                SetWindowText(hWnd2, "DbDo - Dot Prompt");
                SetForegroundWindow(hWnd2);
            }

            inputThread = new System.Threading.Thread(inputLoop);
            inputThread.IsBackground = true;
            inputThread.Start();
        }

        private static void inputLoop()
        {
            try
            {
                printBanner();
                while (!bShouldExit)
                {
                    Console.Write(". ");
                    string sLine;
                    try { sLine = Console.ReadLine(); } catch { break; }
                    if (sLine == null) break;
                    sLine = sLine.Trim();
                    if (sLine.Length == 0) { printPositionOnly(); continue; }
                    try { dispatch(sLine); }
                    catch (Exception ex) { Console.WriteLine("Error: " + ex.Message); }
                }
            }
            finally
            {
                Console.WriteLine();
                if (bAllocated)
                {
                    // We allocated this console; free it. The GUI form keeps running.
                    Console.WriteLine("Exiting Dot Prompt; closing console window.");
                    try { FreeConsole(); } catch { }
                    bAllocated = false;
                }
                else
                {
                    // CLI-only mode: caller (Program.runCliOnly) owns the console.
                    Console.WriteLine("Exiting Dot Prompt.");
                }
            }
        }

        // The dot-prompt's startup banner. Kept brief (one line plus a
        // hint) so screen readers don't drone before the user can
        // begin typing. Detailed help is one keystroke away ("help").
        private static void printBanner()
        {
            Console.WriteLine("DbDo dot prompt. Type 'help' for commands, 'help <name>' for details.");
            Console.WriteLine();
            printRowSummary();
        }

        // Print "[table] row N of M  filter: ...  sort: ..." for the
        // current recordset. Uses the db accessor so it works in both
        // GUI/Both mode (db comes from the form) and CLI-only mode
        // (db comes from inputMgr).
        private static void printRowSummary()
        {
            DbDoManager dbMgr = db;
            if (dbMgr == null) { Console.WriteLine("(no manager)"); return; }
            if (!dbMgr.isOpen()) { Console.WriteLine("(no database open)"); return; }
            string sTable = dbMgr.currentTable;
            if (string.IsNullOrEmpty(sTable)) { Console.WriteLine("(no table selected)"); return; }
            string sFilter = string.IsNullOrEmpty(dbMgr.filter) ? "" : "  filter: " + dbMgr.filter;
            string sSort = string.IsNullOrEmpty(dbMgr.sort) ? "" : "  sort: " + dbMgr.sort;
            Console.WriteLine(string.Format("[{0}] row {1} of {2}{3}{4}",
                sTable, dbMgr.absolutePosition, dbMgr.recordCount, sFilter, sSort));
        }

        // Print just "N of M" for the current recordset. Used when the
        // user presses bare Enter at the dot prompt: they already know
        // which table is open and the word "row" is redundant when the
        // ratio N-of-M is the only piece they actually need to hear.
        // Filter / sort are also omitted -- those are best heard via
        // an explicit Say-Status or Say-Yield command.
        private static void printPositionOnly()
        {
            DbDoManager dbMgr = db;
            if (dbMgr == null) { Console.WriteLine("(no manager)"); return; }
            if (!dbMgr.isOpen()) { Console.WriteLine("(no database open)"); return; }
            if (string.IsNullOrEmpty(dbMgr.currentTable)) { Console.WriteLine("(no table selected)"); return; }
            Console.WriteLine(dbMgr.absolutePosition + " of " + dbMgr.recordCount);
        }

