        // cmdSayColumn: console form of Say Column from Cursor. In
        // the console we don't have a virtual cursor; we sweep all
        // rows of the first display field as a reasonable default.
        // Capped at 50 lines to keep the output tractable.
        private static void cmdSayColumn()
        {
            if (!requireRecordset()) return;
            List<string> lCols = db.getDisplayFieldNames();
            if (lCols.Count == 0) lCols = db.getFieldNames();
            if (lCols.Count == 0) { Console.WriteLine("(no columns)"); return; }
            string sCol = lCols[0];
            Console.WriteLine("Column: " + sCol);
            object original = null;
            try { original = db.bookmark; } catch { }
            int iShown = 0;
            int iMax = 50;
            try
            {
                for (int i = 1; i <= db.recordCount && iShown < iMax; i++)
                {
                    try
                    {
                        db.absolutePosition = i;
                        Console.WriteLine("  " + (db.getFieldValue(sCol) ?? "blank"));
                        iShown++;
                    }
                    catch { }
                }
            }
            finally
            {
                if (original != null) try { db.bookmark = original; } catch { }
            }
            if (db.recordCount > iMax)
                Console.WriteLine("  ... plus " + (db.recordCount - iMax) + " more rows");
        }

        // cmdSayPosition: console form of Alt+Delete Say Position. The
        // dot prompt has no virtual cursor, so we report the first
        // display column header and the recordset's current row.
        private static void cmdSayPosition()
        {
            if (!requireRecordset()) return;
            List<string> lCols = db.getDisplayFieldNames();
            if (lCols.Count == 0) lCols = db.getFieldNames();
            string sCol = (lCols.Count > 0) ? lCols[0] : "(no columns)";
            Console.WriteLine("Column: " + sCol + ", Row: " + db.absolutePosition);
        }

        // cmdSayClipboard: console form of Alt+Apostrophe Say
        // Clipboard. Prints the current clipboard text to stdout, or
        // a sentinel if the clipboard is empty or non-text. Note
        // that Clipboard.GetText() requires STA threading; the dot-
        // prompt's host thread is STA by default in this app, so the
        // direct call is safe. If a non-STA caller invokes this it
        // will throw, in which case we catch and print the error.
        private static void cmdSayClipboard()
        {
            try
            {
                if (Clipboard.ContainsText())
                {
                    string sText = Clipboard.GetText() ?? "";
                    Console.WriteLine(sText.Length == 0 ? "(clipboard is empty)" : sText);
                }
                else
                {
                    Console.WriteLine("(non-text clipboard)");
                }
            }
            catch (Exception ex)
            {
                Console.WriteLine("(clipboard unavailable: " + ex.Message + ")");
            }
        }

        // cmdSaySortFilter: console form of Shift+8 Say Sort and
        // Filter. Prints both, with explicit "(none)" for empty.
        private static void cmdSaySortFilter()
        {
            if (!requireRecordset()) return;
            string sSort = db.sort ?? "";
            string sFilter = db.filter ?? "";
            Console.WriteLine("Sort: " + (string.IsNullOrEmpty(sSort) ? "(none)" : sSort));
            Console.WriteLine("Filter: " + (string.IsNullOrEmpty(sFilter) ? "(none)" : sFilter));
        }

        // cmdSayKin: console form of Shift+K Say Kin. Walks parent and
        // child FKs for the current row and prints each related
        // record's look value. Console layout differs from the GUI
        // speech form -- the console gets one line per section header
        // and one line per look value, which reads better than the
        // semicolon-separated speech form.
        private static void cmdSayKin()
        {
            if (!requireRecordset()) return;
            if (db.eof || db.bof)
            { Console.WriteLine("(no row selected)"); return; }
            string sCurrentTable = db.currentTable;
            if (string.IsNullOrEmpty(sCurrentTable))
            { Console.WriteLine("(no table)"); return; }

            List<string> lAllTables = db.getTableAndViewNames();
            List<string> lCurrentCols = db.getFieldNames();
            string sCurrentPk = db.actualPrimaryKey(sCurrentTable);

            bool bAny = false;
            // PARENTS
            foreach (string sCol in lCurrentCols)
            {
                if (string.Equals(sCol, sCurrentPk, StringComparison.OrdinalIgnoreCase))
                    continue;
                if (!sCol.EndsWith(Metadata.PrimaryKeySuffix, StringComparison.OrdinalIgnoreCase))
                    continue;
                string sFkValue = "";
                try { sFkValue = db.getFieldValue(sCol) ?? ""; }
                catch { sFkValue = ""; }
                if (string.IsNullOrEmpty(sFkValue)) continue;
                string sParentTable = findParentTableForFkStatic(sCol, lAllTables);
                if (string.IsNullOrEmpty(sParentTable)) continue;
                int iFound;
                List<string> lLook = db.queryColumnValues(
                    sParentTable, "look", sCol, sFkValue, 1, out iFound);
                string sLookVal = (lLook.Count > 0 && !string.IsNullOrEmpty(lLook[0]))
                                  ? lLook[0]
                                  : "(no look)";
                Console.WriteLine("Parent " + sParentTable + ": " + sLookVal);
                bAny = true;
            }

            // CHILDREN
            string sCurrentPkValue = "";
            if (!string.IsNullOrEmpty(sCurrentPk))
            {
                try { sCurrentPkValue = db.getFieldValue(sCurrentPk) ?? ""; }
                catch { sCurrentPkValue = ""; }
            }
            int iMaxPerChild = 25;
            if (!string.IsNullOrEmpty(sCurrentPk) && !string.IsNullOrEmpty(sCurrentPkValue))
            {
                foreach (string sChildTable in lAllTables)
                {
                    if (string.Equals(sChildTable, sCurrentTable, StringComparison.OrdinalIgnoreCase))
                        continue;
                    List<string> lChildCols = db.getColumnsOfTable(sChildTable);
                    bool bHasFk = false;
                    foreach (string sChildCol in lChildCols)
                    {
                        if (string.Equals(sChildCol, sCurrentPk, StringComparison.OrdinalIgnoreCase))
                        { bHasFk = true; break; }
                    }
                    if (!bHasFk) continue;
                    int iFound;
                    List<string> lLook = db.queryColumnValues(
                        sChildTable, "look", sCurrentPk, sCurrentPkValue,
                        iMaxPerChild, out iFound);
                    if (iFound == 0) continue;
                    Console.WriteLine("Child " + sChildTable + " (" + iFound + "):");
                    if (lLook.Count == 0)
                        Console.WriteLine("  (no look column)");
                    else
                    {
                        foreach (string sL in lLook)
                            Console.WriteLine("  " + (string.IsNullOrEmpty(sL) ? "blank" : sL));
                        if (iFound > lLook.Count)
                            Console.WriteLine("  ... " + (iFound - lLook.Count) + " more");
                    }
                    bAny = true;
                }
            }

            if (!bAny) Console.WriteLine("(no related records)");
        }

        // cmdAppendCell / cmdCopyCell: console mirrors of Shift+A /
        // Shift+C. In a console session "current virtual cell" maps
        // to "first display field of the current row".
        private static void cmdAppendCell()
        {
            if (!requireRecordset()) return;
            List<string> lCols = db.getDisplayFieldNames();
            if (lCols.Count == 0) lCols = db.getFieldNames();
            if (lCols.Count == 0) { Console.WriteLine("(no columns)"); return; }
            string sV = db.getFieldValue(lCols[0]) ?? "";
            // Console doesn't access the clipboard from arbitrary
            // threads safely. Print to stdout instead, which is the
            // console-equivalent "the user can copy it from here."
            Console.WriteLine(sV);
        }
        private static void cmdCopyCell()
        {
            cmdAppendCell();
        }

        // cmdSetCell: console form of Edit Cell. Syntax:
        //     set-cell <column> = <value>
        // If <column> is omitted (just a value), targets the first
        // display field. Applies regex validation if configured.
        private static void cmdSetCell(string sArgs)
        {
            if (!requireRecordset()) return;
            if (db.readOnly || db.currentIsView)
            { Console.WriteLine("(read-only context; cannot set)"); return; }
            if (db.eof || db.bof) { Console.WriteLine("(no row selected)"); return; }
            string sCol, sVal;
            int iEq = sArgs.IndexOf('=');
            if (iEq < 0)
            {
                List<string> lCols = db.getDisplayFieldNames();
                if (lCols.Count == 0) lCols = db.getFieldNames();
                if (lCols.Count == 0) { Console.WriteLine("(no columns)"); return; }
                sCol = lCols[0];
                sVal = sArgs.Trim();
            }
            else
            {
                sCol = sArgs.Substring(0, iEq).Trim();
                sVal = sArgs.Substring(iEq + 1).Trim();
            }
            if (!db.hasField(sCol)) { Console.WriteLine("(no such field: " + sCol + ")"); return; }

            string sRegex = null;
            try { sRegex = IniValidation.lookup(db.currentTable, sCol); } catch { }
            if (!string.IsNullOrEmpty(sRegex) && sVal.Length > 0)
            {
                try
                {
                    if (!System.Text.RegularExpressions.Regex.IsMatch(sVal, sRegex))
                    {
                        Console.WriteLine("(value does not match required pattern: " + sRegex + ")");
                        return;
                    }
                }
                catch (Exception ex)
                {
                    Console.WriteLine("(invalid regex in DbDo.inix: " + ex.Message + ")");
                    return;
                }
            }
            try
            {
                db.setFieldValue(sCol, sVal);
                db.update();
                Console.WriteLine(sCol + " = " + sVal);
            }
            catch (Exception ex)
            {
                try { db.cancelUpdate(); } catch { }
                Console.WriteLine("(error: " + ex.Message + ")");
            }
        }

        // cmdMeasureColumn: console form of Describe Column. Mirrors
        // the GUI report but prints to stdout. Calls into the form's
        // public column-report helper so the math stays in one place.
        private static void cmdMeasureColumn()
        {
            if (!requireRecordset()) return;
            List<string> lCols = db.getDisplayFieldNames();
            if (lCols.Count == 0) lCols = db.getFieldNames();
            if (lCols.Count == 0) { Console.WriteLine("(no columns)"); return; }
            string sCol = lCols[0]; // first display field
            object original = null;
            try { original = db.bookmark; } catch { }
            List<string> lRaw = new List<string>();
            try
            {
                for (int i = 1; i <= db.recordCount; i++)
                {
                    try { db.absolutePosition = i;
                          lRaw.Add(db.getFieldValue(sCol) ?? ""); }
                    catch { }
                }
            }
            finally
            {
                if (original != null) try { db.bookmark = original; } catch { }
            }
            Console.Write(DbDoForm.buildColumnReportPublic(sCol, lRaw));
        }

        // cmdNewPlot: console form of Plot Column. Plotting requires
        // Excel; in a pure console session we cannot pop a chart
        // window over a screen reader's review cursor, so this
        // function tells the user how to run the GUI command instead
        // and offers to print a textual summary in lieu of a chart.
        private static void cmdNewPlot(string sArgs)
        {
            Console.WriteLine("Plot Column is a GUI command. In the GUI window:");
            Console.WriteLine("  - Move the Alt+Control+arrow cursor to the column you want to plot");
            Console.WriteLine("  - Press Control+Shift+P (or pick \"Plot Column\" from the Misc menu)");
            Console.WriteLine();
            Console.WriteLine("In the meantime, here is the textual description of the");
            Console.WriteLine("first display column (Describe Column):");
            cmdMeasureColumn();
        }

        // cmdEditConfiguration: console form of the Configuration
        // Settings dialog. Bounces to the GUI dialog if a form is
        // available (the [both] mode case); otherwise prints the
        // ini file path so the user can edit it directly.
        private static void cmdEditConfiguration()
        {
            if (frm != null && frm.IsHandleCreated && !frm.IsDisposed)
            {
                try
                {
                    frm.Invoke(new Action(delegate {
                        try { frm.invokeEditConfiguration(); }
                        catch (Exception ex) { Console.WriteLine("(error: " + ex.Message + ")"); }
                    }));
                }
                catch (Exception ex) { Console.WriteLine("(error: " + ex.Message + ")"); }
                return;
            }
            // Pure CLI fallback: just print the ini path.
            string sBase = Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData);
            string sPath = string.IsNullOrEmpty(sBase) ? "" :
                System.IO.Path.Combine(System.IO.Path.Combine(sBase, "DbDo"), "DbDo.inix");
            Console.WriteLine("Configuration file: " + sPath);
            Console.WriteLine("Edit it directly with a text editor; values take effect on next launch.");
        }

        // F8 mark-anchor and Alt+F8 unmark-anchor family for the
        // console. Mirrors the GUI's iMarkAnchor / iUnmarkAnchor with
        // two static fields each: anchor row and anchor table. The
        // pairs are independent so the user can stage both a mark
        // and an unmark range without interference.
        private static int iCliMarkAnchor = -1;
        private static string sCliMarkAnchorTable = null;
        private static int iCliUnmarkAnchor = -1;
        private static string sCliUnmarkAnchorTable = null;

        private static void cmdSetMarkAnchor()
        {
            if (!requireRecordset()) return;
            iCliMarkAnchor = db.absolutePosition;
            sCliMarkAnchorTable = db.currentTable;
            Console.WriteLine("Mark anchor at row " + iCliMarkAnchor);
        }

        private static void cmdSetUnmarkAnchor()
        {
            if (!requireRecordset()) return;
            iCliUnmarkAnchor = db.absolutePosition;
            sCliUnmarkAnchorTable = db.currentTable;
            Console.WriteLine("Unmark anchor at row " + iCliUnmarkAnchor);
        }

        private static void cmdMarkRange(bool bMark)
        {
            if (!requireRecordset()) return;
            if (db.readOnly || db.currentIsView)
            { Console.WriteLine("(read-only context)"); return; }
            if (!db.hasField(Metadata.MarkedColumn))
            { Console.WriteLine("(no marked column in this table)"); return; }
            int iAnchor = bMark ? iCliMarkAnchor : iCliUnmarkAnchor;
            string sAnchorTable = bMark ? sCliMarkAnchorTable : sCliUnmarkAnchorTable;
            string sKindWord = bMark ? "mark" : "unmark";
            string sStartVerb = bMark ? "set-markanchor" : "set-unmarkanchor";
            if (iAnchor < 1)
            { Console.WriteLine("(no " + sKindWord + " anchor; run " + sStartVerb + " first)"); return; }
            if (!string.Equals(sAnchorTable, db.currentTable, StringComparison.OrdinalIgnoreCase))
            {
                Console.WriteLine("(anchor was set on table \"" + sAnchorTable
                    + "\"; current table is \"" + db.currentTable + "\")");
                if (bMark) { iCliMarkAnchor = -1; sCliMarkAnchorTable = null; }
                else       { iCliUnmarkAnchor = -1; sCliUnmarkAnchorTable = null; }
                return;
            }
            int iCur = db.absolutePosition;
            int iFrom = Math.Min(iAnchor, iCur);
            int iTo = Math.Max(iAnchor, iCur);
            if (iFrom < 1) iFrom = 1;
            if (iTo > db.recordCount) iTo = db.recordCount;
            object bookmarkSaved = null;
            try { bookmarkSaved = db.bookmark; } catch { }
            int iChanged = 0;
            try
            {
                for (int i = iFrom; i <= iTo; i++)
                {
                    try
                    {
                        db.absolutePosition = i;
                        db.setFieldValue(Metadata.MarkedColumn, bMark ? "1" : "0");
                        db.update();
                        iChanged++;
                    }
                    catch { try { db.cancelUpdate(); } catch { } }
                }
            }
            finally
            {
                if (bookmarkSaved != null) try { db.bookmark = bookmarkSaved; } catch { }
            }
            Console.WriteLine((bMark ? "Marked " : "Unmarked ") + iChanged
                + " of " + (iTo - iFrom + 1) + " row(s); rows " + iFrom + " to " + iTo);
        }

        private static void cmdSayYieldMarked()
        {
            if (!requireRecordset()) return;
            if (!db.hasField(Metadata.MarkedColumn))
            { Console.WriteLine("(this table has no marked column)"); return; }
            object original = null;
            try { original = db.bookmark; } catch { }
            int iCount = 0;
            try
            {
                for (int i = 1; i <= db.recordCount; i++)
                {
                    try
                    {
                        db.absolutePosition = i;
                        string sV = db.getFieldValue(Metadata.MarkedColumn).Trim();
                        if (sV.Equals("true", StringComparison.OrdinalIgnoreCase) || sV == "1") iCount++;
                    }
                    catch { }
                }
            }
            finally
            {
                if (original != null) try { db.bookmark = original; } catch { }
            }
            Console.WriteLine(iCount + " marked row" + (iCount == 1 ? "" : "s"));
        }

        // cmdExtractRegex: walks every visible row and prints every
        // match to stdout. The user can redirect the output with
        // Out-File ('output extracted.txt' or 'tee') if desired.
        // Argument is the regex itself.
        private static void cmdExtractRegex(string sPattern)
        {
            if (!requireRecordset()) return;
            sPattern = (sPattern ?? "").Trim();
            if (sPattern.Length == 0)
            { Console.WriteLine("Extract-Regex requires a regex argument."); return; }
            System.Text.RegularExpressions.Regex re;
            try
            {
                re = new System.Text.RegularExpressions.Regex(sPattern,
                    System.Text.RegularExpressions.RegexOptions.IgnoreCase);
            }
            catch (Exception ex)
            { Console.WriteLine("Invalid regex: " + ex.Message); return; }

            List<string> lFields = db.getDisplayFieldNames();
            object original = null;
            try { original = db.bookmark; } catch { }
            int iMatches = 0;
            try
            {
                for (int i = 1; i <= db.recordCount; i++)
                {
                    try
                    {
                        db.absolutePosition = i;
                        foreach (string sCol in lFields)
                        {
                            string sV = db.getFieldValue(sCol) ?? "";
                            if (sV.Length == 0) continue;
                            foreach (System.Text.RegularExpressions.Match match in re.Matches(sV))
                            {
                                Console.WriteLine(match.Value);
                                iMatches++;
                            }
                        }
                    }
                    catch { }
                }
            }
            finally
            {
                if (original != null) try { db.bookmark = original; } catch { }
            }
            if (iMatches == 0) Console.WriteLine("(no matches)");
            else Console.WriteLine("(" + iMatches + " match" + (iMatches == 1 ? "" : "es") + ")");
        }

        private static void cmdCopyRow()
        {
            if (!requireRecordset()) return;
            try
            {
                List<string> lFields = db.getDisplayFieldNames();
                StringBuilder sb = new StringBuilder();
                for (int i = 0; i < lFields.Count; i++)
                {
                    if (i > 0) sb.Append('\t');
                    string sV = db.getFieldValue(lFields[i]) ?? "";
                    sV = sV.Replace('\t', ' ').Replace("\r\n", "\\n").Replace("\n", "\\n").Replace("\r", "\\n");
                    sb.Append(sV);
                }
                Console.WriteLine(sb.ToString());
                // The GUI form (if any) is what owns the WinForms
                // Clipboard. Try to set it from the CLI too; if no
                // form is loaded (CLI-only mode), Clipboard access
                // throws and we just print the row.
                try { Clipboard.SetText(sb.ToString()); Console.WriteLine("(copied to clipboard)"); }
                catch { /* no clipboard in pure CLI mode */ }
            }
            catch (Exception ex) { Console.WriteLine("Copy Row: " + ex.Message); }
        }

        private static void cmdJumpNextInitial()
        {
            // Pure-CLI version is meaningless without a "current
            // column" concept (the data list has Tab-driven column
            // focus; the CLI dot prompt does not). Print a hint.
            Console.WriteLine("Jump-NextInitial is a data-list command (GUI only).");
        }

        // Parse and dispatch one command line.
        // toCanonicalDisplay: format a lowercase hyphenated verb
        // ("step-record-first") into the user-visible canonical name
        // ("Step Record First") for the Command Echo marker.
        private static string toCanonicalDisplay(string sVerb)
        {
            if (string.IsNullOrEmpty(sVerb)) return sVerb;
            string[] aParts = sVerb.Split('-');
            for (int i = 0; i < aParts.Length; i++)
            {
                string p = aParts[i];
                if (p.Length == 0) continue;
                aParts[i] = char.ToUpperInvariant(p[0]) + p.Substring(1);
            }
            return string.Join("-", aParts);
        }

        // s_aCanonicalVerbs: every canonical verb that the dispatch
        // switch recognizes, in alphabetical order. Used for the
        // unique-prefix expansion feature: when the user types a
        // shorter form like "first" or "step record n", the
        // expansion helper looks for a unique canonical that starts
        // with the typed text. This list must be kept in sync with
        // the case arms in dispatch; the validation test at the top
        // of dispatch's prefix-expansion path will print a console
        // warning if a typed verb that resolveAlias would otherwise
        // map turns out to be missing here.
        //
        // The short single-character aliases ('n', '+', 'a', etc.)
        // do not appear here -- they are resolved by resolveAlias
        // ahead of prefix expansion. Aliases like "find", "config",
        // "configuration" that match a canonical name appear here
        // because they ARE the canonical (resolveAlias is a no-op
        // for them).
        private static readonly string[] s_aCanonicalVerbs = new string[]
        {
            "about-dbdo", "alternate-menu", "append-cell", "backup-database",
            "clear-bookmark", "clear-mark", "close-database",
            "configuration", "copy-cell", "copy-record", "copy-row", "copy-visiblecells",
            "edit-settings", "elevate-version",
            "enter-child", "enter-console",
            "exit-application", "exit-child", "exit-childtoroot",
            "exit-console", "export-data", "extract-regex",
            "find", "find-previous", "find-regex",
            "find-regexagain", "find-regexprevious",
            "get-field", "get-fieldname", "get-help",
            "get-property", "get-table", "get-verb",
            "import-data", "invoke-script", "invoke-sql",
            "invert-marked",
            "jump-record", "jump-recordagain", "jump-recordprevious",
            "mark-range",
            "statistics-column", "statistics-field", "statistics-longest",
            "statistics-maximum", "statistics-minimum", "statistics-shortest",
            "table-summary",
            "graphics-grid", "graphics-column", "new-record",
            "open-database", "open-filefolder", "open-website",
            "order-records", "out-file", "delete-record", "delete-record-force",
            "reset-filter", "reset-sort", "reverse-order",
            "list-bookmarks", "save-bookmark", "save-database",
            "say-cell", "say-clipboard", "say-column",
            "say-column-rest", "say-column-rest-marked",
            "say-database", "say-edited", "say-goto", "say-marked", "say-notes",
            "say-position", "say-records-rest", "say-records-rest-marked",
            "say-sortfilter", "say-status",
            "say-tables", "say-tags", "say-url", "say-prime", "say-find", "say-yield",
            "say-yieldmarked",
            "toggle-marked",
            "search-next", "search-previous",
            "select-column", "filter-records", "select-table", "select-columns",
            "edit-cell", "edit-record",
            "set-field", "set-mark", "set-markanchor",
            "set-position", "set-unmarkanchor",
            "show-history", "show-log", "show-object", "show-readme",
            "show-related", "show-schema", "show-status", "show-table",
            "sort-object",
            "jump-nextinitial",
            "step-record", "step-record-first", "step-record-last",
            "step-record-next", "step-record-prev",
            "switch-focus", "toggle-keyhelp", "toggle-readonly", "sync-session",
            "test-database", "test-driver",
            "unmark-range", "replace-column", "update-view",
            "select-window",
            "set-location", "get-location", "invoke-item", "clear-host",
        };

        // expandUniquePrefix: find the canonical verb that uniquely
        // starts with the typed text. Returns:
        //   - the canonical verb if exactly one matches
        //   - null if no canonical starts with the typed text
        //   - the sentinel "@AMBIG@<v1>;<v2>;..." if multiple match
        //     (the caller prints the list and bails)
        //
        // Match is case-insensitive. Hyphens and spaces are treated
        // as equivalent, so "step record n" and "step-record-n"
        // both expand to "step-record-next" if that is unique. The
        // typed text is the WHOLE prefix to match -- so "first"
        // matches "step-record-first"? No: it has to be a prefix
        // FROM THE START, so "first" does NOT match "step-record-
        // first" (which starts with "step"). For "first" to work,
        // the user types "first" and resolveAlias maps it directly.
        // Prefix expansion handles the case where the user types
        // the BEGINNING of a canonical verb -- "step rec n" for
        // "step-record-next", or "measure col" for "statistics-column".
        // splitArgsRespectingQuotes: split a command-line into tokens,
        // honoring double-quoted regions so that whitespace inside
        // quotes is preserved as part of a single token. Surrounding
        // quotes are stripped from each returned token; interior
        // doubled-quotes are unescaped to a single quote (matching
        // cmd.exe's convention for parameters that contain quote
        // characters). Single quotes are NOT treated specially -- only
        // double quotes group whitespace -- because users commonly
        // type single quotes inside SQL fragments and shouldn't have
        // those changes in meaning.
        //
        // Examples:
        //   find regex "Hello World"      -> ["find", "regex", "Hello World"]
        //   import "C:\Path With Space\f" -> ["import", "C:\Path With Space\f"]
        //   sql SELECT * FROM 'Cells'     -> ["sql", "SELECT", "*", "FROM", "'Cells'"]
        //   echo "She said ""hi""."       -> ["echo", "She said \"hi\"."]
        //
        // Case is preserved in every token; this routine does NOT
        // lowercase. Lowercasing is the job of resolveAlias /
        // expandUniquePrefix for command verbs, where case-
        // insensitivity matters; argument data passes through verbatim.
        private static string[] splitArgsRespectingQuotes(string sLine)
        {
            List<string> lTokens = new List<string>();
            if (string.IsNullOrEmpty(sLine)) return lTokens.ToArray();
            System.Text.StringBuilder sb = new System.Text.StringBuilder();
            bool bInQuotes = false;
            bool bHasContent = false;
            for (int i = 0; i < sLine.Length; i++)
            {
                char ch = sLine[i];
                if (ch == '"')
                {
                    if (bInQuotes && i + 1 < sLine.Length && sLine[i + 1] == '"')
                    {
                        // Doubled-quote inside a quoted region: literal quote.
                        sb.Append('"');
                        i++;
                        bHasContent = true;
                    }
                    else
                    {
                        bInQuotes = !bInQuotes;
                        bHasContent = true;   // even an empty "" yields a token
                    }
                }
                else if ((ch == ' ' || ch == '\t') && !bInQuotes)
                {
                    if (bHasContent)
                    {
                        lTokens.Add(sb.ToString());
                        sb.Length = 0;
                        bHasContent = false;
                    }
                }
                else
                {
                    sb.Append(ch);
                    bHasContent = true;
                }
            }
            if (bHasContent) lTokens.Add(sb.ToString());
            return lTokens.ToArray();
        }

        // joinArgsRespectingQuotes: opposite of splitArgsRespectingQuotes.
        // Used by tryDispatchPrefix to rebuild a remainder string after
        // peeling off the leading verb tokens. Re-quotes any token that
        // contains whitespace so the rebuilt line round-trips through
        // a subsequent splitArgsRespectingQuotes call without losing
        // structure. Embedded quotes are doubled (cmd.exe convention).
        private static string joinArgsRespectingQuotes(string[] aTokens, int iStart)
        {
            System.Text.StringBuilder sb = new System.Text.StringBuilder();
            for (int i = iStart; i < aTokens.Length; i++)
            {
                if (sb.Length > 0) sb.Append(' ');
                string sTok = aTokens[i];
                bool bNeedsQuotes = sTok.Length == 0 || sTok.IndexOfAny(
                    new char[] { ' ', '\t' }) >= 0 || sTok.IndexOf('"') >= 0;
                if (bNeedsQuotes)
                {
                    sb.Append('"');
                    sb.Append(sTok.Replace("\"", "\"\""));
                    sb.Append('"');
                }
                else
                {
                    sb.Append(sTok);
                }
            }
            return sb.ToString();
        }

        // unquote: if a single string argument is surrounded by
        // double quotes, strip them and unescape doubled quotes
        // inside; otherwise return the input unchanged. Use this in
        // command handlers that take one "rest of the line" argument
        // when the user might quote it to include spaces. For multi-
        // argument handlers, use splitArgsRespectingQuotes instead.
        // unquote: return the trailing dot-prompt argument as the user
        // typed it, honoring the Homer/Lbc/DbDo "type it verbatim" rule.
        // The value is taken literally -- no escape characters are ever
        // required. As a convenience, a value MAY be wrapped in a single
        // matching pair of double or single quotes; exactly that one
        // outer pair is removed and the inside is returned verbatim
        // (nothing inside is un-escaped). Enclosing quotes are therefore
        // optional: "John Smith", 'John Smith', and John Smith all yield
        // John Smith. Two things follow naturally, with no escaping:
        //   - To include a literal quote, type it bare. a b"c yields
        //     a b"c, because the value does not both start and end with
        //     the same quote character.
        //   - To keep a value that itself begins and ends with the same
        //     quote, or that has leading or trailing spaces, wrap it once:
        //     ""x""  yields  "x" ;   " x "  yields  (space)x(space).
        //     Wrapping again is the same rule applied, not an escape.
        // Bare leading and trailing spaces are trimmed; wrap the value in
        // quotes to preserve them. The few values that cannot be written
        // under these rules (for example a field name that contains a
        // command's own list separator) are rejected by that command with
        // an explanation, rather than by adding escape syntax.
        private static string unquote(string sArg)
        {
            if (string.IsNullOrEmpty(sArg)) return sArg;
            string s = sArg.Trim();
            if (s.Length >= 2)
            {
                char cFirst = s[0];
                if ((cFirst == '"' || cFirst == '\'') && s[s.Length - 1] == cFirst)
                    return s.Substring(1, s.Length - 2);
            }
            return s;
        }

        // resolvePathArg: extract a file path from a "rest of the line"
        // argument with optional quotes. The rule is "if the unquoted
        // line resolves to an existing file, prefer that interpretation
        // over tokenized parsing." This lets the user type
        //
        //     open database C:\My Stuff\foo.db
        //
        // without quotes when the result happens to be unambiguous.
        // If the unquoted line is not an existing file, fall back to:
        //
        //   1. If sArg is a single quoted token, strip the quotes.
        //   2. Otherwise return sArg trimmed (which the caller may
        //      then pass to a file-open API that may itself report
        //      "file not found" if the path is wrong).
        //
        // This is opt-in per handler -- the caller decides whether
        // file-existence is a meaningful test for this argument.
        private static string resolvePathArg(string sArg)
        {
            if (string.IsNullOrEmpty(sArg)) return sArg;
            string sTrim = sArg.Trim();
            string sUnquoted = unquote(sTrim);
            // Test the unquoted line as a single path. System.IO.File
            // is happy to handle either backslashes or forward slashes
            // on Windows. We test File.Exists first, then Directory.
            try
            {
                if (System.IO.File.Exists(sUnquoted)) return sUnquoted;
                if (System.IO.Directory.Exists(sUnquoted)) return sUnquoted;
            }
            catch { /* malformed paths throw; fall through to fallback */ }
            // Fallback: try tokenizing and using the first arg. If
            // the user actually meant a multi-token argument list,
            // they should quote.
            string[] aArgs = splitArgsRespectingQuotes(sTrim);
            if (aArgs.Length == 1) return aArgs[0];
            // Multiple unquoted tokens AND no existing file. Best we
            // can do: return the unquoted whole line and let the
            // caller's open attempt report a clear "not found" error.
            return sUnquoted;
        }

        // promptChoiceCli: dot-prompt equivalent of an LBC GUI pick
        // list. Prints each option with a 1-based number, marks the
        // default by trailing "(default)", and reads a line of user
        // input. Returns the 0-based index of the selected option,
        // or -1 if the user cancels or types invalid input.
        //
        // Conventions:
        //   - Empty line accepts the default.
        //   - User can type the number of the option (1..N).
        //   - User can type a unique substring of an option's label
        //     (case-insensitive); the first match wins.
        //   - "cancel", "quit", "q" returns -1.
        //
        // Output example for prompt="Choose a sort field" with options
        // ["title", "author", "year"] and iDefault=1:
        //
        //   Choose a sort field:
        //     1. title
        //     2. author (default)
        //     3. year
        //   Number or text [2]: _
        public static int promptChoiceCli(string sPrompt, IList<string> lOptions, int iDefault)
        {
            if (lOptions == null || lOptions.Count == 0) return -1;
            if (iDefault < 0 || iDefault >= lOptions.Count) iDefault = 0;
            Console.WriteLine();
            if (!string.IsNullOrEmpty(sPrompt))
            {
                Console.WriteLine(sPrompt + ":");
            }
            for (int i = 0; i < lOptions.Count; i++)
            {
                string sMark = (i == iDefault) ? " (default)" : "";
                Console.WriteLine("  " + (i + 1).ToString() + ". " + lOptions[i] + sMark);
            }
            Console.Write("Number or text [" + (iDefault + 1).ToString() + "]: ");
            string sInput = Console.ReadLine();
            if (sInput == null) return -1;
            sInput = sInput.Trim();
            if (sInput.Length == 0) return iDefault;
            if (sInput.Equals("cancel", StringComparison.OrdinalIgnoreCase)
                || sInput.Equals("quit", StringComparison.OrdinalIgnoreCase)
                || sInput.Equals("q", StringComparison.OrdinalIgnoreCase))
                return -1;
            int iNum;
            if (int.TryParse(sInput, out iNum))
            {
                if (iNum >= 1 && iNum <= lOptions.Count) return iNum - 1;
                Console.WriteLine("Out of range. Choose 1.." + lOptions.Count + ".");
                return -1;
            }
            for (int i = 0; i < lOptions.Count; i++)
            {
                if (string.Equals(lOptions[i], sInput, StringComparison.OrdinalIgnoreCase))
                    return i;
            }
            for (int i = 0; i < lOptions.Count; i++)
            {
                if (lOptions[i].IndexOf(sInput, StringComparison.OrdinalIgnoreCase) >= 0)
                    return i;
            }
            Console.WriteLine("No option matches \"" + sInput + "\".");
            return -1;
        }

        // promptYesNoCli: prints a yes/no question with a default
        // shown as a capitalized letter. Empty line accepts default;
        // "y/yes/true/1" returns true, "n/no/false/0" returns false,
        // "cancel/quit/q" returns null. Up to 3 attempts before
        // giving up.
        public static bool? promptYesNoCli(string sPrompt, bool bDefault)
        {
            for (int iAttempt = 0; iAttempt < 3; iAttempt++)
            {
                Console.Write(sPrompt + " [" + (bDefault ? "Y/n" : "y/N") + "]: ");
                string sInput = Console.ReadLine();
                if (sInput == null) return null;
                sInput = sInput.Trim().ToLowerInvariant();
                if (sInput.Length == 0) return bDefault;
                if (sInput == "y" || sInput == "yes" || sInput == "true" || sInput == "1") return true;
                if (sInput == "n" || sInput == "no" || sInput == "false" || sInput == "0") return false;
                if (sInput == "cancel" || sInput == "quit" || sInput == "q") return null;
                Console.WriteLine("Please answer y or n.");
            }
            return null;
        }

        // promptTextCli: read a single line of input with an optional
        // default. Returns the typed string, or sDefault on empty
        // input, or null on EOF/cancel.
        public static string promptTextCli(string sPrompt, string sDefault)
        {
            string sShown = (sDefault == null) ? "" : (" [" + sDefault + "]");
            Console.Write(sPrompt + sShown + ": ");
            string sInput = Console.ReadLine();
            if (sInput == null) return null;
            sInput = sInput.Trim();
            if (sInput.Length == 0) return sDefault;
            if (sInput.Equals("cancel", StringComparison.OrdinalIgnoreCase)
                || sInput.Equals("quit", StringComparison.OrdinalIgnoreCase)) return null;
            return sInput;
        }

        private static string expandUniquePrefix(string sTyped)
        {
            if (string.IsNullOrEmpty(sTyped)) return null;
            // Normalize both the typed text and each canonical to a
            // "squished key": lower-cased with every word separator
            // (space, tab, dash, underscore) removed, so dash, underline,
            // space, and no separator at all are equivalent and case is
            // ignored. "Edit Record", "edit-record", "edit_record", and
            // "editrecord" therefore all share the one key "editrecord".
            string sKey = squishKey(sTyped);
            if (sKey.Length == 0) return null;

            List<string> lMatches = new List<string>();
            foreach (string sCanon in s_aCanonicalVerbs)
            {
                string sCanonKey = squishKey(sCanon);
                if (sCanonKey.StartsWith(sKey, StringComparison.Ordinal))
                {
                    if (sCanonKey.Length == sKey.Length)
                        return sCanon; // exact squished match wins outright
                    lMatches.Add(sCanon);
                }
            }
            if (lMatches.Count == 0) return null;
            if (lMatches.Count == 1) return lMatches[0];
            // Multiple: build the sentinel so the caller can print.
            return "@AMBIG@" + string.Join(";", lMatches.ToArray());
        }

        // squishKey: lower-case and strip every word separator (space,
        // tab, dash, underscore) so command names compare equal
        // regardless of separators or capitalization. This is what lets
        // the dot prompt accept a command typed however reads most
        // naturally to the user.
        private static string squishKey(string sText)
        {
            if (string.IsNullOrEmpty(sText)) return "";
            System.Text.StringBuilder sb = new System.Text.StringBuilder(sText.Length);
            foreach (char ch in sText.ToLowerInvariant())
            {
                if (ch == ' ' || ch == '\t' || ch == '-' || ch == '_') continue;
                sb.Append(ch);
            }
            return sb.ToString();
        }

        // favoredFor: when a typed key is an ambiguous prefix of several
        // canonical commands, a few words have an obvious intended target
        // (the user's example: "edit" means Edit Record). Return that
        // favored canonical, or null to fall back to listing candidates.
        // Common single words already mapped by resolveAlias (edit, show,
        // find, sort, delete, filter, ...) need no entry here -- this is
        // only for prefixes resolveAlias does not already resolve.
        private static string favoredFor(string sSquishedKey)
        {
            switch (sSquishedKey)
            {
                case "select": return "select-columns";
                default:       return null;
            }
        }

        // tryDispatchPrefix: attempt to dispatch a line where the user
        // may have typed a unique prefix of a canonical verb, possibly
        // with extra spaces or spaces instead of hyphens. Returns true
        // if a unique expansion was found and dispatched (or printed
        // as ambiguous); false if no canonical prefix matched, leaving
        // the caller's existing "Unknown command" path intact.
        //
        // Strategy: try increasing numbers of leading tokens, joined
        // with hyphens, until a unique match is found or we run out of
        // tokens (cap at 4 leading tokens, which covers the longest
        // canonical "step-record-prev" -- 3 tokens).
        private static bool tryDispatchPrefix(string sLine)
        {
            if (string.IsNullOrEmpty(sLine)) return false;
            // v1.0.94: split with quote awareness so that
            // `find regex "Hello World"` is three tokens, and
            // rejoining the trailing arguments preserves the literal
            // spaces inside the quoted phrase. Previously a plain
            // whitespace split shattered quoted regions.
            string[] aTokens = splitArgsRespectingQuotes(sLine);
            if (aTokens.Length == 0) return false;
            int iCap = Math.Min(4, aTokens.Length);
            for (int iTake = 1; iTake <= iCap; iTake++)
            {
                string[] aPrefix = new string[iTake];
                Array.Copy(aTokens, 0, aPrefix, 0, iTake);
                string sPrefix = string.Join("-", aPrefix);
                string sExpanded = expandUniquePrefix(sPrefix);
                if (sExpanded == null) continue;
                if (sExpanded.StartsWith("@AMBIG@", StringComparison.Ordinal))
                {
                    // If we get an ambiguous match at iTake tokens,
                    // taking MORE tokens might disambiguate -- try
                    // the next size. Only act once we've exhausted
                    // token counts.
                    if (iTake < iCap) continue;
                    // Exhausted: if this prefix has a favored target
                    // (e.g. "select" -> Select Columns), take it rather
                    // than make the user choose.
                    string sFav = favoredFor(squishKey(sPrefix));
                    if (sFav != null)
                    {
                        string sFavLine = sFav;
                        if (aTokens.Length > iTake)
                            sFavLine = sFav + " " + joinArgsRespectingQuotes(aTokens, iTake);
                        if (sFavLine != sLine) { dispatch(sFavLine); return true; }
                    }
                    string sList = sExpanded.Substring("@AMBIG@".Length);
                    Console.WriteLine("Ambiguous command \"" + sPrefix + "\". Matches:");
                    foreach (string sMatch in sList.Split(';'))
                        Console.WriteLine("  " + sMatch);
                    return true; // we "handled" it by reporting ambiguity
                }
                // Unique expansion: rebuild the line with the
                // canonical verb plus the remaining tokens. Use the
                // quote-aware rejoiner so quoted strings round-trip
                // back to the next dispatch() call without losing
                // internal whitespace.
                string sNewLine = sExpanded;
                if (aTokens.Length > iTake)
                {
                    string sRest = joinArgsRespectingQuotes(aTokens, iTake);
                    sNewLine = sExpanded + " " + sRest;
                }
                // If expansion produced the same line we were given, the
                // verb is already canonical; don't re-dispatch (which
                // would loop) -- let the alias/switch path below handle it.
                if (sNewLine == sLine) return false;
                dispatch(sNewLine);
                return true;
            }
            return false;
        }

        // Public wrapper for dispatch, used by ScriptHelper.runDuoBatch
        // to execute each line of a .dbdo command-batch file as if the
        // user had typed it at the dot prompt. The wrapper is needed
        // because dispatch() is private; exposing it lets the script
        // engine reach the same code path without making the method
        // itself part of the broader public surface.
        public static void runLine(string sLine)
        {
            if (string.IsNullOrEmpty(sLine)) return;
            dispatch(sLine);
        }

        private static void dispatch(string sLine)
        {
            // '/' = raw SQL to the current database; '!' = pass-through
            // to the bundled sqlean.exe shell. Handled first so neither
            // SQL text nor a shell line is ever parsed as a DbDo command.
            // ('; <sql>' also runs SQL; '/' is the more discoverable form.)
            if (sLine.StartsWith("/"))
            {
                string sSql = sLine.Substring(1).Trim();
                if (sSql.Length == 0) Console.WriteLine("Usage: /<sql>   run SQL against the current database, e.g. /SELECT * FROM events");
                else cmdInvokeSql(sSql);
                return;
            }
            if (sLine.StartsWith("!")) { cmdSqleanShell(sLine.Substring(1).Trim()); return; }

            // Auto-space single-char shortcuts: =foo -> = foo
            string sFirst = sLine.Substring(0, 1);
            if ("+-=?*;#&^@".Contains(sFirst) && sLine.Length > 1 && sLine[1] != ' ')
                sLine = sFirst + " " + sLine.Substring(1);

            string[] aTokens = sLine.Split(new[] { ' ' }, 2, StringSplitOptions.RemoveEmptyEntries);
            string sVerb = aTokens[0].ToLowerInvariant();
            string sRest = aTokens.Length > 1 ? aTokens[1].Trim() : "";

            // v1.0.93: when the user types a multi-word line whose
            // leading words match a multi-word canonical command
            // ("edit settings", "jump previous record", "say sort
            // filter"), prefer that interpretation over single-token
            // alias resolution. Without this check, "edit settings
            // export.csv" would dispatch as edit-record (the bare
            // "edit" alias) with the rest of the line as a filename
            // argument -- wrong. tryDispatchPrefix only succeeds when
            // there is an unambiguous multi-token prefix match, so
            // single-word commands like "edit" alone still fall
            // through to the single-token alias path below.
            string[] aSpaceTokens = sLine.Split(new char[] { ' ', '\t' },
                StringSplitOptions.RemoveEmptyEntries);
            if (aSpaceTokens.Length >= 2 && tryDispatchPrefix(sLine)) return;

            // Single-token (or alias) resolution. Aliases win first, so
            // the short forms (n, p, e, g, +, -, ;, ...) keep priority
            // over prefix matching. If the verb is not a known alias,
            // resolve it as a canonical command name with separators and
            // case ignored, so "order-records", "order_records",
            // "orderrecords", and the unique prefix "ord" all reach it.
            string sResolved = resolveAlias(sVerb);
            if (sResolved != sVerb)
            {
                sVerb = sResolved;
            }
            else
            {
                string sExp = expandUniquePrefix(sVerb);
                if (sExp != null && !sExp.StartsWith("@AMBIG@", StringComparison.Ordinal))
                {
                    sVerb = sExp;
                }
                else if (sExp != null)
                {
                    string sFav = favoredFor(squishKey(sVerb));
                    if (sFav != null)
                    {
                        sVerb = sFav;
                    }
                    else
                    {
                        Console.WriteLine("Ambiguous command \"" + sVerb + "\". Matches:");
                        foreach (string sMatch in sExp.Substring("@AMBIG@".Length).Split(';'))
                            Console.WriteLine("  " + sMatch);
                        return;
                    }
                }
                // sExp == null: leave sVerb unchanged; the switch's
                // default branch reports it as an unknown command.
            }

            // Command Echo is GUI-only. In the dot prompt the user's
            // own typed line and the command's stdout output are
            // already plenty of confirmation; an additional canonical-
            // name marker line just slows down screen-reader review of
            // recent output.

            switch (sVerb)
            {
                case "step-record":       cmdStepRecord(sRest);     break;
                case "step-record-first": cmdStepRecord("first");   break;
                case "step-record-last":  cmdStepRecord("last");    break;
                case "step-record-next":  cmdStepRecord("next " + sRest);     break;
                case "step-record-prev":  cmdStepRecord("previous " + sRest); break;
                case "set-position":     cmdSetPosition(sRest);    break;
                case "show-object":      cmdShowObject(sRest);     break;
                case "show-table":       cmdShowTable(sRest);      break;
                case "show-schema":      cmdShowSchema(sRest);     break;
                case "show-status":      printRowSummary();        break;
                // Speech-only commands. Their GUI handlers push
                // through LiveRegion; the CLI equivalents print to
                // Console since there's no live region in a console.
                case "say-status":       cmdSayStatus();           break;
                case "say-path":         cmdSayPath();             break;
                case "say-yield":        cmdSayYield();            break;
                case "say-tables":       cmdSayTables();           break;
                case "say-marked":       cmdSayMarked();           break;
                case "say-edited":       cmdSayEdited();         break;
                case "say-url":          cmdSayUrl();              break;
                case "say-prime":        cmdSayPrime();            break;
                case "say-find":         cmdSayFind();             break;
                case "say-goto":         cmdSayGoto();             break;
                case "say-notes":        cmdSayNotes();            break;
                case "say-tags":         cmdSayTags();             break;
                case "say-column":       cmdSayColumn();           break;
                case "say-position":     cmdSayPosition();         break;
                case "say-clipboard":    cmdSayClipboard();        break;
                case "say-sortfilter":   cmdSaySortFilter();       break;
                case "say-yieldmarked":  cmdSayYieldMarked();      break;
                case "toggle-marked":    cmdToggleMarked();        break;
                // Action commands new this turn.
                case "extract-regex":    cmdExtractRegex(sRest);   break;
                case "copy-visiblecells": cmdCopyRow();            break;
                case "copy-row":         cmdCopyRow();             break;  // backward-compat alias
                case "append-cell":      cmdAppendCell();          break;
                case "copy-cell":        cmdCopyCell();            break;
                case "jump-nextinitial": cmdJumpNextInitial(); break;
                case "get-field":        cmdGetField(sRest);       break;
                case "set-field":        cmdSetField(sRest);       break;
                case "edit-cell":        cmdSetCell(sRest);        break;
                case "statistics-column":   cmdMeasureColumn();       break;
                case "graphics-column":         cmdNewPlot(sRest);        break;
                case "edit-settings": cmdEditConfiguration(); break;
                case "configuration":    cmdEditConfiguration();   break; // friendly alias
                case "set-markanchor":   cmdSetMarkAnchor();       break;
                case "set-unmarkanchor": cmdSetUnmarkAnchor();     break;
                case "mark-range":       cmdMarkRange(true);       break;
                case "unmark-range":     cmdMarkRange(false);      break;
                case "jump-record":      cmdFindRecord(sRest);     break;
                case "jump-recordagain": cmdFindAgain();           break;
                case "jump-recordprevious": cmdFindPrevious();    break;
                case "find":             cmdFindRecord(sRest);     break; // CLI Find shares the ADO-Find handler
                case "find-previous":    cmdFindPrevious();        break;
                case "search-next":      cmdFindAgain();           break;
                case "search-previous":  cmdFindPrevious();        break;
                case "find-regex":       cmdFindRegex(sRest);      break;
                case "find-regexagain":  cmdFindRegexAgain();      break;
                case "find-regexprevious": cmdFindRegexPrevious(); break;
                case "filter-records":    cmdSelectRecord(sRest);   break;
                case "select-column":    cmdSelectColumn(sRest);   break;
                case "reset-filter":     cmdResetFilter();         break;
                case "sort-object":      cmdSortObject(sRest);     break;
                case "order-records":    cmdOrderRecords(sRest);   break;
                case "reverse-order":    cmdReverseOrder(sRest);   break;
                case "reset-sort":       cmdResetSort();           break;
                case "new-record":       cmdNewRecord();           break;
                case "edit-record":      cmdSetRecord();           break;
                case "delete-record":    cmdRemoveRecord();        break;
                case "copy-record":      cmdCopyRecord();          break;
                case "select-table":     cmdSelectTable(sRest);    break;
                case "table":            cmdTable(sRest);          break;
                case "get-table":        cmdGetTable();            break;
                case "get-property":     cmdGetProperty();         break;
                case "set-mark":         cmdSetMark(true);         break;
                case "clear-mark":       cmdSetMark(false);        break;
                case "show-related":     Console.WriteLine("(Show-Related is GUI-only in this build)"); break;
                case "enter-child":      cmdEnterChild();          break;
                case "exit-child":       cmdExitChild();           break;
                case "exit-childtoroot": cmdExitChildToRoot();     break;
                case "replace-column":     Console.WriteLine("(Update-Column is GUI-only in this build)"); break;
                case "table-summary":    cmdMeasureTable();        break;
                case "graphics-grid":        cmdNewChart(sRest);       break;
                case "statistics-field":    cmdMeasureField(sRest);   break;
                case "statistics-longest":  cmdMeasureLength(sRest, true);  break;
                case "statistics-shortest": cmdMeasureLength(sRest, false); break;
                case "statistics-maximum":  cmdMeasureExtreme(sRest, true); break;
                case "statistics-minimum":  cmdMeasureExtreme(sRest, false); break;
                case "get-fieldname":    cmdGetFieldNames();       break;
                case "test-database":    cmdTestDatabase();        break;
                case "test-driver":      cmdTestDriver();          break;
                case "update-view":      cmdUpdateView();          break;
                case "save-database":  cmdSaveAs(sRest);         break;
                case "backup-database":  cmdSaveAs(sRest);         break;
                case "export-data":      cmdExportData(sRest);     break;
                case "import-data":      cmdImportData(sRest);     break;
                case "open-database":    cmdOpenDatabase(sRest);   break;
                case "close-database":   cmdCloseDatabase();       break;
                case "invoke-sql":       cmdInvokeSql(sRest);      break;
                case "save-bookmark":    cmdSaveBookmark();        break;
                case "list-bookmarks":   cmdListBookmarks();       break;
                case "clear-bookmark":   cmdClearBookmark();       break;
                case "get-help":         cmdGetHelp(sRest);         break;
                case "show-history":     cmdShowHistory();          break;
                case "get-verb":         cmdGetVerb();             break;
                case "alternate-menu":   cmdAlternateMenu();       break;
                case "toggle-keyhelp": cmdToggleKeyHelp(sRest); break;
                case "toggle-readonly":  cmdToggleReadOnly(sRest); break;
                case "toggle-read-only": cmdToggleReadOnly(sRest); break;
                case "read-only":        cmdToggleReadOnly(sRest); break;
                case "readonly":         cmdToggleReadOnly(sRest); break;
                case "sync-session":     printRowSummary();        break;
                case "out-file":         cmdOutFile(sRest);        break;
                case "invoke-script":    cmdInvokeScript(sRest);   break;
                case "exit-console":     bShouldExit = true;       break;
                case "exit-application": cmdExitApplication();      break;
                case "switch-focus":     cmdSwitchFocus();          break;
                case "select-window":    cmdSelectWindow(sRest);    break;
                case "set-location":     cmdSetLocation(sRest);     break;
                case "get-location":     cmdGetLocation();          break;
                case "invoke-item":      cmdInvokeItem(sRest);      break;
                case "clear-host":       cmdClearHost();            break;
                case "about-dbdo":      cmdAboutDbDo();          break;
                case "elevate-version":  cmdElevateVersion();      break;
                case "show-readme":      cmdShowReadme();          break;
                case "show-log":         cmdShowLog();             break;
                case "open-website":     cmdOpenWebsite();         break;
                case "open-filefolder":  cmdOpenFileFolder();      break;
                case "command-prompt":   cmdCommandPrompt();       break;
                case "enter-console":    Console.WriteLine("(already at the dot prompt)"); break;
                default:
                    // Prefix expansion: the user may have typed a
                    // short unique prefix of a canonical verb, or
                    // used spaces instead of hyphens. Try expansion
                    // before giving up.
                    if (tryDispatchPrefix(sLine)) return;
                    if (tryInvokeMenuCommand(sLine)) return;
                    Console.WriteLine("Unknown command: " + sVerb);
                    Console.WriteLine("Type 'help' for the command list.");
                    break;
            }
        }

        // Switch-Focus: bring the GUI form (if running in Both mode)
        // to the foreground. The dot prompt's console window remains
        // open; Alt+Tab returns to it. This is the dot-prompt
        // counterpart of Enter-Console (Control+\\) in the GUI.
        //
        // Internally calls SetForegroundWindow on the form's HWND
        // (declared earlier in this class). In CLI-only mode there is
        // no GUI; the command prints a notice and returns.
        private static void cmdSwitchFocus()
        {
            if (frm == null || frm.IsDisposed)
            {
                Console.WriteLine("Switch-Focus: no GUI form is available (CLI-only mode).");
                return;
            }
            try
            {
                IntPtr hWnd = frm.Handle;
                if (hWnd != IntPtr.Zero) SetForegroundWindow(hWnd);
            }
            catch (Exception ex)
            {
                Console.WriteLine("Switch-Focus failed: " + ex.Message);
            }
        }

        // cmdSelectWindow: dot-prompt equivalent of F4 (Current Windows).
        // With no argument it lists the open database windows and prompts
        // for one; with an argument it matches a window by title -- typed
        // verbatim, case-insensitive, exact match preferred then a
        // contains match. The chosen window is activated AND the console
        // is rebound to it (frm), so every later command acts on that
        // window's database -- the context-setting the user asked for.
        private static void cmdSelectWindow(string sArg)
        {
            if (frm == null || frm.IsDisposed)
            {
                Console.WriteLine("Select-Window: no GUI windows are available (CLI-only mode).");
                return;
            }
            DbDoFrame frame = DbDoFrame.frame;
            if (frame == null) { Console.WriteLine("No window frame available."); return; }
            List<string> lTitles = frame.windowTitles();
            if (lTitles.Count == 0) { Console.WriteLine("No windows open."); return; }
            string sWanted = unquote(sArg ?? "");
            string sChosen = null;
            if (sWanted.Length > 0)
            {
                foreach (string sT in lTitles)
                    if (string.Equals(sT, sWanted, StringComparison.OrdinalIgnoreCase)) { sChosen = sT; break; }
                if (sChosen == null)
                    foreach (string sT in lTitles)
                        if (sT.IndexOf(sWanted, StringComparison.OrdinalIgnoreCase) >= 0) { sChosen = sT; break; }
                if (sChosen == null)
                {
                    Console.WriteLine("No window matches: " + sWanted);
                    Console.WriteLine("Open: " + string.Join(", ", lTitles.ToArray()));
                    return;
                }
            }
            else
            {
                int iChoice = promptChoiceCli("Current Windows", lTitles, 0);
                if (iChoice < 0) { Console.WriteLine("Cancelled."); return; }
                sChosen = lTitles[iChoice];
            }
            try
            {
                // Find the target child by its title up front so the
                // rebind does not depend on the timing of window
                // activation events.
                DbDoForm frmTarget = null;
                foreach (Form f in frame.MdiChildren)
                {
                    DbDoForm fd = f as DbDoForm;
                    if (fd != null && fd.Text == sChosen) { frmTarget = fd; break; }
                }
                frame.activateByTitle(sChosen);
                if (frmTarget != null && !frmTarget.IsDisposed) frm = frmTarget;
                refresh();
                Console.WriteLine("Current window: " + sChosen);
                printRowSummary();
            }
            catch (Exception ex) { Console.WriteLine("Error: " + ex.Message); }
        }

        // cmdSetLocation: dot-prompt cd. Change the process working
        // directory so later relative paths (export, save-as, open,
        // invoke-item) resolve against it. PowerShell Set-Location;
        // aliases cd, chdir, sl. With no argument, prints the current
        // directory. No GUI peer.
        private static void cmdSetLocation(string sArg)
        {
            string sPath = resolvePathArg(sArg ?? "");
            if (sPath.Length == 0) { Console.WriteLine(System.IO.Directory.GetCurrentDirectory()); return; }
            try
            {
                System.IO.Directory.SetCurrentDirectory(sPath);
                Console.WriteLine(System.IO.Directory.GetCurrentDirectory());
            }
            catch (Exception ex) { Console.WriteLine("Error: " + ex.Message); }
        }

        // cmdGetLocation: dot-prompt pwd / cwd. Print the current working
        // directory. PowerShell Get-Location; aliases pwd, cwd, gl.
        private static void cmdGetLocation()
        {
            try { Console.WriteLine(System.IO.Directory.GetCurrentDirectory()); }
            catch (Exception ex) { Console.WriteLine("Error: " + ex.Message); }
        }

        // cmdInvokeItem: open a verbatim file, folder, or URL in its
        // default Windows program (the shell "open" verb), the way
        // double-clicking it would. PowerShell Invoke-Item; aliases
        // start, ii, open-file, launch. This lets a script create a file
        // and then open it for viewing as its final step. The plain
        // "open" verb stays bound to Open-Database, so a database loads
        // into DbDo rather than launching in another program.
        private static void cmdInvokeItem(string sArg)
        {
            string sTarget = unquote(sArg ?? "");
            if (sTarget.Length == 0) { Console.WriteLine("Invoke-Item requires a file, folder, or URL."); return; }
            try
            {
                ComAutomation.shellOpen(sTarget);
                Console.WriteLine("Opened " + sTarget);
            }
            catch (Exception ex) { Console.WriteLine("Error: " + ex.Message); }
        }

        // cmdClearHost: clear the console screen. PowerShell Clear-Host;
        // aliases cls, clear. No GUI peer.
        private static void cmdClearHost()
        {
            try { Console.Clear(); } catch { }
        }

        // About-DbDo: print the version banner to the CLI. Mirrors
        // the GUI About dialog. Always available.
        private static void cmdAboutDbDo()
        {
            Console.WriteLine();
            Console.WriteLine("DbDo " + BuildInfo.VersionString);
            Console.WriteLine("Dual-interface (GUI + CLI) database manager.");
            Console.WriteLine("Designed for keyboard productivity and screen-reader accessibility.");
            Console.WriteLine("Project: https://github.com/JamalMazrui/DbDo");
            Console.WriteLine();
        }

        // Elevate-Version: check GitHub for a newer DbDo_setup.exe,
        // download it if found, and run the installer. The download url is the
        // stable "latest release" GitHub redirect; the version check
        // queries the GitHub Releases API for the tag of the latest
        // release. Inno Setup's installer detects a running DbDo
        // and offers to close it, so we can run the installer
        // without first stopping the current process.
        private static void cmdElevateVersion()
        {
            ElevateVersion.run();
        }

        private static void cmdShowReadme()
        {
            string sPath = System.IO.Path.Combine(
                System.IO.Path.GetDirectoryName(Application.ExecutablePath) ?? ".",
                "README.htm");
            if (!System.IO.File.Exists(sPath)) { Console.WriteLine("README.htm not found at " + sPath); return; }
            try { System.Diagnostics.Process.Start(sPath); Console.WriteLine("Opened README.htm"); }
            catch (Exception ex) { Console.WriteLine("Could not open README.htm: " + ex.Message); }
        }

        private static void cmdShowLog()
        {
            string sPath = DbDoLog.getLogPath();
            Console.WriteLine("Log: " + sPath);
        }

        private static void cmdOpenWebsite()
        {
            try { System.Diagnostics.Process.Start("https://github.com/JamalMazrui/DbDo"); Console.WriteLine("Opened DbDo website."); }
            catch (Exception ex) { Console.WriteLine("Open-WebSite failed: " + ex.Message); }
        }

        private static void cmdOpenFileFolder()
        {
            if (db == null || !db.isOpen() || string.IsNullOrEmpty(db.filePath))
            { Console.WriteLine("Open-FileFolder: no database is open."); return; }
            try
            {
                string sArg = "/select,\"" + db.filePath + "\"";
                System.Diagnostics.Process.Start("explorer.exe", sArg);
                Console.WriteLine("Opened Explorer at " + db.filePath);
            }
            catch (Exception ex) { Console.WriteLine("Open-FileFolder failed: " + ex.Message); }
        }

        // cmdCommandPrompt: console form of the Command Prompt command.
        // Opens cmd.exe with its working directory set to the open
        // database's folder (or the user's folder when nothing is open).
        private static void cmdCommandPrompt()
        {
            try
            {
                string sPath = (db != null && db.isOpen()) ? db.filePath : null;
                string sDir = (!string.IsNullOrEmpty(sPath) && System.IO.File.Exists(sPath))
                    ? System.IO.Path.GetDirectoryName(sPath)
                    : Environment.GetFolderPath(Environment.SpecialFolder.UserProfile);
                System.Diagnostics.ProcessStartInfo psi =
                    new System.Diagnostics.ProcessStartInfo("cmd.exe");
                psi.WorkingDirectory = sDir;
                psi.UseShellExecute = true;
                System.Diagnostics.Process.Start(psi);
                Console.WriteLine("Opened command prompt at " + sDir);
            }
            catch (Exception ex) { Console.WriteLine("Command-Prompt failed: " + ex.Message); }
        }

        // Enter-Child / Exit-Child from the dot prompt. The actual
        // drill-down logic lives on the form (because it needs the
        // ListView, the listbox dialog for picking among multiple
        // child tables, and access to the per-form drill stack); the
        // console marshals to the form's GUI thread via the public
        // invokeEnterChild / invokeExitChild entry points.
        //
        // In CLI-only mode there is no form, so these commands print
        // a notice and return without doing anything. (A CLI-only
        // implementation is possible but adds another GUI dialog
        // path to maintain; defer until there's demand.)
        private static void cmdEnterChild()
        {
            DbDoForm frmContext = contextForm();
            if (frmContext == null)
            {
                Console.WriteLine("Enter-Child: not available in CLI-only mode.");
                return;
            }
            int iDepth = frmContext.invokeEnterChild();
            if (iDepth > 0)
                Console.WriteLine("Drilled into child table. Stack depth: " + iDepth + ".");
            printRowSummary();
        }

        private static void cmdExitChild()
        {
            DbDoForm frmContext = contextForm();
            if (frmContext == null)
            {
                Console.WriteLine("Exit-Child: not available in CLI-only mode.");
                return;
            }
            if (!frmContext.hasDrillStack())
            {
                Console.WriteLine("Exit-Child: drill stack is empty. Use Enter-Child first.");
                return;
            }
            int iDepth = frmContext.invokeExitChild();
            Console.WriteLine("Returned to parent table. Stack depth: " + iDepth + ".");
            printRowSummary();
        }

        // Exit-ChildToRoot: pop all the way back to the topmost
        // parent. Calls the form's invokeExitChildToRoot via the
        // marshalled method below.
        private static void cmdExitChildToRoot()
        {
            DbDoForm frmContext = contextForm();
            if (frmContext == null)
            {
                Console.WriteLine("Exit-ChildToRoot: not available in CLI-only mode.");
                return;
            }
            if (!frmContext.hasDrillStack())
            {
                Console.WriteLine("Exit-ChildToRoot: drill stack is empty.");
                return;
            }
            int iPopped = frmContext.invokeExitChildToRoot();
            Console.WriteLine("Returned to root (" + iPopped + " level" + (iPopped == 1 ? "" : "s") + ").");
            printRowSummary();
        }

        // Exit-Application: shut down the entire DbDo process,
        // not just the dot prompt. Aliased to 'quit' / 'q' at the
        // dot prompt. The 'exit' / 'x' / 'bye' aliases still mean
        // "close the dot prompt and return to the GUI" via
        // exit-console.
        //
        // In GUI/Both mode the form's Close() runs on the GUI
        // thread (we marshal via Invoke); closing the form
        // terminates the message loop and the process. In CLI-only
        // mode there is no form, so we set bShouldExit and call
        // Application.Exit() to break the Program.Main message
        // pump if one is running.
        private static void cmdExitApplication()
        {
            Console.WriteLine("Exiting DbDo.");
            bShouldExit = true;  // break the dot-prompt input loop
            try
            {
                if (frm != null && !frm.IsDisposed)
                {
                    // Close the form on its own thread.
                    if (frm.InvokeRequired)
                        frm.BeginInvoke(new Action(() => { try { frm.Close(); } catch { } }));
                    else
                        frm.Close();
                }
                else
                {
                    // CLI-only mode.
                    try { Application.Exit(); } catch { }
                }
            }
            catch (Exception ex)
            {
                Console.WriteLine("Exit-Application failed: " + ex.Message);
            }
        }

        // Out-File: redirect future console output to a file, or
        // restore to the screen. Inspired by SQLite's '.output FILE'
        // / '.output stdout', psql's '\o file', and PowerShell's
        // Out-File cmdlet.
        //
        //   Out-File path.txt        Send all subsequent output to path.txt
        //   Out-File -a path.txt     Append rather than overwrite
        //   Out-File stdout          Restore output to the screen (the bare word "stdout")
        //   Out-File                 Show the current redirection target
        //
        // Implementation: when a file is set, Console.SetOut to a
        // TextWriter that tees to both the file and the original
        // stdout. The user sees the same text they would see at
        // the console AND the file gets a copy -- this matches
        // PowerShell's Out-File behavior more naturally than the
        // SQLite/psql "silent file capture" mode, and helps the
        // screen-reader user follow what's happening.
        private static System.IO.TextWriter originalStdout = null;
        private static System.IO.StreamWriter outFileWriter = null;
        private static string sOutFilePath = "";

        private static void cmdOutFile(string sArg)
        {
            string sExpr = sArg.Trim();
            if (sExpr.Length == 0)
            {
                if (sOutFilePath.Length == 0)
                    Console.WriteLine("Out-File: not currently redirected.");
                else
                    Console.WriteLine("Out-File: " + sOutFilePath);
                Console.WriteLine("Usage: Out-File path  |  Out-File -a path  |  Out-File stdout");
                return;
            }
            if (string.Equals(sExpr, "stdout", StringComparison.OrdinalIgnoreCase))
            {
                closeOutFile();
                Console.WriteLine("Out-File: restored to stdout.");
                return;
            }
            bool bAppend = false;
            if (sExpr.StartsWith("-a ", StringComparison.OrdinalIgnoreCase)
                || sExpr.StartsWith("-append ", StringComparison.OrdinalIgnoreCase))
            {
                bAppend = true;
                int iSpace = sExpr.IndexOf(' ');
                sExpr = sExpr.Substring(iSpace + 1).Trim();
            }
            if (sExpr.Length == 0) { Console.WriteLine("Out-File: missing path."); return; }

            try
            {
                closeOutFile();
                if (originalStdout == null) originalStdout = Console.Out;
                outFileWriter = new System.IO.StreamWriter(sExpr, bAppend, System.Text.Encoding.UTF8);
                outFileWriter.AutoFlush = true;
                sOutFilePath = sExpr;
                // Tee writer: every write goes to both the file and the
                // original screen output, so the user sees what they're
                // capturing as they capture it.
                System.IO.TextWriter teeWriter = new TeeWriter(originalStdout, outFileWriter);
                Console.SetOut(teeWriter);
                Console.WriteLine("Out-File: " + (bAppend ? "appending to " : "writing to ") + sExpr);
            }
            catch (Exception ex)
            {
                Console.WriteLine("Out-File failed: " + ex.Message);
                closeOutFile();
            }
        }

        private static void closeOutFile()
        {
            try
            {
                if (originalStdout != null) Console.SetOut(originalStdout);
            }
            catch { }
            try { if (outFileWriter != null) outFileWriter.Dispose(); } catch { }
            outFileWriter = null;
            sOutFilePath = "";
        }

        // TextWriter that forwards Write/WriteLine to two underlying
        // writers. Used by Out-File for screen-and-file tee output.
        private class TeeWriter : System.IO.TextWriter
        {
            private System.IO.TextWriter evA;
            private System.IO.TextWriter branchWriter;
            public TeeWriter(System.IO.TextWriter a, System.IO.TextWriter b) { evA = a; branchWriter = b; }
            public override System.Text.Encoding Encoding { get { return evA.Encoding; } }
            public override void Write(char ch) { try { evA.Write(ch); } catch { } try { branchWriter.Write(ch); } catch { } }
            public override void Write(string s) { try { evA.Write(s); } catch { } try { branchWriter.Write(s); } catch { } }
            public override void WriteLine(string s) { try { evA.WriteLine(s); } catch { } try { branchWriter.WriteLine(s); } catch { } }
            public override void Flush() { try { evA.Flush(); } catch { } try { branchWriter.Flush(); } catch { } }
        }

        // Invoke-Script path.txt: read commands from a file and
        // execute each non-blank, non-comment line as if typed at
        // the dot prompt. SQLite calls this '.read FILE', psql
        // calls it '\i FILE'. PowerShell-canonical name uses the
        // Lifecycle 'Invoke' verb plus the 'Script' noun.
        //
        // Lines starting with '#' or ';' are treated as comments.
        // The script can call any dot-prompt command, including
        // SQL via Invoke-Sql. An error in one line is reported
        // but does not stop the script (matches psql default).
        private static void cmdInvokeScript(string sArg)
        {
            string sPath = sArg.Trim();
            if (sPath.Length == 0)
            {
                Console.WriteLine("Invoke-Script path     run commands from path");
                Console.WriteLine("Aliases: read, script, i");
                return;
            }
            if (!System.IO.File.Exists(sPath))
            {
                Console.WriteLine("Invoke-Script: file not found: " + sPath);
                return;
            }
            string[] aLines;
            try { aLines = System.IO.File.ReadAllLines(sPath); }
            catch (Exception ex) { Console.WriteLine("Invoke-Script: read failed: " + ex.Message); return; }

            int iLine = 0;
            int iRun = 0;
            int iErr = 0;
            foreach (string sRaw in aLines)
            {
                iLine++;
                string sCmd = sRaw.Trim();
                if (sCmd.Length == 0) continue;
                if (sCmd.StartsWith("#") || sCmd.StartsWith(";")) continue;
                Console.WriteLine("[line " + iLine + "] " + sCmd);
                try { dispatch(sCmd); iRun++; }
                catch (Exception ex)
                {
                    Console.WriteLine("  error at line " + iLine + ": " + ex.Message);
                    iErr++;
                }
            }
            Console.WriteLine(string.Format("Invoke-Script done: {0} command(s), {1} error(s).", iRun, iErr));
        }

        // resolveAlias: translate a typed verb to its canonical
        // PowerShell Verb-Noun name. Three rules govern this table:
        //
        //   (1) Every alias here matches one in dbDot.vbs (the
        //       VBScript predecessor) unless it's a single-letter
        //       or single-word shorthand that fits the broader
        //       DbDo / PowerShell idiom.
        //   (2) No vowel-dropped abbreviations: "previous" yes,
        //       "prev" no; "delete" yes, "del" no; "display" yes,
        //       "disp" no; "properties" yes, "props" no;
        //       "average" yes, "avg" no.
        //   (3) Legacy dBASE aliases that overlap with a dbDot
        //       alias are dropped (e.g. dBASE's "locate" gives
        //       way to dbDot's "find").
        //
        // The result is a small, predictable set of aliases that
        // a dbDot user can already type and that don't ask the
        // newcomer to memorize cryptic shorthand.
        // s_dSquishToMenu: squished command name -> the GUI menu item
        // that runs it, built once on first use from KeyMap's registry.
        private static Dictionary<string, ToolStripMenuItem> s_dSquishToMenu;

        // menuItemForSquish: the menu item whose canonical command name
        // squishes to sKey, or null. This is what lets the dot prompt
        // reach any GUI menu command by name with separators and case
        // ignored -- "Database Summary", "database-summary", and
        // "databasesummary" all resolve to the same item.
        private static ToolStripMenuItem menuItemForSquish(string sKey)
        {
            if (string.IsNullOrEmpty(sKey)) return null;
            if (s_dSquishToMenu == null)
            {
                Dictionary<string, ToolStripMenuItem> d = new Dictionary<string, ToolStripMenuItem>();
                foreach (KeyValuePair<ToolStripMenuItem, string> kv in KeyMap.dMenuToCommand)
                {
                    string sK = squishKey(kv.Value);
                    if (sK.Length > 0 && !d.ContainsKey(sK)) d[sK] = kv.Key;
                }
                s_dSquishToMenu = d;
            }
            ToolStripMenuItem mi;
            return s_dSquishToMenu.TryGetValue(sKey, out mi) ? mi : null;
        }

        // tryInvokeMenuCommand: last-resort resolution. Squish the leading
        // words of the line and, if they name a GUI menu command, run it
        // by clicking that menu item on the UI thread. This completes the
        // "type any menu command at the dot prompt" philosophy: separators
        // and case never matter before the parameter. PerformClick takes
        // no argument, so a command that needs input opens its usual
        // dialog and any trailing words are ignored. Console-backed
        // commands never reach here -- the normal resolver matches them
        // first, so their keyboard-friendly console forms still win.
        private static bool tryInvokeMenuCommand(string sLine)
        {
            if (frm == null || frm.IsDisposed) return false;
            string[] aTokens = sLine.Split(new char[] { ' ', '\t' },
                StringSplitOptions.RemoveEmptyEntries);
            if (aTokens.Length == 0) return false;
            // Longest leading run first, so a multi-word menu name wins
            // over a shorter prefix of it.
            for (int iTake = aTokens.Length; iTake >= 1; iTake--)
            {
                string[] aLead = new string[iTake];
                Array.Copy(aTokens, 0, aLead, 0, iTake);
                ToolStripMenuItem mi = menuItemForSquish(squishKey(string.Join(" ", aLead)));
                if (mi != null)
                {
                    try { frm.Invoke(new Action(delegate { if (mi.Enabled) mi.PerformClick(); })); }
                    catch (Exception ex) { Console.WriteLine("Error: " + ex.Message); }
                    return true;
                }
            }
            return false;
        }

        private static string resolveAlias(string sVerb)
        {
            switch (sVerb)
            {
                // Filesystem and console utilities (CLI-only; no GUI peer)
                case "cd": case "chdir": case "sl":   return "set-location";
                case "pwd": case "cwd": case "gl":    return "get-location";
                case "start": case "ii": case "open-file": case "launch":
                                                     return "invoke-item";
                case "cls": case "clear":             return "clear-host";
                // Navigation
                case "n": case "+": case "next":     return "step-record-next";
                case "p": case "-": case "previous": return "step-record-prev";
                case "first":                        return "step-record-first";
                case "last":                         return "step-record-last";
                case "skip":                         return "step-record"; // dbDot SKIP n is retained -- the verb has no clean replacement.
                case "g": case "go": case "goto":    return "set-position";
                // Display
                case "show":                         return "show-object";
                case "l": case "list":               return "show-table";
                case "schema":                       return "show-schema";
                case "status": case "?":             return "show-status";
                // Speech-only family (Query menu). Each speaks a
                // piece of state without changing recordset position.
                // Note: 'yield' is NOT an alias for say-yield -- it
                // remains the long-standing alias for measure-table
                // (the dbDot heritage). Users get the speech-only
                // version by typing 'say-yield' literally; the
                // 'count'/'y'/'yield' chain gives the multi-line
                // verbose count via measure-table.
                case "path":                         return "say-path";
                case "tables-list":                  return "say-tables";
                case "marked-list":                  return "say-marked";
                case "edited":                       return "say-edited";
                case "notes":                        return "say-notes";
                case "tags":                         return "say-tags";
                case "position":                     return "say-position";
                case "sort-filter":                  return "say-sortfilter";
                case "yield-marked":                 return "say-yieldmarked";
                // Action commands new this turn.
                case "extract":                      return "extract-regex";
                case "copy-row": case "copy-row-tsv": return "copy-visiblecells";
                // Edit
                case "a": case "&": case "add": case "append":
                                                     return "new-record";
                case "e": case "^": case "edit": case "modify":
                                                     return "edit-record";
                case "d": case "delete": return "delete-record";
                case "copy":                         return "copy-record";
                // Search families. Three distinct families with
                // dedicated CLI canonicals:
                //   find  = substring across all columns
                //   jump  = substring scoped to one column (legacy
                //           dbDot SEEK / dBASE FIND idiom)
                //   regex = .NET regex across all columns
                // F3 / Shift+F3 in the GUI map to search-next /
                // search-previous; at the dot prompt those are also
                // typeable verbs that repeat whichever family was
                // last invoked.
                case "f": case "find":               return "find";
                case "find-previous":                return "find-previous";
                case "j": case "jump":               return "jump-record";
                case "seek":                         return "jump-record"; // dbDot SEEK
                case "find-next":                    return "search-next"; // legacy alias
                case "find-again":                   return "search-next";
                case "again":                        return "search-next";
                case "previous-match": case "prev-match":
                                                     return "search-previous";
                case "regex":                        return "find-regex";
                case "regex-previous":               return "find-regexprevious";
                // Filter / sort / column
                case "filter": case "where":         return "filter-records";
                case "columns":                      return "select-column";
                case "clear-filter":                 return "reset-filter";
                case "sort": case "order":           return "order-records";
                case "desc": case "descending":      return "reverse-order";
                // Tables
                // NB: "table" is NOT aliased here -- it is its own
                // canonical command (cmdTable), the MDI-window-aware
                // context switch. "open-table"/"select-view" remain
                // in-place recordset swaps via select-table.
                case "open-table":                   return "select-table";
                case "select-view":                  return "select-table";
                case "tables":                       return "get-table";
                case "properties":                   return "get-property";
                // Marks (dbDot mark / unmark)
                case "m": case "mark":               return "set-mark";
                case "u": case "unmark":             return "clear-mark";
                case "related":                      return "show-related";
                // Parent-child drill (DbDo addition; not in dbDot,
                // but all single English words)
                case "zoom": case "drill": case "enter":
                                                     return "enter-child";
                case "unzoom": case "back":          return "exit-child";
                case "root": case "exit-to-root":    return "exit-childtoroot";
                // SQL execution: dbDot uses "exec" and ";"
                case "exec": case ";": case "sql":   return "invoke-sql";
                // Measurements: dbDot has count, yield, y, max, min,
                // longest, shortest; sum and average go to Measure-Field.
                case "count": case "y": case "yield":
                                                     return "table-summary";
                case "longest":                      return "statistics-longest";
                case "shortest":                     return "statistics-shortest";
                case "max": case "maximum":          return "statistics-maximum";
                case "min": case "minimum":          return "statistics-minimum";
                case "sum":                          return "statistics-field"; // dbDot SUM
                case "average":                      return "statistics-field"; // dbDot AVERAGE
                case "fields":                       return "get-fieldname";
                // File / driver
                case "test":                         return "test-database";
                case "drivers":                      return "test-driver";
                case "requery": case "refresh":      return "update-view"; // dbDot REQUERY
                case "backup":                       return "backup-database";
                case "export": case "ex":            return "export-data"; // dbDot ex
                case "open":                         return "open-database";
                case "close":                        return "close-database";
                // Bookmarks
                case "bookmark":                     return "save-bookmark";
                // Help / verbs / Key Help
                case "help":                         return "get-help";
                case "history":                      return "show-history";
                case "verbs":                        return "get-verb";
                // Key Help mode aliases. The canonical verb is
                // toggle-keyhelp; common spellings all map to it.
                case "trace": case "trace-command":
                case "key-describer": case "keydescriber":
                case "describe-key": case "describer":
                                                     return "toggle-keyhelp";
                case "sync":                         return "sync-session";
                // Output redirection (SQLite .output / PowerShell Out-File)
                case "output": case "tee": case "o":
                                                     return "out-file";
                // Run commands from a file (SQLite .read / psql \i)
                case "read": case "script": case "i":
                                                     return "invoke-script";
                case "x": case "exit": case "bye":   return "exit-console";
                case "q": case "quit":               return "exit-application";
                case "gui": case "focus":
                                                     return "switch-focus";
                case "window": case "windows": case "pick-window":
                                                     return "select-window";
                // Additional aliases to give every command both a
                // PowerShell name (the canonical Verb-Noun, always
                // reachable by typing the hyphenated form) and a
                // shorter DbDo / dbDot / English-natural alternate.
                // Per Jamal's guideline, aliases include first letter,
                // first word, or first two words of a longer command
                // where the abbreviation is unambiguous.
                // (case "lock" dropped in v1.0.91 with lock-database.)
                case "new":                          return "new-database";
                case "save":                         return "save-database";
                case "import": case "in":            return "import-data";
                case "compare": case "diff":         return "compare-database";
                case "print":                        return "out-printer";
                case "chart":                        return "graphics-grid";
                case "config": case "settings":      return "edit-settings";
                case "console":                      return "enter-console";
                case "web": case "website":          return "open-website";
                case "folder": case "explorer":      return "open-filefolder";
                case "log":                          return "show-log";
                case "reader":                       return "test-reader";
                case "commands": case "command-picker": case "alt-menu":
                case "alternative-menu": case "show-command":
                                                     return "alternate-menu";
                case "about":                        return "about-dbdo";
                case "readme":                       return "show-readme";
                case "cell":                         return "open-cell";
                case "update": case "replace":       return "replace-column";
                case "initial-change": case "initial":
                                                     return "jump-nextinitial";
                case "switch": case "next-table":    return "switch-table";
                case "prev-table": case "previous-table":
                                                     return "switch-tableprevious";
                case "next-object":                  return "switch-object";
                case "prev-object": case "previous-object":
                                                     return "switch-objectprevious";
                case "elevate": case "update-app":   return "elevate-version";
                // restore alias retired in v1.0.101
                case "clear-mark-all": case "clear-all":
                                                     return "clear-mark-all";
                case "saved-bookmark": case "go-bookmark":
                                                     return "restore-bookmark";
            }
            // Note: step-record-first / step-record-last / step-record-next /
            // step-record-prev are deliberately NOT collapsed here. An
            // earlier version of resolveAlias mapped each of those to
            // bare "step-record", which dropped the direction argument
            // and caused "first" to silently mean "next" -- the bug
            // Jamal reported in May 2026. The dispatcher now switches
            // on the full compound verb and passes the direction
            // explicitly to cmdStepRecord.
            return sVerb;
        }

        // ============================ command handlers ============================

        // Manager accessor: use the context window's manager if one
        // exists (follow-active or pinned, per contextForm), otherwise
        // the directly-owned manager (CLI-only mode).
        private static DbDoManager db
        {
            get
            {
                DbDoForm frmContext = contextForm();
                if (frmContext != null) return frmContext.Db;
                return inputMgr;
            }
        }

        private static bool requireOpen()
        {
            if (db == null || !db.isOpen()) { Console.WriteLine("(no database open)"); return false; }
            return true;
        }

        private static bool requireRecordset()
        {
            if (!requireOpen()) return false;
            if (!db.hasRecordset()) { Console.WriteLine("(no table selected)"); return false; }
            return true;
        }

        // refresh: redraw the context window's grid after any state
        // change. In CLI-only mode there is no grid to redraw, so
        // this is a no-op.
        private static void refresh()
        {
            DbDoForm frmContext = contextForm();
            if (frmContext != null) frmContext.invokeRefresh();
        }

        private static void cmdStepRecord(string sArg)
        {
            if (!requireRecordset()) return;
            // Accept any of:
            //   <empty>                  step forward 1
            //   next [N]                 step forward 1 (or N)
            //   previous|prev [N]        step back 1 (or N)
            //   first|top                go to first row
            //   last|bottom              go to last row
            //   <integer>                bare integer: step forward
            //                            that many rows (negative
            //                            steps backward). Matches
            //                            dBASE's SKIP semantic.
            string sTrim = sArg.Trim();
            string sLower = sTrim.ToLowerInvariant();

            // Bare integer form: "+5", "-3", "10", etc.
            int iSkip;
            if (sTrim.Length > 0 && int.TryParse(sTrim, out iSkip))
            {
                skipBy(iSkip);
                refresh();
                printRowSummary();
                return;
            }

            // Tokenized forms.
            string[] aT = sTrim.Split(new[] { ' ', '\t' }, 2, StringSplitOptions.RemoveEmptyEntries);
            string sVerb = aT.Length > 0 ? aT[0].ToLowerInvariant() : "";
            string sCount = aT.Length > 1 ? aT[1].Trim() : "";
            int iN = 1;
            if (sCount.Length > 0 && !int.TryParse(sCount, out iN))
            {
                Console.WriteLine("Step Record: count must be an integer.");
                return;
            }
            if (iN < 1) iN = 1;

            switch (sVerb)
            {
                case "":
                case "next":
                    skipBy(iN);
                    break;
                case "previous":
                case "prev":
                    skipBy(-iN);
                    break;
                case "first":
                    db.moveFirst();
                    break;
                case "last":
                    db.moveLast();
                    break;
                default:
                    Console.WriteLine("Step Record argument: next [N] | previous [N] | first | last | <integer>");
                    return;
            }
            refresh();
            printRowSummary();
        }

        // Move the cursor by N rows, positive = forward, negative
        // = backward. Bounded by BOF / EOF. Pattern lifted from
        // dBASE's SKIP n. The ADO recordset has no SKIP, so we
        // loop MoveNext / MovePrevious; the client cursor makes
        // this O(N) in memory, not in disk seeks.
        private static void skipBy(int iN)
        {
            if (iN == 0) return;
            if (iN > 0)
            {
                for (int i = 0; i < iN && !db.eof; i++) db.moveNext();
            }
            else
            {
                for (int i = 0; i < -iN && !db.bof; i++) db.movePrevious();
            }
        }

        // Set-Position: jump to a numbered row, accepting either an
        // integer ordinal (1-based) or a percent like "50%" of the
        // current record count. Matches the GUI's Set-Position which
        // accepts both forms in its prompt. Percent is rounded to the
        // nearest row, clamped to [1, recordCount].
        private static void cmdSetPosition(string sArg)
        {
            if (!requireRecordset()) return;
            string sTrim = sArg.Trim();
            int iCount = db.recordCount;
            if (iCount <= 0) { Console.WriteLine("(no records)"); return; }
            int iTarget;
            if (sTrim.EndsWith("%"))
            {
                double dPct;
                if (!double.TryParse(sTrim.TrimEnd('%').Trim(),
                        System.Globalization.NumberStyles.Float,
                        System.Globalization.CultureInfo.InvariantCulture, out dPct)
                    || dPct < 0 || dPct > 100)
                { Console.WriteLine("Set-Position: percent must be 0-100, like 50%."); return; }
                iTarget = (int)Math.Round(iCount * dPct / 100.0);
                if (iTarget < 1) iTarget = 1;
            }
            else if (!int.TryParse(sTrim, out iTarget))
            { Console.WriteLine("Set-Position: requires a row number or percent."); return; }
            if (iTarget < 1) iTarget = 1;
            if (iTarget > iCount) iTarget = iCount;
            db.absolutePosition = iTarget;
            refresh();
            printRowSummary();
        }

        // Show-Object: print the current row's fields, one per line,
        // in the form "field-name = value". After the fields, list
        // related records grouped by table -- parent rows reached
        // via outbound foreign keys, then child rows that reference
        // this one. The GUI equivalent opens the same content in a
        // read-only dialog (bound to Enter).
        //
        // Argument grammar:
        //   Show-Object              all display fields + related records
        //   Show-Object col1,col2    only the named columns; no related
        //   Show-Object all          every field of the recordset; no related
        //
        // The named-columns and 'all' modes are intended for
        // scripting where the user wants a precise field set, so
        // they skip the related-records section.
        private static void cmdShowObject(string sArg)
        {
            if (!requireRecordset()) return;
            if (db.recordCount == 0) { Console.WriteLine("(no records)"); return; }
            List<string> lAll = db.getFieldNames();
            string sArgTrim = sArg.Trim();
            bool bShowRelated = (sArgTrim.Length == 0);

            List<string> lWanted = new List<string>();
            if (sArgTrim.Equals("all", StringComparison.OrdinalIgnoreCase))
            {
                lWanted = lAll;
            }
            else if (sArgTrim.Length > 0)
            {
                foreach (string s in sArgTrim.Split(','))
                {
                    string sT = s.Trim();
                    if (lAll.Contains(sT)) lWanted.Add(sT);
                }
            }
            if (lWanted.Count == 0)
            {
                lWanted = db.getDisplayFieldNames();
                if (lWanted.Count == 0) lWanted = lAll;
            }

            foreach (string sCol in lWanted)
                Console.WriteLine(string.Format("  {0} = {1}", sCol, db.getFieldValue(sCol)));

            if (bShowRelated)
                cmdShowObjectRelated();
        }

        // Print the related-records section of Show-Object to the
        // CLI. Mirrors the GUI's appendRelatedRecords logic but
        // writes directly to Console.
        private static void cmdShowObjectRelated()
        {
            const int iMaxPerSection = 25;
            const string sNoLook = "(no look column on this table)";

            string sCurrentTable = db.currentTable ?? "";
            if (string.IsNullOrEmpty(sCurrentTable)) return;
            List<string> lCurrentCols = db.getFieldNames();
            if (lCurrentCols.Count == 0) return;

            string sCurrentPk = db.actualPrimaryKey(sCurrentTable);
            if (string.IsNullOrEmpty(sCurrentPk))
                sCurrentPk = computePrimaryKeyColumnStatic(sCurrentTable, lCurrentCols);
            string sCurrentPkValue = "";
            if (!string.IsNullOrEmpty(sCurrentPk))
            {
                try { sCurrentPkValue = db.getFieldValue(sCurrentPk) ?? ""; }
                catch { sCurrentPkValue = ""; }
            }
            List<string> lAllTables = db.getTableNames();

            // Outbound FK -> parent.
            bool bAnyEmitted = false;
            foreach (string sCol in lCurrentCols)
            {
                if (string.Equals(sCol, sCurrentPk, StringComparison.OrdinalIgnoreCase)) continue;
                if (!sCol.EndsWith(Metadata.PrimaryKeySuffix, StringComparison.OrdinalIgnoreCase)) continue;

                string sFkValue = "";
                try { sFkValue = db.getFieldValue(sCol) ?? ""; }
                catch { sFkValue = ""; }
                if (string.IsNullOrEmpty(sFkValue)) continue;

                string sParentTable = findParentTableForFkStatic(sCol, lAllTables);
                if (string.IsNullOrEmpty(sParentTable)) continue;

                int iFound;
                List<string> lLook = db.queryColumnValues(
                    sParentTable, "look", sCol, sFkValue, 1, out iFound);

                if (!bAnyEmitted) { Console.WriteLine(); bAnyEmitted = true; }
                Console.WriteLine("Related " + sParentTable + ":");
                if (iFound == 0)
                    Console.WriteLine("  (parent not found)");
                else if (lLook.Count > 0 && !string.IsNullOrEmpty(lLook[0]))
                    Console.WriteLine("  " + lLook[0]);
                else
                    Console.WriteLine("  " + sNoLook);
            }

            // Inbound FK -> children.
            if (string.IsNullOrEmpty(sCurrentPk) || string.IsNullOrEmpty(sCurrentPkValue))
                return;

            foreach (string sChildTable in lAllTables)
            {
                if (string.Equals(sChildTable, sCurrentTable, StringComparison.OrdinalIgnoreCase)) continue;
                List<string> lChildCols = db.getColumnsOfTable(sChildTable);
                bool bHasFk = false;
                foreach (string sChildCol in lChildCols)
                {
                    if (string.Equals(sChildCol, sCurrentPk, StringComparison.OrdinalIgnoreCase))
                    { bHasFk = true; break; }
                }
                if (!bHasFk) continue;

                int iFound;
                List<string> lLook = db.queryColumnValues(
                    sChildTable, "look", sCurrentPk, sCurrentPkValue,
                    iMaxPerSection, out iFound);
                if (iFound == 0) continue;

                Console.WriteLine();
                Console.WriteLine("Related " + sChildTable + ":");
                if (lLook.Count == 0)
                {
                    Console.WriteLine("  (" + iFound + " row(s) -- " + sNoLook + ")");
                }
                else
                {
                    foreach (string sLook in lLook)
                        Console.WriteLine("  " + (string.IsNullOrEmpty(sLook) ? "(empty look)" : sLook));
                    if (iFound > lLook.Count)
                    {
                        int iMore = iFound - lLook.Count;
                        Console.WriteLine("  (... " + iMore + " more; use Enter-Child to see all)");
                    }
                }
            }
        }

        // Static counterparts to the form instance methods, used by
        // the CLI dispatcher. Behaviorally identical -- just relocated.
        private static string computePrimaryKeyColumnStatic(string sTable, List<string> lCols)
        {
            if (string.IsNullOrEmpty(sTable)) return null;
            string sLowerTable = sTable.ToLowerInvariant();
            string sSingular = (sLowerTable.EndsWith("s") && sLowerTable.Length > 1)
                ? sLowerTable.Substring(0, sLowerTable.Length - 1) : sLowerTable;
            string sPkPlural = sSingular + Metadata.PrimaryKeySuffix;
            foreach (string sCol in lCols)
                if (sCol.ToLowerInvariant() == sPkPlural) return sCol;
            string sPkBare = sLowerTable + Metadata.PrimaryKeySuffix;
            foreach (string sCol in lCols)
                if (sCol.ToLowerInvariant() == sPkBare) return sCol;
            foreach (string sCol in lCols)
                if (sCol.ToLowerInvariant() == "id") return sCol;
            return null;
        }

        private static string findParentTableForFkStatic(string sFkColumn, List<string> lAllTables)
        {
            if (string.IsNullOrEmpty(sFkColumn)) return null;
            foreach (string sT in lAllTables)
            {
                string sPk = db.actualPrimaryKey(sT);
                if (string.IsNullOrEmpty(sPk))
                {
                    List<string> lCols = db.getColumnsOfTable(sT);
                    sPk = computePrimaryKeyColumnStatic(sT, lCols);
                }
                if (!string.IsNullOrEmpty(sPk)
                    && string.Equals(sPk, sFkColumn, StringComparison.OrdinalIgnoreCase))
                    return sT;
            }
            return null;
        }

        // Show-Table: print rows from the current recordset.
        // Argument grammar mirrors dBASE's LIST [scope] [fields]:
        //
        //   Show-Table                         first 50 rows
        //   Show-Table all                     every row
        //   Show-Table next 5                  next 5 rows starting from current
        //   Show-Table for <expr>              rows matching an ADO Filter expression
        //                                      (filter is temporarily applied, then
        //                                      restored; the active filter is preserved)
        //   Show-Table fields:col1,col2        restrict columns shown
        //
        // The scope and fields clauses can be combined in any order:
        //   Show-Table next 10 fields:name,updated
        //   Show-Table for "marked = true" fields:name
        //
        // Uses display fields by default (the Select-Column override
        // and the standard-hidden rules still apply); fields:<list>
        // overrides that with an explicit set.
        private static void cmdShowTable(string sArg)
        {
            if (!requireRecordset()) return;
            int iTotal = db.recordCount;
            if (iTotal == 0) { Console.WriteLine("(no records)"); return; }

            // Parse the argument grammar.
            bool bAll = false;
            int iNext = 50;          // default scope: first 50
            bool bScopeIsNext = false;  // true when "next N" used
            string sForExpr = "";
            List<string> lExplicitFields = null;
            string sRest = sArg.Trim();

            // fields:col1,col2 extraction first
            int iFieldsAt = sRest.ToLowerInvariant().IndexOf("fields:");
            if (iFieldsAt >= 0)
            {
                int iEnd = sRest.IndexOf(' ', iFieldsAt + 7);
                if (iEnd < 0) iEnd = sRest.Length;
                string sFieldList = sRest.Substring(iFieldsAt + 7, iEnd - (iFieldsAt + 7));
                lExplicitFields = new List<string>();
                foreach (string s in sFieldList.Split(','))
                {
                    string sT = s.Trim();
                    if (sT.Length > 0) lExplicitFields.Add(sT);
                }
                sRest = (sRest.Substring(0, iFieldsAt) + " "
                       + (iEnd < sRest.Length ? sRest.Substring(iEnd) : "")).Trim();
            }

            // for <expr> extraction (everything after "for ")
            int iForAt = -1;
            string sLower = sRest.ToLowerInvariant();
            if (sLower.StartsWith("for ")) iForAt = 0;
            else
            {
                int i2 = sLower.IndexOf(" for ");
                if (i2 >= 0) iForAt = i2 + 1;
            }
            if (iForAt >= 0)
            {
                sForExpr = sRest.Substring(iForAt + 3).Trim();
                sRest = sRest.Substring(0, iForAt).Trim();
            }

            // Scope: "all", "next N", or empty (default 50).
            sLower = sRest.ToLowerInvariant();
            if (sLower == "all") bAll = true;
            else if (sLower.StartsWith("next "))
            {
                string sN = sRest.Substring(5).Trim();
                int iN;
                if (!int.TryParse(sN, out iN) || iN < 1)
                {
                    Console.WriteLine("Show-Table: 'next' requires a positive integer.");
                    return;
                }
                iNext = iN;
                bScopeIsNext = true;
            }
            else if (sLower.Length > 0)
            {
                // Unknown trailing tokens: try as a plain integer.
                int iN;
                if (int.TryParse(sLower, out iN) && iN > 0)
                {
                    iNext = iN;
                }
                else
                {
                    Console.WriteLine("Show-Table: didn't understand '" + sRest + "'. "
                        + "Use: Show-Table [all | next N | for <expr>] [fields:col1,col2]");
                    return;
                }
            }

            // Choose fields to display.
            List<string> lFields;
            if (lExplicitFields != null && lExplicitFields.Count > 0)
            {
                // Validate against the recordset; drop unknown names.
                List<string> lAll = db.getFieldNames();
                HashSet<string> hAll = new HashSet<string>(lAll, StringComparer.OrdinalIgnoreCase);
                lFields = new List<string>();
                foreach (string s in lExplicitFields)
                    if (hAll.Contains(s)) lFields.Add(s);
                if (lFields.Count == 0)
                {
                    Console.WriteLine("Show-Table: none of the requested fields exist in this table.");
                    return;
                }
            }
            else
            {
                lFields = db.getDisplayFieldNames();
            }

            // Apply temporary FOR filter on top of existing filter.
            string sSavedFilter = db.filter;
            object bookmarkSaved = db.bookmark;
            try
            {
                if (sForExpr.Length > 0)
                {
                    string sCombined = sSavedFilter.Length > 0
                        ? "(" + sSavedFilter + ") AND (" + sForExpr + ")"
                        : sForExpr;
                    try { db.filter = sCombined; }
                    catch (Exception ex)
                    {
                        Console.WriteLine("Filter expression rejected: " + ex.Message);
                        return;
                    }
                }

                int iCount = db.recordCount;
                if (iCount == 0) { Console.WriteLine("(no rows match)"); return; }

                int iStartPos = bScopeIsNext ? db.absolutePosition : 1;
                if (bScopeIsNext && iStartPos < 1) iStartPos = 1;
                int iLimit = bAll ? iCount : iNext;

                Console.WriteLine(string.Join(" | ", lFields));
                int iHeaderLen = string.Join(" | ", lFields).Length;
                Console.WriteLine(new string('-', Math.Min(80, iHeaderLen)));

                if (bScopeIsNext) db.absolutePosition = iStartPos;
                else db.moveFirst();

                int iRowsPrinted = 0;
                int iRowNum = bScopeIsNext ? iStartPos : 1;
                while (!db.eof && iRowsPrinted < iLimit)
                {
                    List<string> lV = new List<string>();
                    foreach (string sN in lFields) lV.Add(db.getFieldValue(sN));
                    Console.WriteLine(string.Format("{0,3}. {1}", iRowNum, string.Join(" | ", lV)));
                    db.moveNext();
                    iRowsPrinted++;
                    iRowNum++;
                }
                int iRemaining = iCount - (bScopeIsNext ? iStartPos - 1 + iRowsPrinted : iRowsPrinted);
                if (iRemaining > 0 && !bAll)
                    Console.WriteLine(string.Format("... {0} more rows. Use 'Show-Table all' to see all.", iRemaining));
            }
            finally
            {
                if (sForExpr.Length > 0)
                {
                    try { db.filter = sSavedFilter; } catch { }
                }
                if (bookmarkSaved != null) try { db.bookmark = bookmarkSaved; } catch { }
                refresh();
            }
        }

        private static void cmdShowSchema(string sArg)
        {
            if (!requireOpen()) return;
            if (sArg.Length > 0)
            {
                List<string> lAll = db.getTableAndViewNames();
                if (!lAll.Contains(sArg)) { Console.WriteLine("(no such table or view)"); return; }
                bool bIsView = db.isViewName(sArg);
                Console.WriteLine("Schema for " + (bIsView ? "view" : "table") + ": " + sArg);
                // Temporarily switch to that table to read its schema.
                string sSavedTable = db.currentTable;
                try { db.selectTable(sArg); foreach (string sN in db.getFieldNames()) Console.WriteLine("  " + sN); }
                finally { if (!string.IsNullOrEmpty(sSavedTable) && sSavedTable != sArg) try { db.selectTable(sSavedTable); } catch { } }
            }
            else
            {
                List<string> lTables = db.getTableNames();
                List<string> lViews = db.getViewNames();
                if (lTables.Count > 0)
                {
                    Console.WriteLine("Tables (" + lTables.Count + "):");
                    foreach (string sN in lTables) Console.WriteLine("  " + sN);
                }
                if (lViews.Count > 0)
                {
                    if (lTables.Count > 0) Console.WriteLine();
                    Console.WriteLine("Views (" + lViews.Count + "):");
                    foreach (string sN in lViews) Console.WriteLine("  " + sN);
                }
            }
        }

        private static void cmdGetField(string sArg)
        {
            if (!requireRecordset()) return;
            string sCol = sArg.Trim();
            if (sCol.Length == 0) { Console.WriteLine("Get-Field requires a column name."); return; }
            if (!db.getFieldNames().Contains(sCol)) { Console.WriteLine("No such column: " + sCol); return; }
            Console.WriteLine(sCol + " = " + db.getFieldValue(sCol));
        }

        private static void cmdSetField(string sArg)
        {
            if (!requireRecordset()) return;
            if (db.readOnly) { Console.WriteLine("Database is read-only."); return; }
            string sCol, sValue;
            int iSplit = sArg.IndexOf('=');
            if (iSplit < 0) iSplit = sArg.IndexOf(' ');
            if (iSplit <= 0) { Console.WriteLine("Set-Field requires '<column> <value>' or '<column>=<value>'."); return; }
            sCol = sArg.Substring(0, iSplit).Trim();
            sValue = sArg.Substring(iSplit + 1).Trim();
            if (sValue.Length >= 2 && sValue.StartsWith("\"") && sValue.EndsWith("\""))
                sValue = sValue.Substring(1, sValue.Length - 2);
            try
            {
                db.setFieldValue(sCol, sValue);
                db.update();
                refresh();
                Console.WriteLine("Saved.");
            }
            catch (Exception ex)
            {
                try { db.cancelUpdate(); } catch { }
                Console.WriteLine("Error: " + ex.Message);
            }
        }

        private static void cmdFindRecord(string sArg)
        {
            if (!requireRecordset()) return;
            string sCriteria = sArg.Trim();
            if (sCriteria.Length == 0) { Console.WriteLine("Find-Record requires a criteria expression."); return; }
            sLastFindCriteria = sCriteria;
            sLastFindKindCli = "plain";
            try
            {
                bool bFound = db.findRecord(sCriteria, true, false);
                if (!bFound) Console.WriteLine("Not found.");
                refresh();
                printRowSummary();
            }
            catch (Exception ex) { Console.WriteLine("Error: " + ex.Message); }
        }

        // jump-recordagain (F3 / "n"): repeat whichever Find variant
        // was last invoked, plain or regex.
        private static void cmdFindAgain()
        {
            if (!requireRecordset()) return;
            if (sLastFindKindCli == "regex")
            {
                cmdFindRegexAgain();
                return;
            }
            if (string.IsNullOrEmpty(sLastFindCriteria)) { Console.WriteLine("No previous Find."); return; }
            try
            {
                bool bFound = db.findRecord(sLastFindCriteria, true, true);
                if (!bFound) Console.WriteLine("No more matches.");
                refresh();
                printRowSummary();
            }
            catch (Exception ex) { Console.WriteLine("Error: " + ex.Message); }
        }

        // jump-recordprevious (Shift+F3): repeat the last Find backward,
        // dispatching on plain vs regex like cmdFindAgain.
        private static void cmdFindPrevious()
        {
            if (!requireRecordset()) return;
            if (sLastFindKindCli == "regex")
            {
                cmdFindRegexPrevious();
                return;
            }
            if (string.IsNullOrEmpty(sLastFindCriteria)) { Console.WriteLine("No previous Find."); return; }
            try
            {
                bool bFound = db.findRecord(sLastFindCriteria, false, true);
                if (!bFound) Console.WriteLine("No earlier matches.");
                refresh();
                printRowSummary();
            }
            catch (Exception ex) { Console.WriteLine("Error: " + ex.Message); }
        }

        // Find-Regex: find a row matching a .NET regex.
        //
        // Argument grammar:
        //   Find-Regex <column> <pattern>
        //   Find-Regex * <pattern>            (scan all visible fields)
        //   Find-Regex <pattern>              (uses last column or "*")
        //
        // The first space-separated token is interpreted as a column
        // name if it matches one of the current table's field names
        // (case-insensitive) or is "*"; otherwise the whole argument
        // is treated as the pattern and the column defaults to the
        // last-used column (initially "*"). Pattern compilation
        // errors are surfaced verbatim.
        //
        // Find-RegexAgain and Find-RegexPrevious repeat the last
        // regex search forward / backward from the current row.
        private static void cmdFindRegex(string sArg)
        {
            if (!requireRecordset()) return;
            string sTrim = sArg.Trim();
            if (sTrim.Length == 0)
            { Console.WriteLine("Find-Regex requires a pattern. Try: find-regex <column> <pattern>"); return; }

            // v1.0.94: tokenize with quote awareness so the user can
            // type `find-regex "*" "Hello World"` or `find-regex Notes
            // "stays \"in\" quotes"` and have the pattern's internal
            // whitespace and embedded quotes preserved. The previous
            // IndexOf(' ') split treated everything literally including
            // quote characters, breaking those forms.
            string[] aArgs = splitArgsRespectingQuotes(sTrim);

            string sCol;
            string sPattern;
            if (aArgs.Length >= 2)
            {
                string sFirst = aArgs[0];
                bool bIsCol = (sFirst == "*");
                if (!bIsCol)
                {
                    foreach (string sF in db.getFieldNames())
                        if (string.Equals(sF, sFirst, StringComparison.OrdinalIgnoreCase))
                        { bIsCol = true; break; }
                }
                if (bIsCol)
                {
                    sCol = sFirst;
                    // Rejoin remaining args -- if the user typed
                    // multiple quoted/unquoted pieces beyond the
                    // column name, treat them as the pattern (rare;
                    // shouldn't usually happen, but is well-defined).
                    sPattern = aArgs.Length == 2
                        ? aArgs[1]
                        : joinArgsRespectingQuotes(aArgs, 1);
                }
                else
                {
                    sCol = string.IsNullOrEmpty(sLastFindRegexColumnCli) ? "*" : sLastFindRegexColumnCli;
                    sPattern = joinArgsRespectingQuotes(aArgs, 0);
                }
            }
            else
            { sCol = string.IsNullOrEmpty(sLastFindRegexColumnCli) ? "*" : sLastFindRegexColumnCli;
              // Single argument: respect surrounding quotes if any.
              sPattern = aArgs.Length == 1 ? aArgs[0] : sTrim; }

            sLastFindRegexCli = sPattern;
            sLastFindRegexColumnCli = sCol;
            sLastFindKindCli = "regex";
            try
            {
                bool bFound = db.findRegexRecord(sCol, sPattern, true, false);
                if (!bFound) Console.WriteLine("Not found.");
                refresh();
                printRowSummary();
            }
            catch (Exception ex) { Console.WriteLine("Error: " + ex.Message); }
        }

        private static void cmdFindRegexAgain()
        {
            if (!requireRecordset()) return;
            if (string.IsNullOrEmpty(sLastFindRegexCli))
            { Console.WriteLine("No previous Find-Regex."); return; }
            try
            {
                bool bFound = db.findRegexRecord(
                    sLastFindRegexColumnCli, sLastFindRegexCli, true, true);
                if (!bFound) Console.WriteLine("No more matches.");
                refresh();
                printRowSummary();
            }
            catch (Exception ex) { Console.WriteLine("Error: " + ex.Message); }
        }

        private static void cmdFindRegexPrevious()
        {
            if (!requireRecordset()) return;
            if (string.IsNullOrEmpty(sLastFindRegexCli))
            { Console.WriteLine("No previous Find-Regex."); return; }
            try
            {
                bool bFound = db.findRegexRecord(
                    sLastFindRegexColumnCli, sLastFindRegexCli, false, true);
                if (!bFound) Console.WriteLine("No earlier matches.");
                refresh();
                printRowSummary();
            }
            catch (Exception ex) { Console.WriteLine("Error: " + ex.Message); }
        }

        private static void cmdSelectRecord(string sArg)
        {
            if (!requireRecordset()) return;
            string sExpr = sArg.Trim();
            // dbDot shortcuts: "filter marked" -> marked = true,
            // "filter unmarked" -> marked = false. The user types
            // the noun, we expand to the ADO Filter expression.
            // Case-insensitive; case "marked" maps to true,
            // "unmarked" to false.
            if (string.Equals(sExpr, "marked", StringComparison.OrdinalIgnoreCase))
                sExpr = "marked = true";
            else if (string.Equals(sExpr, "unmarked", StringComparison.OrdinalIgnoreCase))
                sExpr = "marked = false";
            try
            {
                db.filter = sExpr;
                refresh();
                Console.WriteLine("Filter: " + (db.filter.Length > 0 ? db.filter : "(none)"));
                printRowSummary();
            }
            catch (Exception ex) { Console.WriteLine("Error: " + ex.Message); }
        }

        private static void cmdResetFilter()
        {
            if (!requireRecordset()) return;
            db.resetFilter();
            refresh();
            Console.WriteLine("Filter cleared.");
            printRowSummary();
        }

        // Select-Column: pick which columns are visible in the
        // ListView. Comma-separated list. With no argument, prints
        // the current select-list (or "(default rules)" if none
        // set). Empty argument or the literal word "reset" clears
        // the user override. Invalid column names are dropped
        // silently and reported.
        private static void cmdSelectColumn(string sArg)
        {
            if (!requireRecordset()) return;
            string sExpr = sArg.Trim();
            string sTable = db.currentTable;
            if (sExpr.Length == 0)
            {
                string sCurrent = db.getSelectList(sTable);
                if (sCurrent.Length == 0)
                    Console.WriteLine("Select-Column: (default rules) -- "
                        + string.Join(", ", db.getDisplayFieldNames().ToArray()));
                else
                    Console.WriteLine("Select-Column: " + sCurrent);
                Console.WriteLine("Usage: Select-Column col1, col2, col3");
                Console.WriteLine("       Select-Column reset       (revert to default rules)");
                return;
            }
            if (string.Equals(sExpr, "reset", StringComparison.OrdinalIgnoreCase))
            {
                db.setSelectList(sTable, "");
                refresh();
                Console.WriteLine("Select-Column cleared; default rules apply.");
                return;
            }

            List<string> lRequested = DbDoManager.parseSelectList(sExpr);
            string sStored = db.setSelectList(sTable, sExpr);
            List<string> lAccepted = DbDoManager.parseSelectList(sStored);
            HashSet<string> hAccepted = new HashSet<string>(lAccepted, StringComparer.OrdinalIgnoreCase);
            List<string> lDropped = new List<string>();
            foreach (string sName in lRequested)
                if (!hAccepted.Contains(sName)) lDropped.Add(sName);

            refresh();
            Console.WriteLine("Select-Column: " + (sStored.Length > 0 ? sStored : "(empty -- showing default)"));
            if (lDropped.Count > 0)
                Console.WriteLine("Dropped (not column names of this table): "
                    + string.Join(", ", lDropped.ToArray()));
        }

        // Sort the current recordset by the given expression. The expression
        // is ADO sort syntax: "col" or "col ASC" or "col DESC", optionally
        // multiple columns separated by commas. An empty string clears the
        // sort (equivalent to Reset-Sort).
        //
        // Note: this is the dot-prompt counterpart of the GUI's Sort-Object
        // menu item.
        private static void cmdSortObject(string sArg)
        {
            if (!requireRecordset()) return;
            try
            {
                db.sort = sArg.Trim();
                refresh();
                Console.WriteLine("Sort: " + (db.sort.Length > 0 ? db.sort : "(none)"));
                printRowSummary();
            }
            catch (Exception ex) { Console.WriteLine("Error: " + ex.Message); }
        }

        // cmdOrderRecords: dot-prompt equivalent of Alt+O. Takes a
        // comma-separated precedence list of field names, each optionally
        // followed by asc or desc (case-insensitive; quoting optional),
        // e.g.  order-records city, last_name desc, first_name. With no
        // argument, lists all field names and prompts the user to pick
        // one (CLI equivalent of the GUI listbox).
        private static void cmdOrderRecords(string sArg)
        {
            cmdOrderCommon(sArg, false);
        }

        // cmdReverseOrder: dot-prompt equivalent of Alt+Shift+O.
        // Same as cmdOrderRecords but sorts descending.
        private static void cmdReverseOrder(string sArg)
        {
            cmdOrderCommon(sArg, true);
        }

        private static void cmdOrderCommon(string sArg, bool bDescending)
        {
            if (!requireRecordset()) return;
            string sList = unquote((sArg ?? "").Trim());
            if (sList.Length == 0)
            {
                // No argument: prompt with the alpha-sorted column list,
                // the CLI analog of the GUI listbox (single column).
                List<string> lAll = db.getFieldNames();
                List<string> lSorted = new List<string>(lAll);
                lSorted.Sort(StringComparer.OrdinalIgnoreCase);
                int iChoice = promptChoiceCli(
                    bDescending ? "Reverse Order by column" : "Order Records by column",
                    lSorted, 0);
                if (iChoice < 0) { Console.WriteLine("Cancelled."); return; }
                sList = lSorted[iChoice];
            }
            // Parse a comma-separated precedence list: each term is a field
            // name optionally followed by asc or desc. A term with no
            // direction takes the command default (ascending for Order
            // Records, descending for Reverse Order). Field names match
            // case-insensitively; the assembled clause feeds db.sort, which
            // accepts the same multi-column form as the GUI picker.
            List<string> lTerms = new List<string>();
            foreach (string sRawTerm in sList.Split(','))
            {
                string sTerm = unquote(sRawTerm.Trim());
                if (sTerm.Length == 0) continue;
                bool bTermDesc = bDescending;
                int iSpace = sTerm.LastIndexOf(' ');
                if (iSpace > 0)
                {
                    string sDir = sTerm.Substring(iSpace + 1).Trim().ToLowerInvariant();
                    if (sDir == "asc" || sDir == "ascending")
                    { bTermDesc = false; sTerm = sTerm.Substring(0, iSpace).Trim(); }
                    else if (sDir == "desc" || sDir == "descending")
                    { bTermDesc = true; sTerm = sTerm.Substring(0, iSpace).Trim(); }
                }
                string sActual = null;
                foreach (string sF in db.getFieldNames())
                {
                    if (string.Equals(sF, sTerm, StringComparison.OrdinalIgnoreCase))
                    { sActual = sF; break; }
                }
                if (sActual == null)
                {
                    Console.WriteLine("No such column: \"" + sTerm + "\".");
                    return;
                }
                lTerms.Add(sActual + (bTermDesc ? " DESC" : " ASC"));
            }
            if (lTerms.Count == 0) { Console.WriteLine("No columns to sort by."); return; }
            string sClause = string.Join(", ", lTerms.ToArray());
            try
            {
                db.sort = sClause;
                refresh();
                Console.WriteLine("Ordered by " + sClause + ".");
                printRowSummary();
            }
            catch (Exception ex) { Console.WriteLine("Error: " + ex.Message); }
        }

        private static void cmdResetSort()
        {
            if (!requireRecordset()) return;
            db.resetSort();
            refresh();
            Console.WriteLine("Sort cleared.");
            printRowSummary();
        }

        private static void cmdNewRecord()
        {
            if (!requireRecordset()) return;
            if (db.readOnly) { Console.WriteLine("Database is read-only."); return; }
            List<string> lFields = db.getFieldNames();
            Console.WriteLine("(Press Enter to skip a field. Type a value to set it.)");
            try
            {
                db.addNew();
                foreach (string sCol in lFields)
                {
                    Console.Write(sCol + ": ");
                    string sV = Console.ReadLine();
                    if (sV == null) { db.cancelUpdate(); return; }
                    if (sV.Length > 0) db.setFieldValue(sCol, sV);
                }
                db.update();
                refresh();
                Console.WriteLine("Saved new record.");
            }
            catch (Exception ex)
            {
                try { db.cancelUpdate(); } catch { }
                Console.WriteLine("Error: " + ex.Message);
            }
        }

        private static void cmdSetRecord()
        {
            if (!requireRecordset()) return;
            if (db.readOnly) { Console.WriteLine("Database is read-only."); return; }
            if (db.eof || db.bof) { Console.WriteLine("(no current record)"); return; }
            List<string> lFields = db.getFieldNames();
            Console.WriteLine("(Press Enter to keep the existing value. Type a new value to change it.)");
            try
            {
                foreach (string sCol in lFields)
                {
                    string sCur = db.getFieldValue(sCol);
                    Console.Write(string.Format("{0} [{1}]: ", sCol, sCur));
                    string sV = Console.ReadLine();
                    if (sV == null) { db.cancelUpdate(); return; }
                    if (sV.Length > 0) db.setFieldValue(sCol, sV);
                }
                db.update();
                refresh();
                Console.WriteLine("Saved.");
            }
            catch (Exception ex)
            {
                try { db.cancelUpdate(); } catch { }
                Console.WriteLine("Error: " + ex.Message);
            }
        }

        private static void cmdRemoveRecord()
        {
            if (!requireRecordset()) return;
            if (db.readOnly) { Console.WriteLine("Database is read-only."); return; }
            if (db.eof || db.bof) { Console.WriteLine("(no current record)"); return; }
            Console.Write("Confirm Remove-Record? (y/N): ");
            string s = Console.ReadLine();
            if (s == null || !s.Trim().Equals("y", StringComparison.OrdinalIgnoreCase)) { Console.WriteLine("Cancelled."); return; }
            try
            {
                db.deleteCurrent();
                refresh();
                Console.WriteLine("Removed.");
                printRowSummary();
            }
            catch (Exception ex) { Console.WriteLine("Error: " + ex.Message); }
        }

        private static void cmdCopyRecord()
        {
            if (!requireRecordset()) return;
            List<string> lV = new List<string>();
            foreach (string sN in db.getFieldNames()) lV.Add(db.getFieldValue(sN));
            string sLine = string.Join("\t", lV);
            try { frm.Invoke(new Action(() => Clipboard.SetText(sLine))); }
            catch { Console.WriteLine("(clipboard unavailable)"); return; }
            Console.WriteLine("Row copied to clipboard.");
