        // cmdExportData: dbDot-compatible multi-format export.
        // Argument grammar:
        //
        //   Export-Data                       -> xlsx, into the
        //                                        database's folder,
        //                                        named after the
        //                                        current table.
        //   Export-Data xlsx docx html csv    -> all four at once.
        //   Export-Data x d h c               -> dbDot single-letter
        //                                        shortcuts; same as
        //                                        above.
        //   Export-Data csv path/to/file.csv  -> single-file form
        //                                        with explicit path
        //                                        (backward compat).
        //
        // After writing, each file is opened with its default Windows
        // application via ShellExecute (matches dbDot's shellOpen).
        private static void cmdExportData(string sArg)
        {
            if (!requireRecordset()) return;
            string sTrim = (sArg ?? "").Trim();

            // Detect the legacy single-path form: if the argument
            // contains a path separator or ends with a recognized
            // file extension, treat it as a single destination path.
            // Otherwise treat it as a dbDot-style extension list.
            // v1.0.94: the detection happens on the unquoted form so
            // paths like "C:\My Stuff\out.csv" (with embedded spaces)
            // detect correctly.
            string sUnquoted = unquote(sTrim);
            bool bLegacyPath = sUnquoted.Contains("\\")
                            || sUnquoted.Contains("/")
                            || sUnquoted.EndsWith(".csv", StringComparison.OrdinalIgnoreCase)
                            || sUnquoted.EndsWith(".tsv", StringComparison.OrdinalIgnoreCase)
                            || sUnquoted.EndsWith(".md", StringComparison.OrdinalIgnoreCase)
                            || sUnquoted.EndsWith(".markdown", StringComparison.OrdinalIgnoreCase)
                            || sUnquoted.EndsWith(".json", StringComparison.OrdinalIgnoreCase)
                            || sUnquoted.EndsWith(".inix", StringComparison.OrdinalIgnoreCase)
                            || sUnquoted.EndsWith(".html", StringComparison.OrdinalIgnoreCase)
                            || sUnquoted.EndsWith(".htm",  StringComparison.OrdinalIgnoreCase)
                            || sUnquoted.EndsWith(".xlsx", StringComparison.OrdinalIgnoreCase)
                            || sUnquoted.EndsWith(".docx", StringComparison.OrdinalIgnoreCase);

            try
            {
                if (bLegacyPath)
                {
                    db.exportData(sUnquoted);
                    Console.WriteLine("Exported to " + sUnquoted);
                    ComAutomation.shellOpen(sUnquoted);
                    return;
                }

                // Multi-format form. Empty argument defaults to xlsx.
                List<string> lWritten = db.exportDataMulti(sTrim, null, null);
                if (lWritten.Count == 0)
                {
                    Console.WriteLine("Export-Data: nothing requested (no recognized format).");
                    Console.WriteLine("Try: Export-Data xlsx docx html csv");
                    return;
                }
                foreach (string sP in lWritten)
                {
                    Console.WriteLine("  wrote " + sP);
                    ComAutomation.shellOpen(sP);
                }
            }
            catch (Exception ex) { Console.WriteLine("Error: " + ex.Message); }
        }

        // cmdImportData: read a Markdown table file and append its
        // rows to the currently-open table. Header cell names are
        // matched case-insensitively to columns; cells with no
        // matching column are dropped.
        //
        //   Import-Data path\to\file.md
        //
        // For non-Markdown formats, use Invoke-Sql with INSERT INTO
        // ... SELECT or the database's own native import path.
        private static void cmdImportData(string sArg)
        {
            if (!requireRecordset()) return;
            // v1.0.95: optional-quote file path resolution.
            string sPath = resolvePathArg(sArg ?? "");
            if (string.IsNullOrEmpty(sPath)) { Console.WriteLine("Import-Data requires a file path. Supports .md (Markdown table), .json, and .inix."); return; }
            try
            {
                string sExt = Path.GetExtension(sPath).TrimStart('.').ToLowerInvariant();
                int iCount;
                if (sExt == "inix") iCount = db.importInix(sPath);
                else if (sExt == "json") iCount = db.importJson(sPath);
                else if (sExt == "csv") iCount = db.importDelimited(sPath, ',');
                else if (sExt == "tsv" || sExt == "tab") iCount = db.importDelimited(sPath, '\t');
                else iCount = db.importMarkdown(sPath);
                Console.WriteLine("Imported " + iCount + " row(s) into " + db.currentTable + ".");
                refresh();
            }
            catch (Exception ex) { Console.WriteLine("Error: " + ex.Message); }
        }

        private static void cmdOpenDatabase(string sArg)
        {
            // v1.0.95: resolve the path argument with optional quoting.
            // resolvePathArg() returns an existing file's path verbatim
            // if the unquoted line happens to identify one, so the user
            // can type "open database C:\My Stuff\foo.db" without
            // quoting when there's no ambiguity. It falls back to the
            // quote-aware tokenizer for cases where the line doesn't
            // match an existing file.
            string sPath = resolvePathArg(sArg);
            if (string.IsNullOrEmpty(sPath)) { Console.WriteLine("Open-Database requires a file path."); return; }
            try
            {
                // If a GUI form is up, clear its drill stack first --
                // stale entries from the previous database wouldn't
                // map to any row in the new one.
                if (frm != null && !frm.IsDisposed) frm.clearDrillStack();
                db.openDatabase(sPath, null, false);
                if (!db.hasRecordset())
                {
                    // Prefer base tables; fall back to views.
                    List<string> lT = db.getTableNames();
                    if (lT.Count == 0) lT = db.getViewNames();
                    if (lT.Count > 0) db.selectTable(lT[0]);
                }
                refresh();
                Console.WriteLine("Opened: " + db.filePath);
                printRowSummary();
            }
            catch (Exception ex) { Console.WriteLine("Error: " + ex.Message); }
        }

        private static void cmdCloseDatabase()
        {
            if (db == null) return;
            if (frm != null && !frm.IsDisposed) frm.clearDrillStack();
            try { db.close(); refresh(); Console.WriteLine("Closed."); }
            catch (Exception ex) { Console.WriteLine("Error: " + ex.Message); }
        }

        private static object bookmarkSaved;
        private static void cmdSaveBookmark()
        {
            if (!requireRecordset()) return;
            bookmarkSaved = db.bookmark;
            Console.WriteLine("Bookmark saved at row " + db.absolutePosition);
        }

        private static void cmdRestoreBookmark()
        {
            if (!requireRecordset()) return;
            if (bookmarkSaved == null) { Console.WriteLine("No saved bookmark."); return; }
            db.bookmark = bookmarkSaved;
            refresh();
            Console.WriteLine("Bookmark restored.");
            printRowSummary();
        }

        // Clear-Bookmark: forget the saved row.
        private static void cmdClearBookmark()
        {
            bookmarkSaved = null;
            Console.WriteLine("Bookmark cleared.");
        }

        // cmdListBookmarks: CLI form is a no-op stub. The multi-
        // bookmark feature lives on the form side (GUI Alt+B opens
        // a listbox with look-values per entry); the CLI's single
        // saved bookmark just reports its position.
        private static void cmdListBookmarks()
        {
            if (bookmarkSaved == null)
            {
                Console.WriteLine("(no bookmarks; multi-bookmark requires the GUI Alt+B chord)");
                return;
            }
            Console.WriteLine("(CLI tracks one bookmark; the GUI tracks multiple. Use Alt+B in the GUI for the full list.)");
        }

        // cmdSqleanShell: pass a line to the bundled sqlean.exe shell
        // (the SQLite shell built with SQLean) against the current
        // database file and echo its stdout/stderr. This gives the dot
        // prompt the entire sqlite3 / SQLean shell surface -- .tables,
        // .schema, .indexes, .dump, .mode, .import, .stats, .help, and
        // the rest -- without DbDo reimplementing any of it. Invoked as
        // "!<line>" at the prompt (e.g. !.schema events). The shell is
        // opened read-only so it cannot contend with DbDo's writer.
        private static void cmdSqleanShell(string sInput)
        {
            string sExeDir = Path.GetDirectoryName(System.Reflection.Assembly.GetExecutingAssembly().Location);
            string sShell = Path.Combine(sExeDir ?? ".", "sqlean.exe");
            if (!File.Exists(sShell))
            { Console.WriteLine("sqlean.exe not found beside DbDo.exe; bundle it to use the '!' shell pass-through."); return; }
            if (string.IsNullOrEmpty(sInput))
            { Console.WriteLine("Usage: !<line>   run a line in sqlean.exe, e.g. !.tables  or  !.schema events  or  !SELECT median(amount) FROM events"); return; }

            string sDbPath = (db != null) ? (db.filePath ?? "") : "";
            try
            {
                System.Diagnostics.ProcessStartInfo psi = new System.Diagnostics.ProcessStartInfo();
                psi.FileName = sShell;
                psi.Arguments = (sDbPath.Length > 0) ? ("-readonly \"" + sDbPath + "\"") : "";
                psi.UseShellExecute = false;
                psi.CreateNoWindow = true;
                psi.WorkingDirectory = sExeDir ?? ".";
                psi.RedirectStandardInput = true;
                psi.RedirectStandardOutput = true;
                psi.RedirectStandardError = true;
                using (System.Diagnostics.Process p = System.Diagnostics.Process.Start(psi))
                {
                    p.StandardInput.WriteLine(sInput);
                    p.StandardInput.Flush();
                    p.StandardInput.Close();
                    string sOut = p.StandardOutput.ReadToEnd();
                    string sErr = p.StandardError.ReadToEnd();
                    p.WaitForExit(20000);
                    if (sOut.Length > 0) Console.Write(sOut.EndsWith("\n") ? sOut : sOut + "\n");
                    if (sErr.Length > 0) Console.Write(sErr.EndsWith("\n") ? sErr : sErr + "\n");
                    if (sOut.Length == 0 && sErr.Length == 0) Console.WriteLine("(no output)");
                }
            }
            catch (Exception ex) { Console.WriteLine("sqlean.exe error: " + ex.Message); }
        }

        private static void cmdInvokeSql(string sArg)
        {
            if (!requireOpen()) return;
            string sSql = sArg.Trim();
            if (sSql.Length == 0) { Console.WriteLine("Invoke-Sql requires a SQL command."); return; }
            try
            {
                int iAffected = db.invokeSql(sSql, Console.Out);
                if (iAffected >= 0)
                {
                    Console.WriteLine("(" + iAffected + " record(s) affected)");
                    refresh();
                }
            }
            catch (Exception ex) { Console.WriteLine("Error: " + ex.Message); }
        }

        // Help dispatch: bare 'help' shows the command list; 'help X'
        // shows details for command X. Topic lookup is case-insensitive
        // and accepts both the canonical PowerShell name and any
        // aliases ('help find', 'help find-record', 'help f' all hit
        // the same topic).
        private static void cmdGetHelp(string sTopic)
        {
            sTopic = (sTopic ?? "").Trim();
            if (sTopic.Length == 0) { printHelpIndex(); return; }

            string sCanonical = resolveAlias(sTopic.ToLowerInvariant());
            string sDetails = lookupHelpTopic(sCanonical);
            if (sDetails == null)
                sDetails = lookupHelpTopic(sTopic.ToLowerInvariant());
            if (sDetails == null)
            {
                Console.WriteLine();
                Console.WriteLine("No help topic found for: " + sTopic);
                Console.WriteLine("Type 'help' (no argument) for the command list.");
                Console.WriteLine();
                return;
            }
            Console.WriteLine();
            Console.WriteLine(sDetails);
            Console.WriteLine();
        }

